INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80000, 'Zalew Sielpiński (Sielpia)', 'zalew-sielpinski', 'LAKE', 51.112873, 20.352473, 'Świętokrzyskie', 'Końskie / Sielpia Wielka', 'Zalew Sielpia to turystyczna perła regionu, powstała przez spiętrzenie rzeki Czarnej Koneckiej (pow. ok. 60 ha). Akwen jest wybitnie płytki (średnio 1.5 - 2 m), o piaszczystym dnie i bardzo urozmaiconej linii brzegowej z licznymi wyspami i półwyspami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80001, 'Staw Starzyk', 'staw-starzyk', 'LAKE', 51.133859, 20.181799, 'Świętokrzyskie', 'Fałków / Ruda Maleniecka', 'Starzyk to historyczny staw hodowlany wchodzący w skład wielkiego kompleksu rybackiego w Rudzie Malenieckiej. Charakteryzuje się mulistym dnem i regularnym pasem trzcinowisk. Woda jest żyzna, typowa dla karpiowych zbiorników Staropolskiego Okręgu Przemysłowego. Stanowi ważny punkt na mapie tradycji rybackich regionu.', 'Gospodarstwo Rybackie Ruda Maleniecka');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80002, 'Staw Starczyk I', 'staw-starczyk-1', 'LAKE', 51.130924, 20.17343, 'Świętokrzyskie', 'Fałków', 'Jeden z serii stawów w dolinie rzeki Czarnej. Jest to zbiornik płytki, o wyrównanym dnie, otoczony malowniczymi groblami porośniętymi starymi dębami. Słynie z hodowli karpia królewskiego, który w tych warunkach znajduje doskonałą bazę pokarmową w postaci naturalnego bentosu.', 'Gospodarstwo Rybackie / Prywatne');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80003, 'Staw Starczyk II', 'staw-starczyk-2', 'LAKE', 51.132698, 20.169139, 'Świętokrzyskie', 'Fałków', 'Sąsiadujący zbiornik w kompleksie Starczyk. Akwen wyciszony, położony z dala od głównych dróg. Brzegi są niskie, silnie zarośnięte roślinnością wynurzoną, co czyni go idealnym miejscem dla lęgów dzikiego ptactwa oraz matecznikiem dla ryb karpiowatych. Woda nagrzewa się tu bardzo szybko.', 'Gospodarstwo Rybackie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80004, 'Stawy Czapla', 'stawy-czapla', 'LAKE', 51.159516, 20.217376, 'Świętokrzyskie', 'Ruda Maleniecka', 'Kompleks stawów o nazwie nawiązującej do licznie występujących tu ptaków brodzących. Są to akweny o charakterze produkcyjno-hodowlanym. Dno jest wybitnie miękkie, bogate w ochotkę. Wędkarsko (o ile udostępnione do połowu) są to wody zdominowane przez karpia, lina i dorodną amura.', 'Gospodarstwo Rybackie Ruda Maleniecka');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80005, 'Stawy Praga', 'stawy-praga', 'LAKE', 51.178776, 20.209651, 'Świętokrzyskie', 'Ruda Maleniecka / Maleniec', 'Stawy Praga położone są w bezpośrednim sąsiedztwie zabytkowego zakładu metalurgicznego w Maleńcu. To techniczne zbiorniki wodne, które dawniej napędzały koła wodne, a dziś służą gospodarce rybackiej. Charakteryzują się przepływowym charakterem i obecnością starych konstrukcji mnichów.', 'Gospodarstwo Rybackie / Zespół Zabytkowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80006, 'Jezioro Malenickie', 'jezioro-malenickie', 'LAKE', 51.182665, 20.18593, 'Świętokrzyskie', 'Maleniec', 'Malenickie to malowniczy, wydłużony zbiornik zaporowy na rzece Czarnej Koneckiej. Posiada twardsze dno w osi dawnego koryta rzeki i rozległe, muliste płycizny w zachodniej części. Brzegi są w dużej mierze zalesione, co nadaje akwenowi dziki charakter. To wyśmienite łowisko szczupakowe i okoniowe.', 'PZW Kielce');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80007, 'Jezioro Dargin', 'jezioro-dargin', 'LAKE', '54.117124534325626', '21.72553543945301', 'Warmińsko-Mazurskie', 'Giżycko', 'Potężny, otwarty akwen będący centralną częścią kompleksu Mamr. Dargin to jezioro dla twardzieli – brak osłony od wiatru sprawia, że przy silniejszych podmuchach tworzy się tu wyjątkowo niebezpieczna, krótka i stroma fala. Wędkarze cenią je za krystaliczną wodę (pierwsza klasa czystości) i legendarne już "podwodne góry", które przyciągają rekordowe okonie i szczupaki. To tutaj krzyżują się szlaki żeglowne, więc latem panuje duży ruch, ale jesień to czas absolutnego panowania łowców drapieżników.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80008, 'Jezioro Kisajno', 'jezioro-kisajno', 'LAKE', '54.08533644318498', '21.69748638538963', 'Warmińsko-Mazurskie', 'Giżycko', 'Kisajno to południowa brama do kompleksu Mamr, jezioro o dwóch obliczach. Część południowa to słynny "Labirynt" – archipelag kilkunastu wysp (m.in. Dębowa Górka, Wielka Kiermuza), gdzie między wąskimi przesmykami kryją się płytkie, zarośnięte zatoki idealne na szczupaka i lina. Część północna jest szeroka, otwarta i znacznie głębsza, przypominająca charakterem Dargin. Jezioro słynie z niezwykle czystej wody i ogromnej populacji okonia. Ze względu na duży ruch żeglugowy i statki żeglugi mazurskiej, wędkarze muszą tu uważać na wysoką falę generowaną przez jednostki motorowe, nawet przy bezwietrznej pogodzie.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80009, 'Jezioro Dziaduszyn', 'jezioro-dziaduszyn', 'LAKE', '54.16887078415484', '21.81104676327644', 'Warmińsko-Mazurskie', 'Pozezdrze', 'Kameralne jezioro na szlaku Sapiny, między jez. Święcajty a Stręgiel. Ciche, osłonięte lasem, o dzikim charakterze. Idealne dla wędkarzy szukających spokoju i grubego lina. Mała presja wędkarska ze względu na trudny dostęp i bagniste brzegi.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80010, 'Jezioro Jagoczany', 'jezioro-jagoczany', 'LAKE', '54.16420865007514', '21.834896480225456', 'Warmińsko-Mazurskie', 'Pozezdrze', 'Kameralne, bardzo płytkie jezioro przepływowe na szlaku Sapiny. Otoczone podmokłymi łąkami i lasami, stanowi idealną ostoję dla lina i szczupaka. Akwen o dzikim charakterze, rzadko odwiedzany, co gwarantuje ciszę i brak presji wędkarskiej.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80011, 'Jezioro Lamięt', 'jezioro-lamiet', 'LAKE', '54.15772225586252', '21.813107554068754', 'Warmińsko-Mazurskie', 'Pozezdrze', 'Niezwykle dzikie i płytkie jezioro na szlaku Sapiny. Otoczone bagnistymi lasami, stanowi naturalną ostoję ptactwa i ryb. Ze względu na utrudniony dostęp i gęstą roślinność, jest to łowisko dla wędkarzy ceniących ciszę i wyprawy typu survival.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80012, 'Jezioro Harsz', 'jezioro-harsz', 'LAKE', '54.14984646121775', '21.768516176605285', 'Warmińsko-Mazurskie', 'Giżycko', 'Niezwykle czyste jezioro położone w malowniczej okolicy wsi Harsz. Akwen o urozmaiconej linii brzegowej i bardzo przejrzystej wodzie, co czyni go atrakcyjnym dla spinningistów oraz osób szukających spokoju z dala od głównego szlaku Wielkich Jezior.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80013, 'Jezioro Dgał Mały', 'jezioro-dgal-maly', 'LAKE', '54.120538162486945', '21.789255380296904', 'Warmińsko-Mazurskie', 'Giżycko', 'Kameralne, głębokie jezioro otoczone lasem i wzgórzami. Oferuje świetną osłonę przed wiatrem i krystaliczną wodę. Techniczne łowisko, cenione za populację grubego okonia i szczupaka czatującego na stromych, podwodnych spadach.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80014, 'Jezioro Warniak', 'jezioro-warniak', 'LAKE', '54.12202130226602', '21.800651088318936', 'Warmińsko-Mazurskie', 'Giżycko', 'Płytkie, eutroficzne jezioro znane z historycznych badań ichtiologicznych. Otoczone lasami i polami, oferuje doskonałe warunki dla lina i szczupaka. Ze względu na gęstą roślinność i spokój, jest to ulubione miejsce wędkarzy szukających dzikiej natury.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80015, 'Jezioro Sztynorckie', 'jezioro-sztynorckie', 'LAKE', '54.12851485710404', '21.67762562137206', 'Warmińsko-Mazurskie', 'Sztynort', 'Jezioro Sztynorckie to niewielki, ale niezwykle klimatyczny akwen bezpośrednio sąsiadujący z jedną z największych marin na Mazurach – Sztynortem. Jest połączone z jeziorem Łabap wąskim kanałem, przez który do jeziora wpływają duże ryby na tarło i żerowanie. To typowe jezioro eutroficzne, które powoli zarasta, tworząc idealne warunki dla "zielonego" szczupaka, potężnego lina i złotego karasia. Przez swój osłonięty charakter jest doskonałą alternatywą dla wędkarzy, gdy warunki pogodowe uniemożliwiają wypłynięcie na otwarte plosa Mamr. Mimo bliskości portu, wschodnia i północna część jeziora zachowują dziki, niemal bagienny charakter.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80016, 'Jezioro Łabap', 'jezioro-labap', 'LAKE', '54.12298016775049', '21.644561580583595', 'Warmińsko-Mazurskie', 'Sztynort', 'Łabap to akwen łączący Jezioro Dargin z Kirsajtami i Jeziorem Dobskim. Przez wielu wędkarzy nazywany "płytką wersją Darginu". Jest to jezioro o znacznie mniejszej średniej głębokości, co sprawia, że woda nagrzewa się tu znacznie szybciej wiosną, przyciągając ryby na tarło i żerowanie. To absolutne eldorado dla łowców szczupaków metodą castingową i spinningową, szczególnie w pasie podwodnych roślinności. Ze względu na mniejszą ekspozycję na wiatr niż na otwartym Darginie, jest to doskonała alternatywa, gdy na "dużej wodzie" fala staje się zbyt groźna.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80017, 'Jezioro Dobskie', 'jezioro-dobskie', 'LAKE', '54.09874047940773', '21.63134958592376', 'Warmińsko-Mazurskie', 'Giżycko', 'Jezioro Dobskie to ścisły rezerwat przyrody i jedna z najbardziej fascynujących części Mazur. Cały akwen objęty jest strefą ciszy – obowiązuje bezwzględny zakaz używania silników spalinowych (można pływać wyłącznie na silniku elektrycznym lub żaglach). To jezioro o niezwykle surowym, pierwotnym charakterze, z licznymi wyspami (m.in. Wyspa Wysoki Ostrów zwana Wyspą Kormoranów), które są ostojami ptactwa. Ze względu na brak hałasu i mniejszą presję turystyczną, jest to woda dla koneserów, którzy potrafią docenić krystaliczną czystość i bliskość natury.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80018, 'Jezioro Kirsajty', 'jezioro-kirsajty', 'LAKE', '54.144406547192', '21.709322626835615', 'Warmińsko-Mazurskie', 'Węgorzewo', 'Płytki, niezwykle malowniczy łącznik Mamr i Darginu. Raj dla łowców szczupaków z zarośli i medalowych linów. Przez środek biegnie szlak żeglowny, a rozległe trzcinowiska stanowią tarlisko i ostoję ryb. Idealne na spinning bez zaczepów.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80019, 'Jezioro Pniewskie', 'jezioro-pniewskie', 'LAKE', '54.1648321828533', '21.65226726047471', 'Warmińsko-Mazurskie', 'Węgorzewo', 'Niewielkie, spokojne jezioro połączone z Jeziorem Mamry Właściwe. Otoczone lasami i polami, oferuje doskonałe warunki do wędkowania w ciszy, będąc jednocześnie świetną osłoną przed wiatrem szalejącym na dużych jeziorach.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80020, 'Jezioro Mamry (Właściwe)', 'jezioro-mamry-wlasciwe', 'LAKE', '54.17099012601626', '21.69487842184283', 'Warmińsko-Mazurskie', 'Węgorzewo', 'Drugie co do wielkości jezioro w Polsce. Słynie z krystalicznej wody, licznych wysp i ogromnych głębokości. To "Mazurskie Morze" wymaga od wędkarzy respektu – pogoda zmienia się tu błyskawicznie, tworząc wysoką i niebezpieczną falę.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80021, 'Jezioro Węgielsztyńskie', 'jezioro-wegielsztynskie', 'LAKE', '54.232898383886884', '21.62692591470854', 'Warmińsko-Mazurskie', 'Węgorzewo', 'Malownicze, spokojne jezioro położone na północny zachód od Węgorzewa. Otoczone polami i lasami, oferuje ciszę oraz mniejszą presję wędkarską niż Wielkie Jeziora Mazurskie. Idealne dla łowców szczupaków i linów szukających kontaktu z dziką naturą.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80022, 'Jezioro Rydzówka', 'jezioro-rydzowka', 'LAKE', '54.23240736880973', '21.58436484665863', 'Warmińsko-Mazurskie', 'Węgorzewo', 'Malownicze jezioro na szlaku Kanału Mazurskiego. Rezerwat faunistyczny chroniący ptactwo wodne. Akwen o urozmaiconej linii brzegowej z licznymi wyspami, idealny dla wędkarzy szukających dzikiej natury i grubego szczupaka w otoczeniu lasów i pól.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80023, 'Jezioro Silec', 'jezioro-silec', 'LAKE', '54.17789029627609', '21.530422178946306', 'Warmińsko-Mazurskie', 'Srokowo', 'Urokliwe jezioro o dobrze rozwiniętej linii brzegowej, położone w rolniczym krajobrazie Mazur. Znane z czystej wody i bogatej roślinności podwodnej. Idealne miejsce dla spinningistów szukających szczupaka oraz wędkarzy stacjonarnych polujących na lina.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80024, 'Jezioro Siniec Wielki', 'jezioro-siniec-wielki', 'LAKE', '54.15472715767942', '21.525195736165852', 'Warmińsko-Mazurskie', 'Srokowo', 'Płytkie, śródleśne jezioro o dzikim charakterze. Otoczone bagnistymi olsami i polami, oferuje ciszę oraz bardzo małą presję wędkarską. Eldorado dla łowców szczupaków z zarośli oraz złotych karasi i linów w samym sercu mazurskiej dziczy.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80025, 'Jezioro Oświn', 'jezioro-oswin', 'LAKE', '54.291448363309044', '21.580446524269114', 'Warmińsko-Mazurskie', 'Węgorzewo', 'Unikalny akwen w rezerwacie "Jezioro Siedmiu Wysp". Płytkie, zarastające jezioro o dzikim charakterze, ostoja ptactwa wodnego. Ze względu na status rezerwatu i bliskość granicy państwowej, dostęp dla ludzi i wędkarzy jest drastycznie ograniczony.', 'RDOŚ Olsztyn / Nadleśnictwo Srokowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80026, 'Jezioro Święcajty', 'jezioro-swiecajty', 'LAKE', '54.17881982853269', '21.77518366740936', 'Warmińsko-Mazurskie', 'Węgorzewo', 'Głęboka, wschodnia odnoga kompleksu Mamr. Słynie z krystalicznej wody, piaszczystych plaż i dużych głębokości. Akwen o urozmaiconym dnie, idealny dla wędkarzy szukających dużych drapieżników w toni oraz siei na głębokich rynnach i spadach.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80027, 'Jezioro Stręgiel', 'jezioro-stregiel', 'LAKE', '54.18940457677252', '21.83938154671548', 'Warmińsko-Mazurskie', 'Węgorzewo', 'Dzikie i rybne jezioro połączone z rzeką Sapiną. Oaza spokoju z dala od głównych szlaków, słynąca z potężnych linów, szczupaków i sandaczy. Idealne dla wędkarzy ceniących ciszę oraz naturalne, mocno zarośnięte brzegi.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80028, 'Jezioro Rominty', 'jezioro-rominty', 'LAKE', '54.1883285050162', '21.875418003753982', 'Warmińsko-Mazurskie', 'Węgorzewo', 'Kameralne, śródleśne jezioro na szlaku Sapiny. Krystaliczna woda i brak tłumów czynią je idealną metą dla spinningistów. To tutaj rzeka Sapina niesie natlenioną wodę, co sprawia, że ryba jest tu wyjątkowo waleczna i zdrowa.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80029, 'Jezioro Stręgielek', 'jezioro-stregielek', 'LAKE', '54.18012844309377', '21.858128498243676', 'Warmińsko-Mazurskie', 'Węgorzewo', 'Kameralne, śródleśne jezioro na szlaku Sapiny. Otoczone gęstym lasem, charakteryzuje się dzikim brzegiem i dużą ilością roślinności. Idealne dla wędkarzy szukających absolutnego spokoju oraz kontaktu z dziką naturą i pięknymi linami.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80030, 'Jezioro Białe (k. Stręgla)', 'jezioro-biale-stregel', 'LAKE', '54.174790361754425', '21.848509864881287', 'Warmińsko-Mazurskie', 'Węgorzewo', 'Niewielkie, malownicze jezioro na szlaku Sapiny. Otoczone lasami i bagnistymi łąkami, oferuje spokój i doskonałe warunki dla lina oraz szczupaka. Woda o jasnym dnie, co nadaje mu specyficzny charakter w porównaniu do okolicznych, ciemniejszych akwenów.', 'Gospodarstwo Rybackie PZW w Suwałkach');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80031, 'Jezioro Dgał Wielki', 'jezioro-dgal-wielki', 'LAKE', '54.10972478717987', '21.79360259707125', 'Warmińsko-Mazurskie', 'Giżycko', 'Dgał Wielki to łowisko dla wędkarzy świadomych, szukających spokoju i rekordowych drapieżników. Jezioro ma charakter rynnowy z bardzo urozmaiconą konfiguracją dna. Największym atutem akwenu są jego strome spady, które niemal natychmiast od linii trzcin opadają na 5-8 metrów, tworząc idealne warunki dla szczupaków czatujących w zasadzce. Wschodnia część jeziora charakteryzuje się rozległymi blatami z twardym dnem, gdzie jesienią grupują się potężne stada leszcza i płoci, a za nimi podążają grube sandacze.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80032, 'Jezioro Sement Mały', 'jezioro-sement-maly', 'LAKE', '53.67704492642727', '20.006903359313753', 'Warmińsko-Mazurskie', 'Ostróda', 'Sement Mały to zaciszne jezioro leśne (ok. 10 ha). Charakteryzuje się bogatą roślinnością wynurzoną i mulistym dnem. To klasyczne łowisko lina i karasia, rzadko odwiedzane przez turystów, co zapewnia wędkarzom intymność i ciszę pod osłoną drzew.', 'Gospodarstwo Rybackie Ostróda');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80033, 'Jezioro Skarż Wielki', 'jezioro-skarz-wielki', 'LAKE', '54.095680084462316', '21.772786893614803', 'Warmińsko-Mazurskie', 'Giżycko', 'Skarż Wielki to fascynujące jezioro rynnowe, które zachwyca swoją dzikością i czystością wody. Akwen ten charakteryzuje się bardzo dynamicznym ukształtowaniem dna – linia brzegowa jest urozmaicona, a dno w wielu miejscach gwałtownie załamuje się, tworząc głębokie rynny sięgające ponad 25 metrów. Dla wędkarza jest to łowisko "dwóch twarzy". Z jednej strony mamy rozległe, piaszczyste blaty w części północnej i południowej, gdzie wiosną w słońcu wygrzewają się stada płoci i wzdręg, a za nimi podążają szczupaki. Z drugiej strony, centralna część jeziora to głęboka toń, w której królują sielawa i sieja.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80034, 'Jezioro Fryd', 'jezioro-fryd', 'LAKE', '54.07873715535922', '21.75495250279718', 'Warmińsko-Mazurskie', 'Giżycko', 'Jezioro Fryd to prawdziwa "dzika enklawa" dla wędkarzy szukających ucieczki od motorowodnego zgiełku Wielkich Jezior Mazurskich. Akwen ten, choć niewielki, posiada unikalny ekosystem typowy dla jezior zanikających, co czyni go wyjątkowo atrakcyjnym pod kątem ryb spokojnego żeru. Ze względu na małą głębokość, woda nagrzewa się tu błyskawicznie, co sprawia, że wegetacja roślinna rusza z kopyta już wczesną wiosną, a ryby wykazują dużą aktywność.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80035, 'Jezioro Niegocin', 'jezioro-niegocin', 'LAKE', '54.00254744579695', '21.77817710532732', 'Warmińsko-Mazurskie', 'Giżycko', 'Jezioro Niegocin to trzeci pod względem wielkości akwen w Krainie Wielkich Jezior Mazurskich i jeden z najważniejszych punktów na żeglarskim szlaku. Powierzchnia przekraczająca 2600 hektarów oraz maksymalna głębokość sięgająca blisko 40 metrów sprawiają, że jest to jezioro o ogromnym potencjale wędkarskim, ale i wymagające dużej pokory. Charakterystyczną cechą Niegocina jest niezwykle urozmaicone dno – mimo dużej głębokości średniej, akwen usiany jest licznymi mieliznami i podwodnymi górkami, które są "bankowymi" miejscówkami dla drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80036, 'Jezioro Arwiny', 'jezioro-arwiny', 'LAKE', '53.68379031957651', '21.064665835645314', 'Warmińsko-Mazurskie', 'Dźwierzuty', 'Jezioro Arwiny to niewielki, urokliwy akwen o powierzchni około 14 hektarów, położony w pagórkowatym terenie na północ od jeziora Łęsk. W przeciwieństwie do swoich głębokich sąsiadów, Arwiny są zbiornikiem stosunkowo płytkim i wybitnie eutroficznym. Jezioro otaczają malownicze łąki i fragmenty lasów, a linia brzegowa jest miękka i w znacznej mierze niedostępna z lądu. Woda ma tu specyficzny, żyzny charakter, co sprzyja bujnej wegetacji roślinności podwodnej, tworzącej gęste "podwodne dżungle".
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80037, 'Jezioro Wałpusz', 'jezioro-walpusz', 'LAKE', '53.5989783977777', '21.07176097674083', 'Warmińsko-Mazurskie', 'Szczytno', 'Jezioro Wałpusz to okazały akwen rynnowy o powierzchni około 436 hektarów, położony zaledwie kilka kilometrów na wschód od Szczytna. Jezioro charakteryzuje się wydłużonym kształtem i dość urozmaiconą linią brzegową, którą uatrakcyjniają liczne półwyspy oraz szeroki pas trzcin. Otoczenie akwenu to malownicza mozaika lasów iglastych (od strony wschodniej) oraz pól i terenów rekreacyjnych (od zachodu). Woda w Wałpuszu ma charakter eutroficzny, co przekłada się na jej umiarkowaną przejrzystość i dużą żyzność, sprzyjającą szybkim przyrostom ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80038, 'Jezioro Rudzkie', 'jezioro-rudzkie', 'LAKE', '53.99234263832638', '21.85063498059038', 'Warmińsko-Mazurskie', 'Giżycko', 'Jezioro Rudzkie to klasyczny przykład mazurskiej rynny polodowcowej, która zachowała swój dziki i naturalny charakter mimo bliskości dużych ośrodków turystycznych. Akwen ten, o powierzchni nieco ponad 60 hektarów, jest otoczony przez malownicze wzgórza morenowe, pola oraz pasy lasu, co tworzy wyjątkowo kameralną atmosferę. Jezioro jest połączone szerokim przesmykiem z jeziorem Wojnowo, co sprawia, że rybostan obu zbiorników jest ze sobą ściśle powiązany.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80039, 'Jezioro Grajewko', 'jezioro-grajewko', 'LAKE', '54.0123048715159', '21.819033859002275', 'Warmińsko-Mazurskie', 'Giżycko', 'Jezioro Grajewko (nazywane również jeziorem Grajwo) to urokliwy, kameralny akwen typu polodowcowego, położony zaledwie 4 kilometry na południe od Giżycka. Jezioro ma charakterystyczny rynnowy kształt i jest połączone z jeziorem Niegocin niewielkim kanałem, co teoretycznie umożliwia migrację ryb między tymi zbiornikami. Jest to łowisko o typowo leszczowo-szczupakowej charakterystyce, otoczone malowniczymi pagórkami morenowymi, polami uprawnymi oraz rozległymi łąkami. Dzięki takiemu położeniu, woda jest tu osłonięta od najsilniejszych wiatrów, co czyni Grajewko bezpiecznym miejscem na wyprawy pontonem lub mniejszą łodzią.', 'Bogusław Wyszyński');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80040, 'Jezioro Kąpskie', 'jezioro-kapskie', 'LAKE', '54.01356465048786', '21.847654991756357', 'Warmińsko-Mazurskie', 'Giżycko', 'Jezioro Kąpskie, położone w bezpośrednim sąsiedztwie miejscowości Kąp, to urokliwy i niezwykle żyzny akwen o charakterze stawowym. Jest to jezioro bardzo płytkie, którego średnia głębokość oscyluje wokół 1 metra, co sprawia, że woda nagrzewa się tu błyskawicznie, stymulując intensywny rozwój roślinności zanurzonej i wynurzonej. Dla wędkarza Kąpskie to prawdziwe wyzwanie techniczne – jezioro jest niemal w całości otoczone szerokim i bagnistym pasem trzcin, co praktycznie uniemożliwia wędkowanie z brzegu bez specjalistycznego przygotowania lub korzystania z nielicznych kładek.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80041, 'Jezioro Upałckie Małe', 'jezioro-upalckie-male', 'LAKE', '54.00954461925296', '21.863225698332155', 'Warmińsko-Mazurskie', 'Giżycko', 'Jezioro Upałckie Małe to niezwykle kameralny, niemal ukryty akwen rynnowy, stanowiący mniejszą część kompleksu jezior w okolicach miejscowości Upałty. Jest to łowisko o wybitnie dzikim charakterze, rzadko odwiedzane przez turystów, co czyni je idealną enklawą dla wędkarzy szukających absolutnej ciszy. Akwen charakteryzuje się bardzo rozwiniętą roślinnością wynurzoną – szerokie pasy trzcin i tataraku niemal całkowicie odcinają dostęp do lustra wody z lądu, przez co jezioro zachowało swój pierwotny, naturalny ekosystem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80042, 'Jezioro Upałckie Wielkie', 'jezioro-upalckie-wielkie', 'LAKE', '54.0036978381168', '21.860617726695477', 'Warmińsko-Mazurskie', 'Giżycko', 'Jezioro Upałckie Wielkie to malowniczy akwen rynnowy, który stanowi serce wędkarskiego mikrosystemu w okolicach wsi Upałty. W odróżnieniu od swojej mniejszej części, Upałckie Wielkie posiada wyraźniej zarysowaną rynnę i nieco twardsze partie dna w strefie przybrzeżnej, co czyni je łowiskiem bardziej różnorodnym. Jezioro jest otoczone łagodnymi wzniesieniami, polami i kępami drzew, co zapewnia doskonałą osłonę przed wiatrem i sprawia, że woda niemal zawsze jest tu spokojna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80043, 'Jezioro Mielno', 'jezioro-mielno-brodnickie', 'LAKE', '53.23965604979646', '19.302722853249026', 'Kujawsko-Pomorskie', 'Brodnica', 'Jezioro Mielno (Brodnickie) to urokliwy, wydłużony akwen rynnowy o powierzchni ok. 12 ha. Jest ono połączone systemem cieków z jeziorem Chojno. Jezioro otaczają malownicze wzgórza i lasy, a woda charakteryzuje się średnią żyznością. To klasyczne łowisko linowo-szczupakowe, cenione przez lokalnych wędkarzy za ciszę i bardzo dobre wyniki w połowie lina metodami spławikowymi.', 'Gospodarstwo Rybackie w Ostródzie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80044, 'Jezioro Wojnowo', 'jezioro-wojnowo', 'LAKE', '53.95858582265304', '21.844873541611804', 'Warmińsko-Mazurskie', 'Giżycko', 'Jezioro Wojnowo to imponująca rynna polodowcowa, ciągnąca się na długości ponad 4,5 kilometra. Akwen ten jest niezwykle istotny z punktu widzenia hydrologicznego, gdyż łączy system Niegocina (przez jezioro Niałk) z długą rynną jeziora Buwełno. Wojnowo charakteryzuje się bardzo rozwiniętą linią brzegową oraz dnem o zróżnicowanej konfiguracji, gdzie twarde, piaszczysto-gliniaste blaty przeplatają się z głębszymi partiami rynnowymi. Otoczenie jeziora stanowią głównie pola uprawne, łąki i malownicze nieużytki, co sprawia, że woda jest tu zasobna w składniki odżywcze, sprzyjające szybkim przyrostom ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80045, 'Jezioro Miłkowskie', 'jezioro-milkowskie', 'LAKE', '53.941304980270026', '21.870880079919942', 'Warmińsko-Mazurskie', 'Miłki', 'Jezioro Miłkowskie (Miłki) to klasyczny zbiornik rynnowy, który stanowi ważny element hydrologiczny łączący system jeziora Wojnowo z rynną jeziora Buwełno. Akwen ten charakteryzuje się dość stromymi spadami brzegowymi, które w części centralnej gwałtownie opadają do głębokiej rynny. Otoczenie jeziora to głównie pola uprawne i zabudowania miejscowości Miłki, co wpływa na wysoką żyzność wody (eutrofię) i sprzyja szybkiemu przyrostowi masy u ryb spokojnego żeru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80046, 'Jezioro Buwełno', 'jezioro-buwelno', 'LAKE', '53.88153609107177', '21.863905809392556', 'Warmińsko-Mazurskie', 'Miłki', 'Jezioro Buwełno to potężna rynna polodowcowa, która zachwyca swoją dzikością i surowym krajobrazem. Akwen ten jest niezwykle wąski (średnio około 300-400 metrów szerokości), ale nadrabia to swoją długością i głębokością. Brzegi jeziora są przeważnie wysokie, strome, a miejscami wręcz urwiste, porośnięte gęstymi lasami lub stanowiące malownicze pastwiska. Ze względu na swój rynnowy charakter, dno jeziora opada bardzo gwałtownie – niemal bezpośrednio od linii trzcin zaczynają się stoki schodzące na 5, 10, a nawet 20 metrów głębokości.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80047, 'Jezioro Ublik Mały', 'jezioro-ublik-maly', 'LAKE', '53.88510162822899', '21.90505472122332', 'Warmińsko-Mazurskie', 'Miłki', 'Jezioro Ublik Mały to prawdziwa oaza spokoju, ukryta wśród pagórków morenowych i lasów w pobliżu miejscowości Ublik. Akwen ten jest połączony wąskim, malowniczym przesmykiem z większym jeziorem Ublik Wielki, jednak jego charakter jest zgoła odmienny. Jest to jezioro bardzo płytkie, o silnie zamulonym dnie i krystalicznej wodzie w okresach wiosennych, która latem przybiera intensywny zielony odcień ze względu na bogate życie biologiczne. Brzegi jeziora są w większości niedostępne – bagniste i porośnięte gęstą olszyną oraz szerokim pasem trzcin, co sprawia, że jest to łowisko wybitnie "pontonowe".
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80048, 'Jezioro Leśne', 'jezioro-lesne', 'LAKE', '53.67378264599476', '19.103014935716697', 'Pomorskie', 'Kwidzyn', 'Jezioro Leśne to urokliwy, śródleśny zbiornik o powierzchni około 15 hektarów, położony w kompleksie leśnym na północ od Gardei. Jak sama nazwa wskazuje, akwen jest niemal całkowicie otoczony gęstym borem, co zapewnia mu status łowiska wybitnie zacisznego i osłoniętego od wiatru. Woda ma lekko brunatny odcień, co jest typowe dla jezior dystroficznych otoczonych lasem iglastym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80049, 'Jezioro Ublik Wielki', 'jezioro-ublik-wielki', 'LAKE', '53.89723394071584', '21.88669182034021', 'Warmińsko-Mazurskie', 'Miłki', 'Jezioro Ublik Wielki to potężna rynna polodowcowa, która wraz z Ublikiem Małym tworzy jeden z najbardziej malowniczych kompleksów jeziornych wschodnich Mazur. Akwen charakteryzuje się wysokimi, pagórkowatymi, a miejscami bardzo stromymi brzegami, które są w większości bezleśne, co zapewnia doskonały wgląd w urozmaiconą linię brzegową z licznymi zatokami (szczególnie w części wschodniej). Jezioro jest połączone wąskim kanałem z jeziorem Buwełno oraz przepustem pod nasypem kolejowym z Ublikiem Małym. Woda w Ubliku Wielkim jest bardzo czysta, co pozwala na rozwój bogatych łąk podwodnych sięgających znacznych głębokości.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80050, 'Jezioro Stoczek', 'jezioro-stoczek', 'LAKE', '53.86918311141967', '21.936498886253652', 'Warmińsko-Mazurskie', 'Miłki', 'Jezioro Stoczek to kwintesencja mazurskiej dziczy. Jest to akwen o charakterze wybitnie eutroficznym, powoli ustępujący procesom sukcesji, co czyni go rajem dla gatunków ryb kochających muł, ciepłą wodę i gęstą roślinność. Jezioro jest niemal całkowicie odizolowane od cywilizacji – otoczone pierścieniem podmokłych lasów i bagien, co sprawia, że dostęp do lustra wody jest ekstremalnie trudny i wymaga od wędkarza niemal survivalowego zacięcia. Woda w Stoczku ma charakterystyczny, ciemny, torfowy odcień, a jej tafla przez większą część roku jest osłonięta od wiatru przez wysokie korony drzew.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80051, 'Jezioro Błękitne', 'jezioro-blekitne', 'LAKE', '53.854881856696906', '21.952133081791295', 'Warmińsko-Mazurskie', 'Miłki', 'Jezioro Błękitne to unikalny akwen rynnowy o charakterze śródleśnym, który zachwyca krystaliczną czystością wody i surowym, naturalnym pięknem. Położone w głębokiej niecce, otoczone gęstym lasem sosnowo-świerkowym, jest doskonale osłonięte od wiatru, co sprawia, że tafla wody niemal zawsze jest tu gładka. Jezioro charakteryzuje się bardzo urozmaiconą rzeźbą dna – mimo niewielkiej powierzchni, dno gwałtownie opada, tworząc strome stoki i głębokie rynny. Wysoka przejrzystość wody sprawia, że roślinność podwodna rozwija się tu do znacznych głębokości, tworząc podwodne lasy ramienic.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80052, 'Jezioro Przylesie', 'jezioro-przylesie', 'LAKE', '53.8522025995163', '21.95934896761507', 'Warmińsko-Mazurskie', 'Miłki', 'Jezioro Przylesie to mały, śródleśny klejnot ukryty w głębokiej niecce terenu na południowy wschód od miejscowości Cierzpięty. Akwen ten, ze względu na swoje odizolowanie i otoczenie gęstym borem, jest niemal całkowicie odcięty od cywilizacyjnego zgiełku. Jezioro charakteryzuje się bardzo miękkim, torfowym dnem oraz wodą o lekko brunatnym zabarwieniu (typowym dla jezior o charakterze dystroficznym), co sprawia, że jest to łowisko o specyficznym mikroklimacie. Brzegi jeziora są strome i w większości bagniste, co sprawia, że dostęp do lustra wody z lądu jest niezwykle utrudniony i wymaga od wędkarza dużej determinacji.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80053, 'Jezioro Prątynia', 'jezioro-pratynia', 'LAKE', '53.41322490907676', '19.248674850981324', 'Kujawsko-Pomorskie', 'Jabłonowo Pomorskie', 'Jezioro Prątynia to niewielkie, niemal całkowicie otoczone lasem jezioro rynnowe. Jest to jedno z najbardziej zacisznych łowisk w regionie, charakteryzujące się ciemniejszą barwą wody i dużą ilością powalonych do wody drzew, które stanowią doskonałe kryjówki dla ryb. Jezioro ma charakter linowo-szczupakowy z dużą ilością drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80054, 'Jezioro Kepłaste', 'jezioro-keplaste', 'LAKE', '53.850188562960284', '21.96555552861583', 'Warmińsko-Mazurskie', 'Miłki', 'Jezioro Kepłaste to niewielki, śródleśny akwen o charakterze eutroficznym, niemal całkowicie ukryty w gęstym kompleksie leśnym na południowy wschód od Miłek. Akwen ten jest kwintesencją mazurskiej dziczy – otoczony pasem podmokłych olszyn, bagien i wysokich trzcinowisk, stanowi trudne wyzwanie dla każdego, kto chce dotrzeć do jego brzegów. Woda w Kepłastem charakteryzuje się dużą żyznością, co w połączeniu z małą głębokością i osłonięciem od wiatru sprawia, że jest to klasyczne "jezioro-cieplarniane", gdzie wegetacja roślinna i rozwój ryb przebiegają bardzo intensywnie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80055, 'Jezioro Rzęśnik', 'jezioro-rzesnik', 'LAKE', '53.841827813084436', '21.97623749433093', 'Warmińsko-Mazurskie', 'Miłki', 'Jezioro Rzęśnik to klasyczny przykład mazurskiego "oczka leśnego" o wysokim stopniu eutrofizacji. Położone w głębokim leśnym obniżeniu, jest niemal całkowicie osłonięte od wiatru, co sprawia, że tafla wody przez większą część roku pozostaje nieruchoma, sprzyjając rozwojowi rzęsy wodnej oraz roślinności pływającej. Akwen charakteryzuje się bardzo grubą warstwą osadów dennych (mułu i torfu) oraz ciemnym, herbacianym kolorem wody, co nadaje mu aurę tajemniczości. Brzegi jeziora są bagniste, trudne do przebycia i w większości niedostępne bez woderów lub pontonu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80056, 'Jezioro Orzysz', 'jezioro-orzysz', 'LAKE', '53.83388304896585', '22.023429295196113', 'Warmińsko-Mazurskie', 'Orzysz', 'Jezioro Orzysz to potężny i niezwykle urozmaicony akwen, który dla wielu wędkarzy stanowi synonim mazurskiej przygody. Charakteryzuje się wyjątkowo rozwiniętą linią brzegową z licznymi półwyspami, zatokami (z których największa to Zatoka Wierzbińska) oraz dziesięcioma wyspami, które stanowią naturalne punkty orientacyjne i doskonałe miejsca do poszukiwania ryb. Dno jeziora to prawdziwy labirynt – liczne podwodne górki, gwałtowne uskoky i głębokie rynny sięgające 36 metrów sprawiają, że bez echosondy i dobrej mapy batymetrycznej trudno tu o sukces. Woda w Orzyszu jest stosunkowo czysta, co sprzyja rozwojowi bogatych łąk ramienicowych i rdestnic.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80057, 'Jezioro Wierzbińskie', 'jezioro-wierzbinskie', 'LAKE', '53.79563806485998', '21.967642796835914', 'Warmińsko-Mazurskie', 'Orzysz', 'Jezioro Wierzbińskie to urokliwy i niezwykle rybny akwen rynnowy, stanowiący południowo-zachodnie przedłużenie Jeziora Orzysz. Dzięki bezpośredniemu połączeniu z tym wielkim jeziorem, Wierzbińskie charakteryzuje się ciągłą migracją ryb, co sprawia, że rybostan jest tu niezwykle dynamiczny i różnorodny. Jezioro otoczone jest malowniczymi pagórkami, polami oraz zabudowaniami miejscowości Wierzbiny. W odróżnieniu od głównego plosa Orzysza, Wierzbińskie jest znacznie lepiej osłonięte od wiatru, co czyni je bezpieczną przystanią dla wędkarzy łowiących z mniejszych łodzi i pontonów nawet podczas niesprzyjającej aury.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80058, 'Jezioro Płoczenko', 'jezioro-ploczenko', 'LAKE', '53.40082474009674', '19.27430579357695', 'Kujawsko-Pomorskie', 'Jabłonowo Pomorskie', 'Jezioro Płoczenko to kameralny zbiornik położony w pobliżu miejscowości Płoczeń. Jest to typowe jezioro polne o charakterze linowym, z bardzo bogato rozwiniętą roślinnością wynurzoną. Woda jest żyzna i ciepła, co sprawia, że ryby rosną tu szybko. Jezioro otaczają łąki i pola, co zapewnia bardzo dobrą widoczność i nasłonecznienie łowiska.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80059, 'Jezioro Strzelniki', 'jezioro-strzelniki', 'LAKE', '53.81090368668208', '22.03383641858184', 'Warmińsko-Mazurskie', 'Orzysz', 'Jezioro Strzelniki to kameralny, śródpolny akwen o powierzchni około 20 hektarów, położony w bezpośrednim sąsiedztwie miejscowości Strzelniki, tuż przy trasie Orzysz-Ełk. Jest to typowe jezioro eutroficzne o charakterze linowo-szczupakowym, które ze względu na swoją żyzność i małą głębokość stanowi doskonałe środowisko dla ryb ciepłolubnych. Akwen charakteryzuje się regularną linią brzegową i misowatym dnem, które w większości pokryte jest grubą warstwą osadów organicznych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80060, 'Jezioro Rostki', 'jezioro-rostki', 'LAKE', '53.80538113298135', '22.07466269893741', 'Warmińsko-Mazurskie', 'Orzysz', 'Jezioro Rostki to jeden z ciekawszych akwenów rynnowych w okolicach Orzysza, charakteryzujący się znaczną głębokością i krystaliczną czystością wody. Akwen ten jest niemal idealnie wpisany w polodowcową rynnę, co determinuje jego kształt oraz ukształtowanie dna. Brzegi jeziora są przeważnie wysokie i suche, otoczone polami i łąkami, co zapewnia wędkarzom doskonałe warunki do obserwacji lustra wody. Największym atutem Rostek są strome stoki, które niemal natychmiast od linii trzcin opadają na głębokość 5-10 metrów, tworząc idealne warunki dla drapieżników czatujących na sielawę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80061, 'Jezioro Kraksztyn', 'jezioro-kraksztyn', 'LAKE', '53.79691869412164', '22.109652672386446', 'Warmińsko-Mazurskie', 'Orzysz', 'Jezioro Kraksztyn to urokliwy, śródpolny akwen o powierzchni około 16 hektarów, stanowiący część malowniczego pojezierza w okolicach Skomacka Wielkiego. Jest to jezioro o charakterze wybitnie zacisznym, otoczone pasem łąk i niewielkich zadrzewień, co sprawia, że woda jest tu doskonale osłonięta od porywistych wiatrów. Akwen charakteryzuje się regularną, misowatą niecką dna i dużą żyznością wody, co sprzyja intensywnemu rozwojowi roślinności podwodnej i wynurzonej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80062, 'Jezioro Druglin Duży', 'jezioro-druglin-duzy', 'LAKE', '53.81531641214695', '22.142180938689787', 'Warmińsko-Mazurskie', 'Orzysz', 'Jezioro Druglin Duży to rozległy, płytki akwen o charakterze wybitnie eutroficznym, położony w malowniczej niecce pośród pól i nieużytków w okolicach Skomacka Wielkiego. Jezioro to jest kwintesencją mazurskich łowisk linowo-szczupakowych – charakteryzuje się bardzo rozwiniętą roślinnością przybrzeżną oraz miękkim, zasobnym w materię organiczną dnem. Powierzchnia jeziora jest systematycznie ograniczana przez postępującą sukcesję roślinną, co tworzy idealne warunki dla gatunków ryb kochających ciepłą, płytką wodę i gęste podwodne lasy moczarki.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80063, 'Jezioro Płociczno', 'jezioro-plociczno', 'LAKE', '53.40402035816945', '19.279479905519135', 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Jezioro Płociczno to kameralny, rynnowy zbiornik o powierzchni ok. 18 ha, stanowiący bramę do kompleksu jezior Brodnickiego Parku Krajobrazowego. Jezioro charakteryzuje się dość czystą wodą i urozmaiconą linią brzegową, otoczoną w dużej mierze lasami. Jest połączone wąskim ciekiem z sąsiednim jeziorem Głowińskim. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80064, 'Jezioro Lipińskie', 'jezioro-lipinskie', 'LAKE', '53.77598123985033', '22.163286965653867', 'Warmińsko-Mazurskie', 'Ełk', 'Jezioro Lipińskie to kameralny zbiornik wodny o powierzchni około 25 hektarów, położony w malowniczej, pagórkowatej okolicy pośród pól uprawnych i nielicznych zagajników. Akwen charakteryzuje się dość regularną linią brzegową oraz misowatym kształtem niecki. Woda w jeziorze jest żyzna, co sprzyja intensywnemu rozwojowi flory i fauny. Brzegi jeziora są w większości niskie i otoczone pasem roślinności szuwarowej, co w połączeniu z miękkim dnem tworzy idealne warunki dla ryb ciepłolubnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80065, 'Jezioro Kępno', 'jezioro-kepno', 'LAKE', '53.76918382724168', '22.10631013736656', 'Warmińsko-Mazurskie', 'Orzysz', 'Jezioro Kępno to niewielki, śródleśny i mocno odizolowany akwen położony w malowniczej dolinie na południowy wschód od jeziora Orzysz. Jest to klasyczne jezioro o charakterze dystroficznym, powoli ustępujące procesom naturalnej sukcesji, co czyni je łowiskiem niezwykle dzikim i trudnym technicznie. Woda w jeziorze ma charakterystyczny, ciemny, herbaciany odcień ze względu na dużą zawartość substancji huminowych. Brzegi są w większości bagniste, trzęsawiskowe i porośnięte gęstą olszyną, co sprawia, że dostęp do lustra wody jest możliwy jedynie w kilku punktach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80066, 'Jezioro Zdedy', 'jezioro-zdedy', 'LAKE', '53.759081172234026', '22.17761783860989', 'Warmińsko-Mazurskie', 'Ełk', 'Jezioro Zdedy to jeden z najbardziej cenionych akwenów pojezierza ełckiego, słynący wśród spinningistów z populacji wyjątkowo dorodnych szczupaków. Jest to jezioro rynnowe o charakterze eutroficznym, charakteryzujące się bardzo urozmaiconą linią brzegową z licznymi zatokami i półwyspami, co stwarza niemal nieograniczone możliwości dla wędkarzy poszukujących drapieżników. Akwen otaczają malownicze wzgórza morenowe, pola oraz niewielkie kompleksy leśne. Woda w jeziorze jest żyzna, co sprzyja rozwojowi bogatych łąk podwodnych oraz szerokich pasów trzcinowisk, które stanowią doskonałe schronienie dla ryb spokojnego żeru i bazę wypadową dla drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80067, 'Jezioro Kocioł', 'jezioro-kociol', 'LAKE', '53.721084959570526', '21.859198362511762', 'Warmińsko-Mazurskie', 'Pisz', 'Jezioro Kocioł to głęboki akwen rynnowy położony w gminie Pisz, niedaleko miejscowości Kocioł Duży i Kociołek Szlachecki. Jezioro charakteryzuje się bardzo czystą wodą i urozmaiconą rzeźbą dna, co czyni je jednym z najciekawszych łowisk w regionie dla zwolenników głębokiego spinningu. Akwen posiada strome stoki, które gwałtownie opadają do głębokiej rynny centralnej. Otoczenie jeziora to głównie pola uprawne i łąki, co zapewnia dobrą dostępność do linii brzegowej, choć strome skarpy mogą stanowić wyzwanie przy wodowaniu większych jednostek.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80068, 'Jezioro w Mątkach', 'jezioro-w-matkach', 'LAKE', '53.84902586855951', '18.994094009795678', 'Pomorskie', 'Sztum', 'Jezioro w Mątkach (Jezioro Mątki) to niewielki, ukryty pośród pól i zagajników akwen na południe od Sztumu. Jest to łowisko o charakterze wybitnie dzikim, rzadko odwiedzane przez przyjezdnych wędkarzy. Jezioro charakteryzuje się czystą wodą i dość twardym dnem w wielu miejscach, co odróżnia je od typowych mulistych oczek polnych. Otoczenie jest ciche, pozbawione infrastruktury turystycznej, co czyni je idealną metą na samotną wyprawę "z doskoku".
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80069, 'Jezioro Białoławki', 'jezioro-bialolawki', 'LAKE', '53.736718974421336', '21.824104771586484', 'Warmińsko-Mazurskie', 'Pisz', 'Jezioro Białoławki to głębokie i czyste jezioro rynnowe położone w gminie Pisz, stanowiące istotny element systemu hydrologicznego łączącego mniejsze akweny z kompleksem jeziora Śniardwy (poprzez rzekę Wincentę i jezioro Kocioł). Akwen charakteryzuje się typową dla rynien polodowcowych wydłużoną niecką, stromymi spadami brzegowymi oraz znacznymi głębokościami sięgającymi ponad 30 metrów. Brzegi jeziora są przeważnie wysokie, suche, otoczone polami i łąkami, co zapewnia dobrą dostępność, choć strome zejścia do wody mogą wymagać uwagi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80070, 'Jezioro Śniardwy', 'jezioro-sniardwy', 'LAKE', '53.76375272157345', '21.73491534104601', 'Warmińsko-Mazurskie', 'Pisz', 'Jezioro Śniardwy, nazywane "Mazurskim Morzem", to największe jezioro w Polsce, stanowiące serce Krainy Wielkich Jezior Mazurskich. Akwen ten charakteryzuje się ogromną otwartą przestrzenią, która przy silnych wiatrach staje się ekstremalnie niebezpieczna ze względu na krótką, stromą falę. Śniardwy są jeziorem polodowcowym o stosunkowo niewielkiej średniej głębokości, ale o niezwykle urozmaiconym i niebezpiecznym dnie, usianym tysiącami głazów narzutowych i kamienisk, które sięgają tuż pod powierzchnię wody (szczególnie w rejonie wysp Czarci Ostrów i Szeroki Ostrów). Brzegi jeziora są przeważnie niskie, bagniste i porośnięte szerokim pasem trzcin, co czyni je trudno dostępnymi z lądu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80071, 'Jezioro Seksty', 'jezioro-seksty', 'LAKE', '53.69491507527883', '21.766300619229142', 'Warmińsko-Mazurskie', 'Pisz', 'Jezioro Seksty to rozległy, stosunkowo płytki akwen stanowiący południową część kompleksu Śniardw. Ze względu na swoje położenie i charakter, Seksty są często traktowane jako bezpieczna przystań dla żeglarzy i wędkarzy podczas silnych wiatrów na "Mazurskim Morzu", gdyż fale są tu znacznie mniejsze. Jezioro charakteryzuje się bardzo rozwiniętą roślinnością wynurzoną – szerokie pasy trzcin otaczają niemal całą linię brzegową, tworząc labirynt zatoczek i przesmyków. Dno jest w przeważającej części piaszczysto-muliste, o łagodnym ukształtowaniu, z nielicznymi głębszymi rynnami w centralnej części.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80072, 'Jezioro Głowińskie', 'jezioro-glowinskie', 'LAKE', '53.40657579037833', '19.31086448270766', 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Jezioro Głowińskie to potężna rynna o powierzchni ok. 130 ha, znana z krystalicznie czystej wody i znacznych głębokości (do 18 m). Akwen jest niemal w całości otoczony borami sosnowymi, co nadaje mu niezwykle dziki charakter. Jezioro jest połączone z jeziorem Łąkorz, co zapewnia migrację ryb. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80073, 'Jezioro Wiartel', 'jezioro-wiartel', 'LAKE', '53.60027574053467', '21.69475465044898', 'Warmińsko-Mazurskie', 'Pisz', 'Jezioro Wiartel to jeden z najbardziej klimatycznych akwenów Puszczy Piskiej, charakteryzujący się niezwykle rozwiniętą linią brzegową, która tworzy labirynt półwyspów, wysp i głębokich zatok. Akwen ten składa się z dwóch głównych części połączonych przewężeniem, a jego wschodnia odnoga przechodzi w jezioro Przylasek. Wiartel jest otoczony gęstymi borami sosnowymi, co zapewnia doskonałą osłonę od wiatru i tworzy aurę intymności. Dno jeziora jest bardzo urozmaicone – liczne podwodne górki, gwałtowne spady rynnowe oraz rozległe piaszczyste blaty czynią je łowiskiem niezwykle atrakcyjnym dla wędkarzy poszukujących różnorodnych gatunków ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80074, 'Jezioro Jegocin', 'jezioro-jegocin', 'LAKE', '53.66674115179402', '21.690566287106343', 'Warmińsko-Mazurskie', 'Pisz', 'Jezioro Jegocin to jeden z najpiękniejszych i najczystszych akwenów Puszczy Piskiej, położony w całkowitym odosobnieniu od głównych szlaków turystycznych. Jest to jezioro o wyjątkowych walorach przyrodniczych, charakteryzujące się krystalicznie czystą wodą (często o przejrzystości przekraczającej 5 metrów) oraz wysokimi, zalesionymi brzegami, które nadają mu niemal górski charakter. Akwen jest objęty całkowitą strefą ciszy, co w połączeniu z jego śródleśnym położeniem tworzy unikalne warunki do spokojnego wędkowania. Dno jeziora jest bardzo urozmaicone, z licznymi głęboczkami sięgającymi ponad 30 metrów oraz stromymi stokami, które są porośnięte rzadkimi gatunkami roślinności podwodnej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80075, 'Jezioro Niecponek', 'jezioro-niecponek', 'LAKE', '53.657869986225606', '21.71217547709648', 'Warmińsko-Mazurskie', 'Pisz', 'Jezioro Niecponek (znane również jako Niećpionek) to mały, śródleśny akwen ukryty w samym sercu Puszczy Piskiej, nieopodal jeziora Jegocin. Jest to łowisko o wybitnie dzikim i kameralnym charakterze, otoczone gęstym borem sosnowo-świerkowym, który niemal całkowicie izoluje je od cywilizacji. Jezioro charakteryzuje się wodą o lekko brunatnym, huminowym zabarwieniu oraz bardzo miękkim, torfowym dnem. Ze względu na swoje położenie w niecce leśnej, tafla wody jest tu niemal zawsze idealnie gładka, co sprzyja rozwojowi roślinności pływającej, w tym rozległych pól grążeli.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80076, 'Jezioro Jegocinek', 'jezioro-jegocinek', 'LAKE', '53.6510131595235', '21.705025929847885', 'Warmińsko-Mazurskie', 'Pisz', 'Jezioro Jegocinek to urokliwy, śródleśny akwen stanowiący południowe dopełnienie grupy jezior jegocińskich w sercu Puszczy Piskiej. Jest to typowe jezioro o charakterze dystroficznym, niemal całkowicie otoczone gęstym borem iglastym i podmokłymi brzezinami. Woda w Jegocinku posiada charakterystyczny, ciemnoherbaciany odcień, wynikający z dużej zawartości kwasów huminowych wymywanych z otaczających go torfowisk. Akwen ten jest niezwykle spokojny, osłonięty od wiatru i objęty strefą ciszy, co sprawia, że jest idealnym miejscem dla wędkarzy szukających absolutnego odosobnienia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80077, 'Jezioro Brzozolasek', 'jezioro-brzozolasek', 'LAKE', '53.61595422317581', '21.73755626189736', 'Warmińsko-Mazurskie', 'Pisz', 'Jezioro Brzozolasek to malowniczy, rynnowy akwen o powierzchni blisko 160 hektarów, usytuowany w głębokiej leśnej niecce. Charakteryzuje się bardzo czystą wodą i urozmaiconą linią brzegową, która w części zachodniej i południowej opada spadzistymi, zalesionymi skarpami, natomiast na północy przechodzi w łagodne, płaskie tereny. Jezioro słynie z ciszy i spokoju – ze względu na brak dużych ośrodków motorowodnych bezpośrednio nad brzegiem, jest to idealne miejsce dla wędkarzy ceniących kameralną atmosferę. Dno zbiornika jest piaszczysto-muliste, a w osi jeziora ciągnie się wyraźna rynna z głębokościami przekraczającymi 17 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80078, 'Jezioro Morawy', 'jezioro-morawy', 'LAKE', '53.692698780430696', '19.124129597233644', 'Pomorskie', 'Kwidzyn', 'Jezioro Morawy to urokliwy zbiornik śródpolny położony w pobliżu miejscowości Morawy. Jest to jezioro o charakterze eutroficznym, otoczone malowniczymi pagórkami i polami uprawnymi. Woda ma zielonkawy odcień, co świadczy o jej dużej żyzności. Jezioro jest stosunkowo spokojne, rzadko odwiedzane przez turystów z zewnątrz, co czyni je doskonałą metą dla lokalnych wędkarzy szukających spokoju.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80079, 'Jezioro Starokiejkuckie', 'jezioro-starokiejkuckie', 'LAKE', '53.62857330470803', '21.070690105517006', 'Warmińsko-Mazurskie', 'Szczytno', 'Jezioro Starokiejkuckie to malowniczy zbiornik rynnowy o powierzchni około 165 hektarów, położony w gminie Szczytno, przy miejscowości Stare Kiejkuty. Jezioro charakteryzuje się wydłużonym kształtem i dość urozmaiconą linią brzegową, którą otaczają głównie lasy iglaste oraz tereny rekreacyjne. Woda w akwenie jest stosunkowo żyzna, o zielonkawym zabarwieniu, co sprzyja rozwojowi bogatej flory podwodnej. Dno jeziora jest pofalowane, z kilkoma wyraźnymi przegłębieniami sięgającymi 12 metrów, co tworzy doskonałe warunki dla ryb drapieżnych i spokojnego żeru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80080, 'Jezioro Łęsk', 'jezioro-lesk', 'LAKE', '53.65738769405626', '21.066951152466594', 'Warmińsko-Mazurskie', 'Szczytno', 'Jezioro Łęsk to wyjątkowy akwen rynnowy o powierzchni około 117 hektarów, znany z krystalicznie czystej wody i znacznych głębokości. Jezioro jest niemal w całości otoczone gęstymi lasami iglastymi i mieszanymi, a jego zachodni brzeg przylega do rezerwatu przyrody „Kulka”. Linia brzegowa jest słabo rozwinięta, a brzegi są przeważnie wysokie i bardzo strome, co nadaje jezioru specyficzny, niemal górski charakter. Woda w Łęsku charakteryzuje się bardzo dużą przejrzystością, co sprzyja rozwojowi łąk ramienicowych sięgających nawet 6-8 metrów głębokości.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80081, 'Jezioro Barlewickie', 'jezioro-barlewickie', 'LAKE', '53.91936850529704', '19.049114353166587', 'Pomorskie', 'Sztum', 'Jezioro Barlewickie to płytki, wybitnie eutroficzny akwen położony na wschodnich obrzeżach Sztumu. Jest to zbiornik o charakterze rozlewiskowym, niemal całkowicie otoczony pasem trzcin i tataraku. Woda jest tu bardzo żyzna i ciepła, co sprzyja szybkiej wegetacji roślinności i sprawia, że jezioro jest prawdziwą "stołówką" dla ryb spokojnego żeru. Ze względu na mniejszą głębokość niż w sąsiednim jeziorze Zajezierskim, Barlewickie szybciej budzi się do życia wiosną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80082, 'Jezioro Rańskie', 'jezioro-ranskie', 'LAKE', '53.70128347644957', '21.0645951557668', 'Warmińsko-Mazurskie', 'Dźwierzuty', 'Jezioro Rańskie to malowniczy akwen rynnowy o powierzchni około 104 hektarów, położony w gminie Dźwierzuty, bezpośrednio przy historycznej miejscowości Rańsk. Jezioro charakteryzuje się wydłużonym kształtem i dość łagodnymi brzegami, które w dużej części są porośnięte pasem trzcin i tataraku. Woda w jeziorze jest żyzna (eutroficzna), co sprzyja bogatemu rozwojowi flory podwodnej i sprawia, że ryby znajdują tu doskonałe warunki do wzrostu. Otoczenie jeziora to głównie pola uprawne, łąki oraz zabudowa wiejska, co zapewnia bardzo dobrą dostępność do linii brzegowej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80083, 'Jezioro Wągiel', 'jezioro-wagiel', 'LAKE', '53.78105561139672', '21.344230158126496', 'Warmińsko-Mazurskie', 'Mrągowo', 'Jezioro Wągiel to jeden z najczystszych akwenów w okolicach Mrągowa, położony w malowniczej otulinie lasów Puszczy Piskiej. Jezioro charakteryzuje się bardzo wysoką przejrzystością wody (I i II klasa czystości) oraz piaszczystym, twardym dnem w większości stref przybrzeżnych. Linia brzegowa jest urozmaicona, z licznymi zatokami i wyraźnymi spadami. Dzięki dużej zawartości tlenu i czystości wody, akwen ten jest domem dla sielawy, co bezpośrednio wpływa na kondycję i wielkość bytujących tu drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80084, 'Jezioro Tonka', 'jezioro-tonka', 'LAKE', '54.0366813840429', '20.219314692783865', 'Warmińsko-Mazurskie', 'Orneta', 'Tonka to urokliwe, leśne jezioro o powierzchni ok. 25 ha, położone na północny wschód od Miłakowa. Zbiornik o dość czystej wodzie i mulistym dnie. Słynie z populacji pięknych wzdręg i aktywnych szczupaków "trzciniaków".', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80085, 'Jezioro Mały Wągiel', 'jezioro-maly-wagiel', 'LAKE', '53.77280560232766', '21.351999735394443', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Mały Wągiel (nazywane również Wągielkiem) to niewielki, płytki zbiornik położony na południe od swojego większego imiennika. W przeciwieństwie do Jeziora Wągiel, jest to akwen wybitnie eutroficzny, zarastający, o miękkim dnie i bogatej roślinności pływającej. Jezioro jest niemal całkowicie otoczone lasem, co nadaje mu bardzo dziki i kameralny charakter. Woda jest tu znacznie cieplejsza i żyźniejsza, co tworzy idealne warunki dla ryb spokojnego żeru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80086, 'Jezioro Jeleń', 'jezioro-jelen', 'LAKE', '53.745594456634144', '21.32697814290533', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Jeleń to kameralny, śródleśny zbiornik o powierzchni około 25 hektarów, położony w sercu Puszczy Piskiej, nieopodal miejscowości Piecki. Jest to jezioro o charakterze linowo-szczupakowym, otoczone niemal w całości gęstym borem sosnowo-świerkowym, co zapewnia mu doskonałą osłonę od wiatru i tworzy wyjątkowy, intymny mikroklimat. Woda w Jeleniu jest stosunkowo czysta, o lekko herbacianym odcieniu, co jest typowe dla zbiorników otoczonych torfowiskami. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80087, 'Jezioro Łąkorz', 'jezioro-lakorz', 'LAKE', '53.41528628168388', '19.354545691061148', 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Jezioro Łąkorz to duży (ok. 160 ha) akwen rynnowy, kluczowy punkt systemu Skarlanki. Jezioro słynie z urozmaiconej linii brzegowej i połączenia kanałem z Jeziorem Wielkie Partęczyny. Jest to woda o wysokiej klasie czystości, otoczona lasami i polami. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80088, 'Jezioro Krzywy Róg', 'jezioro-krzywy-rog', 'LAKE', '53.76108991429194', '21.29048948661018', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Krzywy Róg to niewielkie, silnie wydłużone i wygięte jezioro rynnowe, ukryte w malowniczym obniżeniu terenu pośród lasów i łąk. Akwen ten, o powierzchni około 12 hektarów, charakteryzuje się wyjątkowym spokojem i brakiem presji turystycznej. Woda jest żyzna, co sprzyja rozwojowi gęstej roślinności, która niemal całkowicie wypełnia płytkie zatoczki jeziora. Ze względu na swój kształt i osłonięcie wysokimi brzegami, tafli wody rzadko dotyka silny wiatr, co czyni go doskonałym miejscem do precyzyjnego łowienia metodami spławikowymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80089, 'Jezioro Krzywe', 'jezioro-krzywe', 'LAKE', '53.782192094718326', '21.271707331782974', 'Warmińsko-Mazurskie', 'Mrągowo', 'Jezioro Krzywe to głęboki, rynnowy akwen położony w malowniczej okolicy na zachód od Mrągowa. Jezioro charakteryzuje się bardzo czystą wodą i urozmaiconą rzeźbą dna z wyraźnymi spadami i głębokimi rynnami sięgającymi blisko 25 metrów. Brzegi są przeważnie wysokie, zalesione i pagórkowate, co nadaje jezioru specyficzny, kameralny charakter. Ze względu na I i II klasę czystości wody oraz dobre natlenienie, jest to typowe jezioro sielawowe, co bezpośrednio przekłada się na jakość i wielkość bytujących tu drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80090, 'Jezioro Dłużec', 'jezioro-dluzec', 'LAKE', '53.76862173448784', '21.231190171095047', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Dłużec to istotny punkt na szlaku kajakowym rzeki Krutyni, położony w gminie Piecki. Jest to długi, rynnowy zbiornik o powierzchni ok. 120 hektarów, który łączy się z jeziorem Białym oraz jeziorem Ganty. Akwen charakteryzuje się dość żyzną wodą i bardzo rozwiniętą roślinnością przybrzeżną. Brzegi jeziora są w większości wysokie, częściowo zalesione, a od strony południowej przylegają do zabudowań miejscowości Dłużec.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80091, 'Jezioro Robotno', 'jezioro-robotno', 'LAKE', '53.3726077550907', '19.404257712323876', 'Warmińsko-Mazurskie', 'Brodnica', 'Robotno (ok. 50 ha) to jedno z ciekawszych jezior szlaku. Posiada urozmaiconą linię brzegową z wieloma zatoczkami. Słynie z populacji leszcza i dużego lina. Woda jest tu nieco żyźniejsza niż w Partęczynach, co sprzyja szybszym przyrostom białorybu. Spinningiści cenią je za liczne uskoki dna wzdłuż linii lasu.', 'Gospodarstwo Rybackie w Ostródzie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80092, 'Jezioro Borówko', 'jezioro-borowko', 'LAKE', '53.767309834288056', '21.204480493780686', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Borówko to niewielki, śródleśny zbiornik położony w kompleksie leśnym na zachód od jeziora Dłużec. Jest to typowe "oczko" o charakterze dystroficznym, niemal całkowicie otoczone gęstym lasem, co zapewnia mu status łowiska wybitnie dzikiego i zacisznego. Woda ma ciemniejszy, herbaciany odcień, a brzegi są miękkie i bagniste. Ze względu na brak infrastruktury turystycznej i utrudniony dojazd, presja wędkarska jest tu minimalna, co sprzyja populacji lina i dzikiego karasia. To idealne miejsce dla wędkarzy szukających absolutnego spokoju w sercu mazurskiej kniei.', 'Gospodarstwo Rybackie w Mrągowie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80093, 'Jezioro Piłackie', 'jezioro-pilackie', 'LAKE', '53.786320223637794', '21.162434700187116', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Piłackie to malowniczy akwen rynnowy położony w gminie Piecki, otoczony malowniczymi lasami i pagórkami morenowymi. Jezioro charakteryzuje się czystą wodą oraz urozmaiconą linią brzegową z wyraźnymi rynnami i głębokimi partiami sięgającymi blisko 15 metrów. Brzegi są przeważnie wysokie i suche, co ułatwia dostęp do wody w wybranych punktach. Dzięki sielawowemu charakterowi części akwenu, drapieżniki mają tu doskonałą bazę pokarmową, co przekłada się na ich kondycję i waleczność. Jezioro jest połączone z systemem rzeki Krutyni, co sprzyja naturalnej migracji ryb.', 'Gospodarstwo Rybackie w Mrągowie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80094, 'Jezioro Stromek', 'jezioro-stromek', 'LAKE', '53.78451668330536', '21.10040393378284', 'Warmińsko-Mazurskie', 'Sorkwity', 'Jezioro Stromek to okazały zbiornik rynnowy o powierzchni blisko 140 hektarów, stanowiący istotne ogniwo szlaku rzeki Krutyni. Akwen charakteryzuje się wydłużonym kształtem i wysokimi, w większości zalesionymi brzegami, które tworzą malowniczy krajobraz. Jezioro jest znane z urozmaiconego dna z licznymi przegłębieniami oraz twardymi, piaszczystymi partiami. Przepływowy charakter jeziora zapewnia stałą wymianę wód i bogaty rybostan, w którym dominują gatunki typowe dla dużych rynien mazurskich. To popularne łowisko sandaczowe i leszczowe, oferujące doskonałe warunki zarówno do spinningowania, jak i zasiadek z brzegu.', 'Gospodarstwo Rybackie w Mrągowie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80095, 'Jezioro Pierwój', 'jezioro-pierwoj', 'LAKE', '53.804132090688874', '21.111703079656493', 'Warmińsko-Mazurskie', 'Sorkwity', 'Jezioro Pierwój to malowniczy akwen rynnowy o powierzchni około 150 hektarów, stanowiący integralną część szlaku rzeki Krutyni. Jezioro charakteryzuje się wydłużonym kształtem, czystą wodą i urozmaiconą linią brzegową z wyraźnymi półwyspami. Otoczenie jeziora to głównie gęste lasy Puszczy Piskiej oraz pagórkowate tereny morenowe, co zapewnia wędkarzom ciszę i osłonę od wiatru. Dno jeziora jest urozmaicone, z licznymi głęboczkami sięgającymi ponad 20 metrów oraz twardymi, piaszczysto-żwirowymi stokami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80096, 'Jezioro Lampackie', 'jezioro-lampackie', 'LAKE', '53.82781530936497', '21.144835676628507', 'Warmińsko-Mazurskie', 'Sorkwity', 'Jezioro Lampackie to potężny, głęboki akwen rynnowy o powierzchni blisko 280 hektarów, rozpoczynający słynny szlak kajakowy rzeki Krutyni. Jezioro charakteryzuje się krystalicznie czystą wodą (I i II klasa czystości) oraz bardzo urozmaiconym dnem ze stromymi stokami i głębokimi rynnami sięgającymi 38 metrów. Jezioro składa się z dwóch części połączonych przewężeniem, a jego brzegi są w większości wysokie i suche, otoczone lasami, polami oraz zabudową miejscowości Sorkwity i Maradki.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80097, 'Jezioro Gielądzkie', 'jezioro-gieladzkie', 'LAKE', '53.86161019395304', '21.147239491978507', 'Warmińsko-Mazurskie', 'Sorkwity', 'Jezioro Gielądzkie to imponujący akwen rynnowy o powierzchni około 444 hektarów, stanowiący faktyczny początek szlaku rzeki Krutyni. Jest to jezioro o bardzo urozmaiconej linii brzegowej z licznymi półwyspami oraz kilkoma wyspami, z których największa (Ostrów) dodaje akwenowi wyjątkowego charakteru. Woda jest czysta i dobrze natleniona, co sprzyja obecności sielawy. Otoczenie jeziora to mozaika lasów, pól oraz zabudowy turystycznej w miejscowościach Stary Gieląd i Bałowo. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80098, 'Jezioro Jelmuń', 'jezioro-jelmun', 'LAKE', '53.873603662616546', '21.076216042813307', 'Warmińsko-Mazurskie', 'Sorkwity', 'Jezioro Jelmuń to malowniczy zbiornik morenowy o powierzchni około 130 hektarów, ukryty pośród pagórkowatych terenów i lasów na zachód od Sorkwit. Jest to akwen o charakterze eutroficznym, znacznie płytszy od sąsiedniego jeziora Gielądzkiego, co sprzyja bogatemu rozwojowi flory i fauny. Brzegi jeziora są w większości wysokie, miejscami strome, otoczone polami i kępami lasu, co nadaje mu kameralny, sielski klimat. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80099, 'Jezioro Małszewskie', 'jezioro-malszewskie-2', 'LAKE', 53.583263, 20.723562, 'Warmińsko-Mazurskie', 'Jedwabno / Małszewo', 'Jezioro Małszewskie to rozległa (pow. ok. 200 ha) rynna polodowcowa. Charakteryzuje się monumentalną batymetrią – dno opada do 18 metrów. To wyśmienite łowisko sandacza i dorodnego leszcza.', 'Gospodarstwo Rybackie Szwaderowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80100, 'Jezioro Babięty Małe', 'jezioro-babiety-male', 'LAKE', '53.73290870549274', '21.13164687169966', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Babięty Małe to malowniczy akwen rynnowy położony w gminie Piecki, stanowiący północne przedłużenie rynny Jeziora Babięty Wielkie. Choć znacznie mniejsze i płytsze od swojego potężnego sąsiada, zachowuje urokliwy, leśny charakter. Jezioro otaczają gęste bory Puszczy Piskiej, co zapewnia ciszę i doskonałą osłonę od wiatru. Woda jest tu żyźniejsza niż w jeziorze wielkim, co sprzyja rozwojowi bujnej roślinności wynurzonej i zanurzonej. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80101, 'Jezioro Babięty Wielkie', 'jezioro-babiety-wielkie', 'LAKE', '53.71831008318486', '21.120924970392593', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Babięty Wielkie to jeden z najgłębszych i najczystszych akwenów Pojezierza Mrągowskiego, nazywany przez wielu "perłą okolic Piecek". To potężne jezioro rynnowe o powierzchni ok. 250 hektarów imponuje głębokością sięgającą blisko 65 metrów. Krystalicznie czysta woda (I klasa czystości) oraz wysokie, zalesione brzegi nadają mu niemal górskiego charakteru. Jezioro objęte jest strefą ciszy, co w połączeniu z jego głębokością i sielawowym typem wody tworzy unikalne warunki dla wymagających wędkarzy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80102, 'Jezioro Klasztorne', 'jezioro-klasztorne', 'LAKE', '53.68514993248835', '19.1185967349834', 'Pomorskie', 'Kwidzyn', 'Jezioro Klasztorne to niewielki, historyczny akwen położony w bezpośrednim sąsiedztwie Moraw, nieopodal Klecewa. Nazwa jeziora nawiązuje do dawnych dóbr przyklasztornych. Jest to zbiornik płytki, silnie eutroficzny, o bardzo bogatej roślinności pływającej. Jezioro otaczają stare drzewostany i łąki, co nadaje mu wyjątkowego, nieco tajemniczego charakteru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80103, 'Jezioro Drużno', 'jezioro-druzno', 'LAKE', '54.10719946229646', '19.45346648721782', 'Warmińsko-Mazurskie', 'Elbląg', 'Jezioro Drużno to unikatowy w skali kraju płytki zbiornik deltowy o powierzchni przekraczającej 1100 hektarów. Jest to akwen o charakterze reliktowym, stanowiący pozostałość dawnej zatoki morskiej. Całość jeziora znajduje się w granicach Rezerwatu Przyrody "Jezioro Drużno", co wiąże się ze specyficznymi obostrzeniami (m.in. całkowity zakaz używania silników spalinowych i poruszanie się wyłącznie po wyznaczonych szlakach). Jezioro jest niezwykle płytkie – jego średnia głębokość oscyluje wokół 1,2 metra, a dno jest niemal w całości pokryte grubą warstwą mułu i gęstą roślinnością podwodną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80104, 'Jezioro Dąbrówka', 'jezioro-dabrowka', 'LAKE', '53.976216985306934', '19.06701602861867', 'Pomorskie', 'Dzierzgoń', 'Jezioro Dąbrówka to kameralny akwen o powierzchni około 30 hektarów, położony w pagórkowatym krajobrazie rolniczo-leśnym niedaleko Dzierzgonia. Jest to zbiornik o charakterze rynnowym, dość wąski, ale z wyraźnie zaznaczoną głębią. Woda w jeziorze jest żyzna, o umiarkowanej przejrzystości, co sprzyja rozwojowi bujnej roślinności brzegowej. Otoczenie to głównie pola uprawne i niewielkie laski, co zapewnia ciszę i intymność.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80105, 'Jezioro Kaniewo', 'jezioro-kaniewo', 'LAKE', '53.95401019598082', '19.017664065706082', 'Pomorskie', 'Sztum', 'Jezioro Kaniewo to malowniczo położony zbiornik o powierzchni około 50 hektarów, ukryty w zagłębieniu terenu otoczonym przez grunty orne i łąki. Jest to jezioro o charakterze eutroficznym, charakteryzujące się dość miękkim dnem i bardzo dobrze rozwiniętą roślinnością wynurzoną. Linia brzegowa jest dość regularna, ale szeroki pas trzcin tworzy liczne, naturalne stanowiska dla wędkarzy szukających izolacji.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80106, 'Jezioro Uściewierz', 'jezioro-usciewierz', 'LAKE', '51.375361412085525', '23.078016282666315', 'Lubelskie', 'Urszulin', 'Jezioro Uściewierz to największe naturalne jezioro całego Pojezierza Łęczyńsko-Włodawskiego, a zarazem klasyczny przykład ogromnego, zanikającego akwenu polesiowego. Z lustrem wody przekraczającym 300 hektarów, jego maksymalna głębokość ledwie oscyluje w granicach 3 metrów, a średnia wynosi zaledwie nieco ponad metr. Batymetria jest tu niewiarygodnie wręcz jednostajna – to płaski talerz wypełniony wodą i potężną, miękką warstwą mułu i osadów z rozkładających się roślin. Jezioro otoczone jest szczelnym, nierzadko kilkudziesięciometrowym pasem gęstych trzcin i szuwarów, przed którymi w okresie letnim wyrastają nieprzebyte łąki grążela, rdestnic i rogatka.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80107, 'Jezioro Białe', 'jezioro-biale-sztumskie', 'LAKE', '53.93150661495005', '18.98334264094103', 'Pomorskie', 'Sztum', 'Jezioro Białe (często zwane Sztumskim Białym) to jeden z najczystszych i najatrakcyjniejszych akwenów w bezpośrednim sąsiedztwie Sztumu. W przeciwieństwie do pobliskiego jeziora Zajezierskiego, Białe cieszy się opinią wody o wysokiej przejrzystości i piaszczystym dnie. Akwen o powierzchni około 60 hektarów otoczony jest w połowie lasem, a w połowie terenami rekreacyjnymi. Jest to jezioro o charakterze sielawowo-sandaczowym, co czyni je technicznie najciekawszym łowiskiem w okolicy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80108, 'Jezioro Parleta', 'jezioro-parleta', 'LAKE', '53.92158423836195', '19.003187847041925', 'Pomorskie', 'Sztum', 'Jezioro Parleta to kameralny zbiornik położony na zachód od Sztumu, otoczony malowniczą mozaiką pól i kęp leśnych. Jest to jezioro o charakterze linowo-szczupakowym, charakteryzujące się dość spokojną linią brzegową i umiarkowaną głębokością. Woda ma zielonkawy odcień, co świadczy o jej żyzności. Ze względu na mniejszą popularność w porównaniu do jezior miejskich, Parleta oferuje wędkarzom większą dawkę prywatności i szansę na kontakt z rybą w ciszy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80109, 'Jezioro Sztumskie', 'jezioro-sztumskie', 'LAKE', '53.91568705141672', '19.031007940994744', 'Pomorskie', 'Sztum', 'Jezioro Sztumskie, znane również jako Zajezierskie, to wizytówka miasta Sztum, położona u stóp pokrzyżackiego zamku. Jest to jezioro rynnowe o powierzchni blisko 50 hektarów, które dzięki rewitalizacji i budowie nowoczesnego bulwaru stało się centrum rekreacji. Mimo miejskiego charakteru, akwen ten skrywa bardzo ciekawy rybostan, a jego znaczne głębokości (ponad 20 metrów) stwarzają warunki dla gatunków lubiących chłodniejszą wodę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80110, 'Jezioro Brachlewo', 'jezioro-brachlewo', 'LAKE', '53.81169364209656', '18.99377742718995', 'Pomorskie', 'Kwidzyn', 'Jezioro Brachlewo to urokliwy, śródpolny akwen o powierzchni około 20 hektarów, położony na północ od Kwidzyna. Jest to jezioro o charakterze eutroficznym, charakteryzujące się łagodnymi, ale silnie porośniętymi brzegami. Woda ma zielonkawy odcień, a dno jest w dużej mierze muliste, co sprzyja populacji ryb lubiących żyzne wody. Otoczenie to głównie pola uprawne i kępy krzewów, co zapewnia spokój i osłonę od wiatru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80111, 'Jezioro Orkusz', 'jezioro-orkusz', 'LAKE', '53.78946992174136', '19.13176918539371', 'Pomorskie', 'Prabuty', 'Jezioro Orkusz to jeden z najatrakcyjniejszych i najczystszych akwenów w okolicach Prabut. To jezioro rynnowe o powierzchni około 70 hektarów, znane z urozmaiconego dna i czystej wody. Brzegi są zróżnicowane – od wysokich i zalesionych po łagodne, graniczące z łąkami. Dzięki dobrej klasie czystości wody i piaszczystym partiom dna, jezioro to cieszy się dużą popularnością zarówno wśród wędkarzy, jak i amatorów kąpieli.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80112, 'Jezioro Liwieniec', 'jezioro-liwieniec', 'LAKE', '53.759298541162565', '19.186922459035667', 'Pomorskie', 'Prabuty', 'Jezioro Liwieniec to unikatowy, płytki akwen stanowiący centralną część Rezerwatu Przyrody "Jezioro Liwieniec". Jest to jezioro o charakterze wybitnie zarastającym, o średniej głębokości nieprzekraczającej 1 metra. Ze względu na status rezerwatu ornitologicznego (miejsce lęgowe tysięcy mew śmieszek i innych ptaków wodnych), wędkowanie na tym akwenie podlega ścisłym regulacjom i obostrzeniom Regionalnej Dyrekcji Ochrony Środowiska. Jezioro jest w większości niedostępne, otoczone szerokim pasem trzcinowisk i bagnistych łąk.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80113, 'Jezioro Sowica', 'jezioro-sowica', 'LAKE', '53.752080171262655', '19.240810297591683', 'Pomorskie', 'Prabuty', 'Jezioro Sowica to malowniczy akwen rynnowy położony na południowy wschód od Prabut. Jezioro o powierzchni około 70 hektarów charakteryzuje się wydłużonym kształtem i urozmaiconą linią brzegową. Otoczenie to mozaika pól, łąk oraz fragmentów lasu, co nadaje mu klasyczny, pojezierny klimat. Woda w Sowicy jest stosunkowo czysta, o średniej żyzności, co sprzyja stabilnemu rybostanowi. Jezioro jest połączone systemem cieków z jeziorem Liwieniec.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80114, 'Jezioro Grażymowskie Zachodnie', 'jezioro-grazymowskie-zachodnie', 'LAKE', '53.721248058283344', '19.19863621599994', 'Pomorskie', 'Prabuty', 'Jezioro Grażymowskie Zachodnie (często zwane po prostu Grażymowskim) to malowniczy akwen rynnowy położony na południe od Prabut. Jezioro charakteryzuje się bardzo czystą wodą i urozmaiconym dnem z wyraźnymi spadami i podwodnymi górkami. Otoczenie to mozaika lasów iglastych oraz pól, co zapewnia wędkarzom ciszę i osłonę od wiatru. Dzięki dobrej klasie czystości wody, jest to doskonałe łowisko drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80115, 'Jezioro Grażymowskie Wschodnie', 'jezioro-grazymowskie-wschodnie', 'LAKE', '53.710127249401815', '19.232009302185403', 'Pomorskie', 'Prabuty', 'Jezioro Grażymowskie Wschodnie to mniejszy sąsiad części zachodniej, o bardziej dzikim i kameralnym charakterze. Akwen ten jest znacznie płytszy i silniej zarastający, co czyni go idealnym siedliskiem dla ryb spokojnego żeru. Brzegi są w większości miękkie, porośnięte gęstą roślinnością wynurzoną, co zapewnia spokój i niemal całkowitą izolację od cywilizacji.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80116, 'Jezioro Ostrowite', 'jezioro-ostrowite-lipnowskie', 'LAKE', '52.780228032756206', '19.14409050286779', 'Kujawsko-Pomorskie', 'Lipno', 'Jezioro Ostrowite (koło Lipna) to jeden z najcenniejszych przyrodniczo i wędkarsko akwenów regionu. Jezioro o powierzchni blisko 70 ha słynie z krystalicznie czystej wody (I klasa czystości) i sielawowego charakteru. Brzegi są wysokie, suche i w większości zalesione. To techniczne, trudne, ale niezwykle satysfakcjonujące łowisko dla łowców okazów.', 'PZW Włocławek');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80117, 'Jezioro Rybno', 'jezioro-rybno', 'LAKE', '53.66630808535484', '19.080864563372607', 'Pomorskie', 'Gardeja', 'Jezioro Rybno to malowniczy akwen położony bezpośrednio przy miejscowości Rybno, na zachód od Gardei. Jest to jezioro o charakterze eutroficznym, charakteryzujące się dość żyzną wodą i urozmaiconą linią brzegową. Otoczenie to mozaika pól uprawnych, łąk oraz zabudowań wiejskich, co zapewnia łatwy dostęp do wody. Nazwa jeziora nie jest przypadkowa – od lat cieszy się ono opinią bardzo zasobnego w ryby spokojnego żeru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80118, 'Jezioro Kucki', 'jezioro-kucki', 'LAKE', '53.653373584527046', '19.116508757623976', 'Pomorskie', 'Gardeja', 'Jezioro Kucki to największy i najgłębszy akwen w gminie Gardeja, stanowiący istotny punkt na mapie wędkarskiej regionu. To jezioro rynnowe o powierzchni około 150 hektarów, charakteryzujące się bardzo urozmaiconym dnem z wyraźnymi uskokami, głębokimi rynnami (do 22 metrów) oraz podwodnymi górkami. Brzegi są wysokie, częściowo zalesione, co nadaje jezioru majestatyczny wygląd. Woda jest stosunkowo czysta i dobrze natleniona.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80119, 'Jezioro Czarne', 'jezioro-czarne-gardeja', 'LAKE', '53.629264267584766', '19.06880736355174', 'Pomorskie', 'Gardeja', 'Jezioro Czarne (Gardejskie) to urokliwy zbiornik położony na południowy zachód od Gardei. Jest to jezioro o charakterze linowo-szczupakowym, o stosunkowo małej głębokości i bardzo żyznej wodzie. Nazwa nawiązuje do ciemniejszego zabarwienia wody, co w połączeniu z bujną roślinnością nadaje mu dziki charakter. Jezioro jest osłonięte od wiatrów przez okoliczne pagórki i fragmenty lasów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80120, 'Jezioro Kurzyny', 'jezioro-kurzyny', 'LAKE', '53.36530543590514', '19.414072523527878', 'Warmińsko-Mazurskie', 'Brodnica', 'Jezioro Kurzyny (ok. 40 ha) zamyka ten etap szlaku Skarlanki. To jezioro o charakterze leszczowo-szczupakowym, bardzo ciche i odizolowane. Brzegi są podmokłe, co czyni je rajem dla ptactwa i ryb. Dominują tu liny, leszcze i szczupaki. Ze względu na trudny dostęp z lądu, łódź jest tu niezbędnym narzędziem.', 'Gospodarstwo Rybackie w Ostródzie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80121, 'Jezioro Czarne Dolne', 'jezioro-czarne-dolne', 'LAKE', '53.628994851483384', '19.04262002080197', 'Pomorskie', 'Gardeja', 'Jezioro Czarne Dolne to zaciszny akwen wytopiskowy o powierzchni około 21 hektarów, położony w gminie Gardeja. Jezioro charakteryzuje się dość regularną linią brzegową i stosunkowo niewielką głębokością, co sprzyja szybkiej wegetacji roślinności podwodnej. Brzegi są w znacznej części zalesione, co zapewnia wędkarzom osłonę od wiatru i tworzy aurę intymności. Woda w jeziorze jest żyzna, o zielonkawym zabarwieniu, co jest typowe dla zbiorników o wysokiej produktywności biologicznej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80122, 'Jezioro Kuchnia', 'jezioro-kuchnia', 'LAKE', '53.58974561365167', '19.022326685260367', 'Kujawsko-Pomorskie', 'Łasin', 'Jezioro Kuchnia to malowniczy akwen przepływowy o powierzchni około 57 hektarów, przez który przepływa rzeka Gardęga. Jezioro położone jest w rynnie polodowcowej na północ od Łasina i stanowi istotny element lokalnego systemu hydrologicznego. Charakter przepływowy zapewnia stałą wymianę wód i dobre natlenienie, co bezpośrednio przekłada się na bogaty rybostan. Brzegi jeziora są w większości wysokie, suche, otoczone polami i kępami lasu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80123, 'Jezioro Nogat', 'jezioro-nogat', 'LAKE', '53.57915426013473', '19.068519632915834', 'Kujawsko-Pomorskie', 'Łasin', 'Jezioro Nogat to potężny akwen rynnowy o powierzchni około 117 hektarów, stanowiący jedno z najciekawszych łowisk sandaczowych w tej części Pojezierza Iławskiego. Jezioro charakteryzuje się znaczną długością (ok. 7 km) i urozmaiconym dnem z głębokimi rynnami sięgającymi blisko 27 metrów. Przez akwen przepływa rzeka Gardęga, co zapewnia stały przepływ i bogactwo tlenu. Brzegi są przeważnie wysokie, pagórkowate, otoczone lasami i polami, co nadaje jezioru majestatyczny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80124, 'Jezioro Małe Partęczyny', 'jezioro-male-parteczyny', 'LAKE', '53.40017080149448', '19.373442849370203', 'Warmińsko-Mazurskie', 'Brodnica', 'Jezioro Małe Partęczyny to mniejszy, ale niezwykle urokliwy sąsiad Wielkich Partęczyn. Akwen o powierzchni ok. 35 ha jest całkowicie otoczony lasem. Woda jest bardzo czysta, a brzegi dość strome. Jezioro ma charakter typowo linowo-szczupakowy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80125, 'Jezioro Święte', 'jezioro-swiete-lasinskie', 'LAKE', '53.518513506718826', '19.192208141558115', 'Kujawsko-Pomorskie', 'Łasin', 'Jezioro Święte (zwane również Łasińskim Świętym) to okazały, płytki akwen o powierzchni około 61 hektarów, położony na południe od miejscowości Kisielice. Jest to jezioro o wybitnie eutroficznym charakterze, charakteryzujące się dużą żyznością wody i bogatą roślinnością przybrzeżną. Jezioro otaczają malownicze pola uprawne i łąki, co nadaje mu klasyczny, sielski klimat. Woda w akwenie szybko się nagrzewa, co sprzyja intensywnemu żerowaniu ryb spokojnego żeru już od wczesnej wiosny.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80126, 'Jezioro Łasińskie', 'jezioro-lasinskie', 'LAKE', '53.5202164829931', '19.119458147391512', 'Kujawsko-Pomorskie', 'Łasin', 'Jezioro Łasińskie (znane również jako Zamkowe) to największy akwen w bezpośrednim sąsiedztwie Łasina, o powierzchni około 160 hektarów. Jest to jezioro rynnowe o bardzo urozmaiconym dnie i wysokich, malowniczych brzegach. Nad jeziorem wznosi się panorama miasta Łasin oraz pozostałości dawnych fortyfikacji. Woda jest żyzna, o umiarkowanej przejrzystości, co sprzyja bogatemu rybostanowi. Jezioro jest połączone z systemem rzeki Gardęgi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80127, 'Jezioro Czartek', 'jezioro-czartek', 'LAKE', '53.32374029051445', '19.361596031384256', 'Kujawsko-Pomorskie', 'Brodnica', 'Jezioro Czartek to niewielki, śródleśny zbiornik o powierzchni około 3 ha, położony na północ od Brodnicy. Jest to jezioro o charakterze linowo-szczupakowym, niemal całkowicie otoczone gęstym lasem, co zapewnia mu status łowiska wybitnie dzikiego i osłoniętego od wiatru. Woda ma lekko brunatny odcień. Ze względu na utrudniony dojazd i bagniste brzegi, presja wędkarska jest tu znikoma, co sprzyja populacji dzikiego lina i karasia.', 'Gospodarstwo Rybackie w Ostródzie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80128, 'Jezioro Lisnówko', 'jezioro-lisnowko', 'LAKE', '53.47530997892945', '19.138417913989137', 'Kujawsko-Pomorskie', 'Łasin', 'Jezioro Lisnówko to kameralny, płytki akwen o powierzchni około 20 hektarów, położony w pobliżu miejscowości Lisnowo. Jest to jezioro o charakterze linowo-szczupakowym, otoczone polami i łąkami, co nadaje mu cichy, sielski klimat. Woda jest bardzo żyzna i szybko się nagrzewa, co sprzyja intensywnemu żerowaniu ryb spokojnego żeru. Jezioro jest rzadziej odwiedzane przez turystów, co czyni je doskonałą metą dla wędkarzy szukających spokoju.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80129, 'Jezioro Szańcowe', 'jezioro-szancowe', 'LAKE', '53.47530997892945', '19.138417913989137', 'Kujawsko-Pomorskie', 'Łasin', 'Jezioro Szańcowe to niewielki, historyczny akwen położony w bezpośrednim sąsiedztwie jeziora Lisnówko. Nazwa jeziora nawiduje do dawnych umocnień ziemnych (szańców) znajdujących się w tej okolicy. Jest to zbiornik płytki, silnie zarastający, o charakterze linowym. Jezioro otaczają podmokłe łąki i zarośla, co sprawia, że jest to ostoja dla ptactwa wodnego i dzikiej zwierzyny.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80130, 'Jezioro Płowęż', 'jezioro-plowez', 'LAKE', '53.45233956088346', '19.213239381189684', 'Kujawsko-Pomorskie', 'Jabłonowo Pomorskie', 'Jezioro Płowęż to okazały akwen o powierzchni około 175 hektarów, położony na pograniczu Pojezierza Brodnickiego i Chełmińskiego. Jest to jezioro o charakterze szczupakowo-linowym, przez które przepływa rzeka Osa. Jezioro charakteryzuje się dość małą głębokością w stosunku do swojej powierzchni oraz bardzo rozwiniętą roślinnością wynurzoną. Brzegi są w większości niskie, otoczone polami uprawnymi oraz zabudowaniami miejscowości Płowęż.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80131, 'Jezioro Duże', 'jezioro-duze-plowezek', 'LAKE', '53.42536759730635', '19.212276931578703', 'Kujawsko-Pomorskie', 'Jabłonowo Pomorskie', 'Jezioro Duże (często zwane Płowężek Duży) to malowniczy akwen położony w sąsiedztwie miejscowości Płowężek. Jest to jezioro o charakterze linowo-szczupakowym, otoczone polami i łąkami. Woda jest żyzna, o zielonkawym odcieniu, co sprzyja rozwojowi bujnej roślinności wynurzonej. Jezioro jest stosunkowo płytkie, co sprawia, że wiosną woda szybko się nagrzewa, stymulując ryby do intensywnego żerowania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80132, 'Jezioro Zaleń', 'jezioro-zalen', 'LAKE', '53.417888522753046', '19.23148678089292', 'Kujawsko-Pomorskie', 'Jabłonowo Pomorskie', 'Jezioro Zaleń to urokliwy, wydłużony akwen rynnowy położony w zagłębieniu terenu nieopodal miejscowości o tej samej nazwie. Jezioro charakteryzuje się dość stromymi, miejscami zalesionymi brzegami i stosunkowo czystą wodą. Jest to łowisko o charakterze mieszanym, łączące cechy jezior leszczowych i szczupakowych. Dzięki swojemu położeniu, tafla jeziora jest często osłonięta od wiatru, co sprzyja precyzyjnemu łowieniu na spławik.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80133, 'Jezioro Wielkie Partęczyny', 'jezioro-wielkie-parteczyny', 'LAKE', '53.40066779134074', '19.39234688932657', 'Warmińsko-Mazurskie', 'Brodnica', 'Jezioro Wielkie Partęczyny to największy (ponad 320 ha) i najpopularniejszy akwen Brodnickiego Parku Krajobrazowego. To potężna rynna o głębokości do 30 m, z licznymi wyspami (w tym wyspą Wielka Kępa – rezerwatem przyrody). Jezioro słynie z II klasy czystości wody i sielawowego charakteru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80134, 'Jezioro Okonek', 'jezioro-okonek', 'LAKE', '53.385916809369185', '19.407182583138574', 'Warmińsko-Mazurskie', 'Brodnica', 'Jezioro Okonek to niewielki, leśny łącznik w systemie Skarlanki, położony między Wielkimi Partęczynami a jeziorem Robotno. To klasyczne "oczko" o powierzchni ok. 4 ha, otoczone gęstym borem sosnowym. Woda ma lekko brunatny odcień, a dno jest miękkie. To miejsce, gdzie czas się zatrzymał – idealne na samotną zasiadkę z lekkim pontonem w poszukiwaniu lina.', 'Gospodarstwo Rybackie w Ostródzie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80135, 'Jezioro Strążek', 'jezioro-strazek', 'LAKE', '53.3826789745537', '19.398094350507083', 'Warmińsko-Mazurskie', 'Brodnica', 'Strążek to małe, urokliwe jezioro dystroficzne ukryte w lesie. Charakteryzuje się bardzo miękkimi, torfowymi brzegami i dużą ilością grążeli. To typowe łowisko karasia i lina, gdzie presja wędkarska praktycznie nie istnieje. Wymaga jednak dużej dyskrecji i technicznego łowienia w oknach roślinności.', 'Gospodarstwo Rybackie w Ostródzie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80136, 'Jezioro Dębno', 'jezioro-debno', 'LAKE', '53.378025907037674', '19.415785578899428', 'Warmińsko-Mazurskie', 'Brodnica', 'Jezioro Dębno (ok. 60 ha) to przepływowy akwen na Skarlance. Ma charakter rynnowy, jest dość wąskie i wydłużone. Brzegi są wysokie i całkowicie zalesione. To świetne łowisko szczupaka i okonia, które korzystają z bogatego natlenienia wody niesionej przez rzekę. Występują tu też piękne płocie i wzdręgi.', 'Gospodarstwo Rybackie w Ostródzie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80137, 'Jezioro Popek', 'jezioro-popek', 'LAKE', '53.32245236487793', '19.356288366408634', 'Kujawsko-Pomorskie', 'Brodnica', 'Jezioro Popek to miniaturowe oczko leśne sąsiadujące z jeziorem Czartek. Akwen o powierzchni nieco ponad 1 ha jest silnie zarastający i ma charakter dystroficzny. To klasyczne "oczko", gdzie ryby nie rosną do rekordowych rozmiarów, ale w całkowitym odosobnieniu można tu zapolować na karasia złocistego. Brzegi są miękkie i torfowe, co czyni jezioro trudno dostępnym z lądu.', 'Gospodarstwo Rybackie w Ostródzie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80138, 'Jezioro Wysokie Brodno', 'jezioro-wysokie-brodno', 'LAKE', '53.30733891220985', '19.372321673882027', 'Kujawsko-Pomorskie', 'Brodnica', 'Wysokie Brodno to okazałe jezioro rynnowe o powierzchni ok. 90 ha, będące istotnym elementem szlaku Skarlanki. Jezioro charakteryzuje się wysokimi, malowniczymi brzegami, w dużej mierze zalesionymi. Woda jest stosunkowo czysta, a dno urozmaicone z wyraźną rynną centralną. To popularne łowisko leszczowo-szczupakowe, oferujące bardzo dobre warunki zarówno do spinningu z łodzi, jak i zasiadek brzegowych na licznych pomostach.', 'Gospodarstwo Rybackie w Ostródzie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80139, 'Jezioro Niskie Brodno', 'jezioro-niskie-brodno', 'LAKE', '53.28097332815134', '19.379594927254757', 'Kujawsko-Pomorskie', 'Brodnica', 'Jezioro Niskie Brodno o powierzchni ok. 90 ha to akwen bezpośrednio przylegający do Brodnicy, pełniący funkcję głównego miejskiego kąpieliska i terenu rekreacyjnego. Jest to jezioro rynnowe, przepływowe (przez akwen przepływa rzeka Skarlanka). Ze względu na bliskość miasta, brzegi od strony południowej są dobrze zagospodarowane, z licznymi pomostami i bulwarem. Północna część jeziora jest bardziej dzika i zalesiona.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80140, 'Jezioro Chojno', 'jezioro-chojno', 'LAKE', '53.26362407005421', '19.290193983590928', 'Kujawsko-Pomorskie', 'Brodnica', 'Jezioro Chojno to malowniczo położony akwen rynnowy o powierzchni około 75 ha, znajdujący się na zachód od Brodnicy. Jezioro jest dość głębokie (blisko 20 m) i charakteryzuje się czystą wodą oraz urozmaiconym ukształtowaniem dna. Brzegi są w znacznej części zalesione, co zapewnia wędkarzom ciszę i osłonę od wiatru. Jezioro ma charakter rynnowy, jest wąskie i wydłużone, co ułatwia namierzanie ryb przemieszczających się wzdłuż stoków.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80141, 'Jezioro Niewierz', 'jezioro-niewierz', 'LAKE', '53.244432336729076', '19.29732377404922', 'Kujawsko-Pomorskie', 'Brodnica', 'Jezioro Niewierz to kameralny, rynnowy zbiornik o powierzchni ok. 15 ha, położony w bliskim sąsiedztwie jezior Chojno i Mielno. Akwen charakteryzuje się dość czystą wodą i urozmaiconą linią brzegową, którą otaczają lasy i tereny rolnicze. Ze względu na mniejszą głębokość i żyzność wody, jest to doskonałe siedlisko dla ryb spokojnego żeru. To idealne miejsce na spokojną zasiadkę z dala od miejskiego zgiełku.', 'Gospodarstwo Rybackie w Ostródzie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80142, 'Jezioro Chełmickie', 'jezioro-chelmickie', 'LAKE', '52.73450463491719', '19.12677533792082', 'Kujawsko-Pomorskie', 'Włocławek', 'Jezioro Chełmickie to potężny (ok. 160 ha) i bardzo popularny akwen położony na północ od Włocławka. Jezioro ma charakter sandaczowo-leszczowy, z bardzo urozmaiconym dnem, licznymi górkami podwodnymi i rozległymi trzcinowiskami. Ze względu na dużą żyzność wody i regularne zarybienia, jest to jedno z najproduktywniejszych łowisk w regionie.', 'PZW Włocławek');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80143, 'Jezioro Lenie', 'jezioro-lenie', 'LAKE', '52.6536167506272', '19.36209957153076', 'Kujawsko-Pomorskie', 'Dobrzyń nad Wisłą', 'Jezioro Lenie to urokliwy, kameralny akwen o powierzchni około 25 ha, położony w malowniczej rynnie dobrzyńskiej. Jezioro otoczone jest w dużej mierze lasami oraz terenami rolniczymi, co zapewnia wędkarzom ciszę i osłonę od wiatru. Woda jest żyzna, o zielonkawym odcieniu. To klasyczne łowisko linowo-szczupakowe, słynące z bardzo silnej populacji lina i dorodnego karasia złocistego. Idealne miejsce na spokojną zasiadkę spławikową.', 'PZW Włocławek');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80144, 'Jezioro Chalińskie', 'jezioro-chalinskie', 'LAKE', '52.69282337875793', '19.37325827202802', 'Kujawsko-Pomorskie', 'Dobrzyń nad Wisłą', 'Jezioro Chalińskie to malowniczo położony zbiornik rynnowy o powierzchni ok. 35 ha. Akwen charakteryzuje się dość stromymi brzegami i wydłużonym kształtem. Woda jest stosunkowo żyzna, a dno w wielu miejscach twarde, piaszczysto-żwirowe. Jezioro słynie z populacji sandacza oraz dorodnego leszcza. Ze względu na swoje położenie w rynnie, jest to technicznie ciekawe łowisko dla spinningistów szukających spadów i górek podwodnych.', 'PZW Włocławek');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80145, 'Jezioro Tupadelskie', 'jezioro-tupadelskie', 'LAKE', '52.743946182938316', '19.2941071126409', 'Kujawsko-Pomorskie', 'Wielgie', 'Jezioro Tupadelskie to okazały akwen o powierzchni ok. 50 ha, stanowiący istotne ogniwo jezior rynny wielkiej. Jezioro charakteryzuje się urozmaiconą linią brzegową i licznymi trzcinowiskami. Woda ma charakter eutroficzny, co sprzyja szybkiej wegetacji i doskonałym przyrostom ryb spokojnego żeru. Słynie z populacji dużego szczupaka oraz węgorza. Brzegi są w większości dostępne, co ułatwia wędkowanie z lądu.', 'PZW Włocławek');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80146, 'Jezioro Orłowskie', 'jezioro-orlowskie', 'LAKE', '52.76630055189748', '19.27522254989125', 'Kujawsko-Pomorskie', 'Lipno', 'Jezioro Orłowskie to prawdziwa perełka regionu. Słynie z krystalicznie czystej wody (często klasyfikowanej jako I klasa czystości) i piaszczystego dna. Akwen o powierzchni ok. 45 ha jest otoczony wspaniałymi borami sosnowymi, co nadaje mu charakter niemal mazurski. To techniczne łowisko sielawowe, oferujące szansę na spotkanie z rekordowym okoniem i szczupakiem. Przejrzystość wody wymusza na wędkarzach stosowanie bardzo finezyjnych zestawów.', 'PZW Włocławek');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80147, 'Jezioro Zygmunta Augusta', 'jezioro-zygmunta-augusta', 'LAKE', '53.351152201150434', '22.904062934516208', 'Podlaskie', 'Knyszyn', 'Jezioro Zygmunta Augusta (znane również jako Zalew Czechowizna) to jeden z najstarszych sztucznych zbiorników zaporowych w Polsce, powstały w XVI wieku na rzece Nereśl. Akwen o powierzchni blisko 480 ha jest bardzo płytki i silnie zarośnięty, co nadaje mu charakter wielkiego rozlewiska. Otaczają go torfowiska i lasy, a linia brzegowa jest niezwykle urozmaicona. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80148, 'Jezioro Tajno', 'jezioro-tajno', 'LAKE', '53.69170483420239', '22.847919638215522', 'Podlaskie', 'Augustów', 'Jezioro Tajno to urokliwy akwen rynnowy o powierzchni ok. 235 ha, położony na Równinie Augustowskiej. Jezioro jest częścią systemu wodnego rzeki Netty. Charakteryzuje się dość wyrównanym dnem i stosunkowo niewielką głębokością jak na rynnę (do 6 metrów). Brzegi są w znacznej części podmokłe i porośnięte gęstą trzciną, co zapewnia rybom doskonałe schronienie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80149, 'Jezioro Dunajewo', 'jezioro-dunajewo', 'LAKE', '54.40869077072981', '22.852659488743964', 'Podlaskie', 'Wiżajny', 'Jezioro Dunajewo (lit. Danojevas) to niewielki akwen graniczny położony na samej granicy polsko-litewskiej, na północ od Wiżajn. Jest to jezioro o powierzchni około 8 hektarów (w polskiej części), otoczone malowniczymi pagórkami Suwalszczyzny i bezleśnymi terenami rolniczymi. Ze względu na swoje położenie, woda jest tu niezwykle czysta, choć jezioro ulega naturalnemu procesowi wypłycania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80150, 'Jezioro Wiżajny', 'jezioro-wizajny', 'LAKE', '54.38378411599742', '22.857783394010234', 'Podlaskie', 'Wiżajny', 'Jezioro Wiżajny to jeden z największych i najciekawszych akwenów Suwalszczyzny, o powierzchni blisko 300 hektarów. Jest to typowe jezioro rynnowe, ale o nietypowo małej głębokości (średnio ok. 2,3 m), co sprawia, że woda bardzo szybko nagrzewa się latem. Jezioro słynie z trzech malowniczych wysp oraz bardzo urozmaiconej, bezleśnej linii brzegowej zdominowanej przez pola i łąki.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80151, 'Jezioro Czarne', 'jezioro-czarne-ostroda', 'LAKE', '53.70554097600515', '19.910817750213006', 'Warmińsko-Mazurskie', 'Ostróda', 'Jezioro Czarne to małe, miejskie jezioro w Ostródzie (ok. 5 ha). Pełni funkcję łowiska rekreacyjnego, idealnego na krótki wypad z wędką spławikową. Dominuje płoć, wzdręga i okoń.', 'Gospodarstwo Rybackie Ostróda');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80152, 'Jezioro Wisztuć', 'jezioro-wisztuc', 'LAKE', '54.35824422644624', '22.86565343772351', 'Podlaskie', 'Wiżajny', 'Jezioro Wisztuć (często zwane Wistuć) to urokliwy, silnie zarastający zbiornik położony na południe od Wiżajn. Jest to akwen o powierzchni ok. 20 hektarów, charakteryzujący się bardzo miękkim dnem i obfitą roślinnością pływającą. Jezioro otaczają podmokłe łąki, co nadaje mu wyjątkowo dziki charakter. Wypływa z niego rzeka Wizga, która stanowi część dorzecza Niemna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80153, 'Jezioro Staneluszki', 'jezioro-staneluszki', 'LAKE', '54.368397256192914', '22.88819629025974', 'Podlaskie', 'Wiżajny', 'Jezioro Staneluszki to niewielkie, wysokogórskie (jak na warunki polskie) oczko polodowcowe położone na wschód od Wiżajn. Akwen o powierzchni ok. 3 ha charakteryzuje się bardzo czystą wodą i brakiem odpływu. Otoczone jest malowniczymi, stromymi wzgórzami, co nadaje mu unikalny, niemal alpejski charakter. Jest to typowe łowisko linowo-szczupakowe, rzadko odwiedzane, oferujące ciszę i spokój.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80154, 'Jezioro Ślepak', 'jezioro-slepak', 'LAKE', '54.373124111120426', '22.897479541325435', 'Podlaskie', 'Wiżajny', 'Ślepak to miniaturowe jezioro wytopiskowe ukryte w zagłębieniu terenu. Nazwa sugeruje zbiornik o ograniczonym dostępie światła lub braku wyraźnego odpływu. Powierzchnia nie przekracza 2 ha. Brzegi są dość strome, porośnięte roślinnością zielną. To łowisko dla "łowców przygód", gdzie można liczyć na spotkanie z dzikim okoniem i szczupakiem. Ze względu na mały rozmiar, presja wędkarska jest tu zerowa.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80155, 'Jezioro Kuprelek', 'jezioro-kuprelek', 'LAKE', '54.37536668250864', '22.89162820786922', 'Podlaskie', 'Wiżajny', 'Kuprelek to kolejne z serii małych jezior w okolicach miejscowości Burniszki. Posiada bardzo regularny kształt niecki. Woda jest stosunkowo żyzna, co sprzyja populacji białorybu. To idealne miejsce na krótką zasiadkę spławikową w poszukiwaniu dorodnej płoci i lina. Jezioro jest bardzo fotogeniczne ze względu na otaczający je surowy, suwalski krajobraz.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80156, 'Jezioro Prudel', 'jezioro-prudel', 'LAKE', '54.37965890565315', '22.898472744854537', 'Podlaskie', 'Wiżajny', 'Jezioro Prudel to największe z opisywanej czwórki "oczek", położone najbliżej granicy z Litwą. Ma charakter linowo-szczupakowy z wyraźnie zaznaczonym pasem trzcin. Woda jest płytka i szybko nagrzewa się wiosną, co czyni je atrakcyjnym miejscem na wczesne rozpoczęcie sezonu. Słynie z walecznych szczupaków i dużej ilości wzdręgi.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80157, 'Jezioro Sudawskie', 'jezioro-sudawskie', 'LAKE', '54.38607716720673', '22.91706884058438', 'Podlaskie', 'Wiżajny', 'Jezioro Sudawskie to malowniczo położony akwen rynnowy o powierzchni ok. 20 ha, znajdujący się w bezpośrednim sąsiedztwie granicy litewskiej. Jest to jezioro o stosunkowo czystej wodzie i urozmaiconym dnie. Otoczone przez pofałdowane wzgórza Sudawszczyzny, oferuje niesamowite widoki i spokój. Wędkarsko to klasyczne łowisko szczupakowo-okoniowe, gdzie drapieżniki świetnie reagują na naturalne kolory przynęt.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80158, 'Jezioro Jesieryń', 'jezioro-jesieryn', 'LAKE', '54.37191614118423', '22.914319401076863', 'Podlaskie', 'Wiżajny', 'Jesieryń to urokliwe, mniejsze jezioro o charakterze linowo-szczupakowym. Akwen jest dość płytki i posiada bogatą roślinność wynurzoną, co czyni go idealnym miejscem dla lina i karasia. Ze względu na swoje odosobnienie, jest to łowisko o bardzo małej presji wędkarskiej. Brzegi są miejscami podmokłe, co dodaje mu dzikiego charakteru.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80159, 'Jezioro Wysokie', 'jezioro-wysokie-wizajny', 'LAKE', '54.370330266964935', '22.92333481052941', 'Podlaskie', 'Wiżajny', 'Jezioro Wysokie to typowy suwalski zbiornik rynnowy, wąski i głęboki. Jego nazwa nawiązuje do wysokiego położenia n.p.m. oraz stromych brzegów. Woda jest przejrzysta, a dno piaszczysto-żwirowe na spadach. To świetne miejsce na okonia, który chętnie patroluje krawędzie stoków. Wędkarze stacjonarni cenią je za waleczne płocie i leszcze.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80160, 'Jezioro Potop', 'jezioro-potop', 'LAKE', '54.344703244982476', '22.96877599451717', 'Podlaskie', 'Rutka-Tartak', 'Jezioro Potop to większy (ok. 30 ha) akwen rynnowy położony w pobliżu miejscowości Potopy. Jezioro charakteryzuje się czystą wodą i urozmaiconą linią brzegową. Słynie z populacji szczupaka i dużego leszcza. Przez jezioro przepływa rzeka Potopianka, co zapewnia dobrą cyrkulację wody i tlenu. To jedno z ciekawszych łowisk w gminie Rutka-Tartak, oferujące dobre warunki do połowu z łodzi.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80161, 'Jezioro Samanin', 'jezioro-samanin', 'LAKE', '54.33333804611529', '22.97594785926665', 'Podlaskie', 'Rutka-Tartak', 'Jezioro Samanin (często traktowane jako kompleks z jeziorem Potop) to urokliwy, rynnowy zbiornik o powierzchni ok. 10 ha. Schowane między pagórkami Suwalszczyzny, oferuje krystaliczną wodę i spokój, o którym na Mazurach można tylko pomarzyć. Brzegi są częściowo zalesione, a dno urozmaicone z wyraźnymi spadami. To typowe łowisko szczupakowo-linowe, gdzie ryba nie widziała "gumy" z najnowszego katalogu od wielu sezonów.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80162, 'Jezioro Pobondzie', 'jezioro-pobondzie', 'LAKE', '54.31188262968285', '22.948925685075608', 'Podlaskie', 'Rutka-Tartak', 'Jezioro Pobondzie to jeden z najciekawszych akwenów w dolinie Szeszupy. Przez to jezioro (pow. ok. 50 ha) przepływa rzeka Szeszupa, co zapewnia doskonałe natlenienie wody i sprawia, że ryby są tu wyjątkowo waleczne. Jezioro ma charakter rynnowy, jest dość głębokie (do 10 m) i posiada bardzo urozmaiconą linię brzegową z malowniczymi półwyspami. To absolutne królestwo szczupaka, sandacza i dorodnego leszcza, który uwielbia nurt rzeki płynący przez środek akwenu.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80163, 'Jezioro Krupowo', 'jezioro-krupowo', 'LAKE', '54.304642802081894', '23.046061303009864', 'Podlaskie', 'Szypliszki', 'Jezioro Krupowo (Krupiszki) to zaciszny, śródpolny zbiornik położony na wschód od Rutki-Tartak. Jest to akwen o powierzchni ok. 12 ha, charakteryzujący się dość płytką wodą i bogatą roślinnością wynurzoną. Brzegi są w większości niskie, co zapewnia dobry dostęp dla wędkarzy stacjonarnych. To klasyczne "linowe oczko", w którym przy odrobinie cierpliwości można wypracować piękne, złote ryby. Spinningiści znajdą tu sporo okonia i szczupaka czatującego w pasie trzcin.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80164, 'Jezioro Szelment Mały', 'jezioro-szelment-maly', 'LAKE', '54.252005079731866', '23.021433006572753', 'Podlaskie', 'Jeleniewo', 'Jezioro Szelment Mały to potężna i głęboka rynna polodowcowa o powierzchni ok. 168 ha. Jest to akwen o wysokich, miejscami stromych i zalesionych brzegach, co nadaje mu majestatyczny charakter. Woda jest czysta i dobrze natleniona. Jezioro słynie z populacji sandacza oraz grubego okonia, który znajduje doskonałe kryjówki na twardych, piaszczysto-żwirowych stokach. Ze względu na znaczną głębokość i przejrzystość wody, jest to łowisko wymagające, ale regularnie obdarzające rekordowymi drapieżnikami.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80165, 'Jezioro Iłgiel', 'jezioro-ilgiel', 'LAKE', '54.27021909492298', '23.048473069164356', 'Podlaskie', 'Szypliszki', 'Jezioro Iłgiel to urokliwy zbiornik rynnowy o powierzchni ok. 25 ha, położony na północny wschód od jeziora Szelment Wielki. Akwen charakteryzuje się bardzo czystą wodą i spokojną linią brzegową, otoczoną w dużej mierze lasami. To klasyczne łowisko szczupakowo-leszczowe, cenione przez wędkarzy za ciszę i brak dużej presji turystycznej. Dzięki swojemu kameralnemu charakterowi, jest to doskonałe miejsce na całodniową wyprawę z łodzi w poszukiwaniu "zębatego" drapieżnika.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80166, 'Jezioro Szurpiły', 'jezioro-szurpily', 'LAKE', '54.227696069213714', '22.89473418605413', 'Podlaskie', 'Jeleniewo', 'Jezioro Szurpiły to jedno z najpiękniejszych i najczystszych jezior na Suwalszczyźnie, położone w sercu Suwalskiego Parku Krajobrazowego. Akwen o powierzchni ok. 80 ha charakteryzuje się krystaliczną wodą i ogromną głębokością (do 46 m). Nad jeziorem góruje słynna Góra Zamkowa – dawne grodzisko Jaćwingów. Wędkarsko Szurpiły to techniczne łowisko sielawowe. Słynie z olbrzymich okoni i szczupaków żerujących w toni. Obowiązuje tu całkowita strefa ciszy, co w połączeniu z dzikimi brzegami tworzy unikalną atmosferę pierwotnej natury.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80167, 'Jezioro Kluczysko', 'jezioro-kluczysko', 'LAKE', '54.23311494687182', '22.880672047518036', 'Podlaskie', 'Jeleniewo', 'Jezioro Kluczysko to niewielki (ok. 10 ha), ale bardzo głęboki akwen rynnowy, połączony krótkim kanałem z jeziorem Szurpiły. Słynie z krystalicznie czystej wody i wysokich, zalesionych brzegów. To typowe łowisko szczupakowo-okoniowe. Ze względu na położenie w rezerwacie i Parku Krajobrazowym, panuje tu absolutna cisza, a woda zachowuje I klasę czystości. To idealne miejsce dla wędkarzy szukających "dzikich" okazów w krystalicznej toni.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80168, 'Jezioro Jegłówek', 'jezioro-jeglowek', 'LAKE', '54.23755454097814', '22.8890118335516', 'Podlaskie', 'Jeleniewo', 'Jezioro Jegłówek to urokliwy zbiornik o powierzchni ok. 20 ha, położony na północ od Szurpił. Jezioro charakteryzuje się bardzo urozmaiconą rzeźbą dna z głębokimi rynnami sięgającymi blisko 30 metrów. Woda jest bardzo przejrzysta. Słynie z populacji dorodnego okonia i siei. Brzegi są wysokie i w znacznej części porośnięte lasem, co chroni taflę wody przed silnym wiatrem. To techniczne łowisko dla wymagających spinningistów.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80169, 'Jezioro Kopane', 'jezioro-kopane', 'LAKE', '54.24754072501332', '22.904856751658574', 'Podlaskie', 'Jeleniewo', 'Jezioro Kopane to niewielki akwen rynnowy ukryty pośród wzgórz morenowych. Jest to jezioro o charakterze linowo-szczupakowym, o nieco mniejszej głębokości niż sąsiednie rynny, co sprzyja rozwojowi roślinności podwodnej. Woda jest czysta, a brzegi dzikie i rzadko odwiedzane przez turystów. To świetna meta na lina, którego można podejść w zacisznych zatoczkach przy ścianie trzcin.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80170, 'Jezioro Gulbin', 'jezioro-gulbin', 'LAKE', '54.25966984587017', '22.900393877021', 'Podlaskie', 'Jeleniewo', 'Jezioro Gulbin położone jest w bezpośrednim sąsiedztwie słynnej Cisowej Góry. To malownicza rynna o powierzchni ok. 15 ha, przez którą przepływa rzeka Szeszupa. Dzięki stałemu przepływowi woda jest doskonale natleniona, co sprzyja waleczności tutejszych ryb. Słynie z dorodnego klenia i jazia (rzadkość w jeziorach), które wchodzą tu z rzeki, oraz klasycznych drapieżników: szczupaka i okonia.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80171, 'Jezioro Perły', 'jezioro-perly', 'LAKE', '54.27450988456236', '22.898589032303576', 'Podlaskie', 'Wiżajny', 'Jezioro Perły (często nazywane Perty) to krystalicznie czysty akwen położony w sąsiedztwie jeziora Kojle. Słynie z niesamowitej przejrzystości wody i piaszczysto-żwirowego dna. Jezioro ma charakter rynnowy, jest otoczone malowniczymi pagórkami i łąkami. Wędkarsko to łowisko sielawowe, oferujące szansę na spotkanie z potężnym okoniem i szczupakiem żerującym w toni. Ze względu na czystość wody, ryby są tu wyjątkowo waleczne i ostrożne.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80172, 'Jezioro Kojle', 'jezioro-kojle', 'LAKE', '54.27585880158076', '22.891495852659002', 'Podlaskie', 'Wiżajny', 'Jezioro Kojle to głęboki, rynnowy zbiornik o powierzchni ok. 17 ha, połączony z jeziorem Perty. Charakteryzuje się bardzo stromymi spadami i twardym dnem. Woda jest przejrzysta, o błękitnym odcieniu. To techniczne łowisko okoniowe – ryby często grupują się na podwodnych półkach i stokach rynny. Ze względu na brak dużej presji turystycznej, zachowuje dziki charakter i spokój.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80173, 'Jezioro Jaczno', 'jezioro-jaczno', 'LAKE', '54.27990039917604', '22.87352271660109', 'Podlaskie', 'Wiżajny', 'Jaczno to "Perła Suwalszczyzny" – jezioro o unikalnej, szmaragdowej barwie wody, którą zawdzięcza procesom wytrącania węglanu wapnia. To jedno z najgłębszych (26 m) i najbardziej urokliwych jezior w SPK. Brzegi są wysokie, strome i porośnięte gęstym lasem liściastym. Wędkarsko to łowisko trudne, ale obfitujące w wielkie szczupaki i sieje. Obowiązuje tu całkowita strefa ciszy, a krajobraz przypomina jeziora alpejskie.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80174, 'Jezioro Kamenduł', 'jezioro-kamendul', 'LAKE', '54.26611999985165', '22.864693832637258', 'Podlaskie', 'Jeleniewo', 'Jezioro Kamenduł (Kameduł) to głęboki, śródleśny zbiornik rynnowy położony w sercu Suwalskiego Parku Krajobrazowego. Akwen słynie z niezwykle czystej wody i urozmaiconego dna. Otaczają go wysokie wzgórza porośnięte starodrzewem, co nadaje mu unikalny mikroklimat. Wędkarsko to łowisko sielawowe, oferujące szansę na spotkanie z rekordowym okoniem i sieją. Ze względu na ochronę przyrody panuje tu absolutna cisza.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80175, 'Jezioro Pogorzałek', 'jezioro-pogorzalek', 'LAKE', '54.273945319766355', '22.838436003979634', 'Podlaskie', 'Przerośl', 'Pogorzałek to niewielkie, wysokogórskie w charakterze jezioro położone na wschód od Hańczy. Jezioro charakteryzuje się czystą wodą i piaszczystym dnem. Brzegi są suche, w dużej mierze otwarte, co zapewnia świetne warunki do obserwacji okolicy. To klasyczne łowisko szczupakowo-okoniowe, cenione za waleczność ryb i brak dużej presji wędkarskiej.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80176, 'Jezioro Hańcza', 'jezioro-hancza', 'LAKE', '54.262891045483954', '22.812389964993695', 'Podlaskie', 'Przerośl', 'Jezioro Hańcza to najgłębsze jezioro w Polsce i na całym Niżu Środkowoeuropejskim (108,5 m). To krystalicznie czysty, oligotroficzny akwen o kamienistych brzegach, przypominający jeziora skandynawskie lub alpejskie. Hańcza to legendarne łowisko rekordowych okoni i szczupaków żerujących w toni. Występują tu rzadkie gatunki ryb, jak głowacz białopłetwy i miętus jeziorowy. Woda ma niesamowitą przejrzystość (do 12 metrów), co czyni ją mekką dla nurków i najbardziej wymagających spinningistów.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80177, 'Jezioro Boczniel', 'jezioro-boczniel', 'LAKE', '54.260519670912466', '22.8211798923113', 'Podlaskie', 'Przerośl', 'Jezioro Boczniel to mniejszy, rynnowy sąsiad Hańczy, z którą jest połączone rzeką Czarną Hańczą. Mimo bliskości giganta, Boczniel ma swój własny charakter – jest płytszy, silniej zarośnięty i oferuje doskonałe warunki dla lina i szczupaka "trzciniaka". To świetna alternatywa, gdy na otwartej toni Hańczy wieje zbyt silny wiatr.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80178, 'Jezioro Pauzeńskie', 'jezioro-pauzenskie', 'LAKE', '53.72468299664758', '19.95570171273964', 'Warmińsko-Mazurskie', 'Ostróda', 'Jezioro Pauzeńskie (Puzy) o powierzchni ok. 50 ha, stanowi część szlaku Kanału Elbląskiego. Jezioro jest dość płytkie, z bardzo bogatą roślinnością. Słynie z populacji sandacza i szczupaka. Wędkarze cenią je za waleczne ryby przepływowe, które migrują systemem kanałów i rzeki Drwęcy.', 'Gospodarstwo Rybackie Ostróda');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80179, 'Jezioro Wersele', 'jezioro-wersele', 'LAKE', '54.293989465407435', '22.75726543891912', 'Podlaskie', 'Wiżajny', 'Jezioro Wersele to zaciszny akwen położony na zachód od Hańczy, blisko granicy z województwem warmińsko-mazurskim. Jest to jezioro o charakterze linowo-szczupakowym, otoczone lasami i torfowiskami. Woda ma lekko brunatny odcień. Wersele słynie z populacji dzikiego lina i dorodnego karasia. To jedno z najbardziej odosobnionych jezior w regionie, oferujące absolutną ciszę i kontakt z dziką naturą.', 'Wody Polskie (RZGW Białystok)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80180, 'Jezioro Pobłędzie', 'jezioro-pobledzie', 'LAKE', '54.30801373056594', '22.755357158130575', 'Podlaskie', 'Przerośl', 'Jezioro Pobłędzie to malowniczy akwen rynnowy o powierzchni ok. 50 ha, położony w pobliżu granicy z województwem warmińsko-mazurskim. Jezioro charakteryzuje się dość urozmaiconą linią brzegową i czystą wodą. Otoczone jest pagórkowatym terenem, polami i kępami lasu. Wędkarsko to bardzo ciekawe łowisko szczupakowo-leszczowe, z silną populacją okonia. Dzięki umiarkowanej presji wędkarskiej, można tu liczyć na udane zasiadki w ciszy i spokoju.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80181, 'Jezioro Białe Filipowskie', 'jezioro-biale-filipowskie', 'LAKE', '54.197963355618356', '22.65021826667558', 'Podlaskie', 'Filipów', 'Jezioro Białe Filipowskie to jeden z najgłębszych (ponad 50 m) i najczystszych akwenów w dolinie Rospudy. To potężna rynna polodowcowa o powierzchni ok. 120 ha. Woda posiada I klasę czystości, a dno jest piaszczysto-kamieniste. To typowe łowisko sielawowe, słynące z olbrzymich szczupaków i siei. Ze względu na przejrzystość wody i strome spady, jest to łowisko wymagające dużej wiedzy technicznej od wędkarza.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80182, 'Jezioro Przystajne', 'jezioro-przystajne', 'LAKE', '54.223449912383494', '22.664658159129146', 'Podlaskie', 'Filipów', 'Jezioro Przystajne to niewielki, zaciszny akwen położony na północ od Filipowa. Jezioro o powierzchni ok. 15 ha charakteryzuje się silnie rozwiniętą roślinnością wynurzoną i mulistym dnem w zatokach. To klasyczne łowisko linowo-szczupakowe, idealne dla osób szukających spokoju i kameralnej atmosfery. Często pomijane przez turystów, co sprzyja populacji dzikiego lina.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80183, 'Jezioro Czostków', 'jezioro-czostkow', 'LAKE', '54.219565333381105', '22.626514852543796', 'Podlaskie', 'Filipów', 'Jezioro Czostków to urokliwy zbiornik o powierzchni ok. 25 ha, o charakterze leszczowo-szczupakowym. Akwen posiada urozmaiconą linię brzegową z wieloma zatoczkami, które są świetnym schronieniem dla białorybu. Woda jest stosunkowo czysta. Wędkarze cenią to jezioro za dobre brania płoci oraz szczupaki, które najchętniej atakują w okolicach szerokich pasów trzcin.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80184, 'Jezioro Garbas', 'jezioro-garbas', 'LAKE', '54.13597409623732', '22.620697886143894', 'Podlaskie', 'Filipów', 'Jezioro Garbas to potężna i niezwykle głęboka rynna (do 40 m) o powierzchni ok. 140 ha. Jest to jedno z najpiękniejszych jezior w systemie Rospudy. Charakteryzuje się wysokimi, częściowo zalesionymi brzegami i krystaliczną wodą. To wybitne łowisko sielawowe. Słynie z rekordowych okoni, które trzymają się kamienistych spadów, oraz wielkich szczupaków żerujących w toni. Ze względu na głębokość i przejrzystość, jezioro jest również popularne wśród nurków.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80185, 'Jezioro Gatne', 'jezioro-gatne', 'LAKE', '54.127189624736', '22.639648397363327', 'Podlaskie', 'Filipów', 'Jezioro Gatne to urokliwy, rynnowy zbiornik o powierzchni ok. 7 ha, będący częścią szlaku Rospudy. Jezioro charakteryzuje się bardzo czystą wodą i piaszczystym dnem. Brzegi są w większości otwarte, otoczone malowniczymi pagórkami i łąkami. To klasyczne łowisko szczupakowo-okoniowe, cenione za ciszę i kameralny charakter. Idealne miejsce na szybką wyprawę z lekkim spinningiem lub spławikiem.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80186, 'Jezioro Głębokie', 'jezioro-glebokie-filipow', 'LAKE', '54.11451846031318', '22.635213106228306', 'Podlaskie', 'Filipów', 'Jezioro Głębokie to typowa rynna polodowcowa, która zgodnie z nazwą charakteryzuje się stromymi spadami dna i znaczną głębokością (do 18 m). Akwen o powierzchni ok. 15 ha posiada krystalicznie czystą wodę. Brzegi są wysokie, częściowo zalesione. To techniczne łowisko okoniowe – ryby trzymają się tu twardych, piaszczysto-żwirowych stoków. Wędkarze stacjonarni mogą liczyć na dorodnego leszcza i płoć.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80187, 'Jezioro Siekierowo', 'jezioro-siekierowo', 'LAKE', '54.11289794917365', '22.64544218141125', 'Podlaskie', 'Filipów', 'Jezioro Siekierowo to niewielki, dziki akwen o powierzchni ok. 5 ha, położony w lekkim oddaleniu od głównego nurtu Rospudy. Jezioro charakteryzuje się mulistym dnem i bogatą roślinnością wynurzoną. Otoczone jest kępami lasu i podmokłymi łąkami, co zapewnia mu status łowiska bardzo zacisznego. To typowe "linowe oczko", gdzie w spokoju można zapolować na złotego lina i dorodną wzdręgę.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80188, 'Jezioro Sumowo', 'jezioro-sumowo-filipowskie', 'LAKE', '54.076664788757924', '22.651941741052575', 'Podlaskie', 'Filipów', 'Jezioro Sumowo (Filipowskie) to jedno z najważniejszych jezior regionu, o imponującej długości blisko 7 km i powierzchni ok. 90 ha. Jest to jezioro przepływowe (rzeka Rospuda), co gwarantuje doskonałe natlenienie i bogaty rybostan. Rynna jeziora jest głęboka i posiada bardzo urozmaicone dno z licznymi górkami. Słynie z populacji sandacza, szczupaka oraz potężnych leszczy. Dzięki bardzo dobrej infrastrukturze w Filipowie, jest to łowisko chętnie odwiedzane, ale ze względu na swoją długość pozwala każdemu znaleźć ciche miejsce.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80189, 'Jezioro Karasiewek', 'jezioro-karasiewek', 'LAKE', '54.059872732062416', '22.662370980159313', 'Podlaskie', 'Filipów', 'Jezioro Karasiewek to niewielki, zaciszny akwen o powierzchni ok. 12 ha, położony na południe od Filipowa. Jak sama nazwa wskazuje, jezioro jest prawdziwym rajem dla łowców karasi i linów. Charakteryzuje się dość miękkim dnem i bogatą roślinnością zanurzoną. Brzegi są w większości niskie, co ułatwia dostęp wędkarzom stacjonarnym. To idealne miejsce na spokojną, rodzinną zasiadkę, gdzie brania mniejszych ryb są niemal gwarantowane, a co jakiś czas trafia się dorodny "złoty" karaś.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80190, 'Jezioro Jałowo', 'jezioro-jalowo-raczki', 'LAKE', '53.95541501464795', '22.874249399325276', 'Podlaskie', 'Augustów', 'Jezioro Jałowo to jedna z najpiękniejszych rynien polodowcowych w okolicach Raczek. Akwen o powierzchni ok. 22 ha zachwyca przejrzystością wody i wysokimi, zalesionymi brzegami. Jezioro jest dość głębokie (do 12 m) i posiada bardzo twarde, piaszczysto-żwirowe dno. To techniczne łowisko okoniowe – garbusy uwielbiają tutejsze spady i podwodne przeszkody. Dzięki położeniu w niecce, woda jest tu zazwyczaj spokojna, co sprzyja precyzyjnemu spinningowaniu z łodzi.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80191, 'Jezioro Stupień', 'jezioro-stupien', 'LAKE', '53.035842780826826', '23.458463077859808', 'Podlaskie', 'Giby', 'Jezioro Stupień (pow. ok. 32 ha) to urokliwy akwen położony w gminie Giby. Charakteryzuje się dość dużą głębokością maksymalną (do 14 m) i żyzną wodą. To klasyczne łowisko linowo-szczupakowe, otoczone lasami i polami. Brzegi są miejscami zalesione, co zapewnia spokój i osłonę od wiatru.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80192, 'Jezioro Kalejty (Długie Augustowskie)', 'jezioro-kalejty', 'LAKE', 53.882088, 23.063307, 'Podlaskie', 'Augustów', 'Jezioro Kalejty, znane również jako Długie Augustowskie, to niezwykle urokliwy, wydłużony akwen rynnowy położony w samym sercu Puszczy Augustowskiej. Całe jezioro objęte jest ochroną w ramach rezerwatu przyrody, co gwarantuje zachowanie jego pierwotnego, dzikiego charakteru. Linię brzegową w 100% porasta majestatyczny, stary bór sosnowo-świerkowy, który chroni taflę przed silnymi wiatrami. Woda odznacza się wybitną czystością i chłodem, nawet w upalne letnie dni.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80193, 'Jezioro Bolesty (Dolina Rospudy)', 'jezioro-bolesty-rospuda', 'LAKE', 54.029979, 22.718697, 'Podlaskie', 'Raczki', 'Bolesty to monumentalna, długa na kilka kilometrów rynna polodowcowa, przez którą przepływa legendarna rzeka Rospuda. Zbiornik ten charakteryzuje się niezwykle surowym, niemal skandynawskim krajobrazem. Strome, wysokie na kilkanaście metrów brzegi porośnięte są gęstym lasem mieszanym, który momentami wręcz "wchodzi" do wody, tworząc sieć zwalonych pni i naturalnych zawad. Maksymalna głębokość jeziora przekracza 16 metrów, a nurt Rospudy stale dostarcza natlenioną, chłodną wodę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80194, 'Jezioro Dejgunek', 'jezioro-dejgunek', 'LAKE', '54.0120670482091', '21.632352982924363', 'Warmińsko-Mazurskie', 'Giżycko', 'Jezioro Dejgunek to mniejszy sąsiad potężnych Dejgun. Jest to akwen o powierzchni ok. 40 ha, znacznie płytszy i bardziej zarośnięty od swojego większego brata. Jezioro otaczają podmokłe łąki i kępy lasu, co nadaje mu dziki charakter. To klasyczne łowisko linowo-szczupakowe, gdzie w spokoju można zapolować na lina i karasia złocistego. Presja wędkarska jest tu znacznie mniejsza niż na głównym szlaku WJM.', 'Gospodarstwo Rybackie Giżycko');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80195, 'Jezioro Dejguny', 'jezioro-dejguny', 'LAKE', '54.036022324293654', '21.60564865005913', 'Warmińsko-Mazurskie', 'Giżycko', 'Dejguny to jedno z najciekawszych i najgłębszych (do 45 m) jezior w okolicach Giżycka. Akwen o powierzchni ponad 760 ha ma charakter sielawowy i słynie z krystalicznie czystej wody. Jezioro objęte jest strefą ciszy, co czyni je rajem dla wędkarzy ceniących spokój. Słynie z olbrzymich okoni i wielkich szczupaków żerujących w toni na stadach sielawy. Urozmaicona linia brzegowa z licznymi półwyspami i głębokimi rynnami wymaga od wędkarza dobrej znajomości techniki echosondy.', 'Gospodarstwo Rybackie Giżycko');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80196, 'Jezioro Okrągłe', 'jezioro-okragle-raczki', 'LAKE', 54.056667, 22.702732, 'Podlaskie', 'Raczki / Dowspuda', 'Jezioro Okrągłe to podręcznikowy przykład akwenu wytopiskowego (tzw. kociołka). Jak wskazuje nazwa, ma ono bardzo regularny, niemal okrągły kształt. Położone na skraju rozległych lasów i pól w pobliżu rzeki Rospudy, stanowi kameralną oazę spokoju. Zbiornik jest bardzo głęboki w stosunku do swojej małej powierzchni – dno stromo opada niczym lejek, osiągając w centralnym punkcie głębokości nierzadko przekraczające kilkanaście metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80197, 'Zalew Dojlidzkie (Stawy Dojlidy)', 'zalew-dojlidy-bialystok', 'LAKE', 53.107683, 23.234797, 'Podlaskie', 'Białystok', 'Kompleks Stawów Dojlidzkich to kluczowy punkt na rekreacyjnej i wędkarskiej mapie Białegostoku. Jest to sztuczny, rozległy zbiornik wodny położony w dolinie rzeki Białej. Ze względu na swoje miejskie usytuowanie, akwen tętni życiem od wczesnej wiosny do późnej jesieni. Brzegi są w dużej mierze zagospodarowane – znajdziemy tu szerokie piaszczyste plaże, wybetonowane promenady oraz profesjonalne pomosty wędkarskie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80198, 'Żwirownia "Egipt"', 'zwirownia-egipt', 'LAKE', 52.801958, 21.311567, 'Mazowieckie', 'Pułtusk / Gzowo', 'Żwirownia potocznie nazywana "Egiptem" (ze względu na surowy, piaszczysty krajobraz poeksploatacyjny i upały panujące tu latem) to spektakularne, głębokie wyrobisko położone niedaleko doliny Narwi. To zbiornik wciąż częściowo połączony z industrialnym krajobrazem, charakteryzujący się bardzo czystą wodą, filtrującą się przez grube warstwy żwiru. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80199, 'Jezioro Żwirownia (Dolina Narwi)', 'zwirownia-dolina-narwi', 'LAKE', 52.685918, 21.106775, 'Mazowieckie', 'Zatory / Popowo Kościelne', 'Jezioro będące dawnym wyrobiskiem żwiru, wkomponowane w malowniczy krajobraz zalewowy rzeki Narwi. Choć zbiornik jest pochodzenia antropogenicznego, natura błyskawicznie przejęła nad nim kontrolę. Akwen okresowo – przy bardzo wysokich stanach rzeki – łączy się z wodami Narwi, co gwarantuje naturalną i potężną wymianę rybostanu. Średnia głębokość to ok. 3 do 6 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80200, 'Jezioro Jaśkowo Duże', 'jezioro-jaskowo-duze', 'LAKE', 53.608306, 21.652894, 'Warmińsko-Mazurskie', 'Pisz / Wiartel', 'Jaśkowo Duże to wspaniały, ukryty w głębi Puszczy Piskiej akwen rynnowy, będący częścią wielkiego szlaku wodnego. Powierzchnia to nieco ponad 100 hektarów. Jest to jezioro wybitnie leśne, oddalone od głównych, gwarnych szlaków mazurskich, co pozwala na obcowanie z dziką, nienaruszoną naturą. Wokół jeziora rosną gęste bory sosnowe, które chronią wodę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80201, 'Jezioro Tajty', 'jezioro-tajty', 'LAKE', '54.0211995252738', '21.678847258397944', 'Warmińsko-Mazurskie', 'Giżycko', 'Jezioro Tajty to ważny akwen na szlaku Wielkich Jezior Mazurskich, połączony kanałami z jeziorami Niegocin i Kisajno. Mimo turystycznego charakteru, jezioro (pow. ok. 240 ha) oferuje świetne warunki wędkarskie, szczególnie w swoich bocznych, spokojniejszych odnogach. Charakteryzuje się dość urozmaiconym dnem i czystą wodą. Słynie z populacji sandacza i dorodnego leszcza. Ze względu na ruch żeglugowy, wędkarze najchętniej wybierają tu pory wczesnoporanne lub jesienne, polując na drapieżniki wzdłuż stoków rynny.', 'Gospodarstwo Rybackie Giżycko');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80202, 'Jezioro Iławki', 'jezioro-ilawki', 'LAKE', '54.01165537895391', '21.54662252953979', 'Warmińsko-Mazurskie', 'Ryn', 'Jezioro Iławki to niewielki (ok. 10 ha), malowniczo położony zbiornik w pobliżu miejscowości o tej samej nazwie. Jest to typowe jezioro polne o charakterze linowo-karasiowym. Brzegi są niskie, częściowo dostępne, a dno w dużej mierze muliste. To świetna meta na szybką, popołudniową zasiadkę spławikową w poszukiwaniu płoci, wzdręgi i lina. Jezioro jest rzadko odwiedzane przez turystów, co zapewnia duży komfort łowienia.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80203, 'Jezioro Wersmina', 'jezioro-wersmina', 'LAKE', '54.01980240918032', '21.508073020556044', 'Warmińsko-Mazurskie', 'Kętrzyn', 'Wersmina to jedno z najbardziej znanych łowisk szczupakowych w Polsce. Akwen o powierzchni ok. 88 ha słynie z rygorystycznej polityki ochrony ryb (C&R dla dużych okazów), co przekłada się na niesamowitą populację szczupaka i okonia. Woda jest bardzo przejrzysta, a dno urozmaicone z licznymi górkami. To jezioro prywatne, doskonale zagospodarowane, z bazą noclegową i wypożyczalnią łodzi. Idealne miejsce dla spinningistów nastawionych na bicie życiowych rekordów.', 'Właściciel prywatny (Łowisko Wersmina)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80204, 'Jezioro Stare', 'jezioro-stare-elblag', 'LAKE', '54.23735286527601', '19.496485488963998', 'Warmińsko-Mazurskie', 'Tolkmicko', 'Jezioro Stare to urokliwe, leśne oczko położone na Wysoczyźnie Elbląskiej, w pobliżu Jeleniej Doliny. Jest częścią kompleksu małych jezior śródleśnych. Charakteryzuje się czystą wodą i specyficznym mikroklimatem wynikającym z dużych deniwelacji terenu. To doskonałe łowisko dla osób szukających absolutnego spokoju, polujących na płoć, okonia i szczupaka w otoczeniu starych buczyn.', 'PZW Elbląg');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80205, 'Jezioro Martiany', 'jezioro-martiany', 'LAKE', '54.026473946022705', '21.526943256394258', 'Warmińsko-Mazurskie', 'Kętrzyn', 'Jezioro Martiany (często nazywane również Jeziorem Martjańskim) to malowniczy zbiornik o powierzchni ok. 16 ha. Położone tuż przy miejscowości Martiany, oferuje łatwy dostęp i typowo mazurski klimat. Jest to jezioro o charakterze linowo-szczupakowym, z dość czystą wodą i pasem trzcin otaczającym niemal całą linię brzegową. To świetna meta na spokojną zasiadkę spławikową lub popołudniowy spinning z łodzi.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80206, 'Jezioro Kierstynówko', 'jezioro-kierstynowko', 'LAKE', '54.0323542567663', '21.50180411188002', 'Warmińsko-Mazurskie', 'Kętrzyn', 'Jezioro Kierstynówko to kameralne, dzikie oczko położone na północny zachód od Wersminy. Ma powierzchnię ok. 5 ha i jest niemal całkowicie otoczone lasem i nieużytkami. Ze względu na brak infrastruktury i utrudniony dostęp, jest to miejsce dla prawdziwych odkrywców. Dominuje tu lin, karaś i szczupak. Idealne dla wędkarzy ceniących absolutną samotność i kontakt z naturą.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80207, 'Jezioro Guber', 'jezioro-guber', 'LAKE', '53.97787294297048', '21.531774083525743', 'Warmińsko-Mazurskie', 'Ryn', 'Jezioro Guber to płytki, silnie zarastający zbiornik o powierzchni ok. 20 ha, położony w pobliżu miejscowości Salpik. Jezioro ma charakter wybitnie linowy. Woda jest żyzna, a dno muliste, co sprzyja populacji złotego lina i wzdręgi. To łowisko wymagające, ale bardzo satysfakcjonujące dla wędkarzy spławikowych, którzy potrafią łowić w oknach roślinności wynurzonej.', 'Gospodarstwo Rybackie Giżycko');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80208, 'Jezioro Łuknajno', 'jezioro-luknajno', 'LAKE', '53.815182706803064', '21.6272618008683', 'Warmińsko-Mazurskie', 'Mikołajki', 'Jezioro Łuknajno to jeden z najcenniejszych przyrodniczo obiektów w Polsce, wpisany na listę UNESCO jako międzynarodowy rezerwat biosfery. Jest to bardzo płytkie jezioro morenowe (średnia głębokość to zaledwie 0,6 m), połączone wąskim kanałem ze Śniardwami. Słynie jako największa w Europie ostoja łabędzia niemego (w czasie linienia przebywa tu nawet 2000 osobników). ZE WZGLĘDU NA OCHRONĘ REZERWATOWĄ OBOWIĄZUJE TU CAŁKOWITY ZAKAZ WĘDKOWANIA ORAZ PŁYWANIA. Jezioro można podziwiać z wież widokowych, co stanowi wielką atrakcję turystyczną regionu Mikołajek.', 'Mazurski Park Krajobrazowy / RDOŚ Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80209, 'Jezioro Gardyńskie', 'jezioro-gardynskie', 'LAKE', '53.755498729411535', '21.519278259604683', 'Warmińsko-Mazurskie', 'Mikołajki', 'Jezioro Gardyńskie to malowniczy, płytki akwen o powierzchni ok. 80 ha, położony na południowy zachód od Mikołajek, w pobliżu miejscowości Gardyny. Jezioro jest połączone systemem cieków z Jeziorem Śniardwy. Charakteryzuje się bardzo silnie rozwiniętą roślinnością wynurzoną – niemal całe jezioro otoczone jest szerokim pasem trzcin. To klasyczne łowisko szczupakowo-linowe, bardzo "ciche" i rzadko odwiedzane przez turystów z głównego szlaku. Idealne miejsce dla wędkarzy szukających dzikich mazurskich linczy i szczupaków "trzciniaków".', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80210, 'Jezioro Skok', 'jezioro-skok', 'LAKE', '53.74032310328098', '21.49872767278078', 'Warmińsko-Mazurskie', 'Ruciane-Nida', 'Jezioro Skok to niewielkie, śródleśne oczko położone na południe od jeziora Gardyńskiego. Akwen o powierzchni ok. 4 ha jest niemal całkowicie ukryty w Puszczy Piskiej. Charakteryzuje się miękkim, torfowym dnem i bardzo czystą wodą o herbacianym odcieniu. To typowe jezioro dystroficzne, w którym można spotkać pięknie ubarwione liny i stadka złotych karasi. Ze względu na trudny dostęp i status ostoi zwierzyny, jest to łowisko dla najbardziej wytrwałych wędkarzy-odkrywców.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80211, 'Jezioro Bolkowskie', 'jezioro-bolkowskie', 'LAKE', '53.721135919832086', '21.549156128808725', 'Warmińsko-Mazurskie', 'Mrągowo', 'Jezioro Bolkowskie (często utożsamiane z pobliskim Jeziorem Borkowskim) to niewielki, zaciszny akwen położony w bezpośrednim sąsiedztwie jeziora Dłużec. Jest to typowe jezioro polodowcowe o charakterze linowo-szczupakowym. Brzegi są w znacznej części zalesione i podmokłe, co zapewnia rybom naturalną osłonę i ogranicza presję turystyczną. To "dzikie" łowisko dla osób szukających spokoju, gdzie można zapolować na lina i karasia złocistego w zacisznych zatoczkach.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80212, 'Jezioro Gryżewskie', 'jezioro-gryzewskie', 'LAKE', '53.72388811500939', '21.55138030616932', 'Warmińsko-Mazurskie', 'Mikołajki', 'Jezioro Gryżewskie to miniaturowy akwen rynnowy o powierzchni ok. 4 ha, położony w lesie niedaleko północnego krańca Jeziora Bełdany. Mimo niewielkich rozmiarów, jezioro jest dość głębokie i posiada urozmaiconą roślinność podwodną. Ze względu na swoje odosobnienie i trudny dostęp, jest to łowisko niemal całkowicie zapomniane przez turystów. Dominują tu szczupak, okoń oraz płoć. To idealna meta dla wędkarzy-eksploratorów, którzy cenią sobie klimat leśnych oczek mazurskich.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80213, 'Jezioro Smolak Mały', 'jezioro-smolak-maly', 'LAKE', '53.707750684698546', '21.607900203853067', 'Warmińsko-Mazurskie', 'Mikołajki', 'Smolak Mały to unikalne przyrodniczo jezioro dystroficzne, położone w Puszczy Piskiej, w pobliżu miejscowości Popielno. Jest to zbiornik o miękkim, torfowym dnie i charakterystycznej wodzie o herbacianym odcieniu. Jezioro otoczone jest trzęsawiskami i torfowiskami, a na jego tafli można zaobserwować rzadkie zjawisko "pływających wysp" torfowych. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80214, 'Jezioro Warmołty', 'jezioro-warmolty', 'LAKE', '53.70264068979404', '21.62941834013282', 'Warmińsko-Mazurskie', 'Mikołajki', 'Jezioro Warmołty to urokliwy, śródleśny zbiornik o powierzchni ok. 15 ha, położony na południowy wschód od miejscowości Wejsuny. Akwen charakteryzuje się dość czystą wodą i urozmaiconą linią brzegową z przewagą lasów iglastych. Jest to jezioro o charakterze linowo-szczupakowym, rzadko odwiedzane przez turystów, co zapewnia wędkarzom dużą dawkę prywatności. To idealne miejsce na spokojną zasiadkę spławikową w otoczeniu dzikiej przyrody Puszczy Piskiej.', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80215, 'Jezioro Wejsunek', 'jezioro-wejsunek', 'LAKE', '53.683201106504136', '21.61471577016131', 'Warmińsko-Mazurskie', 'Pisz', 'Jezioro Wejsunek (ok. 28 ha) to bardzo popularne wśród lokalnych wędkarzy łowisko położone tuż przy miejscowości Wejsuny. Jezioro ma charakter rynnowy, jest dość płytkie i silnie zarośnięte, co stwarza wybitne warunki dla lina i szczupaka. Słynie z populacji dorodnego karasia złocistego oraz pięknych wzdręg. Ze względu na łatwy dostęp od strony wsi, jest to doskonałe miejsce na rodzinne wędkowanie z licznych pomostów.', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80216, 'Jezioro Guzianka Wielka', 'jezioro-guzianka-wielka', 'LAKE', '53.6660915422553', '21.577312009733827', 'Warmińsko-Mazurskie', 'Ruciane-Nida', 'Guzianka Wielka to strategiczny akwen na szlaku Wielkich Jezior Mazurskich, stanowiący wraz z Guzianką Małą łącznik między Jeziorem Bełdany a Jeziorem Nidzkim. Jezioro (pow. ok. 70 ha) jest głęboką rynną (do 15 m) o wysokich, zalesionych brzegach. Choć w sezonie letnim panuje tu ogromny ruch żeglarski ze względu na śluzę Guzianka, wędkarze cenią to jezioro za populację sandacza i dorodnego leszcza. Najlepsze wyniki osiąga się tu jesienią lub wczesnym świtem, obławiając strome spady rynny głównej.', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80217, 'Jezioro Galik', 'jezioro-galik', 'LAKE', '53.64509135903916', '21.578732021409667', 'Warmińsko-Mazurskie', 'Ruciane-Nida', 'Jezioro Galik to niewielkie, leśne oczko (ok. 4 ha) ukryte na południe od Rucianego-Nidy. Jest to klasyczne jezioro dystroficzne o miękkim, torfowym dnie i charakterystycznej wodzie o barwie mocnej herbaty. Galik jest niemal całkowicie odizolowany od cywilizacji, co czyni go ostoją dla lina i karasia. To łowisko "techniczne", wymagające przedzierania się przez leśne gęstwiny, ale wynagradzające ciszą i spotkaniem z dziką, nienaruszoną przyrodą.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80218, 'Jezioro Pogubie Małe', 'jezioro-pogubie-male', 'LAKE', '53.55199618159174', '21.745451694119932', 'Varminsko-mazursko', 'Pisz', 'Jezero Pogubie Małe je skrovito i plitko jezero smješteno u srcu šume Puszcza Piska, južno od grada Piša (Pisz). Ovo jezero karakterizira netaknuta divlja priroda i vrlo niska razina ljudske intervencije. Voda je bogata organskim tvarima, a obale su niske, močvarne i obrasle gustom vegetacijom. To je idealno stanište za linjaka i karasa. Zbog svog položaja unutar gustog šumskog kompleksa, jezero nudi potpunu tišinu i izolaciju, čineći ga savršenim mjestom za ribiče koji cijene mir i kontakt s prirodom.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80219, 'Jezioro Mokre', 'jezioro-mokre', 'LAKE', '53.69289272569289', '21.390136410696723', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Mokre to jeden z największych i najgłębszych akwenów w dorzeczu Krutyni (pow. ok. 450 ha, głębokość do 28 m). To potężna rynna polodowcowa o urozmaiconym dnie, z pięcioma wyspami. Woda posiada II klasę czystości. Jezioro słynie z populacji sielawy, co przekłada się na obecność wielkich szczupaków i dorodnych okoni żerujących w toni. Obowiązuje tu strefa ciszy, a brzegi są niemal w całości zalesione (Puszcza Piska), co nadaje mu niezwykle dziki charakter.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80220, 'Jezioro Mojtyny', 'jezioro-mojtyny', 'LAKE', '53.69038520820001', '21.343658942878037', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Mojtyny to niewielki, zaciszny akwen o powierzchni ok. 15 ha, położony na zachód od Jeziora Mokrego. Jest to typowe jezioro linowo-szczupakowe o charakterze wytopiskowym. Brzegi są niskie, często podmokłe, co sprzyja populacji ryb spokojnego żeru. To idealne miejsce na spokojną zasiadkę, z dala od głównych szlaków turystycznych, gdzie w ciszy można zapolować na lina i grubą wzdręgę.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80221, 'Jezioro Nawiady', 'jezioro-nawiady', 'LAKE', '53.69313640470437', '21.329065594967243', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Nawiady to malowniczy zbiornik o powierzchni ok. 100 ha, położony w pobliżu miejscowości o tej samej nazwie. Jezioro ma charakter leszczowo-szczupakowy. Charakteryzuje się dość wyrównanym dnem i szerokim pasem trzcin. To bardzo popularne łowisko wśród lokalnych wędkarzy, słynące z regularnych brań leszcza i płoci. Spinningiści chętnie szukają tu szczupaka, który znajduje doskonałe kryjówki w licznych kępach roślinności podwodnej.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80222, 'Jezioro Nowe Kiełbonki', 'jezioro-nowe-kielbonki', 'LAKE', '53.67335611224761', '21.32429286249965', 'Warmińsko-Mazurskie', 'Piecki', 'Nowe Kiełbonki (Kiełbońskie) to rynnowe jezioro przepływowe na szlaku Krutyni. Akwen o powierzchni ok. 25 ha jest stosunkowo płytki, co sprawia, że woda szybko się nagrzewa. Dzięki stałemu przepływowi wody rzeźba dna jest ciekawa, a ryby są tu wyjątkowo waleczne. To doskonałe łowisko okoniowe i szczupakowe. Wędkarze stacjonarni cenią je za obfitość białorybu, zwłaszcza w okresach wiosennych przemieszczeń ryb w górę rzeki.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80223, 'Jezioro Zdruzno', 'jezioro-zdruzno', 'LAKE', '53.63692845302537', '21.350839966151458', 'Warmińsko-Mazurskie', 'Ruciane-Nida', 'Jezioro Zdruzno to okazały zbiornik o powierzchni ok. 120 ha, wchodzący w skład rezerwatu "Krutynia". Akwen charakteryzuje się bardzo urozmaiconą linią brzegową z licznymi półwyspami i zatokami. Woda jest czysta, a brzegi w większości zalesione. To techniczne łowisko leszczowe i szczupakowe. Ze względu na ochronę rezerwatową i strefę ciszy, jest to miejsce dla wędkarzy ceniących pierwotną mazurską przyrodę i brak motorówek.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80224, 'Jezioro Kierwik', 'jezioro-kierwik', 'LAKE', '53.61003849014006', '21.378763179567624', 'Warmińsko-Mazurskie', 'Spychowo', 'Jezioro Kierwik to urokliwy, śródleśny zbiornik o powierzchni ok. 11 ha, położony w sercu Puszczy Piskiej. Akwen charakteryzuje się bardzo czystą wodą i spokojną linią brzegową, niemal w całości porośniętą lasem. Jest to typowe jezioro linowo-szczupakowe, rzadko odwiedzane przez turystów ze szlaku Krutyni, co zapewnia wędkarzom intymność i spokój. To idealne miejsce na poranną zasiadkę w poszukiwaniu "złotego" lina i dorodnej płoci.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80225, 'Jezioro Spychowskie', 'jezioro-spychowskie', 'LAKE', '53.602881181946195', '21.338101265215684', 'Warmińsko-Mazurskie', 'Spychowo', 'Jezioro Spychowskie to istotne ogniwo szlaku Krutyni (pow. ok. 37 ha). Przez jezioro przepływa rzeka, co gwarantuje doskonałe natlenienie wody i stabilne warunki dla ryb. Akwen ma charakter przepływowy, jest dość płytki i posiada bardzo bogatą roślinność wynurzoną. Słynie z populacji sandacza, który lubi tutejsze piaszczyste rynny, oraz walecznych szczupaków i okoni. Mimo dużego ruchu kajakowego w sezonie, wędkarze cenią to jezioro za rybność i łatwy dostęp w miejscowości Spychowo.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80226, 'Jezioro Lichtajny', 'jezioro-lichtajny', 'LAKE', '53.6499734339605', '20.01582288012685', 'Warmińsko-Mazurskie', 'Ostróda', 'Jezioro Lichtajny (ok. 13 ha) to niewielki zbiornik o charakterze linowo-szczupakowym. Położone wśród pól i łąk, oferuje spokojne warunki do wędkowania stacjonarnego. Woda jest stosunkowo żyzna, co sprzyja populacji leszcza i płoci. To idealne miejsce na szybki wypad "po pracy" dla mieszkańców okolic Ostródy.', 'Gospodarstwo Rybackie Ostróda');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80227, 'Jezioro Świetajno', 'jezioro-swietajno-szczycienskie', 'LAKE', '53.603131874116535', '21.245777309813473', 'Warmińsko-Mazurskie', 'Szczytno', 'Jezioro Świetajno (często nazywane przez turystów Jeziorem Narty) to jeden z najczystszych akwenów w Polsce, nazywany "Mazurskimi Karaibami". Woda posiada I klasę czystości, a piaszczyste dno jest widoczne nawet na kilku metrach głębokości. Jezioro (pow. ok. 213 ha) ma charakter sielawowy. To techniczne wyzwanie dla wędkarzy – krystaliczna woda wymusza stosowanie bardzo finezyjnych zestawów. Słynie z olbrzymich okoni, sielawy oraz szczupaków żerujących w toni. Idealne miejsce dla pasjonatów spinningu i nurkowania.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80228, 'Jezioro Piasutno', 'jezioro-piasutno', 'LAKE', '53.606893854621816', '21.206400369735178', 'Warmińsko-Mazurskie', 'Świętajno', 'Jezioro Piasutno (ok. 80 ha) to malowniczy zbiornik o charakterze leszczowo-szczupakowym. Jezioro posiada dość wyrównane dno i szeroki pas trzcinowisk. Woda jest stosunkowo czysta. Akwen słynie z obfitości białorybu, szczególnie dorodnego leszcza i płoci. Spinningiści chętnie szukają tu szczupaka, który znajduje doskonałe kryjówki wzdłuż wschodniego, zalesionego brzegu. To spokojna alternatywa dla bardziej obleganych jezior w regionie.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80229, 'Jezioro Nożyce', 'jezioro-nozyce', 'LAKE', '53.62073498390044', '21.19410425358635', 'Warmińsko-Mazurskie', 'Świętajno', 'Jezioro Nożyce to niewielkie, dzikie oczko leśne ukryte na północ od Piasutna. Jest to klasyczny zbiornik linowo-szczupakowy o powierzchni ok. 25 ha. Brzegi są w większości wysokie i porośnięte gęstym lasem, co chroni taflę przed wiatrem i zapewnia absolutną ciszę. Woda ma lekko brunatny odcień. To idealna meta dla wędkarzy ceniących samotność, gdzie w spokoju można zapolować na grubego lina i dzikiego okonia czatującego pod zwalonymi drzewami.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80230, 'Jezioro Martwe', 'jezioro-martwe-elblag', 'LAKE', '54.23091973299972', '19.49748721662072', 'Warmińsko-Mazurskie', 'Elbląg', 'Jezioro Martwe, położone w popularnej rekreacyjnie Jeleniej Dolinie, to niewielki, ale bardzo urokliwy zbiornik w sercu Parku Krajobrazowego Wysoczyzny Elbląskiej. Jezioro jest dość płytkie i silnie zarośnięte, co czyni je królestwem lina i szczupaka. Ze względu na malownicze położenie wśród wzgórz, jest chętnie odwiedzane przez wędkarzy z Elbląga, szczególnie wiosną.', 'PZW Elbląg');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80231, 'Jezioro Marksoby', 'jezioro-marksoby', 'LAKE', '53.62703277966671', '21.131755216800357', 'Warmińsko-Mazurskie', 'Szczytno', 'Jezioro Marksoby to jedna z najjaśniejszych pereł powiatu szczycieńskiego. Akwen o powierzchni ok. 155 ha charakteryzuje się bardzo czystą wodą i urozmaiconą linią brzegową, niemal w całości otoczoną gęstymi borami Puszczy Piskiej. Jezioro ma charakter rynnowy, jest głębokie i posiada liczne podwodne górki. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80232, 'Jezioro Krawienko', 'jezioro-krawienko', 'LAKE', '53.671529332179055', '21.213681858118658', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Krawienko to kameralny, płytki akwen o powierzchni ok. 28 ha, położony w otulinie Puszczy Piskiej. Jezioro charakteryzuje się dość wysokimi brzegami i bogatą roślinnością zanurzoną (rogatek, ramienice). To typowe łowisko linowo-szczupakowe, gdzie w ciszy można zapolować na dorodną płoć i lina. Woda jest stosunkowo czysta, a brak dużej presji turystycznej sprawia, że jest to idealne miejsce dla wędkarzy ceniących spokój i kontakt z naturą.', 'Kompania Mazurska Pasym');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80233, 'Jezioro Krawno Wielkie', 'jezioro-krawno-wielkie', 'LAKE', '53.67450043520115', '21.193652295015138', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Krawno Wielkie (często nazywane po prostu Krawnem) to malowniczy, rynnowy zbiornik o powierzchni ok. 45 ha. Jezioro otoczone jest przepięknymi lasami i posiada bardzo urozmaiconą linię brzegową z licznymi zatokami. Woda jest żyzna, a dno w wielu miejscach muliste, co sprzyja populacji linów i grubych leszczy. Słynie z walecznych szczupaków oraz sandaczy, które znajdują tu doskonałe kryjówki na stokach podwodnych rynien. To wybitne łowisko dla osób szukających "dzikich" Mazur.', 'Kompania Mazurska Pasym');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80234, 'Jezioro Tejsowo', 'jezioro-tejsowo', 'LAKE', '53.68995162609771', '21.220337695336653', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Tejsowo to urokliwy zbiornik o powierzchni ok. 30 ha, położony na odludziu, w malowniczej dolinie pośród lasów. Akwen ma charakter rynnowy i jest dość głęboki (do 16 m). Dzięki połączeniu z dorzeczem Babięckiej Strugi, ryby mogą tu swobodnie migrować, co zwiększa atrakcyjność wędkarską jeziora. Słynie z populacji szczupaka i okonia, a wędkarze stacjonarni cenią je za dorodne wzdręgi i liny. To miejsce, gdzie czas płynie wolniej, a brania potrafią być bardzo widowiskowe.', 'Kompania Mazurska Pasym');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80235, 'Jezioro Gant', 'jezioro-gant', 'LAKE', '53.71081365209681', '21.23879676714585', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Gant (Ganckie) to perła szlaku Krutyni, imponująca rynna polodowcowa o powierzchni ok. 75 ha i głębokości sięgającej 28 metrów. Brzegi jeziora są strome, wysokie i niemal w całości zalesione. Woda posiada wysoką klasę czystości. To klasyczne łowisko sielawowe, co gwarantuje obecność wielkich, toniowych szczupaków. Spinningiści chętnie szukają tu sandaczy na podwodnych stokach, a wędkarze spławikowi mogą liczyć na rekordowe leszcze.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80236, 'Jezioro Białe (Pieckie)', 'jezioro-biale-pieckie', 'LAKE', '53.73136668687971', '21.247774928122613', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Białe koło Gantu to potężny, rynnowy akwen o powierzchni ok. 150 ha i krystalicznie czystej wodzie (I klasa czystości). Jezioro słynie z niesamowitej przejrzystości, co sprawia, że dno porośnięte łąkami ramienicowymi widać nawet na kilku metrach. To wybitne łowisko sielawowe, cenione za populację ogromnych okoni i szczupaków. Ze względu na czystość wody, ryby są tu wyjątkowo waleczne, ale i ostrożne, co wymaga od wędkarza dużej finezji i techniki.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80237, 'Jezioro Nawiadki', 'jezioro-nawiadki', 'LAKE', '53.68166602559223', '21.31934645837694', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Nawiadki to niewielki (ok. 10 ha), ale bardzo urokliwy akwen położony w sąsiedztwie większego jeziora Nawiady. Jest to typowe jezioro śródpolne o charakterze linowo-szczupakowym. Woda jest stosunkowo czysta, a brzegi otoczone malowniczymi pagórkami i kępami lasu. To idealne miejsce na spokojną zasiadkę spławikową, gdzie w ciszy można zapolować na dorodną płoć i lina. Jezioro jest rzadko odwiedzane przez turystów, co zapewnia wędkarzom dużą dawkę prywatności.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80238, 'Jezioro Pawełek', 'jezioro-pawelek', 'LAKE', '53.67689999066312', '21.334776987898824', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Pawełek to małe, leśne oczko (ok. 5 ha) ukryte pośród borów Puszczy Piskiej, niedaleko Nowych Kiełbonek. Jezioro charakteryzuje się miękkim, torfowym dnem i wodą o lekko brunatnym zabarwieniu. To klasyczny zbiornik linowo-karasiowy, niemal całkowicie odcięty od zgiełku turystycznego. Brzegi są dzikie i trudno dostępne, co sprzyja populacji "złotych" karasi i linów. To łowisko dla wędkarzy-eksploratorów, którzy cenią sobie klimat pierwotnej przyrody.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80239, 'Jezioro Zyzdrój Wielki', 'jezioro-zyzdroj-wielki', 'LAKE', '53.640228391252435', '21.29779593063066', 'Warmińsko-Mazurskie', 'Spychowo', 'Zyzdrój Wielki to okazałe jezioro rynnowe o powierzchni ok. 200 ha, będące kluczowym etapem szlaku Krutyni. Akwen zachwyca krajobrazem – brzegi są wysokie, porośnięte gęstą puszczą, a na jeziorze znajduje się słynna "Wyspa Miłości". Jezioro jest głębokie (do 14,5 m) i posiada bardzo urozmaicone dno. Słynie z populacji sandacza, dużego leszcza oraz rekordowych szczupaków żerujących na stokach rynny. Mimo ruchu kajakowego w sezonie, jego wielkość pozwala na znalezienie spokojnych zatok idealnych do wędkowania z łodzi.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80240, 'Jezioro Pogubie Wielkie', 'jezioro-pogubie-wielkie', 'LAKE', '53.5788443409671', '21.745971417700858', 'Warmińsko-Mazurskie', 'Pisz', 'Jezioro Pogubie Wielkie to potężny (ok. 700 ha), ale niezwykle płytki akwen (średnia głębokość to zaledwie 1 m). Całość jeziora stanowi rezerwat przyrody „Jezioro Pogubie Wielkie”, chroniący miejsca lęgowe licznych gatunków ptaków wodnych. Jezioro jest niemal w całości porośnięte roślinnością wynurzoną i zanurzoną. UWAGA: Ze względu na status rezerwatu, wędkowanie jest tu mocno ograniczone i możliwe tylko w wyznaczonych strefach i okresach. To królestwo lina i szczupaka, gdzie woda tętni życiem, a krajobraz przypomina dzikie rozlewiska Biebrzy.', 'PZW Suwałki / RDOŚ Olsztyn (Rezerwat)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80241, 'Jezioro Domowe Wielkie', 'jezioro-domowe-wielkie', 'LAKE', '53.56873689187961', '20.978414179848286', 'Warmińsko-Mazurskie', 'Szczytno', 'Jezioro Domowe Wielkie (często nazywane przez mieszkańców Jeziorem Długim) to większy z dwóch akwenów znajdujących się w granicach Szczytna (pow. ok. 60 ha). Jezioro otoczone jest nowoczesną promenadą, ścieżkami rowerowymi i parkami, co czyni je sercem rekreacyjnym miasta. Dzięki przeprowadzonej rekultywacji, woda jest czysta, a rybostan systematycznie odbudowywany. To świetne miejsce na miejski spinning – słynie z populacji sandacza oraz okonia. Wędkarze stacjonarni cenią je za wygodne pomosty i regularne brania leszcza oraz płoci.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80242, 'Jezioro Iłgiełk', 'jezioro-ilgielk', 'LAKE', '54.06204235473965', '23.471072037702573', 'Podlaskie', 'Sejny', 'Jezioro Iłgiełk (ok. 34 ha) to rynnowy akwen położony na skraju Puszczy Augustowskiej. Typ jeziora: leszczowy. Charakteryzuje się bogatą roślinnością zanurzoną, która porasta niemal całą misę dna do głębokości 3,6 m. To doskonałe miejsce dla wędkarzy szukających dorodnej płoci, wzdręgi i okonia.', 'Gospodarstwo Rybackie Falko');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80243, 'Jezioro Domowe Małe', 'jezioro-domowe-male', 'LAKE', '53.567304238634144', '20.994498439545012', 'Warmińsko-Mazurskie', 'Szczytno', 'Jezioro Domowe Małe (pow. ok. 10 ha) znajduje się w samym centrum Szczytna, tuż przy ruinach zamku krzyżackiego i ratuszu. Jest połączone z Jeziorem Domowym Wielkim wąskim kanałem. To płytki, bardzo żyzny akwen o charakterze parkowym. Brzegi są doskonale zagospodarowane, z licznymi ławeczkami i pomostami. Wędkarsko to typowe łowisko linowo-karasiowe. Ze względu na położenie, jest to idealne miejsce na krótkie, popołudniowe zasiadki spławikowe, gdzie można złowić ładne płocie, wzdręgi i liny.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80244, 'Jezioro Lemańskie', 'jezioro-lemanskie', 'LAKE', '53.587936342361225', '21.036748751275358', 'Warmińsko-Mazurskie', 'Szczytno', 'Jezioro Lemańskie (Lemany) to urokliwy akwen o powierzchni ok. 15 ha, położony na północny wschód od Szczytna, w pobliżu miejscowości Lemany. Jezioro ma charakter linowo-szczupakowy i jest otoczone malowniczą mozaiką pól i lasów. Charakteryzuje się dość czystą wodą i bogatą roślinnością wynurzoną. To bardzo spokojne łowisko, rzadko odwiedzane przez turystów, co sprzyja populacji dzikiego lina i dorodnego karasia złocistego. Spinningiści mogą tu liczyć na spotkanie z walecznym szczupakiem czatującym w pasach trzcin.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80245, 'Jezioro Zielonieckie', 'jezioro-zielonieckie', 'LAKE', '53.598378824457534', '21.03563411140237', 'Warmińsko-Mazurskie', 'Szczytno', 'Jezioro Zielonieckie (Zielonka) to niewielkie, leśne oczko (ok. 8 ha) położone na północ od Leman. Jest to zbiornik o charakterze szczupakowo-okoniowym, niemal całkowicie otoczony lasem. Jezioro charakteryzuje się piaszczysto-mulistym dnem i wodą o lekko brunatnym zabarwieniu. Ze względu na swoje odosobnienie i brak infrastruktury, jest to łowisko dla wędkarzy ceniących ciszę i kontakt z dziką naturą. Słynie z dużej populacji okonia, który bardzo chętnie reaguje tu na małe przynęty gumowe.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80246, 'Jezioro Romanek', 'jezioro-romanek', 'LAKE', '53.603425358555334', '20.97694172455086', 'Warmińsko-Mazurskie', 'Szczytno', 'Jezioro Romanek (znane również jako Romany) to urokliwy, hydrologicznie zamknięty akwen o powierzchni ok. 14 ha, położony na północny zachód od Szczytna. Jezioro charakteryzuje się spokojną okolicą i jest popularnym miejscem rekreacji dla mieszkańców pobliskich miejscowości. Jest to typowe jezioro linowo-szczupakowe o czystej wodzie i dość dobrze rozwiniętej linii brzegowej. Ze względu na brak odpływu i dopływu, ryby mają tu stabilne warunki bytowe, co sprzyja populacji linów i dorodnych płoci.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80247, 'Jezioro Fręckie', 'jezioro-freckie', 'LAKE', '53.6102012012053', '20.95903486990876', 'Warmińsko-Mazurskie', 'Szczytno', 'Jezioro Fręckie to niewielki zbiornik o powierzchni ok. 13 ha, położony w pobliżu miejscowości Dębówko. Akwen ma charakter linowo-szczupakowy i jest średnio zasobny w ryby, co czyni go idealnym miejscem dla wędkarzy szukających ciszy z dala od obleganych łowisk. Jezioro otaczają pola i łąki, a dostęp do wody jest możliwy w kilku punktach. Mimo niewielkich rozmiarów, potrafi zaskoczyć ładnym szczupakiem czatującym w pasach trzcinowisk.', 'PZW Olsztyn (Zakład Rybacki Szczytno)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80248, 'Jezioro Sasek Wielki', 'jezioro-sasek-wielki', 'LAKE', '53.63885364994586', '20.927323749684703', 'Warmińsko-Mazurskie', 'Szczytno', 'Sasek Wielki to największe jezioro powiatu szczycieńskiego, o imponującej powierzchni ok. 870 ha. Jest to typowe jezioro rynnowe o długości ponad 12 km, ciągnące się z północy na południe. Akwen słynie z niezwykle urozmaiconego dna z licznymi głęboczkami (do 38 m) i podwodnymi górkami. Na jeziorze znajdują się dwie wyspy. Sasek Wielki to legendarne łowisko sielawowe, cenione przede wszystkim za populację sandacza, dużego szczupaka oraz rekordowych okoni. Na całym jeziorze obowiązuje strefa ciszy, co w połączeniu z czystą wodą (III klasa) i malowniczymi brzegami czyni je jednym z najatrakcyjniejszych punktów na mapie Mazur.', 'PZW Okręg Mazowiecki (Zakład Rybacki Szczytno)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80249, 'Jezioro Gromskie', 'jezioro-gromskie', 'LAKE', '53.63443634461249', '20.88500942179239', 'Warmińsko-Mazurskie', 'Pasym', 'Jezioro Gromskie (Grom) to okazała rynna polodowcowa o powierzchni ok. 200 ha. Jezioro charakteryzuje się dość wysokimi, zalesionymi brzegami i czystą wodą. Wędkarsko to typowe łowisko szczupakowo-leszczowe. Słynie z dużej populacji okonia oraz dorodnego leszcza. Ze względu na urozmaicone dno z licznymi spadami, jest to techniczne łowisko, które wymaga od wędkarza cierpliwości, ale potrafi wynagrodzić okazami powyżej średniej krajowej.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80250, 'Jezioro Leleskie', 'jezioro-leleskie', 'LAKE', '53.641073071484584', '20.848415540660017', 'Warmińsko-Mazurskie', 'Pasym', 'Jezioro Leleskie to absolutna perła regionu i jedno z najczystszych jezior w Polsce (I/II klasa czystości). Jest bardzo głębokie (do 49 m) i posiada krystaliczną wodę o błękitnym odcieniu. To legendarne łowisko sielawowe, znane przede wszystkim z populacji potężnych okoni (garbusów), które w przejrzystej toni osiągają imponujące rozmiary. Obowiązuje tu strefa ciszy, co w połączeniu z dziką linią brzegową i kilkoma wyspami tworzy unikalny mikroklimat dla wędkarzy i nurków.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80251, 'Jezioro Kalwa', 'jezioro-kalwa', 'LAKE', '53.656852557420315', '20.78672906943014', 'Warmińsko-Mazurskie', 'Pasym', 'Kalwa to największe jezioro w okolicach Pasymia (pow. ok. 560 ha), o charakterystycznym kształcie podkowy. Posiada niezwykle rozwiniętą linię brzegową z mnóstwem zatok, półwyspów i ośmioma wyspami. Jest to klasyczne łowisko sandaczowo-szczupakowe. Płytkie, zarośnięte zatoki są domem dla dużych linów, natomiast twardsze partie dna to królestwo sandacza. Mimo sporej presji turystycznej, ogromna liczba "zakamarków" pozwala każdemu wędkarzowi znaleźć cichą miejscówkę.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80252, 'Jezioro Kalwa Mała', 'jezioro-kalwa-mala', 'LAKE', '53.67142747628159', '20.785271142465557', 'Warmińsko-Mazurskie', 'Pasym', 'Kalwa Mała to mniejszy sąsiad głównej Kalwy, o powierzchni ok. 14 ha. Jest to jezioro znacznie spokojniejsze, o charakterze linowo-szczupakowym. Woda jest tu nieco żyźniejsza, a dno mulisto-piaszczyste. To świetna meta na poranną zasiadkę spławikową w poszukiwaniu lina i karasia złocistego. Często pomijane przez turystów, co czyni je doskonałym wyborem dla osób ceniących ciszę.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80253, 'Jezioro Kalwka', 'jezioro-kalwka', 'LAKE', '53.68259337970542', '20.740265404578395', 'Warmińsko-Mazurskie', 'Pasym', 'Kalwka to niewielkie, śródleśne oczko położone na północny zachód od jeziora Kalwa. Jest to akwen o typowo dzikim charakterze, otoczony borem iglastym. Powierzchnia to zaledwie kilka hektarów, ale jezioro jest głębokie i czyste. To idealne miejsce na "escape fishing" – krótki wypad z lekkim sprzętem w poszukiwaniu okoni i płoci.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80254, 'Jezioro Upałtek', 'jezioro-upaltek', 'LAKE', '53.68989864783031', '20.745747150957076', 'Warmińsko-Mazurskie', 'Pasym', 'Upałtek to zaciszny zbiornik o powierzchni ok. 15 ha. Jezioro charakteryzuje się dość regularną linią brzegową i jest otoczone malowniczą mozaiką pól i lasów. Ma charakter linowo-szczupakowy. Woda jest przejrzysta, a dno piaszczysto-muliste. Słynie z pięknych wzdręg i aktywnych szczupaków, które chętnie atakują wzdłuż pasów trzcinowisk.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80255, 'Jezioro Troyl', 'jezioro-troyl', 'LAKE', '54.22111840877471', '19.503632660949886', 'Warmińsko-Mazurskie', 'Tolkmicko', 'Jezioro Troyl (Troil) to kolejny z klejnotów Wysoczyzny Elbląskiej. To dzikie jezioro leśne, niemal całkowicie odizolowane od cywilizacji. Woda ma lekko brunatny odcień, a dno jest muliste. To typowe łowisko "dzikiego" lina i karasia złocistego. Wymaga od wędkarza przedzierania się przez gęste lasy bukowe, co wynagradza niesamowitą ciszą i szansą na spotkanie z pięknie ubarwionymi rybami.', 'PZW Elbląg');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80256, 'Jezioro Purdy', 'jezioro-purdy', 'LAKE', '53.69178619899871', '20.72083352797939', 'Warmińsko-Mazurskie', 'Purda', 'Jezioro Purdy (Purdzkie) to malowniczy, rynnowy zbiornik o powierzchni ok. 87 ha, położony tuż przy miejscowości Purda. Jezioro charakteryzuje się urozmaiconą linią brzegową i znaczną głębokością (ponad 30 m). Woda jest czysta, a brzegi otaczają piękne warmińskie lasy. Wędkarsko to typowe łowisko leszczowo-sielawowe. Słynie z dużej populacji okonia oraz regularnych zarybień szczupakiem i sielawą. To doskonałe miejsce dla wędkarzy ceniących spokój, ale z dobrym dostępem do infrastruktury w pobliskiej Purdzie.', 'Stowarzyszenie Ekologiczne Łajs 2000');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80257, 'Jezioro Dłużek', 'jezioro-dluzek-purda', 'LAKE', '53.69438128851199', '20.767904988736685', 'Warmińsko-Mazurskie', 'Pasym', 'Jezioro Dłużek to ukryta w lesie perła powiatu szczycieńskiego i olsztyńskiego. Akwen o powierzchni ok. 29 ha jest zbiornikiem hydrologicznie zamkniętym i słynie z niesamowitej, krystalicznej czystości wód (II klasa, ale o przejrzystości bliskiej I). Jezioro ma wydłużony kształt i jest otoczone dziewiczymi lasami. Wędkarsko zaliczane do typu sandaczowego, choć dominują tu szczupak, okoń oraz ryby spokojnego żeru: leszcz, płoć i lin. Ze względu na unikatowe walory przyrodnicze i czystość wody, zaleca się tu szczególną dbałość o etykę wędkarską i ekologię.', 'Kompania Mazurska Sp. z o.o.');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80258, 'Jezioro Serwent', 'jezioro-serwent', 'LAKE', '53.708666598944816', '20.754556322679637', 'Warmińsko-Mazurskie', 'Purda', 'Serwent to jedno z najpiękniejszych i najczystszych jezior na Warmii i Mazurach (I klasa czystości). Akwen o powierzchni ok. 250 ha położony jest w całkowitej izolacji od osad ludzkich, w sercu Purdzkich Lasów. Obowiązuje tu strefa ciszy. Woda jest przejrzysta na kilka metrów, a dno w wielu miejscach porastają łąki ramienicowe. To elitarne łowisko sielawowe. Wędkarze szukają tu przede wszystkim wielkich, "toniowych" szczupaków i rekordowych okoni. Jezioro posiada urozmaicone dno z głębokimi rynnami i podwodnymi górkami, co czyni je technicznie wymagającym, ale bardzo satysfakcjonującym.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80259, 'Jezioro Wielkie Kajmno', 'jezioro-wielkie-kajmno', 'LAKE', '53.7188236514682', '20.72553216714014', 'Warmińsko-Mazurskie', 'Purda', 'Jezioro Wielkie Kajmno (znane również jako Kemno Wielkie) to dziki, leśny zbiornik o powierzchni ok. 30 ha, położony na północ od jeziora Serwent. Jest to typowe jezioro linowo-szczupakowe, o stosunkowo czystej wodzie i silnie rozwiniętej roślinności przybrzeżnej. Brzegi są w większości wysokie i zalesione, co utrudnia dostęp z lądu, ale zapewnia rybom doskonałe warunki do naturalnego rozrodu. To idealne łowisko dla osób szukających samotności i kontaktu z nienaruszoną przyrodą, polujących na dzikie szczupaki i liny.', 'Gospodarstwo Rybackie LokFish');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80260, 'Jezioro Małe Kajmno', 'jezioro-male-kajmno', 'LAKE', '53.721300991832514', '20.73540178937401', 'Warmińsko-Mazurskie', 'Purda', 'Jezioro Małe Kajmno (Kemno Małe) to niewielkie, śródleśne oczko o powierzchni ok. 6 ha, położone w bezpośrednim sąsiedztwie swojego "Wielkiego" brata. Akwen jest niemal całkowicie ukryty w gęstym borze, co zapewnia mu status łowiska wyjątkowo spokojnego i dzikiego. Jezioro charakteryzuje się torfowym dnem i wodą o barwie mocnej herbaty. To królestwo lina i karasia złocistego. Brzegi są trudne, często bagniste, co sprawia, że jest to miejsce dla wędkarzy ceniących survivalowy klimat i brak jakiejkolwiek infrastruktury.', 'Gospodarstwo Rybackie LokFish');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80261, 'Jezioro Pajtuńskie', 'jezioro-pajtunskie', 'LAKE', '53.72812068894047', '20.719123169012832', 'Warmińsko-Mazurskie', 'Purda', 'Jezioro Pajtuńskie (ok. 25 ha) to bardzo ciekawe jezioro przepływowe, przez które płynie rzeka Kośna. Dzięki stałemu ruchowi wody, akwen jest doskonale natleniony i obfituje w ryby białe oraz drapieżniki. Jezioro otoczone jest malowniczymi łąkami i kępami lasu w pobliżu miejscowości Pajtuny. Słynie z walecznych szczupaków i dorodnych okoni, które chętnie grupują się w nurcie rzeki wpływającym do jeziora. To świetne łowisko dla osób lubiących aktywny spinning z łodzi lub lekką gruntówkę.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80262, 'Jezioro Klebarskie', 'jezioro-klebarskie', 'LAKE', '53.74202577795801', '20.59830083475937', 'Warmińsko-Mazurskie', 'Olsztyn', 'Jezioro Klebarskie to jeden z największych i najpopularniejszych akwenów w bezpośrednim sąsiedztwie Olsztyna (pow. ok. 260 ha). Jezioro jest stosunkowo płytkie (średnio ok. 3 m), co sprzyja bardzo szybkiemu nagrzewaniu się wody i intensywnemu żerowaniu ryb. Klebark słynie w całym regionie jako "maszyna do produkcji leszcza" – ryby te osiągają tu imponujące rozmiary. Bardzo silna jest również populacja sandacza i szczupaka, które znajdują idealne warunki na pofałdowanym, piaszczysto-mulistym dnie. Mimo sporej presji wędkarskiej, jezioro regularnie obdarowuje rekordowymi okazami.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80263, 'Jezioro Linowskie', 'jezioro-linowskie', 'LAKE', '53.72754619195491', '20.57809093212071', 'Warmińsko-Mazurskie', 'Olsztyn', 'Jezioro Linowskie (ok. 15 ha) to kameralny akwen położony na wschód od Olsztyna, w pobliżu miejscowości Linowo. Jest to typowe jezioro rynnowe o charakterze linowo-szczupakowym. Woda jest stosunkowo czysta, a brzegi otoczone malowniczą mozaiką pól i lasów. Jezioro słynie z populacji dorodnego lina oraz walecznych szczupaków. Ze względu na brak dużej presji turystycznej, jest to idealne miejsce dla wędkarzy ceniących spokój i kontakt z naturą.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80264, 'Jezioro Bartąg', 'jezioro-bartag', 'LAKE', '53.71728324189076', '20.49169219246121', 'Warmińsko-Mazurskie', 'Olsztyn', 'Jezioro Bartąg (ok. 72 ha) to bardzo popularny akwen położony tuż przy południowej granicy Olsztyna, w miejscowości Bartąg. Jest to jezioro przepływowe, przez które płynie rzeka Łyna, co gwarantuje doskonałe natlenienie wody i bogaty rybostan. Akwen ma charakter rynnowy i jest dość głęboki (do 14 m). Słynie z populacji sandacza, szczupaka oraz dorodnego leszcza. Ze względu na bliskość dużych osiedli (Jaroty, Pieczewo), jezioro cieszy się dużą popularnością wśród lokalnych wędkarzy.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80265, 'Jezioro Kielarskie', 'jezioro-kielarskie', 'LAKE', '53.69501119727478', '20.512125899892435', 'Warmińsko-Mazurskie', 'Olsztyn', 'Jezioro Kielarskie to okazały, rynnowy zbiornik o powierzchni ok. 130 ha, położony na południe od Olsztyna, w otulinie rezerwatu "Las Warmiński". Przez jezioro przepływa rzeka Łyna. Akwen charakteryzuje się bardzo urozmaiconą linią brzegową i znaczną głębokością (do 25 m). Brzegi są w większości wysokie i zalesione, co nadaje mu dziki i majestatyczny charakter. To wybitne łowisko leszczowo-szczupakowe, cenione za krystaliczną wodę i obecność rekordowych okazów drapieżników.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80266, 'Jezioro Gągławieckie', 'jezioro-gaglawieckie', 'LAKE', '53.683213874656', '20.457373948096876', 'Warmińsko-Mazurskie', 'Stawiguda', 'Jezioro Gągławieckie (ok. 36 ha) to malowniczy, rynnowy zbiornik położony w pobliżu miejscowości Gągławki. Akwen charakteryzuje się dość urozmaiconą linią brzegową i czystą wodą. Jezioro jest otoczone lasami i polami, co zapewnia wędkarzom ciszę i spokój. To klasyczne łowisko leszczowo-szczupakowe, słynące z dorodnych płoci oraz okoni. Ze względu na umiarkowaną presję wędkarską, jest to doskonałe miejsce na relaksujący wypad z łodzi lub lekką gruntówkę.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80267, 'Jezioro Kluka Duża', 'jezioro-kluka-duza', 'LAKE', '53.6840294958896', '20.426346651197804', 'Warmińsko-Mazurskie', 'Olsztyn', 'Jezioro Kluka Duża (ok. 9 ha) to niewielkie, zaciszne oczko położone w lesie nieopodal trasy Olsztyn-Warszawa. Mimo bliskości szlaku komunikacyjnego, jezioro zachowuje swój dziki charakter. Jest to typowy zbiornik linowo-szczupakowy o mulistym dnie i bogatej roślinności wynurzoną. To idealna meta dla wędkarzy szukających "złotego" lina i karasia złocistego w spokoju leśnej głuszy. Brzegi są miejscami podmokłe, co dodaje mu uroku dzikiego łowiska.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80268, 'Jezioro Wulpińskie', 'jezioro-wulpinskie', 'LAKE', '53.70704886415574', '20.345802478425927', 'Warmińsko-Mazurskie', 'Olsztyn', 'Jezioro Wulpińskie (często nazywane Dorotowskim) to jeden z najpiękniejszych i najbardziej urozmaiconych akwenów w okolicach Olsztyna (pow. ok. 700 ha). Jezioro składa się z dwóch wyraźnych części połączonych przewężeniem i posiada aż 8 wysp, z których najsłynniejsza to Herta. Woda jest czysta (II klasa), a dno bardzo urozmaicone z głęboczkami sięgającymi 54 metrów. To wybitne łowisko sielawowo-sandaczowe, znane z olbrzymich szczupaków, rekordowych okoni oraz dorodnych leszczy. Obowiązuje tu strefa ciszy, co czyni je rajem dla wędkarzy i żeglarzy ceniących naturę.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80269, 'Jezioro Świętajno (Naterki)', 'jezioro-swietajno-naterki', 'LAKE', '53.725753175639056', '20.367456295023874', 'Warmińsko-Mazurskie', 'Olsztyn', 'Jezioro Świętajno (ok. 23 ha) położone jest w pobliżu miejscowości Naterki. Nie należy go mylić z popularnym akwenem w Nartach. To urokliwe, śródleśne jezioro o charakterze linowo-szczupakowym. Woda jest stosunkowo czysta, a brzegi w dużej mierze zalesione i wysokie. To doskonałe miejsce dla wędkarzy szukających spokoju blisko Olsztyna, oferujące dobre warunki do połowu dorodnej płoci oraz okonia.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80270, 'Jezioro Sarąg', 'jezioro-sarag', 'LAKE', '53.691465044635656', '20.27898358197047', 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Jezioro Sarąg to okazały zbiornik rynnowy o powierzchni ok. 180 ha, położony w malowniczej dolinie rzeki Pasłęki. Jezioro charakteryzuje się bardzo urozmaiconą linią brzegową i znaczną głębokością (do 16 m). Słynie z krystalicznie czystej wody i bogatego rybostanu, w którym dominują szczupak, sandacz oraz dorodny leszcz. To techniczne łowisko, cenione przez spinningistów za liczne podwodne górki i twarde, piaszczyste blaty.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80271, 'Jezioro Helgut', 'jezioro-helgut', 'LAKE', '53.67915042535254', '20.181370085577413', 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Helgut to niewielkie, dzikie oczko leśne ukryte pośród borów niedaleko miejscowości Guzowy Piec. Jezioro ma powierzchnię ok. 15 ha i charakter linowo-szczupakowy. Charakteryzuje się miękkim dnem i wodą o lekko brunatnym zabarwieniu. To idealne miejsce na "escape fishing" – absolutna cisza, kontakt z dziką naturą i szansa na złotego lina sprawiają, że jest to łowisko wyjątkowe dla pasjonatów spławika.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80272, 'Jezioro Gugowo', 'jezioro-gugowo', 'LAKE', '53.63937491159673', '20.139596252618357', 'Warmińsko-Mazurskie', 'Olsztynek', 'Jezioro Gugowo (Gugówko) to miniaturowy zbiornik (ok. 10 ha) o wybitnie linowo-karasiowym charakterze. Akwen jest płytki, silnie zarośnięty i posiada bardzo muliste dno. Brzegi są podmokłe i trudno dostępne, co sprzyja populacji dzikich ryb spokojnego żeru. To łowisko dla wędkarzy cierpliwych, którzy potrafią łowić w "oknach" roślinności wynurzonej.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80273, 'Jezioro Obst', 'jezioro-obst', 'LAKE', '53.62667090623614', '20.119897708278234', 'Warmińsko-Mazurskie', 'Olsztynek', 'Jezioro Obst to leśny, bagnisty zbiornik położony na odludziu w pobliżu Ostrowina. Jest to klasyczne jezioro dystroficzne, w fazie intensywnego lądowacenia. Woda jest kwaśna i miękka, a dno wyścielone grubą warstwą torfu. To unikalne łowisko karłowatego okonia i lina, cenione głównie za niesamowite walory przyrodnicze i kompletną izolację od cywilizacji.', 'Nadleśnictwo Olsztynek / PZW');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80274, 'Jezioro Ostrowin', 'jezioro-ostrowin', 'LAKE', '53.65681881525355', '20.071223307325734', 'Warmińsko-Mazurskie', 'Olsztynek', 'Jezioro Ostrowin to malownicza rynna o powierzchni ok. 75 ha, położona przy miejscowości o tej samej nazwie. Jezioro charakteryzuje się czystą wodą i urozmaiconym dnem. Brzegi są wysokie, częściowo zalesione. To bardzo solidne łowisko szczupakowe i leszczowe. Ryby mają tu doskonałe warunki do żerowania na piaszczystych stokach rynny głównej. Cieszy się uznaniem wśród spinningistów szukających jesiennych szczupaków.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80275, 'Jezioro Platyńskie', 'jezioro-platynskie', 'LAKE', '53.603505289445806', '20.17203909713277', 'Warmińsko-Mazurskie', 'Olsztynek', 'Jezioro Platyńskie to piękna rynna polodowcowa o powierzchni ok. 120 ha. Jezioro słynie z krystalicznie czystej wody i piaszczystego dna. Brzegi są w większości wysokie i zalesione, co nadaje mu kameralny charakter. To doskonałe łowisko sielawowe, cenione przez spinningistów za populację grubego okonia i szczupaka żerującego na stokach rynny.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80276, 'Jezioro Sajmino', 'jezioro-sajmino', 'LAKE', '53.684239866081896', '19.98877788725218', 'Warmińsko-Mazurskie', 'Ostróda', 'Jezioro Sajmino, znane lokalnie jako Kajkowskie (pow. ok. 30 ha), to bardzo popularny akwen rekreacyjny Ostródy. Mimo miejskiego charakteru i dobrze zagospodarowanych plaż, oferuje świetne warunki do połowu okonia i szczupaka. Woda jest czysta, a dno piaszczyste, co sprzyja aktywnej turystyce wędkarskiej.', 'Gospodarstwo Rybackie Ostróda');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80277, 'Jezioro Morliny', 'jezioro-morliny', 'LAKE', '53.675482659745704', '19.941499371886245', 'Warmińsko-Mazurskie', 'Ostróda', 'Jezioro Morliny to rynnowy akwen o powierzchni ok. 50 ha. Położone w pobliżu znanych zakładów mięsnych, jest cenionym łowiskiem sandacza i szczupaka. Charakteryzuje się dość stromymi spadami i twardym dnem w wielu partiach, co czyni je atrakcyjnym dla spinningistów łowiących z opadu.', 'Gospodarstwo Rybackie Ostróda');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80278, 'Jezioro Smordy', 'jezioro-smordy', 'LAKE', '53.69244192007658', '19.93720855656221', 'Warmińsko-Mazurskie', 'Ostróda', 'Jezioro Smordy (Jakuba) to niewielki akwen bezpośrednio sąsiadujący z Ostródą i jeziorem Drwęckim. Jest to płytkie jezioro o charakterze linowo-szczupakowym, silnie zarośnięte, co stwarza idealne warunki dla ryb spokojnego żeru i młodych drapieżników.', 'Gospodarstwo Rybackie Ostróda');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80279, 'Jezioro Drwęckie', 'jezioro-drweckie', 'LAKE', '53.69785571813175', '19.90212275923167', 'Warmińsko-Mazurskie', 'Ostróda', 'Drwęckie to największe jezioro Ostródy (pow. ok. 880 ha) i ważny węzeł Kanału Elbląskiego. Przez jezioro przepływa rzeka Drwęca. To wybitne łowisko sandaczowe. Ogromna powierzchnia, liczne zatoki i zróżnicowane dno sprawiają, że jest to mekka dla wędkarzy łodziowych. Słynie z dorodnych leszczy, węgorzy i jesiennych brań wielkich szczupaków.', 'Gospodarstwo Rybackie Ostróda');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80280, 'Jezioro Perskie', 'jezioro-perskie', 'LAKE', '53.71288007046273', '19.98578518431613', 'Warmińsko-Mazurskie', 'Ostróda', 'Jezioro Perskie (ok. 12 ha) to kameralny, śródleśny zbiornik o charakterze rynnowym. Ukryte w gęstym borze niedaleko Starych Jabłonek, oferuje krystaliczną wodę i absolutną ciszę. To typowe łowisko szczupakowo-okoniowe, cenione przez wędkarzy szukających samotności. Ze względu na wysokie brzegi i leśne otoczenie, jezioro jest osłonięte od wiatru, co sprzyja precyzyjnemu łowieniu z małych łódek lub pontonów.', 'Gospodarstwo Rybackie Ostróda');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80281, 'Jezioro Szeląg Wielki', 'jezioro-szelag-wielki', 'LAKE', '53.7353839816276', '20.028131010154326', 'Warmińsko-Mazurskie', 'Ostróda', 'Szeląg Wielki to jedna z najpiękniejszych i najdłuższych rynien polodowcowych w regionie (pow. ok. 600 ha, długość 12 km). Jezioro jest częścią szlaku Kanału Elbląskiego. Charakteryzuje się bardzo wysokimi, zalesionymi brzegami (Lasy Taborskie) i czystą wodą. To wybitne łowisko sielawowe, znane z potężnych szczupaków i okoni żerujących w toni. Ze względu na głębokość sięgającą 35 metrów, jest to akwen wymagający technicznie, ale niezwykle rybny.', 'Gospodarstwo Rybackie Ostróda');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80282, 'Jezioro Mielnik', 'jezioro-mielnik', 'LAKE', '53.734806258217084', '20.127227734198726', 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Jezioro Mielnik (ok. 10 ha) to zaciszny akwen położony wśród pól i lasów w pobliżu Gietrzwałdu. Jest to typowe jezioro linowo-szczupakowe o mulistym dnie i bogatej roślinności wynurzonej. To doskonałe miejsce na spokojną zasiadkę spławikową, gdzie w ciszy warmińskiego krajobrazu można zapolować na złotego lina i dorodną płoć.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80283, 'Jezioro Bobrzynek', 'jezioro-bobrzynek', 'LAKE', '53.73853304591504', '20.145221880387517', 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Bobrzynek to miniaturowe, dzikie oczko leśne (ok. 5 ha) o charakterze dystroficznym. Jezioro charakteryzuje się miękkim, torfowym dnem i wodą o barwie mocnej herbaty. To królestwo lina i karasia, niemal całkowicie odcięte od cywilizacji. Idealna meta dla wędkarzy-eksploratorów szukających kontaktu z pierwotną naturą.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80284, 'Jezioro Łęguty', 'jezioro-leguty', 'LAKE', '53.75703325630766', '20.146654351074268', 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Jezioro Łęguty (ok. 60 ha) to jezioro przepływowe, przez które płynie rzeka Pasłęka. Akwen ma charakter sandaczowo-szczupakowy. Dzięki stałemu natlenieniu wody przez rzekę, ryby są tu bardzo waleczne i liczne. Jezioro słynie z dorodnego sandacza oraz wielkich leszczy, które grupują się w okolicach ujścia i wypływu rzeki.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80285, 'Jezioro Łoby', 'jezioro-loby', 'LAKE', '53.76841007727008', '20.11712318938854', 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Jezioro Łoby to malowniczy, śródleśny zbiornik o powierzchni ok. 15 ha. Akwen charakteryzuje się dość czystą wodą i urozmaiconą linią brzegową. To klasyczne łowisko szczupakowo-okoniowe, rzadko odwiedzane przez turystów. Brzegi są wysokie i porośnięte gęstym lasem, co zapewnia wędkarzom spokój nawet w szczycie sezonu.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80286, 'Jezioro Isąg', 'jezioro-isag', 'LAKE', '53.78211527920642', '20.13682118287682', 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Isąg (ok. 400 ha) to jedno z najpiękniejszych i najczystszych jezior Pojezierza Olsztyńskiego (I klasa czystości). Jest to głęboka rynna polodowcowa (do 54 m) z dwiema wyspami. Jezioro objęte jest strefą ciszy. To elitarne łowisko sielawowe, słynące z olbrzymich okoni (garbusów) i wielkich, toniowych szczupaków. Krystaliczna woda i dzikie, zalesione brzegi sprawiają, że Isąg jest uważany za jedno z najlepszych łowisk drapieżników w północno-wschodniej Polsce.', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80287, 'Jezioro Giłwa', 'jezioro-gilwa', 'LAKE', '53.76959823958763', '20.233921633495562', 'Warmińsko-Mazurskie', 'Gietrzwałd', 'Jezioro Giłwa (często nazywane Rentyńskim) to okazały zbiornik o powierzchni ok. 100 ha, położony w malowniczej dolinie rzeki Giłwy. Akwen ma charakter rynnowy i jest otoczony pięknymi lasami warmińskimi. Słynie jako popularne miejsce rekreacji (miejscowość Rentyny), ale dla wędkarzy to przede wszystkim techniczne łowisko sandaczowo-szczupakowe. Woda jest czysta (II klasa), a dno urozmaicone z wyraźnymi spadami, co sprzyja aktywnemu spinningowi.', 'Gospodarstwo Rybackie Bartołty Wielkie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80288, 'Jezioro Gil', 'jezioro-gil', 'LAKE', '53.82699462123567', '19.989992438218025', 'Warmińsko-Mazurskie', 'Łukta', 'Jezioro Gil to krystalicznie czysta rynna polodowcowa (ok. 168 ha), położona w sercu lasów nieopodal miejscowości Kotkowo. Jezioro objęte jest strefą ciszy, co zapewnia mu niesamowity spokój. Charakteryzuje się twardym, piaszczysto-żwirowym dnem i znaczną głębokością (do 22 m). To elitarne łowisko sielawowe, znane z populacji wielkiego okonia i szczupaka żerującego w toni. Idealne miejsce dla wędkarzy szukających dzikiej natury i ryb "czystej wody".', 'Gospodarstwo Rybackie Ostróda');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80289, 'Jezioro Ruskie', 'jezioro-ruskie-morag', 'LAKE', '53.830861273933266', '19.962675272127214', 'Warmińsko-Mazurskie', 'Morąg', 'Jezioro Ruskie (Rusek) to niewielki, dziki akwen o powierzchni ok. 47 ha, położony na południe od Morąga. Jest to typowe jezioro linowo-szczupakowe o mulistym dnie i bogatej roślinności przybrzeżnej. Brzegi są w większości wysokie i zalesione, co utrudnia dostęp z lądu, ale zapewnia rybom doskonałe warunki do naturalnego rozrodu. To świetna meta na spokojną zasiadkę spławikową w poszukiwaniu lina i karasia złocistego.', 'Kompania Mazurska Sp. z o.o.');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80290, 'Jezioro Bronisławskie', 'jezioro-bronislawskie', 'LAKE', 52.650199, 18.110189, 'Kujawsko-Pomorskie', 'Mogilno / Bronisław', 'Bronisławskie to malowniczy akwen położony wśród pól Pałuk. Posiada regularną linię brzegową i dno muliste. Średnia głębokość to ok. 4-5 metrów. Woda jest żyzna, co sprzyja szybkim przyrostom lina i karpia. Idealne miejsce na spokojną zasiadkę spławikową.', 'PZW Bydgoszcz');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80291, 'Jezioro Golub', 'jezioro-golub-rozlewisko', 'LAKE', '53.81644317423597', '19.95738417276892', 'Warmińsko-Mazurskie', 'Morąg', 'Jezioro Golub, obecnie znane bardziej jako Rozlewisko Morąskie, to rozległy, bardzo płytki obszar wodno-błotny o powierzchni ok. 110 ha. To królestwo lina i szczupaka, a także ostoja niezliczonych gatunków ptaków. Zbiornik jest silnie zarośnięty, z mulistym dnem, co sprawia, że jest to łowisko trudne technicznie, ale niezwykle satysfakcjonujące dla wędkarzy potrafiących łowić w "zielsku". Prawdziwy azyl dla dzikiej przyrody tuż obok Morąga.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80292, 'Jezioro Florczackie', 'jezioro-florczackie', 'LAKE', '53.84279459583388', '20.014938883415606', 'Warmińsko-Mazurskie', 'Łukta', 'Jezioro Florczackie to niewielkie, płytkie oczko (ok. 13 ha) położone w pobliżu miejscowości Florczaki. Ma charakter linowo-karasiowy i jest w fazie naturalnego lądowacenia. Charakteryzuje się miękkim dnem i dużą ilością roślinności zanurzonej. To idealne miejsce dla wędkarzy ceniących samotność, polujących na płocie i wzdręgi wśród grążeli.', 'Gmina Łukta / PZW');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80293, 'Jezioro Marąg', 'jezioro-marag-gubity', 'LAKE', '53.846149879516595', '20.066880426406673', 'Warmińsko-Mazurskie', 'Morąg', 'Jezioro Marąg to potężny i niezwykle rybny akwen o powierzchni ponad 400 ha. To typowa rynna z bardzo urozmaiconym dnem i legendarną Wyspą Lipową, która jest rezerwatem przyrody (kolonia kormoranów i czapli). Woda jest czysta, a jezioro objęte strefą ciszy. Marąg słynie w całym regionie z populacji sandacza, dużego szczupaka oraz rekordowych leszczy. To jedno z najbardziej cenionych łowisk w okolicach Morąga, wymagające od wędkarza znajomości topografii dna, ale oferujące szansę na rybę życia.', 'Zakład Rybacki Bogaczewo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80294, 'Jezioro Piłąg', 'jezioro-pilag', 'LAKE', '53.87920752058769', '19.98968669370138', 'Warmińsko-Mazurskie', 'Morąg', 'Jezioro Piłąg (Piłąskie) to urokliwy, rynnowy zbiornik o powierzchni ok. 20 ha, położony na zachód od jeziora Narie. Jezioro charakteryzuje się dość wysokimi, zalesionymi brzegami i czystą wodą. To typowe łowisko szczupakowo-linowe, rzadko odwiedzane przez turystów, co zapewnia wędkarzom dużą dawkę prywatności. Dno jest urozmaicone, piaszczysto-muliste, a woda obfituje w dorodną płoć i okonia.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80295, 'Jezioro Narie', 'jezioro-narie', 'LAKE', '53.908284191904634', '20.035729302749136', 'Warmińsko-Mazurskie', 'Morąg', 'Jezioro Narie to absolutna perła regionu i jedno z najpiękniejszych jezior w Polsce (pow. ok. 1240 ha). Posiada niezwykle rozwiniętą linię brzegową i 19 wysp, z których największa (Duża Wyspa) jest zamieszkana. Woda posiada II klasę czystości, a dno jest bardzo urozmaicone z głęboczkami do 44 m. To legendarne łowisko sielawowe, słynące z potężnych szczupaków, rekordowych okoni i dorodnych leszczy. Na całym jeziorze obowiązuje strefa ciszy, co czyni je rajem dla wędkarzy i miłośników natury.', 'Zakład Rybacki Bogaczewo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80296, 'Jezioro Brzydowskie', 'jezioro-brzydowskie', 'LAKE', '53.90718210717129', '20.12288490411492', 'Warmińsko-Mazurskie', 'Miłakowo', 'Jezioro Brzydowskie (ok. 60 ha) to malowniczy akwen o charakterze leszczowo-szczupakowym, położony w pobliżu miejscowości Brzydowo. Jezioro ma wydłużony kształt rynnowy i urozmaicone dno. Brzegi są w większości dostępne, otoczone polami i kępami lasu. To bardzo solidne łowisko dla wędkarzy stacjonarnych, słynące z regularnych brań leszcza i płoci, oraz dla spinningistów szukających szczupaka wzdłuż trzcinowisk.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80297, 'Czarne Jezioro', 'czarne-jezioro-bogaczewo', 'LAKE', '53.92263090716249', '20.046395418284543', 'Warmińsko-Mazurskie', 'Morąg', 'Czarne Jezioro (ok. 12 ha) to niewielkie, śródleśne oczko położone na północny wschód od jeziora Narie. Jezioro charakteryzuje się ciemniejszą wodą i mulistym dnem, co jest typowe dla zbiorników dystroficznych w fazie lądowacenia. To klasyczne łowisko lina i karasia złocistego. Brzegi są dzikie i zalesione, co zapewnia absolutny spokój i klimat "leśnej głuszy" tuż obok wielkiego jeziora Narie.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80298, 'Jezioro Trądla', 'jezioro-tradla', 'LAKE', '53.925074791598625', '20.033625595924615', 'Warmińsko-Mazurskie', 'Morąg', 'Jezioro Trądla to niewielki (ok. 8 ha), malowniczo położony zbiornik w sąsiedztwie jeziora Ponary. Jest to klasyczne jezioro linowo-szczupakowe o dość czystej wodzie. Brzegi są częściowo zalesione, co zapewnia osłonę od wiatru. Idealne dla wędkarzy ceniących kameralną atmosferę i precyzyjne łowienie spławikowe w oknach roślinności.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80299, 'Jezioro Ponary', 'jezioro-ponary', 'LAKE', '53.93224331819281', '20.02949486305755', 'Warmińsko-Mazurskie', 'Morąg', 'Jezioro Ponary to rynnowy akwen o powierzchni ok. 50 ha. Charakteryzuje się dość regularną linią brzegową i wyraźnymi spadami dna. To solidne łowisko leszczowe, w którym przy odrobinie cierpliwości można trafić na dorodne okazy. Spinningiści chętnie szukają tu szczupaka, który patroluje pas trzcin otaczający niemal całe jezioro.', 'Gospodarstwo Rybackie Bogaczewo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80300, 'Jezioro Peneper Mały', 'jezioro-peneper-maly', 'LAKE', '53.9367373868553', '20.000101492507852', 'Warmińsko-Mazurskie', 'Morąg', 'Peneper Mały to urokliwe oczko polodowcowe o powierzchni ok. 6 ha. Jezioro jest dość płytkie i silnie zarośnięte, co stwarza wybitne warunki dla lina i karasia. Ze względu na dziki charakter brzegów, dostęp jest utrudniony, co przekłada się na niską presję wędkarską.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80301, 'Jezioro Peneper Duży', 'jezioro-peneper-duzy', 'LAKE', '53.94199195024917', '19.999031834360288', 'Warmińsko-Mazurskie', 'Morąg', 'Jezioro Peneper Duży (ok. 15 ha) to rynnowy zbiornik o czystej wodzie i piaszczysto-mulistym dnie. Słynie z populacji okonia i szczupaka. Brzegi są w większości dostępne, co ułatwia łowienie stacjonarne. To spokojna alternatywa dla dużych mazurskich rynien.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80302, 'Jezioro Balwiąg', 'jezioro-balwiag', 'LAKE', '53.98288556990922', '20.009467345022966', 'Warmińsko-Mazurskie', 'Miłakowo', 'Jezioro Balwiąg (ok. 45 ha) to malowniczy zbiornik o urozmaiconej linii brzegowej, położony niedaleko Miłakowa. Jezioro charakteryzuje się żyzną wodą i bogatą roślinnością zanurzoną. To wybitne łowisko szczupakowe, gdzie drapieżniki mają mnóstwo naturalnych kryjówek.', 'Gospodarstwo Rybackie Bogaczewo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80303, 'Jezioro Mildzkie', 'jezioro-mildzkie', 'LAKE', '53.99217658889019', '20.064064704007805', 'Warmińsko-Mazurskie', 'Miłakowo', 'Jezioro Mildzkie (Mildzie) to okazały akwen o powierzchni ok. 100 ha. Jest to jezioro rynnowe o dość dużej głębokości (do 24 m). Słynie z krystalicznej wody i doskonałych warunków do spinningu. Dominują tu szczupak i sandacz, a wędkarze spławikowi mogą liczyć na dorodne leszcze.', 'Gospodarstwo Rybackie Bogaczewo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80304, 'Jezioro Wuksniki', 'jezioro-wuksniki', 'LAKE', '53.971029010020324', '20.098873646107453', 'Warmińsko-Mazurskie', 'Miłakowo', 'Wuksniki to najgłębsze jezioro Pojezierza Mazurskiego (68 m). Woda o niesamowitej, szafirowej barwie i I klasie czystości przyciąga nurków z całej Polski. Dla wędkarzy to łowisko sielawowe, dom wielkich, toniowych szczupaków i siei. Objęte strefą ciszy, stanowi azyl dla ryb szlachetnych i wymaga od wędkarza dużej wiedzy o łowieniu w głębokiej toni.', 'Gospodarstwo Rybackie Bogaczewo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80305, 'Jezioro Bieniańskie', 'jezioro-bienianskie', 'LAKE', '53.973278676198916', '20.122691586429134', 'Warmińsko-Mazurskie', 'Miłakowo', 'Jezioro Bieniańskie (Bienie) to kameralny akwen (ok. 25 ha) położony w sąsiedztwie Wuksnik. Ma charakter linowo-szczupakowy. Brzegi są wysokie i zalesione, co nadaje mu klimat górskiego jeziora ukrytego w lesie.', 'Gospodarstwo Rybackie Bogaczewo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80306, 'Jezioro Taftowo', 'jezioro-taftowo', 'LAKE', '54.171420845924224', '20.093212969328505', 'Warmińsko-Mazurskie', 'Pieniężno', 'Jezioro Taftowo (znane również jako Tauty lub Tajtowo) to malowniczy akwen o powierzchni ok. 85 ha, położony w sercu Lasów Pieniężnieńskich. Jezioro charakteryzuje się dość czystą wodą i urozmaiconą linią brzegową. To typowe łowisko szczupakowo-linowe, cenione za dziki charakter i spokój. Otoczone niemal w całości lasem, jest doskonałym miejscem dla wędkarzy szukających samotności i kontaktu z naturą. Słynie z populacji dorodnego lina i walecznych szczupaków.', 'Zakład Rybacki Bogaczewo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80307, 'Jezioro Dąbrówka', 'jezioro-dabrowka-sztum', 'LAKE', '53.9759667722802', '19.067775029398945', 'Pomorskie', 'Sztum', 'Jezioro Dąbrówka to potężny sztuczny zbiornik (pow. ok. 250 ha), będący kluczowym elementem historycznego systemu hydrotechnicznego doprowadzającego wodę do zamku w Malborku. Akwen jest połączony kanałami z innymi jeziorami regionu. Wędkarsko to bardzo rybne łowisko leszczowo-szczupakowe. Ze względu na swoją funkcję i ukształtowanie, dno jest tu dość wyrównane, ale obfituje w ryby białe. To popularne miejsce zawodów wędkarskich, słynące z rekordowych ilości płoci i leszcza.', 'PZW Elbląg / Miasto Sztum');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80308, 'Jezioro Kaniewo', 'jezioro-kaniewo-sztum', 'LAKE', '53.95413792671198', '19.017562788506847', 'Pomorskie', 'Sztum', 'Jezioro Kaniewo (Koniecwałd) to mniejszy sąsiad Dąbrówki (ok. 18 ha). Jest to zbiornik przepływowy, połączony z systemem Kanału Juranda. Jezioro ma charakter linowo-szczupakowy. Mimo incydentalnych problemów z jakością wody w przeszłości, pozostaje ważnym punktem na wędkarskiej mapie okolic Sztumu. Słynie z populacji karasia srebrzystego oraz szczupaka, który znajduje doskonałe kryjówki w pasach trzcinowisk.', 'PZW Elbląg');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80309, 'Jezioro Średnie (Pasym)', 'jezioro-srednie-pasym', 'LAKE', 53.504713, 20.797977, 'Warmińsko-Mazurskie', 'Pasym / Rekowe', 'Jezioro Średnie to łącznik rynnowy między Rekowym a Kalwą. Posiada dno piaszczysto-muliste i średnią głębokość ok. 8-10 metrów. Pod kątem wędkarskim to bardzo stabilna woda leszczowo-szczupakowa.', 'Gospodarstwo Rybackie Szwaderowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80310, 'Jezioro Goplanica', 'jezioro-goplanica', 'LAKE', '54.20855498038084', '19.468974802836584', 'Warmińsko-Mazurskie', 'Elbląg', 'Goplanica to unikalne łowisko komercyjne położone w Parku Krajobrazowym Buki Wysoczyzny Elbląskiej. Akwen o powierzchni ok. 9-10 ha przypomina kształtem literę „L” i charakteryzuje się bardzo urozmaiconym, trudnym technicznie dnem (głębokość do 8 m). To mekka dla łowców dużych karpi (okazy powyżej 20 kg) oraz sumów (do 100 kg). Na łowisku obowiązuje całkowity zakaz spinningowania i połowu drapieżników – jest to łowisko typowo karpiowe o statusie „złów i wypuść”.', 'Łowisko Komercyjne Goplanica');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80311, 'Jezioro Głębockie', 'jezioro-glebockie-lelkowo', 'LAKE', '54.384765708634895', '20.283300419565713', 'Warmińsko-Mazurskie', 'Lelkowo', 'Jezioro Głębockie (Głębokie) to okazały akwen o powierzchni ok. 87 ha, położony na wschodnich rubieżach Warmii, zaledwie 2 km od granicy państwa. Jest to jezioro typu sandaczowego o nieregularnym kształcie i urozmaiconym dnie, które miejscami jest muliste, a miejscami kamieniste. Brzegi są w większości bezleśne, otoczone łąkami i polami, co zapewnia dobrą dostępność dla wędkarzy. Słynie z populacji sandacza oraz – co nietypowe dla jezior tej wielkości – dorodnego bolenia. W latach 80. zbiornik służył jako magazyn drewna, co do dziś wpływa na ukształtowanie niektórych partii dna.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80312, 'Jesionowy Staw', 'jesionowy-staw-gorowo', 'LAKE', '54.36235290542837', '20.434278382045726', 'Warmińsko-Mazurskie', 'Górowo Iławeckie', 'Jesionowy Staw to urokliwy zbiornik miejski położony w Górowie Iławeckim. Pełni funkcję łowiska rekreacyjnego i jest chętnie odwiedzany przez lokalnych wędkarzy oraz rodziny szukające odpoczynku nad wodą. Akwen ma charakter linowo-karasiowy i jest systematycznie zarybiany. Dzięki zadbanej infrastrukturze, licznym ławkom i dogodnym stanowiskom, jest to idealne miejsce na krótkie, popołudniowe zasiadki spławikowe w samym sercu miasta.', 'Miasto Górowo Iławeckie / PZW');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80313, 'Jezioro Żabiona', 'jezioro-zabiona-kaminsk', 'LAKE', '54.32100081083078', '20.444476097127865', 'Warmińsko-Mazurskie', 'Górowo Iławeckie', 'Jezioro Żabiona (Żabie) to niewielki, dziki akwen o powierzchni nieco ponad 1 ha, ukryty w pobliżu miejscowości Kamińsk. Jezioro charakteryzuje się bardzo spokojną okolicą i jest otoczone malowniczą mozaiką lasów i nieużytków. To typowe łowisko linowo-karasiowe o mulistym dnie i bogatej roślinności wynurzonej. Ze względu na swój dziki charakter i oddalenie od głównych dróg, jest to miejsce dla wędkarzy szukających absolutnej ciszy i bliskiego kontaktu z naturą.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80314, 'Jezioro Łęgnowskie', 'jezioro-legnowskie', 'LAKE', '53.9836699555883', '20.32763679839526', 'Warmińsko-Mazurskie', 'Dobre Miasto', 'Jezioro Łęgnowskie (Łęgno) to malowniczy akwen o powierzchni ok. 40 ha, położony w gminie Dobre Miasto. Jezioro charakteryzuje się dość regularną linią brzegową i jest otoczone mozaiką pól oraz lasów. To typowe łowisko linowo-szczupakowe, cenione przez lokalnych wędkarzy za spokój i rybność. Woda jest stosunkowo czysta, a brzegi w wielu miejscach dostępne dla wędkarzy stacjonarnych. Słynie z dorodnych płoci i linów żerujących w pasach grążeli.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80315, 'Jezioro Sunia', 'jezioro-sunia', 'LAKE', '53.96396842269281', '20.275916773608927', 'Warmińsko-Mazurskie', 'Świątki', 'Jezioro Sunia to jeden z najpiękniejszych akwenów w gminie Świątki (pow. ok. 110 ha). Jezioro ma charakter rynnowy, jest dość głębokie (do 8,5 m) i posiada urozmaiconą linię brzegową z wyraźnym półwyspem. Woda posiada II klasę czystości. To wybitne łowisko leszczowe i szczupakowe. Jezioro otaczają piękne, wysokie brzegi, w połowie zalesione, co stwarza doskonałe warunki do wypoczynku i wędkowania z łodzi w osłonie od wiatru.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80316, 'Jezioro Wuksniki', 'jezioro-wuksniki-milakowo', 'LAKE', '53.971719258102375', '20.099346373827267', 'Warmińsko-Mazurskie', 'Miłakowo', 'Wuksniki to najgłębsze jezioro Warmii i jedno z najgłębszych w Polsce (68 m). Akwen o powierzchni ok. 117 ha słynie z niesamowitej, szafirowej barwy wody i przejrzystości sięgającej 10 metrów (I klasa czystości). Jezioro objęte jest strefą ciszy. To elitarne łowisko sielawowe, dom wielkich, toniowych szczupaków i siei. Krystaliczna woda i strome, zalesione brzegi sprawiają, że Wuksniki są uważane za jedno z najbardziej mistycznych i technicznie wymagających łowisk w regionie.', 'Gospodarstwo Rybackie Bogaczewo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80317, 'Jezioro Skolickie', 'jezioro-skolickie', 'LAKE', '53.88865940377251', '20.183072873922285', 'Warmińsko-Mazurskie', 'Świątki', 'Jezioro Skolickie (ok. 22 ha) to urokliwy, rynnowy zbiornik położony w pobliżu miejscowości Skolity. Akwen jest niemal całkowicie otoczony lasem, co zapewnia mu dziki charakter i absolutną ciszę. Woda jest czysta, a dno piaszczysto-muliste. To klasyczne łowisko szczupakowo-okoniowe, cenione przez wędkarzy szukających odosobnienia. Słynie z pięknych okoni, które chętnie trzymają się zwalonych do wody drzew przy wschodnim brzegu.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80318, 'Jezioro Nidzkie', 'jezioro-nidzkie', 'LAKE', '53.57659583072132', '21.541256449959565', 'Warmińsko-Mazurskie', 'Ruciane-Nida', 'Jezioro Nidzkie to jeden z najbardziej legendarnych i dzikich akwenów Krainy Wielkich Jezior Mazurskich (pow. ok. 1800 ha). Prawie w całości leży w rezerwacie przyrody, co oznacza rygorystyczną strefę ciszy. Jezioro ma charakter rynnowy, jest bardzo długie (23 km) i otoczone potężnymi borami Puszczy Piskiej. Słynie z krystalicznej wody, sielawy oraz ogromnych leszczy i szczupaków. To miejsce, które natchnęło Gałczyńskiego, do dziś zachwyca pierwotną naturą i brakiem motorówek.', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80319, 'Jezioro Roś', 'jezioro-ros', 'LAKE', '53.67001111696934', '21.918365423139154', 'Warmińsko-Mazurskie', 'Pisz', 'Jezioro Roś (pow. ok. 1880 ha) to południowo-wschodni kraniec szlaku WJM, z którego wypływa rzeka Pisa. Jezioro ma specyficzny kształt litery "S" i składa się z trzech rynien. Jest to akwen bardzo rybny, o charakterze sandaczowo-szczupakowym. Charakteryzuje się rozległymi trzcinowiskami i piaszczysto-mulistym dnem. To doskonałe łowisko sandacza, który znajduje tu świetne warunki na twardych spadach, oraz dorodnego leszcza.', 'Gospodarstwo Rybackie Pisz (PZW Suwałki)');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80320, 'Jezioro Borowe', 'jezioro-borowe-prostki', 'LAKE', '53.64158561947374', '22.27446703454056', 'Warmińsko-Mazurskie', 'Prostki', 'Jezioro Borowe (ok. 25 ha) to kameralny, śródleśny zbiornik położony na południe od Ełku. Jest to typowe jezioro linowo-szczupakowe o dość czystej wodzie i zróżnicowanej roślinności podwodnej. Brzegi są w większości wysokie i zalesione, co zapewnia osłonę przed wiatrem i poczucie całkowitego odosobnienia. Słynie z pięknych linów i okoni, które chętnie trzymają się powalonych do wody drzew.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80321, 'Jezioro Dybowskie', 'jezioro-dybowskie', 'LAKE', '53.675383041167', '22.27349902637238', 'Warmińsko-Mazurskie', 'Prostki', 'Jezioro Dybowskie to okazała rynna polodowcowa (ok. 120 ha) położona w pobliżu miejscowości Dybowo. Akwen jest głęboki (do 23 m) i posiada bardzo urozmaicone dno z wyraźnymi górkami podwodnymi. To wybitne łowisko sielawowe i szczupakowe. Woda jest czysta, a brzegi w wielu miejscach dostępne dla wędkarzy stacjonarnych. Słynie z populacji dużego leszcza oraz sandacza, który trzyma się twardych, żwirowych stoków.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80322, 'Jezioro Kunis', 'jezioro-kunis', 'LAKE', '54.04904095210827', '23.44310134812926', 'Podlaskie', 'Sejny', 'Kunis (ok. 43 ha) to jezioro przepływowe w dorzeczu rzeki Marychy. Akwen ma wydłużony kształt i charakter linowo-szczupakowy. Dzięki stałemu natlenieniu wody przez rzekę, ryby są tu bardzo waleczne. To świetne łowisko lina i dużego leszcza, a spinningiści mogą liczyć na spotkanie z sandaczem i szczupakiem w twardszych partiach dna.', 'Gospodarstwo Rybackie Falko');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80323, 'Jezioro Sajno', 'jezioro-sajno', 'LAKE', '53.82674697964597', '23.03303118808346', 'Podlaskie', 'Augustów', 'Jezioro Sajno to największe jezioro w grupie jezior augustowskich (pow. ok. 480 ha). Leży na południowy wschód od Augustowa i jest otoczone z trzech stron gęstymi lasami Puszczy Augustowskiej. Akwen charakteryzuje się dobrze rozwiniętą linią brzegową z licznymi zatokami (Orzechówka, Tartaczna). To wybitne łowisko sielawowe i leszczowe, oferujące krystaliczną wodę i doskonałe warunki do spinningu z łodzi.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80324, 'Jezioro Kolno', 'jezioro-kolno', 'LAKE', '53.76795988037114', '23.018172337827874', 'Podlaskie', 'Augustów', 'Jezioro Kolno (pow. ok. 269 ha) to płytki, silnie zatorfiony zbiornik, będący w całości rezerwatem przyrody. Jest to ostoja ptactwa wodnego i błotnego. Brzegi są trudne, bagniste i niedostępne, a dno niemal w całości pokryte ramienicami. Ze względu na ochronę rezerwatową, wędkowanie jest tu ograniczone – to królestwo lina i szczupaka w fazie naturalnego lądowacenia.', 'PZW Suwałki / RDOŚ Białystok');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80325, 'Jezioro Jezierskie', 'jezioro-jezierskie', 'LAKE', '53.83989509970332', '22.81717669009229', 'Podlaskie', 'Augustów', 'Jezioro Jezierskie to niewielki, dziki akwen (ok. 8 ha) położony na zachód od Augustowa, w pobliżu miejscowości Jeziorki. Ma wydłużony kształt i bezleśne brzegi otoczone polami. To typowe łowisko linowo-karasiowe, idealne dla osób szukających spokoju z dala od turystycznego zgiełku miasta.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80326, 'Jezioro Necko', 'jezioro-necko', 'LAKE', '53.8633105561299', '22.961750912926096', 'Podlaskie', 'Augustów', 'Jezioro Necko to wizytówka Augustowa (pow. ok. 400-500 ha). Jest to jezioro rynnowe o bardzo dobrze rozwiniętej linii brzegowej, piaszczystych plażach i czystej wodzie. Łączy się z jeziorami Rospuda i Białe. To wyśmienite łowisko szczupaka, sandacza i okonia. Dzięki połączeniu z Kanałem Augustowskim, ryby mają tu doskonałe warunki do migracji i żerowania.', 'PZW Suwałki / GR Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80327, 'Jezioro Rospuda', 'jezioro-rospuda-augustowska', 'LAKE', '53.87365864320141', '22.983606287803532', 'Podlaskie', 'Augustów', 'Rospuda Augustowska to wydłużona rynna (ok. 340 ha) stanowiąca wschodnie przedłużenie jeziora Necko. Brzegi są wysokie i porośnięte lasem iglastym. Jezioro słynie z czystej wody i urozmaiconego dna z licznymi głęboczkami. To techniczne łowisko sielawowe, oferujące szansę na dorodne szczupaki i sieje.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80328, 'Jezioro Białe Augustowskie', 'jezioro-biale-augustowskie', 'LAKE', '53.864203732053674', '23.025557448278413', 'Podlaskie', 'Augustów', 'Jezioro Białe (pow. ok. 480 ha) to kolejny duży akwen na szlaku Kanału Augustowskiego. Charakteryzuje się niezwykle urozmaiconym dnem z licznymi głęboczkami i czterema wyspami. Otoczone lasami puszczy, słynie z krystalicznej wody i populacji sandacza, szczupaka oraz węgorza. To klasyczne łowisko typu sielawowego.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80329, 'Staw Wojciech', 'staw-wojciech', 'LAKE', '53.862934908158245', '23.07747753583962', 'Podlaskie', 'Augustów', 'Staw Wojciech to płytkie jezioro rynnowe (ok. 22 ha) położone w północno-wschodniej części Augustowa. Od jeziora Studzienicznego oddziela go grobla. To bardzo żyzne łowisko linowo-szczupakowe, gdzie woda szybko się nagrzewa, co sprzyja populacji białorybu. Słynie z pięknych wzdręg i aktywnych okoni.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80330, 'Jezioro Studzieniczne', 'jezioro-studzieniczne', 'LAKE', '53.863900997905326', '23.114379690038184', 'Podlaskie', 'Augustów', 'Jezioro Studzieniczne (pow. ok. 250 ha) to akwen o bardzo rozwiniętej linii brzegowej i licznych wyspach (m.in. Brzozowy Grąd). Położone na szlaku śluz Przewięź i Swoboda. Jezioro objęte jest strefą ciszy, co zapewnia komfort łowienia. Słynie z dorodnego leszcza, sandacza oraz węgorza.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80331, 'Jezioro Serwy', 'jezioro-serwy', 'LAKE', '53.91552338636082', '23.2151534669992', 'Podlaskie', 'Augustów', 'Serwy to jedno z najczystszych jezior Pojezierza Augustowskiego (ok. 460 ha, I klasa czystości). Na jeziorze znajdują się trzy wyspy, w tym Sosnowo z rezerwatem kormoranów. Akwen objęty strefą ciszy. To elitarne łowisko sielawowe, cenione za wielkie okonie i szczupaki żerujące w toni.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80332, 'Jezioro Orle', 'jezioro-orle', 'LAKE', '53.90846168346158', '23.262355143750863', 'Podlaskie', 'Augustów', 'Jezioro Orle to malowniczy akwen na szlaku Kanału Augustowskiego (pow. ok. 12 ha). Jezioro ma charakter rynnowy i jest otoczone gęstym borem iglastym. Woda jest czysta, o lekko torfowym zabarwieniu. To doskonałe miejsce dla wędkarzy szukających spokoju na szlaku wodnym – słynie z populacji dorodnego lina oraz szczupaka czatującego przy pasach trzcin. Brzegi są wysokie i suche, co ułatwia dostęp w wybranych punktach.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80333, 'Jezioro Pobojno', 'jezioro-pobojno', 'LAKE', '53.90432905853144', '23.271344541398967', 'Podlaskie', 'Augustów', 'Jezioro Pobojno (ok. 15 ha) to kolejny element systemu Kanału Augustowskiego, połączony bezpośrednio z jeziorem Orle. Jest to zbiornik płytki, o bogatej roślinności wynurzonej. To wybitne łowisko lina i karasia złocistego. Dzięki stałemu przepływowi wody przez kanał, ryby są tu waleczne i zdrowe. Jezioro jest rzadziej odwiedzane przez turystów niż Necko czy Białe, co zapewnia wędkarzom dużą dawkę prywatności.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80334, 'Jezioro Paniewo', 'jezioro-paniewo', 'LAKE', '53.90421091008423', '23.294694467972068', 'Podlaskie', 'Augustów', 'Jezioro Paniewo (pow. ok. 13 ha) znane jest przede wszystkim z sąsiedztwa unikalnej, dwukomorowej śluzy Paniewo. Akwen ma charakter rynnowy, jest dość głęboki i posiada bardzo urozmaicone dno. Słynie z populacji sandacza oraz dużego leszcza. Brzegi są w większości wysokie i zalesione. To techniczne łowisko, gdzie ryby często grupują się w okolicach prądów wodnych wywoływanych przez pracę śluzy.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80335, 'Jezioro Krzywe (Augustowskie)', 'jezioro-krzywe-augustowskie', 'LAKE', '53.89587789244259', '23.308285082620504', 'Podlaskie', 'Augustów', 'Jezioro Krzywe to wąska, kręta rynna (pow. ok. 13 ha) wkomponowana w szlak Kanału Augustowskiego pomiędzy Paniewem a Perkuć. Jezioro jest otoczone dziewiczą Puszczą Augustowską. Woda jest przejrzysta, a dno piaszczysto-muliste. To królestwo okonia i szczupaka. Ze względu na swój kształt i osłonięcie lasem, jezioro jest idealne do wędkowania nawet podczas wietrznej pogody.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80336, 'Jezioro Kruglak', 'jezioro-kruglak', 'LAKE', '53.89136479130115', '23.321696271766562', 'Podlaskie', 'Augustów', 'Jezioro Kruglak to niewielki, owalny zbiornik (pow. ok. 11 ha) stanowiący ważny węzeł na trasie Kanału Augustowskiego. Mimo niewielkich rozmiarów, jezioro jest dość głębokie. Słynie z pięknych wzdręg oraz walecznych ryb przepływowych migrujących kanałem. To świetne miejsce na poranną zasiadkę spławikową w sercu puszczy.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80337, 'Jezioro Mikaszewo', 'jezioro-mikaszewo', 'LAKE', '53.891636416970215', '23.34742496516798', 'Podlaskie', 'Augustów', 'Jezioro Mikaszewo to największy akwen w tym zestawieniu (pow. ok. 120 ha), położony w gminie Płaska. Jezioro ma charakter rynnowy, jest głębokie (do 15 m) i posiada czystą wodę. Brzegi są w większości wysokie, piaszczyste i porośnięte gęstym lasem sosnowym. To wybitne łowisko szczupakowe i leszczowe. Ryby mają tu doskonałe warunki do żerowania na podwodnych blatach i stokach rynny głównej. Cieszy się uznaniem wśród wędkarzy szukających dzikich Mazur w wydaniu podlaskim.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80338, 'Jezioro Płaskie', 'jezioro-plaskie-augustowskie', 'LAKE', '53.913429645546906', '23.414539294491643', 'Podlaskie', 'Płaska', 'Jezioro Płaskie (pow. ok. 120 ha) to centralny punkt gminy Płaska, stanowiący integralną część szlaku Kanału Augustowskiego. Akwen ma charakter rynnowy, jest otoczony pięknymi lasami sosnowymi. Woda jest czysta, a dno piaszczysto-muliste. To bardzo rybne łowisko, cenione za populację sandacza i dużego leszcza. Dzięki dogodnym dojazdom i infrastrukturze we wsi Płaska, jest to świetna baza wypadowa dla wędkarzy.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80339, 'Jezioro Krejwelanek', 'jezioro-krejwelanek', 'LAKE', '53.91929343134658', '23.417174042484895', 'Podlaskie', 'Płaska', 'Krejwelanek to niewielkie (ok. 10 ha), urokliwe jezioro położone tuż na północ od jeziora Płaskiego. Jest to zbiornik zaciszny, o charakterze linowo-szczupakowym. Charakteryzuje się bogatą roślinnością wynurzoną i spokojną wodą, co czyni go idealnym miejscem na poranną zasiadkę spławikową w poszukiwaniu "złotych" linów i dorodnych wzdręg.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80340, 'Jezioro Brożane', 'jezioro-brozane', 'LAKE', '53.92903299046554', '23.429873860418173', 'Podlaskie', 'Płaska', 'Jezioro Brożane (ok. 55 ha) to jedno z najpiękniejszych i najbardziej dzikich jezior w tej części puszczy. Akwen ma krystalicznie czystą wodę i jest całkowicie otoczony lasem. Ze względu na brak odpływów i dopływów (jezioro bezodpływowe), ryby mają tu specyficzne, stabilne warunki. Słynie z populacji wielkiego okonia i walecznego szczupaka. To łowisko dla osób ceniących ciszę i krystaliczną wodę.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80341, 'Jezioro Głębokie (Mikaszówka)', 'jezioro-glebokie-mikaszowka', 'LAKE', '53.89816474414265', '23.46958062593887', 'Podlaskie', 'Płaska', 'Jezioro Głębokie (pow. ok. 20 ha) to klasyczna rynna polodowcowa ukryta w głębi Puszczy Augustowskiej niedaleko Mikaszówki. Zgodnie z nazwą, charakteryzuje się stromymi spadami dna i czystą wodą. To wybitne łowisko sielawowe i okoniowe. Brzegi są wysokie, porośnięte starym lasem, co stwarza niesamowity klimat "górskiego" jeziora na nizinach.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80342, 'Jezioro Szlamy', 'jezioro-szlamy', 'LAKE', '53.908162090349805', '23.50597292995585', 'Podlaskie', 'Płaska', 'Jezioro Szlamy (ok. 70 ha) to akwen graniczny – przez jego wschodnią część przebiega linia granicy z Białorusią. Jest to jezioro bardzo płytkie, silnie zarośnięte i dzikie. Mimo nazwy sugerującej muł, jest to raj dla miłośników lina i szczupaka oraz ostoja ptactwa wodnego. UWAGA: Ze względu na położenie graniczne, wędkarze muszą zachować szczególną ostrożność i posiadać przy sobie dokumenty tożsamości.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80343, 'Jezioro Długie (Płaska)', 'jezioro-dlugie-plaska', 'LAKE', '53.90475776323416', '23.513997013274455', 'Podlaskie', 'Płaska', 'Jezioro Długie to wąska i bardzo długa rynna leśna (ok. 20 ha) położona w sąsiedztwie jeziora Szlamy. Jezioro charakteryzuje się bardzo czystą wodą i piaszczystym dnem. To doskonałe łowisko szczupaka i płoci. Dzięki swojemu kształtowi i zalesionym brzegom, jest niemal zawsze osłonięte od wiatru, co sprzyja precyzyjnemu łowieniu spławikowemu.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80344, 'Jezioro Wiązowiec', 'jezioro-wiazowiec', 'LAKE', '53.89686408290113', '23.51399249195897', 'Podlaskie', 'Płaska', 'Jezioro Wiązowiec to niewielkie, dzikie oczko leśne (ok. 5 ha) położone na południe od jeziora Długiego. Jest to zbiornik o charakterze linowo-karasiowym, rzadko odwiedzany przez wędkarzy ze względu na trudny dostęp. Oferuje krystaliczną wodę i absolutną ciszę, będąc idealną meta dla wędkarzy-eksploratorów.', 'Gospodarstwo Rybackie Augustów');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80345, 'Jezioro Wiłkokuk', 'jezioro-wilkokuk', 'LAKE', '54.016621135882986', '23.40599472542132', 'Podlaskie', 'Giby', 'Jezioro Wiłkokuk (pow. ok. 48 ha) to malownicza rynna leśna położona w głębi Puszczy Augustowskiej. Akwen charakteryzuje się czystą wodą i piaszczystym dnem. Brzegi są wysokie, całkowicie zalesione, co zapewnia absolutną ciszę. To typowe łowisko szczupakowo-linowe, idealne dla osób szukających ucieczki od cywilizacji. Wędkarze cenią je za populację dużego okonia i dzikiego lina.', 'Gospodarstwo Rybackie Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80346, 'Jezioro Zelwa', 'jezioro-zelwa', 'LAKE', '54.02315254002174', '23.42387055703151', 'Podlaskie', 'Giby', 'Jezioro Zelwa (ok. 100 ha) to jezioro przepływowe, przez które płynie rzeka Marycha. Akwen ma bardzo urozmaiconą linię brzegową i jest otoczony lasami oraz polami. Słynie jako bardzo rybne łowisko leszczowo-sandaczowe. Dzięki stałemu przepływowi wody ryby są tu waleczne. To popularne miejsce wśród wędkarzy łodziowych, oferujące szansę na dorodnego szczupaka i sandacza.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80347, 'Jezioro Tobolinka I', 'jezioro-tobolinka-1', 'LAKE', '54.02658969822887', '23.405073942535772', 'Podlaskie', 'Giby', 'Tobolinka I to małe, dystroficzne jezioro leśne (suchar). Woda ma charakterystyczny brunatny kolor, a dno jest torfowe. To unikalny ekosystem, w którym można spotkać rzadkie gatunki ryb, w tym karłowate okonie o ciemnym ubarwieniu. Miejsce dla koneserów dzikiej przyrody.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80348, 'Jezioro Tobolinka II', 'jezioro-tobolinka-2', 'LAKE', '54.02873262695951', '23.40409414222009', 'Podlaskie', 'Giby', 'Tobolinka II to bliźniacze oczko leśne, niemal całkowicie otoczone torfowiskiem i borem. Jest to akwen o wybitnie linowo-karasiowym charakterze. Bardzo płytki, silnie zarośnięty, stanowiący ostoje spokoju dla zwierząt leśnych i wędkarzy szukających samotności.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80349, 'Jezioro Pomorze', 'jezioro-pomorze-giby', 'LAKE', '54.036179710015254', '23.402481720697565', 'Podlaskie', 'Giby', 'Pomorze to jedno z największych jezior w okolicach Gib (pow. ok. 300 ha). Jezioro ma charakter rynnowy, jest głębokie (do 23 m) i posiada bardzo czystą wodę. Brzegi są wysokie, porośnięte starymi drzewami. To wybitne łowisko sielawowe, cenione za wielkie okonie i szczupaki żerujące w toni. Ze względu na rozmiar i ukształtowanie dna, jest to meta dla wędkarzy profesjonalnych.', 'Gospodarstwo Rybackie Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80350, 'Jezioro Gieret', 'jezioro-gieret', 'LAKE', '54.03576169120613', '23.34164191020243', 'Podlaskie', 'Giby', 'Jezioro Gieret (ok. 80 ha) to krystalicznie czysta rynna, osiągająca głębokość aż 42 metrów. Jest to jedno z najbardziej atrakcyjnych łowisk w regionie. Słynie z populacji sielawy, siei oraz rekordowych szczupaków. Dzięki ogromnej głębokości ryby mają tu doskonałe warunki do wzrostu. To techniczne łowisko dla spinningistów i łowców toniowych.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80351, 'Jezioro Wierśnie', 'jezioro-wiersnie', 'LAKE', '54.02345662751191', '23.322390027902912', 'Podlaskie', 'Giby', 'Jezioro Wierśnie (pow. ok. 35 ha) to malowniczy akwen o charakterze rynnowym, niemal w całości otoczony lasem. Woda jest czysta, a brzegi strome i trudno dostępne. To doskonałe łowisko szczupakowe i płociowe. Ze względu na odosobnienie, ryba czuje się tu bardzo pewnie.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80352, 'Jezioro Dowcień', 'jezioro-dowcien', 'LAKE', '54.04493519912954', '23.399432108909995', 'Podlaskie', 'Krasnopol', 'Jezioro Dowcień (pow. ok. 83 ha) to urokliwy zbiornik o nieregularnym kształcie i dwóch wyspach, położony w gminie Krasnopol. Z jeziora wypływa rzeczka Dowcianka, dopływ Czarnej Hańczy. To typowe łowisko szczupakowo-linowe o średniej głębokości 4 m. Czysta woda i piaszczysto-muliste dno sprzyjają populacji okonia oraz dorodnego lina. Jezioro otaczają malownicze pola i łąki, co zapewnia łatwy dostęp do linii brzegowej.', 'PZW Suwałki / Gospodarz Prywatny');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80353, 'Jezioro Aszaryn', 'jezioro-aszaryn', 'LAKE', '54.067541355845286', '23.44175265466488', 'Podlaskie', 'Sejny', 'Aszaryn (ok. 12 ha) to niewielkie jezioro okoniowe związane z historią – w pobliżu znajdowało się wojenne lotnisko z okresu II wojny światowej. Akwen jest dość głęboki (do 7,8 m) i charakteryzuje się czystą wodą. To idealna meta dla spinningistów szukających garbusów w spokojnej, mało uczęszczanej okolicy.', 'PZW Suwałki / Falko');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80354, 'Jezioro Berżnik', 'jezioro-berznik', 'LAKE', '54.102311155032496', '23.429786857192987', 'Podlaskie', 'Sejny', 'Jezioro Berżnik (Berżniak) to potężna rynna polodowcowa o powierzchni ok. 87 ha i imponującej głębokości blisko 39 metrów. Akwen objęty jest strefą ciszy i posiada krystaliczną wodę (I/II klasa). To elitarne łowisko sielawowe, słynące z rekordowych siei, potężnych leszczy oraz toniowych szczupaków. Na południu znajduje się wyspa z polem namiotowym.', 'Gospodarstwo Rybackie Falko');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80355, 'Jezioro Hołny', 'jezioro-holny', 'LAKE', '54.13935295435014', '23.45960419668943', 'Podlaskie', 'Sejny', 'Jezioro Hołny (ok. 158 ha) to jeden z najatrakcyjniejszych akwenów w pobliżu granicy z Litwą (Ogrodniki). Jezioro typu leszczowo-sandaczowego o urozmaiconym dnie i czystej wodzie. Słynie z populacji pięknych, złotych linów, dużych sandaczy i okoni. Z południowej części wypływa rzeka Hołnianka, niosąca wody na Litwę.', 'Gospodarstwo Rybackie Falko');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80356, 'Jezioro Gaładuś', 'jezioro-galadus', 'LAKE', '54.16872869272524', '23.421856670003795', 'Podlaskie', 'Sejny', 'Jezioro Gaładuś to najpiękniejszy i największy akwen ziemi sejnejskiej (pow. ok. 560 ha po stronie polskiej). Przez jezioro przebiega granica z Litwą. Jest to głęboka rynna (do 55 m) o krystalicznej wodzie (II klasa) i bardzo urozmaiconym dnie, obfitującym w podwodne górki i głęboczki. Brzegi są wysokie, bezleśne, otoczone malowniczymi pagórkami. To elitarne łowisko sielawowe, słynące z ogromnych sielaw, siei oraz rekordowych "garbusów" (okoni) łowionych często spod lodu.', 'PZW Suwałki / Gospodarz prywatny');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80357, 'Jezioro Szejpiszki', 'jezioro-szejpiszki', 'LAKE', '54.16970242965877', '23.27421409189711', 'Podlaskie', 'Sejny', 'Jezioro Szejpiszki (lit. Klevas) to okazała rynna polodowcowa o powierzchni ok. 78 ha. Jezioro charakteryzuje się bardzo urozmaiconym dnem – północna część to klasyczna, głęboka rynna, natomiast południowa obfituje w liczne górki podwodne. To wybitne łowisko sandaczowo-leszczowe. Woda jest czysta, a brzegi malowniczo położone wśród wzgórz Pojezierza Wschodniosuwalskiego. Słynie z walecznych ryb i pięknych złotych linów.', 'Gospodarstwo Rybackie Falko');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80358, 'Jezioro Klejwy', 'jezioro-klejwy', 'LAKE', '54.157389564377034', '23.27849201375997', 'Podlaskie', 'Sejny', 'Jezioro Klejwy to mniejszy, ale niezwykle głęboki zbiornik rynnowy (pow. ok. 14 ha, głębokość do 30 m). Akwen słynie z krystalicznej czystości wód i bogatej roślinności podwodnej. To typowe łowisko szczupakowo-linowe, w którym występują również sieje. Ze względu na znaczną głębokość w stosunku do małej powierzchni, ryby mają tu doskonałe warunki do wzrostu, a wędkarze mogą liczyć na spotkanie z rekordowymi okoniami.', 'Gospodarstwo Rybackie Falko');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80359, 'Jezioro Boksze', 'jezioro-boksze', 'LAKE', '54.19882991613268', '23.171100924983502', 'Podlaskie', 'Puńsk', 'Jezioro Boksze (pow. ok. 102 ha) to unikalny akwen składający się z dwóch odrębnych pod względem wędkarskim plos. Część północna to głęboka rynna (do 22 m) – królestwo drapieżników: sandacza, okonia i szczupaka. Część południowa jest płytsza i ma charakter leszczowy, oferując wspaniałe stanowiska dla łowców linów, sumów i węgorzy. Jezioro otaczają lasy i łąki, a linia brzegowa jest bardzo rozwinięta z licznymi zatokami.', 'Gospodarstwo Rybackie Falko');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80360, 'Jezioro Judialis', 'jezioro-judialis', 'LAKE', '54.22205768965853', '23.15988638454997', 'Podlaskie', 'Puńsk', 'Jezioro Judialis (lit. Juodelis) to niewielkie, dzikie oczko polodowcowe położone w gminie Puńsk, niedaleko granicy państwa. Przez akwen przepływa rzeka Marycha. Jest to typowe jezioro linowo-szczupakowe o mulistym dnie i bogatej roślinności wynurzonej. Brzegi są trudne, bagniste, co zapewnia rybom spokój i naturalne warunki do rozrodu. To idealna meta dla wędkarzy-eksploratorów szukających kontaktu z pierwotną naturą.', 'Gospodarstwo Rybackie Falko');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80361, 'Jezioro Meldzinis', 'jezioro-meldzinis', 'LAKE', '54.22205768965853', '23.15988638454997', 'Podlaskie', 'Puńsk', 'Jezioro Meldzinis (często utożsamiane z Jeziorem Puńskim) to malowniczy akwen położony w sercu Puńska. Jezioro ma charakter rekreacyjno-wędkarski. Dzięki przeprowadzonej rekultywacji brzegów, oferuje dogodne stanowiska dla wędkarzy spławikowych. To klasyczne łowisko linowo-karasiowe, gdzie woda szybko się nagrzewa, co sprzyja intensywnym braniom ryb spokojnego żeru w okresie wiosennym.', 'Gmina Puńsk / PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80362, 'Jezioro Punia', 'jezioro-punia', 'LAKE', '54.24723825208916', '23.17427699996187', 'Podlaskie', 'Puńsk', 'Jezioro Punia (znane również jako Jezioro Puńskie lub Meldzinis) to serce miejscowości Puńsk. Jest to płytki, żyzny akwen o powierzchni ok. 16 ha. Jezioro słynie z malowniczych trzech wysp i jest systematycznie zarybiane szczupakiem oraz linem. To ulubione miejsce lokalnych wędkarzy, oferujące klimat spokojnej, pogranicznej osady. Brzegi są dobrze zagospodarowane, z pomostami i ścieżkami spacerowymi.', 'PZW Białystok / Gmina Puńsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80363, 'Jezioro Jodel', 'jezioro-jodel', 'LAKE', '54.25979667121726', '23.038738059065885', 'Podlaskie', 'Szypliszki', 'Jezioro Jodel to kameralny zbiornik śródpolny położony na północ od Szelmentu. Jest to typowe łowisko linowo-szczupakowe, otoczone pagórkami i polami uprawnymi. Dzięki małej presji turystycznej, jezioro zachowuje spokojny charakter, będąc idealną meta dla wędkarzy szukających ciszy i regularnych brań ryb spokojnego żeru.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80364, 'Jezioro Szelment Wielki', 'jezioro-szelment-wielki', 'LAKE', '54.22772582429161', '22.98089574478274', 'Podlaskie', 'Jeleniewo', 'Szelment Wielki to jedna z najpotężniejszych rynien Suwalszczyzny (pow. 334 ha, głębokość do 45 m). Jezioro imponuje swoimi rozmiarami i czystością wód (typ mezotroficzny). To wybitne łowisko sielawowe, dom wielkich szczupaków, siei i okoni. U podnóża Góry Jesionowej znajduje się nowoczesny ośrodek WOSiR Szelment z wyciągiem nart wodnych, co czyni jezioro atrakcyjnym również turystycznie. Wędkarze cenią je za urozmaicone dno z licznymi głęboczkami i twardymi blatami.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80365, 'Jezioro Burdąskie', 'jezioro-burdanskie', 'LAKE', 53.560896, 20.746393, 'Warmińsko-Mazurskie', 'Jedwabno / Burdąg', 'Burdąskie to malowniczy akwen rynnowy położony w pofałdowanym terenie. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym w strefie litoralu. Wędkarsko to doskonała woda na szczupaka i lina.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80366, 'Jezioro Leszczewo', 'jezioro-leszczewo', 'LAKE', '54.19606561069095', '22.984829540592177', 'Podlaskie', 'Suwałki', 'Jezioro Leszczewo to niewielki, zaciszny akwen położony na południe od Szelmentu Wielkiego. Jest to klasyczne jezioro linowo-szczupakowe o mulistym dnie i bogatej roślinności przybrzeżnej. Ze względu na swoje położenie w rynnie, oferuje krystaliczną wodę i osłonę od wiatru. To doskonałe miejsce na poranną zasiadkę w poszukiwaniu dorodnego lina i płoci.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80367, 'Jezioro Okmin', 'jezioro-okmin', 'LAKE', '54.15446098587698', '22.827350903959015', 'Podlaskie', 'Suwałki', 'Jezioro Okmin (lit. "akmuo" - kamień) to piękna rynna polodowcowa o powierzchni ok. 115 ha. Jezioro słynie z czystej, chłodnej wody i piaszczysto-żwirowych brzegów z dużą ilością kamieni. To wybitne łowisko sielawowe, cenione za populację rekordowych okoni i szczupaków. Głębokość sięgająca 40 metrów oraz urozmaicona linia brzegowa z licznymi skarpami i zatokami czynią je jednym z najciekawszych łowisk w okolicach Suwałk.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80368, 'Jezioro Ożewo', 'jezioro-ozewo', 'LAKE', '54.14731230449712', '22.810474537823886', 'Podlaskie', 'Suwałki', 'Ożewo to unikatowy, głęboki zbiornik (do 55,5 m) o statusie jeziora oligotroficznego (ubogiego w roślinność, ale o krystalicznej wodzie). Mimo niewielkiej powierzchni (55 ha), jest to jedno z najgłębszych jezior regionu. To elitarne łowisko sielawowe, mekka dla nurków i wędkarzy szukających ryb toniowych. Krystaliczna woda pozwala na obserwację dna nawet na kilku metrach głębokości.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80369, 'Jezioro Taciewo', 'jezioro-taciewo', 'LAKE', '54.14452258886734', '22.78494702514543', 'Podlaskie', 'Suwałki', 'Jezioro Taciewo to malowniczy, niewielki zbiornik o charakterze linowo-szczupakowym. Akwen jest położony wśród pagórków Suwalszczyzny, co zapewnia mu osłonę od wiatru. Słynie z populacji dorodnego karasia i lina. To idealne miejsce na wyciszenie i tradycyjne wędkowanie spławikowe.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80370, 'Jezioro Grabieńsk', 'jezioro-grabiansk', 'LAKE', '54.14396329178046', '22.77234567482092', 'Podlaskie', 'Suwałki', 'Grabieńsk to niewielkie oczko polodowcowe w dorzeczu Szeszupy. Jezioro charakteryzuje się mulistym dnem i bardzo bogatą roślinnością zanurzoną. To klasyczne łowisko szczupakowe i płociowe, niemal całkowicie odcięte od zgiełku turystycznego.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80371, 'Jezioro Pluszne (Pluszne Wielkie)', 'jezioro-pluszne', 'LAKE', 53.598628, 20.398521, 'Warmińsko-Mazurskie', 'Pluski / Olsztynek', 'Pluszne to jeden z absolutnych gigantów i hydrobiologicznych cudów Warmii (ponad 900 ha). Jezioro to zachwyca monumentalną wręcz głębokością sięgającą 52 metrów oraz niesamowitą, kryształową czystością wody (często klasyfikowaną jako klasa I). Na akwenie znajdują się trzy urokliwe wyspy, z których największa kryje mroczną historię jako poligon celowniczy z czasów II wojny światowej – na dnie wciąż można natrafić na fragmenty betonowych konstrukcji bombowych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80372, 'Jezioro Szczeberka', 'jezioro-szczeberka', 'LAKE', '54.12718920987132', '22.739723505195588', 'Podlaskie', 'Nowinka', 'Jezioro Szczeberka (pow. ok. 15 ha) to kameralny, dziki akwen położony w dorzeczu rzeki Szczeberki, w malowniczej okolicy Puszczy Augustowskiej. Jest to typowe jezioro linowo-szczupakowe o dość czystej wodzie i urozmaiconej linii brzegowej. Otoczone lasami i bagnistymi łąkami, zapewnia wędkarzom dużą prywatność. Słynie z populacji pięknego lina oraz walecznych szczupaków "trzciniaków", które znajdują tu doskonałe kryjówki.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80373, 'Jezioro Dąbrówka', 'jezioro-dabrowka-suwalki', 'LAKE', '54.10418870629022', '22.98881526987591', 'Podlaskie', 'Suwałki', 'Jezioro Dąbrówka to kameralny, ale niezwykle urokliwy akwen położony zaledwie kilka kilometrów na północny wschód od granic Suwałk. Jest to typowe jezioro polodowcowe o powierzchni około 12 hektarów, które stanowi idealną odskocznię dla mieszkańców miasta szukających spokoju. Charakteryzuje się dość urozmaiconą linią brzegową, która w dużej części jest porośnięta gęstym pasem trzcin i pałki wodnej, co stwarza doskonałe warunki lęgowe dla ptactwa wodnego. Woda w jeziorze jest stosunkowo czysta, a dno piaszczysto-muliste z licznymi kępami roślinności zanurzonej, takiej jak moczarka kanadyjska. Wędkarsko jest to łowisko typu linowo-szczupakowego. Można tu liczyć na regularne brania dorodnej płoci oraz lina, który szczególnie upodobał sobie płytkie, muliste zatoczki. Dzięki swojemu położeniu wśród pagórkowatych pól i kęp lasu, jezioro jest dobrze osłonięte od silnych wiatrów, co czyni je wdzięcznym miejscem do łowienia metodą spławikową.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80374, 'Jezioro Krzywe', 'jezioro-krzywe-suwalskie', 'LAKE', '54.09436833817659', '23.00578400440977', 'Podlaskie', 'Suwałki', 'Jezioro Krzywe to jeden z najbardziej rozpoznawalnych akwenów Suwalszczyzny, będący "bramą" do Wigierskiego Parku Narodowego. To okazała rynna polodowcowa o powierzchni około 138 hektarów i imponującej głębokości sięgającej blisko 30 metrów. Jezioro słynie z niezwykle czystej wody (I klasa czystości) o wysokiej przezroczystości, co sprawia, że jest popularnym miejscem dla nurków oraz pasjonatów obserwacji podwodnej natury – wytyczono tu nawet edukacyjną ścieżkę podwodną. Brzegi jeziora są wysokie, miejscami urwiste, porośnięte starymi drzewostanami iglastymi i liściastymi. Jako akwen sielawowy, Krzywe oferuje unikalny rybostan – oprócz sielawy i siei, królują tu potężne okonie (garbusy) oraz toniowe szczupaki. Wędkarstwo na tym akwenie jest regulowane rygorystycznymi przepisami parku narodowego, co jednak przekłada się na wysoką kulturę łowienia i ochronę rybostanu. Obowiązuje tu bezwzględna strefa ciszy, co pozwala w pełni cieszyć się odgłosami natury i krystalicznym powietrzem puszczy.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80375, 'Jezioro Zielone', 'jezioro-zielone-suchar', 'LAKE', '54.099204711893584', '23.011089603434463', 'Podlaskie', 'Suwałki', 'Jezioro Zielone to unikatowy w skali kraju przykład tzw. "suchara" – małego, dystroficznego jeziora śródleśnego, położonego w bezpośrednim sąsiedztwie jeziora Krzywego. Mimo swojej nazwy, woda w Zielonym ma charakterystyczny, herbaciany kolor wynikający z wysokiej zawartości kwasów humusowych, jednak przy tym pozostaje niezwykle przejrzysta. Jezioro jest bezodpływowe i otoczone przez "pło" – uginający się dywan mszarny z mchów torfowców, na którym rosną rzadkie rośliny, jak rosiczka okrągłolistna. Powierzchnia akwenu to zaledwie około 1,5 hektara, ale głębokość dochodzi do 6-7 metrów. Rybostan sucharów jest specyficzny – dominują tu karłowate formy okonia o niemal czarnym ubarwieniu oraz niezwykle waleczne liny. Ze względu na położenie w strefie ochrony ścisłej lub czynnej Wigierskiego Parku Narodowego, dostęp do jeziora i możliwość wędkowania są mocno ograniczone, a sam akwen traktowany jest głównie jako unikatowy obiekt badawczy i przyrodniczy, przypominający krajobrazy dalekiej północy lub tajgi.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80376, 'Jezioro Koleśne', 'jezioro-kolesne', 'LAKE', '54.10130203119015', '23.020219457522863', 'Podlaskie', 'Suwałki', 'Jezioro Koleśne to urokliwy, śródleśny akwen o powierzchni około 12 hektarów, położony w północnej części Wigierskiego Parku Narodowego, nieopodal ścieżki edukacyjnej „Suchary”. Jezioro ma charakter rynnowy i charakteryzuje się czystą wodą oraz urozmaiconą linią brzegową, która niemal w całości porośnięta jest starym borem sosnowo-świerkowym. Maksymalna głębokość zbiornika wynosi około 9 metrów. Pod względem wędkarskim jest to jezioro typu szczupakowo-linowego. Występuje tu dorodna płoć, leszcz oraz okoń, a w płytkich, mocno zarośniętych zatokach można spotkać pięknie ubarwione liny. Ze względu na położenie w strefie ochrony czynnej parku, wędkowanie jest tu dozwolone wyłącznie po wykupieniu licencji WPN i odbywa się w warunkach absolutnej ciszy i poszanowania dzikiej przyrody.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80377, 'Jezioro Czarne (Krzywiańskie)', 'jezioro-czarne-krzywianskie', 'LAKE', '54.0929311703427', '23.02259857110753', 'Podlaskie', 'Suwałki', 'Jezioro Czarne (znane również jako Czarne Krzywiańskie) to miniaturowy klejnot o powierzchni zaledwie 1,67 hektara, ukryty w lesie niedaleko siedziby parku w Krzywem. Mimo niewielkich rozmiarów, jest to jezioro zaskakująco głębokie (ponad 10 metrów) i charakteryzuje się niezwykle przejrzystą, błękitną wodą o charakterze mezotroficznym. Jest ono połączone sezonowymi przesmykami z okolicznymi sucharami. Brzegi są strome i całkowicie zalesione, co nadaje mu klimat górskiego stawu. To jedno z najpiękniejszych miejsc na trasie ścieżki „Suchary”, gdzie można obserwować rzadkie gatunki roślin wodnych, takie jak kłoć wiechowata. Wędkarsko jest to akwen trudny, zamieszkały głównie przez szczupaki i okonie, które w krystalicznej toni stają się niezwykle płochliwe i wymagają od wędkarza dużej finezji.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80378, 'Jezioro Suchar V', 'suchar-v-wigry', 'LAKE', '54.08906291105783', '23.03141941535924', 'Podlaskie', 'Suwałki', 'Suchar V to jedno z najbardziej niedostępnych i dzikich jeziorek dystroficznych w kompleksie leśnym Wigierskiego Parku Narodowego. Ten niewielki zbiornik o powierzchni około 0,5 hektara jest przykładem jeziora w zaawansowanej fazie naturalnego lądowacenia. Woda ma tu specyficzny, ciemny, niemal czarny kolor (stąd nazwa „suchar”), co wynika z dużej zawartości kwasów humusowych i braku wapnia. Jezioro otoczone jest przez „pło mszarne” – pływający kożuch torfowiskowy, który uniemożliwia bezpośredni dostęp do lustra wody. Suchar V jest siedliskiem rzadkich bezkręgowców i płazów. Rybostan jest tu skrajnie ubogi, ograniczony do gatunków tolerujących wysokie zakwaszenie, takich jak karłowate okonie. Akwen ten znajduje się pod ochroną ścisłą, co oznacza zakaz jakiejkolwiek ingerencji ludzkiej, w tym wędkowania – jest on traktowany jako naturalne laboratorium ewolucji.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80379, 'Jezioro Suchar IV', 'suchar-iv-wigry', 'LAKE', '54.08988096080545', '23.024488586827168', 'Podlaskie', 'Suwałki', 'Suchar IV to największy i najbardziej znany z sucharów w rejonie Krzywego (pow. ok. 1 hektara). Jest to klasyczne jezioro dystroficzne, otoczone gęstym borem sosnowym i pasem torfowiska wysokiego. To właśnie nad tym jeziorem wybudowano specjalną kładkę widokową w ramach ścieżki edukacyjnej, umożliwiającą bezpieczną obserwację tego unikatowego ekosystemu. Woda jest kwaśna i miękka, o niskiej przezroczystości, co sprzyja rozwojowi specyficznej flory (m.in. rosiczek i bagnicy torfowej). W przeciwieństwie do Suchara V, w „Czwórce” stwierdzono występowanie niewielkiej populacji karasia złocistego i szczupaka, choć ryby te rzadko osiągają duże rozmiary ze względu na trudne warunki środowiskowe. Jezioro jest symbolem pierwotnego krajobrazu polodowcowego Suwalszczyzny, gdzie procesy torfotwórcze zachodzą nieprzerwanie od tysięcy lat.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80380, 'Jezioro Suchar III', 'suchar-iii-wigry', 'LAKE', '54.08879861461525', '23.021784919969452', 'Podlaskie', 'Suwałki', 'Suchar III to małe, śródleśne jezioro dystroficzne o powierzchni ok. 0,4 ha, położone w głębi Wigierskiego Parku Narodowego. Akwen ten jest modelowym przykładem jeziora w fazie lądowacenia, otoczonego pierścieniem mchów torfowców (pło mszarne). Woda jest kwaśna i ma barwę ciemnobrunatną, co jest efektem dużej zawartości kwasów humusowych. Jezioro jest bezodpływowe i charakteryzuje się niemal całkowitym brakiem roślinności zanurzonej. Pod względem wędkarskim występuje tu głównie karłowata forma okonia, a dostęp do lustra wody jest możliwy tylko w wyznaczonych punktach ścieżki edukacyjnej.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80381, 'Jezioro Suchar II', 'suchar-ii-wigry', 'LAKE', '54.0873577304041', '23.017419355115315', 'Podlaskie', 'Suwałki', 'Suchar II (pow. ok. 0,5 ha) to jedno z najbardziej malowniczych leśnych oczek na trasie ścieżki przyrodniczej w Krzywem. Jezioro otoczone jest gęstym borem sosnowo-świerkowym, a jego brzegi stanowi uginający się kożuch roślinny, pod którym znajduje się woda. Mimo małych rozmiarów, jezioro jest dość głębokie (ok. 6 m). To kraina bobrów i rzadkich roślin torfowiskowych. Woda o herbacianym kolorze jest niezwykle miękka. Ze względu na ochronę parku, nie prowadzi się tu gospodarki rybackiej, pozwalając na naturalne trwanie populacji karasia i okonia.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80382, 'Jezioro Suchar I', 'suchar-i-wigry', 'LAKE', '54.085299530897046', '23.014977032042072', 'Podlaskie', 'Suwałki', 'Suchar I to największy z grupy sucharów w rejonie siedziby WPN (pow. ok. 1 ha). Jest to klasyczne jezioro dystroficzne o brunatnej wodzie i torfowym dnie. Charakterystyczną cechą akwenu są liczne grążele żółte pokrywające znaczną część lustra wody w okresie letnim. Jezioro jest oazą spokoju, położoną z dala od głównych szlaków turystycznych. Słynie z populacji walecznego, "czarnego" okonia oraz karasia złocistego, który doskonale radzi sobie w zakwaszonym środowisku jeziora.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80383, 'Jezioro Sobolewo', 'jezioro-sobolewo', 'LAKE', '54.07476944235055', '22.95978303639123', 'Podlaskie', 'Suwałki', 'Jezioro Sobolewo (pow. ok. 80 ha) to malowniczy akwen położony w bezpośrednim sąsiedztwie południowo-wschodnich granic Suwałk. Jest to jezioro typu mezotroficznego o czystej wodzie i bardzo urozmaiconym dnie. Przez jezioro przepływa rzeka Czarna Hańcza, co zapewnia mu stały dopływ świeżej, natlenionej wody. To wybitne łowisko sandaczowo-szczupakowe, cenione za krystaliczną wodę i piękne okonie. Brzegi są w większości dostępne, piaszczyste, z dobrze rozwiniętą infrastrukturą rekreacyjną (plaża, pomosty).', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80384, 'Jezioro Pierty', 'jezioro-pierty', 'LAKE', '54.10147322859124', '23.077732256742742', 'Podlaskie', 'Suwałki', 'Jezioro Pierty to jedna z pereł Wigierskiego Parku Narodowego (pow. ok. 228 ha). To okazałe jezioro rynnowe o bardzo urozmaiconej linii brzegowej z licznymi zatokami i półwyspami. Woda jest bardzo czysta, o szafirowym odcieniu. To wybitne łowisko sielawowe i sandaczowe. Jezioro słynie z ogromnych leszczy oraz sandaczy, które znajdują doskonałe warunki żerowania na twardych, żwirowych stokach podwodnych górek. Obowiązuje tu bezwzględna strefa ciszy, a wędkowanie regulowane jest licencjami WPN, co zapewnia wysoką rybność akwenu.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80385, 'Jezioro Leszczewek', 'jezioro-leszczewek', 'LAKE', '54.072397406036366', '23.062840048391358', 'Podlaskie', 'Suwałki', 'Jezioro Leszczewek (pow. ok. 21 ha) to niezwykle malowniczy akwen położony tuż przy północno-zachodnim brzegu Wigier, w okolicach miejscowości Stary Folwark. Leży w granicach Wigierskiego Parku Narodowego i łączy się z Wigrami wąskim przesmykiem. Ze względu na swoje położenie i bardzo czystą wodę, jest to oaza spokoju, oferująca wspaniałe widoki na okoliczne wzgórza. Dno jeziora jest piaszczysto-muliste i dość szybko opada, osiągając maksymalną głębokość około 6,5 metra. Wędkarsko jest to zbiornik typu linowo-szczupakowego z dużą populacją ładnej płoci i wzdręgi. Wiosną, gdy woda szybko się tu nagrzewa, Leszczewek staje się doskonałym łowiskiem białorybu, a wczesnym rankiem można tu zaobserwować spławiające się potężne liny. Połów wymaga licencji WPN i przestrzegania ścisłych zasad ochrony przyrody.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80386, 'Jezioro Omułówek', 'jezioro-omulowek', 'LAKE', '54.085066653075124', '23.091419864982914', 'Podlaskie', 'Suwałki', 'Jezioro Omułówek (ok. 17 ha) to wydłużona, rynnowa zatoka, która geologicznie i hydrologicznie ciąży ku systemowi Wigier, znajdując się w północnej części Wigierskiego Parku Narodowego niedaleko miejscowości Tartak. Akwen jest mocno wcięty w zalesiony teren, co nadaje mu charakter dzikiego, śródleśnego fiordu. Strome brzegi porośnięte są starym borem iglastym, który rzuca cień na ciemne i chłodne wody jeziora. Maksymalna głębokość sięga tu około 9 metrów. Jest to doskonałe miejsce dla wędkarzy szukających absolutnej ciszy – z dala od głównych szlaków kajakowych. Występuje tu piękny, ciemno ubarwiony okoń oraz szczupak, a w strefie litoralu (przybrzeżnej) można liczyć na spotkanie z linem i dorodnym karasiem.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80387, 'Jezioro Żubrowo', 'jezioro-zubrowo', 'LAKE', '54.10755376996647', '23.14425789769227', 'Podlaskie', 'Krasnopol', 'Jezioro Żubrowo to kameralny zbiornik wodny o powierzchni kilkunastu hektarów, położony na obrzeżach Puszczy Augustowskiej, w gminie Krasnopol. W przeciwieństwie do pobliskich głębokich rynien polodowcowych, Żubrowo jest akwenem stosunkowo płytkim i bardzo żyznym, szybko zarastającym roślinnością wynurzoną (szuwary) i zanurzoną (grążele, rdestnice). Dno jest tu wybitnie muliste i miękkie. To klasyczne, typowo "wiejskie" jezioro linowo-karasiowe, które latem zamienia się w zieloną dżunglę. Jest to wymarzone łowisko dla tradycyjnych spławikowców, którzy przy odpowiednim, kilkudniowym nęceniu kukurydzą i pęczakiem, mogą liczyć na wyjątkowo silne, puszczańskie liny oraz potężne karasie złociste. Dostęp z brzegu jest utrudniony ze względu na pasy bagien, dlatego do wędkowania zalecany jest ponton lub lekka łódka.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80388, 'Jezioro Gremzdy', 'jezioro-gremzdy', 'LAKE', '54.08300479724795', '23.20465260283868', 'Podlaskie', 'Krasnopol', 'Jezioro Gremzdy (Gremzdy Polskie) to przepiękny, rynnowy akwen o powierzchni około 140 hektarów i głębokości dochodzącej do blisko 30 metrów. Położone na wschód od Wigier, nie jest objęte reżimem Parku Narodowego, co czyni je niezwykle atrakcyjnym dla wędkarzy szukających swobody, a jednocześnie wód o puszczańskim charakterze. Woda w Gremzdach jest krystalicznie czysta, o zielonkawym odcieniu, a dno jest bardzo urozmaicone – obfituje w kamieniste rafy, podwodne górki oraz strome uskoki (tzw. "półki"). To wybitne łowisko drapieżników: toniowego szczupaka, dorodnego okonia, a także coraz częściej spotykanego sandacza. Zimą to popularny cel podlodowych łowców siei. Brzegi jeziora są na przemian zalesione i otoczone łąkami, co ułatwia biwakowanie i wędkowanie z łodzi.', 'Gospodarstwo Rybackie PZW / Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80389, 'Jezioro Głuche', 'jezioro-gluche-krasnopol', 'LAKE', '54.06462875474443', '23.238624904463425', 'Podlaskie', 'Krasnopol', 'Jezioro Głuche, zgodnie ze swoją nazwą, to niezwykle ciche i spokojne, śródleśne oczko polodowcowe ukryte w kompleksie Lasów Krasnopolskich. Ten mały (ok. 8 ha), bezodpływowy zbiornik ma charakter dystroficzny – woda posiada lekko brunatny, herbaciany odcień wynikający z otaczających go torfowisk. Brzegi są trudne, zdominowane przez olsy i trzęsawiska, co skutecznie odstrasza przypadkowych turystów i gwarantuje łowisku niemal całkowitą izolację. Wędkarsko to domena "czarnego" okonia, dzikiego szczupaka (tzw. pistoleta) i karasia. Idealne miejsce dla łowców-eksploratorów przedzierających się przez gęstwiny z krótkim spinningiem.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80390, 'Jezioro Jurkowo', 'jezioro-jurkowo', 'LAKE', '54.05710916309645', '23.23132158207505', 'Podlaskie', 'Krasnopol', 'Jezioro Jurkowo to bliski sąsiad jeziora Głuchego, leżący w tej samej niecce wytopiskowej. To miniaturowy, kilkuhektarowy akwen o wybitnie bagnistych, porośniętych szerokim pasem trzciny i pałki wodnej brzegach. Zbiornik ulega powolnemu, naturalnemu procesowi lądowacenia, przez co jego średnia głębokość wynosi zaledwie 1-2 metry. Mimo to, latem tętni tu życie – to doskonałe tarlisko dla płoci, wzdręgi i lina. Wędkarze odwiedzający to miejsce muszą być przygotowani na walkę z gęstą roślinnością podwodną; łowienie "w oczkach" i na tzw. spadochron to jedyne skuteczne metody.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80391, 'Jezioro Królówek', 'jezioro-krolowek', 'LAKE', '54.11401606684355', '23.074002098756694', 'Podlaskie', 'Suwałki', 'Jezioro Królówek to bardzo interesujący, kilkunastohektarowy zbiornik leżący na północ od słynnego jeziora Pierty. Jego linia brzegowa jest silnie rozwinięta, a w południowej części jeziora znajduje się przewężenie. Akwen ten oferuje bardzo przejrzystą wodę i urozmaicone, piaszczysto-żwirowe dno. Z racji swojego położenia – nieco na uboczu głównego szlaku turystycznego Parku – Królówek jest oazą dla lokalnej fauny. Wędkarsko to bardzo solidne łowisko szczupakowe i okoniowe. Ryby mają tu doskonałe warunki do żerowania na podwodnych blatach. Dostęp z lądu jest możliwy dzięki leśnym ścieżkom, a kilka naturalnych prześwitów w trzcinowiskach pozwala na komfortowe wędkowanie.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80392, 'Jezioro Pietronajcie', 'jezioro-pietronajcie', 'LAKE', '54.12919224516118', '23.066918566029152', 'Podlaskie', 'Suwałki', 'Pietronajcie to ukryte w rolniczo-leśnym krajobrazie na wschód od Huty (gm. Suwałki) małe jezioro polodowcowe. Zbiornik zajmuje około 10 hektarów i ma kształt owalnej misy z łagodnie opadającymi stokami. Dno jest tu mocno zamulone, a woda w okresie letnim często ulega zakwitom glonów (typ eutroficzny). Ze względu na bliskość pól uprawnych, do jeziora spływa sporo substancji odżywczych, co z kolei sprzyja szybkiemu przyrostowi ryb z rodziny karpiowatych. To lokalne "eldorado" na wielką, złotą wzdręgę, potężnego karasia i tłustego lina. Wędkarskie stanowiska znajdują się głównie na wschodnim, twardszym brzegu.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80393, 'Jezioro Dowcień (Wigierskie)', 'jezioro-dowcien-wigierskie', 'LAKE', '54.08052471429854', '23.12817898449015', 'Podlaskie', 'Suwałki', 'Uwaga: nie mylić z jeziorem Dowcień w okolicach Krasnopola. Ten Dowcień to niezwykle urokliwy, podłużny akwen zlokalizowany w otulinie WPN, w bezpośrednim sąsiedztwie Czerwonego Folwarku i ujścia Czarnej Hańczy do Wigier. Zajmujący około 15 hektarów zbiornik charakteryzuje się bardzo czystą wodą i przepięknymi, zalesionymi brzegami, które opadają stromo do wody. To jezioro słynie z dużej populacji walecznego okonia i pięknej płoci, a z uwagi na dogodny przepływ wód z rzeki, wędkarze często notują tu brania ryb "przechodnich", w tym jazi i dorodnych kleni. Z racji swojego podłużnego kształtu, przypomina małą, zalaną dolinę rzeczną.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80394, 'Jezioro Postaw', 'jezioro-postaw', 'LAKE', '54.071433680989315', '23.110156456934547', 'Podlaskie', 'Suwałki', 'Jezioro Postaw to kluczowy, choć niewielki (ok. 14 ha) węzeł hydrologiczny Wigierskiego Parku Narodowego. Akwen stanowi naturalne, szerokie rozlewisko rzeki Czarna Hańcza, która majestatycznie wpływa do jeziora Wigry właśnie przez ten zbiornik. Z tego powodu Postaw charakteryzuje się stałym przepływem, doskonale natlenioną wodą i brakiem termokliny charakterystycznej dla wód stojących. Dno jeziora jest tu wyjątkowo ciekawe – piaszczyste i żwirowe na głównym nurcie, a muliste w zakolach. Dla wędkarza oznacza to jedno: bogactwo gatunków. Można tu złowić piękne rzeczne jazie i klenie, jeziorowe leszcze, a także wielkie szczupaki, które czatują na granicy nurtu i spokojnej wody na migrującą z rzeki drobnicę.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80395, 'Jezioro Wigry', 'jezioro-wigry', 'LAKE', '54.05296832072686', '23.083473738535154', 'Podlaskie', 'Suwałki', 'Jezioro Wigry to absolutna korona suwalskich wód, bijące serce Wigierskiego Parku Narodowego i jedno z najcenniejszych, nizinnych jezior w całej Europie. Powierzchnia tego giganta wynosi niemal 2170 hektarów, a maksymalna głębokość sięga imponujących 73 metrów! [Image of Jezioro Wigry bathymetry map] Akwen wyróżnia się niezwykle skomplikowaną linią brzegową – przypomina literę "S" i rozwidla się na liczne, głębokie zatoki (m.in. Słupiańska, Uklejowa, Hańczańska), które same w sobie wielkością przewyższają niejedno standardowe jezioro. Ponadto na jeziorze znajduje się 19 malowniczych wysp (m.in. Ostrów, Kamień, Ordów). Wigry słyną z szafirowej, krystalicznej wody o I klasie czystości. Nad akwenem, na półwyspie wznosi się słynny, zabytkowy Pokamedulski Klasztor w Wigrach. Wędkarsko to raj o charakterze sielawowym – żyją tu potężne toniowe szczupaki, legendarne wręcz okonie, wspaniałe sieje i sielawy. Historycznie jezioro słynęło z występowania troci jeziorowej. Łowienie tu to przywilej wymagający przestrzegania ścisłych reguł WPN (m.in. bezwzględny zakaz używania silników spalinowych), co pozwala cieszyć się wędkowaniem w dziewiczych, niemal pierwotnych warunkach. Ze względu na rozmiary i głębokości, Wigry są akwenem niezwykle kapryśnym i technicznym – znajomość batymetrii i korzystanie z echosondy to często klucz do sukcesu.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80396, 'Jezioro Łańskie', 'jezioro-lanskie', 'LAKE', 53.599137, 20.48624, 'Warmińsko-Mazurskie', 'Łańsk / Stawiguda', 'Jezioro Łańskie to wędkarska i historyczna legenda. Położone w samym sercu Puszczy Napiwodzko-Ramuckiej, przez dziesięciolecia było odcięte od świata, funkcjonując jako zamknięty ośrodek wypoczynkowy dla najwyższych władz państwowych (tzw. "Imperium Łańskie"). Dzięki tej izolacji, rynnowe jezioro o długości niemal 11 kilometrów i głębokości 53 metrów, zachowało nieskażony, dziki charakter i potężny rybostan. Przez jezioro przepływa rzeka Łyna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80397, 'Jezioro Długie (Sejneńskie)', 'jezioro-dlugie-sejnenskie', 'LAKE', '54.10915206309543', '23.177767972887573', 'Podlaskie', 'Krasnopol', 'Jezioro Długie w gminie Krasnopol to klasyczna, bardzo wąska rynna polodowcowa, która malowniczo wije się wśród pagórkowatych pól i mieszanych lasów. Powierzchnia akwenu wynosi około 60 hektarów, a strome spady denne i głębokość maksymalna dochodząca do 20 metrów czynią je wybitnym łowiskiem typu sielawowego. Ze względu na swój rynnowy charakter, jezioro jest doskonale osłonięte od bocznych wiatrów. Czysta, świetnie natleniona woda sprzyja występowaniu dorodnej sielawy, a co za tym idzie – wielkich, toniowych drapieżników. Wędkarze z sukcesami polują tu na potężne szczupaki oraz okonie. Na płytszych, porośniętych rdestnicą blatach można liczyć na spotkanie z pięknym leszczem.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80398, 'Jezioro Gremzdel', 'jezioro-gremzdel', 'LAKE', '54.14121637564719', '23.166594915423733', 'Podlaskie', 'Krasnopol', 'Jezioro Gremzdel (ok. 24 ha) to bliski, płytszy sąsiad potężnego jeziora Gremzdy. Wędkarsko to typowe łowisko linowo-szczupakowe. W przeciwieństwie do swojego głębokiego sąsiada woda szybciej się tu nagrzewa, co powoduje bujny rozkwit flory podwodnej, m.in. rogatka i grążeli. To doskonałe miejsce dla spinningistów lubiących obławiać płycizny za pomocą lekkich błystek obrotowych i żab antyzaczepowych. Tutejsze szczupaki, choć nie osiągają gigantycznych rozmiarów, są bardzo agresywne i licznie patrolują granice roślinności.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80399, 'Jezioro Jegliniec', 'jezioro-jegliniec', 'LAKE', '54.14407172138764', '23.142793639006396', 'Podlaskie', 'Krasnopol', 'Jezioro Jegliniec to piękny, około 30-hektarowy zbiornik położony wśród borów sosnowych. Wyróżnia się dość dużą przezroczystością wody i piaszczystym, urozmaiconym dnem. Strome zalesione brzegi opadają szybko na głębokość kilkunastu metrów. Zbiornik słynie w regionie z bardzo zdrowej populacji sandacza oraz wyrośniętego okonia, które chętnie trzymają się zwalonych do wody pni drzew i żwirowych półek. Wędkowanie z łodzi lub pontonu jest tu niemal koniecznością z uwagi na brak dogodnych dojść do lustra wody z poziomu lasu.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80400, 'Jezioro Sejwy', 'jezioro-sejwy', 'LAKE', '54.212335621540575', '23.189531273301952', 'Podlaskie', 'Puńsk', 'Jezioro Sejwy to majestatyczna, głęboka rynna polodowcowa o powierzchni blisko 100 ha, leżąca niedaleko granicy z Litwą i miejscowości Wojtokiemie. Przez akwen przepływa malownicza rzeka Marycha. Dzięki stałemu przepływowi wody jezioro jest doskonale natlenione przez cały rok, a dno jest wolne od nadmiaru osadów. To wybitne łowisko leszczowo-sandaczowe. Tutejsze leszcze potrafią osiągać wagę powyżej 3 kg, a spinningiści regularnie zgłaszają tu brania okazałych szczupaków u ujścia rzeki. Jezioro otoczone jest pagórkowatymi polami, co naraża je na wiatry, ale też zapewnia piękny, surowy krajobraz.', 'Gospodarstwo Rybackie Falko / PZW');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80401, 'Jezioro Mielin', 'jezioro-mielin', 'LAKE', '54.207928307730946', '23.17050764904967', 'Podlaskie', 'Puńsk', 'Jezioro Mielin to nieduży (ok. 15 ha), cichy i silnie zarośnięty sąsiad jeziora Boksze. Zbiornik ten leży w naturalnym zagłębieniu terenu, otoczony gęstymi szuwarami i zadrzewieniami. Jest to ostoja ryb spokojnego żeru – dominuje tu lin, złoty karaś i okazała wzdręga. Dno jest wybitnie muliste, co zmusza wędkarzy do ostrożnego wyważania zestawów spławikowych. Miejsce doceniane przez tradycjonalistów szukających odskoczni od gwaru i presji wędkarskiej dużych akwenów.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80402, 'Jezioro Ogórki', 'jezioro-ogorki', 'LAKE', '54.23209307614094', '23.244437262826132', 'Podlaskie', 'Sejny', 'Jezioro Ogórki (w pobliżu miejscowości Sankury) to dzikie, śródleśne jezioro rynnowe leżące niemal przy samej granicy z Litwą. Krystalicznie czysta, chłodna woda i strome spady to wizytówka tego kilkunastohektarowego akwenu. Dominują tu duże okonie, płocie i szczupaki. Obecność zwalonych drzew w wodzie tworzy naturalne rafy, wokół których kręcą się największe drapieżniki. Wymaga od wędkarza bardzo cichego podejścia, gdyż ryby ze względu na przejrzystość wody są ekstremalnie ostrożne.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80403, 'Jezioro Dmitrowo', 'jezioro-dmitrowo', 'LAKE', '54.08870225497894', '23.276911137719864', 'Podlaskie', 'Giby', 'Jezioro Dmitrowo (często zapisywane jako Dymitrowo) to urokliwy, podłużny zbiornik zagubiony w Puszczy Augustowskiej na wschód od Maćkowej Rudy. Akwen o powierzchni ok. 22 ha, leżący w otoczeniu wysokich, mieszanych lasów. To typowe łowisko szczupakowo-linowe o piaszczysto-mulistym dnie. Latem duża część brzegów zarasta nenufarami, tworząc naturalne zielone korytarze. Spokój zakłócają tu jedynie uderzenia dużych szczupaków polujących na płyciznach o poranku.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80404, 'Jezioro Białowierśnie', 'jezioro-bialowiersnie', 'LAKE', '54.055481511647606', '23.30203856989757', 'Podlaskie', 'Giby', 'Białowierśnie to perła Puszczy Augustowskiej o powierzchni około 35 ha. Ten głęboki, rynnowy akwen charakteryzuje się niesamowitą wręcz przejrzystością wody i twardym, kamienisto-żwirowym dnem. Jezioro znane jest łowcom podwodnym oraz pasjonatom wędkarstwa podlodowego. Dominującym drapieżnikiem jest tu wspaniale wybarwiony, niemal czarny w grzbiecie okoń oraz szczupak żerujący na stadach sielawy. Z uwagi na gęsty bór iglasty porastający strome brzegi, zwodowanie łodzi jest tu sporym wyzwaniem logistycznym.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80405, 'Jezioro Czarne (k. Białowierśni)', 'jezioro-czarne-giby', 'LAKE', '54.04448128146645', '23.29870417848741', 'Podlaskie', 'Giby', 'Jezioro Czarne położone tuż obok Białowierśni to jego przyrodnicze przeciwieństwo. Ten niewielki, kilkuhektarowy zbiornik ma charakter dystroficzny. Otoczony bagnistym płem (mchami torfowcami), przechowuje w swych trzewiach ciemną, brunatną wodę o dużej kwasowości. Wędkarsko to królestwo bardzo ciemno ubarwionego lina i piskorza, oraz karłowatego okonia. Idealna propozycja na "chodzony" spacer z lekkim spinningiem w poszukiwaniu nietypowych rybich mieszkańców.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80406, 'Jezioro Okuniewo', 'jezioro-okuniewo-giby', 'LAKE', '54.02368373329836', '23.307112411343425', 'Podlaskie', 'Giby', 'Zgodnie z nazwą, Okuniewo to śródleśne, niewielkie oczko polodowcowe słynące z "garbusów". Leżące na południe od miejscowości Giby, ma powierzchnię kilkunastu hektarów i mocno opadające do wody, podmokłe brzegi. Woda, z uwagi na dopływ związków humusowych, ma tu specyficzny odcień. Zbiornik uchodzi za kapryśny, ale przy odpowiednim ciśnieniu potrafi obdarzyć wędkarza serią imponujących okoni łowionych na małe twistery (boczny trok) lub małe wahadłówki.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80407, 'Jezioro Dąbiel', 'jezioro-dabiel', 'LAKE', '54.035232400006045', '23.31466607770802', 'Podlaskie', 'Giby', 'Dąbiel to wydłużone, rynnowe jezioro ukryte w kompleksie Puszczy Augustowskiej na wschód od Gib. Zajmuje powierzchnię ok. 25 ha i jest świetnym przykładem zdrowego, przepływowego akwenu leśnego. Dno opada tu równomiernie, tworząc doskonałe blaty porośnięte roślinnością zanurzoną. Słynie z bogatej populacji szczupaka oraz dużej płoci, z którą walka w kryształowo czystej wodzie dostarcza wielu emocji.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80408, 'Jezioro Stulpień (Stupień)', 'jezioro-stulpien', 'LAKE', '54.03592810396346', '23.458402593808064', 'Podlaskie', 'Giby', 'Stulpień to malownicze, dzikie jezioro o powierzchni około 30 ha zlokalizowane blisko granicy, w niedalekim sąsiedztwie rzeki Marychy i wsi Zelwa. Jest to jezioro bardzo spokojne, w większości zarośnięte liliami wodnymi i grążelami. Z uwagi na grube pokłady mułu na dnie, dominującym gatunkiem jest tu lin i karaś. Ze względu na bagniste brzegi, połów z lądu jest niemal niemożliwy bez woderów lub uprzednio przygotowanych, rzadkich tu dzikich pomostów.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80409, 'Jezioro Łempis', 'jezioro-lempis', 'LAKE', '54.046136094827844', '23.471792127414567', 'Podlaskie', 'Sejny', 'Jezioro Łempis, leżące na pograniczu polsko-litewskim, to fantastyczna rynna o wyjątkowej głębokości (ok. 27 m). Woda ma tu niemal alpejski odcień błękitu i jest niezwykle czysta. Akwen obfituje w górki podwodne, wokół których kręcą się stada sielawy, a co za tym idzie – olbrzymie, toniowe szczupaki. Znajduje się z dala od asfaltowych dróg, zapewniając wędkarzom 100% obcowania z nieskażoną naturą. Wymaga dobrej echosondy do namierzenia stromych, podwodnych spadów.', 'Gospodarstwo Rybackie Falko / PZW');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80410, 'Jezioro Blizno', 'jezioro-blizno-ateny', 'LAKE', '53.958663691266935', '23.067379910389892', 'Podlaskie', 'Nowinka', 'Jezioro Blizno to potężna, przepiękna rynna polodowcowa (ok. 240 ha) ciągnąca się na długości blisko 5 kilometrów w okolicach turystycznych Aten. Jest to bardzo głęboki akwen (do 29 m) o piaszczysto-żwirowym dnie i stromych stokach. Woda, będąca w I/II klasie czystości, jest tu chłodna i doskonale natleniona. Blizno to legendarna "woda" dla łowców sandaczy, grubych szczupaków i sielawy. Z racji rozległej powierzchni wędkarze najczęściej przeczesują je trollingując. Przylegające doń stare lasy sosnowe tworzą mikroklimat sprzyjający długiemu wędkowaniu.', 'Gospodarstwo Rybackie PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80411, 'Jezioro Busznica', 'jezioro-busznica', 'LAKE', '53.94426913142369', '23.083102036986915', 'Podlaskie', 'Nowinka', 'Sąsiadująca z Bliznem Busznica to zdecydowanie mniejsze (ok. 30 ha), ale niesamowicie urokliwe oczko. Często traktowana jako zatoka rynny blizneńskiej, posiada jednak swój odrębny, spokojniejszy charakter. Jezioro otoczone jest stromymi zboczami obrośniętymi puszczą, co stwarza świetną osłonę przed wiatrami. Jego głębokość dochodząca do ponad 20 metrów czyni z niego wybitne łowisko dla spinningistów łowiących "z opadu" i wędkarzy podlodowych polujących na wielkiego okonia. Przy brzegach wśród trzcin z powodzeniem można zasiąść na okazałą płoć.', 'Gospodarstwo Rybackie PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80412, 'Jezioro Blizenko', 'jezioro-blizenko', 'LAKE', '53.954162858737476', '23.11105958627373', 'Podlaskie', 'Nowinka', 'Jezioro Blizenko to urokliwy, mniejszy "brat" potężnego jeziora Blizno, z którym jest zresztą połączone krótkim przesmykiem. Akwen o powierzchni niespełna 40 hektarów leży w głębokiej rynnie polodowcowej otoczonej gęstymi lasami Puszczy Augustowskiej. W przeciwieństwie do Blizna, woda nagrzewa się tu nieco szybciej, co skutkuje bogatszym pasem roślinności wynurzonej i bujnymi podwodnymi łąkami. Wędkarsko to znakomity zbiornik mieszany, słynący z wielkich, złotych linów ukrywających się w zatoczkach oraz niezwykle walecznych szczupaków, które chętnie patrolują skraje trzcinowisk. Czysta woda, leśna głusza i mniejsza presja turystyczna czynią z Blizenka idealne miejsce na długie, ciche zasiadki z łodzi.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80413, 'Jezioro Tobołowo', 'jezioro-tobolowo', 'LAKE', '53.9647196281333', '23.147393889385455', 'Podlaskie', 'Nowinka', 'Tobołowo to wydłużone, rynnowe jezioro rzeczne o powierzchni około 85 hektarów, przez które przepływa rzeka Blizna. Ten stały przepływ wody doskonale natlenia akwen, co ma kluczowy wpływ na kondycję tutejszych ryb. Zbiornik charakteryzuje się dość piaszczystym dnem i wodą o lekko rzecznym, mętnawym zabarwieniu w okresach silniejszych opadów. Tobołowo to prawdziwe eldorado dla spinningistów – tutejsze szczupaki rosną bardzo szybko, a przy ujściu i wypływie rzeki można trafić na dorodne okonie i przepływowe jazie. Brzegi są w większości wysokie i zalesione, co ułatwia znalezienie osłony przed wiatrem podczas wędkowania z łodzi.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80414, 'Jezioro Długie Wigierskie', 'jezioro-dlugie-wigierskie', 'LAKE', '54.02169991404248', '23.035658936031673', 'Podlaskie', 'Suwałki', 'Jezioro Długie to wąska, długa na niemal 3 kilometry rynna o powierzchni ok. 75 hektarów, leżąca w ścisłym sercu Wigierskiego Parku Narodowego. Zbiornik ten, wraz z sąsiadującymi jeziorami Okrągłym i Mulicznym, stanowi rezerwat ścisły, powołany do ochrony pierwotnych ekosystemów wodnych oraz rzadkich gatunków ptaków i ssaków (m.in. wydry i bobra). Długie charakteryzuje się bardzo urozmaiconym dnem z licznymi przegłębieniami sięgającymi kilkunastu metrów oraz bogatą florą ramienicową. UWAGA: Ze względu na status rezerwatu ścisłego WPN, na jeziorze obowiązuje bezwzględny zakaz wędkowania, turystyki wodnej oraz poruszania się po brzegach. To naturalne sanktuarium, które możemy jedynie podziwiać z wyznaczonych szlaków w oddali.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80415, 'Jezioro Okrągłe', 'jezioro-okragle-wpn', 'LAKE', '54.02086201431621', '23.022306814147672', 'Podlaskie', 'Suwałki', 'Okrągłe to małe (ok. 14 ha), niemal idealnie koliste jezioro leżące tuż obok jeziora Długiego, z którym dzieli status rezerwatu ścisłego Wigierskiego Parku Narodowego. Posiada bardzo czystą wodę i piaszczysto-muliste dno, które gwałtownie opada do głębokości kilkunastu metrów. Jezioro otoczone jest zwartym pierścieniem lasu, stanowiąc doskonałą enklawę dla dzikiej zwierzyny i ptactwa. Podobnie jak w przypadku jeziora Długiego, z uwagi na najwyższy stopień ochrony przyrody, działalność wędkarska i turystyczna jest tutaj surowo wzbroniona. Akwen służy wyłącznie celom badawczym i zachowaniu nienaruszonej bioróżnorodności.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80416, 'Jezioro Muliczne', 'jezioro-muliczne-wpn', 'LAKE', '54.02772516372878', '23.03581066468942', 'Podlaskie', 'Suwałki', 'Jezioro Muliczne (ok. 22 ha) to trzeci element unikalnego, ściśle chronionego trójkąta wodnego w południowo-zachodniej części Wigierskiego Parku Narodowego (wraz z Długim i Okrągłym). Zbiornik o silnie zarośniętych, mulistych brzegach, które dają schronienie niezliczonym gatunkom płazów i ptactwa błotnego. Płytkie zatoki są naturalnymi tarliskami ryb spokojnego żeru, których populacja regulowana jest tu wyłącznie przez samą naturę, a zwłaszcza potężne, dzikie szczupaki. Jako rezerwat ścisły, Muliczne jest całkowicie zamknięte dla wędkarzy. Jego istnienie ma kluczowe znaczenie dla utrzymania równowagi ekologicznej całego pojezierza wigierskiego.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80417, 'Jezioro Białe Wigierskie', 'jezioro-biale-wigierskie', 'LAKE', '54.03134289661359', '23.090433786926436', 'Podlaskie', 'Suwałki', 'Białe Wigierskie to niezwykle urokliwy, ok. 100-hektarowy akwen leżący po wschodniej stronie kompleksu wigierskiego. Swoją nazwę zawdzięcza wyjątkowo jasnemu, piaszczystemu dnu i krystalicznie czystej wodzie (I klasa), która nadaje płyciznom charakterystyczny, białawo-błękitny odcień. Misa jeziora jest bogato urzeźbiona, ze stromymi spadkami prowadzącymi na głębokość ponad 30 metrów. To wybitne jezioro sielawowe, oferujące świetne warunki do połowu dużych, toniowych szczupaków oraz "garbatych" okoni na spinning. Wędkowanie uwarunkowane jest posiadaniem licencji WPN i przestrzeganiem ścisłych limitów (oraz zakazu silników spalinowych). Czystość wody wymusza na wędkarzach stosowanie bardzo finezyjnych i niewidocznych zestawów.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80418, 'Jezioro Mulaczysko', 'jezioro-mulaczysko', 'LAKE', '54.00677645125303', '23.099931489169762', 'Podlaskie', 'Suwałki', 'Mulaczysko to malowniczy, około 20-hektarowy zbiornik leżący na południe od Wigier, w otulinie Parku Narodowego. Mimo "mulistej" nazwy, woda jest tu stosunkowo czysta, a dno w wielu miejscach piaszczyste i zarośnięte bujnymi łąkami podwodnymi. Jezioro słynie ze świetnych warunków dla ryb karpiowatych – to prawdziwa wylęgarnia i dom wielkich linów, karasi oraz potężnych leszczy. Płytkie, trzcinowe zatoki wiosną niemal "gotują się" od spławiających się ryb. To idealne łowisko dla wędkarzy spławikowych i gruntowych, którzy cenią sobie ciszę i kontakt z dziką, parkową przyrodą.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80419, 'Jezioro Krusznik', 'jezioro-krusznik', 'LAKE', '54.01224095760776', '23.107393243304863', 'Podlaskie', 'Suwałki', 'Jezioro Krusznik to niewielkie, niespełna 10-hektarowe oczko wodne sąsiadujące z jeziorami Mulaczysko i Wigry. Otoczone gęstym lasem mieszanym i pagórkami, stanowi zaciszną enklawę, rzadko odwiedzaną przez turystów. Jego dno jest dość muliste, co sprzyja rozwojowi bujnej roślinności zanurzonej. Wędkarsko to typowe łowisko okoniowo-szczupakowe, w którym wędkarze najczęściej korzystają z lekkich zestawów spławikowych, poszukując ładnej płoci i wzdręgi na skraju trzcin. Pełni funkcję spokojnego, bocznego akwenu dla osób uciekających od trudnych i technicznych wód głównych rynien.', 'Wigierski Park Narodowy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80420, 'Jezioro Skazdubek', 'jezioro-skazdubek', 'LAKE', '54.11442658139058', '22.69353911070183', 'Podlaskie', 'Bakałarzewo', 'Skazdubek to ukryte w polodowcowym krajobrazie Pojezierza Zachodniosuwalskiego, nieduże jezioro o powierzchni około 15 hektarów. Leży z dala od głównych dróg, otoczone polami uprawnymi i kępami zadrzewień. Posiada niezwykle urozmaicone dno z głęboczkami i piaszczystymi wypłyceniami. Ze względu na dość żyzne wody, jest to fantastyczne łowisko leszczowo-linowe. Spinningiści chętnie zaglądają tu jesienią, polując na wyrośnięte, choć bardzo ostrożne szczupaki. Brak rozbudowanej infrastruktury turystycznej sprawia, że to miejsce docenią wędkarze-samotnicy.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80421, 'Jezioro Jemeliste', 'jezioro-jemeliste', 'LAKE', '54.17439651502022', '22.736251920214713', 'Podlaskie', 'Filipów', 'Jemeliste (często zapisywane jako Jemieliste) to podłużna rynna polodowcowa o powierzchni ok. 35 hektarów, leżąca w gminie Filipów. Charakteryzuje się bardzo czystą, przejrzystą wodą i stromo opadającymi stokami, które na dużych głębokościach tworzą twarde, piaszczysto-żwirowe blaty. To doskonałe, techniczne łowisko dla spinningistów łowiących z opadu – w toni grasują stada dużych okoni oraz sandacze. Zimą pokrywa lodowa przyciąga łowców borykających się z tutejszą, bardzo silną populacją płoci. Otoczenie to surowe wzgórza, typowe dla krajobrazu północnej Suwalszczyzny.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80422, 'Jezioro Jegliniszki', 'jezioro-jegliniszki', 'LAKE', '54.31328056389805', '22.851190803091527', 'Podlaskie', 'Wiżajny', 'Jegliniszki to malowniczy, przygraniczny zbiornik w gminie Wiżajny, o powierzchni blisko 40 hektarów. Region ten, często nazywany "Polskim Biegunem Zimna", charakteryzuje się surowym klimatem, przez co woda w jeziorze nagrzewa się wolno, ale za to obfituje w tlen. Zbiornik jest płytki i mocno zarośnięty, co czyni go wspaniałym tarliskiem i schronieniem dla szczupaków i ogromnych wręcz linów. Latem łowienie z brzegu jest tu niezwykle trudne z powodu gęstego pasa trzcin; do osiągnięcia sukcesu niemal niezbędny jest ponton lub łódka, by obławiać tzw. "oczka" w roślinności.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80423, 'Jezioro Siekierowo (Wiżajny)', 'jezioro-siekierowo-wizajny', 'LAKE', '54.325205626489456', '22.865433351965414', 'Podlaskie', 'Wiżajny', 'Uwaga: To drugi zbiornik o tej samej nazwie na Suwalszczyźnie, zlokalizowany na dalekiej północy przy granicy z Litwą (gmina Wiżajny). Jest to niewielkie (ok. 12 ha), polodowcowe jezioro eworsyjne o owalnym kształcie. Charakteryzuje się stosunkowo dużą głębokością jak na swoje rozmiary oraz bardzo stromymi, wysokimi brzegami, co sprawia, że wygląda jak gigantyczny krater zalany wodą. Dno jest twarde i gliniaste. Złowisz tu przede wszystkim walecznego, żyjącego w chłodnej wodzie okonia oraz wyrośniętą, ostrożną płoć.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80424, 'Jezioro Mauda', 'jezioro-mauda', 'LAKE', '54.327593802057734', '22.793417916569716', 'Podlaskie', 'Wiżajny', 'Mauda (często nazywana też Maudą Wielką) to imponujący, śródpolny akwen o powierzchni około 35 hektarów, leżący rzut beretem od trójstyku granic (Polska-Litwa-Rosja). Jezioro jest rynnowe, dość głębokie, z chłodną i czystą wodą. Brzegi są wybitnie bezleśne, narażone na silne, północne wiatry. Mauda znana jest wśród wędkarskich ekspertów z niesamowicie silnej populacji okonia, który osiąga tu imponujące rozmiary, żerując na stadach uklei i stynki. Spadki dna są tu gwałtowne, dlatego łowienie "z opadu" cięższymi gumami to absolutna podstawa jesienią.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80425, 'Jezioro Ingiel', 'jezioro-ingiel', 'LAKE', '54.364314882568394', '22.802522445195134', 'Podlaskie', 'Rutka-Tartak', 'Jezioro Ingiel to jedno z najdalej wysuniętych na północ polskich jezior, dosłownie ocierające się o granicę z Litwą. To nieduży, dystroficzny i dziki zbiornik otoczony lasami i torfowiskami. Woda ma odcień ciemno-herbaciany. To miejsce skrajnie odcięte od cywilizacji, w którym wędkowanie to przede wszystkim polowanie na puszczańskie szczupaki (często o niezwykle ciemnym, smolistym ubarwieniu) i złote karasie. Ostoja absolutnego spokoju, jednak wymaga ostrożności i orientacji ze względu na bezpośrednią bliskość pasa granicznego.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80426, 'Jezioro Boczne (WJM)', 'jezioro-boczne-wjm', 'LAKE', '53.95798327823257', '21.74662131601515', 'Warmińsko-Mazurskie', 'Rydzewo', 'Wracamy na Szlak Wielkich Jezior Mazurskich! Jezioro Boczne (pow. ok. 183 ha) to ważny, żeglowny łącznik na głównej osi WJM, płynnie przechodzący na północy w jezioro Niegocin (przez Kanał Kula), a na południu w Jagodne. Akwen ten jest stosunkowo płytki (maksymalnie kilkanaście metrów) i silnie uczęszczany przez żeglarzy oraz motorówki. Mimo to, jego rozległe, porośnięte gęstą rdestnicą i moczarką blaty są domem dla wybitnych okazów szczupaka i sandacza. Wędkarze najczęściej przeczesują je trollingując o świcie, zanim na wodzie pojawi się ruch turystyczny. Ujście Kanału Kula to z kolei legendarna miejscówka na wiosennego leszcza i płoć.', 'Gospodarstwo Rybackie PZW Suwałki / Wody Polskie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80427, 'Jezioro Jagodne', 'jezioro-jagodne', 'LAKE', '53.931768771590725', '21.73113173096913', 'Warmińsko-Mazurskie', 'Giżycko', 'Jagodne to potężna (ok. 940 ha) i wydłużona rynna polodowcowa, stanowiąca serce południowej części Szlaku Wielkich Jezior Mazurskich. Z głębokością maksymalną przekraczającą 37 metrów, kryje w sobie potężne stada sielawy i siei. To jezioro słynie ze skrajnie trudnych warunków dla wędkarzy w sezonie letnim z powodu ogromnego ruchu jachtów (szlak Giżycko - Mikołajki). Jednak jesienią, gdy szlak pustoszeje, strome stoki i podwodne rafy (tzw. "górki") stają się areną walk z gigantycznymi szczupakami i sandaczami. Zachodnie, zalesione i zarośnięte trzciną brzegi oferują wspaniałe, ukryte zatoki, gdzie w ciszy można zapolować na kapitalnego lina.', 'Gospodarstwo Rybackie PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80428, 'Jezioro Paproteckie', 'jezioro-paproteckie', 'LAKE', '53.92477870315903', '21.805453723408217', 'Warmińsko-Mazurskie', 'Miłki', 'Jezioro Paproteckie to rozległy, niezależny akwen (ponad 250 ha) położony nieco na wschód od głównego szlaku WJM, niedaleko wsi Paprotki. To fantastyczna alternatywa dla zatłoczonych jezior żeglownych. Posiada bardzo rozwiniętą linię brzegową z zatokami i jedną większą wyspą. Dno jest twarde, kamienisto-żwirowe, a miejscami gliniaste, z licznymi górkami. To woda o charakterze wybitnie sandaczowym – "mętnookie" regularnie uderzają tu w gumy prowadzone ciężkim jigowaniem. Płytsze zatoki to z kolei królestwo dorodnego leszcza, systematycznie nęconego przez okolicznych gospodarzy i wędkarzy stacjonarnych.', 'PZW / Lokalni dzierżawcy');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80429, 'Jezioro Jędzelek', 'jezioro-jedzelek', 'LAKE', '53.89893533081325', '21.719510287375506', 'Warmińsko-Mazurskie', 'Rydzewo', 'Jezioro Jędzelek (czasem nazywane Jędzel) to niewielki, boczny zbiornik wodny położony w pobliżu Rydzewa, stanowiący spokojniejszą odnogę głównego szlaku WJM. Charakteryzuje się bardzo rozwiniętą roślinnością przybrzeżną i mulistym dnem. Ze względu na bliskość głównych szlaków przepływowych, ryby często szukają tu schronienia przed hałasem motorówek. To doskonałe, kameralne łowisko lina, karasia oraz szczupaka czatującego w gęstych trzcinowiskach. Płytka woda szybko się nagrzewa, co czyni je świetnym miejscem na wiosenne zasiadki.', 'PZW Suwałki / Wody Polskie');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80430, 'Jezioro Szymoneckie', 'jezioro-szymoneckie', 'LAKE', '53.904858858057985', '21.688378608909115', 'Warmińsko-Mazurskie', 'Szymonka', 'Jezioro Szymoneckie to rozległa, stosunkowo płytka zatoka jeziora Szymon, stanowiąca ważny punkt na szlaku wodnym Giżycko-Mikołajki. Powierzchnia akwenu jest mocno porośnięta rdestnicą i moczarką, tworząc podwodne łąki idealne dla ryb karpiowatych. Głębokość rzadko przekracza tu 3 metry, a dno jest w większości piaszczysto-muliste. To legendarne łowisko wiosennego leszcza i płoci, a w letnie świty można tu z powodzeniem polować na żerujące przy powierzchni szczupaki i bolenie, które zaganiają stada uklei.', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80431, 'Jezioro Szymon', 'jezioro-szymon', 'LAKE', '53.8883106327485', '21.635081690006757', 'Warmińsko-Mazurskie', 'Mikołajki', 'Jezioro Szymon to serce przepływowego szlaku WJM (ok. 150 ha). Charakteryzuje się podłużnym kształtem i stałym, choć powolnym, ruchem mas wodnych pomiędzy Kanałem Szymońskim a Kanałem Mioduńskim. Ruch statków jest tu ogromny, co wymusza wędkowanie wczesnym rankiem lub jesienią. Akwen słynie z potężnych sandaczy trzymających się twardego koryta w centralnej części jeziora, a także z potężnych, wędrownych leszczy, które przemierzają szlak w poszukiwaniu pokarmu.', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80432, 'Jezioro Tałtowisko', 'jezioro-taltowisko', 'LAKE', '53.87341266926943', '21.56945610222432', 'Warmińsko-Mazurskie', 'Mikołajki', 'Tałtowisko (ok. 320 ha) to głębokie (niemal 40 m) jezioro polodowcowe, wyraźnie oddzielające się charakterem od płytszego Szymona. Woda jest tu znacznie chłodniejsza i bardziej przejrzysta, co klasyfikuje ten akwen jako wybitnie sielawowy. Strome, twarde stoki i rozległe podwodne blaty tworzą idealne środowisko dla toniowego szczupaka, okonia oraz sandacza. Zachodnie brzegi są wysokie i częściowo zalesione, zapewniając osłonę przed wiatrem i wspaniałe miejsca do kotwiczenia dla spinningistów.', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80433, 'Jezioro Ławki', 'jezioro-lawki', 'LAKE', '53.91013399959917', '21.577598816453055', 'Warmińsko-Mazurskie', 'Ryn', 'Jezioro Ławki to średniej wielkości zbiornik leżący nieco na północ od głównego zgiełku szlaku WJM. Oferuje ucieczkę od hałasu motorówek. Jezioro posiada urozmaiconą linię brzegową z zatokami i półwyspami. Jego dno jest pofałdowane, z licznymi podwodnymi łąkami. Jest to bardzo cenione łowisko szczupakowo-linowe, gdzie wędkarze cenią sobie spokój i możliwość obławiania dzikich, porośniętych liliami wodnymi zatoczek.', 'PZW Suwałki / Lokalny dzierżawca');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80434, 'Jezioro Ryńskie', 'jezioro-rynskie', 'LAKE', '53.9104864702587', '21.498771493398745', 'Warmińsko-Mazurskie', 'Ryn', 'Jezioro Ryńskie (ok. 670 ha) to północna część potężnej, niemal 20-kilometrowej rynny ciągnącej się aż do Mikołajek. Akwen ten, z majestatycznym Zamkiem w Rynie na północnym krańcu, charakteryzuje się niezwykłą głębokością (ponad 50 m) i licznymi wyspami (m.in. Ptasia Wyspa). Woda jest zimna i czysta, obfitująca w sielawę i stynkę. Dla wędkarzy to jedno z najbardziej wymagających jezior w Polsce – dom gigantycznych szczupaków pelagicznych i siei. Kluczem do sukcesu jest tu znajomość batymetrii i trolling na dużych głębokościach.', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80435, 'Jezioro Tałty', 'jezioro-talty', 'LAKE', '53.85740885182439', '21.539279103951415', 'Warmińsko-Mazurskie', 'Mikołajki', 'Jezioro Tałty (ponad 1800 ha) to bezpośrednie przedłużenie Jeziora Ryńskiego i jedna z najdłuższych rynien w Polsce, sięgająca samych Mikołajek. Akwen jest głęboki, o stromych, piaszczysto-żwirowych stokach i krystalicznej wodzie w głębszych partiach. Ruch turystyczny jest tu ekstremalnie wysoki, dlatego wędkarze skupiają się tu głównie na jesiennych łowach. Tałty słyną z "garbatych" okoni patrolujących podwodne rafy na 10-15 metrach oraz pięknych sandaczy. Zimowe wędkowanie podlodowe przynosi tu często spektakularne okazy siei.', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80436, 'Jezioro Jorzec', 'jezioro-jorzec', 'LAKE', '53.8367709559762', '21.510753442211676', 'Warmińsko-Mazurskie', 'Mikołajki', 'Jezioro Jorzec (ok. 41 ha) to rynnowy, głęboki zbiornik połączony strugą z Jeziorem Tałty. Dzięki znacznej głębokości (ok. 30 m) i wąskiej, chroniącej od wiatru dolinie, posiada stratyfikację termiczną charakterystyczną dla jezior sielawowych. Czysta woda sprzyja łowieniu z opadu. Dno gwałtownie opada tuż od brzegu, co pozwala na połów drapieżników nawet bez użycia łodzi, rzucając prosto z leśnych skarp.', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80437, 'Jezioro Zelwążek', 'jezioro-zelwazek', 'LAKE', '53.820880249259694', '21.513506794685608', 'Warmińsko-Mazurskie', 'Zełwągi', 'Zelwążek to zaledwie 12-hektarowe, wydłużone jezioro przepływowe, przez które woda wędruje z jeziora Inulec do Tałt. Akwen bardzo zaciszny, o silnie zarośniętych brzegach, stanowiący naturalną ostoję ryb karpiowatych. Z uwagi na stały przepływ i bogatą roślinność, jest to znakomite łowisko lina, płoci oraz szczupaka. Wiosną woda w tym płytkim zbiorniku nagrzewa się błyskawicznie, prowokując ryby do intensywnego żerowania.', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80438, 'Jezioro Głębokie (k. Mikołajek)', 'jezioro-glebokie-mikolajki', 'LAKE', '53.81081550341326', '21.50464646353329', 'Warmińsko-Mazurskie', 'Zełwągi', 'Jak nazwa wskazuje, jezioro Głębokie to eworsyjna misa o imponującej głębokości (ponad 30 m) na zaledwie 47 hektarach powierzchni. Strome spadki dna, niemal pionowe ściany i krystaliczna woda to cechy tego sielawowego akwenu. Znajduje się tu strefa ciszy, a wędkowanie z łodzi wymaga namierzenia ławic drobnicy w toni. To woda dla koneserów szukających okazów okonia i szczupaka pelagicznego z użyciem nowoczesnych echosond.', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80439, 'Jezioro Inulec', 'jezioro-inulec', 'LAKE', '53.80547302606595', '21.480881094602722', 'Warmińsko-Mazurskie', 'Zełwągi', 'Inulec to duże, malownicze jezioro o powierzchni blisko 180 hektarów. Jego linia brzegowa jest wybitnie rozwinięta, z licznymi półwyspami, wyspami i zacisznymi zatokami. Dno jest tu mocno zróżnicowane – od płytkich, piaszczystych blatów, po głębokie na ponad 10 metrów rynny. Akwen ten uchodzi za jedno z najrybniejszych jezior szczupakowo-leszczowych w okolicy Mikołajek. Szerokie pasy grążeli to idealne stanowiska do łowienia linów, a twarde spadki wokół wysp to bankowe miejsca na sandacza.', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80440, 'Jezioro Płociczne', 'jezioro-plociczne', 'LAKE', '53.79868529215665', '21.50040098163501', 'Warmińsko-Mazurskie', 'Mikołajki', 'Jezioro Płociczne to zaciszny, urokliwy akwen wkomponowany w Lasy Mazurskie (pow. ok. 17 ha). Zbiornik o charakterze linowo-szczupakowym, ze stosunkowo czystą wodą i miękkim dnem w zatokach. Otoczony starodrzewem, jest doskonale chroniony przed wiatrem. To idealne miejsce na wyciszenie z batem w dłoni w poszukiwaniu złotej wzdręgi i pięknego lina w ciepłe letnie poranki.', 'Gospodarstwo Rybackie Mikołajki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80441, 'Jezioro Majcz Wielki', 'jezioro-majcz-wielki', 'LAKE', '53.77890573172723', '21.45445543030023', 'Warmińsko-Mazurskie', 'Piecki', 'Majcz Wielki to prawdziwa perła rezerwatu przyrody, akwen o powierzchni około 160 hektarów, objęty rygorystycznymi przepisami ochronnymi. Woda w jeziorze jest szafirowo czysta (I klasa), a widoczność sięga kilku metrów. Dno obfituje w głazowiska i strome, żwirowe stoki. To elitarne łowisko sielawowe. Wędkarze mogą tu (przy zachowaniu regulaminu) zmierzyć się z legendarnymi, wielkimi szczupakami i starymi, przebiegłymi okoniami. Panuje tu bezwzględna strefa ciszy, a przyroda wynagradza każdą minutę spędzoną na tej krystalicznej wodzie.', 'Wody Polskie / Rezerwat Przyrody');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80442, 'Jezioro Majcz Mały', 'jezioro-majcz-maly', 'LAKE', '53.76823926776212', '21.437953899306226', 'Warmińsko-Mazurskie', 'Piecki', 'Majcz Mały to bezpośredni sąsiad Majcza Wielkiego, silnie wypłycający się zbiornik o bagnistych brzegach. Ma charakter zanikającego jeziora leśnego, w dużej mierze pokrytego pływającymi pęcherznicami i mszarami. To niedostępna dla wędkarzy lądowych ostoja lina i piskorza, stanowiąca ważne zaplecze lęgowe dla ptactwa wodnego w obrębie Mazurskiego Parku Krajobrazowego.', 'Wody Polskie / Rezerwat Przyrody');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80443, 'Jezioro Kołowinek', 'jezioro-kolowinek', 'LAKE', '53.737750702825366', '21.42689908164103', 'Warmińsko-Mazurskie', 'Piecki', 'Kołowinek to urocze, maleńkie oczko leśne ukryte w głuszy Puszczy Piskiej, stanowiące system wodny połączony z rzeką Krutynią. Jest to płytki, silnie zarośnięty zbiornik linowo-karasiowy. Woda ma tu herbaciany kolor, a dno jest grubo wysłane warstwą opadłych liści i torfu. Miejsce to rzadko widuje wędkarzy i oferuje stuprocentową dzicz.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80444, 'Jezioro Kołowin', 'jezioro-kolowin', 'LAKE', '53.73167340234072', '21.404331152898738', 'Warmińsko-Mazurskie', 'Piecki', 'Jezioro Kołowin to większy (ok. 75 ha) brat Kołowinka. Akwen ma kształt wydłużonej misy i wyraźnie leśny charakter. Woda jest czystsza, a dno w wielu miejscach twardsze. Posiada świetne warunki do rozwoju szczupaka i okonia. Z uwagi na zalesione brzegi opadające bezpośrednio do lustra wody, połów z brzegu jest trudny, co wymusza korzystanie ze środków pływających i zapewnia mniejszą presję wędkarską.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80445, 'Jezioro Krutyńskie', 'jezioro-krutynskie', 'LAKE', '53.70493641173641', '21.430707563391234', 'Warmińsko-Mazurskie', 'Krutynia', 'Jezioro Krutyńskie to rezerwat przyrody (część Mazurskiego Parku Krajobrazowego), z którego wypływa jeden z najpiękniejszych szlaków kajakowych w Europie – rzeka Krutynia. Jezioro zachwyca krystaliczną wodą i dnem pokrytym dywanami rdestnic i ramienic, pośród których przepływają stada wielkich płoci, wzdręg i kleni. Ochrona rezerwatowa wyklucza swobodne wędkowanie w wielu strefach, czyniąc ten akwen przede wszystkim atrakcją wizualną i przyrodniczą. W nielicznych miejscach dozwolonych, wędkarze cenią je za niezwykle waleczne, żyjące w silnym przepływie ryby.', 'Rezerwat Przyrody Krutynia');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80446, 'Jezioro Głęboczek (k. Mlewa)', 'jezioro-gleboczek-mlewo', 'LAKE', 53.194144, 18.771601, 'Kujawsko-Pomorskie', 'Kowalewo Pomorskie', 'Głęboczek to niewielkie, rynnowe jezioro o stosunkowo stromych brzegach. Woda posiada przyzwoitą przejrzystość. Dominują tu okonie i szczupaki polujące wzdłuż wąskiego pasa trzcinowisk. Ze względu na ustronne położenie, presja wędkarska jest tu umiarkowana.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80447, 'Jezioro Klimunt', 'jezioro-klimunt', 'LAKE', '53.706333791119896', '21.447851860765603', 'Warmińsko-Mazurskie', 'Krutynia', 'Klimunt to niewielki, kilkunastohektarowy zbiornik położony tuż obok jeziora Krutyńskiego. To typowe leśne jeziorko eutroficzne z gęstym pierścieniem szuwarów i grążeli. Dno jest wybitnie muliste. Łowisko to dedykowane jest wędkarzom szukającym lina i szczupaka czatującego w roślinności. Dzięki swojemu odosobnieniu, uchodzi za bardzo spokojne i ciche.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80448, 'Jezioro Duś', 'jezioro-dus', 'LAKE', '53.65839169066467', '21.46278287514351', 'Warmińsko-Mazurskie', 'Wojnowo', 'Jezioro Duś (ok. 45 ha) to piękny zbiornik leżący przy zabytkowym Klasztorze Staroobrzędowców w Wojnowie, połączony krótkim kanałem z rzeką Krutynią. Jego brzegi są częściowo bezleśne i rolnicze, co zwiększa użyźnienie wód. Jezioro słynie ze świetnych brań dorodnego leszcza, potężnych linów oraz szczupaków. Ze względu na płaski charakter dna z niewielkimi spadkami, kluczem do sukcesu jest nęcenie kierunkowe i znalezienie twardszych pasów żwiru pośród mułu.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80449, 'Jezioro Skarp', 'jezioro-skarp', 'LAKE', '53.637172126404344', '21.458712445379124', 'Warmińsko-Mazurskie', 'Wojnowo', 'Skarp to płytkie (ok. 25 ha), przepływowe jezioro w dolnym biegu rzeki Krutyni. Jest mocno porośnięte roślinnością, a w wielu miejscach przypomina raczej szerokie rozlewisko rzeczne niż typowe jezioro. Nurt rzeki rzeźbi tu ciekawe rynienki i dołki w mulistym dnie. To znakomite łowisko rzecznych gatunków: klenia, jazia, a także dorodnej płoci i szczupaka "trzciniaka". Akwen wymaga cichego podejścia, gdyż ryby ze względu na płytką wodę są bardzo płochliwe.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80450, 'Jezioro Wierzbowskie', 'jezioro-wierzbowskie', 'LAKE', '53.8273856033256', '21.326422255357908', 'Warmińsko-Mazurskie', 'Mrągowo', 'Jezioro Wierzbowskie (ok. 130 ha) to podłużna, piękna rynna polodowcowa leżąca tuż przy południowych granicach Mrągowa. Akwen charakteryzuje się dość głęboką wodą (do 25 m), twardym, kamienisto-żwirowym dnem i wysokimi brzegami. To jezioro obfitujące w drapieżniki – spinningiści regularnie chwalą się tu łowieniem pięknych okoni z opadu oraz dorodnych sandaczy, które upodobały sobie głębokie spadki. Woda jest czysta i świetnie natleniona, a brak intensywnego ruchu motorowodnego czyni je łowiskiem wymarzonym do spokojnego wędkowania z łodzi.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80451, 'Jezioro Sutapie Wielkie', 'jezioro-sutapie-wielkie', 'LAKE', '53.83821482297231', '21.306962574299376', 'Warmińsko-Mazurskie', 'Mrągowo', 'Sutapie Wielkie (ok. 35 ha) to jedno z tzw. "miejskich" jezior Mrągowa, połączone niewielkimi ciekami z systemem Wierzbowskiego i Czosem. Mimo bliskości miasta, zachowało stosunkowo dziki charakter dzięki bagnistym i niedostępnym z wielu stron brzegom. To płytki, silnie eutroficzny zbiornik, który obfituje w białą rybę. Jest doskonałym miejscem do rekreacyjnego łowienia płoci, lina i karasia, choć gęsta roślinność podwodna utrudnia połowy spinningowe w miesiącach letnich.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80452, 'Jezioro Sutapie Małe', 'jezioro-sutapie-male', 'LAKE', '53.84496485001178', '21.312151694395244', 'Warmińsko-Mazurskie', 'Mrągowo', 'Maleńkie (kilka hektarów) oczko leżące bezpośrednio pomiędzy Sutapiem Wielkim a jeziorem Czos. Jest niemal całkowicie porośnięte trzciną, a woda w okresie letnim często ulega zakwitom. Z wędkarskiego punktu widzenia to zbiornik trudny technicznie, ale kryjący w swoich mulistych toniach potężne, stare karasie i liny, które nikt nie niepokoi z racji trudnego dostępu do lustra wody.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80453, 'Jezioro Czos', 'jezioro-czos', 'LAKE', '53.85191901838981', '21.318347061101452', 'Warmińsko-Mazurskie', 'Mrągowo', 'Jezioro Czos to serce i wizytówka Mrągowa (pow. ok. 280 ha), doskonale znane z amfiteatru wkomponowanego w jego zachodni brzeg. Mimo miejskiego charakteru, Czos to głęboka (do 42 m) rynna polodowcowa w kształcie rogala, o zaskakująco urozmaiconym dnie, pełnym uskoków i podwodnych półek. Ze względu na głębokość, zaliczane jest do jezior sielawowych. To wędkarskie wyzwanie – w dzień tętni tu życie turystyczne, jednak nocą i świtem akwen oddaje piękne okazy okonia, sandacza i szczupaka toniowego. Na płytszych blatach od strony północnej po odpowiednim zanęceniu wędkarze łowią okazałe leszcze.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80454, 'Jezioro Dobrynek', 'jezioro-dobrynek', 'LAKE', '53.85273476164141', '21.34801294368657', 'Warmińsko-Mazurskie', 'Mrągowo', 'Dobrynek to peryferyjne, zaciszne jezioro leżące na wschód od Mrągowa, pełniące funkcję lokalnego łowiska rekreacyjnego. Jego powierzchnia wynosi kilkanaście hektarów, a głębokość jest umiarkowana. Dno piaszczysto-muliste i dostępność wielu drewnianych pomostów sprawiają, że to świetna alternatywa dla dużego Czosu, gdy mocno wieje. Łowisko bogate w płoć, wzdręgę, a wśród drapieżników króluje klasyczny "szczupak z zielska".', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80455, 'Jezioro Probarskie', 'jezioro-probarskie', 'LAKE', '53.82071068724631', '21.377176367994068', 'Warmińsko-Mazurskie', 'Mrągowo', 'Jezioro Probarskie to imponujący, ponad 200-hektarowy akwen leżący zaledwie kilka kilometrów na południowy wschód od Mrągowa. Zbiornik charakteryzuje się niezwykłą wręcz głębokością, dochodzącą do 31 metrów, oraz krystalicznie czystą wodą (często klasyfikowaną w I klasie czystości). Jego brzegi są wysokie, strome i w dużej mierze porośnięte starymi lasami, co nadaje mu wręcz "górski" charakter. Dno obfituje w strome spady, twarde, kamienisto-żwirowe półki i głęboczki. Jest to wybitne jezioro sielawowe. Wędkarsko Probarskie to królestwo wielkich, toniowych szczupaków oraz potężnych okoni. Przezroczystość wody zmusza wędkarzy do łowienia z dużego dystansu i stosowania długich przyponów z fluorocarbonu. Płytsze zatoki wiosną oddają piękne liny i grube płocie.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80456, 'Jezioro Kuc', 'jezioro-kuc', 'LAKE', '53.8207106871468', '21.404970946055798', 'Warmińsko-Mazurskie', 'Mrągowo', 'Kuc to bezpośredni sąsiad jeziora Probarskiego, z którym jest zresztą połączony drobnym ciekiem. Zajmujący niespełna 100 hektarów zbiornik powiela najlepsze cechy swojego większego brata – jest głęboki (ok. 28 m), a jego wody są bardzo przejrzyste i chłodne. Charakteryzuje się jednak spokojniejszą linią brzegową i mniejszą presją turystyczną. Strome, twarde stoki opadające niemal od samego brzegu to idealne miejsca dla spinningistów łowiących "z opadu" na ciężkie jigi. Tutejsze okonie, wybarwione na ciemnozielono z krwistoczerwonymi płetwami, to trofea, dla których zjeżdżają tu łowcy z całej Polski.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80457, 'Jezioro Juksty', 'jezioro-juksty', 'LAKE', '53.85094172293004', '21.37455061012403', 'Warmińsko-Mazurskie', 'Mrągowo', 'Juksty to wielka (ponad 300 hektarów) rynna ciągnąca się na wschód od Mrągowa, o niezwykle urozmaiconej i rozwiniętej linii brzegowej z licznymi półwyspami i zatokami. Maksymalna głębokość zbliża się tu do 39 metrów! Akwen posiada wyraźną stratyfikację termiczną, kryjąc w chłodnych głębinach stada sielawy. Dno jeziora to prawdziwy rollercoaster – piaszczyste blaty gwałtownie przechodzą w pionowe ściany i kamieniste rafy. To jeden z najlepszych sandaczowo-szczupakowych zbiorników w powiecie mrągowskim. Wschodnie, zalesione brzegi oferują wspaniałe, dzikie miejsca biwakowe, a same Juksty wymagają pływadła i dobrej echosondy, by w pełni wykorzystać ich potencjał.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80458, 'Jezioro Sarż', 'jezioro-sarz', 'LAKE', '53.84601804521137', '21.204038198988176', 'Warmińsko-Mazurskie', 'Sorquity', 'Jezioro Sarż to nieduży (ok. 50 ha), podłużny zbiornik rynnowy leżący nieco na zachód od głównego pojezierza mrągowskiego. Przepływa przez nie urokliwa rzeka Babant. Akwen ten, otoczony łąkami i kępami lasu, jest spokojny i rzadko odwiedzany przez wędkarzy z zewnątrz. Dzięki stałemu przepływowi i urozmaiconemu dnu, rybostan jest tu zdrowy i zróżnicowany. Wędkarze spławikowi i gruntowi celują tu w piękne leszcze i płocie, podczas gdy wczesnym rankiem na płyciznach wzdłuż brzegów można liczyć na agresywne ataki szczupaków.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80459, 'Jezioro Kociołek', 'jezioro-kociolek-mragowo', 'LAKE', '53.86457295450461', '21.25979776411849', 'Warmińsko-Mazurskie', 'Mrągowo', 'Zgodnie z nazwą, Kociołek to miniaturowe oczko wodne o owalnym kształcie, przypominające zatopiony kocioł polodowcowy. Znajduje się na północny zachód od Mrągowa. Jezioro jest dość głębokie jak na swoje rozmiary (ok. 10 ha) i otoczone pasem gęstych trzcin oraz drzew. Z uwagi na trudny dostęp z lądu i muliste partie brzegowe, zachowało niezwykle dziki charakter. To dom dla ostrożnego, starego lina oraz karasia złocistego. Idealne miejsce dla łowców kochających wędkarstwo podchodowe z użyciem pojedynczego "bata".', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80460, 'Jezioro Juno', 'jezioro-juno', 'LAKE', '53.903393359362035', '21.294283298274387', 'Warmińsko-Mazurskie', 'Mrągowo', 'Juno to potężna, długa na prawie 7 kilometrów rynna rzeczna o powierzchni około 380 hektarów, ciągnąca się na północ od Mrągowa. Przez jezioro płynie rzeka Dajna, tworząc popularny szlak kajakowy. Akwen jest bardzo głęboki (do 33 metrów), o stromych, piaszczysto-żwirowych stokach. Woda jest czysta i doskonale natleniona. Juno uchodzi za jedno z najważniejszych łowisk sandaczowych na Mazurach. Nocą mętnoocy drapieżnicy wychodzą na płytsze blaty przybrzeżne, a za dnia trzymają się koryta na głębokości 8-15 metrów. W północnej, płytszej części (tzw. Juno Małe) wędkarze z sukcesami nęcą wielkie leszcze.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80461, 'Jezioro Kot', 'jezioro-kot', 'LAKE', '53.907013940594666', '21.30412581457467', 'Warmińsko-Mazurskie', 'Kiersztanowo', 'Jezioro Kot to malutki sąsiad potężnego Juno, z którym często dzieli losy wędkarskich eskapad jako "opcja zapasowa" podczas bardzo silnych wiatrów. To kilkohektarowe oczko, silnie zarośnięte grążelami i grzybieniem białym, z bardzo miękkim, mulistym dnem. Pełni funkcję cichego tarliska dla ryb karpiowatych. Spławikowcy zaglądają tu z lekkim sprzętem, licząc na dynamiczne holowania wzdręg, pięknych linów, a od czasu do czasu – potężnego szczupaka, który urządza tu rzeź w stadach narybku.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80462, 'Jezioro Kiersztanowskie', 'jezioro-kiersztanowskie', 'LAKE', '53.94704595150438', '21.240654208564287', 'Warmińsko-Mazurskie', 'Kiersztanowo', 'Jezioro Kiersztanowskie (ok. 150 ha) to kolejny element rynny na szlaku rzeki Dajny, leżący na północ od jeziora Juno. Akwen wąski, ale bardzo głęboki (ok. 30 m), wcięty w zalesione z obu stron wzgórza. Dno charakteryzuje się nagłymi skokami głębokości i twardym, żwirowym podłożem. Prąd rzeki sprawia, że woda rzadko bywa tu mętna. To bardzo wymagające, ale i nagradzające łowisko spinningowe – słynie z dużego okonia, sandacza oraz wybitnie silnego szczupaka rzeczno-jeziornego. Długie brzegi stanowią doskonałą osłonę przed wiatrem.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80463, 'Jezioro Salęt', 'jezioro-salet', 'LAKE', '53.91933202052006', '21.341979051268545', 'Warmińsko-Mazurskie', 'Szestno', 'Salęt (lub Salęt Wielki) to rozległy, około 340-hektarowy zbiornik leżący na północny wschód od Mrągowa. W odróżnieniu od sąsiednich, wąskich rynien, Salęt to szeroka i bardzo urozmaicona misa polodowcowa, naszpikowana wieloma wyspami (m.in. Wyspa Rębowo) i głębokimi zatokami. Dno akwenu jest mocno zróżnicowane – od płytkich piaszczystych plaż, po muliste rowy do 14 metrów głębokości. To wyśmienite łowisko szczupakowe i leszczowe. Obecność wysp tworzy doskonałe "korytarze", w których drapieżniki czatują na przemieszczającą się błękitną drobnice. Północne, łagodnie opadające brzegi to z kolei raj dla grunciarzy.', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80464, 'Jezioro Salęt Mały', 'jezioro-salet-maly', 'LAKE', '53.93563531932613', '21.32391547394046', 'Warmińsko-Mazurskie', 'Szestno', 'Salęt Mały to wąska, płytka i bardzo silnie porośnięta rdestnicą odnoga jeziora Salęt, uchodząca do niego krótkim strumieniem. Ze względu na gęstą roślinność podwodną i wynurzoną (trzcinowiska), w okresie letnim łowienie spinningowe jest tu mocno utrudnione. Akwen ten jest za to naturalną, gigantyczną wylęgarnią białorybu, do której regularnie zapuszczają się dorodne okazy linów, karasi oraz "pajków" (szczupaków z zielska).', 'Gospodarstwo Rybackie Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80465, 'Jezioro Ruskowiejskie', 'jezioro-ruskowiejskie', 'LAKE', '53.95142001957932', '21.314264920193246', 'Warmińsko-Mazurskie', 'Ruska Wieś', 'Ruskowiejskie to zaciszne, ukryte za wałem wzgórz morenowych nieduże (ok. 20 ha) jezioro typu linowo-szczupakowego. Woda latem szybko się tu nagrzewa, co sprzyja rozwojowi litoralu (roślinności przybrzeżnej). Dno jest w większości piaszczysto-muliste. Wędkarze cenią ten zbiornik za ciszę i możliwość wędkowania z małych łódek lub brzegowych luków. To pewne miejsce na solidną płoć, krąpia i linową zasiadkę o świcie.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80466, 'Jezioro Rydwągi', 'jezioro-rydwagi', 'LAKE', '53.95938698795147', '21.299260293293894', 'Warmińsko-Mazurskie', 'Rydwągi', 'Rydwągi to nieduży akwen (ok. 15 ha), który powoli, naturalnie zarasta, wchodząc w fazę lądowacenia. Niemal w całości otoczony jest grubym pasem trzcin. Brzegi są miejscami bagniste i trudno dostępne. To ekstremalne środowisko zapewnia schronienie wspaniale ubarwionym, "złotym" wzdręgom oraz ukrywającym się wśród grążeli szczupakom. Czysta kwintesencja "dzikiej wody", gdzie sukces wymaga wodera, pontonu i ogromnej cierpliwości w uwalnianiu zestawów z zaczepów.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80467, 'Jezioro Legińskie', 'jezioro-leginskie', 'LAKE', '53.97802996330396', '21.133630956204847', 'Warmińsko-Mazurskie', 'Leginy', 'Jezioro Legińskie (ok. 220 ha) to gigantyczna i niesamowicie głęboka rynna polodowcowa, leżąca w połowie drogi między Reszlem a Biskupcem. Jej głębokość maksymalna wynosi aż 37 metrów. Legińskie posiada wyjątkowo czystą i chłodną wodę, przez co zaliczane jest do jezior sielawowych o pierwszej klasie czystości. To łowisko dla profesjonalistów – dno jest twarde, kamienisto-żwirowe, pocięte uskokami. Zimą to legendarna arena wędkarstwa podlodowego, latem z kolei mekka trollingowców szukających wielkich szczupaków w toni oraz łowców grubych, pasiastych okoni na ciężkie "koguty". Wzdłuż wschodniego brzegu ulokowane są malownicze ośrodki wypoczynkowe (np. Łężany).', 'Gospodarstwo Rybackie Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80468, 'Jezioro Widryńskie', 'jezioro-widrynskie', 'LAKE', '53.98289567788132', '21.166657497900612', 'Warmińsko-Mazurskie', 'Widryny', 'Widryńskie (ponad 120 ha) to sąsiad Legińskiego, o zauważalnie innym charakterze. Jest znacznie płytsze (do ok. 8-10 m) i szerokie, co przekłada się na szybkie nagrzewanie wody i obfitość flory podwodnej. Wędkarsko to typowe jezioro szczupakowo-leszczowe. Otwarta przestrzeń akwenu naraża go na podmuchy wiatrów, które z kolei doskonale natleniają wodę latem. Świetne miejsce do obławiania rozległych podwodnych łąk dużymi obrotówkami i płytko schodzącymi woblerami, w poszukiwaniu intensywnie żerujących drapieżników.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80469, 'Jezioro Pasterzewo', 'jezioro-pasterzewo', 'LAKE', '53.98946888476943', '21.182537377973325', 'Warmińsko-Mazurskie', 'Pasterzewo', 'Jezioro Pasterzewo to niewielka, ok. 50-hektarowa niecka o łagodnych spadkach dna i dużej powierzchni litoralu. Zlokalizowane w rolniczym krajobrazie między Świętą Lipką a Reszlem. Płytkie i zamulone zatoki stanowią wspaniałe tarliska lina, karasia, a obfitość małych ryb wabi tu stada dużych, choć ostrożnych okoni. Brzegi są wybitnie dostępne dla wędkarzy lądowych, przez co jezioro cieszy się sporą popularnością wśród grunciarzy rozbijających obozowiska w letnie weekendy.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80470, 'Jezioro Dejnowa', 'jezioro-dejnowa', 'LAKE', '54.001731719393355', '21.2243904711784', 'Warmińsko-Mazurskie', 'Święta Lipka', 'Jezioro Dejnowa to absolutny hit tego regionu. Jest to długa na ponad 5 kilometrów, głęboka (do 33 m) i wąska rynna o powierzchni ok. 125 hektarów. Akwen leży u stóp słynnego Sanktuarium w Świętej Lipce. Przez jezioro przepływa rzeka Dajna. Ze względu na zjawiskową przejrzystość wody, urozmaicone dno i otaczające je niemal zewsząd wysokie, strome wzgórza leśne, Dejnowa przypomina wodny kanion. To fantastyczne jezioro sielawowo-sandaczowe. Tutejsze mętnoocy drapieżnicy łowieni z opadu na twardych, gliniastych skarpach to prawdziwe okazy. Niezbędna jest łódź, gdyż brzegi są wybitnie strome i zalesione.', 'PZW Olsztyn / GR Mrągowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80471, 'Staw Pilecki (Zalew Pilec)', 'staw-pilecki', 'LAKE', '53.982214115586196', '21.233612550270365', 'Warmińsko-Mazurskie', 'Pilec', 'Staw Pilecki to malowniczy, zaporowy zbiornik na rzece Dajnie, zlokalizowany w urokliwej wsi Pilec. Został utworzony w związku z funkcjonowaniem tutejszego dawnego młyna. Akwen ten, o powierzchni ok. 25 ha, ma mocno wydłużony kształt i specyficzny, przepływowy charakter. Dno jest wybitnie zróżnicowane – dawne koryto rzeczne meandruje wśród zalanych, płytkich łąk porośniętych liliami wodnymi. To łowisko pełne niespodzianek; można tu złowić rzeczne gatunki: grubego klenia czy jazia, ale dominują drapieżniki "z zielska": szczupak i okoń, czatujące na skraju nurtu i spokojnej wody.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80472, 'Jezioro Kławój', 'jezioro-klawoj', 'LAKE', '54.00762851786924', '21.14039625691501', 'Warmińsko-Mazurskie', 'Reszel', 'Kławój to ciche, urokliwe oczko polodowcowe ukryte w polno-leśnym krajobrazie niedaleko Reszla. Powierzchnia kilkunastu hektarów i w miarę równe, piaszczysto-muliste dno czynią z niego przyjazne łowisko typu szczupakowo-płociowego. Woda nagrzewa się dość szybko, prowokując wiosenny, masowy wylęg owadów, który przyciąga stada białorybu. Zbiornik jest bardzo zaciszny, oddalony od głównych dróg, a otaczające go kępy starodrzewu nadają każdej zasiadce wędkarskiej niepowtarzalnego, mazurskiego klimatu.', 'PZW Olsztyn');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80473, 'Jezioro Ustrych', 'jezioro-ustrych', 'LAKE', 53.635125, 20.496969, 'Warmińsko-Mazurskie', 'Ruś / Olsztyn', 'Ustrych to prawdziwa perełka schowana w cieniu starych lasów Rezerwatu Las Warmiński. Jest to jezioro niewielkie, ale uderzająco malownicze, wyrzeźbione w rynnie rzeki Łyny, która wpada do niego i z niego wypływa. Ze względu na lokalizację w obszarze ściśle chronionym, akwen ten tchnie mistyczną, puszczańską aurą. Stare sosny często przeglądają się w mrocznej, leśnej wodzie, a liczne powalone pnie tworzą naturalne, nienaruszone środowisko.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80474, 'Jezioro Jełguńskie', 'jezioro-jelgunskie', 'LAKE', 53.65067, 20.52804, 'Warmińsko-Mazurskie', 'Jełguń / Ruś', 'Jezioro Jełguńskie, usytuowane głęboko w Lasach Warmińskich, to ustronny rynnowy zbiornik o powierzchni niespełna 30 hektarów, który swoim kształtem przypomina rogal. Jest to woda typowo śródleśna, do której dostęp jest stosunkowo trudny ze względu na brak asfaltowych dróg dojazdowych, co od lat chroni ją przed najazdem masowej turystyki i wędkarskiej presji.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80475, 'Jezioro Kruklin', 'jezioro-kruklin', 'LAKE', '54.03810237567088', '21.913443259526687', 'Warmińsko-Mazurskie', 'Giżycko', 'Jezioro Kruklin to rozległy, ponad 350-hektarowy akwen leżący na wschód od Giżycka. Jego dno jest niezwykle urozmaicone – znajdziemy tu rozległe, piaszczyste wypłycenia, liczne podwodne górki, głazy oraz wyraźne spadki sięgające 25 metrów. Kruklin słynie w regionie z potężnej populacji szczupaka oraz wspaniałego, "garbatego" okonia, który chętnie patroluje żwirowe blaty. Jezioro bywa kapryśne, ale wietrzne, pochmurne dni często przynoszą tu spektakularne brania. Na północnym brzegu znajduje się rezerwat przyrody, a linia brzegowa zdominowana jest przez gęste szuwary, co wymusza wędkowanie ze środków pływających.', 'Gospodarstwo Rybackie PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80476, 'Jezioro Wydmińskie', 'jezioro-wydminskie', 'LAKE', '54.00977689700461', '22.000502038277293', 'Warmińsko-Mazurskie', 'Wydminy', 'Jezioro Wydmińskie (ponad 330 ha) to prawdziwy labirynt wodny. Posiada jedną z najbardziej rozwiniętych linii brzegowych na Mazurach z kilkoma zalesionymi wyspami i niezliczoną ilością głębokich zatok. Akwen uchodzi za jezioro wybitnie leszczowo-sandaczowe, choć tutejsze, zarośnięte zatoki to klasyczne wylęgarnie wspaniałych linów i szczupaków "z zielska". Z uwagi na ogromną ilość podwodnych górek i zróżnicowane dno (miejscami twarde, w zatokach muliste), namierzenie ryb bez echosondy wymaga doskonałej znajomości wody. Płytsze partie w okolicach miejscowości Wydminy przyciągają wędkarzy spławikowych.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80477, 'Jezioro Żywki', 'jezioro-zywki', 'LAKE', '54.058922705706514', '21.967243202362436', 'Warmińsko-Mazurskie', 'Kruklanki', 'Jezioro Żywki to niewielki, kilkunastohektarowy akwen leżący na uboczu głównych szlaków turystycznych, niedaleko wsi Żywki. Jezioro jest rynnowe, dość płytkie i bardzo żyzne, przez co latem silnie zarasta bujną roślinnością podwodną (rdestnice i wywłóczniki). To typowe łowisko szczupakowo-linowe. Idealne na poranne zasiadki w ciszy – wędkarze cenią tu zwłaszcza duże, złote karasie i liny, które nęci się blisko pasa trzcin grubą frakcją ziaren.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80478, 'Jezioro Babka', 'jezioro-babka', 'LAKE', '54.070520908346005', '21.94898139255271', 'Warmińsko-Mazurskie', 'Kruklanki', 'Babka to kameralne, dzikie oczko polodowcowe zlokalizowane blisko Kruklanek. Zbiornik ten cechuje się stromymi, zadrzewionymi brzegami, co doskonale chroni taflę przed wiatrem i ułatwia precyzyjne operowanie spławikiem. Dno jest wybitnie muliste. Stanowi idealny azyl dla ryb karpiowatych – z naciskiem na pięknie ubarwione płocie i wzdręgi. Latem powierzchnię wody często pokrywają liście nenufarów, wśród których kryją się puszczańskie szczupaki.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80479, 'Jezioro Małe (k. Kruklanek)', 'jezioro-male-kruklanki', 'LAKE', '54.0784958583843', '21.9513556857755', 'Warmińsko-Mazurskie', 'Kruklanki', 'Jezioro Małe to zaledwie kilkuhektarowa, płytka niecka leżąca tuż u południowych brzegów potężnego jeziora Gołdapiwo. Zbiornik ten to typowe jezioro eworsyjne, silnie zamulone i zarastające. Stanowi niemal naturalny rezerwat białorybu i jest często odwiedzane przez lokalnych wędkarzy "od lina". Ze względu na bagienne brzegi dostęp z lądu jest skrajnie utrudniony.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80480, 'Jezioro Patelnia', 'jezioro-patelnia', 'LAKE', '54.0742703607286', '21.9229520712794', 'Warmińsko-Mazurskie', 'Kruklanki', 'Jezioro Patelnia swą nazwę zawdzięcza niemal idealnie okrągłemu kształtowi. To typowy "kociołek" polodowcowy, który mimo małej powierzchni charakteryzuje się nagłymi uskokami dna sięgającymi kilku metrów już tuż przy brzegu. Woda jest tu ciemna, a dno grubo zasłane opadłymi liśćmi drzew otaczających akwen. Łowisko to dedykowane jest wędkarzom szukającym wyciszenia i dużych, starych okoni łowionych na klasycznego, żywego czerwonego robaka.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80481, 'Jezioro Brożówka', 'jezioro-brozowka', 'LAKE', '54.091654721129316', '21.951448430113604', 'Warmińsko-Mazurskie', 'Kruklanki', 'Brożówka to bardzo wąska i mocno wydłużona rynna polodowcowa, ciągnąca się wzdłuż wschodnich brzegów Gołdapiwa. Jest to zbiornik przepływowy, charakteryzujący się wybitnie stromymi stokami i chłodną wodą. Twarde dno i dobra przejrzystość czynią z niego znakomite łowisko okoniowo-szczupakowe. Głębokie partie przyciągają amatorów łowienia "z opadu". Zalesione brzegi opadają tu nierzadko pionowo do wody, co sprawia, że łódź jest tu absolutnie niezbędna.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80482, 'Jezioro Gołdapiwo', 'jezioro-goldapiwo', 'LAKE', '54.11454752719969', '21.94613648439165', 'Warmińsko-Mazurskie', 'Kruklanki', 'Gołdapiwo (blisko 860 ha) to perła tego regionu i jezioro o niezwykłej urodzie oraz wędkarskim potencjale. Akwen ten jest ogromny, bardzo głęboki (niemal 40 m) i objęty strefą ciszy, co sprawia, że na wodzie nie uświadczysz hałasu silników spalinowych. Woda posiada pierwszą klasę czystości, a na północnym wschodzie (wyspa i przyległa zatoka) rozciąga się rezerwat przyrody Borki. Dno jest wybitnie twarde, piaszczysto-kamieniste, z licznymi górkami. To wspaniała arena do łowienia kapitalnych sandaczy, gigantycznych szczupaków (żerujących na wszechobecnej sielawie) i rekordowych okoni. Wymaga znakomitej orientacji nawigacyjnej i odporności na puszczańskie wiatry.', 'Gospodarstwo Rybackie PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80483, 'Jezioro Pozezdrze', 'jezioro-pozezdrze', 'LAKE', '54.1425897448442', '21.88894169188865', 'Warmińsko-Mazurskie', 'Pozezdrze', 'Pozezdrze (ok. 130 ha) to centralny punkt rzecznego szlaku Sapiny. Przez jezioro przetacza się stały nurt, co świetnie natlenia jego wody i zapobiega zimowym przyduchom. Dno jeziora jest miejscami twarde, a miejscami gliniaste, ze świetnie zaznaczonym korytem rzecznym, wokół którego skupia się życie drapieżników. To klasyczne łowisko sandaczowo-leszczowe, doceniane przez spinningistów polujących na mętnookiego drapieżnika za pomocą jaskrawych, żółto-seledynowych gum na pograniczu twardych spadów.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80484, 'Jezioro Piecek', 'jezioro-piecek', 'LAKE', '54.1579937725784', '21.883689086854005', 'Warmińsko-Mazurskie', 'Pozezdrze', 'Piecek to malutkie, niespełna 3-hektarowe oczko wodne przylegające niemal bezpośrednio do jeziora Pozezdrze. Akwen bardzo płytki, mocno porośnięty liliami wodnymi i rzęsą. Ze względu na bliskość większego zbiornika pełni rolę naturalnego tarliska dla ryb z całego systemu. Wędkarze rzadko tu zaglądają, chociaż to pewny punkt na wiosenne wędkowanie ze spławikiem w poszukiwaniu intensywnie żerującej wzdręgi i niewielkiego lina.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80485, 'Jezioro Wilkus', 'jezioro-wilkus', 'LAKE', '54.15183628984809', '21.928746013730912', 'Warmińsko-Mazurskie', 'Pozezdrze', 'Jezioro Wilkus (ok. 85 ha) to podłużny zbiornik rynnowy na szlaku Sapiny, spinający jezioro Pozezdrze z okolicami Kątów Węgorzewskich. Posiada niezwykle czystą, przejrzystą wodę i urozmaicone, piaszczysto-żwirowe dno. To doskonałe, wietrzne łowisko sielawowo-szczupakowe, w którym stada wielkich drapieżników często przebywają w toni. Liczne zatoczki i przewężenia tworzą wspaniałe stanowiska dla wędkarzy gruntowych, celujących w dorodnego, migrującego szlakiem leszcza.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80486, 'Jezioro Smolak', 'jezioro-smolak', 'LAKE', '54.14172305310341', '21.954533199130303', 'Warmińsko-Mazurskie', 'Pozezdrze', 'Smolak to typowe małe jezioro dystroficzne, ukryte w głębi lasu pomiędzy Gołdapiwem a Krzywą Kutą. Woda w jeziorze jest bardzo miękka i mocno zakwaszona, przybierając charakterystyczny kolor mocnej herbaty. Ze względu na te specyficzne warunki chemiczne, rybostan jest uboższy gatunkowo, zdominowany przez karasia złocistego, okonia "z czarnym grzbietem" i niewielkiego szczupaka. Wędkowanie tutaj ma przede wszystkim walor eksploracyjny i kontakt z dziewiczą, surową naturą.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80487, 'Jezioro Biała Kuta', 'jezioro-biala-kuta', 'LAKE', '54.15236055893548', '21.945491426516867', 'Warmińsko-Mazurskie', 'Pozezdrze', 'Biała Kuta to dzikie, śródleśne jezioro polodowcowe o owalnym kształcie, powierzchni ok. 25 ha i wyraźnie płytkiej misie. Otoczone ze wszystkich stron lasami Puszczy Boreckiej, uchodzi za akwen wyjątkowo cichy. Swoją nazwę zawdzięcza stosunkowo jasnemu, piaszczystemu ukształtowaniu płycizn brzegowych. To znakomita "woda" na grubego lina i płociową zasiadkę. Z racji trudno dostępnych brzegów poleca się łowienie z pontonu lub środka pływającego na granicy rzadkich trzcinowisk.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80488, 'Jezioro Krzywa Kuta', 'jezioro-krzywa-kuta', 'LAKE', '54.14995877464958', '21.96577811523507', 'Warmińsko-Mazurskie', 'Pozezdrze', 'Krzywa Kuta (pow. ok. 130 ha) to fascynująca, zakrzywiona rynna jeziorna z dnem usianym licznymi podwodnymi górami i głębokimi rowami osiągającymi blisko 25 metrów. Krystalicznie czysta woda i lasy Puszczy Boreckiej schodzące pionowo do brzegów nadają mu surowy, wręcz skandynawski charakter. Jest to wspaniałe, ale niezwykle trudne łowisko sielawowo-szczupakowe. Wymaga od spinningisty używania najcieńszych fluorocarbonów i doskonałego wyczucia ciężkich jigów na opadających gwałtownie skarpach. Obecność wielkich okoni rekompensuje techniczne trudności łowiska.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80489, 'Jezioro Żabinki', 'jezioro-zabinki', 'LAKE', '54.13270813586682', '21.98120181489723', 'Warmińsko-Mazurskie', 'Kruklanki', 'Jezioro Żabinki (często zwane też Żabinkami) to niemal idealnie czysta perła o powierzchni ok. 40 hektarów, wkomponowana w pofałdowany krajobraz wokół wsi Żabinka. To klasyczny, głęboki zbiornik sielawowy z pięknym, twardym, żwirowym dnem. Akwen słynie z wyjątkowej estetyki – z brzegów zniknęły niemal trzcinowiska, a dno widać nawet na kilku metrach głębokości. Wyborne łowisko na wielkiego szczupaka polującego w pół wód (pelagicznie) oraz dla łowców spławikowych szukających "siełai" (siei) w mroźne, zimowe poranki.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80490, 'Jezioro Zajeziory', 'jezioro-zajeziory', 'LAKE', '54.335171913656104', '22.048517262638576', 'Warmińsko-Mazurskie', 'Banie Mazurskie', 'Zajeziory to mały, dziki zbiornik ukryty w malowniczym, rzadko odwiedzanym przez turystów rejonie Wzgórz Szeskich. Akwen jest mocno porośnięty trzciną i w okresie letnim przypomina zielone rozlewisko. Woda nagrzewa się tu bardzo szybko, co napędza metabolizm tutejszych ryb karpiowatych. Uchodzi za rewelacyjne, pewne łowisko lina i karasia, choć wymaga od wędkarza obfitego i regularnego nęcenia oraz cichego, podchodowego sposobu łowienia.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80491, 'Jezioro Jagielskie', 'jezioro-jagielskie', 'LAKE', '54.32412276731881', '22.0686580360885', 'Warmińsko-Mazurskie', 'Banie Mazurskie', 'Jagielskie (ok. 20 ha) to zagubione wśród wzgórz polodowcowych, urokliwe jeziorko o owalnym kształcie. Charakteryzuje się bardzo spokojną, osłoniętą taflą wody i mulisto-piaszczystym dnem. Wokół jeziora rosną dzikie sady i stare lasy, co nadaje mu niezwykle sielski klimat. To dom wielkich, starych płoci i pięknych szczupaków atakujących drobnicę wśród lilii wodnych. Świetne miejsce do testowania powierzchniowych przynęt spinningowych typu "popper" o wschodzie słońca.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80492, 'Jezioro Czupowskie', 'jezioro-czupowskie', 'LAKE', '54.27971068461076', '22.063664450886687', 'Warmińsko-Mazurskie', 'Banie Mazurskie', 'Czupowskie to klasyczne leśne oczko o powierzchni zaledwie kilku hektarów, schowane w dzikim paśmie Lasów Skaliskich. Zbiornik jest płytki i silnie eutroficzny (częste zakwity alg latem). To tarlisko dla niezliczonych ilości małych żab, które z kolei stanowią przysmak dla tutejszych szczupaków. Ze względu na zalesienie i podmokłe tereny przylegające do linii brzegowej, jest to teren wyłącznie dla wędkarskich traperów kochających trudne warunki i rzuty z tzw. "luk" w krzakach.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80493, 'Jezioro Jagoczany', 'jezioro-jagoczany-2', 'LAKE', '54.29727442168961', '22.132270918757897', 'Warmińsko-Mazurskie', 'Banie Mazurskie', 'Jagoczany to przepiękne, ciche jezioro o powierzchni ok. 15 hektarów, leżące na dalekich krańcach regionu, blisko polsko-rosyjskiej granicy obwodu królewieckiego. Akwen o stosunkowo czystej wodzie i piaszczysto-mulistym dnie, obrośnięty starymi olchami i brzozami. Wędkarze mogą liczyć tu na świetną populację lina, okonia i szczupaka. Odcięcie od cywilizacji i dróg asfaltowych sprawia, że każda wyprawa nad Jagoczany to mała przygoda połączona z biwakiem i słuchaniem wycia wilków z pobliskich puszcz.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80494, 'Jezioro Dręstwo', 'jezioro-drestwo', 'LAKE', '53.70528080080232', '22.728920366798146', 'Podlaskie', 'Bargłów Kościelny', 'Jezioro Dręstwo (pow. ok. 500 ha) to potężny, malowniczy akwen położony w sąsiedztwie Biebrzańskiego Parku Narodowego. Charakteryzuje się w miarę wyrównanym dnem, które w większości jest piaszczyste i piaszczysto-żwirowe, z gwałtowniejszymi spadkami jedynie od strony północnej. Woda jest tu czysta i dobrze natleniona. Dręstwo to klasyczne łowisko leszczowo-szczupakowe. Szerokie pasy trzcin stanowią idealne tarliska, a piaszczyste blaty to miejsca, gdzie wędkarze gruntowi nęcą gigantyczne stada białorybu. Spinningiści z sukcesami obławiają stoki w poszukiwaniu grubego okonia i szczupaka. Jezioro jest bardzo otwarte, przez co często tworzy się na nim duża fala.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80495, 'Jezioro Kroszewo', 'jezioro-kroszewo', 'LAKE', '53.73420953496382', '22.775565349407355', 'Podlaskie', 'Bargłów Kościelny', 'Kroszewo to niewielki, boczny zbiornik o charakterze eworsyjnym, położony w niedalekiej odległości od Dręstwa. To spokojne i ciche łowisko, w dużej mierze otoczone polami uprawnymi i kępami olszyn. Woda nagrzewa się tu znacznie szybciej niż w okolicznych molochach, co sprawia, że Kroszewo budzi się do życia już wczesną wiosną. Dno jest muliste i mocno zarośnięte rogatkiem. To pewna "miejscówka" dla wędkarzy spławikowych polujących na "złote" liny i dorodne karasie, które żerują tuż na skraju gęstych grążeli.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80496, 'Jezioro Rajgrodzkie', 'jezioro-rajgrodzkie', 'LAKE', '53.74538593941666', '22.648971722871895', 'Podlaskie', 'Rajgród', 'Rajgrodzkie to absolutny gigant regionu (ponad 1500 ha) i jedno z najbardziej fascynujących jezior rynnowych w Polsce. Jego głębokość maksymalna przekracza 50 metrów! Składa się z kilku potężnych odnóg (Zatoka Rajgrodzka, Przepiórka, Stackie, Czarnowiejskie). Woda, zasilana licznymi źródłami, jest lodowata i krystalicznie czysta. To królestwo wielkich, toniowych drapieżników – gigantycznych szczupaków pelagicznych, sandaczy i okoni. Z uwagi na ogromne głębokości i występowanie sielawy, łowienie tu wymaga doskonałej znajomości batymetrii i echosondy. Jesienny trolling na 10-15 metrach to najczęstsza metoda poszukiwania "ryby życia".', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80497, 'Jezioro Wrońskie', 'jezioro-wronskie', 'LAKE', 53.305558, 18.887547, 'Kujawsko-Pomorskie', 'Płużnica / Wronie', 'Wrońskie to malowniczy akwen rynnowy położony w sąsiedztwie lasu wronieckiego. Charakteryzuje się piaszczysto-mulistym dnem i głębokością sięgającą 10 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są zróżnicowane, z licznymi stanowiskami wędkarskimi i kładkami.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80498, 'Jezioro Stackie', 'jezioro-stackie', 'LAKE', '53.74997319218752', '22.630752143288714', 'Warmińsko-Mazurskie', 'Rajgród', 'Jezioro Stackie to de facto potężne, wschodnie ramię Jeziora Rajgrodzkiego, często traktowane przez wędkarzy jako osobny akwen ze względu na swoją wielkość i specyfikę. Posiada bardzo strome, zalesione brzegi, które szybko schodzą na głębokość ponad 30 metrów. Dno jest wybitnie twarde, pocięte podwodnymi rowami i najeżone głazami z czasów zlodowacenia. To elitarna woda sandaczowa i okoniowa – drapieżniki doskonale reagują tu na methodę opadową ("jigging") z użyciem jaskrawych, smukłych gum i ciężkich główek. Obszar ten jest rajem dla doświadczonych wędkarzy łodziowych.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80499, 'Jezioro Przepiórka', 'jezioro-przepiorka', 'LAKE', '53.76837369674658', '22.69071039114723', 'Podlaskie', 'Rajgród', 'Przepiórka to kolejna, węższa odnoga systemu Jeziora Rajgrodzkiego. Akwen ten jest niezwykle malowniczy, wcięty głęboko w kompleksy leśne. Oferuje znakomitą osłonę od wiatru w przeciwieństwie do głównego plosa Rajgrodzkiego. Słynie z krystalicznej wody i stromych spadków dna. Wędkarze cenią to miejsce za wspaniałe wyniki w połowach okoni "na boczny trok" oraz dorodnych płoci, które grupują się wzdłuż zwalonych do wody pni sosnowych.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80500, 'Jezioro Krzywe (Rajgrodzkie)', 'jezioro-krzywe-rajgrodzkie', 'LAKE', '53.76151868505083', '22.591448954053273', 'Warmińsko-Mazurskie', 'Stacze', 'Jezioro Krzywe to ukryty w lasach, średniej wielkości zbiornik (ok. 130 ha) sąsiadujący z zachodnimi brzegami jeziora Stackiego. Charakteryzuje się podłużnym kształtem i doskonałą czystością wód (typ sielawowy). Mimo mniejszej presji niż na okolicznych gigantach, akwen ten potrafi obdarzyć rekordowym okazem szczupaka. Zachodnie brzegi są łagodniejsze, porośnięte łąkami podwodnymi, gdzie wiosną z sukcesami łowi się piękne liny i grube leszcze. To jezioro wymagające, uczące cierpliwości i dokładnego obławiania skarp.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80501, 'Jezioro Kuczki', 'jezioro-kuczki', 'LAKE', '53.770856292606005', '22.586870964082664', 'Warmińsko-Mazurskie', 'Stacze', 'Kuczki to małe, urokliwe oczko rynnowe leżące tuż za północnym krańcem jeziora Krzywego. Jest to jezioro ciche, osłonięte od wiatru zaroślami i pagórkami, z relatywnie żyzną wodą i mulistym dnem. Pełni funkcję naturalnej oazy dla lina, karasia oraz drobnego szczupaka potocznie nazywanego "pistoletem". Wymarzone miejsce na rozbicie namiotu z dala od cywilizacji i kontemplację porannej mgły unoszącej się nad taflą, z cichym plumkaniem spławika w tle.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80502, 'Jezioro Białe (k. Rajgrodu)', 'jezioro-biale-rajgrod', 'LAKE', '53.79281909260739', '22.65784862415895', 'Warmińsko-Mazurskie', 'Gąsiorowo', 'Jezioro Białe w gminie Kalinowo to spory akwen (ok. 180 ha), który urzeka niesamowicie jasnym, wręcz białym piaszczystym dnem widocznym w płytkich partiach (stąd nazwa). Jezioro jest głębokie (do ok. 35 m) i posiada krystalicznie czystą wodę sielawową. To fantastyczne, techniczne łowisko. Brak dużej ilości roślinności przybrzeżnej sprawia, że ryby drapieżne trzymają się wyraźnych uskoków dna i głębokich blatów. Kluczem do sukcesu na tutejsze okonie i szczupaki jest łowienie pelagiczne (w toni) i precyzyjne operowanie echosondą.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80503, 'Jezioro Nieciecze', 'jezioro-nieciecze', 'LAKE', '53.81621658311484', '22.627130544756284', 'Warmińsko-Mazurskie', 'Kalinowo', 'Nieciecze to nieduży, wydłużony zbiornik (ok. 25 ha), który powoli, na skutek naturalnej eutrofizacji, zarasta ze wszystkich stron, przybierając charakter starorzecza czy bagiennego rozlewiska. Dno pokrywają grube warstwy mułu, a dostęp z brzegu staje się z roku na rok coraz trudniejszy. To absolutne królestwo twardych walk z linami wyciąganymi spomiędzy gęstych pędów lilii wodnych. Ze względu na niedostępność, łowisko bywa odwiedzane niemal wyłącznie przez zapaleńców uzbrojonych w środki pływające o małym zanurzeniu.', 'PZW Suwałki / GR Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80504, 'Jezioro Skomętno', 'jezioro-skometno', 'LAKE', '53.83962745614283', '22.608367922548172', 'Warmińsko-Mazurskie', 'Skomętno Wielkie', 'Jezioro Skomętno to ponad 200-hektarowa, bardzo głęboka (do 33 m) rynna, wcięta w pofałdowany, rolniczy krajobraz na wschód od Ełku. To akwen, w którym żyją świetnej kondycji drapieżniki, w tym coraz liczniejszy sandacz i wielki szczupak. Zbiornik z racji swojego otwartego ukształtowania bywa bardzo wietrzny, co w lecie fantastycznie natlenia wodę, zapobiegając "przegrzaniu" ryb. Obfitość uklei ściąga pod powierzchnię stada potężnych, żerujących watahami okoni. Wymaga dobrego zwiadu wędkarskiego, by namierzyć podwodne twarde blaty.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80505, 'Jezioro Selmęt Wielki', 'jezioro-selmet-wielki', 'LAKE', '53.822382737688045', '22.489485680592882', 'Warmińsko-Mazurskie', 'Ełk', 'Selmęt Wielki to jeden z największych i najpiękniejszych akwenów Pojezierza Ełckiego, o powierzchni sięgającej niespełna 1300 hektarów. Linia brzegowa jest wybitnie urozmaicona – znajdziemy tu dzikie, puszczańskie zatoki, otwarte plosa z ogromnymi wiatrami oraz malownicze wyspy. Mimo ogromnych rozmiarów, jezioro nie należy do najgłębszych (maks. ok. 22 m), a na dnie znajdziemy niezliczone podwodne "górki" i rozległe piaszczyste wypłycenia. To absolutne, sandaczowe eldorado i mekka dla łowców "mętnookich" łowiących techniką opadową. Latem zarośnięte zatoki dają wspaniałe rezultaty w łowieniu lina i szczupaka.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80506, 'Jezioro Regielskie', 'jezioro-regielskie', 'LAKE', '53.79283017989628', '22.439510695897233', 'Warmińsko-Mazurskie', 'Ełk', 'Jezioro Regielskie (ok. 130 ha) to podłużny akwen graniczący od południowego wschodu z przedmieściami Ełku. Jest stosunkowo płytkie, mocno zarośnięte, o przewadze dna mulistego. Dzięki takiemu charakterowi jest niesamowicie żyzne i stanowi naturalny bufor tarliskowy dla wielu gatunków. To doskonałe, wręcz podręcznikowe łowisko białorybu. Wędkarze spławikowi i miłośnicy drgającej szczytówki systematycznie wyciągają stąd piękne płocie, wzdręgi, liny i krąpie. Bliskość miasta sprawia, że w weekendy bywa tu tłoczno.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80507, 'Jezioro Bajtkowo', 'jezioro-bajtkowo', 'LAKE', '53.74713257624974', '22.253033463733825', 'Warmińsko-Mazurskie', 'Bajtkowo', 'Jezioro Bajtkowo to zaciszna, klasyczna rynna polodowcowa leżąca na południowy zachód od Ełku (pow. ok. 60 ha). Akwen ten zachwyca krystaliczną, przejrzystą wodą i stromymi, gwałtownie opadającymi stokami, często porośniętymi lasem. To idealne warunki dla rozwoju okonia i szczupaka, a w chłodniejszych, głębokich partiach można trafić na okazy sielawy i siei. Piaszczysto-żwirowe dno sprawia, że nie ma tu zbyt wielu zawad, co ułatwia łowienie gruntowe grubych leszczy nocą.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80508, 'Jezioro Karbowskie', 'jezioro-karbowskie', 'LAKE', '53.75677411737481', '22.255842960531204', 'Warmińsko-Mazurskie', 'Bajtkowo', 'Karbowskie to malutkie, niespełna 10-hektarowe, dzikie oczko ukryte w lasach, tuż obok jeziora Bajtkowo. Jest to płytka, torfowa misa, która w okresie wiosenno-letnim w dużej mierze zarasta dywanem nenufarów. To klasyczne jeziorko z cyklu "rzut w oczko": wymaga od wędkarza umiejętnego operowania krótkim wędziskiem i podawania lekkiej przynęty (robak, kukurydza) prosto w luki między roślinami, by sprowokować pięknie ubarwione liny i karasie.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80509, 'Jezioro Łyse', 'jezioro-lyse-pomorskie', 'LAKE', 53.680083, 18.435859, 'Pomorskie', 'Osiek', 'Łyse to niewielki, ustronny zbiornik o charakterze wytopiskowym. Posiada muliste dno i regularną linię brzegową porośniętą rzadką trzciną. To typowa woda "spokojnego żeru", rzadko odwiedzana przez turystów, co zapewnia wędkarzom dużą intymność.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80510, 'Jezioro Tatarskie', 'jezioro-tatarskie', 'LAKE', '53.78188404920739', '22.37493888771702', 'Warmińsko-Mazurskie', 'Nowa Wieś Ełcka', 'Jezioro Tatarskie to kilkunastohektarowy, podmiejski zbiornik, wciśnięty między zabudowania a lokalne drogi w okolicach Nowej Wsi Ełckiej. Akwen ulega procesowi naturalnej eutrofizacji, a jego woda bywa mętna. Z uwagi na dużą dostępność linii brzegowej i liczne dzikie pomosty, jest to bardzo popularne "łowisko po pracy" dla mieszkańców Ełku. Nęcone niemal non stop dno przyciąga duże stada płoci i leszcza. Dla spinningistów zostaje łowienie mniejszych szczupaków na skraju wąskiego pasa trzcin.', 'PZW Suwałki / GR Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80511, 'Jezioro Szarek', 'jezioro-szarek', 'LAKE', '53.80466054398249', '22.31055359082483', 'Warmińsko-Mazurskie', 'Ełk', 'Szarek (ok. 130 ha) to popularne jezioro leżące na zachód od Ełku, będące zapleczem rekreacyjnym i wędkarskim miasta. Zbiornik jest dość głęboki (ponad 16 m), o wybitnie zróżnicowanym dnie, pełnym podwodnych uskoków i blatów. Woda jest czysta, a rybostan dobrze utrzymany dzięki regularnym zarybieniom. To woda o charakterze sandaczowo-szczupakowym. Świetne wyniki daje nocne łowienie węgorzy i leszczy na piaszczystych stokach południowego brzegu.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80512, 'Jezioro Ełckie', 'jezioro-elckie', 'LAKE', '53.811152534089366', '22.34706572782877', 'Warmińsko-Mazurskie', 'Ełk', 'Jezioro Ełckie to spektakularny akwen miejski i jedna z wizytówek regionu. Przedzielone na dwie części (Małe i Duże Ełckie) przez most, jezioro posiada olbrzymią powierzchnię (ok. 380 ha) i gigantyczną głębokość (ponad 55 metrów!). Mimo potężnej presji wędkarskiej i turystycznej (przepiękna promenada w Ełku), dzięki wielkim głębokościom i twardemu ukształtowaniu rynny, ryby mają tu doskonałe warunki ochronne. To topowe łowisko sandaczowe i okoniowe w Polsce – łowienie na twardych, gliniastych skarpach na głębokościach 8-15 metrów to tutejsza klasyka. Nocą, ełckie sandacze wychodzą żerować pod same latarnie miejskiej promenady!', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80513, 'Jezioro Szczurkowskie', 'jezioro-szczurkowskie', 'LAKE', 53.222276, 18.842797, 'Kujawsko-Pomorskie', 'Ryńsk', 'Szczurkowskie to mały, dziki zbiornik o charakterze wytopiskowym. Dno jest miękkie, a woda ma lekki odcień torfowy. To wymarzone miejsce dla miłośników lekkiego spławika i poszukiwaczy "złotych" karasi. Brzegi są trudniej dostępne, co zapewnia spokój.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80514, 'Jezioro Sunowo', 'jezioro-sunowo', 'LAKE', '53.83172689577016', '22.28613390512994', 'Warmińsko-Mazurskie', 'Ełk', 'Jezioro Sunowo to potężny rynnowy sąsiad Jeziora Ełckiego (ok. 180 ha), leżący po północno-zachodniej stronie miasta. Cechuje je bardzo nieregularna linia brzegowa z wieloma przewężeniami oraz wysoka jakość wody. To wyborne łowisko sielawowe o głębokości sięgającej 22 metrów. Dno obfituje w liczne górki, za którymi czają się dorodne sandacze, a toniowy szczupak patroluje stada stynki i sielawy. Z uwagi na dość gęstą zabudowę wokół zachodniego brzegu, do obławiania najciekawszych miejsc poleca się wypożyczenie łodzi.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80515, 'Jezioro Woszczelskie', 'jezioro-woszczelskie', 'LAKE', '53.85157887984008', '22.24685843446263', 'Warmińsko-Mazurskie', 'Woszczele', 'Jezioro Woszczelskie to rozległy, ponad 170-hektarowy akwen leżący na zachód od Sunowa, w pobliżu miejscowości Woszczele. Jezioro składa się z głównego plosa oraz kilku głębokich, bardzo zarośniętych zatok. Dno urozmaicone, twardo-muliste. Wędkarsko to fenomenalna "woda ryb spokojnego żeru" – tutejsze stada pięknej, ponad kilogramowej płoci oraz olbrzymich leszczy budzą respekt na całym pojezierzu. Dla spinningistów najatrakcyjniejsze są wschodnie i zachodnie stoki w poszukiwaniu radosnych, letnich "garbusów".', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80516, 'Jezioro Sawinda Wielka', 'jezioro-sawinda-wielka', 'LAKE', '53.877971520939155', '22.22082272810665', 'Warmińsko-Mazurskie', 'Zawady Ełckie', 'Sawinda Wielka to klasyk Pojezierza Ełckiego o powierzchni ponad 220 ha. Zbiornik charakteryzuje się niesamowitą czystością wód (I klasa), stromo opadającymi stokami (głębokość do 24 m) i kamienistym dnem. Brzegi są miejscami zalesione, tworząc wspaniały, surowy klimat. To prawdziwy poligon doświadczalny dla spinningistów! Łowienie na 15-20 metrach metodą drop-shot czy ciężkim jigiem przynosi tu spektakularne okonie i duże szczupaki, które żerują na sielawie niemal w połowie głębokości jeziora.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80517, 'Jezioro Zierczyk (Sierczyk)', 'jezioro-zierczyk', 'LAKE', '53.86362601897788', '22.21684136803782', 'Warmińsko-Mazurskie', 'Zawady Ełckie', 'Zierczyk (lub Sierczyk) to ukryte w lasach, małe jezioro rynnowe sąsiadujące z Sawindą Wielką. Powierzchnia kilkunastu hektarów i woda osłonięta od wiatru wysokim drzewostanem sprawiają, że lustro wody bywa tu gładkie jak lustro. Woda ma brunatny, puszczański odcień. Ze względu na strome spadki, brak w nim szerokiego litoralu. Jest to woda pełna niespodzianek, z mocną populacją drapieżnika "stacjonarnego" (szczupak spod kija) i płoci.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80518, 'Jezioro Grabnik', 'jezioro-grabnik', 'LAKE', '53.86809159721613', '22.209351506636054', 'Warmińsko-Mazurskie', 'Grabnik', 'Jezioro Grabnik to malownicza, płytka misa o powierzchni ok. 35 hektarów, leżąca w gminie Stare Juchy. To raj dla zwolenników wędkowania "w sałacie" – latem jezioro bywa niezwykle mocno porośnięte grążelami, rdestnicą i osoką aloesowatą. Wędkarze używający żab antyzaczepowych, spinnerbaitów i gum prowadzonych po powierzchni osiągają tu niesamowite wyniki łowiąc agresywne szczupaki. Płytka, szybko nagrzewająca się woda to również matecznik gigantycznych linów i karasi.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80519, 'Jezioro Sawinda Mała', 'jezioro-sawinda-mala', 'LAKE', '53.90682862627893', '22.20837239567977', 'Warmińsko-Mazurskie', 'Stare Juchy', 'Sawinda Mała to naturalne przedłużenie Sawindy Wielkiej na północ, przedzielone krótkim kanałem. Akwen znacznie płytszy i spokojniejszy, o łagodniej opadających brzegach i bardziej rozwiniętej roślinności szuwarowej. Pełni funkcję ogromnego, naturalnego tarliska dla ryb z głównego jeziora. W iosną to miejsce tętni życiem, oferując pewne łowienie leszczy i płoci. Późną jesienią warto tu wpaść z żywcem na dużego szczupaka, który zamyka się w tych płytszych wodach w poszukiwaniu łatwego łupu.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80520, 'Jezioro Garbas (Stare Juchy)', 'jezioro-garbas-stare-juchy', 'LAKE', '53.90393424894249', '22.162665637486942', 'Warmińsko-Mazurskie', 'Stare Juchy', 'Uwaga: nie mylić z Garbasiem koło Filipowa! Ten Garbas to piękne, 40-hektarowe jezioro polodowcowe zlokalizowane blisko Starych Juch. Woda jest czysta, dno wyrównane, a przyroda wokół niemal nietknięta. Wędkarze spławikowi uwielbiają ten zbiornik za ciszę i bardzo silną populację puszczańskiego lina i wzdręgi. Stoki obfitują również w drobnego okonia, co jest gwarancją świetnej zabawy przy łowieniu na boczny trok czy ultra-light (XUL).', 'PZW Suwałki / GR Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80521, 'Jezioro Rękaty', 'jezioro-rekaty', 'LAKE', '53.91841201458899', '22.187147973226455', 'Warmińsko-Mazurskie', 'Stare Juchy', 'Jezioro Rękaty to specyficzny, niewielki akwen rynnowy połączony z rzeką Gawlik, o bardzo stromych, gliniasto-kamienistych brzegach, które od razu przechodzą w głębocza. Otoczenie stanowią dzikie łąki i kępy lasu. Słynie z czystej wody i wymagających warunków łowienia – brak rozległych wypłyceń sprawia, że łowienie spławikowe jest trudne, natomiast spinning z łodzi, rzucając "pod brzeg" i prowadząc w dół stoku, potrafi przynieść pięknego okonia i sandacza.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80522, 'Jezioro Łaśmiady (Łaźno)', 'jezioro-lasmiady', 'LAKE', '53.91255618816737', '22.288033524534345', 'Warmińsko-Mazurskie', 'Stare Juchy', 'Jezioro Łaśmiady to jeden z największych (ponad 880 ha) i najwspanialszych akwenów Pojezierza Ełckiego, połączone systemem przesmyków z sąsiednim Jeziorem Ułówki. Jest to potężne, rozległe rozlewisko z jedną dużą wyspą, niezwykle skomplikowaną batymetrią – najeżone jest głazami, górkami i mieliznami, które gwałtownie uciekają w 40-metrowe głębiny. Ta wędkarska "dżungla" to raj na ziemi dla łowców szczupaków, sandaczy i potężnych sielawowych okoni. Wymaga absolutnego szacunku od żeglarzy i wędkarzy (niebezpieczne, podwodne kamienie blisko powierzchni) oraz dobrej elektroniki.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80523, 'Jezioro Zawadzkie', 'jezioro-zawadzkie', 'LAKE', '53.94064668152686', '22.234151436541318', 'Warmińsko-Mazurskie', 'Zawady Ełckie', 'Zawadzkie to przepływowe, bardzo urozmaicone i głębokie (do 29 m) jezioro o powierzchni ok. 150 hektarów, wchodzące w skład szlaku rzecznego Łaźnej Strugi. To fantastyczne, czyste jezioro o twardym, żwirowo-piaszczystym dnie. Jest domem dla wielu gatunków drapieżników: z opadu złowisz tu sandacza, w toni szczupaka, a przy ujściach rzecznych często "siada" potężny jaź i okoń. Liczne półwyspy stwarzają naturalne osłony przed uciążliwymi jesiennymi wiatrami.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80524, 'Jezioro Jędzelewo', 'jezioro-jedzelewo', 'LAKE', '53.93176479958484', '22.14933434426759', 'Warmińsko-Mazurskie', 'Stare Juchy', 'Jędzelewo to serce Starych Juch – piękne, rozległe jezioro (pow. ok. 150 ha), w którym głębokość maksymalna wynosi kilkanaście metrów. Dno ukształtowane w formie łagodnej misy obfituje w podwodne, rdestnicowe łąki, będące wspaniałym terytorium dla szczupaków i gigantycznych płoci. Bliskość turystycznej miejscowości ułatwia wodowanie łodzi i czyni to miejsce bardzo popularnym, jednak jego rozległość pozwala na znalezienie cichych i dziewiczych zatok, szczególnie po południowej stronie zbiornika.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80525, 'Jezioro Wieczno (Południowe)', 'jezioro-wieczno-poludniowe', 'LAKE', 53.259953, 18.79765, 'Kujawsko-Pomorskie', 'Płużnica', 'Wieczno to potężny akwen (pow. ok. 350 ha) podzielony groblą na dwie części. Część południowa jest głębsza i bardziej otwarta. To wyśmienite łowisko szczupaka i sandacza. Słynie również z ogromnych stad leszcza, które wymagają intensywnego nęcenia na piaszczysto-mulistych blatach.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80526, 'Jezioro Szóstak Mały', 'jezioro-szostak-maly', 'LAKE', '53.95004372026447', '22.15364581531668', 'Warmińsko-Mazurskie', 'Czarnówka', 'Szóstak Mały to naturalna, zatokowa odnoga połączona ciekiem z głównym jeziorem Szóstak. Płytki, bagnisty i niezwykle bogaty w tlen w miesiącach wiosennych. Stanowi naturalne, potężne tarlisko dla ryb jeziornych. O ile latem łowienie jest tu niemal niemożliwe z powodu gęstej roślinności podwodnej (tzw. "sałaty"), o tyle wczesną wiosną lub jesienią, po opadnięciu zielska, jest to łowisko "bankowe" na pięknie wybarwionego lina i dużego szczupaka.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80527, 'Jezioro Szóstak', 'jezioro-szostak', 'LAKE', '53.979113454056936', '22.150574183303814', 'Warmińsko-Mazurskie', 'Szczecinowo', 'Szóstak to absolutny król tego subregionu – gigantyczne jezioro o powierzchni niespełna 500 hektarów, słynące z kilkunastu malowniczych, dzikich wysp, które tworzą labirynt kanałów i zatok. Dno jest wybitnie pofałdowane, pełne dołów (do blisko 30 m głębokości) i płycizn. Taka mozaika gwarantuje zróżnicowany rybostan: od sielawy i sandacza w toni, po majestatyczne liny w płytkich odnogach. Do efektywnego namierzenia drapieżników w tym wędkarskim raju, oprócz silnika spalinowego (jeśli jest dozwolony lokalnie), niezastąpiony bywa solidny chartplotter.', 'Gospodarstwo Rybackie Ełk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80528, 'Jezioro Gawlik', 'jezioro-gawlik', 'LAKE', '54.028683747912936', '22.114534519164458', 'Warmińsko-Mazurskie', 'Gawliki Wielkie', 'Jezioro Gawlik (pow. ok. 415 ha) to jedno z najważniejszych łowisk pomiędzy Wydminami a Oleckiem. Jest to bardzo urozmaicony, mezotroficzny zbiornik wodny z dwiema wysepkami. Linia brzegowa dzieli się na głębokie, twarde brzegi od wschodu oraz płytsze, bagniste rozlewiska od zachodu. Wędkarsko to bardzo silny punkt na mapie łowców sandacza (który lubi tutejsze, kamieniste rafy), jak i zwolenników wędkowania gruntowego – jezioro słynie z potężnych, ciągnących całymi nocami stad dorodnego leszcza.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80529, 'Jezioro Sołtmany', 'jezioro-soltmany', 'LAKE', '54.04555128615571', '22.028376092312044', 'Warmińsko-Mazurskie', 'Sołtmany', 'Jezioro Sołtmany to 130-hektarowe jezioro rynnowe leżące na północny wschód od Wydmin. Cechuje je piękny, bardzo jasny kolor wody, będący wynikiem znacznych głębokości i osadów kredy jeziornej. Brzegi są strome, w przeważającej części zalesione, a spady na dnie niezwykle gwałtowne. To jezioro, które nagradza cierpliwość – nie jest to "woda na jedno popołudnie". Wymaga precyzyjnego podawania przynęt gumowych na opad na głębokości 10-15 metrów, za co odwdzięcza się przepięknym, rzecznym wręcz okoniem oraz sieją łowioną zimą.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80530, 'Jezioro Żywy', 'jezioro-zywy', 'LAKE', '54.06428731111629', '22.0409661470561', 'Warmińsko-Mazurskie', 'Żywy', 'Jezioro Żywy to ukryte w malowniczym pofalowaniu terenu rynnowe "oko" o powierzchni blisko 120 ha. Słynie w regionie z absolutnej ciszy, bardzo mrocznego, zalesionego charakteru i mroźnej, czystej wody. W najgłębszych partiach jezioro dno opada na blisko 25 metrów. Stanowi idealne schronienie dla ryb szlachetnych (sielawa). Wędkarze zjeżdżają tu na wymagające łowienie szczupaków na duże woblery trollingowe i wędkarstwo podlodowe, które z racji chłodnego mikroklimatu bywa tu bardzo owocne.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80531, 'Jezioro Róg', 'jezioro-rog', 'LAKE', '54.06293869883692', '22.12161143343432', 'Warmińsko-Mazurskie', 'Róg Orłowski', 'Jezioro Róg to mały (ok. 20 ha), rzadko odwiedzany przez wędkarzy z centralnej Polski zbiornik rynnowy. Ukryty z dala od szos, charakteryzuje się gęsto porośniętą, często bagnistą linią brzegową z domieszką zwalonych sosen, co nadaje mu bajkowy, puszczański klimat. Dno jeziora jest stosunkowo muliste, obfitujące w zarośla podwodne. Złowisz tu przede wszystkim pięknego, ciemnego lina oraz "wybrednego", wyrośniętego na drobnicy szczupaka. Idealna propozycja dla poszukiwaczy dzikiej, nienaruszonej wody.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80532, 'Jezioro Łękuk', 'jezioro-lekuk', 'LAKE', '54.06587227832233', '22.132720360476963', 'Warmińsko-Mazurskie', 'Wydminy', 'Jezioro Łękuk to niezwykle urokliwy, rynnowy akwen (ok. 80 ha) na skraju Puszczy Boreckiej. Przez jezioro przepływa rzeka Łaźna Struga, co zapewnia doskonałe natlenienie wody przez cały rok. Północne, bardzo strome brzegi porośnięte są potężnym, mieszanym lasem, który rzuca majestatyczny cień na taflę wody. Dno jeziora opada gwałtownie do głębokości ok. 15 metrów, tworząc wybitne środowisko dla okonia i sandacza. Zachodnia i południowa część akwenu, przy historycznym Folwarku Łękuk, jest płytsza i bardziej dostępna, oferując wspaniałe możliwości do połowu dużych płoci i leszczy.', 'PZW Suwałki / GR Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80533, 'Jezioro Dubinek', 'jezioro-dubinek', 'LAKE', '54.06598212904191', '22.14417066840298', 'Warmińsko-Mazurskie', 'Wydminy', 'Dubinek to miniaturowy sąsiad jeziora Łękuk, z którym jest zresztą połączony wąskim, malowniczym przesmykiem. Ten zaledwie 12-hektarowy zbiornik ma skrajnie odmienny charakter od swojego starszego brata – jest płytki (do ok. 4 m), silnie zamulony i w dużej mierze pokryty gęstym dywanem lilii wodnych oraz grążeli. To naturalna i niemal nietknięta oaza spokoju, pełniąca rolę ogromnego tarliska. Dla wędkarza to idealne łowisko linowo-karasiowe. Sukces wymaga tu cichego podchodzenia na pontonie i precyzyjnego wrzucania zestawu w naturalne luki między liśćmi grzybieni.', 'PZW Suwałki / GR Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80534, 'Jezioro Czarne (Osiek - Południe)', 'jezioro-czarne-osiek-1', 'LAKE', 53.732146, 18.507096, 'Pomorskie', 'Osiek', 'Pierwsze z jezior Czarnych w rejonie Osieka. Akwen typowo śródleśny, o mrocznej, żyznej wodzie. Dno jest miękkie, wyścielone osadami organicznymi. To matecznik szczupaka leśnego i dorodnej wzdręgi.', 'Nadleśnictwo Lubichowo / PZW');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80535, 'Jezioro Litygajno', 'jezioro-litygajno', 'LAKE', '54.08949598530135', '22.184153919368583', 'Warmińsko-Mazurskie', 'Kruklanki', 'Jezioro Litygajno (pow. ok. 162 ha) to klasyczna, długa na prawie 3 kilometry rynna polodowcowa, będąca ważnym ogniwem dzikiego szlaku kajakowego Łaźnej Strugi. Otoczone gęstymi borami Puszczy Boreckiej, sprawia wrażenie jeziora skandynawskiego. Dno jest wybitnie twarde, piaszczysto-żwirowe, z nagłymi uskokami sięgającymi 16 metrów głębokości. Nurt rzeki utrzymuje tu krystaliczną wodę, co przyciąga łowców walecznego, jeziornego sandacza oraz grubego okonia. Wymaga znakomitych umiejętności czytania wody i odpowiedniego, cięższego sprzętu spinningowego z uwagi na silne wiatry "kominowe" wiejące wzdłuż rynny.', 'Gospodarstwo Rybackie PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80536, 'Jezioro Łaźno', 'jezioro-lazno', 'LAKE', '54.093765811670146', '22.207252316638478', 'Warmińsko-Mazurskie', 'Kruklanki', 'Łaźno to absolutny gigant i serce Puszczy Boreckiej! Z powierzchnią wynoszącą ponad 560 hektarów i głębokością przekraczającą 27 metrów, jest to prawdziwe wędkarskie morze. Objęte jest strefą ciszy, co gwarantuje brak skuterów wodnych i motorówek, pozwalając wędkarzom na całkowity relaks. Jezioro charakteryzuje się wodą typu sielawowego (I i II klasa czystości) oraz bardzo urozmaiconą linią brzegową z wyspami, półwyspami i piaszczystymi cypelkami. To woda pełna trofeów: potężnych szczupaków pelagicznych pływających za ławicami sielawy, wyrośniętych sandaczy i siei. Płytsze zatoki to z kolei matecznik "puszczańskich prosiaczków" – kilkukilogramowych leszczy.', 'Gospodarstwo Rybackie PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80537, 'Jezioro Wieczno Północne', 'jezioro-wieczno-polnocne', 'LAKE', 53.271038, 18.789282, 'Kujawsko-Pomorskie', 'Płużnica', 'Wieczno Północne jest płytsze i silniej zarośnięte od swojego południowego sąsiada. To absolutne królestwo lina i potężnego szczupaka polującego z zasadzki. Spinningiści najskuteczniej łowią tu w oknach roślinności przy użyciu przynęt powierzchniowych.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80538, 'Jezioro Szwałk Mały', 'jezioro-szwalk-maly', 'LAKE', '54.10440850125694', '22.24007840379522', 'Warmińsko-Mazurskie', 'Kowale Oleckie', 'Jezioro Szwałk Mały (pow. ok. 75 ha) to jedno z najbardziej niezwykłych jezior na całych Mazurach Garbatych. Niemal w całości leży w granicach rezerwatu przyrody, co czyni go ostoją dla rzadkich gatunków ptaków i ssaków, w tym żubrów, które często gaszą tu pragnienie! Mimo niedużej powierzchni, akwen ma imponującą głębokość (ponad 22 metry) i formę stromego, zalanego kotła. Strome, zalesione brzegi opadają pod wodą równie gwałtownie, co wymusza techniczne łowienie "w pionie". Złowisz tu przede wszystkim wyśmienitej kondycji okonia i czatującego na skarpach szczupaka.', 'Rezerwat Przyrody / PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80539, 'Jezioro Szwałk Wielki', 'jezioro-szwalk-wielki', 'LAKE', '54.11234743287892', '22.204941298605807', 'Warmińsko-Mazurskie', 'Kowale Oleckie', 'Szwałk Wielki (ok. 215 ha) to podłużny, dziki akwen, który urzeka swoim surowym, puszczańskim klimatem. Na jeziorze znajduje się duża wyspa (Wyspa Lipowa), będąca ścisłym rezerwatem przyrody. Dno jeziora jest stosunkowo wyrównane (maksymalnie kilkanaście metrów głębokości), a przy brzegach rozciągają się rozległe, piaszczysto-żwirowe blaty porośnięte łąkami podwodnymi. To fantastyczne łowisko szczupakowe – drapieżniki mają tu doskonałe warunki do kamuflażu wśród wysokich roślin. Warto spędzić tu noc, by zapolować na wędrujące z głębin stada olbrzymich leszczy i linów.', 'Gospodarstwo Rybackie PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80540, 'Jezioro Piłwąg', 'jezioro-pilwag', 'LAKE', '54.117131748532884', '22.171128689856964', 'Warmińsko-Mazurskie', 'Kowale Oleckie', 'Jezioro Piłwąg, bezpośrednio połączone rzeczką ze Szwałkiem Wielkim, to prawdziwa "zielona dżungla". Przy ogromnej powierzchni (ponad 135 hektarów) jego średnia głębokość wynosi niewiele ponad 1 metr, a maksymalna ledwie dochodzi do 4,5 metra! W sezonie letnim akwen w niemal 80% pokrywa się roślinnością wynurzoną i podwodną (trzcinowiska, grążele, rogatek, wywłócznik). Z racji tak specyficznych warunków, spinningowanie jest tu bardzo trudne i wymaga stosowania żab antyzaczepowych. Za to wędkarze preferujący przepływankę i bat będą w siódmym niebie – to oaza wspaniałych krasnopiórek (wzdręg), złotych linów i piskorzy.', 'Gospodarstwo Rybackie PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80541, 'Jezioro Ciche', 'jezioro-ciche', 'LAKE', '54.11981443700553', '22.260181334042258', 'Warmińsko-Mazurskie', 'Świętajno', 'Zgodnie ze swoją nazwą, Ciche to niewielki (ok. 42 ha), kameralny akwen całkowicie ukryty w gęstych lasach Puszczy Boreckiej na wschód od jezior szwałckich. Stanowi formę wąskiej rynny, mocno chronionej przed wiatrami przez otaczające ją wyniesienia terenu. Woda ma odcień ciemnozielony, a dno, z racji opadających od tysiącleci liści, jest dość muliste. To rewelacyjne, pewne jezioro szczupakowo-okoniowe. Ryby uderzają tu agresywnie na klasyczne wahadłówki (tzw. "gnomy" i "algi") oraz duże, żółte twistery prowadzone na granicy strefy światła i cienia przybrzeżnego lasu.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80542, 'Jezioro Solińskie', 'jezioro-solinskie', 'LAKE', '49.37211204585855', '22.454727849412198', 'Podkarpackie', 'Polańczyk', 'Jezioro Solińskie to prawdziwy wędkarski ocean w sercu Bieszczad, zbiornik zaporowy na rzece San o niezwykle urozmaiconej, górskiej charakterystyce. Z maksymalną głębokością przekraczającą 60 metrów i linią brzegową o długości ponad 160 km, jest to woda wymagająca ogromnej pokory i doskonałego czytania echosondy. Batymetria zbiornika to istny labirynt: znajdziemy tu strome, pionowe skały uciekające w mrok, zatopione lasy, pozostałości dawnych wiosek, fundamenty domów oraz stare koryto Sanu, które stanowi autostradę dla największych drapieżników. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80543, 'Jezioro Sieniawskie', 'jezioro-sieniawskie', 'LAKE', 49.55259948356, '21.93257181990114', 'Podkarpackie', 'Rymanów', 'Jezioro Sieniawskie to malowniczy, zaporowy zbiornik na rzece Wisłok, oferujący kameralny, dziki klimat, w opozycji do zatłoczonej Soliny. Jest to akwen rynnowy, mocno wydłużony, z wyraźnie zaznaczonym starym korytem rzeki, które stanowi klucz do wędkarskiego sukcesu. Batymetria jest bardzo czytelna – zachodni brzeg jest w dużej mierze stromy i głęboki, szybko opadający w stronę koryta, natomiast brzeg wschodni i rejon cofki to wypłycenia z łagodniejszymi stokami. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80544, 'Jezioro Tejstymy', 'jezioro-tejstymy', 'LAKE', 53.953285, 20.886211, 'Warmińsko-Mazurskie', 'Biskupiec / Tejstymy', 'Jezioro Tejstymy to potężna i głęboka rynna (max 33 m) o powierzchni ok. 200 ha. Woda charakteryzuje się wysoką przejrzystością i sielawowym charakterem. Dno jest wybitnie urozmaicone z licznymi podwodnymi górkami i gwałtownymi uskokami piaszczysto-żwirowymi. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80545, 'Jezioro Klimkowskie', 'jezioro-klimkowskie', 'LAKE', '49.54363375682234', '21.09864085068366', 'Małopolskie', 'Uście Gorlickie', 'Klimkówka to surowy, górski zbiornik zaporowy na rzece Ropa, ukryty w głębokiej dolinie Beskidu Niskiego. To łowisko o niezwykle trudnym charakterze, zarezerwowane dla wędkarzy ceniących wyzwania i gotowych na zmagania z żywiołem – zbiornik słynie z bardzo silnych, porywistych wiatrów potęgujących falę. Dno Klimkówki to przewaga twardych formacji: od łupków i skał osadowych, po naniesiony przez Ropę żwir i kamienie. Roślinność zanurzona praktycznie nie istnieje z powodu znacznych wahań poziomu wody oraz kamienistego podłoża.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80546, 'Jezioro Rożnowskie', 'jezioro-roznowskie', 'LAKE', '49.726048658196916', '20.699135609295098', 'Małopolskie', 'Gródek nad Dunajcem', 'Jezioro Rożnowskie to historycznie jeden z najważniejszych zbiorników zaporowych w Polsce, utworzony na Dunajcu. Na przestrzeni dekad jego charakter uległ jednak dramatycznej transformacji. Niegdyś głęboki i twardy, dziś – szczególnie w górnej i środkowej części – jest silnie zapiaszczony i zamulony przez osady niesione przez rzekę. To zmieniło strukturę gatunkową ryb. Górna część zbiornika (od Znamirowic w górę) jest bardzo płytka, z rozległymi mulistymi blatami, podczas gdy część dolna, w okolicach zapory i słynnej Małpiej Wyspy, wciąż oferuje znaczne głębokości (nawet do 30m) i twardsze, pofałdowane dno.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80547, 'Jezioro Czchowskie', 'jezioro-czchowskie', 'LAKE', '49.80734635436493', '20.666899278882127', 'Małopolskie', 'Czchów', 'Jezioro Czchowskie pełni rolę zbiornika wyrównawczego dla potężnego Rożnowa, co diametralnie kształtuje jego warunki hydrologiczne. To akwen bardzo specyficzny – przypomina raczej potężną, wezbraną rzekę nizinną z bardzo wyraźnym uciągiem wody, niż klasyczne jezioro. Dno jest tu niesamowicie urozmaicone przez pracujący nurt: znajdziemy głębokie rynny (do 9m), prądy wsteczne, potężne warkocze, naniesione piaszczyste i żwirowe łachy oraz kamieniste rafy. Roślinność wodna występuje tylko w spokojnych, wyłączonych z nurtu zatoczkach i na krawędziach wałów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80548, 'Jezioro Czorsztyńskie', 'jezioro-czorsztynskie', 'LAKE', '49.44032114979145', '20.269973418751263', 'Małopolskie', 'Niedzica', 'Jezioro Czorsztyńskie to jedno z najbardziej zjawiskowych i wędkarsko elitarnych łowisk w Polsce, położone w majestatycznej scenerii Pienin, między zamkami w Czorsztynie i Niedzicy. Zbiornik charakteryzuje się surową, alpejską morfologią: dno opada tu niezwykle stromo, tworząc podwodne klify, pionowe ściany i potężne półki skalne sięgające 50 metrów w głąb. Woda zachowuje niesamowitą wręcz krystaliczność przez cały rok, co z jednej strony zapiera dech w piersiach, a z drugiej stanowi ogromne wyzwanie wędkarskie – ryby doskonale widzą najdrobniejszy błąd w prezentacji przynęty czy zbyt gruby przypon. Zatopione pozostałości Starego Maniowego (ruiny budynków, asfaltowe drogi) tworzą jedyne w swoim rodzaju struktury.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80549, 'Jezioro Dratów', 'jezioro-dratow', 'LAKE', '51.33965962781161', '22.943773621695225', 'Lubelskie', 'Łęczna', 'Jezioro Dratów, kluczowy element systemu kanału Wieprz-Krzna na Pojezierzu Łęczyńsko-Włodawskim, to doskonały przykład mocno zeutrofizowanego, płytkiego jeziora nizinnego. Średnia głębokość akwenu rzadko przekracza 1.5 metra, a batymetria przypomina płaską misę bez zauważalnych dołków, rynien czy górek podwodnych. Dno w całości pokryte jest bardzo grubą, często kilkudziesięciocentymetrową warstwą miękkiego mułu i osadów organicznych. Woda w okresie letnim bardzo szybko się nagrzewa, co sprzyja zakwitom fitoplanktonu i obniża widoczność niemal do zera. Cały zbiornik otoczony jest gęstym pierścieniem trzcin i usypanymi wałami ochronnymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80550, 'Jezioro Nadrybie', 'jezioro-nadrybie', 'LAKE', '51.35785102452637', '23.04210312913801', 'Lubelskie', 'Puchaczów', 'Jezioro Nadrybie to niezwykle klimatyczny, dziki i zagadkowy akwen, którego obecny kształt i morfologia są silnie uwarunkowane działalnością pobliskiej kopalni węgla kamiennego "Bogdanka". Osiadanie terenu spowodowało podniesienie i powiększenie lustra wody, tworząc rozległe, płytkie rozlewiska i zalane łąki. Dno zbiornika jest bardzo miękkie, torfowe i muliste, z dużą ilością zatopionych gałęzi i szczątków organicznych. Nadrybie charakteryzuje się ogromnym bogactwem roślinności wynurzonej (szerokie pasy pałki wodnej i gęstej trzciny) oraz podwodnej (rozległe dywany rdestnicy i wywłócznika), co latem potrafi skutecznie odciąć duże partie jeziora.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80551, 'Jezioro Rogóźno', 'jezioro-rogozno', 'LAKE', '51.37621540606315', '22.97267103231663', 'Lubelskie', 'Ludwin', 'Jezioro Rogóźno to absolutny fenomen i anomalia hydrologiczna na mapie bardzo płytkiego Pojezierza Łęczyńsko-Włodawskiego. Jest to jezioro pochodzenia krasowego (powstałe z zapadliska w skałach węglanowych), które osiąga zawrotną na tym terenie głębokość niemal 25 metrów, zachowując przy tym formę stosunkowo niewielkiego i owalnego zbiornika. Profil dna przypomina stromy lejek – już kilka metrów od brzegu głębokość drastycznie opada, tworząc wspaniałe, twarde półki i ostre stoki schodzące w zimną ciemność. Krystaliczna, natleniona woda sprzyja występowaniu stref termicznych i rzadkich na nizinach gatunków ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80552, 'Jezioro Kręcko', 'jezioro-krecko', 'LAKE', '52.32043961866977', '14.97781552101357', 'Lubuskie', 'Torzym', 'Niewielkie i dzikie jezioro sąsiadujące blisko z jeziorem Boczowskim, charakteryzujące się jednak zdecydowanie bardziej bagiennym i ustronnym klimatem. Dno Kręcka jest wysoce muliste, usłane potężną warstwą osadu i torfu opadającego z nadbrzeżnych olsów i wierzb. Całość uformowana jest jako płytki talerz ze sporadycznymi twardszymi łatkami. Woda w jeziorze przybiera często bardzo ciemny, mętny odcień od procesów gnilnych na dnie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80553, 'Jezioro Rotcze', 'jezioro-rotcze', 'LAKE', '51.376855891091495', '23.11085116589219', 'Lubelskie', 'Urszulin', 'Jezioro Rotcze (często nazywane przez wędkarzy Grabniakiem od nazwy pobliskiej wsi) to płytki, wysoce zeutrofizowany akwen o charakterze polesiowym. Misa jeziora jest niesamowicie płaska – średnia głębokość rzadko przekracza 1.5 metra, a dno stanowi gruba, miękka poduszka osadów dennych. Brzegi są mocno porośnięte gęstymi pasami trzciny pospolitej, a w sezonie letnim lustro wody pokrywa się ogromnymi połaciami grążela, rdestnicy i rogatka, tworząc iście amazoński klimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80554, 'Jezioro Sumin', 'jezioro-sumin', 'LAKE', '51.375147911101855', '23.139581688714834', 'Lubelskie', 'Urszulin', 'Sumin to urokliwe, bardzo żyzne i dość rozległe jezioro, oferujące klasyczne warunki linowo-szczupakowe. W przeciwieństwie do płytszych sąsiadów, Sumin posiada wyraźniejsze, choć wciąż łagodne spadki dna, osiągając maksymalnie około 6 metrów głębokości w rynnie środkowej. Dno jest muliste i torfowe, obfitujące w bentos, co stanowi idealną stołówkę dla stad wielkich leszczy i okazałych karpi, którymi woda ta od lat jest regularnie zarybiana. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80555, 'Jezioro Bikcze', 'jezioro-bikcze', 'LAKE', '51.37984470273682', '23.05133794004529', 'Lubelskie', 'Ludwin', 'Bikcze to akwen silnie włączony w sieć hydrologiczną kanału Wieprz-Krzna, co spowodowało utworzenie obwałowań na znacznej części jego brzegów. Posiada bardzo regularny kształt i dno pozbawione ostrych rzeźb – dominują tu płytkie blaty (średnio 1.5 - 2m) obficie pokryte miękkimi osadami. Woda charakteryzuje się niestety dość niską przejrzystością, która spada do minimum w okresie letnich zakwitów. Silne zarastanie zbiornika czyni z niego wyborne schronienie dla narybku.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80556, 'Jezioro Piaseczno', 'jezioro-piaseczno', 'LAKE', '51.3849679258192', '23.029105987861104', 'Lubelskie', 'Ludwin', 'Jezioro Piaseczno to perła całego regionu i absolutny unikat hydrologiczny. To krasowe jezioro jest najgłębszym zbiornikiem Pojezierza (oficjalnie blisko 39 metrów!), wyróżniającym się wodą w pierwszej klasie czystości, niesamowitą przejrzystością i białymi, piaszczystymi plażami. Dno opada tu niezwykle stromo niemal od samego brzegu, tworząc dramatyczne podwodne klify, mocno zarośnięte na krawędziach rozległymi łąkami ramienic. Brak dopływów sprawia, że woda jest zimna i bogata w tlen, co warunkuje egzystencję ryb łososiowatych (sielawa).
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80557, 'Jezioro Łukie', 'jezioro-lukie', 'LAKE', '51.41121544404165', '23.08348876378477', 'Lubelskie', 'Urszulin', 'Łukie to serce Poleskiego Parku Narodowego, akwen niezwykle dziki, otoczony rozległymi bagnami, torfowiskami i trudnymi do przebycia olsami. Jest to największe naturalne jezioro w obrębie Parku. Mimo sporej powierzchni, jezioro jest bardzo płytkie (około 6 metrów w max punktach), a gruba warstwa osadów dennych przypomina o postępującym procesie wypłycania. Jezioro to ostoja ptactwa wodnego, co wymusza rygorystyczne przestrzeganie stref ochronnych. Wędkowanie jest tu ściśle limitowane, możliwe tylko z określonych pomostów lub wypożyczonych z Parku łodzi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80558, 'Jezioro Wytyckie', 'jezioro-wytyckie', 'LAKE', '51.43211732099296', '23.225431229301236', 'Lubelskie', 'Urszulin', 'Wytyckie to największy akwen Pojezierza Łęczyńsko-Włodawskiego, pełniący funkcję potężnego zbiornika retencyjnego, całkowicie otoczonego wałami ochronnymi. Ze względu na swój charakter, jest to zbiornik niesamowicie wręcz płytki (średnio ponad 1 metr, maksimum w dołkach rzadko sięga 3 metrów). Niewielka głębokość na ogromnej przestrzeni sprzyja szybkiemu nagrzewaniu się wody, co powoduje niemal całkowite zarastanie akwenu podwodnymi "łąkami" wywłócznika i moczarki. Dno urozmaicone jest resztkami zalanych niegdyś grobli i kanałów melioracyjnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80559, 'Jezioro Zagłębocze', 'jezioro-zaglebocze', 'LAKE', '51.43105113011602', '23.023975539509138', 'Lubelskie', 'Ludwin', 'Jezioro Zagłębocze to akwen wybitny, często zestawiany w jednym rzędzie z Piasecznem. Jest to głębokie jezioro krasowe (ponad 23 metry głębokości), charakteryzujące się wybitną przejrzystością, jasnym, piaszczysto-żwirowym dnem z rzadkim pasem roślinności brzegowej. Kształt jeziora jest niemal idealnie okrągły, a stoki stromo uciekają ku centralnej rynnie. Woda ta należy do najczystszych w regionie i cieszy się ogromną popularnością wśród wędkarzy i płetwonurków.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80560, 'Jezioro Łukcze', 'jezioro-lukcze', 'LAKE', '51.39542605945677', '22.967198551343376', 'Lubelskie', 'Ludwin', 'Łukcze to niesłychanie ciekawe jezioro o mocno rozwiniętej, wydłużonej linii brzegowej i urozmaiconej rzeźbie dna. Miejscami dno jest tu twarde, wysadzane podwodnymi górkami krasowymi (maksymalna głębokość rynny osiąga około 9 metrów), przeplatane płytszymi, piaszczystymi zatokami porośniętymi pałką wodną i grążelami. Ze względu na łatwy dojazd z Lublina, wokół akwenu wyrosło mnóstwo domków letniskowych, co wiąże się ze sporą presją rekreacyjną i wędkarską, na szczęście rybostan zdaje się wciąż regenerować.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80561, 'Jezioro Krzczeń', 'jezioro-krzczen', 'LAKE', '51.40076092077093', '22.935047728184703', 'Lubelskie', 'Ludwin', 'Jezioro Krzczeń (czasami błędnie scalane nazwą z pobliskim jeziorem Krasne) to płytki, typowo nizinno-błotny zbiornik sztucznie zasilany wodą, z mocno zarastającą, dziką linią brzegową. Maksymalne głębokości osiągają tu zaledwie okolice 2.5 - 3 metrów w dołkach. Dno to istne królestwo mułu i gnijących części organicznych. Odizolowany charakter zbiornika sprawia, że spotkamy tu urokliwą ciszę, a otoczenie sprzyja wyciszeniu i długim zasiadkom z wędziskiem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80562, 'Jezioro Mutcze', 'jezioro-mutcze', 'LAKE', '51.39990738477264', '22.848856159716778', 'Lubelskie', 'Ludwin', 'Niewielkie, niesamowicie urokliwe i niezwykle zarośnięte jezioro ukryte na obrzeżach pojezierza. Charakteryzuje się wybitnie eutorficznym charakterem – jego głębokość to maksymalnie zaledwie kilka metrów, a latem znaczna część lustra wody pokryta jest oszałamiającym dywanem grążeli żółtych i grzybieni białych. Muł zalega tu grubą warstwą na płaskim, misowatym dnie, do którego niemal do samego końca dociera światło słoneczne. Pasy trzcin tworzą niedostępną, niemal dżunglowatą ścianę odgradzającą od świata cywilizacji.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80563, 'Jezioro Krasne', 'jezioro-krasne', 'LAKE', '51.427227604848', '22.96141841369771', 'Lubelskie', 'Uścimów', 'Jezioro Krasne to absolutny klasyk pojezierza – niezwykle popularny i tętniący życiem akwen, oferujący jednocześnie wybitne walory łowieckie. Krasne to duże i głębokie (sięgające ponad 33 metrów) jezioro krasowe, rynnowe. Charakteryzuje się wspaniałymi, szerokimi, piaszczystymi plażami, a zaraz za nimi twardym, bardzo szybkim spadem na duże głębokości. Woda niemal zawsze jest krystalicznie czysta, co przyciąga tu fanów nurkowania. Roślinność wodna występuje rzadziej i jest rozsiana punktowo wokół łagodniejszych zatok.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80564, 'Jezioro Tomaszne', 'jezioro-tomaszne', 'LAKE', '51.4718834234764', '23.002633033576572', 'Lubelskie', 'Uścimów', 'Jezioro Tomaszne to mniejszy, bardzo spokojny, lecz niezwykle wędkarsko atrakcyjny akwen. W odróżnieniu od skrajnie płytkich stawów, oferuje ono nieco bardziej urozmaiconą strukturę z wyraźnie odznaczającymi się rynnami, spadami do kilku-kilkunastu metrów oraz naprzemiennie występującymi pasami podwodnej roślinności i rzadszych trzcin na obrzeżach. Jest zbiornikiem dość uniwersalnym, oferującym schronienie zarówno dla gatunków reofilizujących głębsze wody, jak i klasycznych ciepłolubnych bywalców przybrzeżnych płyt.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80565, 'Jezioro Maśluchowskie', 'jezioro-masluchowskie', 'LAKE', '51.4685810284761', '22.94465894288088', 'Lubelskie', 'Uścimów', 'Bardzo kameralne, ciche i zarośnięte jezioro w urokliwej otulinie leśno-łąkowej. Ze swoją maksymalną głębokością oscylującą na poziomie 7-8 metrów plasuje się w średniej klasie na pojezierzu, stając się idealną mieszanką cech wód krasowych i eutroficznych. Dno jest urozmaicone: piaszczysto-żwirowe place przy brzegu bardzo szybko i nieubłaganie przechodzą w szeroką, podłużną rynnę usłaną miękkim organicznym mułem. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80566, 'Jezioro Uścimowskie', 'jezioro-uscimowskie', 'LAKE', '51.47465298980844', '22.935937177024012', 'Lubelskie', 'Uścimów', 'Średniej wielkości, bardzo wydłużone i zagłębione rynnowo jezioro przylegające niemal do samej wsi. Posiada bardzo regularne, uskokowe stoki. Mimo bliskości ludzkich osad, jezioro posiada silnie zarośnięte brzegi pałką, trzciną, olszyną, co z wędkarskiego punktu widzenia czyni z niego wyzwanie – znalezienie miejsca bez kładki czy sprzętu wodnego jest niezwykle trudne. Dno jest tu na przemian piaszczyste i błotniste, w zależności od cyrkulacji wody opadowej, ze średnimi wartościami głębokości dochodzącymi do 9-10 metrów w centrum rynny.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80567, 'Jezioro Kleszczów', 'jezioro-kleszczow', 'LAKE', '51.518198275436625', '22.888052971780294', 'Lubelskie', 'Ostrów Lubelski', 'Jezioro Kleszczów to urokliwy, niezbyt wielki, ale przepięknie osadzony w krajobrazie leśnym zbiornik. Posiada niezwykle przejrzystą, natlenioną i bardzo chłodną wodę, typową dla leśnych wód krasowych, osiągającą maksymalne głębokości nawet do 8-10 metrów. Twarde jak skała, usypane żwirem i ubitym piaskiem dno to cecha rozpoznawcza i zarazem ogromny atut tego środowiska. Linie brzegowe przeplatają się od czystych, malutkich piaskowych urwisk, po spokojne, ukryte w krzakach malin i olszyn zatoczki łowców okoni.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80568, 'Jezioro Białe Włodawskie', 'jezioro-biale', 'LAKE', '51.53458352037015', '23.044702728179036', 'Lubelskie', 'Włodawa', 'Jezioro Białe (obok Okuninki) to perła turystyczna regionu, ale paradoksalnie, niezwykle interesujące, głębokie łowisko. Z głębokościami sięgającymi blisko 33 metrów na środku jeziora, posiada charakter typowo krasowy – o stromo opadających z wierzchu plaż uskokach z piaszczystego do kamienistego i wreszcie mulistego. Jego wyjątkowa w skali kraju piaszczysta linia brzegowa to latem przekleństwo (tłumy plażowiczów), ale o świcie lub w jesiennej mgle... absolutny raj dla wędkarzy ceniących finezję i sport. Woda posiada wybitną jakość (i klasę czystości!).
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80569, 'Jezioro Nyskie', 'jezioro-nyskie', 'LAKE', '50.45309479495808', '17.262812779336528', 'Opolskie', 'Nysa', 'Jezioro Nyskie (Głębinowskie) to potężny, podgórski zbiornik zaporowy utworzony na rzece Nysie Kłodzkiej, stanowiący mekkę południowo-zachodniej Polski dla łowców drapieżników. Akwen charakteryzuje się bardzo zróżnicowaną batymetrią. Zachodnia część zbiornika (cofka) jest płytsza, z licznymi piaszczystymi wyspami, naniesionym żwirem i pozostałościami zatopionych lasów. W miarę zbliżania się do zapory wschodniej, dno stromo opada, odkrywając zatopione drogi, mosty i ruiny wsi, sięgając głębokości ponad 20 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80570, 'Jezioro Otmuchowskie', 'jezioro-otmuchowskie', 'LAKE', '50.46402337857511', '17.11724393388734', 'Opolskie', 'Otmuchów', 'Starszy brat Jeziora Nyskiego, również położony na Nysie Kłodzkiej, ale charakteryzujący się nieco odmienną specyfiką. Jezioro Otmuchowskie jest starsze i płytsze – średnia głębokość to ok. 5 metrów, a dno, choć urozmaicone dawnym korytem rzeki, uległo na przestrzeni dekad znacznemu zamuleniu. Stwarza to doskonałe warunki dla ryb spokojnego żeru. Zbiornik okalają potężne wały ziemne, wyłożone w wielu miejscach kamiennymi opaskami, na których wędkarze ustawiają swoje stanowiska.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80571, 'Jezioro Jańsko', 'jezioro-jansko', 'LAKE', '51.89741118936717', '15.040928627627654', 'Lubuskie', 'Krosno Odrzańskie', 'Jezioro Jańsko (często znane lokalnie pod nazwą Dychowskie Małe, choć to odrębny akwen w kompleksie) to zjawiskowe, zatopione w gęstych borach sosnowych jezioro na Ziemi Lubuskiej. Posiada bardzo bogatą, pofałdowaną linię brzegową z dużą ilością cypli, głębokich rynien brzegowych i piaszczysto-żwirowych wypłyceń. Woda zazwyczaj charakteryzuje się znakomitą, leśną przejrzystością, lekko zabarwioną na ciemny odcień od opadających liści i igliwia. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80572, 'Jezioro Bronków', 'jezioro-bronkow', 'LAKE', '51.96985611931862', '15.000067436438503', 'Lubuskie', 'Bronków', 'Bronków (Jezioro Bronkowskie) to rynnowe, typowo polodowcowe jezioro lubuskie. Jego dno jest wyraźnie ukształtowane w formę ostrej, podłużnej litery "V" z bardzo mocnymi spadekiami z obu stron i spłaszczeniem w samej osi. Rzeźba dna jest twarda, z przewagą drobnego żwiru i piasku krasowego, pokryta osadami dopiero w największych wgłębieniach rynny głównej. Okolice okalane są majestatycznym lasem i wysokimi skarpami, co gwarantuje wspaniałą osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80573, 'Zbiornik Dychowski', 'jezioro-dychowskie', 'LAKE', '51.98603393468427', '15.04418440964657', 'Lubuskie', 'Dychów', 'Jezioro Dychowskie (Zbiornik Dychów) to unikat na wędkarskiej mapie Polski. Służy jako zbiornik retencyjny i górny dla miejscowej elektrowni szczytowo-pompowej (zasilany wodami rzeki Bóbr). Z tego powodu warunki tu panujące przypominają ekstremalną, wezbraną rzekę. Poziom wody w ciągu jednej doby potrafi wahać się o kilka metrów(!), a betonowe wały, wyłożone płytami pod ostrym kątem, oraz porywiste prądy sprawiają, że to woda piekielnie trudna, wręcz "zabójcza" dla sprzętu i nieostrożnych pływaków. Dno wyłożone jest betonem i wypłukanym kamieniem, pełno tu prądów wstecznych i rynien rzecznych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80574, 'Jezioro Raduszeckie', 'jezioro-raduszeckie', 'LAKE', '52.01634131837348', '15.064187651438823', 'Lubuskie', 'Stara Woda', 'Niewielkie, nizinne jezioro znane w rejonie jako Stara Woda lub Raduszec, będące de facto klasycznym, silnie zeutrofizowanym i bardzo wypłyconym jeziorem polnym. Misa jeziorna przypomina płaski talerz. Przez większą część lata woda kwitnie i zarasta podwodnymi "dywanami" rogatka, ograniczając dostępne do łowienia miejsca do niewielkich oczek wyciętych siłowo w grążelach i moczarce. Dno jest tu ekstremalnie miękkie, okryte ciemnym mułem i grubym osadem z butwiejących liści trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80575, 'Jezioro Bytnickie', 'jezioro-bytnickie', 'LAKE', '52.14250454850183', '15.175648720127901', 'Lubuskie', 'Bytnica', 'Jezioro Bytnickie leży w samym sercu Puszczy Bytnickiej. To niezwykle klimatyczny, rynnowy zbiornik polodowcowy, cechujący się umiarkowanymi spadkami dna i sporą zawartością wód z podziemnych źródeł, co czyni go chłodniejszym i dobrze natlenionym w okresie letnich upałów. W pasie brzegowym występują wyraziste piaszczyste spady schodzące w rynnę pokrytą miękkim, biologicznym osadem. Bogata roślinność przybrzeżna z domieszką zwalonych pni i dębów tworzy wyśmienitą kryjówkę dla narybku.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80576, 'Jezioro Kolno', 'jezioro-kolno-2', 'LAKE', '52.15072097576266', '15.156250984547817', 'Lubuskie', 'Tarnów', 'Położone zaledwie kilka kilometrów od Bytnickiego, a jednak o zupełnie innej, surowej, wręcz "syberyjskiej" specyfice. Kolno to dzikie, mocno torfowe jezioro, które podlega naturalnym procesom silnego zarastania i spłycania. Często mianowane do statusu rezerwatu, otoczone zewsząd niedostępnymi trzęsawiskami, bagnami i olsami, stanowi ostoję zwierzyny. Woda latem ma charakterystyczny, ciemny, herbaciany kolor, a dno przypomina bagnistą, niestabilną gąbkę, bez śladu kamieni.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80577, 'Jezioro Drzewko', 'jezioro-drzewko', 'LAKE', 54.363712, 17.860465, 'Pomorskie', 'Kamienica Królewska', 'Drzewko to kameralny, śródleśny zbiornik o charakterze wytopiskowym. Posiada piaszczysto-muliste dno i przyzwoitą klasę czystości. Maksymalna głębokość nie przekracza 6 metrów. Jezioro jest wyciszone, stanowiąc doskonałe miejsce dla ryb spokojnego żeru szukających schronienia w pasach grążeli żółtych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80578, 'Jezioro Jelito', 'jezioro-jelito', 'LAKE', '52.09787946513198', '15.285118092392205', 'Lubuskie', 'Sycowice', 'Jelito, ukryte głęboko w lubuskich lasach, to niezwykle interesujące, głębokie i niesamowicie przejrzyste jezioro rynnowe o cechach niemal krasowych. Charakteryzuje się bardzo stromymi, piaszczysto-żwirowymi stokami, które opadają natychmiastowo na duże głębokości niemal zaraz za krótką, jasną plażą. Brak istotnych dopływów polnych i osłona z lasu sprawia, że woda rzadko tu kwitnie, pozwalając na swobodne nurkowanie i podglądanie raf przybrzeżnych. Roślinność wodna kończy się gwałtownie z powodu braku oparcia na twardym spadzie rynny.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80579, 'Jezioro Niesłysz', 'jezioro-nieslysz', 'LAKE', '52.22323835436225', '15.397791120598624', 'Lubuskie', 'Świebodzin', 'Niesłysz to absolutny gigant na Ziemi Lubuskiej (blisko 500 ha), perła Pojezierza Łagowskiego, jezioro o niezwykle zawiłej, polodowcowej linii brzegowej, pełnej półwyspów, głębokich rynien i wypłyceń wyspowych. Z głębokością maksymalną sięgającą blisko 35 metrów, wybitną pierwszą klasą czystości wód i piaszczystym, twardym dnem, stanowi doskonały ekosystem dla sielawy – podstawy piramidy pokarmowej w tym akwenie. Ukształtowanie i batymetria to niesamowite, podwodne góry i "blaty" na środku ogromnych głębin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80580, 'Jezioro Wilkowskie', 'jezioro-wilkowskie', 'LAKE', '52.24741798077592', '15.468000623113978', 'Lubuskie', 'Wilkowo / Świebodzin', 'Jezioro Wilkowskie, leżące na obrzeżach Świebodzina, to akwen o wybitnie urozmaiconej charakterystyce polodowcowej, pełne wcięć brzegowych i skomplikowanych podwodnych rzeźb. Pomimo mniejszego rozmiaru niż potężny sąsiad (Niesłysz), Wilkowskie kryje niesamowite "dołki" dochodzące do 23 metrów, otoczone zróżnicowanym dnem – od ostrych, usianych wapieniem uskoków, po gliniaste wzniesienia zwane blatem sandaczowym. Woda cechuje się dużą zawartością fitoplanktonu dającego letni, lekko mętny, ale zdrowy kolor zielonkawy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80581, 'Jezioro Pień', 'jezioro-pien', 'LAKE', '52.27237128983476', '15.438260495819762', 'Lubuskie', 'Pień / Świebodzin', 'Niewielkie, ale niezwykle urzekające i wybitnie głębokie (szczególnie jak na ten rozmiar lustra wody) jezioro w urokliwej osłonie Lasów Lubuskich. Profil jeziora jest bardzo regularny – po minięciu bardzo szybkiej, ostrej strefy litoralnej porośniętej skąpym grążelowym wąsem, dno "zrywa się" w ponad 20-metrową ciemną rynnę. Posiada bardzo wyraziste źródła podziemne, czyniące tę wodę niesamowicie zimną, krystaliczną i utrudniającą wegetację intensywnym roślinom. Brak twardej linii cywilizacyjnej dodaje dzikości.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80582, 'Jezioro Goszcza', 'jezioro-goszcza', 'LAKE', '52.30177302867341', '15.432767331840546', 'Lubuskie', 'Lubrza', 'Goszcza to jezioro łączące wędkarskie emocje z niesamowitymi walorami turystyki kajakowej – stanowi kluczowy punkt skrzyżowania wielu rzek i kanałów wodnych regionu obok Lubrzy. Linia dna ukształtowana jest bardzo faliście, uświadczymy tu rozległe 3-metrowe blaty piaszczyste i muliste doły osiągające 10 metrów w dawnych szlakach wyrwań polodowcowych. Wokół brzegów wybudowano rozległą bazę ośrodków, a brzegi mocno oczyszczono z zalegających kłód drzew dla bezpieczeństwa kajaków. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80583, 'Jezioro Płużnickie', 'jezioro-pluznickie', 'LAKE', 53.287183, 18.786793, 'Kujawsko-Pomorskie', 'Płużnica', 'Płużnickie to urokliwa rynna położona bezpośrednio przy miejscowości Płużnica. Charakteryzuje się pofałdowanym dnem i dobrymi warunkami tlenowymi. Wędkarze cenią je za populację dużego okonia i sandacza, który trzyma się twardych uskoków w centralnej części jeziora.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80584, 'Jezioro Paklicko Wielkie', 'jezioro-paklicko-wielkie', 'LAKE', '52.32892549632785', '15.489850047755235', 'Lubuskie', 'Świebodzin', 'Jezioro Paklicko Wielkie to niesamowicie urozmaicony, potężny akwen rynnowy (blisko 200 ha), w którym głębokości rzędu 22 metrów przeplatają się z rozległymi wypłyceniami i podwodnymi górami. Dno jeziora jest bardzo twarde, wysadzane wapiennymi kamieniami oraz żwirem, a stoki bardzo stromo opadają w chłodny mrok. Linia brzegowa to istny labirynt zatok, porośniętych liliami wodnymi i szerokim pasem trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80585, 'Jezioro Paklicko Małe', 'jezioro-paklicko-male', 'LAKE', '52.37076358444849', '15.453801158896983', 'Lubuskie', 'Świebodzin', 'Mniejszy, bardziej dziki i płytszy brat Paklicka Wielkiego, schowany w gęstej otulinie leśnej. Paklicko Małe ma charakter dużo bardziej eutroficzny, z dnem wysłanym miąższym, organicznym mułem i resztkami liści z okolicznych drzew. Głębokość maksymalna rzadko przekracza 5-6 metrów, a woda w miesiącach letnich potrafi obficie zakwitnąć. Zbiornik jest bardzo mocno obrośnięty barierą roślinności nawodnej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80586, 'Jezioro Wielickie', 'jezioro-wielickie', 'LAKE', '52.219372140268995', '14.959330561856058', 'Lubuskie', 'Gubin', 'Jezioro Wielickie to klasyczny przedstawiciel wąskich, bardzo wydłużonych rynien polodowcowych o piaszczysto-żwirowym, chłodnym dnie. Opada ono nierzadko gwałtownymi, uskokowymi stokami, na których żerują wyborne ryby. Znaczne zasoby wód podziemnych czynią ten akwen dobrze natlenionym, o wodzie przezroczystej i słabo ulegającej zakwitom w środku letnich upałów. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80587, 'Jezioro Głębiniec', 'jezioro-glebiniec', 'LAKE', '52.321896169036215', '14.756426815682081', 'Lubuskie', 'Cybinka', 'Ukryte z dala od zgiełku miast, tajemnicze jezioro leśne o bardzo trafnej nazwie. Głębiniec to typowy "lejek" krasowy osadzony w borach, z niesamowicie czystą, wręcz szmaragdową wodą i błyskawicznie uciekającym w dół piaszczystym dnem. Głębokość maksymalna robi wrażenie, a warstwa organicznego osadu występuje tylko w samym centrum rynny. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80588, 'Jezioro Lubieńskie', 'jezioro-lubienskie', 'LAKE', '52.31098276303847', '14.907488825110486', 'Lubuskie', 'Rzepin', 'Urokliwy, wydłużony akwen, w którym dzikość przeplata się z dużą zasobnością wędkarską. Jezioro charakteryzuje się łagodniejszymi stokami dna niż okoliczne rynny, oferując zróżnicowane podłoże od piaszczystego, przez żwirowe, aż po bogate w okrzemki w płytszych zatokach. Posiada obfite trzcinowiska i sporą ilość wysepek roślinnych rdestnicy dających świetne schronienie narybkowi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80589, 'Jezioro Boczowskie (Rzepińskie)', 'jezioro-boczowskie', 'LAKE', '52.31983628366331', '14.946422946921567', 'Lubuskie', 'Rzepin', 'Nieduży, ale niesłychanie rybny i bardzo lubiany przez lokalnych wędkarzy zbiornik usadowiony u obrzeży Rzepina. Jest to jezioro w dużej mierze eutroficzne, o misowatym profilu i równomiernie układającym się dnie z mniejszymi, mulistymi rynnami. Roślinność brzegowa i podwodna jest tu dość silnie rozwinięta, oferując mnóstwo mikromiejscówek pod drapieżniki obok pasów moczarki i wywłócznika.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80590, 'Jezioro Garbicz', 'jezioro-garbicz', 'LAKE', '52.3034381615301', '14.995668304039711', 'Lubuskie', 'Torzym', 'Jezioro Garbicz (kojarzone z popularnym festiwalem muzycznym na jego brzegach) to duży, wspaniale uformowany akwen rynnowy o bardzo wysokiej przejrzystości wody, zawdzięczanej wapiennemu, filtrującemu podłożu. Maksymalne głębokości przebijają kilkanaście metrów, a stoki piaszczysto-żwirowe zapewniają zjawiskowe formacje denna usiane dołkami i naturalnymi ukryciami. Woda bywa kryształowa na zjazdach rynny i pozwala obserwować dno z kilku metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80591, 'Jezioro Busko', 'jezioro-busko', 'LAKE', '52.381465069197915', '14.849756134069413', 'Lubuskie', 'Ośno Lubuskie', 'Jezioro Busko to niesamowicie cichy, kameralny, wybitnie leśny zbiornik znajdujący się nieco na uboczu popularnych traktów turystycznych. Z głębokością oscylującą w rejonach zaledwie kilku metrów ma formę obniżenia polodowcowego na terenie równinnym. Posiada niezwykły urok, bardzo dużo cienia z obwisłych koron drzew dębowych i sosnowych na brzegach oraz podłoże miękkie, liściasto-torfowe, tworzące znakomitą bazę bentosu (pokarmu dla dna).
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80592, 'Jezioro Grzybno', 'jezioro-grzybno', 'LAKE', '52.44575456854675', '14.837224854048948', 'Lubuskie', 'Ośno Lubuskie', 'Płytkie, eutroficzne jeziorko okalające Ośno Lubuskie, charakteryzujące się wybitną tendencją do szybkiego nagrzewania w okresie letnim, a tym samym – silną wegetacją roślinną i regularnymi zakwitami fitoplanktonu odżywiającego mniejsze gatunki. Dno jest równe, poduszkowato miękkie, ze znaczną powłoką czarnego mułu, otoczone szczelnym kordonem roślin wynurzonych ograniczających pole manewru wędkom.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80593, 'Jezioro Reczynek', 'jezioro-reczynek', 'LAKE', '52.46342145952584', '14.8675989565576', 'Lubuskie', 'Ośno Lubuskie', 'Reczynek to perła miejska i turystyczna Ośna Lubuskiego, pięknie wkomponowana w krajobraz zaraz za murami miasteczka. Pomimo typowo rekreacyjnego profilu, posiada zjawiskową morfologię: to relatywnie głębokie (powyżej 12m), niesamowicie czyste rynnowe obniżenie z bardzo twardym, kredowym i piaszczystym dnem. Szerokie pasaże spacerowe i przygotowane kładki nadają jezioru charakter ucywilizowany i mocno oblegany przez plażowiczów, ale nocą to prawdziwy rybny skarbiec.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80594, 'Jezioro Wielkie', 'jezioro-wielkie', 'LAKE', '52.71115092488596', '14.820899209273957', 'Zachodniopomorskie', 'Witnica / Gorzów Wlkp.', 'Jezioro Wielkie (pogranicze lubusko-zachodniopomorskie) to fenomenalny i bardzo rozległy (jak na region) zbiornik polodowcowy, cechujący się bogatą linią brzegową urozmaiconą mnóstwem piaszczystych półwyspów, wysepek i urokliwych zatok wciętych w starodrzew. Posiada rzeźbę dna niczym pole bitwy: twarde wzniesienia zaledwie metr pod powierzchnią obok ciemnych rowów sięgających ponad 10 metrów głębokości. Woda czysta, żyzna, chłodna u dna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80595, 'Jezioro Witoczno', 'jezioro-witoczno', 'LAKE', '53.87560765989066', '17.512862535864677', 'Pomorskie', 'Swornegacie', 'Jezioro Witoczno to kolejny kluczowy akwen w systemie rzeki Brdy, położony tuż obok Swornegaci. Jest to jezioro przepływowe o powierzchni ok. 100 ha, charakteryzujące się rozległymi piaszczystymi płyciznami u wylotu rzeki i głęboką rynną (do 10 m) w części środkowej. Woda jest żyzna, dobrze natleniona i posiada lekko herbaciany kolor, co jest typowe dla wód puszczańskich przepływających przez torfowiska.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80596, 'Jezioro Postne', 'jezioro-postne', 'LAKE', '52.78621336595114', '14.844730953032997', 'Zachodniopomorskie', 'Barlinek', 'Jezioro Postne w okolicach Barlinka to niezwykle chłodna, głęboka rynna usadowiona wśród falistych wzgórz Puszczy Barlineckiej. Wody o bardzo wysokiej widoczności opadają z płytkich, wąskich wlotów w mroczną toń po piaszczysto-wapiennych schodach, co sprzyja egzystencji ryb pelagicznych. Osady denne w głębinach kumulują znikomą ilość szlamu, ustępując miejsca twardym strukturom marglowym. Z racji leśnego zacisza woda ta jest fantastyczną oazą rzadko mąconą przez turystykę, ustronną od miast.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80597, 'Jezioro Ostrowieckie', 'jezioro-ostrowieckie', 'LAKE', '52.81957844273142', '14.777182201647003', 'Zachodniopomorskie', 'Barlinek / Pełczyce', 'Duże, niesamowicie urozmaicone jezioro z wyraźną, wysoką i pięknie wkomponowaną wyspą centralną, która dzieli batymetrię na dwa niezależne nurty i rynny o stromych spadkach. Jezioro Ostrowieckie posiada twarde jak skała gliniasto-żwirowe stoki, a jego zróżnicowana, popękana pod względem pęknięć podwodnych skorupa potrafi uciec błyskawicznie na ogromne głębokości niemal 30 metrów, dając nieskazitelną przejrzystość wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80598, 'Jezioro Narost', 'jezioro-narost', 'LAKE', '52.88416671149207', '14.507573630217435', 'Zachodniopomorskie', 'Chojna', 'Jezioro Narost to wybitny i podłużny, polodowcowy zbiornik usadowiony w bardzo głębokiej szczelinie geologicznej w rejonie Chojny. Dno tego krystalicznego rezerwuaru opada z nieubłaganą ostrością po twardych jak beton pokładach skał i osadów kredowych, ukrywając potężne rynny (powyżej 25m) chłodnej, wysoce natlenionej toni. Brak zurbanizowania po obu stronach wydłużonych brzegów nadaje mu charakter wręcz skandynawski.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80599, 'Jezioro Morzycko', 'jezioro-morzycko', 'LAKE', '52.86406649761718', '14.409039999820315', 'Zachodniopomorskie', 'Moryń', 'Jezioro Morzycko w Moryniu to absolutny ewenement geologiczny, potężna kryptodepresja i jedno z najgłębszych jezior w skali całego kraju, którego oficjalne badania wskazują na zawrotne 60 metrów głębokości pod powierzchnią krystalicznie czystej, górskiej wręcz wody! Misa krasowa urywa się po krótkich, pięknych plażach Morynia wręcz kaskadowo, podwodnymi piaszczysto-marglowymi klifami. Przerażająca głębia to środowisko obfite w najtrudniejsze w polowaniu gatunki ryb prądolubnych i chłodnych rewirów wód.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80600, 'Jezioro Mętno', 'jezioro-metno', 'LAKE', '52.9323330135596', '14.363978887884048', 'Zachodniopomorskie', 'Chojna', 'Jezioro Mętno, całkowicie odwrócone pod kątem budowy od głębokiego sąsiada (Morzycka), to bardzo duże, niemal idealnie okrągłe i płytkie jezioro eutroficzne. Nazwa idealnie odzwierciedla naturę – woda bywa zawiesista i niska w przezierności latem, gwałtownie nagrzewa i silnie zarasta na niemal każdym metrze potężnej, płaskiej tacy swojego mulistego dna osiągającego ok 3.5m głębokości maksimum.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80601, 'Jezioro Piecki', 'jezioro-piecki', 'LAKE', '53.91293883852474', '17.555755448146265', 'Pomorskie', 'Męcikał', 'Jezioro Piecki to uroczy, leśny akwen rynnowy o bardzo czystej wodzie i piaszczystym dnie. Posiada wyraźnie zarysowaną rynnę centralną i strome spadki od strony południowej. Brzegi są wysokie, porośnięte starym lasem, co chroni jezioro przed wiatrem i zapewnia wędkarzom komfort łowienia nawet w gorszą pogodę. Roślinność podwodna jest umiarkowana, z przewagą ramienic i rdestnicy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80602, 'Jezioro Ostrów', 'jezioro-ostrow', 'LAKE', '52.941489160442394', '14.320119406737506', 'Zachodniopomorskie', 'Chojna / Ostrów', 'Niewielkie i malowniczo zagubione pośród pól i małych zadrzewień akwen w powiecie gryfińskim. Charakteryzuje go regularny, rynnowy wręcz zjazd i wyrównane dno po środku tworzące spłaszczoną nieckę ok. 6 metrów przy twardych krawędziach spadów usianych trzciną i wiankiem zwalonych gałęzi dających super chwyt dla narybku. Woda utrzymuje się tu klarowna, ze zjawiskowo chłodnym nurtem głębin osadzających opadły detrytus z liści i gałęzi u dolnej krawędzi dołów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80603, 'Jezioro Strzeszowskie', 'jezioro-strzeszowskie', 'LAKE', '52.99111672380778', '14.611181186766817', 'Zachodniopomorskie', 'Trzcińsko-Zdrój', 'Jezioro Strzeszowskie (okolice Trzcińska-Zdroju) to fantastyczny, dziki i nieszablonowy akwen w mocno zwężonej rynnie polodowcowej, której brzegi uciekają pod górę podnosząc krajobraz, nadając wręcz pogórzański wygląd. Słynie z ostro pikującego zaledwie na przestrzeni kilku metrów dna uciekającego na 15 metrów chłodnego mroku i niesamowitego stopnia zakrzewienia opasek pożeglowych rdzawą trzciną u litoralu dającego wręcz niespenetrowane ściany do uderzeń szczupaka i lina u samych fundamentów gąszczy tataraku.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80604, 'Jezioro Karpino', 'jezioro-karpino', 'LAKE', '53.63112256733718', '14.406165579635294', 'Zachodniopomorskie', 'Police', 'Jezioro Karpino to urokliwy, niezbyt głęboki akwen leżący na obrzeżach Puszczy Wkrzańskiej. Należy do wód wybitnie eutroficznych, charakteryzujących się płaską misą denną, obfitą w miękkie osady organiczne i bardzo gęstą roślinność litoralną. Trzcinowiska tworzą tu niemal lity mur, a w okresie letnim woda bardzo szybko się nagrzewa, sprzyjając powstawaniu zjawiska zakwitu fitoplanktonu. Batymetria jest mało zróżnicowana, dominują rozległe blaty o głębokości od 1 do 2.5 metra.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80605, 'Jezioro Nowowarpieńskie', 'jezioro-nowowarpienskie', 'LAKE', '53.71138546872114', '14.283921221393294', 'Zachodniopomorskie', 'Nowe Warpno', 'Jezioro Nowowarpieńskie to unikatowy akwen – w rzeczywistości jest to ogromna, płytka zatoka Zalewu Szczecińskiego o statusie wód morskich wewnętrznych (choć łowi się tu ryby słodkowodne). Woda ta podlega ciągłym mieszaniom, a jej poziom i uciąg są bezpośrednio uzależnione od kierunku i siły wiatru (tzw. cofki z Bałtyku). Średnia głębokość oscyluje w granicach 1.5 - 2 metrów, a dno ukształtowane jest w formie rozległych, piaszczysto-mulistych tac z rzadszymi płatami twardszego żwiru u wylotów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80606, 'Jezioro Myśliborskie (Wielkie)', 'jezioro-mysliborskie-wielkie', 'LAKE', '53.65213299937853', '14.285439408035142', 'Zachodniopomorskie', 'Trzebież / Police', 'Schowane w głębi Puszczy Wkrzańskiej Jezioro Myśliborskie (nie mylić z tym w Myśliborzu) to dystroficzno-eutroficzny, bardzo dziki zbiornik. Dno jest wysoce muliste, okryte grubą warstwą opadłych liści i gałęzi, z mroczną, herbacianą tonią typową dla akwenów leśnych. Brzegi w większości opadają łagodnie, przechodząc w trudne do przebycia trzęsawiska, olsy i szerokie pasy gęstej pałki wodnej. To miejsce, w którym rządzi niezakłócona niczym natura.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80607, 'Jezioro Jarnatowskie', 'jezioro-jarnatowskie', 'LAKE', 52.531368, 15.166626, 'Lubuskie', 'Jarnatów', 'Jezioro Jarnatowskie to malowniczy akwen rynnowy o powierzchni ok. 30 ha. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 6-8 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są urozmaicone, częściowo zalesione, z urokliwym pałacem w tle.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80608, 'Jezioro Warnowo Zachodnie', 'jezioro-warnowo-zachodnie', 'LAKE', '53.934413244916094', '14.5435796192005', 'Zachodniopomorskie', 'Warnowo / Międzyzdroje', 'Pierwsze z perłowego naszyjnika jezior Wolińskiego Parku Narodowego. Warnowo Zachodnie to wydłużony, rynnowy zbiornik polodowcowy, cechujący się umiarkowanymi głębokościami i wodą o lekko zabarwionym, leśnym odcieniu. Obejmuje go rygorystyczny regulamin WPN, co chroni ten akwen przed presją komercyjną i tłumami. Dno urozmaicone, piaszczysto-organiczne, stromo opadające od wschodniego brzegu. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80609, 'Jezioro Warnowo Wschodnie', 'jezioro-warnowo-wschodnie', 'LAKE', '53.93547435019772', '14.551604788451385', 'Zachodniopomorskie', 'Warnowo / Międzyzdroje', 'Sąsiad Warnowa Zachodniego, połączony z nim wąskim, płytkim przesmykiem. Akwen o bardzo zbliżonej charakterystyce batymetrycznej, rynnowy, mocno zalesiony ze wspaniałymi, starymi dębami zwieszającymi się nad lustrem wody. Głębokości oscylują tu w granicach 5-7 metrów w rynnie środkowej. Dno posiada twardsze, piaszczyste wypłycenia od strony południowej, które są znakomitym łowiskiem wiosennym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80610, 'Jezioro Czajcze', 'jezioro-czajcze', 'LAKE', '53.94077947186358', '14.563106100532863', 'Zachodniopomorskie', 'Warnowo', 'Jezioro Czajcze to niewątpliwie najbardziej znany i niezwykle widowiskowy akwen Wolińskiego Parku Narodowego. Charakteryzuje się niesamowitym kształtem rogalika, z głęboko wciętym półwyspem w środkowej części, przypominającym podkowę. Ukształtowanie dna jest tu fascynujące – strome i zalesione brzegi zrzucają się gwałtownie do głębokich rynien (nawet ponad 12 metrów głębokości). Dno jest twarde, wysadzane wapieniami i powalonymi pniami drzew, co czyni jezioro idealnym siedliskiem dla dużych drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80611, 'Jezioro Domyślowskie', 'jezioro-domyslowskie', 'LAKE', '53.93753332273523', '14.570026199825607', 'Zachodniopomorskie', 'Domysłów', 'Kolejne z malowniczych, rynnowych jezior wyspy Wolin, ukryte w głębokiej polodowcowej bruździe. Domyślowskie posiada urokliwą, spokojną wodę o wyraźnie ciemniejszym, zabarwionym humusami odcieniu, co jest wynikiem znacznego otoczenia lasów liściastych i borów. Linia brzegowa jest stosunkowo prosta, a dno opada równomiernie do głębokości kilku metrów. Miękki, bogaty w bentos osad denny stwarza idealne warunki dla ryb żerujących na dnie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80612, 'Jezioro Żółwińskie', 'jezioro-zolwinskie', 'LAKE', '53.94671535599342', '14.587203066177233', 'Zachodniopomorskie', 'Żółwino', 'Jezioro Żółwińskie to bezdyskusyjnie najczystsze i najgłębsze (blisko 30 metrów!) jezioro w tym regionie wyspy Wolin. Jego krasowo-rynnowy charakter, strome, porośnięte buczyną urwiska brzegowe i zjawiskowo przejrzysta woda przypominają wręcz akweny górskie. Dno piaszczysto-żwirowe opada tu w niesamowitym tempie, co eliminuje bujną roślinność zanurzoną, ograniczając ją do rzadkich pasów w nielicznych płytszych zatoczkach na północnym skraju.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80613, 'Jezioro Zatorek', 'jezioro-zatorek', 'LAKE', '53.96817799474028', '14.584484791187483', 'Zachodniopomorskie', 'Międzywodzie / Warnowo', 'Zatorek to urokliwe, bardzo płytkie i mocno zarośnięte jezioro położone na obrzeżach Parku. Jego charakter jest wybitnie eutroficzny, wręcz dystroficzny (bagienny). Średnia głębokość ledwie przekracza metr, a dno to potężna, kilkudziesięciocentymetrowa warstwa osadu torfowego i gnijącej roślinności. Lustro wody latem obficie pokrywają dywany nenufarów, wywłócznika i rdestnicy. Woda ma brunatny, rdzawy kolor.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80614, 'Jezioro Recze', 'jezioro-recze', 'LAKE', '53.96813483038003', '14.606554325474765', 'Zachodniopomorskie', 'Kołczewo', 'Jezioro Recze to mały, kameralny, typowo linowo-karasiowy zbiornik ukryty w zagłębieniu terenu niedaleko Kołczewa. Należy do wód żyznych, dość szybko nagrzewających się wczesną wiosną, co czyni go atrakcyjnym już na początku sezonu wędkarskiego. Linia brzegowa urozmaicona, z gęstym pasem oczeretów i licznymi, obalonymi przez bobry drzewami, które stanowią doskonałe, naturalne kryjówki dla ryb. Maksymalna głębokość nie przekracza kilku metrów, a dno jest powlekane organicznym mułem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80615, 'Jezioro Kołczewo', 'jezioro-kolczewo', 'LAKE', '53.9588943881608', '14.610502537132323', 'Zachodniopomorskie', 'Kołczewo', 'Jezioro Kołczewo, położone tuż przy znanych polach golfowych, to dość spory i wędkarsko zróżnicowany akwen na wyspie Wolin. W odróżnieniu od rezerwatowych wód obok, tętni tu bardziej otwarte życie wędkarskie. Dno układa się w rynny i płaskie łachy o żwirowo-piaszczystym charakterze, z naniesionym mułem w najgłębszych punktach rynny (ok. 6-8 m). Woda posiada zadowalającą klarowność przez większość sezonu. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80616, 'Jezioro Koprowo', 'jezioro-koprowo', 'LAKE', '53.97717131424214', '14.652538116462686', 'Zachodniopomorskie', 'Świętouść / Kołczewo', 'Jezioro Koprowo to gigant wyspy Wolin – jest jej największym naturalnym akwenem, zajmującym niemal 500 hektarów. Cechą absolutnie dominującą na tym zbiorniku jest wiatr i potężna fala, gdyż jezioro to rozległa, płytka (średnio nieco ponad 1.5m, max 3m) misa odsłonięta na bałtyckie wiatry. Dno Koprowa jest bardzo muliste i gładkie, niemal zupełnie pozbawione rynien i uskoków. Lustro wody przerywane jest wielkimi wysepkami z trzcin. Posiada bezpośrednie, choć często zarastające połączenie z morzem przez rzekę Lewieńską.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80617, 'Jezioro Woświń', 'jezioro-woswin', 'LAKE', '53.54189133712302', '15.407189885631361', 'Zachodniopomorskie', 'Cieszyno', 'Jezioro Woświń na Pojezierzu Ińskim to gigant pod każdym względem – potężny rynnowy zbiornik o powierzchni ponad 800 hektarów, który swoim surowym, głębokim charakterem przypomina jeziora szwedzkie. Z niesamowitą głębokością maksymalną przekraczającą 28 metrów, bardzo wysoką I klasą czystości i krystaliczną wodą pełną sielawy, Woświń to wyzwanie dla najlepszych. Brzegi są wybitnie uskokowe, piaszczysto-żwirowe i bardzo twarde, szybko gubiące się w ciemnogranatowej toni.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80618, 'Jezioro Węgorzyno', 'jezioro-wegorzyno', 'LAKE', '53.539246129821485', '15.577665078197269', 'Zachodniopomorskie', 'Węgorzyno', 'Jezioro Węgorzyno to duma tytułowego miasta i klasyczny przykład pięknego, polodowcowego jeziora rynnowego, mocno wcinającego się w krajobraz. Posiada batymetrię typową dla tego profilu: ostre krawędzie brzegowe urywające się błyskawicznie po twardych piaszczysto-gliniastych zjazdach na pokaźne głębokości rzędu kilkunastu metrów. Dno obfituje w górki i "przewężenia", na których nurt wietrzny miesza masę wody, doskonale dotleniając głębsze partie żwirowisk. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80619, 'Jezioro Piecki Małe', 'jezioro-piecki-male', 'LAKE', '53.91507270114453', '17.56821337061133', 'Pomorskie', 'Męcikał', 'Niewielkie, kameralne "oczko" leśne o charakterze eutroficznym, położone w bliskim sąsiedztwie jeziora Piecki. Akwen jest płytki (max 4 m), z dnem w dużej mierze mulistym i bardzo bogatą roślinnością litoralną. Woda jest tu cieplejsza i mniej przejrzysta niż w większym sąsiedzie, co czyni to miejsce idealnym tarliskiem dla ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80620, 'Jezioro Przytońskie', 'jezioro-przytonskie', 'LAKE', '53.5389400881814', '15.621138321990681', 'Zachodniopomorskie', 'Węgorzyno', 'Jezioro Przytońskie (połączone z Węgorzynem) to głęboka na ponad 30 metrów, rynnowa perła Pojezierza Ińskiego, stanowiąca potężny, wąski lej polodowcowy. Woda tego akwenu to absolutny kryształ o wysokiej przejrzystości, skrywająca na samym dnie potężne zapadliska kredowo-wapienne i ogromne piaszczyste blaty na zboczach. Porośnięte majestatycznymi lasami dębowo-sosnowymi, brzegi są niezwykle strome, a urokliwy brak gęstej zabudowy nadaje jezioru surowy i dziki wyraz.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80621, 'Jezioro Przytoń', 'jezioro-przyton', 'LAKE', '53.55082308487702', '15.597105729581617', 'Zachodniopomorskie', 'Węgorzyno', 'Jezioro Przytoń to klasyczny, głęboki akwen rynnowy, pocięty malowniczymi skarpami i otoczony w dużej mierze lasem mieszanym. Zbiornik charakteryzuje się bardzo zróżnicowanym dnem – znajdziemy tu łagodne, piaszczyste zatoki przechodzące w twarde, pofalowane blaty, które ostatecznie gwałtownie urywają się w chłodną, kilkunastometrową głębinę. Woda wykazuje bardzo dobrą przejrzystość, co jest cechą charakterystyczną tego pojezierza.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80622, 'Jezioro Brzeźniak', 'jezioro-brzezniak', 'LAKE', '53.53287717191774', '15.680259930052856', 'Zachodniopomorskie', 'Węgorzyno', 'Jezioro Brzeźniak to urokliwy, bardzo żyzny (eutroficzny) zbiornik o umiarkowanych głębokościach, przypominający formą rozległą, płaską misę. Brzegi akwenu ulegają naturalnemu procesowi zarastania – gęsty pas trzciny pospolitej, tataraku oraz połacie grążeli żółtych latem skutecznie zamykają dostępy do otwartej wody. Dno jest wysoce muliste, okryte ciemnym osadem i detrytusem, co gwarantuje wspaniałą stołówkę dla bentosowych organizmów i ryb ryjących.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80623, 'Jezioro Żabice (Żabickie)', 'jezioro-zabice', 'LAKE', '53.54465987003438', '15.692190395570213', 'Zachodniopomorskie', 'Węgorzyno', 'Schowane w głuszy niewielkie, urokliwe jeziorko o bardzo leśnym, dystroficznym charakterze. Żabice to akwen chroniony ścianą drzewostanu przed wiatrami, co sprawia, że jego toń niemal zawsze przypomina gładkie lustro. Woda ma tu charakterystyczny, lekko brunatny, herbaciany odcień, wynikający z obecności kwasów humusowych, a dno opada dość łagodnie w torfowo-liściastą rynnę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80624, 'Jezioro Pucianowo', 'jezioro-pucianowo', 'LAKE', '53.57437458135308', '15.659306355305054', 'Zachodniopomorskie', 'Węgorzyno', 'Pucianowo to piękny, rynnowy zbiornik polodowcowy, cechujący się umiarkowanymi, ale twardymi uskokami dna. Piaszczyste wypłycenia od strony wschodniej idealnie komponują się z gwałtownymi, ciemnymi spadekiami przechodzącymi w żwirowe koryta. Woda w jeziorze potrafi być niezwykle przejrzysta przed nadejściem pełni lata, pozwalając echosondom na doskonałe mapowanie podwodnych kryjówek i skupisk ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80625, 'Jezioro Białynia', 'jezioro-bialynia', 'LAKE', '53.96686067107847', '16.960983468646823', 'Pomorskie', 'Miastko / Biała', 'Jezioro Białynia to malowniczy, śródleśny akwen rynnowy o powierzchni ok. 40 ha. Charakteryzuje się bardzo czystą wodą i twardym dnem. Batymetria jest regularna – rynna o głębokości do 10-12 metrów biegnie przez środek jeziora. Brzegi są wysokie, porośnięte starym lasem sosnowym, co nadaje akwenowi dziki i ustronny charakter. Roślinność wodna jest skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80626, 'Jezioro Zajezierze (Zajezierskie)', 'jezioro-zajezierze', 'LAKE', '53.57952513158854', '15.728213393875066', 'Zachodniopomorskie', 'Łobez / Węgorzyno', 'Jezioro Zajezierze to średniej wielkości, ale niezmiernie ciekawy hydrologicznie zbiornik okalany przez pasy dzikich łąk i zagajników. Charakteryzuje się naprzemiennie występującymi twardymi blatami, które tworzą podwodne "półki" (idealne stołówki białorybu) oraz wgłębieniami, w których gromadzi się bogaty osad. Zrównoważony bilans roślinności litoralu pozwala na swobodne wędkowanie bez konieczności siłowego karczowania łowiska.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80627, 'Jezioro Cianowo', 'jezioro-cianowo', 'LAKE', '53.563101768025994', '15.72168560413261', 'Zachodniopomorskie', 'Łobez', 'Cianowo to typowe, śródleśne "oczko" rynnowe, mocno zagłębione w terenie i charakteryzujące się wybitną obfitością podwodnego ziela latem. Rzeźba dna ucieka dośrodkowo, formułując głęboki, mulisty dół na środku akwenu. Brzegi są podmokłe, zwaliste i mocno zalesione, co ułatwia rybom chowanie się w gąszczu korzeni obalonych drzew. Jezioro przez większość roku uchodzi za bardzo ciche i wyludnione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80628, 'Jezioro Małe Długie', 'jezioro-male-dlugie', 'LAKE', '53.56748520427816', '15.774905266227899', 'Zachodniopomorskie', 'Drawsko Pomorskie', 'Jak sama nazwa wskazuje, jezioro Małe Długie to wąska, wybitnie wydłużona rynna przypominająca szeroką rzekę uwięzioną w polodowcowej bruździe. Dno jest tu bardzo ostre i twarde, wysypane kamieniem i krasowym wapieniem. Uskoki zaczynają się dosłownie metr od brzegu i spadają niemal pod pionowym kątem na głębokości do kilkunastu metrów. Twardy i ubogi w roślinność litoral wymaga precyzyjnego czytania wody przy użyciu nowoczesnej elektroniki na łodziach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80629, 'Jezioro Zarańskie', 'jezioro-zaranskie', 'LAKE', '53.580841932652845', '15.830970879072819', 'Zachodniopomorskie', 'Drawsko Pomorskie / Zarzecko', 'Jezioro Zarańskie to perła Pojezierza Drawskiego, niesamowicie urozmaicony i piękny akwen, pełen wysp, głębokich rynien i wypłyceń (tzw. krasowych górek). Posiada wyśmienitą, I klasę czystości wody, co umożliwia przeżycie gatunków łososiowatych i sielawy. Z dna rzędu kilku metrów nagle wyrastają podwodne blaty żwirowe, tworząc na echosondzie obraz górskich szczytów pod taflą wody. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80630, 'Jezioro Rydzewo (Rydzewskie)', 'jezioro-rydzewo', 'LAKE', '53.607371835445946', '15.823684391539764', 'Zachodniopomorskie', 'Drawsko Pomorskie', 'Rydzewo to bardzo malownicze jezioro położone w ciągu wód polodowcowych, otulone szerokimi pasami szuwarów i lasów mieszanych. Mimo mniejszej głębokości niż sąsiednie giganty rynnowe, Rydzewo posiada ciekawe, urozmaicone dno, obfitujące w zróżnicowane frakcje od piaszczystych zatok, przez żwirowe wypłycenia, po głębsze dołki kumulujące muł. Woda zachowuje przyzwoitą przejrzystość przez całe lato.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80631, 'Jezioro Będargowo', 'jezioro-bedargowo', 'LAKE', '53.61522281368457', '15.812543822807292', 'Zachodniopomorskie', 'Drawsko Pomorskie', 'Jezioro Będargowo to niewielki, wysoce cichy i spokojny zbiornik rynnowy usytuowany na północ od Drawska. Wymyka się klasycznym regułom – nie jest przesadnie głęboki, ale jego twarde, niemal całkowicie zdominowane przez wypłukany piasek i żwir dno tworzy idealne środowisko. Woda utrzymuje lekki, zielonkawy ton, ale zachowuje doskonałą widoczność i natlenienie ze źródeł wybijających na skarpach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80632, 'Jezioro Gagnowo', 'jezioro-gagnowo', 'LAKE', '53.63341075043699', '15.812571819755009', 'Zachodniopomorskie', 'Łobez / Drawsko Pomorskie', 'Urokliwy akwen eutroficzny z rozwiniętą, falistą linią brzegową. Jezioro Gagnowo ulega naturalnym, łagodnym procesom odkładania się materii organicznej, tworząc w głębszych dołkach zasobną stołówkę dla białorybu. Roślinność szuwarowa jest bardzo obfita, a w okresie wysokich temperatur u wylotów zatok pojawiają się mniejsze kożuchy grążela żółtego i rzęsy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80633, 'Jezioro Gęgnowskie', 'jezioro-gegnowskie', 'LAKE', '53.63089145901219', '15.808537777457774', 'Zachodniopomorskie', 'Drawsko Pomorskie', 'Mały, bliźniaczy i niezwykle dziki sąsiad Gagnowa. Zbiornik ulegający szybszej sukcesji i zarastaniu, o płytszej misie dennej i wysoce torfowym podłożu. Wokół brzegów dominuje grzęzawisko, okalane puszczą dębowo-olchową, co w okresie jesiennym przysypuje dno jeziora gigantyczną warstwą opadłych, gnilnych liści, nadając wodzie głęboki, herbaciany kolor typowy dla wód dystroficznych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80634, 'Jezioro Przytonko', 'jezioro-przytonko', 'LAKE', '53.63768730227476', '15.865849394238742', 'Zachodniopomorskie', 'Drawsko Pomorskie / Ostrowice', 'Jezioro Przytonko, niepozorny akwen wtulony w gęstwinę lasów Drawskiego Parku Krajobrazowego, stanowi wodę zdominowaną przez bardzo twarde rzeźby polodowcowe. Szybkie, gliniaste stoki uciekają z małych, piaszczystych plaż do głębokiej na kilkanaście metrów rynny głównej. Cechuje się dobrą przeziernością i relatywnie małą presją roślinną litoralu, co daje sporą przestrzeń dla rzutów spiningowych od samego lądu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80635, 'Jezioro Kamień', 'jezioro-kamien', 'LAKE', '53.60499153540567', '15.898238209393107', 'Zachodniopomorskie', 'Drawsko Pomorskie / Ostrowice', 'Samoistny cud geologiczny Pojezierza Drawskiego. Jezioro Kamień (Kamienne) w pełni zasługuje na swoją nazwę. Ten głęboki rynnowy akwen to dosłownie usypisko podwodnych skał, potężnych głazów narzutowych i żwirowych raf uciekających uskokami w bardzo chłodne głębiny. I klasa czystości i krystalicznie czysta woda pozwalają dostrzec te formacje krasowe na wiele metrów w dół, co w połączeniu z zalesionymi brzegami tworzy niesamowity, surowy mikroklimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80636, 'Jezioro Wielkie Dąbie', 'jezioro-wielkie-dabie', 'LAKE', '53.619967769882386', '15.885089090536091', 'Zachodniopomorskie', 'Drawsko Pomorskie', 'Wielkie Dąbie to przepiękny, bardzo rozległy (ponad 250 hektarów) akwen rynnowy, który mimo swojej nazwy zaskakuje mnogością płytkich zatok, piaszczystych wysp, przewężeń i cypli uderzających w otwartą, głęboką rynnę wodną. Posiada doskonale wypłukane, piaszczysto-żwirowe twarde tło wzdłuż zachodniego brzegu, podczas gdy ciche zatoki północne bogate są w tatarak i żyzny osad przydenny sprzyjający rozmnażaniu i bytowaniu ryb spokojnego żeru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80637, 'Jezioro Niecino', 'jezioro-niecino', 'LAKE', '53.63618914794209', '15.90613510922343', 'Zachodniopomorskie', 'Ostrowice', 'Jezioro Niecino to bardzo cicha i mało rozpoznawalna szerzej, a zarazem wędkarsko znakomita woda otulona rozległymi kompleksami polno-leśnymi. Jest to akwen ulegający lekkiej eutrofizacji, ale posiadający solidne głębokości (często sięgające ok. 10m w dołkach rynny), z twardymi piaszczysto-gliniastymi obrzeżami, ułatwiającymi penetrację spławikowcom z brzegu. Ostoje grążeli nie są uciążliwe i występują punktowo, dając doskonałe markery na rzuty dla wędkarzy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80638, 'Jezioro Klęckie', 'jezioro-kleckie', 'LAKE', '53.664656284542815', '15.927567709416827', 'Zachodniopomorskie', 'Ostrowice / Klęcko', 'Niewielki, ale rzeźbiący w głębi krajobrazu akwen w rynnowym obniżeniu polodowcowym. Jezioro Klęckie zachwyca bardzo uskokowymi, stromymi skarpami okalającymi wodę od wschodu, co sprawia, że łowienie z brzegu niemal z góry wyklucza lekki sprzęt. Dno zjeżdża natychmiastowo na 8-12 metrów i jest wyjątkowo twarde, wysadzane wapieniami krasowymi i gruzem polodowcowym, czyniąc to miejsce doskonałą ostoją dla ryb drapieżnych, prądolubnych i kochających chłodne schronienie latem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80639, 'Jezioro Siecino', 'jezioro-siecino', 'LAKE', '53.60617389795158', '16.022489847234848', 'Zachodniopomorskie', 'Złocieniec / Drawsko Pomorskie', 'Siecino to absolutny gigant, legenda i duma Pojezierza Drawskiego. Ten potężny akwen (prawie 730 ha) i oszałamiająco głęboki (maksymalnie blisko 45 metrów!) przypomina strukturą fiordy skandynawskie. Ogromna, pofalowana toń kryształowej wody (I klasa), piaszczyste i zalesione łagodnie brzegi u wlotów oraz gwałtowne podwodne góry i rowy sielawowe tnące środek dna. Tu nie łowi się w zaroślach – to wielka, wietrzna, otwarta potęga jeziorna!
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80640, 'Jezioro Wilczkowo', 'jezioro-wilczkowo', 'LAKE', '53.545209594161115', '16.091444076283388', 'Zachodniopomorskie', 'Złocieniec', 'Jezioro Wilczkowo to piękny, podłużny akwen, będący częścią wielkiego szlaku wodnego rzeki Drawy i leżący zaledwie "rzut beretem" od Złocieńca. Zbiornik ze świetnie wyżłobionym korytem przepływowym, co odświeża i wybornie dotlenia wodę. Charakteryzuje się pofałdowanym dnem – od piaszczystych naniesień z wlotu rzeki, po szerokie i gliniasto-błotniste rynny na 15 metrach. Szata roślinna ukształtowana jest głównie w rozległe pasy trzcin na brzegach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80641, 'Jezioro Krosino', 'jezioro-krosino', 'LAKE', '53.556326044899', '16.069557251053702', 'Zachodniopomorskie', 'Złocieniec', 'Sąsiad i naturalne, przepływowe przedłużenie Wilczkowa na trasie pięknej, dzikiej rzeki Drawy. Krosino to szerokie jezioro rynnowo-przepływowe o nieco bardziej zarośniętym, puszczańskim charakterze litoralu. Woda ulega w tym akwenie bardzo pożytecznemu mieszaniu i falowaniu, a głębokie na ok. 12-14 metrów "dołki" w korycie przecinają podwodne piaszczyste rafy żwirowe uformowane z wypłukań nurtowych. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80642, 'Jezioro Lubiatowo (Północ)', 'jezioro-lubiatowo-polnoc', 'LAKE', '54.16442456733689', '16.27585968365085', 'Zachodniopomorskie', 'Lubiatowo / Koszalin', 'Północny sektor Jeziora Lubiatowskiego to rejon najgłębszy, o charakterze rynnowym, przylegający do najwyższych brzegów akwenu. Dno opada tu dość stromo, tworząc rynny sięgające maksymalnych głębokości jeziora. Podłoże jest mieszane: piaszczyste spady przechodzą w muliste rynny centralne. Woda jest tu najchłodniejsza, co przyciąga drapieżniki w okresie upalnego lata.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80643, 'Jezioro Tuszynek', 'jezioro-tuszynek', 'LAKE', 53.74189, 18.49671, 'Pomorskie', 'Osiek', 'Tuszynek to niewielki, rynnowy akwen z czystą wodą i piaszczystymi brzegami. Często wykorzystywany rekreacyjnie, ale wędkarsko bardzo ciekawy pod kątem okonia. Ryby te grupują się na piaszczystych skarpach wzdłuż zalesionego brzegu.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80644, 'Jezioro Wierzchołek', 'jezioro-wierzcholek', 'LAKE', 54.061919, 18.080835, 'Pomorskie', 'Przywidz', 'Wierzchołek to kameralny zbiornik połączony systemem rowów z jeziorem Przywidzkim. Ma charakter eutroficzny, z dnem mulistym i bogatą roślinnością zanurzoną. Maksymalna głębokość nie przekracza 5-6 metrów. Akwen jest wybitnie wyciszony, osłonięty od wiatru przez wysokie skarpy i pasy olszyn.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80645, 'Jezioro Dołgie Wielkie', 'jezioro-dolgie-wielkie', 'LAKE', '53.59342230033878', '16.263164520667893', 'Zachodniopomorskie', 'Czaplinek / Siemczyno', 'Jezioro Dołgie Wielkie w całości oddaje swoją nazwę – to długa na kilka kilometrów, niesamowicie wyraźna rynna, przebijająca się przez falisty krajobraz lasów i łąk. Opad brzegów jest ekstremalnie gwałtowny; z piaszczystych, nielicznych plaż można po kilku metrach spotkać się z głębokością ponad 10 metrów! Woda to krasowy kryształ, wybacza wędkarzom bardzo niewiele błędów w doborze grubości sprzętu. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80646, 'Jezioro Słosinieckie Małe', 'jezioro-slosinieckie-male', 'LAKE', '53.953107877897416', '16.980489624844115', 'Pomorskie', 'Słosinko', 'Niewielkie jezioro lobeliowe o krystalicznej wodzie i piaszczystym dnie. Słosinieckie Małe charakteryzuje się niską żyznością wody i obecnością rzadkiej roślinności (lobelia jeziorna). Dno opada dość łagodnie w stronę rynny środkowej (max 8 m). Brzegi są piaszczyste, otoczone lasem, co sprawia, że woda jest nieskazitelnie czysta przez cały rok.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80647, 'Jezioro Wąsosze', 'jezioro-wasosze', 'LAKE', '53.50051037033627', '16.06681066885328', 'Zachodniopomorskie', 'Złocieniec', 'Wąsosze to niezwykle atrakcyjne, głębokie jezioro rynnowe leżące nieopodal Złocieńca. Akwen wyróżnia się bardzo zróżnicowaną rzeźbą dna – znajdziemy tu ostre piaszczysto-żwirowe stoki, które błyskawicznie opadają w mrok głębin sięgających blisko 30 metrów. Woda jest czysta i chłodna, dobrze natleniona przez bijące na dnie źródła, co sprzyja utrzymaniu populacji sielawy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80648, 'Jezioro Drawsko', 'jezioro-drawsko', 'LAKE', '53.5943361581835', '16.182587281994977', 'Zachodniopomorskie', 'Czaplinek', 'Drawsko to wędkarski Olimp – drugie najgłębsze jezioro w Polsce (ponad 79 metrów!), gigantyczny akwen o powierzchni blisko 1800 hektarów, pełen zatok, potężnych wysp (m.in. Bielawa) i niesamowitych, niemal pionowych podwodnych klifów. Krystaliczna woda, ogromne przestrzenie i potężna fala czynią to jezioro łowiskiem wymagającym ogromnego szacunku i sprzętu najwyższej klasy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80649, 'Jezioro Czaplino', 'jezioro-czaplino', 'LAKE', '53.55280479122697', '16.250896570108498', 'Zachodniopomorskie', 'Czaplinek', 'Jezioro leżące dosłownie u stóp Czaplinka. Mimo miejskiego charakteru i bliskości giganta (Jeziora Drawsko), Czaplino to wybitnie wędkarska, polodowcowa rynna o stromych opadach piaszczysto-gliniastych i głębokości rzędu kilkunastu metrów. Dno jest urozmaicone, twarde, a woda charakteryzuje się świetną przezroczystością, co przyciąga zarówno wędkarzy, jak i amatorów wypoczynku na pięknych promenadach miejskich.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80650, 'Jezioro Pławno', 'jezioro-plawno', 'LAKE', '53.53923916045117', '16.21862423165253', 'Zachodniopomorskie', 'Czaplinek', 'Pławno to bardzo zaciszne i urokliwe jeziorko ukryte w kompleksach leśnych na południe od Czaplinka. Charakteryzuje się dużo większym stopniem zeutrofizowania niż sąsiednie rynny – dno jest płaskie, wymoszczone dużą ilością miękkiego mułu dębowego i bukowego, z obfitą szatą roślinną przy brzegach (szeroki pas lilii i trzcin). Woda jest tu ciemniejsza i nagrzewa się znacznie szybciej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80651, 'Jezioro Wieldządzkie', 'jezioro-wieldzadzkie', 'LAKE', 53.322685, 18.817949, 'Kujawsko-Pomorskie', 'Wieldządz / Płużnica', 'Wieldządzkie to jedna z najgłębszych i najbardziej technicznych rynien regionu (max ok. 25 m). Woda jest czysta, a dno wybitnie urozmaicone z gwałtownymi uskokami. To łowisko dla koneserów sandacza i wielkiego okonia sielawowego. Wymaga dobrej echosondy i precyzji.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80652, 'Jezioro Nątlino', 'jezioro-natlino', 'LAKE', '53.569271525582565', '16.246563764210716', 'Zachodniopomorskie', 'Czaplinek', 'Kolejny przedstawiciel jezior rynnowych na obrzeżach Czaplinka. Nątlino uformowane jest jako klasyczne, podłużne zagłębienie o niezwykle wyrównanych, stromych stokach biegnących równolegle do linii brzegowych. Dno to wymyty polodowcowy piasek, w rynnach opadający w twardszy szlam organiczny. Ze względu na wietrzne położenie woda tu jest dobrze wymieszana i przez cały rok natleniona.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80653, 'Jezioro Żerdno (Srebrne)', 'jezioro-zerdno', 'LAKE', '53.60633399289854', '16.216708661226487', 'Zachodniopomorskie', 'Stare Drawsko', 'Przepiękne, legendarne jezioro powiązane hydrologicznie z potężnym Drawskiem poprzez zamek w Starym Drawsku. Żerdno nosi również nazwę "Srebrne" co świetnie oddaje barwę i jakość jego I-klasowych, wyjątkowo czystych i bystrych wód. Akwen jest niebotycznie głęboki, bardzo stromy, z dnem wyścielonym twardą warstwą wapieni krasowych, jasnym piaskiem rzecznym nanoszącym się od prądów rzeki Drawy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80654, 'Jezioro Komorze', 'jezioro-komorze', 'LAKE', '53.62171081841902', '16.295157909304645', 'Zachodniopomorskie', 'Sikory', 'Jezioro Komorze to jeden z najbardziej wydłużonych i najczystszych akwenów Pojezierza Drawskiego. Wciśnięta w wąwóz polodowcowy woda kryje w sobie wspaniałe, piaszczyste spady i zatopione półwyspy uciekające szybko na mroczne głębokości niemal 35 metrów. Dno charakteryzuje się wybitną twardością skał narzutowych i żwirów. Ustronny, leśny charakter akwenu zapewnia odpoczynek od turystycznych skuterów i tłumów na plażach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80655, 'Jezioro Lubicko Wielkie', 'jezioro-lubicko-wielkie', 'LAKE', '53.600412580325916', '16.40021321291687', 'Zachodniopomorskie', 'Łubowo / Borne Sulinowo', 'Jezioro o urozmaiconej i fascynującej linii brzegowej leżące nieopodal dawnych wojskowych stref. Charakteryzuje się naprzemiennie występującymi płytkimi, mocno porośniętymi pałką i trzciną zatokami (bardzo eutroficznymi) i rozdzielającymi je rynnami, dochodzącymi w nielicznych miejscach do sporych "dołków". Różnorodność biologiczna dna zapewnia dogodne miejsce tarła dla białorybu i potężną bazę pokarmową z naniesionego bentosu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80656, 'Jezioro Brody', 'jezioro-brody', 'LAKE', '53.6130930068582', '16.411027879559516', 'Zachodniopomorskie', 'Łubowo', 'Urokliwe, niesłychanie ciche i zarośnięte jezioro dystroficzno-eutroficzne sąsiadujące blisko z Lubickiem. Ze względu na gęstą oprawę leśną, akwen jest niezwykle wyciszony i niemal pozbawiony fali wietrznej. Głębokość jest umiarkowana, a profil misy ma charakter opadającego bardzo powoli leja, bogato wyścielonego grubą warstwą opadłych z drzew liści, co nadaje wodzie rdzawo-mętny odcień wód torfowych. Niezwykle rozwinięta jest szata roślin wynurzonych tworzących wianuszek dookoła lądu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80657, 'Jezioro Strzeszyn', 'jezioro-strzeszyn', 'LAKE', '53.62057725461774', '16.43265721307774', 'Zachodniopomorskie', 'Strzeszyn / Borne Sulinowo', 'Jezioro Strzeszyn, urokliwa perła pojezierza wokół Bornego Sulinowa, zachwyca swoją polodowcową rynnową naturą i świetną wodą. Twarde, usłane żwirem, a miejscami krasową kredą dno obsuwa się w ciemne głębiny za wyraźną strefą litoralu. Rozbudowane piaszczyste zatoczki naprzemiennie występują z pionowymi leśnymi klifami, co daje nieograniczone opcje szukania ryb bez względu na wiatr. Woda zachowuje doskonałą widoczność przez pełne upalne lato.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80658, 'Jezioro Trzemeszno', 'jezioro-trzemeszno', 'LAKE', '53.81521623609916', '17.703794665123883', 'Pomorskie', 'Brusy', 'Jezioro Trzemeszno (Trzemeszno Małe) to zjawiskowo położone jezioro rynnowe, ukryte w głębokiej polodowcowej dolinie w rejonie Brus. Zbiornik charakteryzuje się bardzo czystą wodą i stromo opadającymi piaszczysto-żwirowymi stokami. Dno jest urozmaicone licznymi dołkami i podwodnymi przeszkodami w postaci zwalonych pni drzew, które dają schronienie drapieżnikom. Roślinność brzegowa jest wąska, ale zwarta, z przewagą trzciny i pałki wodnej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80659, 'Jezioro Kocie', 'jezioro-kocie', 'LAKE', '53.61400951675747', '16.43969532942611', 'Zachodniopomorskie', 'Borne Sulinowo', 'Małe, zagubione w gęstych borach leśne jezioro o charakterze przejściowym eutroficznym. "Kocie" jest jeziorem niezwykle kameralnym, bez wodotrysków batymetrycznych i twardych opadów – to raczej wypłaszczona misa z miękkim mułem wymieszanym z dużą ilością torfu. Latem brzegi oplata gęsty wianek lilii, rogatka i trzcin osłaniając wodę. Płytkość tego akwenu wpływa na powstawanie gęstej "zielenicy", silnie pogarszając widoczność dla oczu i ryb podczas upałów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80660, 'Jezioro Pile', 'jezioro-pile', 'LAKE', '53.6059037387233', '16.47279143918829', 'Zachodniopomorskie', 'Borne Sulinowo', 'Jezioro Pile to absolutna legenda tego regionu – potężny akwen przylegający do Bornego Sulinowa, pełen mrocznej historii militarnej i wędkarskich rekordów! Batymetria to labirynt rynien sięgających ponad 40 metrów, wypłyceń, zjawiskowej, wapiennej Wyspy Owczej oraz słynnego, unikalnego w skali Europy "Zapadniętego Lasu" (wyspa, która opadła pod wodę razem z drzewami). Dno bywa piaszczyste, usłane wojskowym gruzem, a w głębinach twarde i bezlitosne dla sprzętu. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80661, 'Jezioro Śmiadowo', 'jezioro-smiadowo', 'LAKE', '53.61707622157368', '16.55762117771516', 'Zachodniopomorskie', 'Śmiadowo / Borne Sulinowo', 'Kolejny tajemniczy akwen objęty przed laty strefą zmilitaryzowaną (do dziś w okolicach jeziora znajdziemy potężne bunkry Wału Pomorskiego). Śmiadowo to piękne, rozległe i dość głębokie polodowcowe jezioro rynnowe. Posiada znakomicie twarde, piaszczysto-żwirowe wypłycenia, szybko przechodzące w mrok głębokiej na ponad kilkanaście metrów rynny dennej, ułożonej równolegle do lądu. Woda bardzo obficie natleniona, filtrująca wapiennym osadem, bywa nieskazitelnie czysta i chłodna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80662, 'Jezioro Ciemino', 'jezioro-ciemino', 'LAKE', '53.6457813653919', '16.566890891930083', 'Zachodniopomorskie', 'Ciemino / Szczecinek', 'Jezioro Ciemino to niezwykle równe, podłużne i typowo eutroficzne łowisko leżące niedaleko Szczecinka. Zbiornik jest płytki do umiarkowanego, uformowany jako szeroka taca ze sporadycznymi piaszczystymi falami na dnie pokrytymi drobną warstwą mułu. Bardzo bogate w kwitnący wiosną i latem fitoplankton, stąd tendencja do obniżonej przezierności wody. Posiada świetne zaplecze szerokich trzcinowisk sprzyjających rybom litoralu, z wyspami grążeli na płyciznach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80663, 'Jezioro Wronowo', 'jezioro-wronowo', 'LAKE', '53.449281247233436', '20.273160163821963', 'Warmińsko-Mazurskie', 'Mielno / Grunwald', 'Jezioro Wronowo to mniejszy akwen rynnowy położony w sąsiedztwie jeziora Mielno. Posiada charakterystyczny, wydłużony kształt i zróżnicowane dno z przewagą osadów mulistych w centralnej części rynny. Akwen jest zaciszny, otoczony pasami drzew i krzewów, co chroni go przed silnymi podmuchami wiatru. Woda jest żyzna, co przekłada się na bogatą bazę pokarmową dla ryb spokojnego żeru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80664, 'Jezioro Łączno', 'jezioro-laczno', 'LAKE', '53.624610666994315', '16.517795738865853', 'Zachodniopomorskie', 'Łączno', 'Łączno to nieduży, ukryty i płytki akwen ulegający mocnemu ciśnieniu eutrofizacji i stopniowo zarastający, zlokalizowany pośród cichych pól i łąk niedaleko Bornego Sulinowa. Obfitujący w szeroki, gęsty pas wodnej gęstwiny i moczarek chroniący błotnisto-torfowe tło i dno. Woda jest bogata w zawiesiny lądowe spływające z okolicznych łąk po deszczach dając ciemny odcień odżywczego mroku lilii na dnie obok usypanego mulistego śluzu dębowych spadów korzeni.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80665, 'Jezioro Studzieniczno Małe', 'jezioro-studzieniczno-male', 'LAKE', '53.96577942238411', '17.008649687336295', 'Pomorskie', 'Studzienice', 'Studzieniczno Małe to mniejszy, bardzo urokliwy i zaciszny akwen sąsiadujący z jeziorem głównym. Ma charakter bardziej eutroficzny, z dnem mulistym i bogatszą roślinnością brzegową. Maksymalna głębokość oscyluje wokół 5-7 metrów. Brzegi są niskie, częściowo podmokłe, co zapewnia rybom spokój i doskonałe tarliska.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80666, 'Jezioro Radacz', 'jezioro-radacz', 'LAKE', '53.707476707549645', '16.547589530543238', 'Zachodniopomorskie', 'Radacz / Parsęcko', 'Potężny powierzchniowo zbiornik przypominający wielką rozlaną tacę wody u podnóża terenów nizinnych. Radacz to wysoce żyzne jezioro o charakterze wybitnie zarośniętym, wybitnie płytkim i mocno zamulonym od wielu dekad naturalnej osadowej cyrkulacji obumarłych rdestnic. Lustro jest wystawione na ciężkie falowania letnich burz podnoszących rzadszą przezroczystość z dna powodując odcienie rdzawej brązowej fali po obrzeżach. Pasy trzciny i pływające wyspy tworzą schrony rzędu setek metrów od brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80667, 'Jezioro Dębno', 'jezioro-debno-2', 'LAKE', '53.692368674761845', '16.313405866428926', 'Zachodniopomorskie', 'Dębno / Połczyn Zdrój', 'Jezioro Dębno (okolice uzdrowiska Połczyn Zdrój) to rewelacyjna rynna polodowcowa, która z uwagi na chłodny urok regionu posiada wybitnie rzeczną jakość opadającego z wolna wody rynnowego nurtu z krasowych pęknięć dna. Usiane ostre kanty spadające na mrok rynien z bardzo twardego ubitego żwiru i drobnego piasku. Wyśmienita, krystaliczna powłoka i lekko niebieskawy odcień dają ułudę pływania na fiordach skandynawii przed krawędziami polodowcowych skał u dołu głębin słońca echa ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80668, 'Jezioro Koprzywno', 'jezioro-koprzywno', 'LAKE', '53.7252631321242', '16.283815736712942', 'Zachodniopomorskie', 'Połczyn-Zdrój / Koprzywno', 'Koprzywno to bardzo głęboko uwięzione między wysokimi brzegami i klifami zalesionymi bukami jezioro rynnowe. Charakteryzuje się absolutnie stromymi zjazdami zaraz za pasem przybrzeżnego kamienia i niespodziewanie opadającymi pochyłościami do mroku chłodnej krystalicznej głębi przekraczającej szybko kilkanaście metrów dna. Środowisko wód twardych, rzadko podchodzących algami ze zjawiskową przepustowością echosondy u rynnowych wyłamań podwodnych głazów i zatopionych ogromnych dębów chroniących lęgi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80669, 'Jezioro Wielimie', 'jezioro-wielimie', 'LAKE', '53.75557968365902', '16.758363629658394', 'Zachodniopomorskie', 'Szczecinek', 'Jezioro Wielimie to obok Drawska jeden z fenomenów tego regionu, jednak o zupełnie innej charakterystyce! To potężny (ok. 1800 hektarów), iście oceaniczny w skali pojezierza akwen uformowany jako... gigantyczna płycizna! Ze średnią głębokością nieco ponad metr, wieloma naniesionymi mulistymi równinami i silnie porastającymi tatarakami i pływającymi wyspami tworzy środowisko o obfitych lęgach. Potężne fale wywoływane wiatrami mieszają stale dno, przez co woda bywa tu trwale mętna w odcieniach szarości u uciagów wód.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80670, 'Jezioro Wierzchowo', 'jezioro-wierzchowo', 'LAKE', '53.86231437330969', '16.66403570445282', 'Zachodniopomorskie', 'Wierzchowo / Szczecinek', 'Jezioro Wierzchowo to rozległy i zróżnicowany akwen rynnowy na północ od Szczecinka o wysokich, polodowcowych brzegach poprzecinanych urokliwymi, twardymi zatokami piaskowymi. Wyróżnia się znacznymi głębokościami w centralnej rynnie (powyżej 25m) i pięknie schodzącymi, szerokimi wypłyceniami łach, na których wymywa się żwir i kamień u krawędzi pęknięć krasowych. Utrzymuje wspaniałą jakość wód chronionych brakiem przemysłu, o wysokiej klasie przezroczystości u stoków.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80671, 'Jezioro Linewskie', 'jezioro-linewskie', 'LAKE', 54.074499, 18.198853, 'Pomorskie', 'Liniewo', 'Jezioro Linewskie to akwen położony bezpośrednio przy miejscowości Liniewo. Zbiornik charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 4-6 metrów. Woda jest żyzna, co przekłada się na bogatą biomasę ryb karpiowatych. Brzegi są w dużej mierze zagospodarowane – pomosty i promenady ułatwiają dostęp do litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80672, 'Jezioro Drężno', 'jezioro-drezno', 'LAKE', '53.8595490799336', '16.700333506823522', 'Zachodniopomorskie', 'Szczecinek / Biały Bór', 'Jezioro Drężno to fascynująca, rynnowa rynna polodowcowa o powierzchni blisko 200 hektarów, stanowiąca kluczowy element dorzecza rzeki Gwdy. Akwen ten charakteryzuje się niezwykle urozmaiconą linią brzegową w kształcie litery "S" oraz bardzo urozmaiconą batymetrią. Dno jeziora to istny poligon dla wędkarza – znajdziemy tu liczne podwodne górki (tzw. "kamienie"), które wyrastają z 15-metrowej głębi niemal pod samą powierzchnię wody, oraz głębokie, mroczne rynny sięgające ponad 25 metrów. Woda jest czysta, o lekko zielonkawym odcieniu, co sprzyja rozwojowi sielawy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80673, 'Jezioro Damskie', 'jezioro-damskie', 'LAKE', '53.836687872618825', '16.72494545663129', 'Zachodniopomorskie', 'Szczecinek / Spore', 'Jezioro Damskie to mniejszy, bardzo kameralny i urokliwy akwen sąsiadujący z kompleksem wód rzeki Gwdy. W odróżnieniu od głębokich rynien w okolicy, Damskie posiada charakter bardziej przejściowy, zbliżony do jezior eutroficznych. Dno jest tu łagodniejsze, w dużej mierze pokryte miękkim osadem organicznym (mułem), z licznymi piaszczystymi "plackami" w pasie przybrzeżnym. Brzegi są mocno zarośnięte pasem trzcin i tataraku, a woda nagrzewa się stosunkowo szybko, co sprzyja bogatej wegetacji roślinności podwodnej, w tym rozległych łąk moczarki kanadyjskiej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80674, 'Jezioro Spore', 'jezioro-spore', 'LAKE', '53.7978649083446', '16.71347949253091', 'Zachodniopomorskie', 'Szczecinek / Spore', 'Jezioro Spore to malowniczy akwen rynnowy o powierzchni około 90 hektarów, malowniczo położony w dolinie rzeki Gwdy. Charakteryzuje się bardzo urozmaiconą rzeźbą dna – znajdziemy tu zarówno rozległe, piaszczyste blaty, jak i głębokie rynny sięgające ponad 16 metrów. Brzegi jeziora są zróżnicowane: od wysokich i zalesionych po stronie zachodniej, po niskie i trawiaste w okolicach samej miejscowości Spore. Woda cechuje się dobrą przezroczystością, choć latem ulega lekkim zakwitom typowym dla jezior żyznych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80675, 'Jezioro Rudnickie Wielkie', 'jezioro-rudnickie-wielkie', 'LAKE', 53.434927, 18.745444, 'Kujawsko-Pomorskie', 'Grudziądz', 'Największe jezioro w okolicach Grudziądza (pow. ok. 170 ha). Akwen rynnowy o urozmaiconym dnie, z licznymi górkami podwodnymi i rynną sięgającą 12 metrów. To wyśmienite łowisko sandacza i dorodnego leszcza. Mimo dużej presji turystycznej w sezonie letnim, jezioro pozostaje bardzo rybne dzięki intensywnym zarybieniom.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80676, 'Jezioro Busino Duże', 'jezioro-busino-duze', 'LAKE', '53.45686060652919', '16.438418101314085', 'Zachodniopomorskie', 'Borne Sulinowo', 'Jezioro Busino Duże to kameralny, leśny akwen rynnowy położony w dzikich rejonach Pojezierza Drawskiego, na południe od Bornego Sulinowa. Jezioro charakteryzuje się typowo leśnym klimatem – jest osłonięte od wiatru gęstym borem sosnowo-dębowym, co sprawia, że tafla wody często pozostaje nienaruszona. Dno opada dość stromo w stronę rynny środkowej, osiągając głębokość około 10-12 metrów. Podłoże jest mieszane: od piaszczystych skarp po muliste i torfowe zagłębienia obfitujące w pokarm.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80677, 'Jezioro Busino', 'jezioro-busino', 'LAKE', '53.46652178395321', '16.52693158308369', 'Zachodniopomorskie', 'Borne Sulinowo', 'Jezioro Busino to ukryty skarb Pojezierza Drawskiego, położony w bezpośrednim sąsiedztwie dawnych poligonów wojskowych. Jest to akwen o wybitnie leśnym charakterze, niemal całkowicie odizolowany od cywilizacji gęstym pasem borów sosnowych. Batymetria jeziora jest typowa dla rynien polodowcowych – dno opada dość rytmicznie w stronę centralnej rynny, osiągając głębokość około 10-12 metrów. Woda jest bardzo czysta, z delikatnym, "leśnym" zabarwieniem, co sprawia, że ryby są tu wyjątkowo silne i dobrze wybarwione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80678, 'Jezioro Sławianowskie Wielkie', 'jezioro-slawianowskie-wielkie', 'LAKE', '53.26644888317993', '17.177258941722705', 'Wielkopolskie', 'Złotów', 'Jezioro Sławianowskie Wielkie to największy i najbardziej majestatyczny akwen w regionie złotowskim, zajmujący powierzchnię ponad 200 hektarów. Jest to typowe jezioro rynnowe o bardzo wydłużonym kształcie i imponującej głębokości, sięgającej w najgłębszych punktach rynny ponad 15 metrów. Dno jest niezwykle urozmaicone – od rozległych piaszczystych blatów w rejonach miejscowości Sławianowo, po ostre, gliniaste spady i podwodne górki w środkowej części jeziora. Woda jest żyzna, o dobrej przejrzystości, choć latem ulega naturalnym zakwitom.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80679, 'Jezioro Stryjewo', 'jezioro-stryjewo', 'LAKE', '53.31862071893037', '17.36245351151716', 'Wielkopolskie', 'Więcbork', 'Jezioro Stryjewo to bardzo urokliwy i nieco "dzikszy" akwen położony na pograniczu Wielkopolski i Kujaw. Charakteryzuje się dość wyrównaną głębokością, oscylującą w granicach 5-7 metrów, z dnem pokrytym w większości miękkim osadem organicznym, przerywanym twardszymi połaciami piasku w pasie przybrzeżnym. Brzegi jeziora są mocno porośnięte trzciną, co tworzy naturalną barierę i oazę spokoju dla ryb. Woda jest ciepła i bardzo żyzna, co sprzyja szybkiemu przyrostowi ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80680, 'Jezioro Zakrzewskie', 'jezioro-zakrzewskie', 'LAKE', '53.36493562168983', '17.40458905803175', 'Wielkopolskie', 'Zakrzewo', 'Jezioro Zakrzewskie, przylegające bezpośrednio do miejscowości Zakrzewo, to akwen o zróżnicowanym charakterze, łączący cechy jeziora rekreacyjnego i dzikiego łowiska. Zbiornik jest stosunkowo płytki, z dnem mulistym, ale z wyraźnymi piaszczystymi strefami w okolicach plaż miejskich. Linia brzegowa jest dobrze rozwinięta, z licznymi półwyspami i zatokami, które dają schronienie rybom przed wiatrem. Woda jest dobrze natleniona, co sprzyja aktywności ryb przez całą dobę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80681, 'Staw Wielki (Maszewo)', 'staw-wielki-maszewo', 'LAKE', 52.099744, 15.04715, 'Lubuskie', 'Maszewo', 'Staw Wielki to największy akwen w kompleksie stawów maszewskich. Posiada charakter hodowlano-rekreacyjny z dnem piaszczysto-mulistym. Słynie z populacji dużego amura i karpia. Ze względu na żyzną wodę, ryby rosną tu wyjątkowo szybko, co przyciąga łowców okazów spokojnego żeru.', 'PZW Zielona Góra');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80682, 'Jezioro Więcborskie', 'jezioro-wiecborskie', 'LAKE', '53.3435040937824', '17.52006711976274', 'Kujawsko-Pomorskie', 'Więcbork', 'Jezioro Więcborskie to serce Krajeńskiego Parku Krajobrazowego, akwen rynnowy o powierzchni około 190 hektarów. Charakteryzuje się bardzo urozmaiconą rzeźbą dna – centralna rynna osiąga głębokość blisko 20 metrów, a stromo opadające stoki przeplatają się z rozległymi, piaszczystymi blatami. Brzegi jeziora są zróżnicowane: północna część przylega bezpośrednio do miejskiej promenady Więcborka, natomiast południowa i zachodnia to dzikie, zalesione skarpy. Woda jest żyzna, co sprzyja szybkiemu przyrostowi ryb białych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80683, 'Jezioro Żarnowieckie', 'jezioro-zarnowieckie', 'LAKE', '54.76199416256426', '18.055476128242635', 'Pomorskie', 'Gniewino / Krokowa', 'Jezioro Żarnowieckie to gigant północy (ponad 1400 ha), rynnowy akwen położony tuż przy Bałtyku. Jest to jezioro specyficzne, pełniące funkcję dolnego zbiornika dla Elektrowni Szczytowo-Pompowej Żarnowiec. Powoduje to częste wahania poziomu wody i wymuszone prądy, co upodabnia jezioro do wielkiej rzeki. Dno jest twarde, piaszczysto-żwirowe, z nielicznymi, ale głębokimi rynnami (do 16-19 m). Brzegi są otwarte i wietrzne.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80684, 'Jezioro Choczewskie', 'jezioro-choczewskie', 'LAKE', '54.73740404466262', '17.92895879814359', 'Pomorskie', 'Choczewo', 'Jezioro Choczewskie to krystalicznie czysta perła ukryta w pasie nadmorskich lasów sosnowych. To typowe jezioro rynnowe o powierzchni ok. 180 ha, z bardzo przejrzystą wodą (I klasa czystości). Batymetria jest bardzo regularna – dno stromo opada od brzegów w stronę rynny środkowej, osiągając głębokość ok. 13-14 metrów. Podłoże jest w przeważającej części twarde, piaszczysto-żwirowe, a pas roślinności brzegowej jest stosunkowo wąski, ale bardzo gęsty.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80685, 'Jezioro Sarbsko', 'jezioro-sarbsko', 'LAKE', '54.76414194885713', '17.627529766618544', 'Pomorskie', 'Łeba / Przybrzeże', 'Jezioro Sarbsko to typowe jezioro przybrzeżne (nadmorskie), oddzielone od Bałtyku zaledwie wąskim pasem zalesionej mierzei. Jest to akwen niesamowicie płytki – średnia głębokość to zaledwie 1,2 metra, a dno jest płaskie, pokryte piaskiem i warstwą miękkiego mułu. Z uwagi na położenie, jezioro jest wystawione na silne wiatry, co powoduje stałe mieszanie wody i jej lekkie zasolenie (woda słonawa).
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80686, 'Jezioro Łebsko', 'jezioro-lebsko', 'LAKE', '54.72146999690984', '17.411543752450907', 'Pomorskie', 'Łeba / Kluki', 'Jezioro Łebsko to trzecie co do wielkości jezioro w Polsce (ponad 7000 ha) i największy akwen Słowińskiego Parku Narodowego. To olbrzymia, płytka (średnio 2,3 m) laguna oddzielona od morza Mierzeją Łebską. Batymetria jest skrajnie monotonna – to gigantyczna "taca" z dnem pokrytym w dużej mierze piaskiem i osadami organicznymi. Z racji ochrony w ramach Parku Narodowego, wędkowanie jest tu ściśle limitowane i dozwolone tylko w wyznaczonych strefach i okresach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80687, 'Jezioro Długie (Liniewskie)', 'jezioro-dlugie-liniewo', 'LAKE', 54.045582, 18.181815, 'Pomorskie', 'Liniewo', 'Jezioro Długie pod Liniewem to klasyczna rynna polodowcowa, długa i wąska. Akwen charakteryzuje się twardym dnem piaszczysto-żwirowym i wyraźnie zarysowaną rynną środkową o głębokości do 9 metrów. Woda jest czysta i dobrze natleniona. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym, co nadaje akwenowi dziki charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80688, 'Jezioro Dołgie Wielkie', 'jezioro-dolgie-wielkie-nadmorskie', 'LAKE', '54.697105954013594', '17.192734210782028', 'Pomorskie', 'Smołdzino / Gardna Wielka', 'Jezioro Dołgie Wielkie położone w granicach Słowińskiego Parku Narodowego to jeden z najbardziej dzikich i niedostępnych akwenów nadmorskich. Jest to jezioro eutroficzne, płytkie (maksymalnie ok. 3 m), o dnie w dużej mierze mulistym, silnie zarastającym. Całość otoczona jest gęstym borem sosnowym i bagnami, co tworzy barierę nie do przebycia dla zwykłego turysty. Woda ma lekko brunatny kolor i jest bardzo żyzna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80689, 'Jezioro Dołgie Małe', 'jezioro-dolgie-male', 'LAKE', '54.68718327943461', '17.157594155803878', 'Pomorskie', 'Smołdzino', 'Jezioro Dołgie Małe to jedno z najmniejszych i najbardziej odizolowanych jezior Słowińskiego Parku Narodowego. Jest to klasyczny akwen dystroficzny, otoczony gęstymi borami sosnowymi i rozległymi mszarami torfowiskowymi. Jezioro jest niezwykle płytkie (średnio poniżej metra), a dno stanowi potężna warstwa płynnego, czarnego mułu organicznego. Woda posiada charakterystyczny, ciemny, herbaciany kolor wynikający z wysokiej zawartości kwasów humusowych. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80690, 'Jezioro Gardno', 'jezioro-gardno', 'LAKE', '54.6485748788242', '17.113263718971858', 'Pomorskie', 'Rowy / Gardna Wielka', 'Jezioro Gardno to potężny (blisko 2500 ha), płytki akwen przymorski, oddzielony od Bałtyku wąską mierzeją. Jest to jezioro o charakterze lagunowym, połączone z morzem rzeką Łupawą. Batymetria jest bardzo monotonna – to gigantyczna, płaska taca o średniej głębokości ok. 1,3 m. Dno jest piaszczysto-muliste, a woda charakteryzuje się dużą mętnością i zmiennym zasoleniem (woda słonawa), co determinuje unikatowy skład gatunkowy ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80691, 'Jezioro Wicko', 'jezioro-wicko', 'LAKE', '54.53697797340527', '16.637415452370856', 'Zachodniopomorskie', 'Jarosławiec / Postomino', 'Jezioro Wicko to duże, płytkie jezioro nadmorskie położone na Wybrzeżu Słowińskim, nieopodal Jarosławca. Akwen ten powstał poprzez odcięcie dawnej zatoki morskiej piaszczystą mierzeją. Średnia głębokość to zaledwie 2 metry, a dno jest płaskie, w dużej mierze pokryte miękkim mułem z domieszką piasku. Woda jest żyzna, o słonawym charakterze, co sprzyja rozwojowi zarówno ryb słodkowodnych, jak i wędrownych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80692, 'Jezioro Kopań', 'jezioro-kopan', 'LAKE', '54.481086311459826', '16.448248417352204', 'Zachodniopomorskie', 'Darłowo', 'Jezioro Kopań to klasyczne jezioro lagunowe, oddzielone od morza niezwykle wąskim i malowniczym pasem mierzei. Akwen jest bardzo rozległy i płytki (max. 4 m), z dnem niemal w całości pokrytym piaskiem nanoszącym się przez sztormy oraz warstwą osadów organicznych. Woda jest wybitnie słonawa, co sprawia, że ekosystem jest niezwykle dynamiczny. Brak wysokich brzegów powoduje, że jezioro jest całkowicie wystawione na działanie wiatru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80693, 'Jezioro Rudnik', 'jezioro-rudnik-miastko', 'LAKE', '53.95948141250482', '16.976881093893255', 'Pomorskie', 'Miastko', 'Jezioro Rudnik to kameralny akwen o charakterze eutroficznym, położony w pobliżu miejscowości Słosinko. Jezioro jest stosunkowo płytkie (max 5-6 m) z dnem w dużej mierze mulistym. Linia brzegowa jest silnie porośnięta trzciną i pałką wodną, co stwarza doskonałe warunki dla lęgów narybku. Woda szybko się nagrzewa, co sprzyja aktywności ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80694, 'Jezioro Bukowo', 'jezioro-bukowo', 'LAKE', '54.344999856329004', '16.28305852037448', 'Zachodniopomorskie', 'Dąbki', 'Jezioro Bukowo to jeden z najatrakcyjniejszych pod kątem wędkarskim zbiorników przymorskich w Polsce. To dawna zatoka morska o powierzchni ok. 1700 ha, połączona z Bałtykiem Kanałem Szczuczym. Jezioro jest płytkie (średnio 1,8 m), o dnie piaszczysto-mulistym i bardzo silnie natlenionej wodzie. Słonawy charakter wody sprawia, że ryby rosną tu znacznie szybciej niż w jeziorach śródlądowych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80695, 'Jezioro Jamno', 'jezioro-jamno', 'LAKE', '54.278481131479865', '16.158507375684888', 'Zachodniopomorskie', 'Mielno / Koszalin', 'Jezioro Jamno to dziewiąte co do wielkości jezioro w Polsce (ponad 2200 ha), położone bezpośrednio przy Koszalinie i Mielnie. Jest to typowy, płytki akwen przymorski (średnia głębokość 1,4 m), charakteryzujący się bardzo mętną wodą i silną eutrofizacją. Dno jest skrajnie muliste, co wynika z lat nanoszenia osadów rzecznych i braku naturalnego przepłukiwania przed budową wrót sztormowych. Mimo problemów z czystością, biomasa ryb w tym jeziorze jest gigantyczna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80696, 'Jezioro Resko Przymorskie', 'jezioro-resko-przymorskie', 'LAKE', '54.14293015190642', '15.371773937789161', 'Zachodniopomorskie', 'Dźwirzyno / Rogowo', 'Jezioro Resko Przymorskie to malowniczy akwen nadmorski, dawna zatoka Bałtyku, dziś oddzielona piaszczystą mierzeją i połączona z morzem kanałem w Dźwirzynie. Średnia głębokość to ok. 1,5 metra, a dno jest w dużej mierze piaszczyste w strefie przymorskiej i muliste w częściach południowych. Jezioro jest bardzo żyzne, o słonawej wodzie, co sprzyja bytowaniu ryb dwuśrodowiskowych. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80697, 'Jezioro Liwia Łuża', 'jezioro-liwia-luza', 'LAKE', '54.088350481349146', '15.096285580822682', 'Zachodniopomorskie', 'Niechorze / Pogorzelica', 'Jezioro Liwia Łuża to unikatowy rezerwat ornitologiczny i jezioro nadmorskie położone między Niechorzem a Pogorzelicą. Jest to akwen bardzo płytki (średnio ok. 1 m), o charakterze lagunowym, połączony z Bałtykiem kanałem Liwia Łuża (tzw. kanał rury). Dno jest mulisto-piaszczyste, silnie zarastające trzcinami, które tworzą szeroki, niemal niedostępny pas litoralu. Z uwagi na status rezerwatu, wędkowanie jest tu mocno ograniczone i wymaga specjalnych pozwoleń oraz przestrzegania rygorystycznych zasad.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80698, 'Jezioro Piaski', 'jezioro-piaski', 'LAKE', '53.85542894377413', '14.7122446692843', 'Zachodniopomorskie', 'Wolin', 'Jezioro Piaski to niezwykle ciekawy akwen stanowiący integralną część kompleksu Zalewu Kamieńskiego. Jest to typowe jezioro przymorskie o charakterze lagunowym, bardzo płytkie (średnio ok. 1,5 m), ale o ogromnym znaczeniu wędkarskim ze względu na bezpośrednie połączenie z rzeką Dziwną. Dno jest tu w przeważającej mierze piaszczyste z grubymi naniesieniami mułu organicznego w zatokach. Woda ma charakter słonawy, co determinuje unikalny skład gatunkowy ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80699, 'Jezioro Wykowo', 'jezioro-wykowo', 'LAKE', 54.047421, 18.1916, 'Pomorskie', 'Liniewo / Wykowo', 'Wykowo to mniejszy akwen rynnowy, silnie ulegający procesom eutrofizacji. Dno jest piaszczysto-muliste, o średniej głębokości ok. 4-5 metrów. Woda jest żyzna, co sprzyja rozwojowi bujnego litoralu. Brzegi są w większości porośnięte trzciną, co tworzy doskonałe warunki ochronne dla ryb spokojnego żeru i lęgów szczupaka.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80700, 'Jezioro Ostrowo', 'jezioro-ostrowo', 'LAKE', '53.826938979924485', '14.698213295715194', 'Zachodniopomorskie', 'Wolin', 'Jezioro Ostrowo to kolejny akwen z grupy wód przymorskich w sąsiedztwie Wolina, połączony systemem rowów i kanałów z rzeką Dziwną. Jest to zbiornik wybitnie eutroficzny, bardzo żyzny, o misowatym i niemal płaskim dnie. Średnia głębokość rzadko przekracza 1,2 metra, co sprawia, że jezioro latem niemal w całości zarasta rdestnicą i wywłócznikiem, tworząc nieprzebyte labirynty dla narybku.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80701, 'Jezioro Ostrowite (Charzykowskie)', 'jezioro-ostrowite', 'LAKE', '53.7925445420802', '17.597560792890867', 'Pomorskie', 'Chojnice', 'Jezioro Ostrowite to jedno z najczystszych i najpiękniejszych jezior rynnowych w otulinie Parku Narodowego Bory Tucholskie. To klasyczna rynna sielawowa o bardzo urozmaiconym dnie – znajdziemy tu ostre piaszczyste spady, głębokie rynny sięgające ponad 18 metrów oraz podwodne górki. Woda posiada I klasę czystości i niesamowitą przejrzystość, co w słoneczne dni pozwala obserwować roślinność ramienicową na głębokości kilku metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80702, 'Jezioro Charzykowskie', 'jezioro-charzykowskie', 'LAKE', '53.77549609446101', '17.508176365359727', 'Pomorskie', 'Charzykowy', 'Jezioro Charzykowskie (Łukomie) to trzynaste co do wielkości jezioro w Polsce (ok. 1360 ha) i główny punkt orientacyjny południowych Kaszub. To potężna polodowcowa rynna o długości blisko 10 km i maksymalnej głębokości przekraczającej 30 metrów. Batymetria jest fascynująca: dno posiada liczne zapadliska, podwodne wyspy i rozległe blaty. Przez jezioro przepływa rzeka Brda, co zapewnia stałą wymianę wód i świetne natlenienie nawet najgłębszych partii rynny.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80703, 'Jezioro Niedźwiedzie', 'jezioro-niedzwiedzie', 'LAKE', '53.757244022565935', '17.540903379461035', 'Pomorskie', 'Chojnice / Charzykowy', 'Jezioro Niedźwiedzie to kameralny, wybitnie leśny zbiornik o charakterze eutroficznym, położony niedaleko wschodniego brzegu Jeziora Charzykowskiego. Akwen charakteryzuje się dość regularną misą denną z łagodnymi spadkami i dnem w dużej mierze pokrytym miękkim osadem liściastym. Całość otacza majestatyczny las sosnowy, co zapewnia doskonałą osłonę przed wiatrem i nadaje wodzie intymny, dziki charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80704, 'Jezioro Dybrzk', 'jezioro-dybrzk', 'LAKE', '53.842379017244845', '17.611261209957046', 'Pomorskie', 'Swarzewo / Brusy', 'Jezioro Dybrzk to bardzo ważny punkt na trasie przepływu rzeki Brdy przez Bory Tucholskie. Jest to jezioro rynnowo-przepływowe, co w ogromnym stopniu wpływa na jego charakterystykę. Nurt Brdy jest tu wyraźnie wyczuwalny, szczególnie w rejonach przewężeń, co powoduje stałe natlenienie wody i tworzenie się rzecznych struktur na dnie – rynien z twardym, wymytym dnem piaszczysto-żwirowym. Maksymalna głębokość oscyluje wokół 18-20 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80705, 'Jezioro Kaczewo', 'jezioro-kaczewo', 'LAKE', '53.9165267583664', '17.55928891210384', 'Pomorskie', 'Brusy / Męcikał', 'Jezioro Kaczewo to dziki, leśny zbiornik o wydłużonym kształcie, otoczony gęstą puszczą. Posiada charakter rynnowy, ale ze znacznym stopniem zarastania. Dno jest mieszane: piaszczyste w rejonach dopływów i muliste w osi głównej. Woda posiada dobrą klasę czystości, choć jesienią przybiera ciemniejszy odcień od opadających liści. To jezioro, w którym presja wędkarska jest znikoma, co pozwala na obcowanie z naturą w najczystszej postaci.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80706, 'Jezioro Pięsno', 'jezioro-piesno', 'LAKE', '53.88009505489083', '17.55006904606306', 'Pomorskie', 'Brusy / Swornegacie', 'Jezioro Pięsno to urokliwy, rynnowy akwen położony w sercu Borów Tucholskich, z dala od głównych szlaków turystycznych. Jezioro cechuje się bardzo czystą wodą i twardym, piaszczystym dnem, które stromo opada w stronę rynny osiągającej 10-12 metrów głębokości. Brzegi są wysokie, porośnięte starym lasem sosnowym, co nadaje akwenowi wyjątkowego mikroklimatu. Roślinność wodna jest tu skąpa, ograniczona do wąskiego pasa trzcin i łąk ramienicowych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80707, 'Jezioro Gardliczno Duże', 'jezioro-gardliczno-duze', 'LAKE', '53.89612437184485', '17.53569747503841', 'Pomorskie', 'Brusy / Swornegacie', 'Jezioro Gardliczno Duże to majestatyczny, leśny akwen rynnowy, który stanowi jedno z najciekawszych wyzwań wędkarskich w tej części Borów Tucholskich. Charakteryzuje się bardzo urozmaiconą linią brzegową i głęboką rynną (ponad 15 m) o twardym, piaszczysto-żwirowym dnie. Woda jest tu niezwykle czysta, dobrze natleniona, o lekko niebieskawym odcieniu, co sprzyja bytowaniu sielawy i dużych drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80708, 'Jezioro Gardliczno Małe', 'jezioro-gardliczno-male', 'LAKE', '53.90396024812574', '17.532499074260755', 'Pomorskie', 'Brusy', 'Mniejszy brat Gardliczna Dużego, połączony z nim wąskim przesmykiem. Akwen ma jednak zupełnie inny charakter – jest znacznie płytszy i bardziej eutroficzny. Dno pokrywa warstwa miękkiego mułu organicznego, a brzegi są mocno zarośnięte szerokim pasem trzcin i grążeli żółtych. To typowe jezioro "linowo-szczupakowe", w którym woda nagrzewa się znacznie szybciej niż w rynnie obok.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80709, 'Jezioro Nawionek', 'jezioro-nawionek', 'LAKE', '53.911075675157235', '17.53123271727675', 'Pomorskie', 'Brusy', 'Jezioro Nawionek to unikat na skalę europejską – klasyczne jezioro lobeliowe o skrajnie niskiej żyzności (oligotroficzne) i niesamowitej, wręcz sterylnej przejrzystości wody. Dno jest piaszczyste, twarde, a charakterystyczna roślinność (lobelia jeziorna, poryblin jeziorny) tworzy podwodne murawy widoczne z kilku metrów głębokości. Akwen jest objęty ochroną rezerwatową, co sprawia, że wędkowanie tutaj podlega bardzo surowym rygorom.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80710, 'Jezioro Czarne', 'jezioro-czarne-brusy', 'LAKE', '53.91224258885355', '17.513576154863255', 'Pomorskie', 'Brusy', 'Typowe jezioro dystroficzne (humusowe) ukryte w głębokim lesie sosnowym. Nazwa idealnie oddaje kolor wody – jest ona ciemna, niemal czarna, co wynika z wysokiej zawartości kwasów humusowych wypłukiwanych z torfowisk. Dno jest bardzo miękkie, wyścielone grubą warstwą osadów torfowych i opadłych liści. Jezioro nie posiada odpływów, co tworzy zamknięty, intymny ekosystem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80711, 'Jezioro Zmarłe Duże', 'jezioro-zmarle-duze', 'LAKE', '53.9210200972454', '17.52854289668488', 'Pomorskie', 'Brusy', 'Jezioro Zmarłe Duże to jeden z najbardziej fascynujących akwenów regionu, położony w sercu Borów Tucholskich. Jest to głębokie jezioro rynnowe (ponad 18 m głębokości) o wybitnie czystej, chłodnej wodzie (I klasa). Dno jest twarde, piaszczyste, ze stromymi spadkami. Brak dopływów powierzchniowych sprawia, że woda jest nieskazitelnie przejrzysta, a roślinność zanurzona (łąki ramienicowe) sięga bardzo głęboko.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80712, 'Jezioro Wilczak', 'jezioro-wilczak', 'LAKE', 53.458953, 18.944678, 'Kujawsko-Pomorskie', 'Radzyń Chełmiński', 'Wilczak to kameralny zbiornik rynnowy położony w pofałdowanym terenie rolniczo-leśnym. Posiada piaszczysto-muliste dno i dobrą klasę czystości. To woda bardzo stabilna, słynąca z dużego leszcza i płoci, które wyśmienicie reagują na nęcenie.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80713, 'Jezioro Mielno', 'jezioro-mielno-mazury', 'LAKE', '53.49412938879594', '20.276978060505282', 'Warmińsko-Mazurskie', 'Mielno / Grunwald', 'Jezioro Mielno to zjawiskowy akwen rynnowy o powierzchni około 360 hektarów, malowniczo położony w sercu Mazur Zachodnich. Charakteryzuje się bardzo wydłużonym kształtem i urozmaiconym dnem, gdzie głębokie rynny (do 40 m!) sąsiadują z rozległymi piaszczystymi blatami. Woda jest czysta, o dobrej przejrzystości, co sprzyja rozwojowi sielawy. Brzegi są w większości wysokie i zalesione, co nadaje jezioru surowy, niemal górski klimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80714, 'Jezioro Tymawskie', 'jezioro-tymawskie', 'LAKE', '53.48904456766221', '20.251892858500792', 'Warmińsko-Mazurskie', 'Tymawa / Grunwald', 'Jezioro Tymawskie to urokliwy zbiornik rynnowy stanowiący południowe przedłużenie kompleksu jeziora Mielno. Jest to akwen znacznie mniejszy i spokojniejszy, o powierzchni ok. 50 ha. Dno jest tu urozmaicone, piaszczysto-muliste, ze spadami schodzącymi do około 10-12 metrów. Brzegi są w większości niskie, częściowo bagniste, porośnięte szerokim pasem trzcin i tataraku, co stwarza idealne warunki dla ryb litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80715, 'Jezioro Okomin Mały', 'jezioro-okomin-maly', 'LAKE', '53.50022156680824', '20.303892829388637', 'Warmińsko-Mazurskie', 'Olsztynek', 'Niewielkie, śródleśne jezioro o charakterze dystroficzno-eutroficznym, ukryte w kompleksie lasów państwowych. Okomin Mały jest akwenem bardzo wyciszonym, z dnem wyścielonym grubą warstwą osadów organicznych i liści. Woda ma lekko herbaciany odcień, typowy dla jezior otoczonych borem sosnowym. Maksymalna głębokość nie przekracza kilku metrów, a strefa przybrzeżna jest silnie zdominowana przez roślinność wynurzoną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80716, 'Jezioro Okomin Wielki', 'jezioro-okomin-wielki', 'LAKE', '53.504131584861774', '20.306855401194213', 'Warmińsko-Mazurskie', 'Olsztynek', 'Jezioro Okomin Wielki to majestatyczna rynna polodowcowa, znacznie głębsza i bardziej przejrzysta niż jej mniejszy sąsiad. Akwen zajmuje około 100 hektarów i charakteryzuje się bardzo czystą wodą oraz twardym, piaszczysto-żwirowym dnem. Batymetria jest typowo rynnowa: ostre spady zaczynają się blisko brzegu i schodzą w mrok głębin sięgających ponad 20 metrów. Roślinność wodna jest tu rzadsza, skupiona głównie w wąskim pasie przybrzeżnym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80717, 'Jezioro Gajskie', 'jezioro-gajskie', 'LAKE', '53.51137312260956', '20.298462461196596', 'Warmińsko-Mazurskie', 'Olsztynek', 'Jezioro Gajskie to kameralny akwen o powierzchni ok. 25 ha, położony w pagórkowatym terenie rolniczo-leśnym. Jezioro ma charakter eutroficzny, z dnem w dużej mierze mulistym, ale z wyraźnymi piaszczystymi wypłyceniami od strony miejscowości Gaj. Linia brzegowa jest stosunkowo regularna, a maksymalna głębokość oscyluje wokół 6-8 metrów. Woda jest żyzna i szybko się nagrzewa, co sprzyja obfitości pokarmu naturalnego.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80718, 'Jezioro Czarne (Osiek - Północ)', 'jezioro-czarne-osiek-2', 'LAKE', 53.753509, 18.514134, 'Pomorskie', 'Osiek / Skórcz', 'Północne jezioro Czarne to akwen o charakterze rynnowym, głębszy od swojego południowego imiennika. Charakteryzuje się twardszym dnem i obecnością sandacza. Brzegi są strome i gęsto zalesione.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80719, 'Jezioro Gąsiorowskie', 'jezioro-gasiorowskie', 'LAKE', '53.51368651918639', '20.283729469685657', 'Warmińsko-Mazurskie', 'Gąsiorowo / Olsztynek', 'Jezioro Gąsiorowskie to kolejna rynnowa perła w okolicy Olsztynka, cechująca się wydłużonym kształtem i twardym, polodowcowym dnem. Akwen jest dość głęboki (do 15 m), z wyraźnie zarysowanymi spadkami i rynną centralną. Woda jest dobrze natleniona i zachowuje przyzwoitą przejrzystość przez większość sezonu. Brzegi są urozmaicone – od piaszczystych plaż po zarośnięte, dzikie skarpy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80720, 'Jezioro Liwia Łuża', 'jezioro-liwia-luza-2', 'LAKE', '54.088635798859784', '15.096497762415476', 'Zachodniopomorskie', 'Niechorze', 'Liwia Łuża to unikatowe jezioro nadmorskie o statusie rezerwatu ornitologicznego, położone tuż przy Niechorzu. Jest to akwen lagunowy, połączony z Bałtykiem kanałem Liwia Łuża, co powoduje okresowe wlewy słonej wody (tzw. cofka). Jezioro jest bardzo płytkie (średnio ok. 1 m), a jego dno pokrywa gruba warstwa mułu organicznego zmieszanego z piaskiem morskim. Całość otacza szeroki, niemal niedostępny pas trzcinowisk.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80721, 'Jezioro Konarzewo (Bagniste)', 'jezioro-konarzewo', 'LAKE', '54.090016280002935', '15.1414098597857', 'Zachodniopomorskie', 'Pogorzelica', 'Jezioro Konarzewo, zwane przez lokalnych wędkarzy "Bagnistym", to dziki i niemal całkowicie zarośnięty akwen przymorski położony na wschód od Pogorzelicy. Jezioro jest w końcowej fazie sukcesji – lustro wody jest niewielkie w stosunku do obszaru trzcinowisk i bagnistych łąk. Głębokość rzadko przekracza 1,5 metra, a dno to puszysta, metrowa warstwa torfu i gnilnych osadów roślinnych. Woda ma ciemny, herbaciany kolor.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80722, 'Jezioro Dąbrowa Wielka', 'jezioro-dabrowa-wielka', 'LAKE', '53.437036032263336', '20.052026713845045', 'Warmińsko-Mazurskie', 'Dąbrówno', 'Dąbrowa Wielka to potężne jezioro rynnowe o powierzchni ponad 600 hektarów, stanowiące wędkarskie serce Mazur Zachodnich. Akwen charakteryzuje się monumentalną batymetrią – dno opada stromo do centralnej rynny osiągającej ponad 30 metrów głębokości. Linia brzegowa jest urozmaicona licznymi półwyspami, a twarde, piaszczysto-kamieniste stoki są idealnym siedliskiem dla drapieżników. Przez jezioro przepływa rzeka Wel, co zapewnia stały dopływ natlenionej wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80723, 'Jezioro Dąbrowa Mała', 'jezioro-dabrowa-mala', 'LAKE', '53.45218957708466', '20.01274276851304', 'Warmińsko-Mazurskie', 'Dąbrówno', 'Mniejsza siostra Dąbrowy Wielkiej, połączona z nią kanałem. Mimo nazwy, to wciąż spore jezioro (ok. 170 ha) o typowo rynnowym charakterze. Jest jednak nieco płytsze i bardziej osłonięte od wiatru, co sprawia, że woda nagrzewa się tu szybciej. Brzegi są wyższe, w dużej mierze zalesione, z bardzo wąskim ale gęstym pasem trzcin. Dno jest urozmaicone, z licznymi powalonymi drzewami, szczególnie od strony zachodniej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80724, 'Jezioro Lubień', 'jezioro-lubien', 'LAKE', '53.475380420459494', '20.17970709176273', 'Warmińsko-Mazurskie', 'Gierzwałd / Olsztynek', 'Jezioro Lubień to malowniczy, rynnowy zbiornik polodowcowy położony w pagórkowatym terenie Mazur Zachodnich. Akwen charakteryzuje się bardzo czystą wodą i twardym, piaszczystym dnem, które stromo opada w stronę rynny sięgającej blisko 15-18 metrów. Jezioro jest otoczone w dużej mierze polami i kępami lasów, co sprzyja dobremu natlenieniu wody przez wiatr.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80725, 'Jezioro Kownatki', 'jezioro-kownatki', 'LAKE', '53.42306583387525', '20.25623651817069', 'Warmińsko-Mazurskie', 'Kozłowo / Nidzica', 'Jezioro Kownatki to absolutna legenda czystości – uznawane za jedno z najprzejrzystszych jezior w Polsce (widoczność sięga czasem 10 metrów!). Jest to głęboka rynna sielawowa (max. 31 m) o dnie twardym, piaszczysto-żwirowym i niemal całkowitym braku mułu w strefie litoralu. Woda jest zimna i wysoce natleniona, co warunkuje egzystencję sielawy oraz dużych drapieżników pelagicznych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80726, 'Jezioro Małe Świdno', 'jezioro-male-swidno', 'LAKE', '54.228852409053246', '16.336342110530104', 'Zachodniopomorskie', 'Koszalin / Polanów', 'Małe Świdno to niezwykle urokliwe, typowo leśne jezioro położone w głębokiej polodowcowej niecce. W odróżnieniu od wielkich jezior przymorskich, jest to akwen o charakterze dystroficzno-eutroficznym, otoczony gęstym borem iglastym. Dno jest tu bardzo miękkie, wyścielone grubą warstwą osadów organicznych i igliwia, co nadaje wodzie charakterystyczny, herbaciany kolor. Średnia głębokość oscyluje wokół 2-3 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80727, 'Jezioro Jamno', 'jezioro-jamno-mielno', 'LAKE', '54.278341204523414', '16.156444097089835', 'Zachodniopomorskie', 'Mielno / Koszalin', 'Jamno to dziewiąte pod względem powierzchni jezioro w Polsce, klasyczny akwen przymorski (lagunowy), połączony z Bałtykiem kanałem Jamneńskim. Jest to jezioro bardzo płytkie (średnio 1,4 m), o dnie skrajnie mulistym i bardzo mętnej wodzie. Specyfika Jamna to ogromna biomasa ryb, która wynika z wysokiej żyzności i dopływu wód morskich. Jezioro jest wystawione na silne wiatry, co powoduje stałe mieszanie osadów dennych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80728, 'Jezioro Bukowo', 'jezioro-bukowo-dabki', 'LAKE', '54.34383781004169', '16.277225079792807', 'Zachodniopomorskie', 'Dąbki', 'Jezioro Bukowo to dawna zatoka morska, oddzielona od Bałtyku Mierzeją Bukowską i połączona z nim Kanałem Szczuczym. Akwen o powierzchni ok. 1700 ha jest płytki (średnio 1,8 m) i charakteryzuje się wodą słonawą (mezohalinową). Dno jest piaszczysto-muliste, a woda znacznie czystsza i lepiej natleniona niż w sąsiednim Jamnie, co sprzyja bogatszemu składowi gatunkowemu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80729, 'Jezioro Młyńskie (Rybojedzko)', 'jezioro-mlynskie-rybojedzko', 'LAKE', 52.108113, 15.057964, 'Lubuskie', 'Maszewo / Rybojedzko', 'Jezioro Młyńskie to urokliwy akwen rynnowy o dnie piaszczysto-mulistym. Woda posiada przyzwoitą klasę czystości. Brzegi są częściowo porośnięte lasem mieszanym, z wieloma dzikimi stanowiskami wędkarskimi. Spinningiści cenią jezioro za populację szczupaka i dorodnego okonia.', 'PZW Zielona Góra');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80730, 'Jezioro Kopań', 'jezioro-kopan-darlowo', 'LAKE', '54.48177169860326', '16.449939408330103', 'Zachodniopomorskie', 'Darłowo / Kopań', 'Jezioro Kopań to wybitny akwen przymorski, oddzielony od morza jedynie wąskim pasem wydm, co sprawia, że podczas sztormów woda morska przelewa się bezpośrednio do jeziora. Jest to zbiornik bardzo płytki (max 4 m), o dnie w przeważającej mierze piaszczystym z warstwą osadów przy brzegach. Brak osłony brzegowej sprawia, że Kopań jest jednym z najwietrzniejszych jezior w Polsce.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80731, 'Jezioro Wicko', 'jezioro-wicko-nadmorskie', 'LAKE', '54.53682505324285', '16.63863632770844', 'Zachodniopomorskie', 'Jarosławiec', 'Jezioro Wicko położone niedaleko Jarosławca to duży (ponad 1000 ha), płytki akwen powstały z dawnej zatoki morskiej. Charakteryzuje się wodą słonawą i bardzo żyznym, mulistym dnem. Jezioro dzieli się na dwie części (wschodnią i zachodnią) połączone przesmykiem. Brzegi są niskie, porośnięte szerokim pasem trzcin, co stwarza wyśmienite warunki dla rozrodu ryb drapieżnych i białorybu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80732, 'Jezioro Modła', 'jezioro-modla', 'LAKE', '54.5513221005836', '16.790108329584573', 'Pomorskie', 'Ustka / Duninowo', 'Jezioro Modła to unikatowy, rezerwatowy akwen przymorski położony na zachód od Ustki. Jest to jezioro w zaawansowanej fazie zarastania, niezwykle płytkie, o dnie w całości mulisto-torfowym. Całość akwenu otoczona jest bagnistymi łąkami i trzęsawiskami, co tworzy naturalną barierę dla turystyki masowej. Woda jest żyzna, o słonawym odcieniu, stanowiąca ostoję dla rzadkich gatunków ptaków wodnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80733, 'Jezioro Gardno', 'jezioro-gardno-rowy', 'LAKE', '54.64741985671956', '17.112631452645722', 'Pomorskie', 'Rowy', 'Gardno to potężne jezioro przymorskie (lagunowe) w granicach Słowińskiego Parku Narodowego. To olbrzymia, płytka niecka o powierzchni blisko 2500 ha i średniej głębokości zaledwie 1,3 m. Jezioro jest zasilane wodami rzeki Łupawy i połączone z morzem kanałem w Rowach. Woda jest bardzo mętna (mieszanie osadów przez wiatr) i słonawa. Dno jest piaszczysto-muliste, obfite w pokarm naturalny.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80734, 'Jezioro Resko Przymorskie', 'jezioro-resko-dzwirzyno', 'LAKE', '54.14339773953388', '15.373641807134058', 'Zachodniopomorskie', 'Dźwirzyno', 'Jezioro Resko Przymorskie to dawna zatoka Bałtyku położona między Dźwirzynem a Rogowem. Akwen o powierzchni ok. 570 ha jest płytki (średnio 1,5 m), połączony z morzem kanałem portowym. Batymetria jest wyrównana, z dnem piaszczystym od strony mierzei i mulistym w głębi lądu. Woda jest słonawa, co przyciąga gatunki typowo morskie, takie jak flądry i węgorze.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80735, 'Jezioro Kamienne', 'jezioro-kamienne-polanow', 'LAKE', '54.023367419019515', '16.73637381292247', 'Zachodniopomorskie', 'Polanów', 'Jezioro Kamienne to urokliwy, leśny akwen rynnowy, który swoją nazwę zawdzięcza wyjątkowo twardemu, usianemu głazami narzutowymi dnu. Batymetria jest tu typowa dla rynien polodowcowych – ostre, piaszczysto-żwirowe stoki gwałtownie uciekają w mrok głębin sięgających ponad 15 metrów. Woda jest czysta, o lekko niebieskawym odcieniu, dobrze natleniona przez bijące pod lodem źródła krasowe.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80736, 'Jezioro Gromadzkie', 'jezioro-gromadzkie-lubuskie', 'LAKE', 52.10341, 15.070817, 'Lubuskie', 'Maszewo / Rybojedzko', 'Jezioro Gromadzkie to kameralny, śródpolny zbiornik o charakterze eutroficznym. Posiada muliste dno i średnią głębokość ok. 3-4 metrów. Woda jest żyzna, co sprzyja biomasie ryb karpiowatych. Jezioro jest wyciszone, stanowiąc doskonałe miejsce dla ryb spokojnego żeru.', 'PZW Zielona Góra');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80737, 'Jezioro Kwiecko', 'jezioro-kwiecko', 'LAKE', '54.02117869709556', '16.695596354913054', 'Zachodniopomorskie', 'Polanów / Żydowo', 'Jezioro Kwiecko to unikatowy akwen pełniący funkcję dolnego zbiornika Elektrowni Szczytowo-Pompowej Żydowo. Specyfika tego jeziora to ogromne, codzienne wahania poziomu wody (nawet do 3 metrów!) oraz wymuszone prądy, co upodabnia je do rzeki. Dno jest w dużej mierze wymyte, piaszczysto-kamieniste, z głębokimi rynnami w osi przepływu rzeki Radwi. Brzegi są częściowo umocnione betonowymi płytami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80738, 'Jezioro Wielkie', 'jezioro-wielkie-polanow', 'LAKE', '54.09304666080428', '16.594050032189237', 'Zachodniopomorskie', 'Polanów', 'Jezioro Wielkie koło Polanowa to rozległa, polodowcowa rynna otoczona gęstymi lasami iglastymi. Akwen charakteryzuje się bardzo regularną batymetrią z dnem twardym, piaszczystym w pasie przybrzeżnym i mulistym w najgłębszych partiach (do 12 m). Woda posiada dobrą klasę czystości, a linia brzegowa jest urozmaicona licznymi powalonymi drzewami, co stwarza wyśmienite naturalne kryjówki dla ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80739, 'Jezioro Nicemino', 'jezioro-nicemino', 'LAKE', '54.11812303271684', '16.47298445923114', 'Zachodniopomorskie', 'Manowo / Koszalin', 'Nicemino to kameralny i stosunkowo płytki akwen (max 6 m) o charakterze wybitnie eutroficznym, położony w powiecie koszalińskim. Jezioro charakteryzuje się miękkim, żyznym dnem i obfitą roślinnością litoralną. Szeroki pas trzcin i liczne skupiska grążeli żółtych stwarzają idealne warunki dla ryb spokojnego żeru. Woda nagrzewa się szybko, co sprzyja intensywnym żerowaniom wiosennym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80740, 'Jezioro Mełno', 'jezioro-melno', 'LAKE', 53.440377, 19.005489, 'Kujawsko-Pomorskie', 'Gruta / Mełno', 'Rozległy (pow. ok. 150 ha), płytki akwen o wybitnie żyznej wodzie. Charakteryzuje się mulistym dnem i bardzo szerokim pasem trzcinowisk. Słynie z rekordowych karpi i amurów. To łowisko wybitnie karpiowe, wymagające ciężkiego nęcenia i cierpliwości.', 'Gospodarstwo Rybackie / PZW');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80741, 'Jezioro Rosnowskie', 'jezioro-rosnowskie', 'LAKE', '54.073674359233976', '16.33947991276686', 'Zachodniopomorskie', 'Rosnowo', 'Jezioro Rosnowskie to potężny zbiornik zaporowy na rzece Radwi, jeden z najbardziej popularnych akwenów w okolicach Koszalina. Posiada bardzo urozmaicony kształt z licznymi odnogami i rynnami. Dno jest pofałdowane, piaszczysto-muliste, z licznymi pozostałościami po zalanych terenach (korzenie, rowy). Średnia głębokość to ok. 5 metrów, z dołkami przy zaporze sięgającymi 10-12 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80742, 'Jezioro Hajka', 'jezioro-hajka', 'LAKE', '54.06914942244585', '16.222365709067596', 'Zachodniopomorskie', 'Rosnowo / Manowo', 'Jezioro Hajka to mniejszy, bardzo malowniczy zbiornik zaporowy na rzece Radwi, położony poniżej zapory w Rosnowie. Akwen ma charakter rynnowo-przepływowy, z wyraźnie zaznaczonym nurtem rzeki. Dno jest twarde, piaszczysto-żwirowe, z licznymi powalonymi dębami i olszynami w pasie brzegowym. Woda jest dobrze natleniona i chłodniejsza niż w Rosnowie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80743, 'Jezioro Lubiatowo (Południe)', 'jezioro-lubiatowo-poludnie', 'LAKE', '54.15303950483496', '16.27642264451482', 'Zachodniopomorskie', 'Lubiatowo / Koszalin', 'Południowa część Jeziora Lubiatowskiego to obszar o charakterze wybitnie tarliskowym i ochronnym. Jest to rejon płytszy, silnie zarośnięty trzcinowiskami i grzybieniami, z dnem mulistym obfitującym w bentos. Woda jest tu cieplejsza, co przyciąga ogromne ilości ryb białych w okresie wiosennym. Brzegi są niskie, często podmokłe, co chroni ten sektor przed nadmierną presją.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80744, 'Jezioro Lubiatowo (Wschód)', 'jezioro-lubiatowo-wschod', 'LAKE', '54.15457046170229', '16.293663707564924', 'Zachodniopomorskie', 'Lubiatowo / Koszalin', 'Wschodni brzeg Jeziora Lubiatowskiego charakteryzuje się twardszym, piaszczysto-żwirowym dnem i nieco wyraźniejszymi spadami dna. Jest to sektor bardziej otwarty na wiatr, co powoduje dobre natlenienie wody. Litoral jest tu węższy, co ułatwia dostęp do wody od strony lądu. Występują tu liczne piaszczyste blaty, na których ryba chętnie żeruje po zmroku.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80745, 'Jezioro Smołowe', 'jezioro-smolowe', 'LAKE', '54.032264154052214', '17.07762741139357', 'Pomorskie', 'Miastko', 'Jezioro Smołowe to niezwykle urokliwy, leśny akwen o charakterze dystroficzno-eutroficznym, położony w głębokiej niecce polodowcowej. Jezioro charakteryzuje się bardzo ciemną, niemal czarną wodą (stąd nazwa), co wynika z wysokiej zawartości kwasów humusowych. Dno jest wysoce muliste, okryte grubą warstwą organicznego detrytusu, a brzegi są miękkie i bagniste, porośnięte gęstymi olsami i brzeziną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80746, 'Jezioro Dolskie', 'jezioro-dolskie', 'LAKE', '54.01678259755569', '17.09861168916871', 'Pomorskie', 'Miastko / Dretyń', 'Jezioro Dolskie to malownicza rynna leśna o wydłużonym kształcie, wciśnięta w pofalowany teren borów sosnowych. Akwen posiada wyraźnie zarysowaną rzeźbę dna z centralną rynną sięgającą około 10 metrów głębokości. Woda jest czysta, o dobrej przejrzystości, co sprzyja rozwojowi roślinności podwodnej, głównie rdestnicy. Brzegi są wyższe i twardsze niż w sąsiednim Smołowem, co ułatwia dostęp do wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80747, 'Jezioro Bobięcińskie Małe', 'jezioro-bobiecinskie-male', 'LAKE', '54.01617466194812', '16.82145670168983', 'Pomorskie / Zachodniopomorskie', 'Bobięcino', 'Mniejsza, północna część kompleksu Bobięcińskiego, połączona z Wielkim przesmykiem. Mimo nazwy "Małe", to wciąż głęboki (do 15-18 m) i niezwykle przejrzysty akwen o charakterze rynnowym. Jest jednak nieco bardziej osłonięty od wiatru przez wysokie brzegi porośnięte buczyną. Dno jest piaszczyste, z rzadkimi płatami moczarki kanadyjskiej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80748, 'Jezioro Siadło', 'jezioro-siadlo', 'LAKE', '54.004632682974545', '17.075113137376178', 'Pomorskie', 'Miastko / Świeszyno', 'Jezioro Siadło to niewielki, kameralny zbiornik rynnowy o bardzo czystej wodzie i twardym, piaszczysto-żwirowym dnie. Akwen cechuje się regularnymi spadkami i głębokością oscylującą wokół 6-8 metrów. Jezioro jest otoczone wianuszkiem lasu, co zapewnia doskonałą osłonę przed wiatrem. Roślinność brzegowa jest wąska, ale zwarta, z przewagą trzciny pospolitej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80749, 'Jezioro Świeszyńskie', 'jezioro-swieszynskie', 'LAKE', '53.994535414024604', '17.080314183413176', 'Pomorskie', 'Świeszyno', 'Jezioro Świeszyńskie to jedna z pereł regionu miasteckiego, akwen rynnowy o powierzchni około 100 hektarów. Charakteryzuje się bardzo czystą wodą (I klasa) i urozmaiconą batymetrią z głębokimi rynnami sięgającymi ponad 15 metrów. Dno jest twarde, w dużej mierze piaszczyste, z licznymi podwodnymi górkami. Brzegi są zróżnicowane: północna część przylega do miejscowości Świeszyno (plaże, pomosty), a południowa jest dzika i zalesiona.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80750, 'Jezioro Starzeńskie', 'jezioro-starzenskie', 'LAKE', '53.97168330635445', '17.067556592079594', 'Pomorskie', 'Starzno', 'Jezioro Starzeńskie to długi i wąski akwen rynnowy o wybitnie polodowcowym charakterze. Dno jest tu twarde, piaszczyste, ze stromymi spadkami schodzącymi do rynny o głębokości ok. 10-12 metrów. Woda jest dobrze natleniona i zachowuje przejrzystość przez większość sezonu. Brzegi są wysokie, porośnięte lasem liściastym, co nadaje jezioru specyficzny, kameralny mikroklimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80751, 'Jezioro Studzieniczno', 'jezioro-studzieniczno', 'LAKE', '53.97376085641174', '17.01247306581484', 'Pomorskie', 'Studzienice', 'Jezioro Studzieniczno to rozległy akwen rynnowy (ponad 100 ha) o zróżnicowanej batymetrii. Posiada kilka głębokich rynien (do 20 m) oraz rozległe, piaszczyste wypłycenia w części północnej. Woda posiada dobrą klasę czystości, a dno jest w przeważającej mierze twarde, piaszczysto-żwirowe. Brzegi są w większości dostępne, z licznymi ośrodkami i pomostami, co czyni go popularnym miejscem rekreacji.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80752, 'Jezioro Olejnickie', 'jezioro-olejnickie', 'LAKE', 51.967439, 16.245346, 'Wielkopolskie', 'Przemęt / Olejnica', 'Jezioro Olejnickie to malownicza rynna rynnowa (pow. ok. 35 ha) połączona kanałami z sąsiednimi akwenami. Charakteryzuje się twardym dnem i czystą wodą. Maksymalna głębokość oscyluje wokół 8-10 metrów. Jezioro otoczone jest gęstymi lasami i pagórkami, co nadaje mu kameralny charakter i zapewnia osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80753, 'Jezioro Bobięcińskie Wielkie', 'jezioro-bobiecinskie-wielkie', 'LAKE', '54.00734304673757', '16.81031251743756', 'Pomorskie / Zachodniopomorskie', 'Bobięcino / Miastko', 'Bobięcińskie Wielkie to największe w Europie Środkowej jezioro lobeliowe i absolutny unikat hydrologiczny. Akwen o powierzchni ponad 500 ha i głębokości sięgającej 48 metrów (!) charakteryzuje się niesamowitą, krystaliczną przejrzystością wody i twardym, piaszczysto-żwirowym dnem. Posiada liczne wyspy (największa to Wyspa Ostrów) i stromo opadające klify podwodne. Woda jest zimna i wysoce natleniona.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80754, 'Jezioro Bobięcińskie (Główne)', 'jezioro-bobiecinskie-glowne', 'LAKE', '54.0083543952486', '16.803101734963043', 'Pomorskie / Zachodniopomorskie', 'Bobięcino', 'Centralna część kompleksu Bobięcińskiego, charakteryzująca się potężną otwartą tonią i krystaliczną wodą. Batymetria to labirynt głębokich rynien i podwodnych wzniesień. Dno jest wybitnie twarde, wysadzane wapieniami. Brak istotnych dopływów rolniczych sprawia, że woda zachowuje sterylną wręcz czystość przez cały rok.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80755, 'Jezioro Gwieździniec', 'jezioro-gwiezdziniec', 'LAKE', '54.007590537565896', '17.25405554922624', 'Pomorskie', 'Miastko / Piaszczyna', 'Jezioro Gwieździniec to malowniczy, śródleśny akwen o charakterze rynnowym, położony w pagórkowatym terenie Borów Tucholskich. Jezioro charakteryzuje się bardzo czystą wodą i twardym, piaszczystym dnem, które wzdłuż wschodniego brzegu stromo opada do centralnej rynny sięgającej ok. 10-12 metrów. Brzegi są wysokie, porośnięte starym lasem sosnowym, co nadaje jezioru dziki i ustronny klimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80756, 'Jezioro Wiejskie', 'jezioro-wiejskie-piaszczyna', 'LAKE', '54.020046174340706', '17.285311893777394', 'Pomorskie', 'Piaszczyna', 'Jezioro Wiejskie położone w miejscowości Piaszczyna to akwen o charakterze eutroficznym, stanowiący lokalne centrum wędkarskie. Jezioro jest stosunkowo płytkie (max 6-7 m) z dnem w dużej mierze mulistym, ale z wyraźnymi piaszczystymi wypłyceniami w rejonie zabudowań. Linia brzegowa jest urozmaicona, z gęstym pasem trzcin i licznymi pomostami wędkarskimi, co czyni je bardzo dostępnym z lądu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80757, 'Jezioro Piaszno Małe', 'jezioro-piaszno-male', 'LAKE', '54.01798424702683', '17.31974410097036', 'Pomorskie', 'Piaszno', 'Jezioro Piaszno Małe to kameralny, wybitnie leśny zbiornik o charakterze dystroficznym, ukryty w głębokiej polodowcowej rynnie. Akwen charakteryzuje się mroczną, lekko brunatną wodą i miękkim dnem wyścielonym osadami leśnymi. Jezioro jest osłonięte wysokimi skarpami porośniętymi buczyną, co sprawia, że tafla wody niemal zawsze jest gładka. Maksymalna głębokość oscyluje wokół 5 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80758, 'Jezioro Piaszno (Wielkie)', 'jezioro-piaszno-wielkie', 'LAKE', '54.02445929650489', '17.32490119465589', 'Pomorskie', 'Piaszno', 'Jezioro Piaszno to reprezentacyjny akwen rynnowy regionu, znany z czystej wody i twardego, piaszczysto-żwirowego dna. Jezioro zajmuje ok. 70 hektarów i charakteryzuje się wyraźnie zarysowaną rynną środkową sięgającą blisko 20 metrów głębokości. Brzegi są w większości wysokie i piaszczyste, z rzadkim, ale twardym pasem trzcin. Woda posiada dobrą klasę czystości, co sprzyja rozwojowi sielawy i dużych okoni.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80759, 'Jezioro Kuchenek', 'jezioro-kuchenek', 'LAKE', '54.023010004418474', '17.315233963052314', 'Pomorskie', 'Piaszno', 'Jezioro Kuchenek to niewielki, niemal okrągły zbiornik o charakterze eutroficznym, położony w bezpośrednim sąsiedztwie jeziora Piaszno. Akwen jest stosunkowo płytki (max 4 m) i silnie zarastający roślinnością miękką. Dno jest muliste, bogate w bentos, co czyni je doskonałą stołówką dla ryb karpiowatych. Jezioro otoczone jest pasem olch i wierzb, co zapewnia rybom liczne kryjówki pod zwisającymi gałęziami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80760, 'Jezioro Bluj', 'jezioro-bluj', 'LAKE', '54.041596251722176', '17.186581514427978', 'Pomorskie', 'Wałdowo / Miastko', 'Jezioro Bluj to dziki, śródleśny akwen rynnowy o bardzo urozmaiconej rzeźbie dna. Charakteryzuje się czystą wodą i twardym, polodowcowym dnem z licznymi podwodnymi górkami. Centralna rynna osiąga głębokość ok. 10 metrów. Jezioro jest w całości otoczone gęstym lasem sosnowym, co chroni je przed wiatrem i zapewnia absolutną wędkarską ciszę. Brzegi są wysokie i strome, co ogranicza liczbę stanowisk brzegowych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80761, 'Jezioro Boczne (Przerośl)', 'jezioro-boczne-przerosl', 'LAKE', 54.276226, 22.646813, 'Podlaskie', 'Przerośl / Pawłówka', 'Jezioro Boczne to mniejszy zbiornik rynnowy położony na północ od Przerośli. Charakteryzuje się czystą wodą i dnem twardym, w dużej mierze piaszczystym. Akwen posiada wydłużony kształt i strome spady wzdłuż zachodniego brzegu. Roślinność brzegowa jest wąska, co ułatwia spinningowanie z lądu. Jezioro jest zaciszne, otoczone polami i kępami lasu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80762, 'Jezioro Wałdowskie Wielkie', 'jezioro-waldowskie-wielkie', 'LAKE', '54.057496643974964', '17.164782647157026', 'Pomorskie', 'Wałdowo', 'Jezioro Wałdowskie Wielkie to największy zbiornik w rejonie Wałdowa, akwen rynnowy o powierzchni ok. 70 ha. Cechuje się wydłużonym kształtem i znacznymi głębokościami dochodzącymi do 15 metrów. Dno jest piaszczysto-żwirowe, w głębszych partiach muliste. Woda posiada dobrą przejrzystość, choć w lecie ulega naturalnym zakwitom. Północna część jeziora przylega do zabudowań wsi, oferując dobrą infrastrukturę, podczas gdy południowa jest dzika i zalesiona.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80763, 'Jezioro Czarne (Kot)', 'jezioro-czarne-kot', 'LAKE', 53.549385, 20.633097, 'Warmińsko-Mazurskie', 'Kot', 'Jezioro Czarne koło miejscowości Kot to niewielki, kameralny zbiornik dystroficzny otoczony gęstym borem sosnowym. Woda posiada ciemny odcień, a dno jest bardzo miękkie, wyścielone osadami leśnymi. Jezioro jest osłonięte od wiatrów, co sprawia, że tafla wody niemal zawsze jest gładka. Maksymalna głębokość nie przekracza kilku metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80764, 'Jezioro Gomolskie Wielkie', 'jezioro-gomolskie-wielkie', 'LAKE', '54.040725847909655', '17.153764696733013', 'Pomorskie', 'Wałdowo', 'Jezioro Gomolskie Wielkie to urokliwy zbiornik rynnowy położony na południowy zachód od Wałdowa. Akwen charakteryzuje się czystą wodą i twardym dnem, które stromo opada w stronę rynny sięgającej 12-14 metrów głębokości. Jezioro jest otoczone wianuszkiem lasów i pól, co sprzyja dobremu natlenieniu wody. Roślinność wodna jest tu umiarkowana, z przewagą rzadkich pasów trzcin i moczarki podwodnej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80765, 'Jezioro Żabionek', 'jezioro-zabionek', 'LAKE', '53.928261286294905', '17.519864684556783', 'Pomorskie', 'Swornegacie', 'Jezioro Żabionek to urokliwy, śródleśny zbiornik o charakterze eutroficznym, położony w bezpośrednim sąsiedztwie Parku Narodowego Bory Tucholskie. Akwen jest stosunkowo płytki, z dnem w dużej mierze pokrytym miękkim osadem organicznym, co sprzyja rozwojowi gęstej roślinności zanurzonej. Woda nagrzewa się tu bardzo szybko, co czyni go idealnym miejscem dla ryb ciepłolubnych. Brzegi są niskie, porośnięte pasem trzcin i tataraku, zapewniając rybom doskonałe warunki do tarła.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80766, 'Jezioro Księże', 'jezioro-ksieze', 'LAKE', '53.93508578769025', '17.490701308821034', 'Pomorskie', 'Brusy / Swornegacie', 'Jezioro Księże to malowniczy zbiornik rynnowy, położony w otulinie leśnej, cechujący się bardzo dobrą przejrzystością wody. Akwen charakteryzuje się wyraźnie zarysowaną centralną rynną sięgającą blisko 12-14 metrów głębokości oraz twardym, piaszczysto-żwirowym dnem na stokach. Brzegi są wyższe, porośnięte lasem sosnowym, co zapewnia dobrą osłonę przed wiatrem i nadaje jezioru kameralny mikroklimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80767, 'Jezioro Śluza', 'jezioro-sluza', 'LAKE', '53.9200363539527', '17.48870449229673', 'Pomorskie', 'Swornegacie', 'Jezioro Śluza to niezwykle interesujący akwen rynnowo-przepływowy, przez który przepływa rzeka Brda. Nurt rzeki jest tu wyraźnie wyczuwalny, co powoduje stałe natlenienie wody i tworzenie się rzecznych struktur na dnie – rynien z twardym, wymytym dnem piaszczysto-żwirowym. Maksymalna głębokość oscyluje wokół 10 metrów. Akwen posiada bardzo rozwiniętą linię brzegową z licznymi półwyspami i piaszczystymi plażami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80768, 'Jezioro Kociołek (k. Grudziądza)', 'jezioro-kociolek-grudziadz', 'LAKE', 53.420431, 18.714051, 'Kujawsko-Pomorskie', 'Grudziądz / Biały Bór', 'Kociołek to niewielkie, niemal okrągłe jezioro wytopiskowe położone w lesie rudnickim. Mimo małej powierzchni jest stosunkowo głębokie (ok. 8-9 m). Woda jest czysta, o sielankowym charakterze. To typowa okoniowa perełka, idealna dla wędkarzy szukających ciszy tuż pod miastem.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80769, 'Jezioro Parszczenica', 'jezioro-parszczenica', 'LAKE', '53.92464161920172', '17.4575594428361', 'Pomorskie', 'Swornegacie', 'Parszczenica to dziki i rozległy akwen rynnowy, będący częścią szlaku wodnego Brdy. Jezioro charakteryzuje się bardzo urozmaiconym dnem – od rozległych piaszczystych blatów po głębokie rowy sięgające 15 metrów. Woda jest dobrze natleniona i żyzna, co przekłada się na ogromną biomasę ryb. Brzegi są w większości zalesione, z licznymi zatokami porośniętymi grzybieniami i moczarką podwodną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80770, 'Jezioro Lipczyno Wielkie', 'jezioro-lipczyno-wielkie', 'LAKE', '53.89251957921839', '17.2541771736781', 'Pomorskie', 'Przechlewo', 'Jezioro Lipczyno Wielkie to jedna z najczystszych pereł rynnowych w okolicach Przechlewa. Akwen o powierzchni ponad 150 hektarów charakteryzuje się nieskazitelną przejrzystością wody (I klasa) i twardym, piaszczysto-żwirowym dnem. Batymetria jest typowo polodowcowa: strome spady uciekają szybko do rynny sięgającej blisko 30 metrów głębokości. Woda jest zimna i wysoce natleniona, co warunkuje egzystencję sielawy oraz dużych drapieżników pelagicznych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80771, 'Jezioro Lipczyno Małe', 'jezioro-lipczyno-male', 'LAKE', '53.90434174063694', '17.253251034882705', 'Pomorskie', 'Przechlewo', 'Lipczyno Małe to kameralny i zaciszny akwen o charakterze eutroficznym, położony w bezpośrednim sąsiedztwie swojego "Wielkiego" brata. Jezioro jest stosunkowo płytkie (max 5-6 m) z dnem w dużej mierze mulistym. Linia brzegowa jest silnie porośnięte trzciną i otoczona majestatycznym borem sosnowym, co stwarza idealne warunki dla ryb spokojnego żeru i chroni przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80772, 'Jezioro Gwiazdy', 'jezioro-gwiazdy', 'LAKE', '53.975119907777874', '17.28813148392263', 'Pomorskie', 'Borzytuchom / Bytów', 'Jezioro Gwiazdy to duży i fascynujący akwen o urozmaiconej linii brzegowej, przypominający kształtem wieloramienną gwiazdę (stąd nazwa). Jest to jezioro rynnowe o powierzchni ponad 200 hektarów, cechujące się czystą wodą i twardym dnem z licznymi podwodnymi górkami. Centralna rynna osiąga głębokość ok. 15-18 metrów. Brzegi są w większości wysokie i zalesione, co nadaje jezioru surowy, puszczański charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80773, 'Jezioro Młyńskie (Borzytuchom)', 'jezioro-mlynskie-borzytuchom', 'LAKE', '53.975457011391505', '17.280335130285998', 'Pomorskie', 'Borzytuchom', 'Jezioro Młyńskie to mniejszy akwen rynnowy położony w bliskim sąsiedztwie jeziora Gwiazdy. Charakteryzuje się bardziej eutroficznym charakterem, z dnem mulistym i bogatszą roślinnością brzegową. Maksymalna głębokość oscyluje wokół 6-8 metrów. Woda jest żyzna i szybko się nagrzewa, co sprzyja obfitości pokarmu naturalnego i szybkiemu przyrostowi ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80774, 'Jezioro Długie (Borzytuchom)', 'jezioro-dlugie-borzytuchom', 'LAKE', '53.97674299930231', '17.26828884347528', 'Pomorskie', 'Borzytuchom', 'Jezioro Długie to typowa, wąska i głęboka rynna polodowcowa, będąca zachodnim przedłużeniem kompleksu jezior wokół Borzytuchomia. Akwen charakteryzuje się bardzo czystą wodą i twardym, piaszczysto-żwirowym dnem, które stromo opada w stronę rynny centralnej (max. 15 m). Brzegi są wysokie i zalesione, co nadaje jezioru surowy charakter. Roślinność wodna jest tu skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80775, 'Staw Żelazna Błacha', 'staw-zelazna-blacha', 'LAKE', 52.110118, 15.043437, 'Lubuskie', 'Maszewo / Rybojedzko', 'Żelazna Błacha to niewielkie leśne oczko, prawdopodobnie pozostałość po dawnych pracach hydrotechnicznych. Posiada muliste dno i jest silnie zarastające. To typowy matecznik lina i szczupaka leśnego. Dostęp do wody jest utrudniony przez gęste szuwary, co gwarantuje rybom spokój.', 'Nadleśnictwo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80776, 'Jezioro Bitkowskie', 'jezioro-bitkowskie', 'LAKE', 54.225353, 22.506008, 'Podlaskie', 'Dubeninki', 'Jezioro Bitkowskie to jedna z pereł Puszczy Rominckiej, akwen o typowym charakterze rynnowym, położony w głębokiej polodowcowej niecce. Jezioro charakteryzuje się bardzo czystą wodą i twardym, piaszczysto-żwirowym dnem, które stromo opada w stronę rynny osiągającej blisko 20 metrów głębokości. Brzegi są wysokie, porośnięte majestatycznym borem, co nadaje akwenowi surowy, północny klimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80777, 'Jezioro Czarne (Dubeninki)', 'jezioro-czarne-dubeninki', 'LAKE', 54.229078, 22.535105, 'Podlaskie', 'Dubeninki', 'Jezioro Czarne to urokliwy, śródleśny zbiornik o charakterze dystroficzno-eutroficznym. Nazwa idealnie oddaje kolor wody – jest ona ciemna, niemal czarna, co wynika z wysokiej zawartości kwasów humusowych wypłukiwanych z okolicznych torfowisk Puszczy Rominckiej. Dno jest miękkie, wyścielone grubą warstwą osadów organicznych i opadłych liści. Jezioro jest osłonięte od wiatru gęstym lasem, co sprawia, że tafla wody niemal zawsze jest gładka.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80778, 'Jezioro Rospuda (Filipowska)', 'jezioro-rospuda-filipowska', 'LAKE', 54.22174, 22.581239, 'Podlaskie', 'Filipów / Przerośl', 'Jezioro Rospuda Filipowska to potężna rynna polodowcowa, będąca początkiem słynnego szlaku rzeki Rospudy. Akwen charakteryzuje się monumentalną batymetrią – dno opada niezwykle stromo do centralnej rynny osiągającej blisko 39 metrów głębokości. Woda posiada I klasę czystości i niesamowitą przejrzystość. Dno jest twarde, piaszczysto-żwirowe, z licznymi głazami narzutowymi. Brzegi są wysokie i w dużej mierze zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80779, 'Staw Baszta I', 'staw-baszta-1', 'LAKE', 52.103055, 15.032687, 'Lubuskie', 'Maszewo / Grzmiąca', 'Pierwszy z kompleksu stawów Baszta. Akwen o charakterze potorfowym, płytki, z mroczną, herbacianą wodą. Wyśmienite łowisko karasia złocistego, który w tych warunkach osiąga piękne rozmiary i złoty kolor łusek.', 'PZW Zielona Góra');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80780, 'Staw Baszta II', 'staw-baszta-2', 'LAKE', 52.103068, 15.028696, 'Lubuskie', 'Maszewo / Grzmiąca', 'Drugi zbiornik w kompleksie, położony głębiej w lesie. Charakteryzuje się dużą ilością zwalonych do wody drzew, które stanowią naturalne kryjówki dla szczupaków. Wymaga od wędkarza precyzyjnego podawania przynęt.', 'PZW Zielona Góra');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80781, 'Jezioro Wysokie', 'jezioro-wysokie-przerosl', 'LAKE', 54.216515, 22.57478, 'Podlaskie', 'Przerośl', 'Jezioro Wysokie to głęboki i czysty akwen rynnowy położony w pagórkowatym terenie Przełomu rzeki Szeszupy. Akwen cechuje się bardzo wyraźnie zarysowaną rzeźbą dna ze stromymi spadkami i twardym podłożem. Woda jest dobrze natleniona i zachowuje doskonałą przejrzystość przez cały rok. Brzegi są wysokie, porośnięte lasem i łąkami, co nadaje jezioru malowniczy charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80782, 'Jezioro Ślepak', 'jezioro-slepak-2', 'LAKE', 54.214444, 22.624358, 'Podlaskie', 'Przerośl', 'Jezioro Ślepak to małe, niezwykle ustronne "oczko" leśne o charakterze dystroficznym. Akwen jest niemal całkowicie otoczony gęstym lasem i torfowiskami, co sprawia, że woda ma charakterystyczny, ciemny odcień. Dno jest wysoce muliste, usłane liśćmi i gałęziami, a strefa przybrzeżna jest bagnista. Jest to jezioro bardzo ciche, rzadko odwiedzane przez wędkarzy spoza najbliższej okolicy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80783, 'Jezioro Kościelne', 'jezioro-koscielne-przerosl', 'LAKE', 54.255423, 22.640548, 'Podlaskie', 'Przerośl', 'Jezioro Kościelne przylega bezpośrednio do miejscowości Przerośl, stanowiąc popularne miejsce wędkowania dla mieszkańców i turystów. Jest to akwen o charakterze eutroficznym, z dnem piaszczysto-mulistym i umiarkowaną głębokością. Linia brzegowa jest dobrze rozwinięta, z licznymi pomostami i łatwym dostępem od strony miasteczka. Woda jest żyzna, co sprzyja szybkiej wegetacji roślinności podwodnej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80784, 'Jezioro Przerośl', 'jezioro-przerosl', 'LAKE', 54.280435, 22.602139, 'Podlaskie', 'Przerośl', 'Jezioro Przerośl to jeden z najgłębszych i najciekawszych akwenów rynnowych regionu. Charakteryzuje się bardzo urozmaiconą rzeźbą dna z głębokimi rynnami sięgającymi ponad 28 metrów oraz licznymi podwodnymi górkami. Woda jest krystalicznie czysta (I klasa), o chłodnym odcieniu, co sprzyja bytności sielawy. Brzegi są wysokie i malownicze, w dużej mierze zdominowane przez piaszczyste skarpy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80785, 'Jezioro Linowo', 'jezioro-linowo-przerosl', 'LAKE', 54.292817, 22.611762, 'Podlaskie', 'Przerośl / Linowo', 'Jezioro Linowo to kameralny zbiornik o charakterze wybitnie eutroficznym, położony na północ od Przerośli. Jak sama nazwa wskazuje, jezioro jest idealnym siedliskiem dla ryb litoralu. Akwen jest stosunkowo płytki (max 5-6 m) z dnem mulistym i bardzo bogatą roślinnością zanurzoną. Brzegi są niskie, porośnięte szerokim pasem trzcin i grążeli żółtych. Woda nagrzewa się tu bardzo szybko.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80786, 'Jezioro Marianka 1', 'jezioro-marianka-1', 'LAKE', 54.338005, 22.896425, 'Podlaskie', 'Rutka-Tartak', 'Pierwszy z kompleksu dwóch niewielkich zbiorników Marianka. Jest to akwen o charakterze eutroficznym, stosunkowo płytki, otoczony malowniczymi pagórkami Suwalszczyzny. Dno jest muliste z piaszczystymi wypłyceniami w rejonie dopływów. Woda jest żyzna, co przekłada się na bogatą bazę pokarmową dla ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80787, 'Jezioro Wysokie 2', 'jezioro-wysokie-2', 'LAKE', 54.252446, 22.508808, 'Podlaskie', 'Dubeninki', 'Jezioro Wysokie 2 (koło Dubeninek) to głęboka i wąska rynna polodowcowa, ukryta wśród pagórków i lasów Puszczy Rominckiej. Akwen charakteryzuje się twardym dnem i bardzo czystą wodą. Batymetria jest typowo rynnowa: strome spady zaczynają się blisko brzegu i schodzą w mrok głębin sięgających ok. 15-18 metrów. Brzegi są wysokie i zalesione, co nadaje jezioru surowy charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80788, 'Jezioro Niskie', 'jezioro-niskie-dubeninki', 'LAKE', 54.257717, 22.505139, 'Podlaskie', 'Dubeninki', 'Jezioro Niskie to rynnowy zbiornik położony w sąsiedztwie jeziora Wysokie 2, połączony z nim małym ciekiem. Akwen ma charakter nieco bardziej eutroficzny, z dnem mulistym i bogatszą roślinnością brzegową. Maksymalna głębokość oscyluje wokół 8-10 metrów. Brzegi są urozmaicone – od wysokich i zalesionych po niskie i podmokłe od strony północnej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80789, 'Jezioro Malinowskie', 'jezioro-malinowskie', 'LAKE', 54.26528, 22.480474, 'Podlaskie', 'Dubeninki', 'Jezioro Malinowskie to kameralny, śródleśny zbiornik o charakterze eutroficznym, położony w sercu Puszczy Rominckiej. Akwen charakteryzuje się regularną misą denną i głębokością sięgającą 6-8 metrów. Dno jest muliste, bogate w bentos, a woda posiada dobrą klasę czystości. Jezioro otoczone jest majestatycznym borem sosnowym, co zapewnia absolutną ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80790, 'Jezioro Czarne (Gołdap)', 'jezioro-czarne-goldap', 'LAKE', 54.285746, 22.477899, 'Warmińsko-Mazurskie', 'Gołdap', 'Jezioro Czarne to niezwykle urokliwy, leśny akwen rynnowy położony w głębokiej polodowcowej rynnie w pobliżu Gołdapi. Jezioro charakteryzuje się bardzo czystą wodą i twardym, piaszczysto-żwirowym dnem, które stromo opada w stronę rynny osiągającej blisko 15-18 metrów głębokości. Brzegi są wysokie, porośnięte majestatycznym lasem iglastym, co nadaje akwenowi surowy, północny klimat i zapewnia doskonałą osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80791, 'Jezioro Kociołek', 'jezioro-kociolek-goldap', 'LAKE', 54.29653, 22.458522, 'Warmińsko-Mazurskie', 'Gołdap', 'Jezioro Kociołek to mały, niemal idealnie okrągły akwen o charakterze "oczka" leśnego, głęboko wcięty w pagórkowaty teren w okolicach Gołdapi. Mimo niewielkiej powierzchni, jezioro posiada znaczną głębokość centralną i stromo opadające brzegi. Dno jest wysoce muliste, okryte grubą warstwą osadów organicznych i liści. Woda ma charakterystyczny, lekko brunatny odcień, a tafla jest niemal zawsze nieruchoma dzięki naturalnej osłonie od wiatru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80792, 'Jezioro Rakówek', 'jezioro-rakowek', 'LAKE', 54.30428, 22.435498, 'Warmińsko-Mazurskie', 'Gołdap', 'Jezioro Rakówek to urokliwy zbiornik o charakterze eutroficznym, położony pośród malowniczych wzgórz i łąk. Akwen charakteryzuje się średnimi głębokościami i dnem piaszczysto-mulistym, obfitującym w bogatą bazę pokarmową dla ryb białych. Linia brzegowa jest urozmaicona, z gęstym pasem trzciny pospolitej i licznymi skupiskami grzybieni białych w płytszych zatokach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80793, 'Jezioro Marianka 2', 'jezioro-marianka-2', 'LAKE', 54.339647, 22.894451, 'Podlaskie', 'Rutka-Tartak', 'Drugie z jezior Marianka, połączone z sąsiadem małym ciekiem. Ma charakter bardziej dystroficzny, z dnem wyścielonym osadami organicznymi i ciemniejszą wodą. Akwen jest wybitnie wyciszony i osłonięty od wiatrów. Maksymalna głębokość nie przekracza kilku metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80794, 'Jezioro Kółki', 'jezioro-kolki', 'LAKE', 54.286548, 22.410758, 'Warmińsko-Mazurskie', 'Gołdap', 'Jezioro Kółki to niewielki, kameralny zbiornik położony w ustronnej dolinie. Posiada charakter rynnowy, ale o łagodniejszym ukształtowaniu niż typowe jeziora polodowcowe regionu. Dno jest tu mieszane, z piaszczystymi wypłyceniami i mulistym korytem w osi głównej. Woda posiada dobrą przejrzystość, a brzeg jest w dużej mierze otoczony pasem zadrzewień, co chroni wędkarzy przed silnymi podmuchami wiatru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80795, 'Jezioro Gołdap', 'jezioro-goldap', 'LAKE', 54.334664, 22.335104, 'Warmińsko-Mazurskie', 'Gołdap', 'Jezioro Gołdap to największy akwen w regionie, przecięty granicą państwową z Rosją. To rynnowe jezioro o powierzchni blisko 150 hektarów, pełniące funkcję turystyczno-uzdrowiskową (tężnie solankowe na brzegu). Batymetria jest bardzo ciekawa – od płytkiej, mulistej zatoki zachodniej, po głęboką rynnę wschodnią sięgającą ponad 10 metrów. Woda jest żyzna, o średniej przejrzystości, dobrze natleniona.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80796, 'Jezioro Wolisko', 'jezioro-wolisko', 'LAKE', 54.09621, 22.091146, 'Warmińsko-Mazurskie', 'Kruklanki / Wydminy', 'Jezioro Wolisko to serce Puszczy Boreckiej, akwen o niespotykanym wręcz poziomie dzikości i ciszy. Jest to jezioro rynnowe o bardzo czystej wodzie, otoczone przez jeden z najlepiej zachowanych kompleksów leśnych w Polsce (ostoja żubrów). Dno jest twarde, piaszczyste, z wyraźnymi uskokami rynnowymi dochodzącymi do 10-12 metrów. Roślinność brzegowa jest skąpa, co ułatwia dostęp do wody w nielicznych wolnych od puszczy miejscach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80797, 'Jezioro Spulino', 'jezioro-spulino', 'LAKE', 52.552104, 16.14001, 'Wielkopolskie', 'Sieraków / Kwilcz', 'Spulino to urokliwy, śródleśny zbiornik o charakterze rynnowym, położony w sercu Sierakowskiego Parku Krajobrazowego. Posiada twarde dno i krystalicznie czystą wodę. Maksymalna głębokość sięga 6-8 metrów. Brzegi są wysokie i w całości porośnięte majestatycznym lasem bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80798, 'Jezioro Czarne (Puszcza Borecka)', 'jezioro-czarne-borecka', 'LAKE', 54.042168, 22.08827, 'Warmińsko-Mazurskie', 'Kruklanki', 'Jezioro Czarne w Puszczy Boreckiej to klasyczny akwen dystroficzny, mniejszy i znacznie bardziej ustronny niż jego rynnowi sąsiedzi. Woda ma ciemny, herbaciany kolor, a dno jest puszyste i muliste. Jezioro nie posiada wyraźnych odpływów, co tworzy unikatowy mikroklimat. Brzegi są podmokłe, porośnięte mchem torfowcem i bagnicą, co czyni akwen niemal niedostępnym z lądu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80799, 'Jezioro Gębałko', 'jezioro-gebalko', 'LAKE', 53.978408, 22.090523, 'Warmińsko-Mazurskie', 'Wydminy', 'Jezioro Gębałko to urokliwy akwen o charakterze eutroficznym, położony w pagórkowatym terenie rolniczo-leśnym w okolicach Wydmin. Zbiornik jest stosunkowo płytki (max 5-6 m) z dnem w dużej mierze mulistym, ale z wyraźnymi piaszczystymi wypłyceniami. Linia brzegowa jest urozmaicona, z gęstym pasem trzcin i tataraku, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80800, 'Jezioro Pokrzywy', 'jezioro-pokrzywy', 'LAKE', 53.944392, 22.177191, 'Warmińsko-Mazurskie', 'Wydminy / Ełk', 'Jezioro Pokrzywy to niewielki, kameralny zbiornik położony na uboczu, otoczony malowniczymi łąkami i kępami lasu. Charakteryzuje się dość wyrównaną głębokością i dnem mulistym z dużą ilością osadów organicznych. Akwen jest zaciszny, co sprzyja rozwojowi bujnej roślinności wodnej – grążeli, rdestnicy i moczarki. Woda jest żyzna i ciepła, typowa dla małych zbiorników nizinnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80801, 'Staw Baszta III', 'staw-baszta-3', 'LAKE', 52.104781, 15.028396, 'Lubuskie', 'Maszewo / Grzmiąca', 'Trzeci staw z grupy Baszta. Najbardziej ustronny i cichy. Dno wyścielone jest grubą warstwą liści i mułu. Idealne miejsce na lekką wędkę spławikową i polowanie na liny żerujące w oknach roślinności.', 'PZW Zielona Góra');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80802, 'Staw Baszta IV', 'staw-baszta-4', 'LAKE', 52.107035, 15.026722, 'Lubuskie', 'Maszewo / Grzmiąca', 'Ostatni z opisywanych stawów kompleksu. Posiada muliste dno i regularną linię brzegową porośniętą trzciną. To klasyczne "oczko" dla osób szukających spokoju i pewnych brań drobnej ryby spokojnego żeru.', 'PZW Zielona Góra');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80803, 'Jezioro Kleszczówka', 'jezioro-kleszczowka', 'LAKE', 53.958061, 22.178339, 'Warmińsko-Mazurskie', 'Wydminy / Ełk', 'Kleszczówka to małe, urokliwe jezioro leśne położone w gęstym kompleksie borów sosnowych. Akwen ma formę regularnego kociołka o twardym, piaszczystym dnie i dobrej przezroczystości wody. Maksymalna głębokość nie przekracza 5-7 metrów. Brzegi są wysokie i suche, co ułatwia dostęp do litoralu. Jezioro jest wybitnie wyciszone i osłonięte od wiatrów, stanowiąc idealne miejsce na wędkarską samotność.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80804, 'Jezioro Łoźna Struga', 'jezioro-lozna-struga', 'LAKE', 53.932595, 22.280788, 'Warmińsko-Mazurskie', 'Stare Juchy / Ełk', 'Jezioro Łoźna Struga to specyficzny akwen rynnowo-przepływowy, połączony z systemem rzeki Gawlik. Charakteryzuje się wydłużonym kształtem i wyraźnym nurtem w osi głównej, co zapewnia stałe natlenienie wody i tworzenie się rzecznych struktur na dnie – rynien z wymytym, piaszczysto-żwirowym podłożem. Maksymalna głębokość oscyluje wokół 8-10 metrów. Brzegi są urozmaicone, częściowo zarośnięte łęgiem wierzbowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80805, 'Jezioro Krzywe (Stare Juchy)', 'jezioro-krzywe-stare-juchy', 'LAKE', 53.944392, 22.316837, 'Warmińsko-Mazurskie', 'Stare Juchy', 'Jezioro Krzywe to majestatyczna rynna polodowcowa o wybitnie urozmaiconej rzeźbie dna i dużej głębokości (max ok. 25-28 m). Akwen posiada krętą linię brzegową z licznymi zatokami i piaszczystymi półwyspami. Woda jest czysta (I/II klasa), o chłodnym odcieniu, co sprzyja bytowaniu sielawy. Dno jest twarde, piaszczysto-żwirowe, z gwałtownymi uskokami rynnowymi. Brzegi są wysokie i malownicze, częściowo zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80806, 'Jezioro Łacha', 'jezioro-lacha', 'LAKE', 53.4548, 21.746106, 'Warmińsko-Mazurskie', 'Pisz', 'Jezioro Łacha (często nazywane starorzeczem) to specyficzny, płytki akwen położony w dolinie Pisy, niedaleko jej ujścia z jeziora Roś. Jest to zbiornik wybitnie eutroficzny, połączony z rzeką systemem kanałów, co sprawia, że jego rybostan jest niezwykle dynamiczny i uzależniony od stanów wody w rzece. Dno jest tu miękkie, wyścielone grubą warstwą mułu organicznego i resztkami trzcin, o średniej głębokości zaledwie 1,5 metra.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80807, 'Jezioro Sędańskie', 'jezioro-sedanskie', 'LAKE', 53.535921, 20.913677, 'Warmińsko-Mazurskie', 'Szczytno', 'Jezioro Sędańskie to urokliwy zbiornik rynnowy położony na południowy zachód od Szczytna. Akwen charakteryzuje się dość urozmaiconym dnem – od piaszczystych blatów w rejonie dopływów po rynnę centralną sięgającą blisko 7-9 metrów głębokości. Woda posiada dobrą przejrzystość wiosną, jednak latem ulega typowym dla tego regionu zakwitom. Brzegi są w dużej mierze zalesione, co nadaje jezioru kameralny i spokojny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80808, 'Jezioro Sasek Mały', 'jezioro-sasek-maly', 'LAKE', 53.505431, 20.889344, 'Warmińsko-Mazurskie', 'Szczytno', 'Sasek Mały to bardzo popularny wśród lokalnych wędkarzy zbiornik o charakterze eutroficznym, położony w kompleksie leśnym. Jezioro jest stosunkowo płytkie (średnio 2-3 m), z dnem w dużej mierze mulistym, ale z wyraźnymi piaszczystymi wypłyceniami. Akwen posiada bardzo rozwiniętą linię brzegową z licznymi półwyspami i piaszczystymi plażami, które są chętnie wykorzystywane przez wędkarzy gruntowych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80809, 'Jezioro Mielno (Maszewo)', 'jezioro-mielno-maszewo', 'LAKE', 52.105228, 15.017838, 'Lubuskie', 'Maszewo / Grzmiąca', 'Jezioro Mielno pod Maszewem to malowniczy zbiornik o pofałdowanym dnie piaszczysto-mulistym. Woda posiada przyzwoitą klasę czystości. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin. To bardzo stabilna woda leszczowo-szczupakowa, słynąca z dużego okonia.', 'PZW Zielona Góra');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80810, 'Jezioro Łażnica', 'jezioro-laznica', 'LAKE', 53.508315, 20.845828, 'Warmińsko-Mazurskie', 'Szczytno / Janowo', 'Jezioro Łażnica to niewielkie, kameralne "oczko" śródleśne o charakterze dystroficzno-eutroficznym. Akwen jest wybitnie wyciszony i osłonięty od wiatrów gęstym borem sosnowym. Dno jest miękkie, wyścielone grubą warstwą osadów organicznych i liści, co nadaje wodzie lekko herbaciany kolor. Maksymalna głębokość oscyluje wokół 4-5 metrów. Brzegi są niskie, częściowo podmokłe, co zapewnia rybom spokój i doskonałe warunki do wzrostu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80811, 'Jezioro Jasne', 'jezioro-jasne-szczytno', 'LAKE', 53.504129, 20.829864, 'Warmińsko-Mazurskie', 'Szczytno', 'Jezioro Jasne koło Szczytna to urokliwy zbiornik rynnowy, który swoją nazwę zawdzięcza (historycznie) wyjątkowo czystej wodzie i piaszczystemu dnu. Jest to akwen o średniej głębokości, z wyraźnie zaznaczoną rynną centralną sięgającą około 8 metrów. Dno jest w przeważającej części twarde, piaszczysto-żwirowe, co sprzyja rozwojowi okonia i ryb sielawowatych. Brzegi są wysokie i zalesione, co nadaje jezioru surowy charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80812, 'Jezioro Płociczno', 'jezioro-plociczno-szczytno', 'LAKE', 53.508953, 20.819864, 'Warmińsko-Mazurskie', 'Szczytno', 'Jezioro Płociczno to rynnowy akwen położony w bliskim sąsiedztwie jeziora Jasnego i Warchalskiego. Charakteryzuje się ono wydłużonym kształtem i twardym, polodowcowym dnem. Jest to jezioro dość głębokie jak na swoją powierzchnię, z wyraźnie zarysowanymi spadkami i rynną centralną. Woda posiada dobrą przejrzystość, a linia brzegowa jest urozmaicona licznymi powalonymi drzewami, co stwarza wyśmienite kryjówki dla ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80813, 'Jezioro Warchalskie', 'jezioro-warchalskie', 'LAKE', 53.525972, 20.82068, 'Warmińsko-Mazurskie', 'Warchałki / Jedwabno', 'Jezioro Warchalskie to jeden z najbardziej znanych akwenów rekreacyjnych w okolicach Szczytna, słynący z czystej wody i piaszczystych plaż. Jest to głębokie jezioro rynnowe (max ok. 15 m) o urozmaiconym dnie z licznymi podwodnymi górkami i blatami. Mimo znacznej presji turystycznej w sezonie letnim, jezioro zachowuje wysokie walory wędkarskie dzięki mądrej gospodarce zarybieniowej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80814, 'Jezioro Ziółko', 'jezioro-ziolko', 'LAKE', 53.524764, 20.808631, 'Warmińsko-Mazurskie', 'Warchałki', 'Jezioro Ziółko to niewielki, wybitnie leśny akwen o charakterze eutroficznym, położony niedaleko jeziora Warchalskiego. Zbiornik jest stosunkowo płytki (max 3-4 m), z dnem wyścielonym osadami organicznymi i bogatą roślinnością zanurzoną. Jezioro jest w całości otoczone gęstym lasem sosnowym, co chroni je przed wiatrem i zapewnia absolutną wędkarską ciszę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80815, 'Jezioro Skonieczne', 'jezioro-skonieczne', 'LAKE', 53.515728, 20.801175, 'Warmińsko-Mazurskie', 'Jedwabno', 'Jezioro Skonieczne to dziki, śródleśny akwen rynnowy o bardzo urozmaiconej rzeźbie dna. Charakteryzuje się czystą wodą i twardym, polodowcowym dnem z licznymi podwodnymi górkami i głębokością sięgającą 10-12 metrów. Jezioro jest w całości otoczone gęstym lasem, co chroni je przed wiatrem i zapewnia ciszę. Brzegi są wysokie i strome, co ogranicza liczbę stanowisk brzegowych, ale nadaje jezioru malowniczy wygląd.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80816, 'Staw Mały Karol', 'staw-maly-karol', 'LAKE', 51.479272, 17.413616, 'Dolnośląskie', 'Potasznia', 'Staw Mały Karol to niewielki, śródpolny zbiornik o charakterze eutroficznym. Akwen posiada dno piaszczysto-muliste i umiarkowaną głębokość. Linia brzegowa jest porośnięta trzciną i pałką wodną, co stwarza doskonałe warunki dla lęgów ryb karpiowatych. Woda szybko się tu nagrzewa, co sprzyja aktywności ryb od wczesnej wiosny.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80817, 'Jezioro Żabieniec', 'jezioro-zabieniec-szczytno', 'LAKE', 53.522126, 20.79537, 'Warmińsko-Mazurskie', 'Jedwabno', 'Jezioro Żabieniec to urokliwy akwen o charakterze eutroficznym, położony w sercu lasu. Jezioro jest stosunkowo płytkie (max 5-6 m) z dnem mulistym, bogatym w bentos. Linia brzegowa jest silnie porośnięta trzciną i tatarakiem, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych. Woda szybko się tu nagrzewa, co sprzyja intensywnym żerowaniom lina i karasia w okresie wiosennym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80818, 'Jezioro Grzybiste', 'jezioro-grzybiste', 'LAKE', 53.526451, 20.79765, 'Warmińsko-Mazurskie', 'Jedwabno', 'Jezioro Grzybiste to mały, niemal ukryty w gęstym lesie akwen o charakterze dystroficznym. Zbiornik charakteryzuje się miękkim dnem i mroczną, lekko brunatną wodą. Maksymalna głębokość nie przekracza kilku metrów. Brzegi są niskie i bagniste, porośnięte mchem torfowcem, co sprawia, że dostęp do lustra wody jest bardzo ograniczony. Jezioro uchodzi za jedno z najbardziej dzikich w okolicach Jedwabna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80819, 'Jezioro Okonek', 'jezioro-okonek-szczytno', 'LAKE', 53.529895, 20.797715, 'Warmińsko-Mazurskie', 'Szczytno / Jedwabno', 'Jezioro Okonek to kameralny zbiornik rynnowy o bardzo czystej wodzie i twardym dnie. Akwen cechuje się regularnymi spadkami i głębokością dochodzącą do 6-8 metrów. Jezioro jest otoczone lasem, co zapewnia doskonałą osłonę przed wiatrem. Roślinność brzegowa jest wąska, z przewagą trzciny pospolitej. To jezioro, w którym presja wędkarska jest znikoma, co pozwala na obcowanie z naturą.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80820, 'Jezioro Rządz', 'jezioro-rzadz', 'LAKE', 53.441625, 18.707271, 'Kujawsko-Pomorskie', 'Grudziądz', 'Jezioro Rządz to akwen o charakterze starorzecza, położony w południowej części Grudziądza. Jest to zbiornik płytki, wybitnie eutroficzny, o mulistym dnie. Słynie z populacji lina i karasia złocistego. Brzegi są silnie zarośnięte trzcinowiskami.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80821, 'Jezioro Priamy', 'jezioro-priamy', 'LAKE', 53.536125, 20.615523, 'Warmińsko-Mazurskie', 'Kot / Jedwabno', 'Jezioro Priamy to dziki, rynnowy akwen położony w ustronnej części puszczy. Jezioro charakteryzuje się twardym dnem i bardzo czystą wodą. Batymetria jest typowo polodowcowa: rynna o głębokości do 10-12 metrów biegnie przez środek jeziora. Brzegi są wysokie i zalesione, co nadaje akwenowi dziki i ustronny charakter. Roślinność wodna jest skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80822, 'Jezioro Linki', 'jezioro-linki', 'LAKE', 53.521683, 20.783161, 'Warmińsko-Mazurskie', 'Jedwabno', 'Jezioro Linki to urokliwy, typowo leśny akwen o charakterze eutroficznym, położony w sercu Puszczy Napiwodzko-Ramuckiej. Jest to jezioro stosunkowo płytkie, o miękkim, wyścielonym grubą warstwą osadów organicznych dnie. Brzegi są niskie, porośnięte gęstym pasem trzcin i tataraku, co tworzy naturalną barierę i oazę spokoju dla ryb. Woda nagrzewa się tu bardzo szybko, co sprzyja intensywnym żerowaniom wiosennym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80823, 'Jezioro Krzywek', 'jezioro-krzywek-jedwabno', 'LAKE', 53.530638, 20.787619, 'Warmińsko-Mazurskie', 'Jedwabno', 'Jezioro Krzywek to niewielki, kameralny zbiornik rynnowy o bardzo czystej wodzie i twardym dnie. Akwen cechuje się regularnymi spadkami i głębokością dochodzącą do 6-8 metrów. Jezioro jest otoczone gęstym lasem sosnowym, co zapewnia doskonałą osłonę przed wiatrem. Roślinność brzegowa jest wąska, z przewagą trzciny pospolitej, co ułatwia dostęp do litoralu w wielu miejscach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80824, 'Jezioro Świętajno (Napiwodzkie)', 'jezioro-swietajno-napiwodzkie', 'LAKE', 53.544898, 20.787849, 'Warmińsko-Mazurskie', 'Szczytno / Warchałki', 'Jezioro Świętajno (Napiwodzkie) to absolutna perła regionu, uznawane za jedno z najczystszych jezior w Polsce. Akwen o powierzchni ponad 200 ha charakteryzuje się niesamowitą przezroczystością wody (widoczność do kilku metrów) i twardym, piaszczystym dnem. Batymetria jest bardzo urozmaicona – strome piaszczyste klify podwodne opadają do rynny sięgającej blisko 30 metrów. To klasyczne jezioro sielawowe o chłodnej, dobrze natlenionej toni.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80825, 'Jezioro Brajnickie', 'jezioro-brajnickie-2', 'LAKE', 53.548314, 20.814242, 'Warmińsko-Mazurskie', 'Brajniki / Jedwabno', 'Jezioro Brajnickie to zbiornik bezpośrednio połączony z jeziorem Świętajno, jednak o zupełnie odmiennym charakterze. Jest to akwen eutroficzny, znacznie płytszy i bardziej żyzny. Dno jest muliste, bogate w bentos, a roślinność zanurzona tworzy rozległe dywany moczarki i rdestnicy. Woda nagrzewa się tu znacznie szybciej niż w sąsiedniej rynnie, co czyni jezioro idealnym tarliskiem dla ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80826, 'Jezioro Kopeć', 'jezioro-kopec', 'LAKE', 53.472588, 20.688758, 'Warmińsko-Mazurskie', 'Jedwabno', 'Jezioro Kopeć to niewielkie, śródleśne jezioro rynnowe położone w głębi puszczy. Akwen charakteryzuje się regularną niecką o głębokości do 10 metrów i bardzo czystą wodą. Dno jest w przeważającej części twarde, piaszczyste, z wąskim pasem trzcin. Jezioro jest wybitnie wyciszone i osłonięte od wiatrów, stanowiąc idealne miejsce na wędkarską samotność.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80827, 'Jezioro Gatno', 'jezioro-gatno', 'LAKE', 54.048908, 18.089976, 'Pomorskie', 'Przywidz / Huta Dolna', 'Jezioro Gatno to malowniczy, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym, co nadaje akwenowi dziki i ustronny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80828, 'Jezioro Czarne (Napiwoda)', 'jezioro-czarne-napiwoda', 'LAKE', 53.459808, 20.593464, 'Warmińsko-Mazurskie', 'Nidzica / Napiwoda', 'Jezioro Czarne koło Napiwody to klasyczny zbiornik dystroficzny, położony w sercu dużego kompleksu leśnego. Woda posiada charakterystyczny, bardzo ciemny, kawowy odcień wynikający z wysokiej zawartości kwasów humusowych. Dno jest wysoce muliste i puszyste, wyścielone grubą warstwą osadów torfowych. Brzegi są miękkie, bagniste, z licznymi powalonymi dębami i olchami, co nadaje miejscu dziki wygląd.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80829, 'Jezioro Blejek', 'jezioro-blejek', 'LAKE', 53.4641, 20.601747, 'Warmińsko-Mazurskie', 'Janowo', 'Jezioro Blejek to mały, śródleśny akwen o charakterze eutroficznym, stanowiący część systemu wód Puszczy Napiwodzko-Ramuckiej. Zbiornik jest płytki (max 4-5 m), z dnem w dużej mierze mulistym i bardzo bogatą roślinnością litoralną. Woda nagrzewa się szybko, co sprzyja rozwojowi narybku. Brzegi są porośnięte gęstą trzciną i otoczone lasem mieszanym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80830, 'Jezioro Trzciana', 'jezioro-trzciana', 'LAKE', 53.464864, 20.575679, 'Warmińsko-Mazurskie', 'Janowo / Nidzica', 'Jezioro Trzciana to wąski i wydłużony zbiornik o charakterze rynnowym, silnie ulegający procesom eutrofizacji. Jak sama nazwa wskazuje, akwen jest otoczony bardzo szerokim i gęstym pasem trzcinowisk, co czyni go idealnym siedliskiem dla ryb litoralu. Dno jest muliste z piaszczystymi wypłyceniami w rejonie dopływów. Maksymalna głębokość oscyluje wokół 6 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80831, 'Jezioro Dłużek (Nidzica)', 'jezioro-dluzek-nidzica', 'LAKE', 53.470468, 20.548242, 'Warmińsko-Mazurskie', 'Nidzica / Dłużek', 'Jezioro Dłużek to jedna z najbardziej znanych rynien polodowcowych w okolicach Nidzicy. Akwen charakteryzuje się potężnymi głębokościami (do 38 m) i bardzo czystą, dobrze natlenioną wodą (I/II klasa). Batymetria jest typowo rynnowa: ostre spady zaczynają się blisko brzegu i schodzą w mrok głębin sielawowych. Dno jest twarde, piaszczysto-żwirowe, z nielicznymi podwodnymi górkami. Brzegi są wysokie i zalesione, co nadaje jezioru surowy urok.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80832, 'Jezioro Szewc', 'jezioro-szewc', 'LAKE', 53.481253, 20.570537, 'Warmińsko-Mazurskie', 'Napiwoda', 'Jezioro Szewc to niewielki, kameralny akwen śródleśny o charakterze eutroficznym. Zbiornik jest stosunkowo płytki (max 5-6 m) z dnem w dużej mierze mulistym, ale z wyraźnymi twardszymi partiami przy brzegach. Linia brzegowa jest silnie porośnięta trzciną i tatarakiem, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych. Woda szybko się tu nagrzewa, co sprzyja aktywności ryb od wczesnej wiosny.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80833, 'Jezioro Omulew', 'jezioro-omulew', 'LAKE', 53.491033, 20.554476, 'Warmińsko-Mazurskie', 'Jabłonka / Nidzica', 'Jezioro Omulew to jeden z największych i najpopularniejszych akwenów w regionie (blisko 550 ha), o bardzo urozmaiconym kształcie i bogatej batymetrii. Akwen dzieli się na kilka wyraźnych plosów z licznymi wyspami i głębokimi rynnami sięgającymi ponad 30 metrów. Dno jest zróżnicowane: od piaszczystych plaż po twarde, gliniaste kanty i podwodne górki. Woda posiada dobrą klasę czystości i jest doskonale natleniona.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80834, 'Jezioro Górskie', 'jezioro-gorskie-przemet', 'LAKE', 51.951789, 16.247234, 'Wielkopolskie', 'Przemęt', 'Jezioro Górskie to urokliwy zbiornik rynnowy o bardzo urozmaiconej linii brzegowej i licznych półwyspach. Posiada twarde dno piaszczysto-muliste i głębokość sięgającą 6-7 metrów. Woda jest dobrze natleniona i żyzna. Brzegi są w większości wysokie i porośnięte lasem mieszanym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80835, 'Jezioro Dłużek (Kot)', 'jezioro-dluzek-kot', 'LAKE', 53.555759, 20.655584, 'Warmińsko-Mazurskie', 'Kot / Pasym', 'Jezioro Dłużek w rejonie miejscowości Kot to długa, wąska rynna polodowcowa o stromych, piaszczystych stokach. Akwen charakteryzuje się bardzo czystą wodą i twardym dnem. Batymetria jest regularna – rynna o głębokości do 12-15 metrów biegnie przez środek jeziora. Brzegi są wysokie i zalesione, co nadaje jezioru surowy charakter. Roślinność wodna jest tu skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80836, 'Jezioro Łabudy Małe', 'jezioro-labudy-male', 'LAKE', 53.562757, 20.63623, 'Warmińsko-Mazurskie', 'Szczytno / Kot', 'Łabudy Małe to niewielki, śródleśny akwen o charakterze eutroficznym. Jezioro jest płytkie (max 4-5 m), z dnem w dużej mierze mulistym i bardzo bogatą roślinnością litoralną. Woda nagrzewa się tu szybko, co sprzyja aktywności ryb karpiowatych. Brzegi są niskie, częściowo podmokłe, co zapewnia rybom spokój i doskonałe warunki do tarła.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80837, 'Jezioro Łabudy Duże', 'jezioro-labudy-duze', 'LAKE', 53.570938, 20.641079, 'Warmińsko-Mazurskie', 'Szczytno / Kot', 'Jezioro Łabudy Duże to malownicza rynna leśna o urozmaiconej rzeźbie dna. Akwen posiada centralną rynnę sięgającą około 8-10 metrów głębokości i twarde piaszczyste blaty. Woda posiada dobrą przejrzystość, a linia brzegowa jest urozmaicona licznymi powalonymi drzewami, co stwarza wyśmienite kryjówki dla ryb. Brzegi są w większości suche i zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80838, 'Jezioro Gim', 'jezioro-gim', 'LAKE', 53.575436, 20.582242, 'Warmińsko-Mazurskie', 'Nowa Wieś / Olsztynek', 'Jezioro Gim to jedna z pereł Mazur Zachodnich, akwen rynnowy o powierzchni blisko 170 hektarów, słynący z niesamowitej czystości wody i piaszczystego dna. Batymetria jest tu bardzo urozmaicona – dno opada stromo do centralnej rynny osiągającej ponad 25 metrów głębokości. Woda posiada I klasę czystości, co sprzyja rozwojowi sielawy oraz dużych drapieżników pelagicznych. Brzegi są wysokie, w całości porośnięte majestatycznym lasem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80839, 'Jezioro Konopne', 'jezioro-konopne', 'LAKE', 53.591104, 20.632432, 'Warmińsko-Mazurskie', 'Nowa Wieś', 'Jezioro Konopne to mały, śródleśny zbiornik o charakterze eutroficznym, położony w głębi kompleksu leśnego Puszczy Ramuckiej. Akwen jest stosunkowo płytki (max 4-5 m) z dnem w dużej mierze mulistym, obfitującym w bentos. Woda nagrzewa się tu bardzo szybko, co sprzyja rozwojowi bogatej szaty roślinnej – grążeli żółtych i rdestnicy. Brzegi są niskie, często podmokłe, co nadaje jezioru dziki i ustronny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80840, 'Jezioro Łowne Duże', 'jezioro-lowne-duze', 'LAKE', 53.599331, 20.638762, 'Warmińsko-Mazurskie', 'Nowa Wieś / Butryny', 'Jezioro Łowne Duże to malowniczy, leśny akwen rynnowy położony w samym sercu Puszczy Ramuckiej. Jezioro charakteryzuje się czystą wodą i dnem twardym, piaszczystym, które regularnie opada do rynny środkowej o głębokości ok. 10-12 metrów. Całość otacza majestatyczny bór sosnowo-dębowy, co zapewnia doskonałą osłonę przed wiatrem i nadaje jezioru wyjątkowy, puszczański mikroklimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80841, 'Staw Jaskółczy', 'staw-jaskolczy', 'LAKE', 51.525894, 17.353688, 'Dolnośląskie', 'Milicz / Ruda Milicka', 'Staw Jaskółczy to mniejszy akwen o urozmaiconej linii brzegowej, położony niedaleko koryta Baryczy. Zbiornik charakteryzuje się czystszą wodą niż typowe stawy produkcyjne i dnem piaszczysto-żwirowym w strefie grobli. Posiada wyraźnie zaznaczoną rynnę przepływową (do 2 m). Roślinność wodna jest tu umiarkowana, z przewagą grzybieni białych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80842, 'Jezioro Łowne Małe', 'jezioro-lowne-male', 'LAKE', 53.604042, 20.640006, 'Warmińsko-Mazurskie', 'Nowa Wieś / Butryny', 'Łowne Małe to kameralne "oczko" sąsiadujące z jeziorem Łowne Duże. Ma charakter bardziej eutroficzny, z dnem mulistym i bogatszą roślinnością brzegową. Maksymalna głębokość nie przekracza 5 metrów. Brzegi są niskie, częściowo bagniste, porośnięte szerokim pasem trzcin i tataraku, co zapewnia rybom doskonałe warunki do tarła i spokój.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80843, 'Jezioro Głęboczek (Butryny)', 'jezioro-gleboczek-butryny', 'LAKE', 53.607976, 20.644426, 'Warmińsko-Mazurskie', 'Butryny', 'Jezioro Głęboczek to mały, ale wyjątkowo głęboki jak na swoją powierzchnię akwen polodowcowy, ukryty w puszczańskim parowie. Jak sama nazwa wskazuje, dno urywa się tu gwałtownie, schodząc do mrocznej rynny o głębokości ok. 15 metrów. Woda jest chłodna, bardzo czysta i dobrze natleniona, co tworzy specyficzne warunki dla ryb drapieżnych kochających zimną toń.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80844, 'Jezioro Orczek', 'jezioro-orczek', 'LAKE', 53.623085, 20.714421, 'Warmińsko-Mazurskie', 'Pasym / Grom', 'Jezioro Orczek to malowniczy, rynnowy akwen położony w pagórkowatym krajobrazie Mazur, niedaleko Pasymia. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem, które stromo opada w stronę centralnej rynny (max. 12 m). Linia brzegowa jest dobrze rozwinięta, z licznymi piaszczystymi plażami i wysepkami roślinności zanurzonej. Jezioro jest otoczone wianuszkiem lasów i pól, co sprzyja aktywności ryb przez całą dobę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80845, 'Jezioro Łajskie', 'jezioro-lajskie', 'LAKE', 53.621074, 20.643311, 'Warmińsko-Mazurskie', 'Łajs / Butryny', 'Jezioro Łajskie (Łajs) to przepiękny, rynnowy akwen położony na styku Warmii i Mazur. Jezioro zajmuje ok. 50 hektarów i charakteryzuje się wyraźnie zarysowaną rzeźbą dna z głęboką rynną (do 18 m) i licznymi podwodnymi górkami. Woda posiada wysoką klasę czystości, a dno jest w przeważającej części twarde, piaszczysto-żwirowe. Brzegi są wysokie, częściowo zalesione, z urokliwymi dzikimi plażami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80846, 'Jezioro Czerwona Mała', 'jezioro-czerwona-mala', 'LAKE', 53.631254, 20.642838, 'Warmińsko-Mazurskie', 'Łajs', 'Czerwona Mała to urokliwe, śródleśne "oczko" o charakterze dystroficzno-eutroficznym. Akwen charakteryzuje się miękkim dnem i lekko mroczną wodą o herbacianym odcieniu. Maksymalna głębokość nie przekracza 5-6 metrów. Jezioro jest wybitnie wyciszone i osłonięte od wiatrów gęstym borem sosnowym, co nadaje mu kameralny charakter. Roślinność brzegowa jest gęsta, z przewagą trzciny i grążeli.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80847, 'Jezioro Kośno', 'jezioro-kosno', 'LAKE', 53.643875, 20.692921, 'Warmińsko-Mazurskie', 'Purda / Pasym', 'Jezioro Kośno to jeden z najbardziej majestatycznych i rygorystycznie chronionych akwenów na Warmii i Mazurach (rezerwat przyrody). To potężna polodowcowa rynna (ponad 500 ha) o nieskazitelnej czystości wody i głębokościach przekraczających 40 metrów. Dno jest twarde, piaszczysto-żwirowe, z gwałtownymi uskokami rynnowymi. Akwen otaczają bezkresne lasy Puszczy Ramuckiej. Wędkowanie tutaj podlega specjalnym przepisom rezerwatu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80848, 'Jezioro Dzika Korsakówka', 'jezioro-dzika-korsakowka', 'LAKE', 53.655836, 20.673459, 'Warmińsko-Mazurskie', 'Purda', 'Dzika Korsakówka to niewielki, zagubiony w głębi puszczy akwen o charakterze eutroficznym. Jak sama nazwa wskazuje, jest to zbiornik wybitnie dziki, niemal całkowicie odcięty od cywilizacji. Jezioro jest płytkie, silnie zarastające, z dnem wyścielonym grubą warstwą osadów organicznych. Woda nagrzewa się szybko, stanowiąc idealne środowisko dla gatunków litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80849, 'Jezioro Czerwona Duża', 'jezioro-czerwona-duza', 'LAKE', 53.645019, 20.633183, 'Warmińsko-Mazurskie', 'Łajs / Nowa Wieś', 'Jezioro Czerwona Duża to malowniczy zbiornik rynnowy położony w pofałdowanym terenie leśnym. Akwen posiada wyraźnie zarysowaną rzeźbę dna z rynną centralną sięgającą blisko 12-14 metrów głębokości. Woda posiada dobrą klasę czystości i jest dobrze natleniona. Brzegi są wysokie, porośnięte lasem mieszanym, co zapewnia świetną osłonę przed wiatrem. Podłoże jest w przeważającej części piaszczyste.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80850, 'Jezioro Silickie', 'jezioro-silickie', 'LAKE', 53.751276, 20.623098, 'Warmińsko-Mazurskie', 'Barczewo / Silice', 'Jezioro Silickie to malowniczy akwen rynnowy położony w pagórkowatym terenie na południe od Barczewa. Jezioro charakteryzuje się bardzo czystą wodą i twardym, piaszczystym dnem, które regularnie opada do rynny środkowej osiągającej głębokość ok. 10-12 metrów. Brzegi są w większości suche, porośnięte lasem mieszanym i polami, co zapewnia dobre natlenienie wody przez wiatr.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80851, 'Jezioro Linówka', 'jezioro-linowka', 'LAKE', 53.775621, 20.657827, 'Warmińsko-Mazurskie', 'Barczewo', 'Jezioro Linówka to niewielkie, kameralne "oczko" śródleśne o charakterze wybitnie eutroficznym. Jak sama nazwa wskazuje, akwen jest idealnym siedliskiem dla ryb litoralu. Jezioro jest płytkie (max 3-4 m) z dnem wyścielonym grubą warstwą osadów organicznych i liści. Brzegi są niskie, porośnięte szerokim pasem trzcin i tataraku, co zapewnia rybom spokój i doskonałe warunki do wzrostu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80852, 'Jezioro Bogdańskie', 'jezioro-bogdanskie', 'LAKE', 53.781523, 20.649211, 'Warmińsko-Mazurskie', 'Barczewo / Bogdany', 'Jezioro Bogdańskie to rynnowy zbiornik polodowcowy o wydłużonym kształcie i urozmaiconym dnie. Akwen jest dość głęboki (do 10-12 m), z wyraźnie zarysowanymi spadkami i rynną centralną. Woda posiada dobrą klasę czystości i jest dobrze natleniona. Brzegi są zróżnicowane – od piaszczystych plaż po zarośnięte, dzikie skarpy porośnięte starodrzewem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80853, 'Jezioro Świetajno (Kierzbuńskie)', 'jezioro-swietajno-2', 'LAKE', 53.793122, 20.686977, 'Warmińsko-Mazurskie', 'Pasym / Kierzbuń', 'Jezioro Świetajno (często mylone z Napiwodzkim, stąd nazwa Świetajno 2 lub Kierzbuńskie) to majestatyczna rynna sielawowa o dużej głębokości (blisko 20 m) i bardzo czystej wodzie. Akwen charakteryzuje się twardym, piaszczysto-żwirowym dnem i stromymi spadkami. Jest to typowe jezioro polodowcowe ukryte wśród lasów i pagórków, co nadaje mu surowy, północny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80854, 'Jezioro Umląg', 'jezioro-umlag', 'LAKE', 53.795607, 20.666834, 'Warmińsko-Mazurskie', 'Barczewo', 'Jezioro Umląg to stosunkowo duży i płytki akwen (max 6-7 m) o charakterze eutroficznym, położony niedaleko Barczewa. Charakteryzuje się bardzo rozwiniętą linią brzegową z licznymi zatokami i półwyspami. Dno jest w dużej mierze muliste, ale z wyraźnymi piaszczystymi wypłyceniami i podwodnymi górkami. Woda jest żyzna, co sprzyja ogromnej biomasie ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80855, 'Jezioro Kiermas', 'jezioro-kiermas', 'LAKE', 53.80795, 20.719571, 'Warmińsko-Mazurskie', 'Barczewo', 'Jezioro Kiermas to urokliwy akwen rynnowo-przepływowy, przez który przepływa rzeka Pisa Warmińska. Zbiornik jest stosunkowo płytki (średnio 2-3 m), o charakterze wybitnie eutroficznym. Dno jest muliste, bogate w bentos, co czyni jezioro doskonałą stołówką dla ryb ryjących. Linia brzegowa jest silnie porośnięta trzciną, a liczne skupiska grzybiemi białych tworzą malownicze krajobrazy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80856, 'Jezioro Kierzlińskie (Arpuń)', 'jezioro-kierzlinskie', 'LAKE', 53.799827, 20.742853, 'Warmińsko-Mazurskie', 'Kierzliny / Barczewo', 'Jezioro Kierzlińskie (znane również jako Arpuń) to głęboka rynna polodowcowa o powierzchni ok. 90 ha. Akwen charakteryzuje się krystalicznie czystą wodą (I klasa) i twardym, piaszczysto-żwirowym dnem. Batymetria jest typowo polodowcowa: strome spady zaczynają się blisko brzegu i schodzą w mrok głębin sięgających ponad 18 metrów. To klasyczne jezioro sielawowe o chłodnej i dobrze natlenionej toni.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80857, 'Jezioro Kierzlińskie Małe', 'jezioro-kierzlinskie-male', 'LAKE', 53.806923, 20.743775, 'Warmińsko-Mazurskie', 'Kierzliny', 'Niewielki, kameralny akwen sąsiadujący z jeziorem Kierzlińskim Wielkim. Ma charakter eutroficzny, z dnem mulistym i bogatą roślinnością brzegową. Maksymalna głębokość nie przekracza 5-6 metrów. Brzegi są niskie, otoczone lasem i polami, co zapewnia rybom spokój i doskonałe warunki do tarła.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80858, 'Jezioro Kiełdynek', 'jezioro-kieldynek', 'LAKE', 53.806125, 20.753753, 'Warmińsko-Mazurskie', 'Kierzliny / Barczewo', 'Jezioro Kiełdynek to mały, śródleśny zbiornik o charakterze rynnowym, położony w ustronnej części puszczy. Akwen posiada twarde dno i dobrą przejrzystość wody. Batymetria jest regularna – rynna o głębokości do 8-10 metrów biegnie przez środek jeziora. Brzegi są wysokie i zalesione, co nadaje akwenowi dziki charakter. Roślinność wodna jest skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80859, 'Jezioro Raks Górny', 'jezioro-raks-gorny', 'LAKE', 53.774055, 20.792913, 'Warmińsko-Mazurskie', 'Jedwabno / Pasym', 'Jezioro Raks Górny to dziki, leśny akwen o wydłużonym kształcie, otoczony gęstą puszczą. Posiada charakter rynnowy ze znacznym stopniem zarastania litoralu. Dno jest mieszane: piaszczyste w rejonach wschodnich i muliste w osi głównej. Woda posiada dobrą klasę czystości, choć jesienią przybiera ciemniejszy odcień od opadających liści. To jezioro, w którym presja wędkarska jest znikoma.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80860, 'Jezioro Grabowo Górne', 'jezioro-grabowo-gorne', 'LAKE', 53.769439, 20.813212, 'Warmińsko-Mazurskie', 'Bartołty Wielkie', 'Grabowo Górne to kameralny, śródleśny zbiornik o charakterze rynnowym, położony w pagórkowatym terenie na południe od Bartołt. Akwen cechuje się bardzo czystą wodą i twardym, piaszczysto-żwirowym dnem. Batymetria jest regularna – rynna o głębokości do 8-10 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte starym lasem sosnowym, co nadaje akwenowi dziki i ustronny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80861, 'Jezioro Grabowo Dolne', 'jezioro-grabowo-dolne', 'LAKE', 53.774803, 20.822074, 'Warmińsko-Mazurskie', 'Bartołty Wielkie', 'Jezioro Grabowo Dolne to zbiornik bezpośrednio sąsiadujący z Grabowem Górnym, połączony z nim małym ciekiem. Ma charakter nieco bardziej eutroficzny, z dnem mulistym w głębszych partiach i bogatszą roślinnością brzegową. Maksymalna głębokość oscyluje wokół 6-7 metrów. Brzegi są urozmaicone – od zalesionych skarp po niskie, częściowo podmokłe zatoki, które stanowią idealne tarliska dla ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80862, 'Jezioro Południewskie', 'jezioro-poludniewskie', 'LAKE', 53.778429, 20.807548, 'Warmińsko-Mazurskie', 'Bartołty Wielkie', 'Jezioro Południewskie to niewielki akwen rynnowy, stanowiący południowy kraniec kompleksu jezior bartołtowskich. Charakteryzuje się wydłużonym kształtem i dnem w dużej mierze mulistym, z wyraźnymi piaszczystymi wypłyceniami w rejonie dopływów. Woda jest żyzna, co sprzyja bogatej wegetacji roślinności podwodnej. Maksymalna głębokość nie przekracza 5-6 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80863, 'Jezioro Bartołtowskie (Bartołty Wielkie)', 'jezioro-bartoltowskie', 'LAKE', 53.781536, 20.819542, 'Warmińsko-Mazurskie', 'Bartołty Wielkie', 'Jezioro Bartołtowskie to majestatyczna rynna polodowcowa o powierzchni blisko 150 hektarów, stanowiąca serce regionu. Akwen charakteryzuje się monumentalną batymetrią – dno opada stromo do centralnej rynny osiągającej ponad 30 metrów głębokości. Woda posiada dobrą klasę czystości, a dno jest w przeważającej części twarde, piaszczysto-żwirowe. Przez jezioro przepływa rzeka Pisa, co zapewnia stały dopływ natlenionej wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80864, 'Jezioro Dłużek Mały', 'jezioro-dluzek-maly', 'LAKE', 53.784566, 20.80802, 'Warmińsko-Mazurskie', 'Bartołty Wielkie', 'Dłużek Mały to kameralny zbiornik rynnowy położony w bliskim sąsiedztwie głównej rynny jeziora Dłużek. Akwen cechuje się czystą wodą i twardym dnem. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte lasem mieszanym, co nadaje akwenowi ustronny charakter. Roślinność wodna jest umiarkowana, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80865, 'Jezioro Dłużek (Bartołty)', 'jezioro-dluzek-bartolty', 'LAKE', 53.789472, 20.80214, 'Warmińsko-Mazurskie', 'Bartołty Wielkie', 'Jezioro Dłużek koło Bartołt to klasyczna, głęboka rynna polodowcowa (do 20 m głębokości) o bardzo przejrzystej wodzie. Akwen charakteryzuje się wąskim kształtem i stromo opadającymi stokami, które są w większości twarde i piaszczyste. Jezioro jest połączone systemem cieków z Piszami i Bartołtami, co sprzyja migracji ryb. Brzegi są wysokie, w dużej mierze zalesione, co zapewnia świetną osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80866, 'Jezioro Tumiańskie', 'jezioro-tumianskie', 'LAKE', 53.802374, 20.809994, 'Warmińsko-Mazurskie', 'Tumiany / Barczewo', 'Jezioro Tumiańskie to jeden z najatrakcyjniejszych turystycznie i wędkarsko akwenów w gminie Barczewo. To rozległe jezioro rynnowe (blisko 130 ha) o bardzo urozmaiconym dnie, z licznymi podwodnymi górkami i blatami. Przez jezioro przepływa rzeka Pisa Warmińska, co zapewnia doskonałe natlenienie wody i wysoką żyzność. Dno jest pofałdowane, piaszczysto-muliste, o maksymalnej głębokości ok. 15-18 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80867, 'Jezioro Omłunek', 'jezioro-omlunek', 'LAKE', 53.797444, 20.771692, 'Warmińsko-Mazurskie', 'Barczewo / Ruszajny', 'Jezioro Omłunek to kameralny akwen o charakterze eutroficznym, położony pośród pól i kęp lasów. Jezioro jest stosunkowo płytkie (max 5-6 m) z dnem w dużej mierze mulistym, bogatym w bentos. Linia brzegowa jest silnie porośnięta trzciną i pałką wodną, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych. Woda szybko się tu nagrzewa, co sprzyja intensywnym żerowaniom lina i karasia w okresie wiosennym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80868, 'Jezioro Masakojtek', 'jezioro-masakojtek', 'LAKE', 53.794886, 20.776579, 'Warmińsko-Mazurskie', 'Barczewo / Ruszajny', 'Jezioro Masakojtek (często nazywane Małym Omłunkiem) to niewielki, niemal ukryty zbiornik o charakterze dystroficzno-eutroficznym. Akwen charakteryzuje się miękkim dnem i mroczną wodą o lekko herbacianym odcieniu. Maksymalna głębokość nie przekracza kilku metrów. Brzegi są niskie i bagniste, porośnięte mchem torfowcem i trzciną, co sprawia, że dostęp do lustra wody jest bardzo ograniczony.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80869, 'Staw Olszawy', 'staw-olszawy', 'LAKE', 52.17736, 21.453638, 'Mazowieckie', 'Natolin', 'Staw Olszawy to klimatyczny, śródleśny akwen otoczony gęstym pasem olszyn (stąd nazwa). Jezioro posiada charakterystyczny, wydłużony kształt i urozmaicone dno z licznymi podwodnymi korzeniami drzew, co stwarza doskonałe kryjówki dla ryb. Średnia głębokość to ok. 1,2 metra. Woda posiada lekkie zabarwienie humusowe.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80870, 'Jezioro Łekuk', 'jezioro-lekuk-2', 'LAKE', 54.125676, 22.026772, 'Warmińsko-Mazurskie', 'Kruklanki / Orłowo', 'Jezioro Łekuk to serce dzikiej Puszczy Boreckiej. Akwen rynnowy o powierzchni ok. 40 ha, charakteryzujący się nieskazitelną czystością wody i twardym, piaszczysto-żwirowym dnem. Batymetria jest typowo polodowcowa: centralna rynna osiąga głębokość ok. 12-14 metrów, a strome stoki są usiane powalonymi dębami. Brzegi są wysokie, w całości porośnięte puszczańskim lasem, co zapewnia absolutną ciszę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80871, 'Jezioro Czarna Kuta', 'jezioro-czarna-kuta', 'LAKE', 54.168941, 21.934505, 'Warmińsko-Mazurskie', 'Kruklanki', 'Czarna Kuta to malowniczy, stosunkowo płytki akwen (max 4-5 m) o charakterze eutroficznym, położony przy miejscowości Kruklanki. Dno jest muliste, bogate w bentos, z licznymi piaszczystymi wypłyceniami przy brzegach. Jezioro posiada bardzo szeroki pas trzcinowisk i liczne skupiska grążeli żółtych, co tworzy idealne warunki dla ryb spokojnego żeru i lęgów szczupaka.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80872, 'Jezioro Głęboka Kuta', 'jezioro-gleboka-kuta', 'LAKE', 54.167371, 21.916416, 'Warmińsko-Mazurskie', 'Kruklanki', 'Głęboka Kuta to rynnowy sąsiad Czarnej Kuty, o zupełnie innym profilu dna. Jak sama nazwa wskazuje, akwen jest znacznie głębszy (do 15-20 m) i posiada stromo opadające, twarde brzegi. Woda jest czystsza i chłodniejsza. Dno jest piaszczysto-gliniaste, co sprzyja bytowaniu sandacza. Jezioro otoczone jest wianuszkiem lasu, co zapewnia osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80873, 'Jezioro Piłackie', 'jezioro-pilackie-2', 'LAKE', 54.194483, 21.961488, 'Warmińsko-Mazurskie', 'Kruklanki / Piłaki Małe', 'Jezioro Piłackie to zjawiskowy akwen o charakterze sielawowym, położony w otulinie Puszczy Boreckiej. Charakteryzuje się niesamowitą przejrzystością wody i bardzo urozmaiconą rzeźbą dna z licznymi podwodnymi górkami i głębokimi rynnami sięgającymi ponad 40 metrów. Dno jest wybitnie twarde, piaszczysto-żwirowe. Brzegi są wysokie i suche, częściowo zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80874, 'Jezioro Graużyny', 'jezioro-grauzyny', 'LAKE', 54.391597, 22.945118, 'Podlaskie', 'Wiżajny', 'Jezioro Graużyny to surowy, polodowcowy akwen położony na samej granicy z Litwą, w rejonie Wiżajn. Charakteryzuje się typowym dla Suwalszczyzny pofałdowanym dnem i twardym podłożem. Woda jest dobrze natleniona i chłodna. Maksymalna głębokość oscyluje wokół 10-12 metrów. Brzegi są w większości otwarte, pagórkowate, co sprawia, że jezioro jest wietrzne, a woda dobrze wymieszana.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80875, 'Jezioro Słascinek', 'jezioro-slascinek', 'LAKE', 54.364355, 22.922298, 'Podlaskie', 'Rutka-Tartak', 'Jezioro Słascinek to kameralny, śródpolny zbiornik o charakterze eutroficznym, położony w pofałdowanym krajobrazie Suwalszczyzny. Akwen jest stosunkowo płytki, z dnem w dużej mierze mulistym i bogatą roślinnością przybrzeżną. Woda nagrzewa się szybko, co sprzyja rozwojowi narybku. Brzegi są urozmaicone, z licznymi skupiskami trzcin i tataraku.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80876, 'Jezioro Makowszczyna', 'jezioro-makowszczyna', 'LAKE', 54.364021, 22.927367, 'Podlaskie', 'Rutka-Tartak', 'Niewielkie, niemal okrągłe jezioro wytopiskowe położone w bliskim sąsiedztwie Słascinka. Makowszczyna charakteryzuje się miękkim dnem i umiarkowaną głębokością. Jezioro jest osłonięte od wiatru przez naturalne ukształtowanie terenu, co sprawia, że tafla wody jest zazwyczaj spokojna. Roślinność wodna jest tu obfita, z przewagą grążeli żółtych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80877, 'Jezioro Wielkie Lnisko Pierwsze', 'jezioro-lnisko-1', 'LAKE', 53.477396, 18.847024, 'Kujawsko-Pomorskie', 'Grudziądz / Lniska', 'Pierwszy z ciągu zbiorników w miejscowości Lniska. Posiada charakter rynnowy z dnem piaszczysto-mulistym. Woda posiada przyzwoitą przejrzystość. Wędkarsko to bardzo stabilna woda leszczowo-szczupakowa, rzadziej odwiedzana przez turystów z miasta.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80878, 'Jezioro Łopuszek', 'jezioro-lopuszek', 'LAKE', 54.35101, 22.983967, 'Podlaskie', 'Rutka-Tartak / Postawele', 'Jezioro Łopuszek to malowniczy, rynnowy akwen położony w głębokiej polodowcowej rynnie. Charakteryzuje się twardym, piaszczysto-żwirowym dnem i bardzo czystą wodą. Brzegi są wysokie i strome, porośnięte lasem mieszanym, co nadaje akwenowi surowy, niemal górski charakter. Batymetria jest regularna z wyraźnie zarysowaną rynną centralną sięgającą 10-12 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80879, 'Długi Staw', 'dlugi-staw-lubuskie', 'LAKE', 52.107943, 15.006616, 'Lubuskie', 'Maszewo / Grzmiąca', 'Długi Staw to wąski, rynnowy zbiornik śródleśny. Posiada charakter dystroficzny z miękkim dnem i roślinnością typową dla torfowisk. To matecznik szczupaka leśnego, który ze względu na barwę wody ma przepiękne, ciemne ubarwienie. Oaza ciszy dla koneserów.', 'PZW Zielona Góra');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80880, 'Jezioro Udziejek', 'jezioro-udziejek', 'LAKE', 54.253749, 22.888234, 'Podlaskie', 'Jeleniewo / Udziejek', 'Jezioro Udziejek to jeden z najbardziej urokliwych akwenów Suwalskiego Parku Krajobrazowego. Położone w głębokiej dolinie rzeki Szeszupy, charakteryzuje się nieskazitelną czystością wody i unikatowym mikroklimatem. Dno jest twarde, piaszczysto-żwirowe, z wyraźnymi uskokami rynnowymi dochodzącymi do 10 metrów. Akwen jest otoczony przez majestatyczne wzgórza morenowe.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80881, 'Jezioro Błędne', 'jezioro-bledne', 'LAKE', 54.24903, 22.87071, 'Podlaskie', 'Jeleniewo / Udziejek', 'Jezioro Błędne to niewielki, dziki akwen położony w samym sercu Suwalskiego Parku Krajobrazowego. Jezioro jest stosunkowo płytkie (max 5-6 m), o charakterze eutroficznym, otoczone bagnistymi łąkami i kępami olszyn. Dno jest miękkie, muliste, bogate w bentos. Woda posiada dobrą przejrzystość, choć latem ulega lekkim zakwitom.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80882, 'Jezioro Wodziłki', 'jezioro-wodzilki', 'LAKE', 54.241801, 22.847872, 'Podlaskie', 'Jeleniewo / Wodziłki', 'Jezioro Wodziłki to malowniczy zbiornik położony w pobliżu znanej wioski staroobrzędowców. Jest to akwen o charakterze rynnowym, dość głęboki (do 10 m), o bardzo czystej wodzie i piaszczystym dnie. Brzegi są wysokie i suche, co ułatwia dostęp do litoralu. Jezioro jest wybitnie wyciszone, stanowiąc integralną część surowego krajobrazu Suwalszczyzny.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80883, 'Jezioro Jęgłóweczek', 'jezioro-jegloweczek', 'LAKE', 54.236605, 22.879441, 'Podlaskie', 'Jeleniewo / Szurpiły', 'Jezioro Jęgłóweczek to mniejszy sąsiad potężnego jeziora Szurpiły, położony w zjawiskowej scenerii Suwalskiego Parku Krajobrazowego. Akwen rynnowy o bardzo czystej wodzie i głębokości sięgającej 8-10 metrów. Dno jest twarde, piaszczyste, ze stromymi spadkami przy brzegu południowym. Jezioro otaczają malownicze wzgórza morenowe, co chroni je przed silnym wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80884, 'Jezioro Zachajskie', 'jezioro-zachajskie', 'LAKE', 51.626889, 23.25943, 'Lubelskie', 'Podedwórze / Włodawa', 'Jezioro Zachajskie to klasyczny przedstawiciel płytkich jezior Polesia Lubelskiego. Akwen o powierzchni ok. 25 ha, charakteryzujący się bardzo silnym procesem eutrofizacji i sukcesji roślinnej. Dno jest wybitnie miękkie, wyścielone grubą warstwą mułu torfowego. Woda posiada lekko brunatny odcień, typowy dla terenów torfowiskowych. Brzegi są niskie, bagniste, otoczone szerokim pasem trzcinowisk i łozowisk.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80885, 'Stary Staw', 'stary-staw-krosnice', 'LAKE', 51.446732, 17.427599, 'Dolnośląskie', 'Krośnice', 'Stary Staw to akwen o bogatej historii, będący częścią dawnego systemu nawadniającego doliny. Posiada bardzo regularny kształt i wyrównane dno, co ułatwia precyzyjne nęcenie. Woda posiada przyzwoitą klasę czystości jak na stawy dolinowe. Brzegi są wysokie, porośnięte trawą i pojedynczymi drzewami, co ułatwia rzuty metodami odległościowymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80886, 'Jezioro Mosty', 'jezioro-mosty', 'LAKE', 51.649182, 23.30389, 'Lubelskie', 'Podedwórze / Parczew', 'Jezioro Mosty to jeden z większych naturalnych zbiorników Polesia Lubelskiego (ok. 70 ha), połączony systemem rowów z kanałem Wieprz-Krzna. Jest to jezioro wybitnie eutroficzne, o średniej głębokości zaledwie 1-1,5 metra. Dno jest płaskie, pokryte grubym osadem organicznym. Brzegi są silnie zarośnięte, co tworzy unikatowy mikroklimat i ostoję dla licznego ptactwa wodnego oraz ryb litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80887, 'Jezioro Podedworskie', 'jezioro-podedworskie', 'LAKE', 51.705023, 23.16971, 'Lubelskie', 'Podedwórze', 'Jezioro Podedworskie to urokliwy, kameralny akwen położony w sąsiedztwie kompleksów stawowych. Zbiornik jest płytki (max 3 m), z dnem mulistym i bogatą roślinnością zanurzoną. Woda jest żyzna, co sprzyja szybkiej wegetacji i obfitości pokarmu naturalnego. Brzegi są w większości dostępne od strony pól i łąk, choć pas trzcin bywa tu dość zwarty.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80888, 'Jezioro Klepacz', 'jezioro-klepacz', 'LAKE', 52.112173, 14.995737, 'Lubuskie', 'Maszewo / Grzmiąca', 'Klepacz to urokliwy, śródleśny akwen rynnowy. Posiada twarde dno w strefie litoralu i rynnę środkową sięgającą 6-7 metrów. Woda jest czysta i dobrze natleniona. Jezioro zapewnia komfortowe warunki łowienia w totalnej ciszy, z dala od szlaków turystycznych.', 'PZW Zielona Góra');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80889, 'Jezioro Żeliźnieckie', 'jezioro-zeliznieckie', 'LAKE', 51.873683, 22.913404, 'Lubelskie', 'Międzyrzec Podlaski / Kąkolewnica', 'Jezioro Żeliźnieckie (Żelizna) to niewielki, zagubiony wśród lasów i mokradeł akwen o charakterze dystroficznym. Zbiornik charakteryzuje się mroczną, lekko brunatną wodą i bardzo miękkim dnem. Brzegi są niskie, bagniste, porośnięte mchem torfowcem, co nadaje jezioru charakterystyczny wygląd "pływającego brzegu". Maksymalna głębokość nie przekracza kilku metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80890, 'Żwirownia Bereza', 'zwirownia-bereza', 'LAKE', 51.948206, 22.790902, 'Lubelskie', 'Międzyrzec Podlaski', 'Żwirownia Bereza to nowoczesny zbiornik poeksploatacyjny o zupełnie innej charakterystyce niż naturalne jeziora regionu. Akwen cechuje się znacznymi głębokościami (do 10-12 m) i bardzo urozmaiconym, twardym, żwirowym dnem. Woda jest tu znacznie przejrzystsza i lepiej natleniona. Brzegi są wysokie, piaszczyste, z szybko narastającą głębokością, co sprzyja bytowaniu drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80891, 'Jezioro Czapelka', 'jezioro-czapelka', 'LAKE', 52.060037, 23.565738, 'Lubelskie', 'Kodeń / Terespol', 'Jezioro Czapelka to urokliwe starorzecze rzeki Bug, położone w malowniczej dolinie nadbużańskiej. Akwen ma kształt podkowy, jest stosunkowo wąski i głęboki w osi dawnego koryta. Charakterystyczną cechą Czapelki jest jej dynamiczny rybostan, uzupełniany podczas corocznych wylewów rzeki. Dno jest mulisto-piaszczyste, z licznymi powalonymi dębami (tzw. "czarne dęby"), co stwarza doskonałe kryjówki dla ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80892, 'Zbiornik Ligotniak', 'zbiornik-ligotniak', 'LAKE', 50.122343, 18.266562, 'Śląskie', 'Racibórz / Babice', 'Ligotniak to jedno z ciekawszych wyrobisk pożwirowych w kompleksie babickim. Akwen charakteryzuje się bardzo urozmaiconym dnem z licznymi uskokami i piaszczystymi wyspami. Woda jest tu stosunkowo przejrzysta, co wynika z przesiąków z pobliskiej Odry. Maksymalna głębokość sięga 5-6 metrów, a twarde, żwirowe podłoże sprzyja bytowaniu drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80893, 'Staw Duża Przystań', 'staw-duza-przystan', 'LAKE', 51.471905, 17.408533, 'Dolnośląskie', 'Potasznia / Police', 'Duża Przystań to rozległy staw o charakterze paciorkowym, będący częścią ścieżki dydaktycznej. Akwen charakteryzuje się ogromnymi przestrzeniami płycizn porośniętych roślinnością miękką. Dno jest wybitnie muliste, co sprzyja ogromnej populacji bentosu i czyni zbiornik doskonałą stołówką dla ryb ryjących. Woda jest żyzna i ciepła.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80894, 'Zbiornik Brzeziniak', 'zbiornik-brzeziniak', 'LAKE', 50.127319, 18.277634, 'Śląskie', 'Racibórz / Babice', 'Brzeziniak to kameralny staw pożwirowy, wybitnie wyciszony i osłonięty pasami drzew (brzóz i olch), co nadaje mu urokliwy charakter. Jezioro posiada typowe dla wyrobisk twarde dno, ale z grubszą warstwą osadów w zacisznych zatokach. Maksymalna głębokość oscyluje wokół 4 metrów. Woda nagrzewa się tu dość szybko, co stymuluje ryby do żerowania już wczesną wiosną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80895, 'Zbiornik Babiczak Południowy', 'zbiornik-babiczak-poludniowy', 'LAKE', 50.133605, 18.277731, 'Śląskie', 'Nędza / Babice', 'Babiczak Południowy to duży i prestiżowy zbiornik poeksploatacyjny, znany w regionie z bardzo czystej wody i bogatego rybostanu. Batymetria jest tu typowa dla "żwirowni": gwałtowne uskok, twarde kanty i głębokie rynny sięgające 7-8 metrów. Jezioro jest bardzo dobrze natlenione, co sprzyja aktywności ryb przez cały rok, również w okresie zimowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80896, 'Zbiornik Tatusiak', 'zbiornik-tatusiak', 'LAKE', 50.136078, 18.282645, 'Śląskie', 'Babice / Ciechowice', 'Tatusiak to mniejszy, urokliwy akwen wchodzący w skład kompleksu babickiego. Posiada charakterystyczny kształt z licznymi cyplami i zatokami. Dno jest mieszane: twardy żwir przeplata się z piaszczystymi łachami. Głębokość średnia to ok. 3 metry. Zbiornik jest zaciszny, osłonięty od wiatru, co czyni go idealnym miejscem na relaksujący wypad ze spławikiem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80897, 'Jezioro Tobołek', 'jezioro-tobolek', 'LAKE', 53.749124, 18.518535, 'Pomorskie', 'Osiek', 'Tobołek to małe, dzikie oczko leśne o charakterze dystroficznym. Woda ma odcień herbaty, a dno jest bardzo miękkie. To raj dla łowców karasia i lina, którzy cenią absolutną ciszę i brak kontaktu z cywilizacją.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80898, 'Zbiornik Babiczak Północny', 'zbiornik-babiczak-polnocny', 'LAKE', 50.139406, 18.27698, 'Śląskie', 'Ciechowice / Babice', 'Babiczak Północny to rozległy akwen o charakterze technicznym, powstały po wydobyciu kruszywa. Zbiornik charakteryzuje się znacznymi głębokościami i bardzo twardym dnem. Batymetria jest tu mniej urozmaicona niż w części południowej, dominują tu szerokie, głębokie rynny. Woda posiada dobrą przezroczystość i jest chłodna w głębszych partiach, co sprzyja zimowaniu ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80899, 'Zbiornik Salm Mały', 'zbiornik-salm-maly', 'LAKE', 50.141919, 18.284265, 'Śląskie', 'Ciechowice', 'Salm Mały to niewielki, kameralny zbiornik pożwirowy o bardzo regularnym kształcie i czystej wodzie. Akwen cechuje się twardym dnem i głębokością dochodzącą do 4-5 metrów. Jezioro jest otoczone pasem krzewów i łąk, co zapewnia wędkarzom prywatność i spokój. Roślinność brzegowa jest rzadka, co ułatwia dostęp do litoralu niemal w każdym punkcie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80900, 'Zbiornik Salm Duży', 'zbiornik-salm-duzy', 'LAKE', 50.146918, 18.278224, 'Śląskie', 'Ciechowice', 'Salm Duży to jeden z najgłębszych akwenów w tym kompleksie, o wybitnie pożwirowym charakterze. Jezioro charakteryzuje się monumentalnymi spadkami dna i licznymi, podwodnymi uskokami. Maksymalna głębokość sięga 9-10 metrów. Woda posiada wysoką klasę czystości i jest dobrze natleniona. Dno jest wybitnie twarde, co sprawia, że woda jest wolna od zawiesin mulistych nawet przy dużej fali.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80901, 'Jezioro Duże (Bierawa)', 'jezioro-duze-bierawa', 'LAKE', 50.397617, 18.135424, 'Opolskie', 'Bierawa / Kędzierzyn-Koźle', 'Jezioro Duże w Bierawie to potężny, nowoczesny zbiornik poeksploatacyjny o powierzchni blisko 80 hektarów. Jest to jeden z najpopularniejszych akwenów wędkarskich na Opolszczyźnie. Charakteryzuje się niesamowitą wręcz dynamiką dna – liczne wyspy, półwyspy, głębokie rynny (do 12 m) i rozległe płycizny. Woda jest żyzna, o dobrej natlenieniu, co przekłada się na gigantyczną biomasę ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80902, 'Akwen Linowy (Bierawa)', 'akwen-linowy-bierawa', 'LAKE', 50.395388, 18.14862, 'Opolskie', 'Bierawa', 'Akwen Linowy, zgodnie ze swoją nazwą, to mniejszy i znacznie płytszy zbiornik w kompleksie Bierawy, dedykowany rybom spokojnego żeru litoralu. Jezioro jest silnie zarastające roślinnością miękką (rogatek, moczarka), z dnem wyścielonym warstwą mułu i osadów organicznych. Maksymalna głębokość nie przekracza 3-4 metrów. Brzegi są niskie, porośnięte gęstą trzciną, co zapewnia rybom idealne schronienie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80903, 'Staw Zaroślak', 'staw-zaroslak', 'LAKE', 51.447548, 17.395949, 'Dolnośląskie', 'Krośnice / Milicz', 'Staw Zaroślak to typowy akwen Doliny Baryczy o charakterze wybitnie eutroficznym. Jak sama nazwa wskazuje, zbiornik charakteryzuje się bardzo silnym zarastaniem – szeroki pas trzcin i liczne wyspy rogatka tworzą tu naturalny labirynt. Dno jest miękkie, wyścielone grubą warstwą mułu organicznego, co sprzyja ogromnej populacji bentosu. Głębokość średnia nie przekracza 1,2 metra.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80904, 'Staw Toń', 'staw-ton', 'LAKE', 51.45174, 17.394769, 'Dolnośląskie', 'Krośnice', 'Staw Toń to jeden z głębszych (jak na standardy milickie) zbiorników w kompleksie, o nieco bardziej otwartym lustrze wody. Akwen posiada wyraźnie zarysowane koryto w osi przepływu wody, gdzie dno jest twardsze i piaszczyste. Woda jest żyzna, o niskiej przezroczystości, co sprzyja aktywności ryb karpiowatych przez całą dobę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80905, 'Jezioro Górny Klepacz', 'jezioro-gorny-klepacz', 'LAKE', 52.118721, 14.992894, 'Lubuskie', 'Maszewo / Grzmiąca', 'Górny Klepacz stanowi północne przedłużenie systemu Klepacz. Jest to akwen o charakterze wytopiskowym z piaszczysto-mulistym dnem. Maksymalna głębokość nie przekracza 5 metrów. Wędkarze cenią jezioro za populację dorodnej płoci i lina w zacisznych zatokach.', 'PZW Zielona Góra');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80906, 'Staw Henryk Nowy', 'staw-henryk-nowy', 'LAKE', 51.451072, 17.402676, 'Dolnośląskie', 'Krośnice', 'Henryk Nowy to nowoczesny w swojej formie staw po-hodowlany o regularnych kształtach i wyrównanej batymetrii. Akwen charakteryzuje się dnem piaszczysto-mulistym i bardzo bogatym rybostanem, typowym dla zbiorników intensywnie zarybianych. Woda szybko się nagrzewa, co sprawia, że żerowanie ryb karpiowatych zaczyna się tu bardzo wcześnie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80907, 'Staw Zimochowy', 'staw-zimochowy', 'LAKE', 51.450517, 17.407944, 'Dolnośląskie', 'Krośnice', 'Staw Zimochowy to urokliwy, zaciszny akwen położony na skraju lasu i pól. Posiada charakterystyczny, wydłużony kształt i zróżnicowane dno z licznymi przegłębieniami. Woda posiada lekko brunatny odcień, a pas trzcin jest tu węższy niż w sąsiednich stawach, co ułatwia dostęp do lustra wody. Średnia głębokość oscyluje wokół 1,5 metra.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80908, 'Staw Brzostowski', 'staw-brzostowski', 'LAKE', 51.444596, 17.416887, 'Dolnośląskie', 'Brzostowo / Krośnice', 'Staw Brzostowski to potężny akwen o charakterze stawu paciorkowego, typowy dla krajobrazu milickiego. Charakteryzuje się ogromnymi przestrzeniami płycizn porośniętych liliami wodnymi i grążelem. Dno jest wybitnie muliste, co wymusza na wędkarzach stosowanie bardzo lekkich zestawów gruntowych, by przynęta nie grzęzła w osadach. Woda jest żyzna i ciepła.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80909, 'Staw Henryk', 'staw-henryk', 'LAKE', 51.449949, 17.414542, 'Dolnośląskie', 'Krośnice', 'Staw Henryk (często mylony z nowszym sąsiadem) to starszy, "dzikszy" zbiornik o bardziej urozmaiconej linii brzegowej. Dno jest tu mocno pofałdowane, z licznymi pozostałościami po starej wycince drzew w niecce stawu. Woda jest żyzna, o odcieniu zielonkawym, bogata w plankton. Brzegi są porośnięte starymi olchami i wierzbami, co zapewnia rybom liczne kryjówki pod zwisającymi gałęziami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80910, 'Staw Żeleźnicki', 'staw-zeleznicki', 'LAKE', 51.453171, 17.420604, 'Dolnośląskie', 'Krośnice', 'Staw Żeleźnicki to urokliwy, średniej wielkości zbiornik położony w malowniczym otoczeniu łąk i lasów. Akwen charakteryzuje się czystszą wodą niż typowe stawy hodowlane i dnem piaszczysto-żwirowym w strefie przybrzeżnej. Posiada wyraźnie zaznaczoną głębię w centralnej części (do 2,5 m). Roślinność wodna jest tu umiarkowana, z przewagą grążeli żółtych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80911, 'Staw Młyński', 'staw-mlynski-krosnice', 'LAKE', 51.454836, 17.411753, 'Dolnośląskie', 'Krośnice / Milicz', 'Staw Młyński to zbiornik o charakterze przepływowym, zasilany wodami rzeki Prądni. Dzięki stałemu przepływowi woda jest tu lepiej natleniona niż w zbiornikach zamkniętych. Akwen jest stosunkowo płytki, z wyraźnie zarysowanym korytem rzecznym na dnie. Podłoże jest twarde, piaszczysto-kamieniste w miejscach nurtu i muliste w zatokach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80912, 'Staw Polny', 'staw-polny-milicz', 'LAKE', 51.543361, 17.360737, 'Dolnośląskie', 'Milicz / Ruda Sułowska', 'Staw Polny to element rezerwatu Stawy Milickie. Jest to płytki zbiornik hodowlany o bogatej historii. Charakteryzuje się mulistym dnem i rozległymi trzcinowiskami, które stanowią ostoję dla rzadkich gatunków ptaków wodnych. Woda jest żyzna, o wysokiej biomasie.', 'Stawy Milickie SA / PZW');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80913, 'Staw Kolejowy', 'staw-kolejowy', 'LAKE', 51.455157, 17.382328, 'Dolnośląskie', 'Krośnice', 'Staw Kolejowy to charakterystyczny akwen położony bezpośrednio przy trasie Krośnickiej Kolei Wąskotorowej. Jest to zbiornik stosunkowo płytki, o dnie piaszczysto-mulistym, który pełni funkcję rekreacyjno-hodowlaną. Woda posiada typowy dla regionu odcień zielonkawy. Brzegi są dobrze zagospodarowane, z licznymi miejscami dostępnymi dla turystów i wędkarzy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80914, 'Staw Brukowy', 'staw-brukowy', 'LAKE', 51.452977, 17.368677, 'Dolnośląskie', 'Krośnice / Police', 'Staw Brukowy to urokliwy, śródleśny akwen wchodzący w skład kompleksu krośnickiego. Zbiornik charakteryzuje się twardszym niż przeciętnie dnem (stąd nazwa) i wyraźnie zarysowaną misą o głębokości do 2 metrów. Brzegi są porośnięte starymi dębami, których korzenie wchodzą do wody, tworząc naturalne kryjówki dla ryb drapieżnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80915, 'Staw Policki', 'staw-policki', 'LAKE', 51.460458, 17.391701, 'Dolnośląskie', 'Police / Krośnice', 'Staw Policki to duży akwen o charakterze produkcyjno-wędkarskim, położony przy miejscowości Police. Zbiornik posiada bardzo rozległe lustro wody i regularną linię brzegową wzdłuż grobli. Dno jest muliste z piaszczystymi łachami w części zachodniej. Woda jest żyzna, co przekłada się na szybkie przyrosty ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80916, 'Staw Grunda', 'staw-grunda', 'LAKE', 51.464527, 17.402892, 'Dolnośląskie', 'Police', 'Staw Grunda to mniejszy, kameralny zbiornik o charakterze eutroficznym, położony w sercu kompleksu stawowego. Charakteryzuje się miękkim dnem i bardzo bogatą roślinnością zanurzoną. Maksymalna głębokość nie przekracza 1,5 metra. Brzegi są niskie, silnie zarośnięte trzciną, co zapewnia rybom spokój i doskonałe warunki do tarła.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80917, 'Jezioro Chełm (Staw)', 'jezioro-chelm', 'LAKE', 51.47099, 17.398513, 'Dolnośląskie', 'Police', 'Staw Chełm to malowniczy akwen położony w północnej części kompleksu, otoczony łąkami i lasami. Zbiornik charakteryzuje się czystszą wodą niż typowe stawy hodowlane i dnem piaszczysto-mulistym. Posiada urozmaiconą linię brzegową z licznymi półwyspami, co stwarza wędkarzom wiele opcji wyboru stanowiska w zależności od kierunku wiatru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80918, 'Jezioro Wielkie Lnisko Drugie', 'jezioro-lnisko-2', 'LAKE', 53.478864, 18.855071, 'Kujawsko-Pomorskie', 'Grudziądz / Lniska', 'Bezpośredni sąsiad Pierwszego Lniska, o nieco bardziej mulistym dnie i bogatszej roślinności zanurzonej. Maksymalna głębokość nie przekracza 8 metrów. To wyśmienite łowisko lina i karasia, który znajduje tu schronienie w pasach grążeli żółtych.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80919, 'Staw Mała Przystań', 'staw-mala-przystan', 'LAKE', 51.476204, 17.41422, 'Dolnośląskie', 'Potasznia', 'Mała Przystań to kameralny zbiornik sąsiadujący z Dużą Przystanią. Ma charakter wybitnie tarliskowy, z dnem mulistym i bardzo bogatą roślinnością brzegową. Maksymalna głębokość nie przekracza 1 metra. Brzegi są niskie, porośnięte szerokim pasem trzcin, co zapewnia rybom spokój i ochronę przed drapieżnikami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80920, 'Jezioro Duży Wrzosowiec', 'jezioro-duzy-wrzosowiec', 'LAKE', 51.479489, 17.406641, 'Dolnośląskie', 'Potasznia / Police', 'Duży Wrzosowiec to jeden z najdzikszych stawów w tej części Doliny Baryczy, położony na skraju rezerwatu. Akwen charakteryzuje się mroczną, lekko brunatną wodą i miękkim dnem wyścielonym osadami roślinnymi. Jezioro jest osłonięte wysokimi groblami i pasami olszyn, co sprawia, że tafla wody jest zazwyczaj spokojna. Średnia głębokość to ok. 1,2 metra.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80921, 'Staw Duży Karol', 'staw-duzy-karol', 'LAKE', 51.478657, 17.427878, 'Dolnośląskie', 'Potasznia', 'Staw Duży Karol to rozległy akwen produkcyjno-wędkarski o regularnych kształtach. Zbiornik charakteryzuje się dnem piaszczysto-mulistym i bardzo bogatym rybostanem karpiowym. Woda jest żyzna, co przekłada się na gigantyczną biomasę ryb białych. Brzegi są wysokie, uformowane w twarde groble, co ułatwia dostęp do lustra wody w wielu miejscach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80922, 'Staw Brzozowy', 'staw-brzozowy', 'LAKE', 51.48173, 17.416806, 'Dolnośląskie', 'Milicz', 'Staw Brzozowy to urokliwy, śródleśny zbiornik wchodzący w skład północnego kompleksu Stawów Milickich. Akwen charakteryzuje się piaszczysto-mulistym dnem i głębokością oscylującą wokół 1,2 metra. Jezioro jest wybitnie wyciszone, osłonięte od wiatru gęstym pasem brzóz i olch, co nadaje mu intymny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80923, 'Staw Lipsk', 'staw-lipsk', 'LAKE', 51.483501, 17.423501, 'Dolnośląskie', 'Milicz / Ruda Milicka', 'Staw Lipsk to większy akwen o charakterze hodowlano-wędkarskim, położony niedaleko Rudy Milickiej. Zbiornik posiada rozległe lustro wody i regularną linię brzegową wzdłuż twardych grobli. Dno jest muliste z licznymi piaszczystymi wypłyceniami, które są idealnymi tarliskami. Woda jest żyzna, co przekłada się na szybkie przyrosty ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80924, 'Staw Czarny Las', 'staw-czarny-las', 'LAKE', 51.488425, 17.408373, 'Dolnośląskie', 'Milicz', 'Staw Czarny Las to jeden z najdzikszych akwenów w rejonie, o mrocznej, lekko brunatnej wodzie wynikającej z wysokiej zawartości kwasów humusowych. Dno jest wysoce muliste i puszyste, wyścielone grubą warstwą osadów leśnych. Brzegi są niskie i bagniste, co nadaje jezioru charakterystyczny, puszczański wygląd.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80925, 'Staw Graniczny', 'staw-graniczny-milicz', 'LAKE', 51.489146, 17.424359, 'Dolnośląskie', 'Milicz', 'Staw Graniczny to podłużny zbiornik położony na styku różnych sekcji kompleksu stawowego. Charakteryzuje się zróżnicowaną batymetrią z wyraźnie zaznaczonym rowem przepływowym. Dno jest mieszane: twardy żwir u wylotów mnichów przechodzi w głęboki muł w środkowej części. Woda jest dobrze natleniona i żyzna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80926, 'Jezioro Zofiówka', 'jezioro-zofiowka', 'LAKE', 51.491271, 17.395115, 'Dolnośląskie', 'Milicz', 'Zofiówka to kameralny, wybitnie rybny akwen o charakterze eutroficznym. Zbiornik jest stosunkowo płytki (max 1,5 m), z dnem wyścielonym osadami organicznymi i bogatą roślinnością zanurzoną. Jezioro jest osłonięte od wiatru przez naturalne ukształtowanie terenu, co sprzyja aktywności ryb spokojnego żeru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80927, 'Staw Czatkowicki', 'staw-czatkowicki', 'LAKE', 51.504348, 17.392945, 'Dolnośląskie', 'Czatkowice / Milicz', 'Staw Czatkowicki to jeden z największych i najważniejszych akwenów w tym sektorze (ponad 50 ha). Posiada regularne kształty i bardzo twarde groble, które służą za doskonałe stanowiska wędkarskie. Dno jest pofałdowane, piaszczysto-muliste, z wyraźnymi uskokami technicznymi. Woda jest żyzna i dobrze natleniona przez wiatr.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80928, 'Staw Grabownica', 'staw-grabownica', 'LAKE', 51.529759, 17.40097, 'Dolnośląskie', 'Grabownica / Milicz', 'Staw Grabownica to gigant (blisko 300 ha) i serce rezerwatu ornitologicznego. Jest to akwen niesamowicie płytki (średnio 0,8 m), o dnie niemal całkowicie wyrównanym, pokrytym piaskiem i warstwą mułu. Jezioro słynie z ogromnych trzcinowisk i wysp lęgowych. Wędkowanie tutaj podlega najsurowszym rygorom ochronnym w regionie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80929, 'Staw Machnicki Górny', 'staw-machnicki-gorny', 'LAKE', 51.536266, 17.384899, 'Dolnośląskie', 'Grabownica / Milicz', 'Machnicki Górny to zbiornik o charakterze hodowlano-wędkarskim położony na nieco wyższym poziomie systemu nawadniającego. Akwen ma regularny kształt i wyrównane dno piaszczysto-muliste. Woda szybko się nagrzewa, co sprzyja wczesnej aktywności ryb karpiowatych. Brzegi są wysokie, uformowane w twarde groble, co ułatwia dostęp do lustra wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80930, 'Staw Golica', 'staw-golica', 'LAKE', 51.539289, 17.371831, 'Dolnośląskie', 'Milicz', 'Staw Golica to otwarty akwen o skąpej roślinności brzegowej (stąd nazwa), co czyni go podatnym na falowanie i dobre natlenienie. Jezioro jest płytkie (max 1,2 m), o dnie w przeważającej mierze piaszczystym z cienką warstwą osadów organicznych. Brak wysokich drzew wokół sprawia, że wiatr stale miesza wodę, co stymuluje ryby do intensywnego żerowania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80931, 'Staw Machnicki Dolny', 'staw-machnicki-dolny', 'LAKE', 51.540383, 17.384534, 'Dolnośląskie', 'Grabownica / Milicz', 'Machnicki Dolny to zbiornik bezpośrednio sąsiadujący z Machnickim Górnym, połączony z nim systemem jazów. Ma charakter bardziej eutroficzny, z dnem mulistym i bogatszą roślinnością brzegową. Maksymalna głębokość oscyluje wokół 1,5 metra. Brzegi są niskie, porośnięte szerokim pasem trzcin, co zapewnia rybom spokój i doskonałe warunki do wzrostu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80932, 'Staw Henryk 2', 'staw-henryk-2', 'LAKE', 51.543346, 17.392945, 'Dolnośląskie', 'Milicz / Krośnice', 'Staw Henryk 2 to akwen o charakterze hodowlano-rekreacyjnym, będący częścią większego kompleksu stawowego. Zbiornik charakteryzuje się dość wyrównanym dnem piaszczysto-mulistym i głębokością sięgającą 1,5 metra. Woda jest wybitnie żyzna, co sprzyja szybkiej wegetacji roślinności podwodnej, głównie moczarki kanadyjskiej. Brzegi są umocnione groblami, co ułatwia dostęp do wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80933, 'Staw Leszek', 'staw-leszek', 'LAKE', 51.544987, 17.382152, 'Dolnośląskie', 'Krośnice', 'Staw Leszek to urokliwy, kameralny zbiornik położony w cieniu starych dębów. Akwen posiada urozmaicone dno z licznymi podwodnymi korzeniami, co stwarza doskonałe kryjówki dla ryb drapieżnych. Średnia głębokość wynosi około 1,2 metra. Woda posiada lekko brunatny odcień, typowy dla stawów otoczonych lasem liściastym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80934, 'Jezioro Średnik', 'jezioro-srednik', 'LAKE', 54.057335, 18.08444, 'Pomorskie', 'Przywidz', 'Średnik to urokliwe "oczko" rynnowe w ciągu jezior przywidzkich. Zbiornik charakteryzuje się czystą wodą i twardym dnem w strefie przybrzeżnej. Maksymalna głębokość oscyluje wokół 7-8 metrów. Jezioro otoczone jest pagórkowatym terenem, co sprzyja dobremu natlenieniu wody przez wiatr.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80935, 'Staw Staś Górny', 'staw-stas-gorny', 'LAKE', 51.546735, 17.378354, 'Dolnośląskie', 'Milicz', 'Staś Górny to jeden z najwyżej położonych stawów w systemie kaskadowym kompleksu. Dzięki temu woda nagrzewa się tu bardzo szybko wiosną, co stymuluje ryby do intensywnego żerowania. Akwen jest płytki (max 1 m) z dnem w dużej mierze mulistym. Brzegi są porośnięte niską roślinnością trawiastą i pasem trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80936, 'Staw Staś Dolny', 'staw-stas-dolny', 'LAKE', 51.546255, 17.371938, 'Dolnośląskie', 'Milicz', 'Staw Staś Dolny to bezpośredni sąsiad Stasia Górnego, położony nieco niżej w systemie nawadniającym. Akwen charakteryzuje się grubszą warstwą mułu i bogatszą szatą roślinności wynurzonej. Maksymalna głębokość oscyluje wokół 1,5 metra. Brzegi są niskie, silnie zarośnięte tatarakiem i trzciną, co zapewnia rybom doskonałe warunki do tarła i ochrony narybku.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80937, 'Staw Słowian', 'staw-slowian', 'LAKE', 51.549591, 17.370973, 'Dolnośląskie', 'Milicz', 'Staw Słowian to otwarty akwen o skąpej roślinności brzegowej, co czyni go podatnym na falowanie i dobre natlenienie wody. Jezioro jest stosunkowo płytkie, o dnie w przeważającej mierze piaszczystym z cienką warstwą osadów organicznych. Brak wysokich drzew wokół sprawia, że wiatr stale miesza wodę, co stymuluje ryby do aktywnego żerowania przez całą dobę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80938, 'Staw Mieszka', 'staw-mieszka-milicz', 'LAKE', 51.548924, 17.378354, 'Dolnośląskie', 'Milicz', 'Staw Mieszka to malowniczy zbiornik o urozmaiconej linii brzegowej, położony w sercu kompleksu milickiego. Akwen charakteryzuje się żyzną wodą i dnem mulistym, bogatym w ochotkę. Roślinność zanurzona tworzy tu rozległe dywany, stanowiące naturalną spiżarnię dla ryb karpiowatych. Brzegi są porośnięte starymi drzewami, co zapewnia cień w upalne dni.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80939, 'Staw Mieszko', 'staw-mieszko', 'LAKE', 51.547656, 17.382495, 'Dolnośląskie', 'Milicz', 'Staw Mieszko (często mylony z sąsiednim zbiornikiem o podobnej nazwie) to akwen o charakterze wybitnie produkcyjnym. Posiada bardzo regularny kształt i twarde groble, które są wygodne dla wędkarzy zmotoryzowanych. Dno jest pofałdowane, piaszczysto-muliste, z wyraźnie zaznaczonym korytem dopływowym. Woda jest dobrze natleniona i żyzna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80940, 'Staw Nowy Świat Dolny', 'staw-nowy-swiat-dolny', 'LAKE', 51.550045, 17.390456, 'Dolnośląskie', 'Milicz', 'Staw Nowy Świat Dolny to urokliwy zbiornik położony w ustronnym miejscu, otoczony łąkami i lasami. Akwen charakteryzuje się mniejszą głębokością (max 1,2 m) i bardzo bogatą roślinnością litoralu. Woda posiada dobrą klasę czystości jak na stawy dolinowe, a dno jest w przeważającej części mulisto-torfowe. Brzegi są niskie, porośnięte szerokim pasem trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80941, 'Staw Nowy Świat Górny', 'staw-nowy-swiat-gorny', 'LAKE', 51.547096, 17.400563, 'Dolnośląskie', 'Milicz', 'Nowy Świat Górny to rozległy akwen o charakterze hodowlano-wędkarskim, położony przy głównej grobli komunikacyjnej. Zbiornik charakteryzuje się twardszym dnem i wyraźnie zarysowanymi spadkami w rejonie mnichów. Woda jest żyzna, co przekłada się na ogromną biomasę ryb. Brzegi są wysokie i suche, co ułatwia dostęp do lustra wody w wielu miejscach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80942, 'Staw Andrzej', 'staw-andrzej', 'LAKE', 51.549791, 17.412364, 'Dolnośląskie', 'Milicz', 'Staw Andrzej to niewielki, kameralny zbiornik o charakterze eutroficznym, położony niedaleko Potaszni. Zbiornik charakteryzuje się miękkim dnem i mroczną wodą o lekkim zabarwieniu humusowym. Maksymalna głębokość nie przekracza 1,5 metra. Brzegi są niskie, porośnięte szerokim pasem trzcin i grążeli żółtych, co zapewnia rybom spokój.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80943, 'Staw Bolko 1', 'staw-bolko-1', 'LAKE', 51.552046, 17.379127, 'Dolnośląskie', 'Milicz', 'Staw Bolko 1 to podłużny akwen wchodzący w skład kompleksu Bolko, położony w otulinie leśnej. Jezioro posiada typowe dla regionu piaszczysto-muliste dno i głębokość do 1,5 metra. Brzegi są porośnięte lasem dębowym, co zapewnia dobrą osłonę przed wiatrem i nadaje zbiornikowi malowniczy wygląd. Woda jest żyzna i dobrze natleniona.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80944, 'Staw Bolko 2', 'staw-bolko-2', 'LAKE', 51.554341, 17.368419, 'Dolnośląskie', 'Milicz', 'Staw Bolko 2 to bezpośredni sąsiad Bolko 1, o bardziej otwartym charakterze i większej powierzchni. Akwen posiada twardsze dno z licznymi piaszczystymi wypłyceniami, które są idealnymi tarliskami. Woda posiada dobrą przezroczystość jak na stawy hodowlane. Brzegi są umocnione groblami, co ułatwia rzuty metodami gruntowymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80945, 'Stawy Wszewilki', 'stawy-wszewilki', 'LAKE', 51.542662, 17.300816, 'Dolnośląskie', 'Milicz / Wszewilki', 'Kompleks stawów we Wszewilkach to jedno z najważniejszych miejsc na wędkarskiej mapie okolic Milicza. Są to zbiorniki o charakterze hodowlano-rekreacyjnym, charakteryzujące się wybitnie żyzną wodą i dnem piaszczysto-mulistym. Głębokość średnia oscyluje wokół 1,3 m. Stawy są połączone systemem jazów, co pozwala na stałą kontrolę poziomu wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80946, 'Staw Słupicki Stary', 'staw-slupicki-stary', 'LAKE', 51.536892, 17.320979, 'Dolnośląskie', 'Słupia / Milicz', 'Staw Słupicki Stary to klimatyczny, nieco "dzikszy" akwen wchodzący w skład kompleksu słupickiego. Zbiornik charakteryzuje się grubszą warstwą mułu i bardzo bogatą roślinnością zanurzoną (rogatek, moczarka). Brzegi są porośnięte starodrzewem, co zapewnia świetną osłonę przed wiatrem i nadaje jezioru puszczański wygląd. Średnia głębokość nie przekracza 1,2 metra.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80947, 'Staw Słupicki Nowy', 'staw-slupicki-nowy', 'LAKE', 51.540282, 17.326086, 'Dolnośląskie', 'Słupia / Milicz', 'Słupicki Nowy to akwen o bardziej regularnym kształcie i twardszym dnie niż jego "stary" sąsiad. Zbiornik został zmodernizowany pod kątem intensywnej gospodarki rybackiej, co przekłada się na bardzo bogaty rybostan. Woda jest dobrze natleniona, a dno piaszczysto-żwirowe w rejonach grobli ułatwia rzuty gruntowe. Maksymalna głębokość wynosi około 1,8 metra.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80948, 'Staw Przelotny', 'staw-przelotny', 'LAKE', 51.536492, 17.332738, 'Dolnośląskie', 'Słupia', 'Staw Przelotny to specyficzny akwen rynnowo-przepływowy, pełniący funkcję tranzytową dla wody zasilającej niższe partie kompleksu. Dzięki stałemu ruchowi wody, dno jest tu twardsze, w wielu miejscach wymyte do czystego piasku. Akwen jest stosunkowo wąski i długi, z wyraźnie zaznaczonym nurtem w osi głównej. Średnia głębokość to ok. 1,5 metra.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80949, 'Staw Wilczy Duży', 'staw-wilczy-duzy', 'LAKE', 51.54763, 17.357798, 'Dolnośląskie', 'Milicz', 'Jeden z większych stawów w kompleksie Rudy Sułowskiej. Akwen typowo karpiowy, o wyrównanym dnie i głębokości rzadko przekraczającej 1,5 metra. Słynie z dorodnych karpi i amurów. Brzegi są trudnodostępne, co sprzyja dzikiej naturze.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80950, 'Staw Wilczy Mały', 'staw-wilczy-maly', 'LAKE', 51.541279, 17.351317, 'Dolnośląskie', 'Milicz', 'Mniejszy brat Stawu Wilczego, ukryty głębiej w szuwarach. Bardzo płytki, silnie zarastający grążelem i liliami wodnymi. Idealne tarlisko dla lina i szczupaka. Wędkowanie tu wymaga ogromnej ciszy i precyzji.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80951, 'Staw Słoneczny Dolny', 'staw-sloneczny-dolny', 'LAKE', 51.547176, 17.325675, 'Dolnośląskie', 'Milicz', 'Staw Słoneczny Dolny to otwarty akwen o skąpej roślinności wysokiej na groblach, co sprawia, że tafla wody jest silnie wystawiona na działanie promieni słonecznych (stąd nazwa). Powoduje to bardzo szybkie nagrzewanie się wody wiosną i burzliwą wegetację roślinności podwodnej. Dno jest muliste, bogate w bentos i ochotkę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80952, 'Stawy Ewa', 'stawy-ewa', 'LAKE', 51.512976, 17.242827, 'Dolnośląskie', 'Milicz', 'Kompleks Stawów Ewa to jeden z najbardziej urokliwych i "dzikich" zakątków w pobliżu Milicza. Są to mniejsze zbiorniki o charakterze paciorkowym, otoczone gęstym lasem i bagnami. Akweny charakteryzują się miękkim, torfowym dnem i mroczną wodą o lekkim zabarwieniu humusowym. Maksymalna głębokość nie przekracza 1,5 metra. Brzegi są niskie, silnie zarośnięte, co zapewnia rybom absolutny spokój.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80953, 'Jezioro Słupeckie', 'jezioro-slupeckie', 'LAKE', 52.307167, 17.90102, 'Wielkopolskie', 'Słupca', 'Jezioro Słupeckie to duży zbiornik zaporowy (powstały przez spiętrzenie rzeki Mesny), o powierzchni ok. 260 ha. Akwen charakteryzuje się wyrównaną batymetrią z dnem piaszczysto-mulistym i średnią głębokością ok. 2 metrów. Woda jest żyzna, o średniej przejrzystości, co sprzyja ogromnej biomasie ryb karpiowatych i drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80954, 'Jezioro Powidzkie Małe', 'jezioro-powidzkie-male', 'LAKE', 52.43906, 17.956574, 'Wielkopolskie', 'Powidz', 'Powidzkie Małe to urokliwa odnoga wielkiego kompleksu powidzkiego, oddzielona od głównego plosa przewężeniem. Charakteryzuje się krystalicznie czystą wodą (I klasa) i twardym, piaszczystym dnem. Akwen jest płytszy od głównego jeziora (max 6-8 m), co sprawia, że woda szybciej się nagrzewa. Brzegi są porośnięte gęstą trzciną, ale z licznymi pomostami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80955, 'Jezioro Kosewskie (Naprusewskie)', 'jezioro-kosewskie', 'LAKE', 52.414318, 17.976058, 'Wielkopolskie', 'Kosewo / Słupca', 'Jezioro Kosewskie (zwane też Naprusewskim) to głęboki akwen rynnowy o powierzchni ok. 140 ha, będący częścią Powidzkiego Parku Krajobrazowego. Dno jest wybitnie urozmaicone z licznymi uskokami, głęboczkami (do 20 m) i podwodnymi górkami. Woda jest niezwykle przejrzysta. Brzegi są w większości wysokie i suche, porośnięte lasami sosnowymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80956, 'Jezioro Powidzkie', 'jezioro-powidzkie', 'LAKE', 52.405561, 17.936726, 'Wielkopolskie', 'Powidz / Przybrodzin', 'Jezioro Powidzkie to "mazurska perła" Wielkopolski, największy i najczystszy akwen regionu (ponad 1000 ha). Jest to klasyczna rynna polodowcowa o monumentalnej batymetrii – głębokość maksymalna sięga 46 metrów. Woda posiada nieskażoną krystaliczność (I klasa), co pozwala obserwować dno na głębokości kilku metrów. Dno jest twarde, piaszczysto-żwirowe, z gwałtownymi uskokami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80957, 'Jezioro Piłka', 'jezioro-pilka', 'LAKE', 52.479226, 17.90956, 'Wielkopolskie', 'Orchowo / Orchówko', 'Jezioro Piłka to kameralny, śródleśny akwen rynnowy o bardzo czystej wodzie. Jezioro ma charakterystyczny, wydłużony kształt i twarde piaszczyste dno. Maksymalna głębokość oscyluje wokół 8-10 metrów. Akwen otaczają dorodne lasy, co zapewnia ciszę i osłonę przed wiatrem. Roślinność wodna jest tu skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80958, 'Staw Słoneczny Górny', 'staw-sloneczny-gorny', 'LAKE', 51.544614, 17.342155, 'Dolnośląskie', 'Milicz / Ruda Sułowska', 'Malowniczy staw o regularnym kształcie, wykorzystywany do intensywnej hodowli karpia milickiego. Dno jest wysoce zamulone, bogate w bentos. Wokół stawu przebiegają ścieżki przyrodnicze, co pozwala na obserwację bielików.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80959, 'Jezioro Skubarczewskie', 'jezioro-skubarczewskie', 'LAKE', 52.491848, 17.922595, 'Wielkopolskie / Kujawsko-Pomorskie', 'Orchowo / Skubarczewo', 'Jezioro Skubarczewskie to malownicza rynna rynnowa położona na granicy województw. Charakteryzuje się bardzo urozmaiconym ukształtowaniem dna z wyraźnie zaznaczoną rynną centralną o głębokości do 12-14 metrów. Woda jest czysta, o dobrej natlenieniu. Brzegi są zróżnicowane – od wysokich zalesionych skarp po piaszczyste plaże.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80960, 'Jezioro Ostrowite (Trzemeszeńskie)', 'jezioro-ostrowite-trzemeszno', 'LAKE', 52.520895, 17.868919, 'Wielkopolskie / Kujawsko-Pomorskie', 'Trzemeszno', 'Jezioro Ostrowite to rozległy akwen rynnowy (blisko 150 ha), stanowiący część ciągu jezior trzemeszeńskich. Posiada bardzo rozwiniętą linię brzegową z licznymi półwyspami i zatokami. Dno jest twarde, piaszczysto-żwirowe, o maksymalnej głębokości ok. 15 metrów. Woda posiada dobrą przejrzystość, choć w lecie ulega naturalnym zakwitom.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80961, 'Jezioro Zieleń', 'jezioro-zielen', 'LAKE', 52.543581, 17.848363, 'Wielkopolskie / Kujawsko-Pomorskie', 'Trzemeszno / Zieleń', 'Jezioro Zieleń to mniejszy akwen rynnowy wciśnięty w pofałdowany teren rolniczo-leśny. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 6-8 metrów. Jezioro posiada liczne przegłębienia w osi głównej i dobrze natlenioną wodę dzięki otwartemu brzegowi zachodniemu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80962, 'Fosa Trzemeszeńska (Jez. Klasztorne)', 'fosa-trzemeszenska', 'LAKE', 52.55539, 17.839372, 'Wielkopolskie / Kujawsko-Pomorskie', 'Trzemeszno', 'Fosa Trzemeszeńska (często nazywana Jeziorem Klasztornym) to specyficzny, niewielki akwen położony w samym sercu Trzemeszna, u stóp zabytkowej bazyliki. Jest to jezioro płytkie (max 3-4 m), o charakterze wybitnie eutroficznym. Dno jest wyścielone grubą warstwą mułu organicznego. Brzegi są w dużej mierze zagospodarowane – promenady, pomosty i skwerki.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80963, 'Jezioro Malicz', 'jezioro-malicz', 'LAKE', 52.577589, 17.833793, 'Wielkopolskie', 'Trzemeszno', 'Jezioro Malicz to urokliwy akwen rynnowy o powierzchni ok. 25 ha, położony w rynnie trzemeszeńskiej. Charakteryzuje się średnią głębokością oscylującą wokół 4-5 metrów i dnem piaszczysto-mulistym. Woda posiada typową dla regionu żyzność, co sprzyja rozwojowi bogatego litoralu. Brzegi są w dużej mierze porośnięte trzciną pospolitą, co tworzy doskonałe warunki ochronne dla narybku.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80964, 'Jezioro Kierzkowskie', 'jezioro-kierzkowskie', 'LAKE', 52.585431, 17.818467, 'Wielkopolskie', 'Trzemeszno / Kierzkowo', 'Jezioro Kierzkowskie to jedna z głębszych rynien w okolicy (max ok. 12 m), o wydłużonym kształcie i wyraźnie zarysowanych spadkach dna. Akwen posiada twarde piaszczysto-żwirowe podłoże w strefie przybrzeżnej, przechodzące w muliste koryto w osi głównej. Woda posiada dobrą przejrzystość wiosną, co sprzyja technikom spinningowym. Brzegi są zróżnicowane – od wysokich skarp po piaszczyste dojścia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80965, 'Jezioro Folusz', 'jezioro-folusz-trzemeszno', 'LAKE', 52.587719, 17.838299, 'Wielkopolskie', 'Trzemeszno', 'Jezioro Folusz to kameralny zbiornik rynnowy, silnie ulegający procesom eutrofizacji. Jest to akwen stosunkowo płytki, z dnem wyścielonym grubą warstwą mułu i resztek roślinnych. Woda jest wysoce żyzna, co przekłada się na ogromną biomasę ryb karpiowatych. Linia brzegowa jest gęsto porośnięte trzciną i tatarakiem, co utrudnia dostęp z brzegu bez wysokich woderów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80966, 'Staw Szklarek', 'staw-szklarek', 'LAKE', 51.556263, 17.336233, 'Dolnośląskie', 'Milicz', 'Szklarek to staw o urozmaiconej linii brzegowej z licznymi "oczkami" wśród trzcin. Woda ma tu charakterystyczny, nieco jaśniejszy odcień. To świetne łowisko szczupaka, który czatuje wzdłuż grobli.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80967, 'Staw Gadzinowy Duży', 'staw-gadzinowy-duzy', 'LAKE', 51.560345, 17.34885, 'Dolnośląskie', 'Milicz', 'Duży zbiornik położony w północnej części kompleksu. Charakteryzuje się ogromną ilością roślinności wynurzonej. Nazwa nawiązuje do bogatej fauny płazów i gadów. Wędkarsko wymagający ze względu na muł i zaczepy.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80968, 'Jezioro Weneckie', 'jezioro-weneckie', 'LAKE', 52.802489, 17.747018, 'Kujawsko-Pomorskie', 'Wenecja', 'Jezioro Weneckie to jedna z najpiękniejszych rynien regionu, położona u stóp ruin zamku w Wenecji. Akwen charakteryzuje się twardym dnem i głębokością sięgającą blisko 15-18 metrów. Woda posiada dobrą klasę czystości i jest dobrze natleniona. Batymetria jest typowo polodowcowa: strome spady uciekają szybko do rynny centralnej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80969, 'Jezioro Kocin', 'jezioro-kocin', 'LAKE', 52.585695, 17.846646, 'Wielkopolskie', 'Trzemeszno / Kocin', 'Jezioro Kocin to niewielki, ustronny zbiornik położony w zagłębieniu terenu wśród pól i kęp drzew. Akwen ma charakter misy jeziornej o łagodnych spadkach i dnie piaszczysto-mulistym. Maksymalna głębokość nie przekracza 5-6 metrów. Jezioro jest osłonięte od wiatru, co sprawia, że tafla wody jest zazwyczaj spokojna, a woda szybko nagrzewa się wiosną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80970, 'Jezioro Młynek', 'jezioro-mlynek-trzemeszno', 'LAKE', 52.598695, 17.830703, 'Wielkopolskie', 'Trzemeszno', 'Jezioro Młynek to mały akwen o charakterze przepływowym, dawniej pełniący funkcję spiętrzenia dla młyna wodnego. Dzięki stałemu ruchowi wody dno jest w wielu miejscach twardsze, wymyte do czystego piasku. Zbiornik jest płytki (max 3 m) i silnie zarastający grążelem i moczarką. Woda jest dobrze natleniona, co sprzyja aktywności ryb przez cały sezon.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80971, 'Jezioro Kurchowskie', 'jezioro-kurchowskie', 'LAKE', 52.603503, 17.803972, 'Kujawsko-Pomorskie / Wielkopolskie', 'Rogowo / Trzemeszno', 'Jezioro Kurchowskie (Kurchów) to głęboki akwen rynnowy położony na pograniczu województw. Charakteryzuje się monumentalną batymetrią – strome, piaszczyste spady schodzą do rynny o głębokości ok. 15 metrów. Woda posiada wysoką klasę czystości i jest dobrze natleniona. Dno jest wybitnie twarde, piaszczysto-żwirowe, co sprzyja bytowaniu drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80972, 'Jezioro Wielkie Łomno', 'jezioro-wielkie-lomno', 'LAKE', 52.637458, 17.762146, 'Kujawsko-Pomorskie', 'Rogowo / Łomno', 'Jezioro Wielkie Łomno to rozległy akwen rynnowy (blisko 100 ha) o bardzo urozmaiconym dnie. Posiada wyraźnie zaznaczoną rynnę centralną sięgającą blisko 18 metrów oraz rozległe piaszczyste blaty w części południowej. Woda posiada dobrą klasę czystości, a dno jest w przeważającej mierze twarde. Brzegi są w większości wysokie i piaszczyste, z rzadkim, ale twardym pasem trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80973, 'Jezioro Małe Łomno', 'jezioro-male-lomno', 'LAKE', 52.639535, 17.768143, 'Kujawsko-Pomorskie', 'Rogowo', 'Małe Łomno to kameralny zbiornik bezpośrednio połączony z Wielkim Łomnem. Ma charakter bardziej eutroficzny, z dnem mulistym i bogatszą roślinnością brzegową. Maksymalna głębokość nie przekracza 6-8 metrów. Brzegi są niskie, porośnięte gęstą trzciną, co zapewnia rybom spokój i doskonałe warunki do tarła.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80974, 'Jezioro Przedwieśnia', 'jezioro-przedwiesnia', 'LAKE', 52.645928, 17.769731, 'Kujawsko-Pomorskie', 'Rogowo', 'Jezioro Przedwieśnia to malowniczy, śródleśny zbiornik o charakterze rynnowym, położony w ustronnej części regionu. Akwen cechuje się bardzo czystą wodą i twardym piaszczystym dnem. Batymetria jest regularna – rynna o głębokości do 10 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte lasem mieszanym, co nadaje akwenowi dziki charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80975, 'Jezioro Palędzkie', 'jezioro-paledzkie', 'LAKE', 52.660949, 17.831647, 'Kujawsko-Pomorskie', 'Rogowo / Palędzie Dolne', 'Jezioro Palędzkie to majestatyczna rynna polodowcowa (ok. 50 ha) o bardzo czystej wodzie i twardym dnie. Akwen charakteryzuje się typowo rynnową batymetrią: strome spady zaczynają się blisko brzegu i schodzą w mrok głębin sięgających ponad 15 metrów. Brzegi są wysokie i w dużej mierze zalesione, co nadaje jezioru surowy urok.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80976, 'Staw Kwasek', 'staw-kwasek', 'LAKE', 51.438525, 17.455988, 'Dolnośląskie', 'Krośnice / Wierzchowice', 'Kwasek to urokliwy staw śródleśny w rejonie Krośnic. Ma charakter bardziej dziki niż stawy produkcyjne. Słynie z pięknych linów o miedzianym kolorze oraz walecznych karasi złocistych.', 'PZW Wrocław');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80977, 'Jezioro Wieneckie', 'jezioro-wieneckie', 'LAKE', 52.681872, 17.874327, 'Kujawsko-Pomorskie', 'Mogilno / Wieniec', 'Jezioro Wieneckie to urokliwy akwen rynnowy stanowiący część ciągu jezior mogileńskich. Charakteryzuje się wydłużonym kształtem i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 6-8 metrów. Woda jest żyzna, co sprzyja rozwojowi bujnej roślinności zanurzonej, szczególnie moczarki kanadyjskiej. Brzegi są w większości niskie, porośnięte gęstym pasem trzcin, co stwarza doskonałe warunki dla lęgów ryb spokojnego żeru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80978, 'Jezioro Chwałowskie', 'jezioro-chwalowskie', 'LAKE', 52.691985, 17.881579, 'Kujawsko-Pomorskie', 'Mogilno / Chwałowo', 'Jezioro Chwałowskie to bezpośredni, mniejszy sąsiad jeziora Wieneckiego, połączony z nim wąskim kanałem. Ma charakter wybitnie eutroficzny, z dnem wyścielonym grubą warstwą mułu i resztek roślinnych. Maksymalna głębokość nie przekracza 4-5 metrów. Brzegi są silnie zarośnięte, co zapewnia rybom doskonałą osłonę i czyni akwen naturalnym tarliskiem dla okolicznych wód.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80979, 'Jezioro Wiecanowskie', 'jezioro-wiecanowskie', 'LAKE', 52.686633, 17.931361, 'Kujawsko-Pomorskie', 'Mogilno / Wiecanowo', 'Jezioro Wiecanowskie to największy i najważniejszy akwen w rejonie Mogilna (blisko 300 ha). To głęboka rynna polodowcowa o urozmaiconym dnie, z licznymi podwodnymi górkami i głębokościami sięgającymi blisko 18 metrów. Woda posiada średnią przejrzystość, a dno jest w przeważającej części twarde, piaszczysto-żwirowe w rejonach uskoków. Jezioro jest dobrze natlenione dzięki dużej powierzchni otwartego lustra wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80980, 'Jezioro Żnińskie Duże', 'jezioro-zninskie-duze', 'LAKE', 52.862109, 17.733994, 'Kujawsko-Pomorskie', 'Żnin', 'Jezioro Żnińskie Duże to potężny akwen (ponad 400 ha) stanowiący centrum rekreacyjne Pałuk. Mimo dużej powierzchni, jest to jezioro stosunkowo płytkie (średnio ok. 5-6 m), o dnie piaszczysto-mulistym. Woda jest bardzo żyzna, co sprzyja ogromnej biomasie ryb, ale też generuje silne zakwity letnie. Jezioro jest wystawione na silne wiatry, co powoduje doskonałe natlenienie wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80981, 'Jezioro Żnińskie Małe', 'jezioro-zninskie-male', 'LAKE', 52.836438, 17.715883, 'Kujawsko-Pomorskie', 'Żnin', 'Jezioro Żnińskie Małe położone jest w bezpośrednim sąsiedztwie miasta. Akwen ma charakter rynnowy, jest głębszy od swojego "dużego" sąsiada (max do 11-12 m) i charakteryzuje się bardziej urozmaiconym dnem. Woda jest żyzna, co przekłada się na bogaty rybostan, choć poddana jest silnej presji urbanistycznej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80982, 'Jezioro Skarbińskie', 'jezioro-skarbinskie', 'LAKE', 52.81201, 17.711484, 'Kujawsko-Pomorskie', 'Żnin / Skarbin', 'Jezioro Skarbińskie to malowniczy, zaciszny akwen rynnowy położony na południe od Żnina. Charakteryzuje się czystą wodą i twardym piaszczystym dnem. Batymetria jest regularna z wyraźnie zarysowaną rynną środkową (max 10 m). Brzegi są w większości suche, porośnięte lasem mieszanym, co nadaje jezioru kameralny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80983, 'Jezioro Wneckie (Wnecze)', 'jezioro-wneckie', 'LAKE', 52.803968, 17.732084, 'Kujawsko-Pomorskie', 'Wenecja / Żnin', 'Jezioro Wneckie (często nazywane Wnecze) to mniejszy akwen rynnowy położony w bliskim sąsiedztwie legendarnej Wenecji. Charakteryzuje się bardzo urozmaiconym kształtem z licznymi zatokami i półwyspami. Dno jest piaszczysto-muliste, o średniej głębokości ok. 4 metrów. Woda jest żyzna i szybko się nagrzewa.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80984, 'Staw Malec', 'staw-malec', 'LAKE', 51.441173, 17.463756, 'Dolnośląskie', 'Krośnice', 'Niewielki staw o charakterze rekreacyjno-wędkarskim. Posiada kilka dobrze przygotowanych stanowisk z brzegu. Dominują tu ryby spokojnego żeru, regularnie dorybiane przez lokalne koła PZW.', 'PZW Wrocław');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80985, 'Staw Drozd', 'staw-drozd', 'LAKE', 51.438686, 17.475085, 'Dolnośląskie', 'Krośnice / Wierzchowice', 'Drozd to klasyczny staw doliny Baryczy, płytki i bardzo żyzny. Woda jest tu bogata w składniki odżywcze, co przekłada się na błyskawiczne przyrosty amurów. To łowisko "siłowe" – ryby po zacięciu natychmiast murują w trzciny.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80986, 'Jezioro Skrzynka (Wenecka)', 'jezioro-skrzynka-wenecja', 'LAKE', 52.798104, 17.761778, 'Kujawsko-Pomorskie', 'Wenecja', 'Jezioro Skrzynka to małe, niezwykle ustronne "oczko" o charakterze dystroficznym, położone niedaleko jeziora Weneckiego. Woda posiada mroczny, lekko brunatny odcień, a dno jest bardzo miękkie, wyścielone osadami liściastymi. Maksymalna głębokość nie przekracza kilku metrów. Brzegi są niskie i bagniste, porośnięte mchem torfowcem, co sprawia, że dostęp do wody jest utrudniony.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80987, 'Jezioro Biskupińskie', 'jezioro-biskupinskie', 'LAKE', 52.791266, 17.743778, 'Kujawsko-Pomorskie', 'Biskupin', 'Jezioro Biskupińskie to światowej sławy akwen, nad którym położona jest osada prasłowiańska. To jezioro rynnowe o powierzchni ok. 100 ha i maksymalnej głębokości ok. 13 metrów. Dno jest piaszczysto-muliste, z wyraźnie zaznaczoną rynną centralną. Woda jest żyzna i dobrze natleniona przez przepływającą rzekę Gąsawkę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80988, 'Staw Puchalski', 'staw-puchalski', 'LAKE', 52.151147, 20.909901, 'Mazowieckie', 'Raszyn / Puchały', 'Staw Puchalski to największy akwen w kompleksie Stawów Raszyńskich, o powierzchni blisko 40 ha. Jest to klasyczny staw paciorkowy o wybitnie eutroficznym charakterze, z dnem wyścielonym grubą warstwą mułu organicznego. Głębokość średnia nie przekracza 1,2 m. Akwen leży w granicach rezerwatu ornitologicznego, co determinuje surowe zasady połowu i ograniczenia w nęceniu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80989, 'Staw Przepływowy', 'staw-przeplywowy-raszyn', 'LAKE', 52.1478, 20.914734, 'Mazowieckie', 'Raszyn', 'Staw Przepływowy to specyficzny zbiornik rynnowy w kaskadzie raszyńskiej, przez który bezpośrednio przepływa rzeka Raszynka. Dzięki temu woda jest tu lepiej natleniona niż w sąsiednich nieckach. Dno jest zróżnicowane: twardsze, piaszczysto-żwirowe w osi nurtu i muliste w zatokach. Średnia głębokość to ok. 1,5 metra. Brzegi są porośnięte starymi wierzbami, których korzenie tworzą podwodne labirynty.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80990, 'Staw Raszyński', 'staw-raszynski', 'LAKE', 52.147579, 20.919546, 'Mazowieckie', 'Raszyn', 'Staw Raszyński to główny i najbardziej reprezentacyjny akwen kompleksu, położony bezpośrednio przy historycznym Pałacu w Falentach. Zbiornik charakteryzuje się wyrównaną batymetrią i dnem piaszczysto-mulistym. Woda jest żyzna, co przekłada się na ogromną biomasę ryb białych. Szeroki pas trzcin i tataraku zapewnia rybom doskonałe schronienie przed drapieżnikami i tarliska.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80991, 'Staw Rozgrodzony', 'staw-rozgrodzony', 'LAKE', 52.143872, 20.92226, 'Mazowieckie', 'Falenty', 'Staw Rozgrodzony to klimatyczny, mniejszy akwen w systemie falenckim, podzielony wewnętrznymi groblami na kilka mniejszych sekcji. Ma charakter wybitnie tarliskowy, z dnem wyścielonym grubą warstwą osadów torfowych. Maksymalna głębokość nie przekracza 1 metra. Brzegi są niskie, silnie zarośnięte, co zapewnia rybom spokój i absolutną oazę przed presją turystyczną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80992, 'Świniarski Staw', 'swiniarski-staw', 'LAKE', 51.435663, 17.465086, 'Dolnośląskie', 'Krośnice', 'Historyczny staw o bardzo starym systemie nawadniania. Posiada twardsze dno w okolicach mnicha i wlotów wody. Ceniony przez spinningistów za populację okonia, który wbrew pozorom świetnie radzi sobie w tych płytkich wodach.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80993, 'Staw Parkowy Dolny', 'staw-parkowy-dolny', 'LAKE', 52.142378, 20.920061, 'Mazowieckie', 'Falenty', 'Staw Parkowy Dolny to urokliwy zbiornik położony w zabytkowym parku pałacowym w Falentach. Akwen charakteryzuje się regularnymi spadkami i głębokością oscylującą wokół 1-1,5 m. Dno jest w dużej mierze muliste z pozostałościami po starych karczowiskach dębów. Woda posiada lekko mroczny odcień, a pasy trzcin są regularnie wykaszane, co ułatwia dostęp do litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80994, 'Staw Przydrożny', 'staw-przydrozny-falenty', 'LAKE', 52.143365, 20.917261, 'Mazowieckie', 'Falenty / Raszyn', 'Staw Przydrożny, położony w bezpośrednim sąsiedztwie Alei Krakowskiej, to specyficzny akwen buforowy. Mimo bliskości drogi, zbiornik tętni życiem biologicznym. Posiada twardsze, piaszczysto-żwirowe dno w strefie grobli i głębokość do 1,5 metra. Woda jest dobrze natleniona przez wiatr, co sprzyja aktywności ryb spokojnego żeru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80995, 'Staw Zimochowy', 'staw-zimochowy-raszyn', 'LAKE', 52.144725, 20.9242, 'Mazowieckie', 'Falenty', 'Staw Zimochowy to zaciszny akwen wschodniej części kompleksu, o charakterze wybitnie wyciszonym. Posiada charakterystyczny, wydłużony kształt i głębokość do 1,2 m. Dno jest wysoce muliste i bogate w bentos (ochotka), co czyni go doskonałą stołówką dla ryb ryjących. Brzegi są niskie, silnie zarośnięte trzciną pospolitą.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80996, 'Staw Falencki', 'staw-falencki', 'LAKE', 52.138282, 20.9174, 'Mazowieckie', 'Falenty', 'Staw Falencki to jeden z najbardziej urokliwych zbiorników kompleksu, położony u stóp rezerwatu przyrody. Posiada zróżnicowaną linię brzegową z licznymi zatoczkami i kępami drzew wchodzącymi do wody. Dno jest piaszczysto-muliste, o głębokości do 1,8 metra. Woda posiada przyzwoitą przejrzystość jak na stawy hodowlane, co sprzyja wegetacji roślinności podwodnej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80997, 'Staw Spiski', 'staw-spiski', 'LAKE', 52.134344, 20.912014, 'Mazowieckie', 'Falenty / Nowe Falenty', 'Staw Spiski to południowy kraniec kompleksu raszyńskiego, o charakterze bardziej otwartym i wietrznym. Akwen posiada twardsze dno z licznymi piaszczystymi wypłyceniami, które są idealnymi tarliskami. Woda jest dobrze natleniona. Brzegi są umocnione twardymi groblami, co ułatwia rzuty metodami gruntowymi. Maksymalna głębokość nie przekracza 1,5 metra.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80998, 'Żwirownia Puchały (Purchały)', 'zwirownia-puchaly', 'LAKE', 52.149831, 20.886694, 'Mazowieckie', 'Raszyn / Puchały', 'Żwirownia Puchały to głęboki (do 8-10 m) akwen poeksploatacyjny, położony w sąsiedztwie Stawów Raszyńskich. Charakteryzuje się zupełnie inną termiką i czystością wody niż sąsiednie stawy – woda jest tu przejrzysta, chłodniejsza w głębi i bardzo dobrze natleniona. Dno jest wybitnie twarde, pofałdowane, usiane kamieniami i żwirem polodowcowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (80999, 'Glinianki Szczęśliwickie', 'glinianki-szczesliwickie', 'LAKE', 52.206883, 20.960101, 'Mazowieckie', 'Warszawa / Ochota', 'Glinianki Szczęśliwickie to unikatowe łowisko miejskie położone w Parku Szczęśliwickim w sercu Warszawy. Akwen powstał w wyniku wydobycia gliny i charakteryzuje się znacznymi głębokościami (do 6-7 m) oraz stromo opadającymi brzegami. Woda jest dobrze natleniona (napowietrzacze), co sprzyja bogatemu rybostanowi. Dno jest twarde, gliniaste, z licznymi półkami podwodnymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81000, 'Jezioro Grzeźnie', 'jezioro-grzeznie', 'LAKE', 51.918607, 16.279335, 'Wielkopolskie', 'Brenno', 'Jezioro Grzeźnie to rynnowy akwen położony w ustronnym terenie leśnym na południe od Boszkowa. Charakteryzuje się czystą wodą i twardym dnem w strefie przybrzeżnej. Maksymalna głębokość sięga 8 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez pas lasu, co nadaje mu intymny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81001, 'Glinianka Krańcowa', 'glinianka-krancowa', 'LAKE', 52.199697, 20.922223, 'Mazowieckie', 'Warszawa / Włochy', 'Glinianka Krańcowa to jeden z akwenów wchodzących w skład Parku Kombatantów na warszawskich Włochach. Jest to typowe wyrobisko gliny o wysokich, stromych brzegach i twardym dnie. Głębokość sięga 4-5 metrów. Woda posiada dobrą przejrzystość i jest dobrze natleniona. Brzegi są umocnione faszyną, co ułatwia dostęp do lustra wody w wyznaczonych punktach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81002, 'Glinianka Cietrzewia', 'glinianka-cietrzewia', 'LAKE', 52.200647, 20.923693, 'Mazowieckie', 'Warszawa / Włochy', 'Glinianka Cietrzewia to większy sąsiad glinianki Krańcowej, połączony z nią w system parkowy. Akwen charakteryzuje się bardzo urozmaiconym dnem z licznymi uskokami i podwodnymi półkami gliniastymi. Maksymalna głębokość oscyluje wokół 5-6 metrów. Brzegi są zagospodarowane – pomosty, kładki i promenady ułatwiają wędkowanie w samym centrum zurbanizowanego terenu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81003, 'Staw Koziorożca', 'staw-koziorozca', 'LAKE', 52.209336, 20.911354, 'Mazowieckie', 'Warszawa / Włochy', 'Staw Koziorożca to urokliwy, zrewitalizowany akwen parkowy położony w sercu warszawskich Włoch. Jest to stosunkowo płytki zbiornik o charakterze eutroficznym, z dnem wyścielonym warstwą mułu i osadów organicznych. Woda jest regularnie napowietrzana, co sprzyja bogatemu rybostanowi. Brzegi są umocnione faszyną i obrzeżami betonowymi, co ułatwia dostęp do lustra wody w niemal każdym punkcie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81004, 'Glinianka Sznajdra', 'glinianka-sznajdra', 'LAKE', 52.217913, 20.9114, 'Mazowieckie', 'Warszawa / Bemowo', 'Glinianka Sznajdra to głęboki (do 5-6 m) zbiornik poeksploatacyjny położony w rejonie Bemowa. Akwen charakteryzuje się typową dla glinianek batymetrią – strome spady, twarde gliniaste półki podwodne i pofałdowane dno. Woda posiada dobrą przejrzystość i jest dobrze natleniona. Brzegi są wysokie, częściowo zarośnięte drzewami, co zapewnia osłonę przed wiatrem i miejskim hałasem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81005, 'Glinianki Jelonek', 'glinianki-jelonek', 'LAKE', 52.220026, 20.913304, 'Mazowieckie', 'Warszawa / Bemowo', 'Glinianki Jelonek to kompleks dwóch akwenów (Jelonek i Jelonek 2) położonych w Parku Górczewska. Zbiornik główny charakteryzuje się bardzo urozmaiconym dnem z licznymi przegłębieniami i twardymi partiami gliniasto-żwirowymi. Maksymalna głębokość oscyluje wokół 4-5 metrów. Woda jest żyzna, co sprzyja ogromnej biomasie ryb białych. Brzegi są częściowo zagospodarowane, z licznymi pomostami dla spacerowiczów i wędkarzy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81006, 'Glinianka Jelonek 2', 'glinianka-jelonek-2', 'LAKE', 52.221235, 20.914452, 'Mazowieckie', 'Warszawa / Bemowo', 'Jelonek 2 to mniejszy z akwenów kompleksu bemowskiego, połączony z głównym zbiornikiem systemem rur wyrównawczych. Posiada charakterystyczny, wydłużony kształt i nieco mniejszą głębokość (max 3 m). Dno jest w przeważającej mierze twarde, gliniaste, z cienką warstwą osadów organicznych. Brzegi są porośnięte rzadkim pasem trzcin, co ułatwia dostęp do lustra wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81007, 'Zbiornik Mokre Łąki', 'zbiornik-mokre-laki', 'LAKE', 52.292621, 20.783708, 'Mazowieckie', 'Izabelin / Truskaw', 'Zbiornik Mokre Łąki to nowoczesny akwen retencyjno-rekreacyjny położony w otulinie Kampinoskiego Parku Narodowego. Zbiornik jest stosunkowo płytki (max 2-2,5 m), o dnie piaszczystym z narastającą warstwą mułu. Woda posiada doskonałą klasę czystości ze względu na leśne zasilanie. Akwen jest w całości ogrodzony i monitorowany, co zapewnia bezpieczeństwo i wysoką kulturę wędkowania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81008, 'Staw Drozdek', 'staw-drozdek', 'LAKE', 51.434513, 17.483883, 'Dolnośląskie', 'Krośnice', 'Mniejszy sąsiad stawu Drozd. Wybitnie linowa woda. Brzegi są porośnięte gęstą wierzbą, co daje cień i osłonę w upalne dni. Ryby są tu wyjątkowo ufne ze względu na mniejszą presję niż na dużych obiektach.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81009, 'Zbiornik Jeziorsko', 'zbiornik-jeziorsko', 'LAKE', 51.796938, 18.669548, 'Łódzkie', 'Sieradz / Warta', 'Jeziorsko to monumentalny zbiornik zaporowy na rzece Warcie, największy w środkowej Polsce (powierzchnia ponad 4200 ha). Akwen charakteryzuje się ogromną dynamiką poziomów wody, co tworzy unikatowe w skali kraju środowisko. Południowa część to rozległe, płytkie tarliska i rezerwat ptactwa, północna to głęboka toń przy zaporze (do 10-12 m). Dno jest piaszczysto-muliste, z licznymi pozostałościami po karczowiskach i starym korycie rzeki.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81010, 'Jezioro Popówko', 'jezioro-popowko', 'LAKE', 53.594466, 19.374175, 'Warmińsko-Mazurskie', 'Susz / Iława', 'Jezioro Popówko to malowniczy, śródleśny zbiornik o charakterze rynnowym, położony w ustronnej części Pojezierza Iławskiego. Akwen charakteryzuje się twardym piaszczystym dnem i bardzo czystą wodą. Batymetria jest regularna – rynna o głębokości do 8-10 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem sosnowym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81011, 'Jezioro Trupel', 'jezioro-trupel', 'LAKE', 53.544362, 19.377308, 'Warmińsko-Mazurskie', 'Susz / Iława', 'Jezioro Trupel to rozległy akwen rynnowy (blisko 300 ha) położony w malowniczej rynnie polodowcowej. Charakteryzuje się dnem piaszczysto-mulistym i maksymalną głębokością sięgającą 8-10 metrów. Woda posiada średnią przejrzystość, co sprzyja rozwojowi bujnej roślinności zanurzonej. Przez jezioro przepływa rzeka Oska, co zapewnia stałe natlenienie i nanosi żyzne osady, tworząc bogatą bazę pokarmową.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81012, 'Jezioro Karaś', 'jezioro-karas', 'LAKE', 53.549742, 19.483438, 'Warmińsko-Mazurskie', 'Iława', 'Jezioro Karaś to unikatowy w skali kraju, rygorystycznie chroniony rezerwat przyrody (objęty konwencją ramsarską). Jest to akwen wybitnie eutroficzny, o zaawansowanym procesie zarastania. Głębokość średnia nie przekracza 0,8 m, a dno jest wyścielone kilkumetrową warstwą płynnego mułu torfowego. To ogromna "miska" wypełniona roślinnością miękką, stanowiąca ostoję dla ptactwa wodnego.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81013, 'Jezioro Dłużek (Susz)', 'jezioro-dluzek-susz', 'LAKE', 53.531942, 19.272122, 'Warmińsko-Mazurskie', 'Susz', 'Dłużek pod Suszem to klasyczna rynna polodowcowa, długa i wąska, wciśnięta w pofalowany krajobraz pól i kęp leśnych. Akwen charakteryzuje się twardym, piaszczystym dnem w strefie litoralu i wyraźnie zarysowaną rynną środkową (do 10 m). Woda posiada przyzwoitą klasę czystości, co sprzyja spinningowaniu. Brzegi są w większości wysokie i suche.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81014, 'Jezioro Goryńskie', 'jezioro-gorynskie', 'LAKE', 53.544337, 19.244313, 'Warmińsko-Mazurskie', 'Susz / Goryń', 'Jezioro Goryńskie to urokliwy, śródleśny zbiornik o charakterze rynnowym. Posiada bardzo regularną batymetrię i twarde piaszczyste podłoże. Maksymalna głębokość oscyluje wokół 8-10 metrów. Jezioro otoczone jest pięknym starodrzewem, co zapewnia doskonałą osłonę przed wiatrem i nadaje wodzie leśny mikroklimat. Roślinność wodna jest tu umiarkowana, ograniczona do wąskiego pasa trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81015, 'Jezioro Małe (Goryń)', 'jezioro-male-goryn', 'LAKE', 53.560552, 19.271607, 'Warmińsko-Mazurskie', 'Susz / Goryń', 'Jezioro Małe to kameralny, płytki akwen (max 3-4 m) o charakterze eutroficznym, położony niedaleko Gorynia. Dno jest muliste, bogate w bentos, z licznymi skupiskami grążeli żółtych. Akwen jest zaciszny, co sprzyja rozwojowi narybku i czyni go idealnym miejscem dla ryb ciepłolubnych. Brzegi są niskie, silnie zarośnięte trzciną i tatarakiem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81016, 'Zakrzowski Staw', 'zakrzowski-staw', 'LAKE', 51.43224, 17.474914, 'Dolnośląskie', 'Krośnice', 'Staw położony najbliżej zabudowań, co ułatwia dostęp. Jest to zbiornik wielogatunkowy – od płoci po sumy. Dno jest urozmaicone naniesionym piaskiem w okolicach grobli.', 'PZW Wrocław');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81017, 'Jezioro Gardęga', 'jezioro-gardega', 'LAKE', 53.605328, 19.203651, 'Warmińsko-Mazurskie', 'Gardzień / Susz', 'Jezioro Gardęga to specyficzny akwen rynnowo-przepływowy, stanowiący część systemu rzeki Gardęgi. Dzięki stałemu ruchowi wody, dno jest w wielu miejscach twardsze, piaszczysto-żwirowe. Akwen jest stosunkowo wąski i wydłużony, o głębokości do 6-8 metrów. Woda jest dobrze natleniona i żyzna. Brzegi są urozmaicone – od zalesionych skarp po piaszczyste dojścia przy miejscowościach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81018, 'Jezioro Łodygowo', 'jezioro-lodygowo', 'LAKE', 53.626063, 19.188008, 'Warmińsko-Mazurskie', 'Łodygowo / Kisielice', 'Jezioro Łodygowo to rozległy, rynnowy akwen o powierzchni ok. 150 ha. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 4-5 metrów. Woda posiada średnią przejrzystość (II klasa), co sprzyja rozwojowi bujnego litoralu. Jezioro jest otoczone wianuszkiem lasów i pól, co sprzyja dobremu natlenieniu wody przez wiatr.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81019, 'Jezioro Suskie', 'jezioro-suskie', 'LAKE', 53.708736, 19.339929, 'Warmińsko-Mazurskie', 'Susz', 'Jezioro Suskie to akwen miejski położony w samym sercu Susza. Jezioro przeszło gruntowną rewitalizację, co poprawiło natlenienie wody i stan rybostanu. Jest to zbiornik stosunkowo płytki (max 5-6 m), o dnie piaszczysto-mulistym. Brzegi są zagospodarowane – promenady, pomosty i oświetlone alejki ułatwiają wędkowanie nawet po zmroku. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81020, 'Jezioro Burgale', 'jezioro-burgale', 'LAKE', 53.747493, 19.292722, 'Warmińsko-Mazurskie', 'Susz / Emilianowo', 'Jezioro Burgale to małe, niezwykle ustronne "oczko" leśne o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym, co nadaje akwenowi dziki i ustronny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81021, 'Jezioro Gaudy', 'jezioro-gaudy', 'LAKE', 53.762564, 19.402628, 'Warmińsko-Mazurskie', 'Iława / Susz', 'Jezioro Gaudy to rozległy (blisko 150 ha), wybitnie płytki akwen rezerwatowy (rezerwat faunistyczny). Średnia głębokość to zaledwie 1,2 m. Jezioro jest w fazie silnego zarastania, z ogromnymi polami lilii wodnych i grążeli. Dno jest wybitnie muliste, torfowe, o ogromnej żyzności. To raj dla ptactwa wodno-błotnego i jedna z najważniejszych ostoi lina w regionie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81022, 'Jezioro Bądzkie', 'jezioro-badzkie', 'LAKE', 53.786315, 19.463085, 'Warmińsko-Mazurskie', 'Stary Dzierzgoń / Kamieniec', 'Jezioro Bądzkie to rynnowy akwen położony w pofałdowanym terenie rolniczo-leśnym. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 10-12 metrów. Jezioro posiada kilka wyraźnych przegłębień i dobrze natlenioną wodę dzięki otwartemu brzegowi wschodniemu. Brzegi są w większości dostępne, z rzadkim pasem trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81023, 'Jezioro Dzierzgoń', 'jezioro-dzierzgon', 'LAKE', 53.799485, 19.253111, 'Warmińsko-Mazurskie', 'Dzierzgoń / Prabuty', 'Jezioro Dzierzgoń to potężny akwen rynnowy (powierzchnia ponad 800 ha), jeden z największych w tej części Polski. Charakteryzuje się monumentalną batymetrią – dno jest bardzo urozmaicone, z licznymi wyspami (największa to Ostrów), głębokimi rynnami (do 15 m) i rozległymi piaszczystymi płyciznami. Woda posiada dobrą przejrzystość, choć jezioro jest wybitnie wietrzne, co generuje wysoką falę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81024, 'Staw Żabieniec Duży II', 'staw-zabieniec-duzy-2', 'LAKE', 51.506834, 17.120819, 'Dolnośląskie', 'Niezgoda', 'Środkowy zbiornik z grupy Żabieniec. Charakteryzuje się twardszymi brzegami wzdłuż grobli. Słynie z populacji amura, który utrzymuje roślinność miękką w ryzach. Woda ma odcień zielonkawy ze względu na bogaty fitoplankton.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81025, 'Jezioro Witoszewskie', 'jezioro-witoszewskie', 'LAKE', 53.820634, 19.498499, 'Warmińsko-Mazurskie', 'Zalewo / Witoszewo', 'Jezioro Witoszewskie to malowniczy akwen rynnowy stanowiący część systemu Kanału Elbląskiego. Charakteryzuje się twardym, piaszczysto-żwirowym dnem i głębokością sięgającą 12-14 metrów. Woda posiada dobrą przejrzystość (II klasa), co sprzyja bytowaniu drapieżników. Linia brzegowa jest urozmaicona, z licznymi powalonymi dębami i olchami wchodzącymi do wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81026, 'Jezioro Gębin', 'jezioro-gebin', 'LAKE', 53.830751, 19.470048, 'Warmińsko-Mazurskie', 'Zalewo', 'Jezioro Gębin to mniejszy, ustronny zbiornik o charakterze rynnowym, położony w pagórkowatym terenie leśno-polnym. Akwen cechuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 6-8 metrów. Jezioro jest wyciszone, co sprzyja aktywności ryb spokojnego żeru. Roślinność brzegowa jest umiarkowana, z przewagą rzadkich pasów trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81027, 'Jezioro Mołtawa Mała', 'jezioro-moltawa-mala', 'LAKE', 53.844476, 19.488502, 'Warmińsko-Mazurskie', 'Zalewo', 'Mołtawa Mała to kameralny akwen o charakterze eutroficznym, stanowiący część kaskady jezior Mołtawskich. Jezioro jest stosunkowo płytkie (max 3-4 m) z dnem wyścielonym grubą warstwą mułu i osadów organicznych. Woda nagrzewa się szybko, co sprzyja rozwojowi bujnego litoralu z dywanami grążeli żółtych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81028, 'Jezioro Mołtawa Wielka', 'jezioro-moltawa-wielka', 'LAKE', 53.852653, 19.497085, 'Warmińsko-Mazurskie', 'Zalewo', 'Jezioro Mołtawa Wielka to większy akwen w ciągu mołtawskim, o wyraźniejszym charakterze rynnowym. Dno jest piaszczysto-muliste, o głębokości sięgającej 8-10 metrów. Woda posiada przyzwoitą przejrzystość wiosną. Brzegi są urozmaicone – od zalesionych skarp po niskie, zarośnięte zatoki. Akwen jest dobrze natleniony przez wiatr, co sprzyja aktywności drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81029, 'Jezioro Ewingi', 'jezioro-ewingi', 'LAKE', 53.834119, 19.583945, 'Warmińsko-Mazurskie', 'Zalewo', 'Jezioro Ewingi to absolutna legenda sandaczowa regionu. Jest to potężny, wybitnie płytki akwen (ponad 500 ha, średnia głębokość ok. 2 m) o charakterze lagunowym, połączony z Jeziorakiem Kanałem Dobrzyckim. Dno jest skrajnie muliste, woda mętna i wysoce żyzna. Specyfika jeziora polega na ogromnej produkcji biomasy ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81030, 'Jezioro Rucewo Wielkie', 'jezioro-rucewo-wielkie', 'LAKE', 53.808811, 19.525623, 'Warmińsko-Mazurskie', 'Zalewo / Rucewo', 'Jezioro Rucewo Wielkie to rynnowy akwen położony w malowniczej, zalesionej dolinie. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem w strefie litoralu, które stromo opada w stronę rynny centralnej (max 15 m). Brzegi są wysokie, porośnięte majestatycznym lasem, co zapewnia ciszę i osłonę przed wiatrem. To klasyczne jezioro polodowcowe o surowym charakterze.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81031, 'Jezioro Rucewo Małe', 'jezioro-rucewo-male', 'LAKE', 53.794517, 19.545879, 'Warmińsko-Mazurskie', 'Rucewo', 'Rucewo Małe to kameralny zbiornik połączony z systemem jezior rynnowych regionu. Ma charakter bardziej eutroficzny, z dnem mulistym i bogatszą roślinnością brzegową. Maksymalna głębokość nie przekracza 5-6 metrów. Brzegi są niskie, porośnięte gęstą trzciną, co zapewnia rybom spokój i doskonałe warunki do tarła.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81032, 'Jezioro Płaskie', 'jezioro-plaskie', 'LAKE', 53.767333, 19.56223, 'Warmińsko-Mazurskie', 'Jerzwałd / Matyty', 'Jezioro Płaskie to w rzeczywistości ogromna, północna zatoka systemu Jezioraka, choć o odrębnym charakterze hydrologicznym. Jest to akwen rozległy i płytki (max 5-6 m), o bardzo urozmaiconym dnie z licznymi podwodnymi górkami i wyspami. Woda jest żyzna, o średniej przejrzystości. Brzegi są w większości porośnięte gęstym lasem i szerokim pasem trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81033, 'Jezioro Kawka', 'jezioro-kawka', 'LAKE', 53.743331, 19.481506, 'Warmińsko-Mazurskie', 'Januszewo / Susz', 'Jezioro Kawka to małe, śródleśne "oczko" o charakterze dystroficzno-eutroficznym, położone w głębi puszczy. Akwen charakteryzuje się miękkim dnem i lekko mroczną wodą o herbacianym odcieniu. Maksymalna głębokość nie przekracza 4-5 metrów. Jezioro jest wybitnie wyciszone i osłonięte od wiatrów gęstym borem sosnowym, co nadaje mu kameralny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81034, 'Jezioro Januszewskie', 'jezioro-januszewskie', 'LAKE', 53.729014, 19.485347, 'Warmińsko-Mazurskie', 'Januszewo', 'Jezioro Januszewskie to malowniczy zbiornik rynnowy (ok. 80 ha) położony niedaleko Susza. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem w wielu partiach. Batymetria jest bardzo urozmaicona z wyraźnie zaznaczoną rynną centralną (max 12 m). Brzegi są wysokie i suche, w dużej mierze zalesione, z licznymi pomostami i dzikimi plażami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81035, 'Jezioro Czerwica', 'jezioro-czerwica', 'LAKE', 53.727097, 19.517148, 'Warmińsko-Mazurskie', 'Januszewo', 'Jezioro Czerwica to rezerwatowy akwen o charakterze rynnowym (rezerwat kormoranów). Charakteryzuje się bardzo czystą wodą i twardym, polodowcowym dnem. Batymetria jest typowo rynnowa: strome spady uciekają szybko do rynny sięgającej ponad 15 metrów. Jezioro jest otoczone bezkresnym lasem, co nadaje mu surowy, pierwotny charakter. Wędkowanie podlega przepisom rezerwatu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81036, 'Jezioro Głębokie (Januszewo)', 'jezioro-glebokie-januszewo', 'LAKE', 53.719873, 19.513543, 'Warmińsko-Mazurskie', 'Januszewo', 'Jezioro Głębokie to mały, śródleśny zbiornik o charakterze rynnowym, położony w bezpośrednim sąsiedztwie Czerwicy. Akwen posiada twarde dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 10-12 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym. Roślinność wodna jest skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81037, 'Staw Żabieniec Duży III', 'staw-zabieniec-duzy-3', 'LAKE', 51.503896, 17.119982, 'Dolnośląskie', 'Niezgoda', 'Południowy staw kompleksu, graniczący z lasami. Najbardziej ustronny z całej grupy. Dno wyścielone grubą warstwą osadów torfowych. Ostoja dzikiego karpia i lina.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81038, 'Jezioro Karszanek', 'jezioro-karszanek', 'LAKE', 53.755614, 18.467631, 'Pomorskie', 'Osiek', 'Karszanek to popularne jezioro rekreacyjne z dobrze rozwiniętą linią brzegową. Posiada piaszczyste dno i przyzwoitą przejrzystość. Wędkarsko słynie z dużych stad płoci i leszcza, które dobrze reagują na nęcenie ziarnem.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81039, 'Jezioro Gubel', 'jezioro-gubel', 'LAKE', 54.054751, 18.105108, 'Pomorskie', 'Nowa Karczma / Huta Dolna', 'Gubel to niewielki, kameralny akwen o charakterze eutroficznym, położony w ustronnej dolinie. Posiada charakter rynnowy z miękkim dnem w osi głównej. Maksymalna głębokość nie przekracza 6 metrów. Jezioro jest osłonięte od wiatru przez naturalne ukształtowanie terenu, co sprzyja rozwojowi roślinności wodnej – grążeli i rdestnicy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81040, 'Jezioro Czerwica', 'jezioro-czerwica-2', 'LAKE', 53.727097, 19.517148, 'Warmińsko-Mazurskie', 'Januszewo / Susz', 'Jezioro Czerwica to rezerwatowy akwen o charakterze rynnowym, znany przede wszystkim z kolonii kormoranów. Charakteryzuje się bardzo czystą wodą i twardym, polodowcowym dnem. Batymetria jest typowo rynnowa: ostre spady zaczynają się blisko brzegu i schodzą w mrok sielawowych głębin sięgających ponad 15-20 metrów. Jezioro otoczone jest bezkresnym lasem, co nadaje mu surowy urok.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81041, 'Staw Brzozowy', 'staw-brzozowy-radziadz', 'LAKE', 51.592353, 17.216778, 'Dolnośląskie', 'Żmigród / Radziądz', 'Staw Brzozowy to malowniczy zbiornik hodowlany położony w kompleksie Radziądz. Charakteryzuje się obecnością licznych brzóz wzdłuż grobli (stąd nazwa). Dno jest muliste, typowe dla stawów karpiowych. Jest to ważne miejsce żerowania dla żurawi i bocianów czarnych.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81042, 'Jezioro Głębokie (Susz)', 'jezioro-glebokie-susz', 'LAKE', 53.719873, 19.513543, 'Warmińsko-Mazurskie', 'Susz / Januszewo', 'Głębokie koło Januszewa to mały, śródleśny zbiornik rynnowy, który swoją nazwę zawdzięcza gwałtownemu ukształtowaniu dna. Mimo niewielkiej powierzchni, akwen posiada wyraźnie zarysowaną rynnę centralną sięgającą 12-14 metrów. Woda jest bardzo czysta, o sielankowym charakterze, dobrze osłonięta od wiatru przez wysokie brzegi porośnięte buczyną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81043, 'Staw Duży Jaś', 'staw-duzy-jas', 'LAKE', 51.614712, 17.224224, 'Dolnośląskie', 'Radziądz', 'Jeden z większych stawów w północnej części kompleksu Radziądz. Charakteryzuje się otwartym lustrem wody i twardszym dnem w okolicach mnichów. To wyśmienite tarlisko dla szczupaka. Akwen jest monitorowany w ramach ochrony siedlisk ptaków rzadkich.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81044, 'Jezioro Piotrowskie', 'jezioro-piotrowskie', 'LAKE', 53.696516, 19.517319, 'Warmińsko-Mazurskie', 'Iława / Januszewo', 'Jezioro Piotrowskie to malowniczy zbiornik rynnowy o wydłużonym kształcie, położony w pagórkowatym terenie rolniczo-leśnym. Akwen charakteryzuje się twardym piaszczystym dnem w strefie litoralu i rynną środkową sięgającą 10 metrów. Woda posiada przyzwoitą klasę czystości, choć w lecie ulega naturalnym zakwitom. Brzegi są w większości dostępne, z rzadkim, ale twardym pasem trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81045, 'Jezioro Małe Piotrowskie', 'jezioro-male-piotrowskie', 'LAKE', 53.688105, 19.532425, 'Warmińsko-Mazurskie', 'Iława / Januszewo', 'Małe Piotrowskie to kameralny, płytki akwen (max 3-4 m) o charakterze eutroficznym, połączony ciekiem z jeziorem głównym. Dno jest muliste, bogate w bentos, z licznymi skupiskami grążeli żółtych. Brzegi są niskie, silnie zarośnięte, co zapewnia rybom doskonałe warunki do tarła ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81046, 'Jezioro Perkun', 'jezioro-perkun', 'LAKE', 53.709739, 19.542489, 'Warmińsko-Mazurskie', 'Jerzwałd / Iława', 'Jezioro Perkun to dziki, śródleśny akwen rynnowy o bardzo urozmaiconej rzeźbie dna. Charakteryzuje się czystą wodą i twardym, polodowcowym dnem z licznymi podwodnymi górkami. Centralna rynna osiąga głębokość ok. 12-14 metrów. Jezioro jest w całości otoczone gęstym lasem, co chroni je przed wiatrem i zapewnia ciszę. Brzegi są wysokie i strome, co ogranicza liczbę stanowisk brzegowych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81047, 'Jezioro Osa', 'jezioro-osa', 'LAKE', 53.701013, 19.559398, 'Warmińsko-Mazurskie', 'Iława / Ząbrowo', 'Jezioro Osa to specyficzny akwen rynnowo-przepływowy, przez który przepływa rzeka Osa. Dzięki stałemu ruchowi wody, dno jest w wielu miejscach twarde, piaszczysto-żwirowe. Akwen jest stosunkowo wąski i długi, o głębokości do 6-8 metrów. Woda jest dobrze natleniona i żyzna. Brzegi są urozmaicone, z licznymi powalonymi dębami i olchami wchodzącymi do wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81048, 'Jezioro Gardzień', 'jezioro-gardzien', 'LAKE', 53.675511, 19.554462, 'Warmińsko-Mazurskie', 'Gardzień / Iława', 'Jezioro Gardzień to rozległy (blisko 100 ha) akwen rynnowy położony w malowniczej dolinie. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 5 metrów. Woda posiada przyzwoitą przejrzystość, a linia brzegowa jest dobrze rozwinięta, z licznymi piaszczystymi plażami i wysepkami roślinności. Jezioro jest znane z doskonałych warunków do rozrodu ryb drapieżnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81049, 'Jezioro Stęgwica', 'jezioro-stegwica', 'LAKE', 53.644434, 19.537339, 'Warmińsko-Mazurskie', 'Iława', 'Jezioro Stęgwica to kameralny akwen o charakterze eutroficznym, położony na północny wschód od Iławy. Jezioro jest stosunkowo płytkie (max 5-6 m) z dnem w dużej mierze mulistym, bogatym w bentos. Linia brzegowa jest silnie porośnięta trzciną i tatarakiem, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych. Woda szybko się tu nagrzewa, co sprzyja intensywnym żerowaniom lina i karasia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81050, 'Jezioro Brzozowe', 'jezioro-brzozowe-radziadz', 'LAKE', 51.591005, 17.220426, 'Dolnośląskie', 'Żmigród / Radziądz', 'Niewielki akwen sąsiadujący ze Stawem Brzozowym, o bardziej naturalnym charakterze linii brzegowej. Posiada muliste dno i bogatą roślinność zanurzoną. Woda jest żyzna, co sprzyja szybkiej wegetacji lina i karasia złocistego.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81051, 'Jezioro Szymbarskie', 'jezioro-szymbarskie', 'LAKE', 53.627641, 19.499016, 'Warmińsko-Mazurskie', 'Szymbark / Iława', 'Jezioro Szymbarskie to jedna z najdłuższych i najwęższych rynien regionu, położona u stóp imponujących ruin zamku w Szymbarku. Akwen charakteryzuje się monumentalną batymetrią – strome, piaszczyste spady uciekają szybko do rynny sięgającej blisko 20-25 metrów. Woda posiada dobrą klasę czystości i jest dobrze natleniona. Brzegi są wysokie i w całości zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81052, 'Jezioro Kolmowo', 'jezioro-kolmowo', 'LAKE', 53.665646, 19.464297, 'Warmińsko-Mazurskie', 'Januszewo / Susz', 'Jezioro Kolmowo to mały, śródleśny zbiornik o charakterze rynnowym, położony w ustronnej części puszczy. Akwen posiada twarde dno i dobrą przejrzystość wody. Batymetria jest regularna – rynna o głębokości do 8-10 metrów biegnie przez środek jeziora. Brzegi są wysokie i zalesione, co nadaje akwenowi dziki i ustronny charakter. Roślinność wodna jest skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81053, 'Jezioro Łabędź', 'jezioro-labedz', 'LAKE', 53.625681, 19.623084, 'Warmińsko-Mazurskie', 'Iława', 'Jezioro Łabędź to jeden z najpopularniejszych akwenów wędkarskich w bezpośrednim sąsiedztwie Iławy. To rozległe jezioro rynnowe (ponad 300 ha) o bardzo urozmaiconym dnie, z licznymi podwodnymi górkami i blatami. Dno jest pofałdowane, piaszczysto-muliste, o maksymalnej głębokości ok. 10 metrów. Woda jest żyzna, co przekłada się na ogromną biomasę ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81054, 'Jezioro Iławskie', 'jezioro-ilawskie', 'LAKE', 53.591371, 19.602356, 'Warmińsko-Mazurskie', 'Iława', 'Jezioro Iławskie to mniejszy akwen rynnowy położony w południowej części Iławy. Charakteryzuje się dość wyrównanym dnem piaszczysto-mulistym i średnią głębokością ok. 4-5 metrów. Woda posiada dobrą klasę czystości. Jezioro jest połączone systemem cieków z rzeką Iławką, co sprzyja migracji ryb. Brzegi są w większości dostępne, z licznymi kładkami i pomostami od strony zabudowań.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81055, 'Jezioro Radomno', 'jezioro-radomno', 'LAKE', 53.520334, 19.561844, 'Warmińsko-Mazurskie', 'Radomno / Iława', 'Jezioro Radomno to majestatyczna rynna polodowcowa (ok. 110 ha) o nieskazitelnej czystości wody (I/II klasa). Akwen charakteryzuje się monumentalną batymetrią – dno opada stromo do rynny centralnej sięgającej ponad 25 metrów. Dno jest wybitnie twarde, piaszczysto-żwirowe, z nielicznymi podwodnymi górkami. To klasyczne jezioro sielawowe o chłodnej i doskonale natlenionej toni.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81056, 'Jezioro Zgniłek', 'jezioro-zgnilek', 'LAKE', 53.530347, 19.561222, 'Warmińsko-Mazurskie', 'Radomno / Iława', 'Jezioro Zgniłek to niewielki, kameralny akwen o charakterze dystroficzno-eutroficznym, położony w bezpośrednim sąsiedztwie dużego jeziora Radomno. Mimo nazwy, woda posiada przyzwoitą przejrzystość, choć dno jest wybitnie miękkie, wyścielone grubą warstwą mułu i osadów leśnych. Maksymalna głębokość nie przekracza 4 metrów. Jezioro jest w całości otoczone lasem, co zapewnia absolutną ciszę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81057, 'Jezioro Gryźliny', 'jezioro-gryzliny', 'LAKE', 53.499624, 19.523971, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Jezioro Gryźliny to malownicza rynna rynnowa o powierzchni ok. 45 ha, wcięta w pagórkowaty teren rolniczo-leśny. Akwen posiada twarde piaszczyste dno w strefie litoralu i wyraźnie zaznaczoną rynnę środkową o głębokości do 10-12 metrów. Woda jest dobrze natleniona i posiada dobrą klasę czystości. Brzegi są zróżnicowane – od wysokich zalesionych skarp po piaszczyste dojścia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81058, 'Jezioro Wierzbiny', 'jezioro-wierzbiny', 'LAKE', 53.752355, 18.454092, 'Pomorskie', 'Osiek / Wierzbiny', 'Wierzbiny to wydłużony akwen rynnowy stanowiący naturalne przedłużenie systemu wodnego Osieka. Woda jest czysta, a dno urozmaicone. To wyśmienite łowisko okoniowe i szczupakowe, szczególnie w okresach jesiennych.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81059, 'Jezioro Studa', 'jezioro-studa', 'LAKE', 53.502291, 19.505732, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Jezioro Studa to kameralny, śródleśny zbiornik o charakterze rynnowym, położony w ustronnej części regionu. Akwen cechuje się bardzo czystą wodą i twardym dnem piaszczysto-żwirowym. Batymetria jest regularna – rynna o głębokości do 8-10 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem, co zapewnia osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81060, 'Jezioro Lekarty', 'jezioro-lekarty', 'LAKE', 53.496369, 19.477172, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Jezioro Lekarty to jeden z najpiękniejszych akwenów rynnowych w powiecie nowomiejskim (blisko 100 ha). Charakteryzuje się krystalicznie czystą wodą i monumentalną batymetrią – strome, piaszczyste spady schodzą do rynny o głębokości ok. 20 metrów. Dno jest wybitnie twarde. Brzegi są wysokie, porośnięte starym lasem mieszanym, co nadaje akwenowi surowy, północny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81061, 'Jezioro Przedzieniec', 'jezioro-przedzieniec', 'LAKE', 53.483832, 19.459105, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Przedzieniec to mniejszy akwen rynnowy, silnie ulegający procesom eutrofizacji, stanowiący część systemu jezior skarlińskich. Dno jest piaszczysto-muliste, o średniej głębokości ok. 4-5 metrów. Woda jest żyzna, co sprzyja rozwojowi bujnego litoralu. Brzegi są w większości porośnięte trzciną, co tworzy doskonałe warunki ochronne dla ryb litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81062, 'Jezioro Kakaj', 'jezioro-kakaj', 'LAKE', 53.482396, 19.450039, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Jezioro Kakaj to niewielki, kameralny zbiornik położony w ustronnej dolinie. Posiada charakter rynnowy z miękkim dnem w osi głównej. Maksymalna głębokość nie przekracza 6 metrów. Jezioro jest osłonięte od wiatru przez naturalne ukształtowanie terenu, co sprzyja rozwojowi roślinności wodnej – grążeli i rdestnicy. Woda szybko się nagrzewa wiosną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81063, 'Jezioro Modzel', 'jezioro-modzel', 'LAKE', 53.478776, 19.442046, 'Warmińsko-Mazurskie', 'Nowe Miasto Lubawskie', 'Jezioro Modzel to typowe, śródpolne "oczko" o charakterze eutroficznym. Akwen charakteryzuje się mulistym dnem i umiarkowaną głębokością (max 5 m). Woda jest żyzna, co przekłada się na bogatą bazę pokarmową dla ryb karpiowatych. Linia brzegowa jest porośnięta trzciną i pałką wodną, co stwarza wyśmienite warunki dla lęgów ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81064, 'Jezioro Wieczorki', 'jezioro-wieczorki', 'LAKE', 53.469893, 19.461197, 'Warmińsko-Mazurskie', 'Skarlin / Nowe Miasto', 'Jezioro Wieczorki to malowniczy, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym, co nadaje akwenowi dziki charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81065, 'Jezioro Skarlińskie', 'jezioro-skarlinskie', 'LAKE', 53.457598, 19.487815, 'Warmińsko-Mazurskie', 'Skarlin / Nowe Miasto', 'Jezioro Skarlińskie to największa rynna polodowcowa w tym regionie (blisko 300 ha). Charakteryzuje się monumentalną batymetrią – dno jest bardzo urozmaicone, z licznymi głębokimi rynnami (do 15 m) i rozległymi piaszczystymi blatami. Woda posiada dobrą przejrzystość. Jezioro jest połączone systemem cieków z rzeką Skarlanką, co sprzyja migracji ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81066, 'Jezioro Osłonińskie', 'jezioro-osloninskie', 'LAKE', 51.944279, 16.222687, 'Wielkopolskie', 'Wieleń / Osłonin', 'Osłonińskie to rynnowe przedłużenie systemu jezior przemęckich. Charakteryzuje się dnem piaszczysto-mulistym i średnią głębokością ok. 4-5 metrów. Woda jest żyzna, co sprzyja rozwojowi bujnego litoralu. Brzegi są częściowo zagospodarowane letniskowo, z licznymi kładkami wędkarskimi od strony miejscowości Osłonin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81067, 'Stawy Łąkowe', 'stawy-lakowe', 'LAKE', 52.175616, 21.442384, 'Mazowieckie', 'Mińsk Mazowiecki / Marianka', 'Stawy Łąkowe to rozległy kompleks płytkich akwenów położonych wśród otwartych przestrzeni doliny Mieni. Charakteryzują się typowo produkcyjnym rodowodem – dno jest wyrównane, w większości muliste, z licznymi piaszczystymi łachami na groblach. Woda jest wybitnie żyzna, co sprzyja szybkiej wegetacji i ogromnej populacji narybku.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81068, 'Staw Gabrielin', 'staw-gabrielin', 'LAKE', 52.173872, 21.443532, 'Mazowieckie', 'Marianka / Mińsk Maz.', 'Staw Gabrielin to urokliwy, nieco bardziej wyciszony zbiornik w południowej części kompleksu. Akwen charakteryzuje się bogatszą roślinnością brzegową i obecnością starych olch przy groblach, co zapewnia cień i osłonę przed wiatrem. Dno jest wyścielone warstwą mułu i osadów organicznych. Maksymalna głębokość nie przekracza 1,5 metra.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81069, 'Staw Natolin Dolny', 'staw-natolin-dolny', 'LAKE', 52.175504, 21.450613, 'Mazowieckie', 'Mińsk Mazowiecki / Natolin', 'Natolin Dolny to jeden z kluczowych akwenów w kaskadzie rzeki Mieni. Zbiornik pełni funkcję osadnika, przez co dno w zachodniej części jest silnie zamulone, natomiast wschodnia część posiada twardsze, piaszczyste podłoże. Woda jest dobrze natleniona dzięki stałemu przepływowi. Brzegi są niskie, porośnięte trzciną, co stwarza doskonałe warunki dla lęgów szczupaka.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81070, 'Staw Marianka', 'staw-marianka', 'LAKE', 52.176294, 21.448252, 'Mazowieckie', 'Marianka / Mińsk Maz.', 'Staw Marianka to serce całego kompleksu, zbiornik o regularnym kształcie i bardzo dobrym dostępie do lustra wody wzdłuż twardych grobli. Dno jest pofałdowane, piaszczysto-muliste, z wyraźnie zaznaczonym starym korytem rzeki. Woda posiada przyzwoitą przejrzystość wiosną. Brzegi są wydeptane i oferują wiele wygodnych stanowisk rzutowych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81071, 'Staw Mienia', 'staw-mienia', 'LAKE', 52.177254, 21.445602, 'Mazowieckie', 'Marianka', 'Staw Mienia to specyficzny akwen rynnowo-przepływowy, bezpośrednio zasilany wodami rzeki o tej samej nazwie. Dzięki stałemu ruchowi wody, dno w osi głównej jest twardsze, w wielu miejscach wymyte do żwiru. Akwen jest stosunkowo wąski, o głębokości do 2 metrów przy mnichu. Brzegi są porośnięte starodrzewem, co zapewnia doskonałą osłonę przed słońcem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81072, 'Staw Krysin', 'staw-krysin', 'LAKE', 52.178958, 21.445849, 'Mazowieckie', 'Marianka', 'Staw Krysin to mniejszy, bardzo regularny zbiornik o charakterze hodowlano-wędkarskim. Akwen posiada dno piaszczysto-muliste i wyrównaną batymetrię (średnio 1,2 m). Woda szybko się tu nagrzewa, co sprzyja wczesnej aktywności ryb karpiowatych. Brzegi są wysokie i suche, uformowane w twarde groble, co ułatwia rzuty metodami odległościowymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81073, 'Staw Zofiówka', 'staw-zofiowka-marianka', 'LAKE', 52.179261, 21.449282, 'Mazowieckie', 'Marianka', 'Zofiówka to kameralny, wybitnie rybny akwen o charakterze eutroficznym, położony w północnej części kompleksu. Zbiornik jest stosunkowo płytki (max 1,2 m), z dnem wyścielonym osadami organicznymi i bogatą roślinnością zanurzoną. Jezioro jest osłonięte od wiatru przez pas drzew leśnych, co sprzyja aktywności lina i karasia złocistego.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81074, 'Staw Wydra', 'staw-wydra', 'LAKE', 52.17909, 21.452243, 'Mazowieckie', 'Natolin / Marianka', 'Staw Wydra to dziki akwen położony na skraju kompleksu, o mrocznej, lekko mętnej wodzie. Nazwa nawiązuje do dużej czystości biologicznej i obecności chronionych drapieżników. Dno jest wysoce muliste i bogate w bentos, co czyni go doskonałą stołówką dla ryb ryjących. Maksymalna głębokość oscyluje wokół 1,3 metra. Brzegi są silnie zarośnięte trzciną pospolitą.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81075, 'Stawy Kroczkowe', 'stawy-kroczkowe', 'LAKE', 52.179386, 21.454926, 'Mazowieckie', 'Natolin / Marianka', 'Stawy Kroczkowe to zespół mniejszych akwenów technicznych, pierwotnie służących do wychowu narybku (tzw. kroczków). Dziś pełnią funkcję wędkarską, oferując doskonałe warunki do połowu ryb białych. Dno jest piaszczysto-muliste, a głębokość rzadko przekracza 1 metr. Woda nagrzewa się błyskawicznie, co stymuluje ryby do bardzo intensywnego żerowania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81076, 'Jezioro Pisz', 'jezioro-pisz', 'LAKE', 53.816058, 20.762315, 'Warmińsko-Mazurskie', 'Barczewo / Kierzliny', 'Jezioro Pisz to jedna z najciekawszych rynien polodowcowych w gminie Barczewo (pow. ok. 200 ha). Akwen charakteryzuje się monumentalną batymetrią – dno opada stromo do centralnej rynny sięgającej blisko 25 metrów. Woda posiada wysoką klasę czystości i jest dobrze natleniona. Dno jest wybitnie twarde, piaszczysto-żwirowe, z licznymi podwodnymi górkami i uskokami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81077, 'Czarne Jezioro', 'czarne-jezioro-barczewo', 'LAKE', 53.821885, 20.752916, 'Warmińsko-Mazurskie', 'Barczewo / Kierzliny', 'Czarne Jezioro to mniejszy, ustronny zbiornik o charakterze rynnowym, położony w bezpośrednim sąsiedztwie jeziora Pisz. Akwen posiada twarde dno i mroczną, głęboką toń (max ok. 10 m). Brzegi są wysokie i porośnięte gęstym lasem mieszanym, co nadaje jezioru kameralny, intymny charakter. Roślinność wodna jest skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81078, 'Jezioro Orzycek', 'jezioro-orzycek', 'LAKE', 53.822012, 20.746136, 'Warmińsko-Mazurskie', 'Barczewo', 'Orzycek to kameralny, płytki akwen (max 4-5 m) o charakterze eutroficznym, stanowiący część systemu rzeki Pisy Warmińskiej. Dno jest piaszczysto-muliste, bogate w bentos. Linia brzegowa jest silnie porośnięta trzciną i pałką wodną, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych. Woda szybko się nagrzewa, co sprzyja intensywnym żerowaniom lina i karasia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81079, 'Jezioro Orzyc', 'jezioro-orzyc', 'LAKE', 53.824735, 20.737875, 'Warmińsko-Mazurskie', 'Barczewo / Zalesie', 'Jezioro Orzyc to rynnowy zbiornik o wydłużonym kształcie, połączony z jeziorem Orzycek. Charakteryzuje się bardziej urozmaiconym dnem i wyraźniejszą rynną środkową sięgającą 8 metrów. Woda posiada dobrą przejrzystość. Brzegi są urozmaicone – od wysokich zalesionych skarp po piaszczyste dojścia. Akwen jest dobrze natleniony dzięki przepływowi wody rzecznej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81080, 'Jezioro Dobrąg', 'jezioro-dobrag', 'LAKE', 53.839147, 20.782866, 'Warmińsko-Mazurskie', 'Barczewo / Dobrąg', 'Jezioro Dobrąg to malowniczy akwen rynnowy (blisko 100 ha) położony w rynnie barczewskiej. Charakteryzuje się twardym piaszczystym dnem w strefie litoralu i rynną środkową sięgającą 10-12 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są w większości wysokie i suche, w dużej mierze zalesione, z licznymi kładkami i pomostami od strony miejscowości Dobrąg.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81081, 'Jezioro Peszk', 'jezioro-peszk', 'LAKE', 53.841412, 20.765963, 'Warmińsko-Mazurskie', 'Barczewo / Dobrąg', 'Jezioro Peszk to niewielki, kameralny zbiornik rynnowy sąsiadujący z jeziorem Dobrąg. Akwen posiada twarde dno piaszczysto-żwirowe i przejrzystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są porośnięte lasem mieszanym, co zapewnia ciszę i osłonę przed wiatrem. Roślinność wodna jest tu umiarkowana.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81082, 'Jezioro Białe (Przemęckie)', 'jezioro-biale-przemet', 'LAKE', 51.935181, 16.221142, 'Wielkopolskie', 'Wieleń', 'Jezioro Białe to jeden z klejnotów Przemęckiego Parku Krajobrazowego. Słynie z piaszczystego, jasnego dna i krystalicznie czystej wody. Maksymalna głębokość sięga 10-12 metrów. Akwen charakteryzuje się sielawowym charakterem i bogatą roślinnością podwodną (łąki ramienicowe).
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81083, 'Jezioro Choszczko', 'jezioro-choszczko', 'LAKE', 53.774118, 20.87323, 'Warmińsko-Mazurskie', 'Biskupiec / Rasząg', 'Jezioro Choszczko to mały, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem, co zapewnia ciszę i osłonę przed wiatrem. Roślinność wodna jest tu umiarkowana.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81084, 'Jezioro Dadaj', 'jezioro-dadaj', 'LAKE', 53.870009, 20.862735, 'Warmińsko-Mazurskie', 'Biskupiec / Ramsowo', 'Jezioro Dadaj to monumentalny akwen rynnowy (powierzchnia ponad 1000 ha), największy w rejonie Biskupca. Charakteryzuje się niesamowicie rozwiniętą linią brzegową z licznymi półwyspami, 15 wyspami i zatokami. Dno jest wybitnie urozmaicone, z gwałtownymi uskokami, głębokimi rynnami (do 40 m) i rozległymi piaszczystymi blatami. Woda posiada dobrą przejrzystość.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81085, 'Jezioro Kraksy', 'jezioro-kraksy', 'LAKE', 53.848096, 20.945413, 'Warmińsko-Mazurskie', 'Biskupiec', 'Jezioro Kraksy to akwen miejski położony w Biskupcu. Jest to jezioro stosunkowo płytkie (max 5 m), o charakterze eutroficznym, z dnem piaszczysto-mulistym. Brzegi są w dużej mierze zagospodarowane – promenady, pomosty i oświetlone alejki ułatwiają wędkowanie. Woda jest żyzna, co przekłada się na bogatą biomasę ryb białych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81086, 'Jezioro Rzeckie', 'jezioro-rzeckie', 'LAKE', 53.818452, 20.910115, 'Warmińsko-Mazurskie', 'Biskupiec / Rzeck', 'Jezioro Rzeckie to malownicza rynna polodowcowa położona na południowy wschód od Biskupca. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem. Batymetria jest bardzo urozmaicona z wyraźnie zaznaczoną rynną centralną sięgającą 15 metrów. Brzegi są wysokie i suche, w dużej mierze zalesione, co zapewnia komfortowe warunki łowienia nawet przy silniejszym wietrze.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81087, 'Jezioro Hutowe', 'jezioro-hutowe', 'LAKE', 54.050204, 18.112468, 'Pomorskie', 'Nowa Karczma', 'Jezioro Hutowe to rynnowy akwen położony w pofałdowanym terenie leśno-polnym. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 10-12 metrów. Jezioro posiada kilka wyraźnych przegłębień i dobrze natlenioną wodę dzięki otwartemu brzegowi zachodniemu. Brzegi są w większości dostępne, z rzadkim pasem trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81088, 'Jezioro Pałaszkowskie', 'jezioro-palaszkowskie', 'LAKE', 54.047673, 18.164606, 'Pomorskie', 'Nowa Karczma / Pałubice', 'Pałaszkowskie to typowa rynna kaszubska o powierzchni ok. 35 ha. Akwen charakteryzuje się twardym dnem i głębokością sięgającą 12-14 metrów. Woda jest przejrzysta, o wysokiej klasie czystości. Brzegi są w większości wysokie i porośnięte lasem mieszanym, z wieloma dzikimi stanowiskami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81089, 'Jezioro Gębory Duże', 'jezioro-gebory-duze', 'LAKE', 53.802108, 20.899494, 'Warmińsko-Mazurskie', 'Biskupiec / Rasząg', 'Gębory Duże to klasyczny akwen rynnowy położony w pagórkowatym terenie leśnym. Charakteryzuje się twardym, piaszczysto-żwirowym dnem i wyraźnie zarysowaną rynną środkową sięgającą 10-12 metrów. Woda posiada dobrą przejrzystość, co sprzyja rozwojowi ramienic. Brzegi są wysokie, w dużej mierze zalesione, z licznymi powalonymi drzewami w litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81090, 'Jezioro Rasząg', 'jezioro-raszag', 'LAKE', 53.793376, 20.902863, 'Warmińsko-Mazurskie', 'Biskupiec / Rasząg', 'Jezioro Rasząg to rozległy akwen rynnowy (pow. ok. 150 ha) stanowiący serce lokalnego systemu hydrologicznego. Dno jest urozmaicone, piaszczysto-muliste, o maksymalnej głębokości ok. 8-10 metrów. Przez jezioro przepływa rzeka Wardęga, co zapewnia stałe natlenienie wody i bogatą bazę pokarmową. Brzegi są w większości dostępne, z licznymi pomostami od strony miejscowości Rasząg.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81091, 'Jezioro Gębory Małe', 'jezioro-gebory-male', 'LAKE', 53.79747, 20.895116, 'Warmińsko-Mazurskie', 'Biskupiec / Rasząg', 'Gębory Małe to kameralny, płytki akwen (max 3-4 m) o charakterze eutroficznym, sąsiadujący z Gęborami Dużymi. Dno jest w dużej mierze muliste, bogate w bentos. Linia brzegowa jest silnie porośnięta trzciną i tatarakiem, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych. Woda szybko się tu nagrzewa, co sprzyja intensywnym żerowaniom lina i karasia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81092, 'Jezioro Stawek', 'jezioro-stawek-biskupiec', 'LAKE', 53.768094, 20.894301, 'Warmińsko-Mazurskie', 'Biskupiec / Rasząg', 'Stawek to niewielki, śródpolny akwen o charakterze eutroficznym. Zbiornik jest stosunkowo płytki (max 3 m), z dnem wyścielonym osadami organicznymi i bogatą roślinnością zanurzoną. Jezioro jest osłonięte od wiatru przez naturalne ukształtowanie terenu, co sprzyja rozwojowi narybku. Woda szybko nagrzewa się wiosną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81093, 'Jezioro Pieczysko', 'jezioro-pieczysko', 'LAKE', 53.766065, 20.877693, 'Warmińsko-Mazurskie', 'Biskupiec / Rasząg', 'Jezioro Pieczysko to dziki, kameralny zbiornik położony w zagłębieniu terenu wśród pól i kęp lasów. Charakteryzuje się miękkim dnem i mroczną wodą o lekkim zabarwieniu humusowym. Maksymalna głębokość nie przekracza 4-5 metrów. Brzegi są niskie i częściowo podmokłe, co zapewnia rybom spokój i sprawia, że presja wędkarska jest tu minimalna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81094, 'Jezioro Wardąg', 'jezioro-wardag', 'LAKE', 53.754179, 20.839756, 'Warmińsko-Mazurskie', 'Biskupiec / Rasząg', 'Jezioro Wardąg to jedna z najczystszych rynien w regionie (I/II klasa czystości). Charakteryzuje się monumentalną batymetrią – strome, piaszczyste spady schodzą do rynny o głębokości blisko 15-18 metrów. Dno jest wybitnie twarde, piaszczysto-żwirowe. Brzegi są wysokie i w większości zalesione, co nadaje akwenowi surowy, północny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81095, 'Jezioro Sąpaty', 'jezioro-sapaty', 'LAKE', 53.726627, 20.8722, 'Warmińsko-Mazurskie', 'Dźwierzuty', 'Jezioro Sąpaty to malowniczy akwen rynnowy położony niedaleko Dźwierzut. Charakteryzuje się wydłużonym kształtem i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 8-10 metrów. Woda posiada dobrą przejrzystość. Jezioro jest otoczone wianuszkiem lasów i pól, co sprzyja dobremu natlenieniu wody. Brzegi są urozmaicone – od piaszczystych plaż po zarośnięte skarpy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81096, 'Jezioro Ruskie', 'jezioro-ruskie-pasym', 'LAKE', 53.711517, 20.844283, 'Warmińsko-Mazurskie', 'Pasym / Giławy', 'Jezioro Ruskie to czysta rynna polodowcowa o powierzchni ok. 50 ha, położona w bardzo urokliwym terenie. Akwen charakteryzuje się twardym dnem i głębokością sięgającą 12-14 metrów. Woda jest przejrzysta, o wysokiej klasie czystości. Brzegi są w większości wysokie i porośnięte lasem mieszanym, z wieloma dzikimi pomostami i kładkami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81097, 'Jezioro Kózka', 'jezioro-kozka', 'LAKE', 53.709079, 20.876212, 'Warmińsko-Mazurskie', 'Dźwierzuty / Giławy', 'Jezioro Kózka to niewielki, kameralny zbiornik rynnowy położony w ustronnej części regionu. Akwen cechuje się bardzo czystą wodą i twardym dnem piaszczysto-żwirowym. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są porośnięte lasem mieszanym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81098, 'Jezioro Małszewskie', 'jezioro-malszewskie', 'LAKE', 53.698383, 20.897884, 'Warmińsko-Mazurskie', 'Jedwabno / Małszewo', 'Jezioro Małszewskie to potężna rynna polodowcowa (powierzchnia ponad 200 ha). Charakteryzuje się monumentalną batymetrią – dno opada stromo do rynny centralnej sięgającej ponad 15-18 metrów. Woda posiada dobrą przejrzystość. Jezioro jest połączone systemem cieków z innymi akwenami rynnowymi, co sprzyja migracji ryb. Brzegi są zróżnicowane, z licznymi pomostami od strony miejscowości Małszewo.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81099, 'Jezioro Zagnanie', 'jezioro-zagnanie', 'LAKE', 54.064425, 18.031912, 'Pomorskie', 'Stężyca / Przywidz', 'Jezioro Zagnanie to głęboka rynna polodowcowa (pow. ok. 120 ha) charakteryzująca się krystaliczną wodą i twardym podłożem. Batymetria jest typowo kaszubska: strome spady, uskoki i centralna rynna sięgająca 20 metrów. Brzegi są w większości zalesione, co nadaje akwenowi dziki charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81100, 'Jezioro Gedajno', 'jezioro-gedajno', 'LAKE', 53.651913, 20.827503, 'Warmińsko-Mazurskie', 'Giławy / Pasym', 'Jezioro Gedajno to dziki, śródleśny akwen rynnowy o bardzo urozmaiconej rzeźbie dna. Charakteryzuje się czystą wodą i twardym, polodowcowym dnem z licznymi podwodnymi górkami. Centralna rynna osiąga głębokość ok. 10-12 metrów. Jezioro jest w całości otoczone gęstym lasem, co chroni je przed wiatrem i zapewnia absolutną ciszę. Brzegi są wysokie i strome, co ogranicza liczbę stanowisk brzegowych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81101, 'Jezioro Giławy', 'jezioro-gilawy', 'LAKE', 53.709993, 20.815272, 'Warmińsko-Mazurskie', 'Giławy / Purda', 'Jezioro Giławy to malownicza rynna o powierzchni ok. 50 ha, położona przy miejscowości o tej samej nazwie. Charakteryzuje się twardym piaszczystym dnem i wyraźnie zarysowaną rynną środkową o głębokości do 10 metrów. Woda jest czysta i dobrze natleniona. Brzegi są w większości dostępne, z licznymi piaszczystymi plażami i pomostami, co sprzyja rekreacji wędkarskiej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81102, 'Jezioro Sobąckie', 'jezioro-sobackie', 'LAKE', 54.064854, 18.176279, 'Pomorskie', 'Nowa Karczma / Sobącz', 'Jezioro Sobąckie to malownicza rynna rynnowa o powierzchni ok. 45 ha. Akwen posiada twarde piaszczyste dno w strefie litoralu i rynnę środkową sięgającą 10-12 metrów. Woda jest dobrze natleniona i posiada dobrą klasę czystości. Brzegi są zróżnicowane – od wysokich zalesionych skarp po piaszczyste dojścia przy miejscowości Sobącz.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81103, 'Jezioro Kark', 'jezioro-kark', 'LAKE', 53.733729, 20.839922, 'Warmińsko-Mazurskie', 'Giławy / Purda', 'Jezioro Kark to mały, śródleśny zbiornik o niemal okrągłym kształcie, położony w głębi puszczy. Akwen charakteryzuje się twardym dnem piaszczystym i bardzo czystą wodą. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym, co nadaje akwenowi dziki i ustronny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81104, 'Jezioro Dźwierzuty', 'jezioro-dzwierzuty', 'LAKE', 53.72697, 20.998414, 'Warmińsko-Mazurskie', 'Dźwierzuty', 'Jezioro Dźwierzuty to akwen rynnowy położony bezpośrednio przy miejscowości o tej samej nazwie. Zbiornik charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 4-6 metrów. Woda jest żyzna, co przekłada się na bogatą biomasę ryb karpiowatych. Brzegi są w dużej mierze zagospodarowane – promenady i pomosty ułatwiają dostęp do wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81105, 'Jezioro Karw', 'jezioro-karw', 'LAKE', 53.832435, 21.253309, 'Warmińsko-Mazurskie', 'Mrągowo', 'Jezioro Karw to malowniczy, rynnowy zbiornik położony na południowy zachód od Mrągowa. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem. Batymetria jest bardzo urozmaicona z wyraźnie zaznaczoną rynną centralną sięgającą 12-14 metrów. Brzegi są wysokie i suche, w dużej mierze zalesione, co zapewnia komfortowe warunki łowienia nawet przy silniejszym wietrze.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81106, 'Jezioro Zimny Kąt', 'jezioro-zimny-kat', 'LAKE', 54.065319, 21.667979, 'Warmińsko-Mazurskie', 'Giżycko / Doba', 'Zimny Kąt to w rzeczywistości głęboka, zachodnia zatoka jeziora Doba (część kompleksu Mamr). Jest to akwen o unikatowym charakterze – woda jest tu krystalicznie czysta, a dno usiane głazami narzutowymi, co jest rzadkością w tej części Mazur. Głębokość narasta gwałtownie do 10-12 metrów. Całość objęta jest strefą ciszy i rezerwatem, co czyni to miejsce jedną z najdzikszych enklaw w krainie Wielkich Jezior.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81107, 'Czarny Staw (Groszowice)', 'czarny-staw-opole', 'LAKE', 51.011757, 17.930675, 'Opolskie', 'Opole', 'Czarny Staw to popularne wyrobisko poeksploatacyjne położone w opolskich Groszowicach. Akwen charakteryzuje się bardzo twardym, piaszczysto-żwirowym dnem i czystą wodą. Głębokość jest zróżnicowana, z licznymi półkami i nagłymi uskokami sięgającymi 6-8 metrów. Brzegi są w większości dostępne i utwardzone.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81108, 'Jezioro Dziewiszewskie', 'jezioro-dziewiszewskie', 'LAKE', 54.064904, 21.619999, 'Warmińsko-Mazurskie', 'Giżycko / Dziewiszewo', 'Jezioro Dziewiszewskie to malownicza, wąska rynna polodowcowa, ukryta w pofałdowanym terenie na zachód od Giżycka. Akwen charakteryzuje się twardym dnem i wyraźnie zarysowaną rynną środkową sięgającą 15 metrów. Woda posiada wysoką klasę czystości. Brzegi są wysokie, częściowo zalesione, co zapewnia świetną osłonę przed wiatrem. Jezioro jest połączone systemem rowów z jeziorem Dobskim.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81109, 'Jezioro Mój', 'jezioro-moj', 'LAKE', 54.092196, 21.463852, 'Warmińsko-Mazurskie', 'Kętrzyn / Gierłoż', 'Jezioro Mój to akwen o ogromnym znaczeniu historycznym, położony w bezpośrednim sąsiedztwie Wilczego Szańca. Jest to jezioro rynnowe o powierzchni ok. 120 ha i maksymalnej głębokości ok. 8 metrów. Dno jest w przeważającej części muliste, z licznymi piaszczystymi wypłyceniami. Woda posiada średnią przejrzystość (II/III klasa), co sprzyja rozwojowi bujnej roślinności zanurzonej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81110, 'Jezioro Siercze', 'jezioro-siercze', 'LAKE', 54.076576, 21.469173, 'Warmińsko-Mazurskie', 'Kętrzyn / Gierłoż', 'Jezioro Siercze to mniejszy, wybitnie eutroficzny sąsiad jeziora Mój. Akwen jest stosunkowo płytki (max 3-4 m), z dnem wyścielonym grubą warstwą mułu i detrytusu. Całe jezioro jest silnie zarastające, z ogromnymi polami grążeli żółtych i lilii wodnych. To typowy matecznik dla ryb karpiowatych i doskonałe tarlisko dla okolicznych wód.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81111, 'Staw Halina', 'staw-halina', 'LAKE', 51.596629, 17.228537, 'Dolnośląskie', 'Żmigród / Radziądz', 'Staw Halina to zbiornik o charakterze produkcyjnym, wykorzystywany w cyklu hodowlanym karpia milickiego. Akwen posiada wyrównane dno i jest płytki (średnio 1,2 m). Szerokie trzcinowiska stanowią doskonałą osłonę przed wiatrem i bazę lęgową dla ptactwa wodnego.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81112, 'Jezioro Kwiedzińskie', 'jezioro-kwiedzinskie', 'LAKE', 54.066264, 21.450462, 'Warmińsko-Mazurskie', 'Kętrzyn / Kwiedzina', 'Kwiedzińskie to niewielki, kameralny akwen o charakterze wytopiskowym, położony w ustronnym terenie rolniczo-leśnym. Charakteryzuje się dnem piaszczysto-mulistym i umiarkowaną głębokością do 6 metrów. Jezioro jest zaciszne, osłonięte od wiatru, co sprzyja szybkiej wegetacji roślinności podwodnej. Woda posiada dobrą klasę czystości.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81113, 'Jezioro Górne (Kętrzyn)', 'jezioro-gorne-ketrzyn', 'LAKE', 54.079824, 21.377174, 'Warmińsko-Mazurskie', 'Kętrzyn', 'Jezioro Górne to akwen miejski położony w samym centrum Kętrzyna. Zbiornik przeszedł w ostatnich latach procesy rekultywacji, co znacznie poprawiło przejrzystość wody. Jest to jezioro płytkie (max 3-4 m) o dnie mulistym, silnie natleniane przez aeratory. Brzegi są w całości zagospodarowane – promenady, pomosty i oświetlone alejki sprzyjają wędkowaniu miejskiemu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81114, 'Jezioro Smokowo', 'jezioro-smokowo', 'LAKE', 54.061296, 21.320622, 'Warmińsko-Mazurskie', 'Kętrzyn / Smokowo', 'Jezioro Smokowo to urokliwy, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8-10 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym, co nadaje akwenowi dziki i ustronny charakter. Roślinność wodna jest skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81115, 'Polder Sątopy-Samulewo', 'polder-satopy-samulewo', 'LAKE', 54.088874, 21.056027, 'Warmińsko-Mazurskie', 'Bisztynek / Sątopy', 'Polder Sątopy-Samulewo to gigantyczny (ponad 1000 ha) obszar rozlewiskowy, będący jednym z najważniejszych siedlisk ptactwa wodnego w Polsce. Jest to akwen niesamowicie płytki (średnio 0,5-1 m), o charakterze wybitnie bagiennym. Dno jest wyścielone grubą warstwą mułu i osadów rzecznych. Woda jest żyzna i bardzo mętna. To unikatowy ekosystem, w którym poziomy wody dynamicznie się zmieniają.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81116, 'Jezioro Luterskie', 'jezioro-luterskie', 'LAKE', 53.991372, 20.851965, 'Warmińsko-Mazurskie', 'Kolno / Lutry', 'Jezioro Luterskie to potężna rynna polodowcowa (powierzchnia blisko 700 ha), jeden z najatrakcyjniejszych akwenów Warmii. Charakteryzuje się monumentalną batymetrią – dno opada stromo do rynny centralnej sięgającej blisko 20 metrów. Woda posiada dobrą przejrzystość. Jezioro jest wybitnie wietrzne, co generuje wysoką falę i zapewnia doskonałe natlenienie głębokich partii wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81117, 'Jezioro Bierdawy', 'jezioro-bierdawy', 'LAKE', 54.009711, 20.850806, 'Warmińsko-Mazurskie', 'Kolno / Lutry', 'Jezioro Bierdawy to malowniczy, rynnowy sąsiad jeziora Luterskiego, połączony z nim wąskim ciekiem. Charakteryzuje się mniejszą głębokością (max 6-8 m) i bardziej urozmaiconym dnem z licznymi podwodnymi górkami. Woda posiada przyzwoitą klasę czystości. Brzegi są w większości wysokie i porośnięte lasem mieszanym, co zapewnia osłonę przed wiatrem i nadaje jezioru kameralny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81118, 'Leśny Staw (Radziądz)', 'lesny-staw-radziadz', 'LAKE', 51.605305, 17.244759, 'Dolnośląskie', 'Radziądz / Żmigród', 'Zgodnie z nazwą, zbiornik ten jest niemal w całości ukryty w lesie. Charakteryzuje się dużą ilością osadów organicznych (liście, gałęzie) na dnie oraz mrocznym odcieniem wody. To typowa woda linowa, zapewniająca rybom absolutny spokój i cień w upalne dni.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81119, 'Jezioro Ławki', 'jezioro-lawki-2', 'LAKE', 53.972748, 20.78536, 'Warmińsko-Mazurskie', 'Biskupiec / Jeziorany', 'Jezioro Ławki to malowniczy zbiornik rynnowy położony w pofałdowanym terenie rolniczym. Charakteryzuje się dość regularną linią brzegową i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 8-10 metrów. Woda posiada przyzwoitą przejrzystość wiosną, jednak latem ulega naturalnym zakwitom. Brzegi są w większości dostępne, z rzadkim pasem trzcin i licznymi kładkami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81120, 'Jezioro Wójtowieckie', 'jezioro-wojtowieckie', 'LAKE', 53.98244, 20.725, 'Warmińsko-Mazurskie', 'Jeziorany / Wójtówko', 'Jezioro Wójtowieckie to kameralny akwen o charakterze rynnowym, połączony systemem rowów z sąsiednimi zbiornikami. Charakteryzuje się twardym dnem w strefie litoralu i wyraźnie zaznaczoną rynną środkową sięgającą 6-8 metrów. Woda jest czysta i dobrze natleniona. Brzegi są zróżnicowane – od zalesionych skarp po niskie, zarośnięte zatoki, co zapewnia rybom doskonałe schronienie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81121, 'Jezioro Pierścień', 'jezioro-pierscien', 'LAKE', 53.988395, 20.730987, 'Warmińsko-Mazurskie', 'Jeziorany / Wójtówko', 'Jezioro Pierścień to niewielki, niemal okrągły akwen o charakterze wytopiskowym, położony w ustronnym miejscu wśród pól. Dno jest piaszczysto-muliste, o wyrównanej batymetrii (max 5 m). Jezioro jest zaciszne, osłonięte od wiatru, co sprzyja szybkiej wegetacji roślinności wodnej – grążeli i rdestnicy. Woda szybko nagrzewa się wiosną, co stymuluje ryby do intensywnego żerowania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81122, 'Jezioro Kok', 'jezioro-kok', 'LAKE', 53.996456, 20.716653, 'Warmińsko-Mazurskie', 'Jeziorany', 'Jezioro Kok to mały, śródleśny zbiornik o charakterze rynnowym, położony w ustronnej dolinie. Akwen charakteryzuje się miękkim dnem i mroczną wodą o lekkim zabarwieniu humusowym. Maksymalna głębokość nie przekracza 5-6 metrów. Jezioro jest wybitnie wyciszone, co nadaje mu dziki charakter. Brzegi są niskie, silnie zarośnięte trzciną pospolitą i tatarakiem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81123, 'Jezioro Karpiowe', 'jezioro-karpiowe-jeziorany', 'LAKE', 53.99474, 20.707533, 'Warmińsko-Mazurskie', 'Jeziorany', 'Jezioro Karpiowe to kameralny, wybitnie rybny akwen o charakterze eutroficznym. Zbiornik jest stosunkowo płytki (max 3-4 m), z dnem wyścielonym osadami organicznymi i bogatą roślinnością zanurzoną. Nazwa nawiązuje do historycznych zarybień karpiem, jednak obecnie dominuje tu silna populacja lina i karasia srebrzystego. Jezioro szybko nagrzewa się wiosną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81124, 'Jezioro Blanki', 'jezioro-blanki', 'LAKE', 54.009005, 20.591683, 'Warmińsko-Mazurskie', 'Lidzbark Warmiński / Blanki', 'Jezioro Blanki to potężny (ponad 400 ha), wybitnie płytki akwen o charakterze eutroficznym. Średnia głębokość to zaledwie 5-6 m, co sprawia, że całe jezioro jest jedną wielką "stołówką" dla ryb. Dno jest muliste z rozległymi piaszczystymi blatami. Woda jest żyzna i często mętna (zakwity), co determinuje specyficzną taktykę połowu drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81125, 'Jezioro Symsar', 'jezioro-symsar', 'LAKE', 54.056415, 20.625587, 'Warmińsko-Mazurskie', 'Lidzbark Warmiński / Kłębowo', 'Jezioro Symsar to jedna z najpiękniejszych rynien polodowcowych na Warmii (ok. 150 ha). Charakteryzuje się urozmaiconą linią brzegową z dwoma wyspami i twardym piaszczysto-żwirowym dnem. Maksymalna głębokość sięga blisko 10 metrów. Woda posiada dobrą klasę czystości. Brzegi są wysokie, w dużej mierze zalesione, co zapewnia komfortowe warunki łowienia nawet przy silniejszym wietrze.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81126, 'Jezioro Linciusz', 'jezioro-linciusz', 'LAKE', 51.923635, 16.25968, 'Wielkopolskie', 'Brenno', 'Linciusz to niewielki, kameralny zbiornik o charakterze eutroficznym, położony wśród borów sosnowych. Akwen jest stosunkowo płytki (max 3-4 m) z dnem wyścielonym grubą warstwą mułu i osadów organicznych. Woda nagrzewa się szybko, co sprzyja aktywności ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81127, 'Rozlewisko Bartniki', 'rozlewisko-bartniki', 'LAKE', 54.078829, 20.748936, 'Warmińsko-Mazurskie', 'Bisztynek / Bartniki', 'Rozlewisko Bartniki to unikatowy, dynamiczny akwen powstały w wyniku spiętrzenia wód rzecznych na terenach torfowiskowych. Jest to obszar wybitnie płytki (średnio 0,5-1 m), o charakterze bagiennym. Dno jest wyścielone grubą warstwą mułu torfowego i resztek roślinnych. To raj dla ptactwa wodnego i jedna z najważniejszych ostoi lina w regionie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81128, 'Jezioro Dost', 'jezioro-dost', 'LAKE', 54.069034, 20.770254, 'Warmińsko-Mazurskie', 'Bisztynek / Jeziorany', 'Jezioro Dost to mały, dziki akwen położony w zagłębieniu terenu wśród pól i kęp lasów. Charakteryzuje się mroczną wodą i bardzo miękkim dnem. Maksymalna głębokość nie przekracza 4-5 metrów. Brzegi są niskie, silnie zarośnięte trzciną pospolitą, co zapewnia rybom absolutny spokój. Jezioro jest wybitnie wyciszone, stanowiąc jedną z ostatnich enklaw dzikości w tej części regionu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81129, 'Jezioro Kinkajmskie', 'jezioro-kinkajmskie', 'LAKE', 54.219745, 20.866964, 'Warmińsko-Mazurskie', 'Bartoszyce / Kinkajmy', 'Jezioro Kinkajmskie to malowniczy akwen rynnowy położony tuż pod Bartoszycami. Charakteryzuje się twardym, piaszczysto-żwirowym dnem i głębokością sięgającą 10-12 metrów. Woda posiada przyzwoitą klasę czystości, a linia brzegowa jest urozmaicona z licznymi pomostami i dogodnymi dojściami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81130, 'Jezioro Wielochowskie', 'jezioro-wielochowskie', 'LAKE', 54.158426, 20.552759, 'Warmińsko-Mazurskie', 'Lidzbark Warmiński', 'Wielochowskie to główne jezioro rekreacyjne dla mieszkańców Lidzbarka Warmińskiego. Jest to akwen o charakterze rynnowym z wyraźnie zarysowaną misą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 10 metrów. Mimo dużej presji turystycznej w sezonie letnim, jezioro utrzymuje stabilny rybostan dzięki regularnym zarybieniom.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81131, 'Pieszkowski Staw', 'pieszkowski-staw', 'LAKE', 54.224513, 20.50257, 'Warmińsko-Mazurskie', 'Górowo Iławeckie / Pieszkowo', 'Pieszkowski Staw to kameralny zbiornik poeksploatacyjny o bardzo urozmaiconej rzeźbie dna. Akwen posiada charakterystyczne dla glinianek i żwirowni twarde uskoki i piaszczyste półki podwodne. Woda nagrzewa się szybko, co sprzyja aktywności ryb karpiowatych. Brzegi są w większości porośnięte trawą i pojedynczymi krzewami, co ułatwia dostęp do litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81132, 'Jezioro Pierzchalskie', 'jezioro-pierzchalskie', 'LAKE', 54.258907, 19.844871, 'Warmińsko-Mazurskie', 'Elbląg / Braniewo', 'Jezioro Pierzchalskie to unikatowy zbiornik zaporowy na rzece Pasłęce, pełniący funkcję retencyjną dla elektrowni wodnej. Akwen ma kształt długiej, krętej rynny (pow. ok. 180 ha). Dno jest piaszczysto-muliste z licznymi pozostałościami starego koryta rzeki i zatopionymi drzewami.  Całość leży w granicach rezerwatu przyrody Ostoja Bobrów, co determinuje surowe zasady ochrony.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81133, 'Jezioro Raduńskie Dolne', 'jezioro-radunskie-dolne', 'LAKE', 54.284168, 18.032341, 'Pomorskie', 'Chmielno / Kartuzy', 'Jezioro Raduńskie Dolne to perła Kaszubskiego Parku Krajobrazowego. To potężna, monumentalna rynna polodowcowa (pow. ponad 700 ha) o nieskazitelnej czystości wody. Batymetria jest tu ekstremalna – dno opada stromo do centralnej rynny sięgającej blisko 35-40 metrów. Dno jest wybitnie twarde, piaszczysto-kamieniste.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81134, 'Jezioro Nierzostowo', 'jezioro-nierzostowo', 'LAKE', 52.281888, 18.014402, 'Pomorskie', 'Chmielno', 'Nierzostowo to niewielki, kameralny akwen rynnowy połączony systemem rowów z jeziorem Raduńskim Dolnym. Zbiornik charakteryzuje się czystą wodą i twardym dnem. Maksymalna głębokość nie przekracza 8-10 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez pagórkowaty teren i pasy lasu, co nadaje mu intymny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81135, 'Jezioro Łączyńskie', 'jezioro-laczynskie', 'LAKE', 54.272968, 18.009639, 'Pomorskie', 'Łączyńska Huta / Chmielno', 'Jezioro Łączyńskie to kolejna głęboka rynna w ciągu Kółka Raduńskiego. Akwen charakteryzuje się bardzo rozwiniętą linią brzegową i twardym podłożem. Batymetria jest urozmaicona z licznymi przegłębieniami sięgającymi blisko 20 metrów. Woda posiada wysoką klasę czystości. Brzegi są wysokie i suche, w dużej mierze zalesione, co stwarza niepowtarzalny klimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81136, 'Jezioro Boruckie', 'jezioro-boruckie', 'LAKE', 54.253492, 17.966895, 'Pomorskie', 'Borucino / Stężyca', 'Boruckie to malowniczy zbiornik rynnowy o wydłużonym kształcie, położony w sercu Szwajcarii Kaszubskiej. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 10-12 metrów. Jezioro jest otoczone wianuszkiem lasów i pól, co sprzyja dobremu natlenieniu wody. Brzegi są w większości dostępne, z wieloma dzikimi plażami i pomostami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81137, 'Jezioro Szewinko', 'jezioro-szewinko', 'LAKE', 54.244641, 17.946553, 'Pomorskie', 'Stężyca', 'Jezioro Szewinko to mały, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym, co nadaje akwenowi dziki charakter. Roślinność wodna jest skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81138, 'Jezioro Raduńskie Górne', 'jezioro-radunskie-gorne', 'LAKE', 54.23037, 17.966895, 'Pomorskie', 'Stężyca / Borucino', 'Jezioro Raduńskie Górne to monumentalna rynna polodowcowa (pow. ok. 380 ha), południowy filar słynnego Kółka Raduńskiego. Charakteryzuje się potężnymi głębokościami sięgającymi blisko 45 metrów. Woda posiada nieskazitelną krystaliczność (I klasa). Dno jest wybitnie twarde, piaszczysto-żwirowe ze stromymi spadkami.  Brzegi są wysokie i w dużej mierze zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81139, 'Jezioro Przywidzkie', 'jezioro-przywidz', 'LAKE', 54.068656, 18.066437, 'Pomorskie', 'Przywidz', 'Jezioro Przywidzkie to serce turystyczne regionu, rozległy zbiornik rynnowy z malowniczą Wyspą Miłości. Akwen posiada urozmaicone dno, od piaszczystych blatów po głębokie doły rynnowe (do 12 m). Woda posiada przyzwoitą klasę czystości. Brzegi są częściowo zagospodarowane, z licznymi pomostami i bazami żeglarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81140, 'Jezioro Stężyckie', 'jezioro-stezyckie', 'LAKE', 54.195663, 17.947068, 'Pomorskie', 'Stężyca', 'Jezioro Stężyckie to rynnowy akwen położony bezpośrednio przy miejscowości Stężyca. Zbiornik charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 5-7 metrów. Woda jest dobrze natleniona. Brzegi są w dużej mierze zagospodarowane – promenady, pomosty i oświetlone alejki ułatwiają dostęp do litoralu. Jezioro jest połączone z systemem Raduni.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81141, 'Jezioro Długie (Stężyckie)', 'jezioro-dlugie-stezyca', 'LAKE', 54.173576, 17.987323, 'Pomorskie', 'Stężyca / Kościerzyna', 'Jezioro Długie to klasyczna kaszubska rynna o bardzo wydłużonym kształcie. Akwen charakteryzuje się czystą wodą i twardym, piaszczysto-żwirowym dnem. Batymetria jest typowo polodowcowa: strome spady zaczynają się blisko brzegu i schodzą do rynny sięgającej 15-18 metrów. Jezioro jest otoczone malowniczymi pagórkami i lasami sosnowymi, co zapewnia osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81142, 'Jezioro Kaliska', 'jezioro-kaliska', 'LAKE', 54.155951, 18.051481, 'Pomorskie', 'Kościerzyna', 'Jezioro Kaliska to urokliwy akwen położony na obrzeżach Kościerzyny. Charakteryzuje się urozmaiconym ukształtowaniem dna z licznymi przegłębieniami i piaszczystymi blatami. Maksymalna głębokość oscyluje wokół 8-10 metrów. Woda posiada dobrą klasę czystości. Brzegi są w większości wysokie i suche, w dużej mierze porośnięte lasem mieszanym, co nadaje jezioru kameralny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81143, 'Jezioro Kikity', 'jezioro-kikity', 'LAKE', 53.967524, 20.851171, 'Warmińsko-Mazurskie', 'Bisztynek / Kikity', 'Jezioro Kikity to malowniczy akwen rynnowy (ok. 60 ha) otoczony lasami. Posiada twarde dno i wodę o I klasie czystości. Maksymalna głębokość sięga 15 metrów. Linia brzegowa jest urozmaicona, z licznymi zatokami porośniętymi grążelem żółtym i rdestnicą, co tworzy idealne warunki dla drapieżników litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81144, 'Jezioro Dobrogoszcz', 'jezioro-dobrogoszcz', 'LAKE', 54.145515, 18.034543, 'Pomorskie', 'Kościerzyna / Dobrogoszcz', 'Jezioro Dobrogoszcz to jeden z najczystszych i najbardziej urokliwych akwenów w rejonie Kościerzyny. Posiada twarde, piaszczyste dno i wodę o wysokiej przejrzystości (I/II klasa). Maksymalna głębokość sięga ok. 6-7 metrów. Jezioro charakteryzuje się bardzo rozwiniętą roślinnością podwodną, co stwarza idealne warunki do rozrodu ryb spokojnego żeru i drapieżników litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81145, 'Jezioro Puc', 'jezioro-puc', 'LAKE', 54.14133, 18.073918, 'Pomorskie', 'Kościerzyna / Puc', 'Jezioro Puc to kameralny, śródleśny zbiornik o charakterze rynnowym. Akwen cechuje się twardym dnem piaszczysto-żwirowym w strefie przybrzeżnej i rynną o głębokości do 9 metrów. Woda jest czysta i dobrze natleniona. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym, co zapewnia ciszę i niepowtarzalny mikroklimat. Roślinność wodna jest tu umiarkowana.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81146, 'Jezioro Grabowskie', 'jezioro-grabowskie', 'LAKE', 54.154807, 18.159006, 'Pomorskie', 'Grabowo Kościerskie', 'Jezioro Grabowskie to duży i głęboki akwen rynnowy (pow. blisko 130 ha) położony w rynnie kościerskiej. Charakteryzuje się monumentalną batymetrią – dno opada stromo do rynny sięgającej ponad 20-25 metrów. Woda posiada wysoką klasę czystości. Dno jest wybitnie twarde, piaszczysto-kamieniste. Jezioro jest połączone systemem cieków z innymi jeziorami rynnowymi, co sprzyja migracji sandacza.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81147, 'Jezioro Barkocińskie', 'jezioro-barkocinskie', 'LAKE', 54.106037, 18.135831, 'Pomorskie', 'Barkoczyn / Kościerzyna', 'Jezioro Barkocińskie to przepiękny akwen rynnowy o bardzo urozmaiconej linii brzegowej, położony w otulinie lasów. Charakteryzuje się czystą wodą i dnem piaszczysto-żwirowym z licznymi przegłębieniami sięgającymi 15 metrów. Brzegi są wysokie, porośnięte starodrzewem, co zapewnia osłonę przed wiatrem i intymną atmosferę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81148, 'Jezioro Piaseczno', 'jezioro-piaseczno-pomorskie', 'LAKE', 54.043793, 18.202972, 'Pomorskie', 'Liniewo / Piaseczno', 'Piaseczno to jeden z najczystszych i najbardziej urokliwych akwenów w rejonie Liniewa. Posiada twarde, piaszczyste dno (stąd nazwa) i wodę o wysokiej przejrzystości (I klasa). Maksymalna głębokość sięga ok. 10-12 metrów. Jezioro charakteryzuje się bardzo rozwiniętą roślinnością podwodną, w tym rozległymi łąkami ramienicowymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81149, 'Jezioro Duże (Piaseczno)', 'jezioro-duze-piaseczno', 'LAKE', 54.042709, 18.216276, 'Pomorskie', 'Liniewo', 'Jezioro Duże to bezpośredni sąsiad Piaseczna, o większej powierzchni i bardziej urozmaiconym dnie. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 10-12 metrów. Jezioro posiada kilka wyraźnych przegłębień i dobrze natlenioną wodę. Brzegi są w większości dostępne, z wieloma pomostami turystycznymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81150, 'Jezioro Garczyn', 'jezioro-garczyn', 'LAKE', 54.052901, 18.241253, 'Pomorskie', 'Liniewo / Garczyn', 'Jezioro Garczyn to rozległa (ok. 100 ha) rynna polodowcowa, znana przede wszystkim z ośrodka wypoczynkowego. Charakteryzuje się twardym dnem i głębokością sięgającą blisko 15 metrów. Woda posiada dobrą klasę czystości i jest dobrze natleniona. Brzegi są wysokie i porośnięte lasem mieszanym, z licznymi pomostami i dzikimi plażami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81151, 'Jezioro Garczonki', 'jezioro-garczonki', 'LAKE', 54.059275, 18.251681, 'Pomorskie', 'Liniewo / Garczyn', 'Garczonki to mniejszy, ustronny zbiornik o charakterze rynnowym, położony w bezpośrednim sąsiedztwie jeziora Garczyn. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są porośnięte lasem mieszanym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81152, 'Jezioro Przybroda', 'jezioro-przybroda', 'LAKE', 54.063493, 18.259106, 'Pomorskie', 'Liniewo', 'Jezioro Przybroda to kameralny zbiornik rynnowy ukryty wśród kaszubskich wzgórz. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 6-8 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez pas lasu, co nadaje mu intymny charakter. Roślinność wodna jest umiarkowana, z przewagą rzadkich pasów trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81153, 'Jezioro Brzęczek', 'jezioro-brzeczek', 'LAKE', 54.04281, 18.315325, 'Pomorskie', 'Nowa Karczma', 'Jezioro Brzęczek to niewielki, kameralny zbiornik o charakterze eutroficznym, położony w pagórkowatym terenie wśród pól i kęp lasów. Dno jest w dużej mierze muliste, bogate w bentos. Linia brzegowa jest silnie porośnięta trzciną i tatarakiem, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych. Woda szybko się nagrzewa, co sprzyja intensywnym żerowaniom lina i karasia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81154, 'Jezioro Deka', 'jezioro-deka', 'LAKE', 54.059312, 18.321955, 'Pomorskie', 'Nowa Karczma / Liniewo', 'Jezioro Deka to malowniczy zbiornik rynnowy o wydłużonym kształcie, położony w otulinie leśnej. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem w strefie przybrzeżnej. Maksymalna głębokość sięga ok. 10-12 metrów. Jezioro posiada kilka wyraźnych przegłębień i dobrze natlenioną wodę. Brzegi są wysokie, w dużej mierze zalesione, co zapewnia osłonę przed wiatrem i nadaje jezioru kameralny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81155, 'Jezioro Łąkie', 'jezioro-lakie-skarszewy', 'LAKE', 54.064904, 18.322985, 'Pomorskie', 'Skarszewy / Nowa Karczma', 'Jezioro Łąkie to malowniczy zbiornik rynnowy położony w pagórkowatym terenie pogranicza Kaszub i Kociewia. Akwen charakteryzuje się czystą wodą i twardym, piaszczystym dnem w strefie litoralu. Maksymalna głębokość sięga 10-12 metrów. Brzegi są zróżnicowane – od wysokich, zalesionych skarp po piaszczyste dojścia leśne.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81156, 'Jezioro Gobrowo', 'jezioro-gobrowo', 'LAKE', 54.073705, 18.333499, 'Pomorskie', 'Skarszewy', 'Gobrowo to kameralny, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde dno i dobrą przejrzystość wody. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte starym lasem mieszanym, co zapewnia ciszę i osłonę przed wiatrem. Roślinność wodna jest umiarkowana.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81157, 'Jezioro Starowieckie', 'jezioro-starowieckie', 'LAKE', 54.109987, 18.319273, 'Pomorskie', 'Skarszewy', 'Jezioro Starowieckie (zwane też Skarszewskim) to główny akwen rekreacyjny Skarszew. Jest to typowa rynna polodowcowa o powierzchni ok. 50 ha. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 5 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są częściowo zagospodarowane, z licznymi pomostami i plażami miejskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81158, 'Jezioro Bronisława', 'jezioro-bronislawa', 'LAKE', 54.146174, 18.430874, 'Pomorskie', 'Skarszewy / Więckowy', 'Bronisława to mniejszy akwen rynnowy, silnie ulegający procesom eutrofizacji. Dno jest piaszczysto-muliste, o średniej głębokości ok. 4-5 metrów. Woda jest żyzna, co sprzyja rozwojowi bujnego litoralu. Brzegi są w większości porośnięte trzciną i olchami, co tworzy doskonałe warunki ochronne dla ryb spokojnego żeru i lęgów szczupaka.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81159, 'Jezioro Mały Mergiel', 'jezioro-maly-mergiel', 'LAKE', 54.072308, 18.521748, 'Pomorskie', 'Skarszewy / Godziszewo', 'Mały Mergiel to kameralny, płytki akwen (max 3-4 m) o charakterze eutroficznym, położony w sąsiedztwie dużego jeziora Godziszewskiego. Dno jest muliste, bogate w bentos, z licznymi skupiskami grążeli żółtych. Brzegi są niskie, silnie zarośnięte, co zapewnia rybom doskonałe warunki do tarła.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81160, 'Jezioro Godziszewskie', 'jezioro-godziszewskie', 'LAKE', 54.076941, 18.537498, 'Pomorskie', 'Skarszewy / Godziszewo', 'Jezioro Godziszewskie to jedna z największych i najpopularniejszych rynien kociewskich (pow. blisko 170 ha). Charakteryzuje się monumentalną batymetrią – dno opada stromo do rynny sięgającej blisko 15 metrów. Woda posiada dobrą klasę czystości i jest dobrze natleniona. Dno jest wybitnie twarde, piaszczysto-żwirowe. Brzegi są zróżnicowane, z licznymi pomostami i bazami turystycznymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81161, 'Jezioro Damaszka', 'jezioro-damaszka', 'LAKE', 54.093253, 18.611054, 'Pomorskie', 'Tczew / Turze', 'Jezioro Damaszka to malowniczy akwen rynnowy położony w sercu Kociewia. Charakteryzuje się twardym dnem i głębokością sięgającą 10-12 metrów. Woda jest przejrzysta, o wysokiej klasie czystości. Brzegi są w większości wysokie i porośnięte lasem mieszanym, z wieloma piaszczystymi plażami i pomostami, co sprzyja rekreacji wędkarskiej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81162, 'Jezioro Rokickie Duże', 'jezioro-rokickie-duze', 'LAKE', 54.067385, 18.706284, 'Pomorskie', 'Tczew / Rokitki', 'Jezioro Rokickie Duże to akwen o charakterze eutroficznym, położony w bezpośrednim sąsiedztwie Tczewa. Jezioro jest stosunkowo płytkie (max 5-6 m) z dnem w dużej mierze mulistym, bogatym w bentos. Linia brzegowa jest silnie porośnięta trzciną i tatarakiem, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych. Woda szybko się nagrzewa, co sprzyja intensywnym żerowaniom lina i karasia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81163, 'Jezioro Szpęgawskie', 'jezioro-szpegawskie', 'LAKE', 54.011501, 18.609638, 'Pomorskie', 'Starogard Gdański / Szpęgawsk', 'Jezioro Szpęgawskie to malownicza rynna o powierzchni ok. 30 ha, położona w zalesionej dolinie. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 4-6 metrów. Woda posiada przyzwoitą przejrzystość. Jezioro jest otoczone majestatycznym lasem sosnowo-bukowym, co zapewnia ciszę i osłonę przed wiatrem. Brzegi są wysokie i suche.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81164, 'Jezioro Rywałdzkie', 'jezioro-rywaldzkie', 'LAKE', 53.994791, 18.599832, 'Pomorskie', 'Starogard Gdański / Rywałd', 'Jezioro Rywałdzkie to urokliwy zbiornik rynnowy położony niedaleko Starogardu Gdańskiego. Charakteryzuje się wydłużonym kształtem i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 8-10 metrów. Woda posiada dobrą przejrzystość wiosną. Brzegi są urozmaicone – od piaszczystych plaż po zarośnięte skarpy, co zapewnia rybom doskonałe schronienie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81165, 'Jezioro Jabłowskie', 'jezioro-jablowskie', 'LAKE', 53.929007, 18.573718, 'Pomorskie', 'Starogard Gdański / Jabłowo', 'Jezioro Jabłowskie to rynnowy zbiornik położony w pagórkowatym terenie rolniczo-leśnym. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem w strefie litoralu. Batymetria jest bardzo urozmaicona z wyraźnie zaznaczoną rynną centralną sięgającą 12-14 metrów. Brzegi są wysokie i suche, w dużej mierze zalesione, z licznymi pomostami i kładkami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81166, 'Jezioro Płaczewo', 'jezioro-placzewo', 'LAKE', 53.902334, 18.497779, 'Pomorskie', 'Starogard Gdański / Płaczewo', 'Jezioro Płaczewo to jeden z najczystszych akwenów Kociewia (I klasa czystości). Posiada twarde, piaszczyste dno i wodę o niesamowitej przejrzystości. Maksymalna głębokość sięga ok. 15-18 metrów. Jezioro charakteryzuje się bardzo rozwiniętą roślinnością podwodną, w tym rozległymi łąkami ramienicowymi, co czyni je unikatowym siedliskiem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81167, 'Jezioro Sumińskie', 'jezioro-suminskie', 'LAKE', 53.908484, 18.434629, 'Pomorskie', 'Starogard Gdański / Sumowo', 'Jezioro Sumińskie to malowniczy, rynnowy zbiornik położony w otulinie leśnej. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem. Batymetria jest bardzo urozmaicona z wyraźnie zaznaczoną rynną centralną sięgającą 12-14 metrów. Brzegi są wysokie i porośnięte majestatycznym lasem sosnowym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81168, 'Jezioro Borzechowskie Wielkie', 'jezioro-borzechowskie-wielkie', 'LAKE', 53.897891, 18.392873, 'Pomorskie', 'Zblewo / Borzechowo', 'Jezioro Borzechowskie Wielkie to perła Kociewia i jeden z najczystszych akwenów w Polsce (I klasa czystości). Jest to potężna rynna polodowcowa o monumentalnej batymetrii – głębokość maksymalna sięga ponad 40 metrów. Woda posiada nieskażoną krystaliczność, co pozwala obserwować dno na głębokości kilku metrów. Dno jest wybitnie twarde, piaszczysto-kamieniste ze stromymi spadkami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81169, 'Jezioro Szteklin', 'jezioro-szteklin', 'LAKE', 53.891948, 18.405361, 'Pomorskie', 'Zblewo / Szteklin', 'Jezioro Szteklin to rynnowy sąsiad jeziora Borzechowskiego, połączony z nim wąskim przesmykiem. Akwen charakteryzuje się również wysoką klasą czystości i twardym podłożem. Maksymalna głębokość oscyluje wokół 15-18 metrów. Jezioro posiada bardzo rozwiniętą linię brzegową z licznymi półwyspami i zatokami, co stwarza wędkarzom wiele opcji wyboru stanowiska.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81170, 'Jezioro Borzechowskie Małe', 'jezioro-borzechowskie-male', 'LAKE', 53.882981, 18.347812, 'Pomorskie', 'Borzechowo / Starogard Gd.', 'Jezioro Borzechowskie Małe to bezpośredni sąsiad "Wielkiego Borzechowskiego", połączony z nim wąskim ciekiem leśnym. Akwen charakteryzuje się niesamowitą wręcz czystością wody (I klasa) i twardym, piaszczystym dnem. Batymetria jest urozmaicona – dno opada do rynny o głębokości ok. 10-12 metrów. Brzegi są wysokie, w całości zalesione dorodnym borem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81171, 'Staw Haneczka', 'staw-haneczka', 'LAKE', 51.622653, 17.220984, 'Dolnośląskie', 'Radziądz / Jutrosin', 'Staw Haneczka to kameralny zbiornik położony na skraju kompleksu leśnego. Posiada urozmaiconą linię brzegową z licznymi kępami tataraku. Dno jest wysoce zamulone, bogate w naturalny pokarm dla ryb karpiowatych.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81172, 'Jezioro Ostrowite (k. Zblewa)', 'jezioro-ostrowite-zblewo', 'LAKE', 53.878453, 18.274105, 'Pomorskie', 'Zblewo / Borzechowo', 'Ostrowite to jedna z najpiękniejszych rynien polodowcowych Kociewia (pow. ok. 100 ha). Charakteryzuje się monumentalną batymetrią – strome spady zaczynają się blisko brzegu i schodzą do rynny sięgającej 25 metrów. Woda posiada wysoką klasę czystości. Jezioro słynie z dużej wyspy, wokół której znajdują się najciekawsze uskoki dna. Dno jest wybitnie twarde, piaszczysto-żwirowe.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81173, 'Jezioro Niedackie', 'jezioro-niedackie', 'LAKE', 53.895564, 18.293781, 'Pomorskie', 'Zblewo / Twardy Dół', 'Jezioro Niedackie to hydrologiczny unikat – akwen o charakterze lobeliowym, co przekłada się na niespotykaną przejrzystość wody (widoczność do kilku metrów). Jest to głęboka rynna (max blisko 30 m) o bardzo stromych stokach. Jezioro położone jest w głębokiej niecce leśnej, co chroni je przed wiatrem i stwarza niepowtarzalny mikroklimat. Dno jest twarde, piaszczyste.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81174, 'Jezioro Trzechowskie', 'jezioro-trzechowskie', 'LAKE', 53.873127, 18.237476, 'Pomorskie', 'Zblewo / Iwiczno', 'Jezioro Trzechowskie to malowniczy akwen rynnowy położony w otulinie leśnej. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 5-7 metrów (max do 12 m). Woda posiada przyzwoitą klasę czystości. Brzegi są urozmaicone, z licznymi pomostami i dzikimi plażami, co sprzyja rekreacji wędkarskiej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81175, 'Jezioro Gogolinek', 'jezioro-gogolinek', 'LAKE', 53.858513, 18.233936, 'Pomorskie', 'Lubichowo / Iwiczno', 'Gogolinek to mniejszy, ustronny zbiornik o charakterze rynnowym, położony w sercu kociewskich lasów. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8-10 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem sosnowym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81176, 'Jezioro Lubickie', 'jezioro-lubickie', 'LAKE', 53.84802, 18.176107, 'Pomorskie', 'Lubichowo / Lubińskie', 'Jezioro Lubickie to rozległy (blisko 100 ha) akwen rynnowo-przepływowy, stanowiący część systemu rzeki Wdy (choć połączenie jest okresowe). Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 4-6 metrów. Woda jest żyzna, co przekłada się na bogatą biomasę ryb. Brzegi są w większości dostępne, z licznymi pomostami od strony miejscowości letniskowych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81177, 'Jezioro Szarmach', 'jezioro-szarmach', 'LAKE', 53.840374, 18.175163, 'Pomorskie', 'Lubichowo', 'Jezioro Szarmach to kameralny, śródleśny zbiornik o charakterze eutroficznym. Zbiornik jest stosunkowo płytki (max 4-5 m), z dnem wyścielonym osadami organicznymi i bogatą roślinnością zanurzoną. Jezioro jest wybitnie wyciszone, osłonięte od wiatru przez wysokie skarpy porośnięte borami, co nadaje mu intymny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81178, 'Jezioro Kłanińskie', 'jezioro-klaninskie', 'LAKE', 53.825368, 18.204989, 'Pomorskie', 'Lubichowo / Kłaniny', 'Jezioro Kłanińskie to malowniczy akwen rynnowy położony w głębi kompleksu leśnego. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem w strefie przybrzeżnej. Maksymalna głębokość sięga 10-12 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są wysokie i w całości zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81179, 'Jezioro Żabno', 'jezioro-zabno-kociewie', 'LAKE', 53.822138, 18.201739, 'Pomorskie', 'Lubichowo / Kłaniny', 'Jezioro Żabno to niewielki, kameralny akwen o charakterze eutroficznym, położony w bezpośrednim sąsiedztwie jeziora Kłanińskiego. Dno jest w dużej mierze muliste, bogate w bentos. Linia brzegowa jest silnie porośnięta trzciną i tatarakiem, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych. Woda szybko się nagrzewa wiosną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81180, 'Jezioro Płocicz', 'jezioro-plocicz-lubichowo', 'LAKE', 53.819662, 18.201427, 'Pomorskie', 'Lubichowo', 'Płocicz to małe, niezwykle urokliwe "oczko" leśne o charakterze dystroficzno-eutroficznym. Akwen charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i miękkim dnem wyścielonym osadami leśnymi. Maksymalna głębokość nie przekracza 4 metrów. Jezioro jest w całości otoczone lasem, co zapewnia absolutną ciszę i ochronę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81181, 'Jezioro Starzyskie', 'jezioro-starzyskie', 'LAKE', 53.78591, 18.162031, 'Pomorskie', 'Lubichowo / Starogard Gd.', 'Jezioro Starzyskie to klasyczna rynna kociewska o powierzchni ok. 40 ha, ukryta wśród lasów i pól. Charakteryzuje się bardzo czystą wodą i twardym dnem piaszczysto-żwirowym. Maksymalna głębokość sięga 14-16 metrów, a stoki opadają gwałtownie, co jest typowe dla jezior polodowcowych tego regionu. Linia brzegowa jest urozmaicona z wieloma powalonymi dębami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81182, 'Jezioro Tuczno', 'jezioro-tuczno-kociewie', 'LAKE', 53.811941, 18.195677, 'Pomorskie', 'Lubichowo / Kłaniny', 'Jezioro Tuczno to malowniczy akwen rynnowy o wydłużonym kształcie, otoczony majestatycznymi borami sosnowymi. Akwen charakteryzuje się czystą wodą i wyraźnie zarysowaną rynną środkową o głębokości do 15 metrów. Dno jest w przeważającej mierze twarde, z nielicznymi partiami mulistymi w głębokich dołach. Jezioro jest dobrze natlenione i osłonięte od silnych wiatrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81183, 'Jezioro Okoniówek', 'jezioro-okoniowek', 'LAKE', 53.815342, 18.198863, 'Pomorskie', 'Lubichowo / Kłaniny', 'Okoniówek to kameralne, śródleśne "oczko" o charakterze eutroficznym, położone w bezpośrednim sąsiedztwie jeziora Tuczno. Akwen jest stosunkowo płytki (max 4-5 m) z dnem wyścielonym grubą warstwą mułu i detrytusu leśnego. Woda posiada lekkie zabarwienie humusowe, a brzegi są niskie i silnie zarośnięte trzciną oraz grążelem żółtym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81184, 'Jezioro Długie (Osieczna)', 'jezioro-dlugie-osieczna', 'LAKE', 53.748305, 18.077145, 'Pomorskie', 'Osieczna / Bory Tucholskie', 'Jezioro Długie to monumentalna rynna polodowcowa położona w samym sercu Borów Tucholskich (pow. ok. 80 ha). Akwen charakteryzuje się ekstremalnie wydłużonym kształtem i bardzo stromymi stokami. Głębokość narasta błyskawicznie do 20-22 metrów. Woda posiada wysoką klasę czystości i sielawowy charakter. Dno jest wybitnie twarde, piaszczysto-żwirowe.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81185, 'Jezioro Ślepe', 'jezioro-slepe-bory', 'LAKE', 53.737505, 18.053584, 'Pomorskie', 'Osieczna / Szlachta', 'Jezioro Ślepe to ustronny, dziki akwen o charakterze dystroficzno-eutroficznym, ukryty głęboko w borach. Jezioro nie posiada odpływu (stąd nazwa), co sprawia, że woda posiada mroczny, herbaciany odcień. Dno jest bardzo miękkie i bogate w bentos. Maksymalna głębokość oscyluje wokół 5-6 metrów. Brzegi są niskie, bagniste, porośnięte mchem torfowcem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81186, 'Jezioro Karsińskie', 'jezioro-karsinskie', 'LAKE', 53.839209, 17.512808, 'Pomorskie', 'Chojnice / Swornegacie', 'Jezioro Karsińskie to potężny akwen rynnowo-przepływowy (pow. blisko 680 ha), przez który przepływa rzeka Brda. Akwen charakteryzuje się monumentalną skalą i bardzo urozmaiconym dnem z licznymi wyspami (m.in. Wyspa Miłości) i głębokimi rynnami sięgającymi 27 metrów. Woda posiada dobrą klasę czystości i jest doskonale natleniona przez nurt Brdy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81187, 'Jezioro Dusalis (Dusa)', 'jezioro-dusalis', 'LAKE', 54.140669, 23.427873, 'Podlaskie', 'Sejny / Sztabinki', 'Jezioro Dusalis (lokalnie zwane Dusa) to mały, śródleśny zbiornik o charakterze rynnowym, położony w głębi kompleksu puszczańskiego. Akwen posiada twarde dno i bardzo czystą wodę. Batymetria jest gwałtowna – rynna o głębokości do 10 metrów zaczyna się blisko brzegu. Jezioro jest wybitnie wyciszone, stanowiąc oazę dzikości. Roślinność wodna jest skąpa.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81188, 'Jezioro Mieruńskie Wielkie', 'jezioro-mierunskie-wielkie', 'LAKE', 54.178286, 22.549138, 'Podlaskie', 'Filipów / Mieruniszki', 'Mieruńskie Wielkie to potężna rynna polodowcowa na styku Mazur Garbatych i Suwalszczyzny (pow. ok. 190 ha). Akwen charakteryzuje się monumentalną głębokością sięgającą blisko 25 metrów. Woda posiada pierwszą klasę czystości. Dno jest wybitnie twarde, piaszczysto-żwirowe, z licznymi podwodnymi górkami, które są "magnesem" dla drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81189, 'Jezioro Długie (k. Filipowa)', 'jezioro-dlugie-filipow', 'LAKE', 54.156227, 22.623532, 'Podlaskie', 'Filipów', 'Jezioro Długie to klasyczny przykład suwalskiej rynny: wąskie, bardzo długie i głębokie (do 20 m). Woda jest krystalicznie czysta i chłodna nawet w upalne lata. Dno opada bardzo stromo – metr od trzcin głębokość może wynosić już 5 metrów. Brzegi są wysokie i suche, w większości porośnięte lasem i łąkami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81190, 'Jezioro Zusno', 'jezioro-zusno', 'LAKE', 54.210498, 22.721465, 'Podlaskie', 'Jeleniewo / Sidory', 'Zusno to malownicze, ustronne jezioro położone w sercu Suwalskiego Parku Krajobrazowego. Akwen charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 10-12 metrów. Jezioro otoczone jest pagórkowatym terenem, co zapewnia osłonę przed wiatrem i tworzy unikatowy mikroklimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81191, 'Jezioro Okminek', 'jezioro-okminek', 'LAKE', 54.166504, 22.801437, 'Podlaskie', 'Jeleniewo / Sidory', 'Jezioro Okminek to jeden z najbardziej fascynujących akwenów regionu. Mimo niewielkiej powierzchni, jest to jezioro wybitnie głębokie (powyżej 20 m) o niespotykanej przejrzystości wody. Widoczność w głąb sięga często 5-7 metrów. Dno jest wybitnie twarde, usiane głazami narzutowymi, co nadaje mu surowy, niemal górski charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81192, 'Jezioro Sumowo (Rutka-Tartak)', 'jezioro-sumowo-rutka', 'LAKE', 54.257403, 22.936728, 'Podlaskie', 'Rutka-Tartak', 'Jezioro Sumowo to jedna z najpiękniejszych rynien w dorzeczu Szeszupy (pow. ok. 90 ha). Akwen posiada wydłużony kształt i głębokość sięgającą 12-14 metrów. Dno jest urozmaicone, piaszczysto-muliste, z wyraźnie zaznaczonym nurtem przepływowej Szeszupy. Brzegi są wysokie, porośnięte lasem i częściowo zabudowane infrastrukturą turystyczną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81193, 'Jezioro Okrągłe (Rutka-Tartak)', 'jezioro-okragle-rutka', 'LAKE', 54.266277, 22.905593, 'Podlaskie', 'Rutka-Tartak', 'Okrągłe to mniejszy, rynnowo-przepływowy sąsiad jeziora Sumowo. Charakteryzuje się bardziej regularnym kształtem i dnem piaszczysto-żwirowym. Maksymalna głębokość oscyluje wokół 8-10 metrów. Woda jest czysta i bardzo dobrze natleniona. Brzegi są w większości dostępne, z licznymi stanowiskami wędkarskimi i kładkami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81194, 'Jezioro Szeszupa', 'jezioro-szeszupa', 'LAKE', 54.271737, 22.918071, 'Podlaskie', 'Rutka-Tartak / Udziejek', 'Jezioro Szeszupa (często utożsamiane z rozlewiskiem rzeki o tej samej nazwie) to akwen o wybitnie przepływowym charakterze. Jest stosunkowo płytkie (max 3-5 m), o dnie twardym w osi nurtu i mulistym w zatokach. Woda jest wysoce żyzna i bardzo dobrze natleniona, co sprzyja ogromnej biomasie ryb. Brzegi są porośnięte gęstą trzciną i tatarakiem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81195, 'Jezioro Przechodnie', 'jezioro-przechodnie', 'LAKE', 54.278581, 22.925849, 'Podlaskie', 'Rutka-Tartak', 'Jezioro Przechodnie to malownicza rynna w ciągu jezior Rutki-Tartak. Akwen charakteryzuje się czystą wodą i twardym podłożem. Batymetria jest urozmaicona z licznymi przegłębieniami sięgającymi 10 metrów. Jezioro jest osłonięte od wiatru przez wysokie skarpy i pasy drzew, co nadaje mu kameralny charakter. Roślinność wodna jest umiarkowana.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81196, 'Jezioro Jałowo (k. Szypliszek)', 'jezioro-jalowo-szypliszki', 'LAKE', 54.267179, 22.958508, 'Podlaskie', 'Szypliszki / Rutka-Tartak', 'Jałowo to majestatyczna rynna polodowcowa (pow. ok. 150 ha) o bardzo czystej wodzie i twardym dnie. Akwen charakteryzuje się monumentalną batymetrią – strome, piaszczyste spady schodzą do rynny o głębokości ok. 25-30 metrów. Brzegi są wysokie i w dużej mierze zalesione, co nadaje akwenowi surowy, północny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81197, 'Jezioro Grauże', 'jezioro-grauze', 'LAKE', 54.205403, 23.06895, 'Podlaskie', 'Szypliszki / Grauże Stare', 'Jezioro Grauże to jedna z najpiękniejszych rynien suwalskich, ukryta wśród pagórkowatego terenu. Charakteryzuje się krystalicznie czystą wodą i twardym piaszczysto-żwirowym dnem. Batymetria jest typowo rynnowa: ostre spady zaczynają się blisko brzegu i schodzą do centralnej rynny o głębokości ok. 20 metrów. Jezioro jest otoczone malowniczymi lasami i polami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81198, 'Jezioro Kaletnik', 'jezioro-kaletnik', 'LAKE', 54.17178, 23.085172, 'Podlaskie', 'Szypliszki / Kaletnik', 'Jezioro Kaletnik to klasyczna rynna suwalska o powierzchni ok. 50 ha. Akwen charakteryzuje się twardym, piaszczysto-kamienistym dnem i głębokością sięgającą 18-20 metrów. Woda posiada wysoką klasę czystości. Jezioro otoczone jest pagórkowatym terenem, a linia brzegowa jest urozmaicona z wyraźnymi spadkami tuż przy pasie trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81199, 'Jezioro Białe (Sejneńskie)', 'jezioro-biale-sejnenskie', 'LAKE', 54.125419, 23.28372, 'Podlaskie', 'Sejny', 'Jezioro Białe to jeden z najgłębszych i najczystszych akwenów w rejonie Sejn (pow. ok. 140 ha). Posiada monumentalną batymetrię – dno opada stromo do rynny sięgającej blisko 30-35 metrów. Woda charakteryzuje się niesamowitą przejrzystością (I klasa), co nadaje dnu jasny, niemal biały odcień (stąd nazwa). Dno jest wybitnie twarde, krasowe.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81200, 'Jezioro Sejny (Sejne)', 'jezioro-sejny', 'LAKE', 54.124161, 23.333824, 'Podlaskie', 'Sejny', 'Jezioro Sejny (często zwane Sejneńskim) to akwen miejski położony bezpośrednio przy Sejnach. Jest to jezioro rynnowe o średniej głębokości ok. 4-5 metrów (max do 10 m). Woda posiada przyzwoitą klasę czystości, a dno jest piaszczysto-muliste. Brzegi są w dużej mierze zagospodarowane – promenady i pomosty miejskie ułatwiają dostęp do litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81201, 'Jezioro Marycha', 'jezioro-marycha', 'LAKE', 54.118678, 23.328663, 'Podlaskie', 'Sejny', 'Jezioro Marycha to akwen rynnowo-przepływowy, przez który przepływa rzeka Marycha. Dzięki stałemu ruchowi wody, dno w osi nurtu jest twardsze, piaszczysto-żwirowe. Akwen jest stosunkowo wąski i długi, o głębokości do 6-8 metrów. Woda jest dobrze natleniona i żyzna. Brzegi są porośnięte trzciną i pasem olszyn.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81202, 'Jezioro Sztabinki', 'jezioro-sztabinki', 'LAKE', 54.126311, 23.419204, 'Podlaskie', 'Sejny / Sztabinki', 'Jezioro Sztabinki to jedna z najpiękniejszych i najbardziej ustronnych rynien w pobliżu granicy polsko-litewskiej. Akwen charakteryzuje się krystalicznie czystą wodą i twardym, piaszczystym dnem. Batymetria jest bardzo urozmaicona z rynną sięgającą 15 metrów. Jezioro otoczone jest majestatycznym lasem mieszanym i pagórkami, co nadaje mu surowy, pierwotny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81203, 'Jezioro Rejslic (Rejsle)', 'jezioro-rejslic', 'LAKE', 54.132573, 23.398261, 'Podlaskie', 'Sejny / Krasnowo', 'Rejslic to kameralne jezioro rynnowe położone w ustronnej dolinie. Charakteryzuje się dość regularną linią brzegową i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 8-10 metrów. Woda posiada wysoką klasę czystości. Jezioro jest wyciszone, osłonięte od wiatru przez pasy lasu i pagórki, co sprzyja rozwojowi bujnej roślinności zanurzonej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81204, 'Jezioro Tarnakowskie (Tarnau)', 'jezioro-tarnakowskie', 'LAKE', 54.178801, 23.443923, 'Podlaskie', 'Szypliszki / Tarnau', 'Jezioro Tarnakowskie to malownicza rynna położona w bezpośrednim sąsiedztwie granicy państwa. Akwen charakteryzuje się czystą wodą i twardym piaszczysto-żwirowym dnem. Maksymalna głębokość sięga 12-14 metrów. Brzegi są wysokie i w dużej mierze zalesione, co zapewnia ciszę i osłonę przed wiatrem. Roślinność brzegowa jest umiarkowana, z przewagą rzadkich pasów trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81205, 'Jezioro Czarne (Wiżajny)', 'jezioro-czarne-wizajny', 'LAKE', 54.291658, 22.893233, 'Podlaskie', 'Wiżajny', 'Jezioro Czarne to malowniczy, głęboki zbiornik rynnowy położony na "polskim biegunie zimna". Akwen charakteryzuje się mrocznym odcieniem wody, co wynika z głębokości (do 15-18 m) i osłonięcia brzegów wysokimi skarpami. Dno jest twarde, piaszczysto-żwirowe, z wyraźnie zarysowanymi spadkami, które zaczynają się niemal od samej linii trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81206, 'Jezioro Białe (Wiżajny)', 'jezioro-biale-wizajny', 'LAKE', 54.294163, 22.897975, 'Podlaskie', 'Wiżajny', 'Jezioro Białe sąsiaduje z jeziorem Czarnym, tworząc unikatowy duet akwenów o skrajnie różnej optyce wody. Jak sama nazwa wskazuje, jezioro posiada bardzo jasne, piaszczysto-kredowe dno, co nadaje wodzie niesamowitą przejrzystość. Jest to rynna o głębokości do 20 metrów, z bardzo stromymi brzegami porośniętymi lasem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81207, 'Jezioro Ostrówek', 'jezioro-ostrowek', 'LAKE', 54.31039, 22.411079, 'Podlaskie / Warmińsko-Mazurskie', 'Gołdap / Filipów', 'Jezioro Ostrówek to kameralny, ale wybitnie głęboki akwen rynnowy położony w dzikim zakątku pogranicza. Posiada twarde, kamieniste dno i bardzo czystą wodę. Batymetria jest gwałtowna – rynna o głębokości do 12 metrów wcina się w pofałdowany teren. Brzegi są wysokie i w całości zalesione, co sprawia, że woda jest niemal zawsze lustrzanie spokojna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81208, 'Jezioro Arklickie', 'jezioro-arklickie', 'LAKE', 54.28993, 21.351457, 'Warmińsko-Mazurskie', 'Barciany / Mołtajny', 'Jezioro Arklickie to rozległy (blisko 60 ha), wybitnie płytki akwen o charakterze eutroficznym, położony tuż przy granicy z Obwodem Królewieckim. Średnia głębokość nie przekracza 1,5 metra. Dno jest wysoce muliste i bogate w bentos. Jezioro jest silnie zarastające, z ogromnymi polami lilii wodnych i grążeli, co czyni je idealnym biotopem dla ryb ciepłolubnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81209, 'Jezioro Kinkajmskie', 'jezioro-kinkajmskie-2', 'LAKE', 54.217449, 20.873551, 'Warmińsko-Mazurskie', 'Bartoszyce', 'Jezioro Kinkajmskie to rynnowy akwen położony w bezpośrednim sąsiedztwie Bartoszyc. Charakteryzuje się dość regularnym kształtem i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 10-12 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są częściowo zagospodarowane, z licznymi pomostami i plażami miejskimi, co sprzyja rekreacji wędkarskiej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81210, 'Jezioro Wyręba', 'jezioro-wyreba', 'LAKE', 54.228439, 20.677643, 'Warmińsko-Mazurskie', 'Bartoszyce / Sępopol', 'Wyręba to mniejszy, ustronny zbiornik o charakterze rynnowym, położony wśród pól i kęp lasów. Akwen cechuje się twardym dnem w strefie przybrzeżnej i rynną o głębokości do 8 metrów. Woda jest dobrze natleniona i żyzna. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin, co ułatwia dostęp do lustra wody z brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81211, 'Chłopski Staw', 'chlopski-staw', 'LAKE', 54.280704, 20.5223, 'Warmińsko-Mazurskie', 'Górowo Iławeckie', 'Chłopski Staw to kameralny, wybitnie rybny akwen o charakterze eutroficznym, położony na obrzeżach Górowa Iławeckiego. Zbiornik jest stosunkowo płytki (max 3 m), z dnem wyścielonym osadami organicznymi i bogatą roślinnością zanurzoną. Woda szybko nagrzewa się wiosną, co stymuluje ryby do bardzo intensywnego żerowania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81212, 'Staw Garncarski', 'staw-garncarski', 'LAKE', 54.285696, 20.495371, 'Warmińsko-Mazurskie', 'Górowo Iławeckie', 'Staw Garncarski to urokliwy, zrewitalizowany akwen miejski położony w samym sercu Górowa Iławeckiego. Jest to zbiornik płytki, z dnem mulistym, otoczony parkiem i alejkami spacerowymi. Brzegi są umocnione faszyną i obrzeżami, co ułatwia dostęp do lustra wody w niemal każdym punkcie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81213, 'Kaczy Staw', 'kaczy-staw-gorowo', 'LAKE', 54.295866, 20.4883, 'Warmińsko-Mazurskie', 'Górowo Iławeckie', 'Kaczy Staw to dziki akwen o charakterze dystroficzno-eutroficznym, położony w zagłębieniu terenu na północ od miasta. Charakteryzuje się mroczną wodą i bardzo miękkim dnem wyścielonym osadami leśnymi. Maksymalna głębokość nie przekracza 4 metrów. Brzegi są niskie i bagniste, silnie zarośnięte trzciną, co zapewnia rybom absolutny spokój.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81214, 'Garbnicki Staw', 'garbnicki-staw', 'LAKE', 54.352092, 20.399616, 'Warmińsko-Mazurskie', 'Górowo Iławeckie / Garbniki', 'Garbnicki Staw to malowniczy, śródleśny zbiornik położony w bezpośrednim sąsiedztwie granicy państwa. Akwen charakteryzuje się twardym piaszczysto-żwirowym dnem i bardzo czystą wodą. Batymetria jest regularna – rynna o głębokości do 6-8 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81215, 'Jezioro Straduńskie', 'jezioro-stradunskie', 'LAKE', 53.897765, 22.324262, 'Warmińsko-Mazurskie', 'Ełk / Straduny', 'Jezioro Straduńskie to malowniczy akwen rynnowo-przepływowy, przez który przepływa rzeka Ełk. Charakteryzuje się twardym dnem w osi nurtu i piaszczysto-mulistymi zatokami. Maksymalna głębokość sięga 8-10 metrów. Dzięki stałemu dopływowi świeżej wody, jezioro jest świetnie natlenione, co sprzyja aktywności drapieżników przez cały rok.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81216, 'Jezioro Haleckie', 'jezioro-haleckie', 'LAKE', 53.880066, 22.362499, 'Warmińsko-Mazurskie', 'Ełk / Halecko', 'Jezioro Haleckie to akwen o charakterze wybitnie eutroficznym, położony w pagórkowatym terenie rolniczym. Zbiornik jest stosunkowo płytki (max 5-6 m) z dnem w dużej mierze mulistym, bogatym w bentos. Linia brzegowa jest silnie porośnięta trzciną i tatarakiem, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81217, 'Jezioro Płociczno', 'jezioro-plociczno-elk', 'LAKE', 53.897614, 22.396746, 'Warmińsko-Mazurskie', 'Ełk / Płociczno', 'Jezioro Płociczno to urokliwy, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 12 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem sosnowym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81218, 'Jezioro Zdrężno', 'jezioro-zdrezno', 'LAKE', 53.912248, 22.40344, 'Warmińsko-Mazurskie', 'Ełk / Gąski', 'Jezioro Zdrężno to klasyczna rynna polodowcowa (pow. ok. 60 ha) charakteryzująca się twardym dnem i głębokością sięgającą 12-14 metrów. Woda jest przejrzysta, o wysokiej klasie czystości. Brzegi są w większości wysokie i porośnięte lasem mieszanym, z wieloma dzikimi stanowiskami wędkarskimi i kładkami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81219, 'Jezioro Krzywionka', 'jezioro-krzywionka', 'LAKE', 53.921623, 22.426744, 'Warmińsko-Mazurskie', 'Ełk / Przytuły', 'Krzywionka to kameralny zbiornik rynnowy ukryty wśród mazurskich wzgórz. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 6-8 metrów. Jezioro jest wyciszone, osłonięte od wiatru, co sprzyja rozwojowi bujnej roślinności zanurzonej – grążeli i rdestnicy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81220, 'Jezioro Przytulskie', 'jezioro-przytulskie', 'LAKE', 53.936033, 22.403955, 'Warmińsko-Mazurskie', 'Ełk / Przytuły', 'Jezioro Przytulskie to potężna rynna polodowcowa (powierzchnia blisko 200 ha). Charakteryzuje się monumentalną batymetrią – dno opada stromo do rynny centralnej sięgającej blisko 18-20 metrów. Woda posiada dobrą przejrzystość. Jezioro posiada bardzo urozmaiconą linię brzegową z licznymi półwyspami i zatokami, co stwarza wędkarzom wiele opcji wyboru stanowiska.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81221, 'Jezioro Jachimowo', 'jezioro-jachimowo', 'LAKE', 53.867335, 22.342458, 'Warmińsko-Mazurskie', 'Ełk / Straduny', 'Jezioro Jachimowo to niewielki, ustronny akwen położony w zagłębieniu terenu wśród pól i kęp drzew. Akwen ma charakter rynnowy z dnem piaszczysto-mulistym. Maksymalna głębokość nie przekracza 6-7 metrów. Jezioro jest osłonięte od wiatru, co sprawia, że tafla wody jest zazwyczaj spokojna, a woda szybko nagrzewa się wiosną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81222, 'Jezioro Golubskie', 'jezioro-golubskie', 'LAKE', 53.877328, 22.522488, 'Warmińsko-Mazurskie', 'Ełk / Golubie', 'Jezioro Golubskie to malowniczy, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 15 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym, co nadaje akwenowi dziki charakter. Roślinność wodna jest skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81223, 'Jezioro Olecko Małe', 'jezioro-olecko-male', 'LAKE', 53.98938, 22.539697, 'Warmińsko-Mazurskie', 'Olecko / Wieliczki', 'Jezioro Olecko Małe to malowniczy akwen rynnowy położony na południe od Olecka. Charakteryzuje się twardym, piaszczysto-żwirowym dnem i głębokością sięgającą 10-12 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest połączone systemem cieków z jeziorem Olecko Wielkie, co sprzyja migracji ryb drapieżnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81224, 'Jezioro Olecko Wielkie', 'jezioro-olecko-wielkie', 'LAKE', 54.041997, 22.513561, 'Warmińsko-Mazurskie', 'Olecko', 'Jezioro Olecko Wielkie to potężna rynna polodowcowa (powierzchnia ponad 200 ha) stanowiąca centrum rekreacyjne Olecka. Charakteryzuje się monumentalną batymetrią – dno opada stromo do rynny centralnej sięgającej ponad 35 metrów. Woda posiada wysoką klasę czystości (I/II klasa). Brzegi są zagospodarowane – promenady, pomosty i oświetlone alejki ułatwiają dostęp do wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81225, 'Jezioro Dobskie (k. Olecka)', 'jezioro-dobskie-olecko', 'LAKE', 54.042031, 22.42979, 'Warmińsko-Mazurskie', 'Olecko / Dobki', 'Jezioro Dobskie to malownicza rynna rynnowa o powierzchni ok. 50 ha, położona w otulinie leśnej. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem w strefie litoralu. Maksymalna głębokość sięga 12-14 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są wysokie i w dużej mierze zalesione, co zapewnia osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81226, 'Jezioro Romały', 'jezioro-romaly', 'LAKE', 54.04765, 22.344689, 'Warmińsko-Mazurskie', 'Olecko / Romały', 'Jezioro Romały to mały, kameralny akwen o charakterze eutroficznym, położony w ustronnej dolinie wśród pól. Zbiornik jest stosunkowo płytki (max 4-5 m), z dnem wyścielonym osadami organicznymi i bogatą roślinnością zanurzoną. Woda szybko nagrzewa się wiosną, co stymuluje ryby karpiowate do intensywnego żerowania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81227, 'Jezioro Ryzonka Duża', 'jezioro-ryzonka-duza', 'LAKE', 54.043139, 22.361748, 'Warmińsko-Mazurskie', 'Olecko / Dobki', 'Jezioro Ryzonka Duża to kameralny akwen rynnowy położony w ustronnym, pofałdowanym terenie. Charakteryzuje się dość twardym dnem piaszczysto-żwirowym i średnią głębokością ok. 5-7 metrów. Woda posiada przyzwoitą przejrzystość, co sprzyja rozwojowi bujnego litoralu. Brzegi są w większości wysokie i suche, porośnięte lasem mieszanym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81228, 'Jezioro Olszewskie', 'jezioro-olszewskie', 'LAKE', 54.074675, 22.385502, 'Warmińsko-Mazurskie', 'Olecko / Olszewo', 'Jezioro Olszewskie to typowa mazurska rynna o wydłużonym kształcie, stanowiąca część systemu hydrologicznego rzeki Legi. Akwen charakteryzuje się pofałdowanym dnem i głębokością sięgającą 10-12 metrów. Woda posiada dobrą klasę czystości. Brzegi są urozmaicone – od zalesionych skarp po piaszczyste dojścia przy miejscowości Olszewo.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81229, 'Jezioro Głębokie (k. Olecka)', 'jezioro-glebokie-olecko', 'LAKE', 54.067702, 22.39224, 'Warmińsko-Mazurskie', 'Olecko / Olszewo', 'Jezioro Głębokie koło Olecka w pełni zasługuje na swoją nazwę – batymetria jest tu gwałtowna, a dno opada stromo do rynny sięgającej blisko 15 metrów. Woda jest krystalicznie czysta, o sielawowym charakterze. Dno jest wybitnie twarde, piaszczysto-żwirowe. Brzegi są wysokie i porośnięte starym lasem bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81230, 'Jezioro Boczne (k. Olecka)', 'jezioro-boczne-olecko', 'LAKE', 54.069615, 22.398634, 'Warmińsko-Mazurskie', 'Olecko / Olszewo', 'Jezioro Boczne to urokliwa odnoga większego systemu rynnowego, oddzielona przewężeniem. Ma charakter nieco bardziej osłonięty i zaciszny. Dno jest piaszczysto-muliste, o średniej głębokości ok. 4-6 metrów. Roślinność wodna jest tu bardziej rozwinięta niż w sąsiednim jeziorze Głębokim, z rozległymi polami grążeli żółtych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81231, 'Jezioro Gordejskie', 'jezioro-gordejskie', 'LAKE', 54.062994, 22.409492, 'Warmińsko-Mazurskie', 'Olecko / Gordejki', 'Jezioro Gordejskie to rozległy akwen rynnowy (pow. ok. 60 ha) o bardzo urozmaiconym ukształtowaniu dna. Charakteryzuje się czystą wodą i twardym podłożem z licznymi podwodnymi górkami. Maksymalna głębokość sięga 12-14 metrów. Brzegi są w większości wysokie i suche, częściowo zalesione, z licznymi pomostami od strony miejscowości Gordejki.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81232, 'Jezioro Kuliste', 'jezioro-kuliste', 'LAKE', 54.06716, 22.433589, 'Warmińsko-Mazurskie', 'Olecko / Sedranki', 'Jezioro Kuliste to niewielki, niemal okrągły akwen o charakterze wytopiskowym, położony w otulinie leśnej. Dno jest piaszczysto-muliste, o wyrównanej batymetrii (max 5-6 m). Jezioro jest wybitnie wyciszone, osłonięte od wiatru przez wysokie brzegi, co sprzyja szybkiej wegetacji roślinności wodnej. Woda szybko nagrzewa się wiosną, co stymuluje ryby do intensywnego żerowania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81233, 'Jezioro Sedraneckie', 'jezioro-sedraneckie', 'LAKE', 54.069519, 22.459682, 'Warmińsko-Mazurskie', 'Olecko / Sedranki', 'Jezioro Sedraneckie to malowniczy zbiornik rynnowo-przepływowy, bezpośrednio zasilany wodami rzeki Legi. Charakteryzuje się twardym dnem w osi nurtu i piaszczystymi blatami w zatokach. Maksymalna głębokość oscyluje wokół 10 metrów. Dzięki stałemu dopływowi świeżej wody, jezioro jest świetnie natlenione, co sprzyja aktywności drapieżników przez cały rok.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81234, 'Jezioro Walulika', 'jezioro-walulika', 'LAKE', 54.050952, 22.473296, 'Warmińsko-Mazurskie', 'Olecko', 'Walulika to głęboki, śródleśny zbiornik o charakterze rynnowym. Akwen cechuje się bardzo czystą wodą i twardym dnem piaszczysto-żwirowym. Batymetria jest regularna – rynna o głębokości do 12 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym borem sosnowym, co nadaje akwenowi dziki i ustronny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81235, 'Jezioro Gołębie', 'jezioro-golebie-olecko', 'LAKE', 54.103298, 22.44657, 'Warmińsko-Mazurskie', 'Olecko / Sedranki', 'Jezioro Gołębie to malowniczy, rynnowy zbiornik położony w otulinie leśnej na północ od Olecka. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem w strefie litoralu. Maksymalna głębokość sięga 10 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są wysokie, w dużej mierze zalesione, co zapewnia osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81236, 'Jezioro Błotne', 'jezioro-blotne-olecko', 'LAKE', 54.119975, 22.414706, 'Warmińsko-Mazurskie', 'Olecko / Gordejki', 'Jezioro Błotne to akwen o charakterze wybitnie eutroficznym, położony w zagłębieniu terenu. Nazwa jest nieco myląca, gdyż woda posiada przyzwoitą czystość, jednak dno jest wybitnie miękkie, wyścielone osadami organicznymi. Zbiornik jest stosunkowo płytki (max 4 m), z bogatą roślinnością zanurzoną. Brzegi są niskie i podmokłe, co zapewnia rybom absolutny spokój.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81237, 'Jezioro Czarne (Sedranki)', 'jezioro-czarne-sedranki', 'LAKE', 54.115799, 22.47159, 'Warmińsko-Mazurskie', 'Olecko / Sedranki', 'Jezioro Czarne w Sedrankach to głęboki akwen rynnowy położony w głębi kompleksu leśnego. Charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i twardym dnem piaszczysto-żwirowym. Maksymalna głębokość sięga 15-18 metrów. Brzegi są wysokie i porośnięte majestatycznym lasem sosnowym. Jezioro jest wyciszone i osłonięte od wiatru, co nadaje mu surowy charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81238, 'Jezioro Białe (Sedranki)', 'jezioro-biale-sedranki', 'LAKE', 54.121433, 22.498498, 'Warmińsko-Mazurskie', 'Olecko / Sedranki', 'Jezioro Białe w Sedrankach to jeden z najczystszych akwenów w rejonie (I klasa czystości). Posiada twarde, piaszczyste dno i wodę o niesamowitej przejrzystości. Maksymalna głębokość sięga ok. 15-20 metrów. Jezioro charakteryzuje się sielawowym charakterem i bogatą roślinnością podwodną, w tym rozległymi łąkami ramienicowymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81239, 'Jezioro Pozorty', 'jezioro-pozorty', 'LAKE', 53.872294, 19.70016, 'Warmińsko-Mazurskie', 'Miłomłyn', 'Pozorty to jezioro rynnowe o powierzchni ok. 40 ha, wchodzące w skład systemu Kanału Elbląskiego. Charakteryzuje się dnem piaszczysto-mulistym i średnią głębokością ok. 4 metrów. Woda jest żyzna i dobrze natleniona. Przez jezioro przepływają rzeczki łączące je z innymi akwenami, co sprzyja stałej migracji ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81240, 'Jezioro Kęty', 'jezioro-kety', 'LAKE', 53.849013, 19.738784, 'Warmińsko-Mazurskie', 'Małdyty / Kęty', 'Jezioro Kęty to kameralny, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są porośnięte majestatycznym lasem sosnowym, co nadaje akwenowi dziki i ustronny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81241, 'Jezioro Czarne (k. Miłomłyna)', 'jezioro-czarne-milomlyn', 'LAKE', 53.844947, 19.711103, 'Warmińsko-Mazurskie', 'Miłomłyn', 'Czarne koło Miłomłyna to niewielki akwen o charakterze dystroficzno-eutroficznym. Woda posiada mroczny, lekko herbaciany odcień, a dno jest miękkie, wyścielone osadami organicznymi. Maksymalna głębokość nie przekracza 5 metrów. Brzegi są niskie i podmokłe, co zapewnia rybom absolutny spokój i czyni akwen naturalnym matecznikiem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81242, 'Jezioro Łysk', 'jezioro-lysk', 'LAKE', 53.834196, 19.74196, 'Warmińsko-Mazurskie', 'Miłomłyn / Liwa', 'Jezioro Łysk to malowniczy akwen rynnowy położony w otulinie lasów liściastych. Charakteryzuje się czystą wodą i twardym piaszczystym dnem w strefie litoralu. Maksymalna głębokość sięga 10-12 metrów. Jezioro jest osłonięte od wiatru przez wysokie skarpy, co sprzyja rozwojowi bujnej roślinności podwodnej przy brzegach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81243, 'Jezioro Młynek (k. Małdyt)', 'jezioro-mlynek-maldyty', 'LAKE', 53.824903, 19.725051, 'Warmińsko-Mazurskie', 'Małdyty / Liwa', 'Jezioro Młynek to akwen o charakterze przepływowym, stanowiący część systemu rzeki Liwy. Dzięki stałemu ruchowi wody, dno w osi głównej jest twardsze, piaszczysto-żwirowe. Akwen jest stosunkowo płytki (max 3-4 m), co sprawia, że woda szybko nagrzewa się wiosną. Brzegi są porośnięte gęstą trzciną i tatarakiem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81244, 'Jezioro Surzyckie', 'jezioro-surzyckie', 'LAKE', 53.816769, 19.769683, 'Warmińsko-Mazurskie', 'Miłomłyn', 'Surzyckie to rynnowy zbiornik położony w pagórkowatym terenie rolniczo-leśnym. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 5 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest połączone systemem cieków z jeziorem Bartężek, co sprzyja migracji ryb drapieżnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81245, 'Jezioro Ruda Woda', 'jezioro-ruda-woda', 'LAKE', 53.85839, 19.808521, 'Warmińsko-Mazurskie', 'Małdyty / Miłomłyn', 'Ruda Woda to potężny akwen rynnowy (ponad 800 ha) stanowiący kluczowy odcinek szlaku Kanału Elbląskiego. Charakteryzuje się monumentalną batymetrią – strome, piaszczyste spady schodzą do rynny o głębokości blisko 30 metrów. Dno jest wybitnie urozmaicone, z licznymi wyspami i podwodnymi górkami. Woda posiada dobrą klasę czystości.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81246, 'Jezioro Bartężek', 'jezioro-bartezek', 'LAKE', 53.8224, 19.845688, 'Warmińsko-Mazurskie', 'Miłomłyn / Winiec', 'Jezioro Bartężek to malownicza, wąska rynna polodowcowa (ok. 300 ha) o bardzo rozwiniętej linii brzegowej. Posiada twarde dno i głębokość sięgającą 15 metrów. Woda jest czysta, o sielawowym charakterze. Jezioro jest połączone kanałem z Rudą Wodą. Brzegi są wysokie, w dużej mierze zalesione, z licznymi pomostami i dzikimi plażami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81247, 'Jezioro Ilińsk (Jelonek)', 'jezioro-ilinsk', 'LAKE', 53.789352, 19.841867, 'Warmińsko-Mazurskie', 'Miłomłyn', 'Jezioro Ilińsk (często nazywane Jelonkiem) to malowniczy akwen rynnowy położony bezpośrednio przy Miłomłynie. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem. Batymetria jest bardzo urozmaicona z wyraźnie zaznaczoną rynną centralną sięgającą 25-27 metrów. Brzegi są w większości porośnięte lasem sosnowym, z licznymi pomostami i bazami turystycznymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81248, 'Jezioro Tarda', 'jezioro-tarda', 'LAKE', 53.792744, 19.904995, 'Warmińsko-Mazurskie', 'Miłomłyn / Tarda', 'Jezioro Tarda to urokliwy, śródleśny zbiornik o charakterze rynnowym, położony w sercu mazurskiej puszczy. Akwen posiada twarde dno i przejrzystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym, co nadaje akwenowi dziki charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81249, 'Jezioro Jelonek', 'jezioro-jelonek-milomlyn', 'LAKE', 53.776522, 19.849033, 'Warmińsko-Mazurskie', 'Miłomłyn', 'Jezioro Jelonek to mniejszy, południowy sąsiad jeziora Ilińsk, połączony z nim szerokim ciekiem. Ma charakter bardziej eutroficzny, z dnem mulistym i bogatszą roślinnością brzegową. Maksymalna głębokość nie przekracza 5-6 metrów. Brzegi są niskie, silnie zarośnięte trzciną, co zapewnia rybom doskonałe warunki do tarła.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81250, 'Jezioro Liwskie', 'jezioro-liwskie', 'LAKE', 53.760782, 19.824336, 'Warmińsko-Mazurskie', 'Miłomłyn', 'Jezioro Liwskie to akwen o charakterze rynnowym, stanowiący istotne ogniwo systemu rzeki Liwy. Posiada wydłużony kształt i dno piaszczysto-muliste. Maksymalna głębokość oscyluje wokół 6-8 metrów. Woda jest żyzna, co sprzyja rozwojowi bujnego litoralu. Brzegi są w większości porośnięte trzciną pospolitą, tworzącą doskonałe warunki ochronne dla narybku.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81251, 'Staw Strumyk', 'staw-strumyk-milomlyn', 'LAKE', 53.740362, 19.804616, 'Warmińsko-Mazurskie', 'Miłomłyn', 'Staw Strumyk to niewielki, kameralny zbiornik położony w ustronnym terenie leśno-polnym. Akwen ma charakter eutroficzny, z dnem wyścielonym grubą warstwą mułu i osadów organicznych. Woda nagrzewa się tu bardzo szybko wiosną. Brzegi są niskie, silnie zarośnięte tatarakiem i trzciną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81252, 'Jezioro Gil Wielkie', 'jezioro-gil-wielkie', 'LAKE', 53.716642, 19.711189, 'Warmińsko-Mazurskie', 'Miłomłyn / Boreczno', 'Jezioro Gil Wielkie to jedna z najczystszych i najgłębszych rynien regionu (max blisko 25 m). Akwen charakteryzuje się niesamowitą przejrzystością wody (I klasa) i sielawowym charakterem. Dno jest wybitnie twarde, piaszczysto-żwirowe ze stromymi spadkami. Brzegi są wysokie i w całości porośnięte majestatycznym lasem sosnowo-bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81253, 'Jezioro Kocioł', 'jezioro-kociol-2', 'LAKE', 53.743336, 19.717283, 'Warmińsko-Mazurskie', 'Miłomłyn / Boreczno', 'Jezioro Kocioł to niewielki, niemal okrągły akwen o charakterze wytopiskowym, położony w bezpośrednim sąsiedztwie jeziora Gil Wielkie. Mimo małej powierzchni, zbiornik jest stosunkowo głęboki (do 8-10 m) i posiada czystą wodę. Dno opada regularnie w stronę środka jeziora. Brzegi są porośnięte gęstym lasem, co zapewnia osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81254, 'Jezioro Karnickie Południowe', 'jezioro-karnickie-poludniowe', 'LAKE', 53.7563, 19.734235, 'Warmińsko-Mazurskie', 'Miłomłyn / Karnity', 'Karnickie Południowe to część unikatowego systemu jeziornego, nad którym przebiega słynny akwedukt Kanału Elbląskiego. Jest to jezioro wybitnie płytkie (max 2-3 m), o charakterze eutroficznym. Dno jest skrajnie miękkie, wyścielone grubą warstwą mułu organicznego. Woda jest bardzo żyzna, co przekłada się na ogromną biomasę ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81255, 'Jezioro Karnickie Północne', 'jezioro-karnickie-polnocne', 'LAKE', 53.766321, 19.739814, 'Warmińsko-Mazurskie', 'Miłomłyn / Karnity', 'Karnickie Północne to północna część akwenu Karnickiego, oddzielona od części południowej nasypem Kanału Elbląskiego. Ma charakter bardziej dziki i mniej dostępny. Jezioro jest płytkie, silnie zarastające moczarką i rdestnicą. Woda nagrzewa się błyskawicznie, co sprzyja tarłu wielu gatunków ryb. Dno jest muliste z piaszczystymi łachami w pobliżu brzegów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81256, 'Jezioro Jaśkowskie', 'jezioro-jaskowskie', 'LAKE', 53.793072, 19.742088, 'Warmińsko-Mazurskie', 'Zalewo / Jaśkowo', 'Jezioro Jaśkowskie to rozległy akwen rynnowy (pow. ok. 150 ha) położony przy malowniczej miejscowości Jaśkowo. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i maksymalną głębokością ok. 12-14 metrów. Woda posiada dobrą klasę czystości. Brzegi są zróżnicowane – od wysokich zalesionych skarp po piaszczyste plaże i pomosty turystyczne.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81257, 'Jezioro Wajgart', 'jezioro-wajgart', 'LAKE', 53.785317, 19.714451, 'Warmińsko-Mazurskie', 'Jaśkowo', 'Wajgart to kameralna, wąska rynna polodowcowa, ukryta w głębi kompleksu leśnego. Akwen charakteryzuje się czystą wodą i twardym piaszczystym dnem w strefie litoralu. Batymetria jest regularna – rynna o głębokości do 8-10 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym, co nadaje akwenowi dziki charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81258, 'Jezioro Dauby', 'jezioro-dauby', 'LAKE', 53.762093, 19.697542, 'Warmińsko-Mazurskie', 'Miłomłyn', 'Jezioro Dauby to akwen bezpośrednio połączony z Kanałem Elbląskim, stanowiący jego istotne poszerzenie rynnowe. Charakteryzuje się urozmaiconą linią brzegową i dnem piaszczysto-mulistym. Maksymalna głębokość sięga 8 metrów. Woda posiada przyzwoitą przejrzystość wiosną. Brzegi są częściowo zalesione, z wieloma dzikimi stanowiskami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81259, 'Zatoka Kraga (Jeziorak)', 'zatoka-kraga-jeziorak', 'LAKE', 53.741261, 19.666901, 'Warmińsko-Mazurskie', 'Iława / Gubławy', 'Zatoka Kraga to północna, wybitnie ustronna część systemu jeziora Jeziorak. Charakteryzuje się znacznie mniejszą głębokością niż główny plos (max 3-5 m) i wybitnie eutroficznym charakterem. Dno jest wysoce muliste i bogate w bentos. Zatoka jest otoczona gęstymi lasami i szerokim pasem trzcin, co stwarza doskonałe warunki dla ptactwa i ryb litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81260, 'Jezioro Silm', 'jezioro-silm', 'LAKE', 53.606107, 19.514222, 'Warmińsko-Mazurskie', 'Iława / Kamień Duży', 'Jezioro Silm to jeden z najczystszych i najbardziej urokliwych akwenów w bezpośrednim sąsiedztwie Iławy (I klasa czystości). Posiada twarde, piaszczyste dno i wodę o niesamowitej przejrzystości. Maksymalna głębokość sięga ok. 15-18 metrów. Jezioro charakteryzuje się bardzo rozwiniętą roślinnością podwodną, w tym rozległymi łąkami ramienicowymi, co czyni je unikatowym siedliskiem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81261, 'Jezioro Iławskie', 'jezioro-ilawskie-poludniowe', 'LAKE', 53.591311, 19.57768, 'Warmińsko-Mazurskie', 'Iława', 'Jezioro Iławskie to rynnowy akwen położony w południowej części Iławy, stanowiący naturalne przedłużenie systemu rzeki Iławki. Charakteryzuje się dość wyrównanym dnem piaszczysto-mulistym i średnią głębokością ok. 4-5 metrów. Woda posiada przyzwoitą klasę czystości, choć w lecie ulega naturalnym zakwitom.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81262, 'Jezioro Łąckie', 'jezioro-lackie', 'LAKE', 53.55798, 19.571543, 'Warmińsko-Mazurskie', 'Iława / Łąka', 'Jezioro Łąckie to malownicza rynna rynnowa położona w ustronnym terenie rolniczo-leśnym na południe od Iławy. Akwen charakteryzuje się czystą wodą i twardym, piaszczystym dnem w strefie litoralu. Maksymalna głębokość sięga 10-12 metrów. Brzegi są w większości wysokie i porośnięte lasem mieszanym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81263, 'Jezioro Łajskie', 'jezioro-lajskie-2', 'LAKE', 53.551965, 19.58519, 'Warmińsko-Mazurskie', 'Iława / Łąka', 'Jezioro Łajskie to kameralny, płytki akwen (max 4-5 m) o charakterze eutroficznym. Dno jest w dużej mierze muliste, bogate w bentos, z licznymi skupiskami grążeli żółtych. Akwen jest zaciszny, co sprzyja rozwojowi narybku i czyni go idealnym miejscem dla ryb ciepłolubnych. Brzegi są niskie, silnie zarośnięte trzciną i tatarakiem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81264, 'Jezioro Długie (k. Łąki)', 'jezioro-dlugie-laka', 'LAKE', 53.558413, 19.610982, 'Warmińsko-Mazurskie', 'Iława / Łąka', 'Jezioro Długie pod Łąką to klasyczna rynna polodowcowa, długa i wąska, wciśnięta w pofalowany krajobraz. Akwen charakteryzuje się twardym dnem piaszczysto-żwirowym i wyraźnie zarysowaną rynną środkową o głębokości do 9-10 metrów. Woda jest czysta i dobrze natleniona. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81265, 'Jezioro Zawada', 'jezioro-zawada', 'LAKE', 53.616887, 18.639173, 'Pomorskie', 'Osiek / Starogard Gd.', 'Jezioro Zawada to malowniczy akwen kociewski położony w dorzeczu rzeki Wdy. Charakteryzuje się urozmaiconą linią brzegową i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 8-10 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest otoczone wianuszkiem lasów i pól, co sprzyja dobremu natlenieniu wody przez wiatr. Brzegi są w większości dostępne, z licznymi piaszczystymi plażami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81266, 'Jezioro Czarne (k. Osieka)', 'jezioro-czarne-osiek', 'LAKE', 53.637948, 18.638005, 'Pomorskie', 'Osiek', 'Jezioro Czarne koło Osieka to głęboki akwen rynnowy położony w głębi kompleksu leśnego Borów Tucholskich. Charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i twardym dnem piaszczysto-żwirowym. Maksymalna głębokość sięga 15-18 metrów. Brzegi są wysokie i porośnięte majestatycznym lasem sosnowym. Jezioro jest wyciszone i osłonięte od wiatru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81267, 'Jezioro Łakosz', 'jezioro-lakosz', 'LAKE', 53.640822, 18.612299, 'Pomorskie', 'Skórcz / Osiek', 'Jezioro Łakosz to kameralny, śródleśny zbiornik o charakterze eutroficznym. Zbiornik jest stosunkowo płytki (max 4-5 m), z dnem wyścielonym osadami organicznymi i bogatą roślinnością zanurzoną. Jezioro jest wybitnie wyciszone, osłonięte od wiatru przez wysokie skarpy porośnięte borami, co nadaje mu intymny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81268, 'Jezioro Radodzierz', 'jezioro-radodzierz', 'LAKE', 53.642427, 18.578653, 'Kujawsko-Pomorskie', 'Warlubie / Osiek', 'Jezioro Radodzierz to jeden z największych i najpopularniejszych akwenów w tej części Borów Tucholskich (pow. ok. 240 ha). Jest to jezioro rynnowe o bardzo rozwiniętej linii brzegowej, z licznymi zatokami i półwyspami. Dno jest pofalowane, piaszczysto-muliste, o maksymalnej głębokości ok. 15-17 metrów. Woda posiada przyzwoitą przejrzystość, choć w lecie ulega naturalnym zakwitom.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81269, 'Jezioro Płochocin', 'jezioro-plochocin', 'LAKE', 53.590599, 18.587365, 'Kujawsko-Pomorskie', 'Warlubie / Płochocin', 'Jezioro Płochocin to malownicza, śródleśna rynna polodowcowa o powierzchni ok. 40 ha. Akwen charakteryzuje się czystą wodą i twardym, piaszczystym dnem w strefie litoralu. Maksymalna głębokość sięga 12-14 metrów. Brzegi są wysokie i w całości porośnięte majestatycznym lasem sosnowym, co zapewnia doskonałą osłonę przed wiatrem i unikatowy mikroklimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81270, 'Jezioro Piaseczno (k. Warlubia)', 'jezioro-piaseczno-warlubie', 'LAKE', 53.593092, 18.567152, 'Kujawsko-Pomorskie', 'Warlubie', 'Piaseczno to hydrologiczna perła regionu – jezioro o charakterze zbliżonym do lobeliowego, z krystalicznie czystą wodą i jasnym, piaszczystym dnem. Akwen jest stosunkowo głęboki (do 15 m) i posiada bardzo ubogi litoral, co przekłada się na wysoką przejrzystość. Jezioro położone jest w głębokiej niecce leśnej, co chroni je przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81271, 'Jezioro Lipnowskie', 'jezioro-lipnowskie', 'LAKE', 53.482926, 18.457632, 'Kujawsko-Pomorskie', 'Jeżewo / Lipno', 'Jezioro Lipnowskie to rynnowy akwen o wydłużonym kształcie, otoczony pagórkowatym terenem. Posiada dno piaszczysto-muliste i średnią głębokość ok. 4-5 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są w większości wysokie, co zapewnia osłonę przed wiatrem i tworzy urokliwe stanowiska wędkarskie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81272, 'Jezioro Krokwiki Wielkie', 'jezioro-krokwiki-wielkie', 'LAKE', 53.550732, 18.525631, 'Kujawsko-Pomorskie', 'Warlubie / Buśnia', 'Krokwiki Wielkie to rynnowy akwen położony w pofałdowanym terenie leśno-polnym. Charakteryzuje się pofalowanym dnem piaszczysto-mulistym i średnią głębokością ok. 5 metrów (max do 10 m). Woda posiada przyzwoitą klasę czystości. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin, co ułatwia dostęp do lustra wody z brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81273, 'Jezioro Krokwiki Małe', 'jezioro-krokwiki-male', 'LAKE', 53.557539, 18.535287, 'Kujawsko-Pomorskie', 'Warlubie', 'Krokwiki Małe to mniejszy, kameralny sąsiad Krokwik Wielkich. Ma charakter bardziej eutroficzny, z dnem mulistym i bogatszą roślinnością brzegową. Maksymalna głębokość nie przekracza 5-6 metrów. Brzegi są niskie, silnie zarośnięte trzciną, co zapewnia rybom doskonałe warunki do tarła.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81274, 'Jezioro Bielskie', 'jezioro-bielskie', 'LAKE', 53.480877, 18.529172, 'Kujawsko-Pomorskie', 'Jeżewo / Biała', 'Jezioro Bielskie to malownicza rynna rynnowa (pow. ok. 50 ha) położona w dorzeczu rzeki Mątawy. Charakteryzuje się twardym dnem piaszczystym w strefie litoralu i wyraźnie zarysowaną rynną środkową sięgającą 12-14 metrów. Woda jest dobrze natleniona i posiada dobrą klasę czystości. Brzegi są wysokie i w dużej mierze zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81275, 'Jezioro Święte (k. Skórcza)', 'jezioro-swiete-skorcz', 'LAKE', 53.460221, 18.595176, 'Pomorskie / Kujawsko-Pom.', 'Skórcz / Osiek', 'Jezioro Święte to jeden z najczystszych akwenów Kociewia (I klasa czystości). Posiada twarde, piaszczyste dno i wodę o niesamowitej przejrzystości. Maksymalna głębokość sięga ok. 10-12 metrów. Jezioro charakteryzuje się bardzo rozwiniętą roślinnością podwodną, w tym rozległymi łąkami ramienicowymi, co czyni je unikatowym siedliskiem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81276, 'Jezioro Radon', 'jezioro-radon', 'LAKE', 53.453331, 18.502758, 'Kujawsko-Pomorskie', 'Jeżewo', 'Jezioro Radon to kameralny, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i przejrzystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są porośnięte majestatycznym lasem sosnowym, co zapewnia ciszę i osłonę przed wiatrem. Roślinność wodna jest umiarkowana.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81277, 'Jezioro Wielkie (k. Jeżewa)', 'jezioro-wielkie-jezewo', 'LAKE', 53.453178, 18.491707, 'Kujawsko-Pomorskie', 'Jeżewo', 'Jezioro Wielkie to akwen położony bezpośrednio przy miejscowości Jeżewo. Zbiornik charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 4-6 metrów. Woda jest żyzna, co przekłada się na bogatą biomasę ryb karpiowatych. Brzegi są w dużej mierze zagospodarowane – pomosty i promenady ułatwiają dostęp do wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81278, 'Jezioro Piaskowe (k. Jeżewa)', 'jezioro-piaskowe-jezewo', 'LAKE', 53.456511, 18.487952, 'Kujawsko-Pomorskie', 'Jeżewo', 'Jezioro Piaskowe to rynnowy sąsiad jeziora Wielkiego, charakteryzujący się – zgodnie z nazwą – wybitnie twardym, piaszczystym dnem. Maksymalna głębokość sięga 8-10 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest wyciszone i osłonięte od wiatrów, co sprzyja rozwojowi bujnego litoralu w płytkich zatokach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81279, 'Jezioro Piskarki', 'jezioro-piskarki', 'LAKE', 53.466846, 18.487158, 'Kujawsko-Pomorskie', 'Jeżewo / Piskarki', 'Jezioro Piskarki to kameralny akwen o charakterze eutroficznym, położony wśród pól i lasów. Charakteryzuje się mulistym dnem z licznymi piaszczystymi wypłyceniami w strefie brzegowej. Maksymalna głębokość nie przekracza 5-6 metrów. Woda jest żyzna, co sprzyja szybkiej wegetacji lina i karasia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81280, 'Jezioro Laskowickie', 'jezioro-laskowickie', 'LAKE', 53.49443, 18.468876, 'Kujawsko-Pomorskie', 'Laskowice', 'Jezioro Laskowickie to malowniczy zbiornik położony w bezpośrednim sąsiedztwie Laskowic. Charakteryzuje się urozmaiconą linią brzegową i dnem piaszczysto-żwirowym w strefie litoralu. Maksymalna głębokość sięga 8-10 metrów. Woda jest dobrze natleniona i posiada dobrą przejrzystość wiosną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81281, 'Jezioro Zamkowe (k. Laskowic)', 'jezioro-zamkowe-laskowice', 'LAKE', 53.503415, 18.459885, 'Kujawsko-Pomorskie', 'Laskowice', 'Jezioro Zamkowe to niewielki, ale głęboki akwen o charakterze rynnowym. Posiada twarde dno i wodę o wysokiej klasie czystości. Nazwa nawiązuje do historycznych osad w tym rejonie. Brzegi są wysokie i porośnięte lasem, co nadaje jezioru kameralny i nieco mroczny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81282, 'Jezioro Stelchno', 'jezioro-stelchno', 'LAKE', 53.524598, 18.459992, 'Kujawsko-Pomorskie', 'Jeżewo / Jeżewice', 'Jezioro Stelchno to hydrologiczny unikat i jedno z najczystszych jezior w Polsce (I klasa czystości). Posiada wybitnie twarde, piaszczysto-kredowe dno i niesamowitą przejrzystość wody (widoczność do 6-8 metrów). Batymetria jest urozmaicona z rynną sięgającą 12-15 metrów. Jezioro słynie z obecności raków, co jest najlepszym certyfikatem czystości.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81283, 'Jezioro Żurskie (Zalew Żurski)', 'jezioro-zurskie', 'LAKE', 53.596709, 18.306355, 'Kujawsko-Pomorskie', 'Osie / Żur', 'Jezioro Żurskie to zbiornik zaporowy na rzece Wdzie, jeden z najbardziej atrakcyjnych akwenów w Borach Tucholskich. Posiada wybitnie urozmaiconą linię brzegową z licznymi wyspami (m.in. Wyspa Miłości) i zatopionymi korytami rzecznymi. Dno jest piaszczysto-muliste z ogromną ilością karczowisk i zatopionych drzew, co stwarza idealne warunki dla drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81284, 'Jezioro Piaseczno (Gruta)', 'jezioro-piaseczno-gruta', 'LAKE', 53.475533, 18.885584, 'Kujawsko-Pomorskie', 'Gruta', 'Piaseczno to urokliwy zbiornik o twardym piaszczystym dnie (stąd nazwa) i czystej wodzie. Akwen cechuje się regularną linią brzegową i głębokością do 10 metrów. To doskonała woda okoniowa, gdzie drapieżniki o jasnym ubarwieniu grupują się na piaszczystych skarpach.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81285, 'Jezioro Suchom', 'jezioro-suchom', 'LAKE', 53.555251, 18.14568, 'Kujawsko-Pomorskie', 'Lniano / Suchomie', 'Suchom to urokliwa, głęboka rynna polodowcowa położona w sercu kompleksu leśnego. Akwen charakteryzuje się twardym dnem i wodą o wysokiej przejrzystości. Maksymalna głębokość sięga 15-18 metrów. Brzegi są wysokie, porośnięte starym lasem sosnowym, co zapewnia osłonę przed wiatrem i unikatowy mikroklimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81286, 'Jezioro Bieszewskie', 'jezioro-bieszewskie', 'LAKE', 53.53503, 18.136196, 'Kujawsko-Pomorskie', 'Lniano / Błądzim', 'Jezioro Bieszewskie to malowniczy akwen rynnowy otoczony lasami i polami Kociewia. Posiada urozmaiconą batymetrię z wyraźnie zaznaczoną rynną środkową sięgającą 10-12 metrów. Dno jest piaszczysto-muliste. Woda posiada dobrą klasę czystości i jest dobrze natleniona dzięki otwartej ekspozycji na wiatr z kierunków zachodnich.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81287, 'Jezioro Czerwono', 'jezioro-czerwono', 'LAKE', 53.528451, 18.139758, 'Kujawsko-Pomorskie', 'Lniano / Błądzim', 'Czerwono to niewielki, kameralny zbiornik położony w bezpośrednim sąsiedztwie jeziora Bieszewskiego. Ma charakter bardziej eutroficzny, z dnem mulistym i bogatszą roślinnością brzegową. Maksymalna głębokość nie przekracza 5 metrów. Jezioro jest wyciszone, stanowiąc doskonałe miejsce dla ryb spokojnego żeru szukających schronienia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81288, 'Jezioro Mukrz', 'jezioro-mukrz', 'LAKE', 53.520372, 18.122938, 'Kujawsko-Pomorskie', 'Lniano / Mukrz', 'Jezioro Mukrz to jedna z pereł Borów Tucholskich (pow. ok. 40 ha), znana z krystalicznie czystej wody i bogatej populacji sielawy. Akwen charakteryzuje się monumentalną batymetrią – strome spady zaczynają się blisko brzegu i schodzą do rynny sięgającej blisko 20 metrów. Dno jest wybitnie twarde, piaszczysto-żwirowe. Brzegi są porośnięte lasem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81289, 'Osadnik Gajówka (Lazurowe Jezioro)', 'osadnik-gajowka', 'LAKE', 52.001746, 18.578396, 'Wielkopolskie', 'Turek / Przykona', 'Gajówka to sztuczny zbiornik po odkrywce węgla brunatnego, pełniący rolę osadnika popiołów. Słynie z niesamowitego, turkusowego koloru wody przypominającego Malediwy. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81290, 'Jezioro Ostrowite (k. Lniana)', 'jezioro-ostrowite-lniano', 'LAKE', 53.507084, 18.156025, 'Kujawsko-Pomorskie', 'Lniano / Ostrowite', 'Jezioro Ostrowite pod Lnianem to klasyczna rynna polodowcowa o powierzchni ok. 50 ha. Charakteryzuje się czystą wodą i twardym dnem piaszczystym w strefie przybrzeżnej. Maksymalna głębokość oscyluje wokół 12-14 metrów. Brzegi są wysokie i suche, w dużej mierze zalesione, co sprzyja rekreacji wędkarskiej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81291, 'Jezioro Dąbrowa', 'jezioro-dabrowa-lniano', 'LAKE', 53.504169, 18.143023, 'Kujawsko-Pomorskie', 'Lniano', 'Jezioro Dąbrowa to niewielki, kameralny zbiornik rynnowy położony niedaleko Lniana. Charakteryzuje się dnem piaszczysto-mulistym i średnią głębokością ok. 6-8 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest wyciszone, osłonięte od wiatru przez pas lasu, co nadaje mu intymny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81292, 'Jezioro Bładzimskie', 'jezioro-bladzimskie', 'LAKE', 53.494802, 18.150275, 'Kujawsko-Pomorskie', 'Lniano / Błądzim', 'Jezioro Bładzimskie to akwen rynnowy położony bezpośrednio przy miejscowości Błądzim. Zbiornik charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 5 metrów. Woda jest żyzna, co przekłada się na bogatą biomasę ryb karpiowatych. Brzegi są częściowo zagospodarowane, z licznymi pomostami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81293, 'Jezioro Branickie Duże', 'jezioro-branickie-duze', 'LAKE', 53.441142, 18.163404, 'Kujawsko-Pomorskie', 'Bukowiec / Branica', 'Jezioro Branickie Duże to rozległy akwen rynnowy (pow. ok. 70 ha) położony w pofałdowanym terenie rolniczo-leśnym. Charakteryzuje się urozmaiconą linią brzegową i dnem piaszczysto-mulistym. Maksymalna głębokość sięga 10-12 metrów. Woda posiada przyzwoitą przejrzystość wiosną. Brzegi są częściowo zalesione, z wieloma dzikimi stanowiskami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81294, 'Jezioro Szewińskie', 'jezioro-szewinskie', 'LAKE', 53.443008, 18.138127, 'Kujawsko-Pomorskie', 'Lniano / Branica', 'Jezioro Szewińskie to malowniczy zbiornik rynnowy (pow. ok. 35 ha) o bardzo regularnym kształcie i czystej wodzie. Akwen charakteryzuje się twardym dnem piaszczysto-żwirowym i rynną środkową sięgającą 12-14 metrów. Brzegi są wysokie i w całości zalesione, co zapewnia świetną osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81295, 'Jezioro Branickie Małe', 'jezioro-branickie-male', 'LAKE', 53.440145, 18.199581, 'Kujawsko-Pomorskie', 'Bukowiec / Branica', 'Branickie Małe to kameralny, płytki akwen o charakterze eutroficznym. Zbiornik jest zaciszny, z dnem wyścielonym grubą warstwą mułu i bogatą roślinnością brzegową. Maksymalna głębokość nie przekracza 4 metrów. Woda nagrzewa się szybko, co sprzyja rozwojowi narybku i czyni jezioro idealnym biotopem dla ryb ciepłolubnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81296, 'Jezioro Świętokwiatowe', 'jezioro-swietokwiatowe', 'LAKE', 53.419612, 18.083196, 'Kujawsko-Pomorskie', 'Świekatowo', 'Jezioro Świętokwiatowe to jeden z najgłębszych akwenów w rynnie świekatowskiej (max blisko 22 m). Charakteryzuje się krystalicznie czystą wodą i monumentalną batymetria – stoki opadają gwałtownie niemal od samej linii trzcin. Dno jest wybitnie twarde, krasowe, z unikatowymi formami polodowcowymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81297, 'Jezioro Duże Łaskie', 'jezioro-duze-laskie', 'LAKE', 53.399479, 18.071373, 'Kujawsko-Pomorskie', 'Świekatowo / Łaskie', 'Duże Łaskie to rozległy akwen rynnowy (pow. ok. 60 ha) o urozmaiconym ukształtowaniu dna. Posiada kilka wyraźnych przegłębień sięgających 12 metrów oraz rozległe piaszczyste blaty. Woda posiada przyzwoitą klasę czystości. Brzegi są zróżnicowane – od wysokich zalesionych skarp po dogodne piaszczyste dojścia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81298, 'Zbiornik Bogdałów', 'zbiornik-bogdalow', 'LAKE', 52.04699, 18.602214, 'Wielkopolskie', 'Turek / Brudzew', 'Bogdałów to zbiornik retencyjny powstały w wyrobisku poeksploatacyjnym. W przeciwieństwie do Gajówki, został w pełni zrekultywowany i zarybiony. Charakteryzuje się czystą wodą i piaszczystym dnem. Otoczony nowymi nasadzeniami leśnymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81299, 'Jezioro Piaseczno (k. Świekatowa)', 'jezioro-piaseczno-swiekatowo', 'LAKE', 53.385788, 18.067274, 'Kujawsko-Pomorskie', 'Świekatowo', 'Piaseczno pod Świekatowem to klasyczny akwen rynnowy o bardzo czystej wodzie i wybitnie twardym, piaszczystym dnie (stąd nazwa). Maksymalna głębokość oscyluje wokół 8-10 metrów. Jezioro charakteryzuje się bardzo rozwiniętą roślinnością podwodną, w tym rozległymi łąkami ramienicowymi na stokach rynny.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81300, 'Jezioro Rudzianek', 'jezioro-rudzianek', 'LAKE', 53.388986, 18.051138, 'Kujawsko-Pomorskie', 'Świekatowo', 'Rudzianek to niewielkie, urokliwe "oczko" leśne o charakterze dystroficzno-eutroficznym. Akwen charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i miękkim dnem wyścielonym osadami leśnymi. Maksymalna głębokość nie przekracza 5 metrów. Jezioro jest w całości otoczone lasem, co zapewnia absolutną ciszę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81301, 'Jezioro Rudno', 'jezioro-rudno-swiekatowo', 'LAKE', 53.382564, 18.043842, 'Kujawsko-Pomorskie', 'Świekatowo / Rudno', 'Jezioro Rudno to malownicza rynna o powierzchni ok. 30 ha, położona w pagórkowatym terenie. Charakteryzuje się twardym dnem piaszczysto-żwirowym i rynną środkową sięgającą 10-12 metrów. Woda jest czysta i dobrze natleniona. Brzegi są wysokie, częściowo porośnięte lasem mieszanym, co nadaje jezioru kameralny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81302, 'Jezioro Szukaj', 'jezioro-szukaj', 'LAKE', 53.371207, 18.071587, 'Kujawsko-Pomorskie', 'Pruszcz / Serock', 'Jezioro Szukaj to kameralny zbiornik rynnowy położony w ustronnym terenie wśród pól i lasów. Charakteryzuje się dość regularną linią brzegową i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 6-8 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest wyciszone, osłonięte od wiatru przez pas lasu, co sprzyja rozwojowi bujnej roślinności podwodnej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81303, 'Jezioro Płusczno (Pluszzno)', 'jezioro-pluszczno', 'LAKE', 53.360853, 18.069709, 'Kujawsko-Pomorskie', 'Pruszcz / Serock', 'Jezioro Płusczno (często nazywane Pluszzno) to potężna rynna polodowcowa (pow. ok. 40 ha) o monumentalnej głębokości sięgającej blisko 20-22 metrów. Woda charakteryzuje się wysoką przejrzystością i sielawowym charakterem. Dno jest wybitnie twarde, piaszczysto-żwirowe ze stromymi spadkami zaczynającymi się blisko brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81304, 'Jezioro Księże', 'jezioro-ksieze-serock', 'LAKE', 53.358216, 18.076426, 'Kujawsko-Pomorskie', 'Pruszcz / Serock', 'Księże to mniejszy, ustronny zbiornik o charakterze eutroficznym, położony w bezpośrednim sąsiedztwie jeziora Płusczno. Posiada miękkie dno i bogatą roślinność brzegową. Maksymalna głębokość nie przekracza 5-6 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez pagórkowaty teren, co sprzyja rozwojowi bujnego litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81305, 'Jezioro Święte (k. Serocka)', 'jezioro-swiete-serock', 'LAKE', 53.352787, 18.059506, 'Kujawsko-Pomorskie', 'Pruszcz / Serock', 'Jezioro Święte to jeden z najczystszych akwenów w rejonie Serocka (I/II klasa czystości). Posiada twarde, piaszczyste dno i wodę o wysokiej przejrzystości. Maksymalna głębokość sięga ok. 12-15 metrów. Jezioro charakteryzuje się sielawowym charakterem i bogatą roślinnością podwodną, w tym rozległymi łąkami ramienicowymi na spadkach dna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81306, 'Jezioro Zamkowe (k. Serocka)', 'jezioro-zamkowe-serock', 'LAKE', 53.348137, 18.043499, 'Kujawsko-Pomorskie', 'Pruszcz / Serock', 'Jezioro Zamkowe to malowniczy akwen położony przy miejscowości Serock. Zbiornik charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 6-8 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są częściowo zagospodarowane, z licznymi pomostami i plażami, co sprzyja rekreacji wędkarskiej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81307, 'Jezioro Lipkusz', 'jezioro-lipkusz', 'LAKE', 53.342663, 17.995391, 'Kujawsko-Pomorskie', 'Cekcyn / Gostycyn', 'Jezioro Lipkusz to klasyczna rynna polodowcowa, ukryta w gęstym kompleksie Borów Tucholskich. Akwen charakteryzuje się bardzo czystą wodą i twardym, piaszczysto-żwirowym dnem. Batymetria jest typowa dla regionu: strome spady zaczynają się blisko brzegu i schodzą do centralnej rynny sięgającej 15-18 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81308, 'Jezioro Krzywe (k. Cekcyna)', 'jezioro-krzywe-cekcyn', 'LAKE', 53.380369, 17.875013, 'Kujawsko-Pomorskie', 'Cekcyn', 'Jezioro Krzywe, zgodnie ze swoją nazwą, posiada bardzo rozwiniętą i krętą linię brzegową. Jest to głęboka rynna (max ok. 25 m) o sielawowym charakterze. Woda jest krystalicznie czysta, co sprzyja rozwojowi bujnej roślinności podwodnej (łąki ramienicowe) na płytszych blatach. Dno jest wybitnie twarde, piaszczyste.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81309, 'Jezioro Płotwickie', 'jezioro-plotwickie', 'LAKE', 53.371072, 17.870679, 'Kujawsko-Pomorskie', 'Cekcyn / Kruszka', 'Płotwickie to malowniczy, śródleśny zbiornik o charakterze rynnowym, połączony z systemem jeziora Krzywego. Akwen cechuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 10-12 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez wysokie skarpy porośnięte starym lasem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81310, 'Jezioro Piaseczno (k. Cekcyna)', 'jezioro-piaseczno-cekcyn', 'LAKE', 53.39193, 17.881579, 'Kujawsko-Pomorskie', 'Cekcyn', 'Jezioro Piaseczno pod Cekcynem to jeden z najczystszych akwenów w tej części Borów Tucholskich (I klasa czystości). Posiada wybitnie twarde, piaszczyste dno (stąd nazwa) i wodę o niesamowitej przejrzystości. Batymetria jest urozmaicona z rynną sięgającą 12-14 metrów. Jezioro charakteryzuje się sielawowym charakterem i bogatą roślinnością podwodną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81311, 'Jezioro Kruszyn', 'jezioro-kruszyn', 'LAKE', 53.472674, 18.906655, 'Kujawsko-Pomorskie', 'Gruta / Kruszyn', 'Niewielki, śródpolny zbiornik rynnowy. Posiada muliste dno i jest wyciszony, osłonięty od wiatru przez pasy drzew. To typowy matecznik lina i szczupaka leśnego. Dostęp do wody jest utrudniony przez szuwary, co zapewnia rybom spokój.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81312, 'Jezioro Stoczek', 'jezioro-stoczek-cekcyn', 'LAKE', 53.410225, 17.89175, 'Kujawsko-Pomorskie', 'Cekcyn / Małe Gacno', 'Stoczek to kameralny, śródleśny zbiornik o charakterze eutroficznym. Akwen jest stosunkowo płytki (max 5-6 m) z dnem wyścielonym osadami leśnymi i piaszczystymi łachami. Jezioro jest wybitnie wyciszone, stanowiąc doskonałe miejsce dla ryb spokojnego żeru szukających schronienia w gęstych pasach trzcin i lilii wodnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81313, 'Jezioro Krzywe Kolano', 'jezioro-krzywe-kolano', 'LAKE', 53.430042, 17.878532, 'Kujawsko-Pomorskie', 'Cekcyn / Krzywogoniec', 'Jezioro Krzywe Kolano to unikatowy pod względem kształtu zbiornik rynnowy, głęboko wcięty w pagórkowaty teren leśny. Posiada bardzo czystą wodę i twarde dno piaszczysto-żwirowe. Batymetria jest gwałtowna – rynna o głębokości do 10-12 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81314, 'Jezioro Kamieniec', 'jezioro-kamieniec-cekcyn', 'LAKE', 53.44604, 17.92192, 'Kujawsko-Pomorskie', 'Cekcyn / Ostrowo', 'Jezioro Kamieniec to malownicza rynna rynnowa charakteryzująca się – zgodnie z nazwą – licznymi partiami dna usianymi głazami narzutowymi i grubym żwirem. Maksymalna głębokość sięga 12 metrów. Woda jest dobrze natleniona i przejrzysta. Brzegi są wysokie, porośnięte lasem mieszanym, co zapewnia doskonałą osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81315, 'Jezioro Niedźwiedź (Nirdiwuec)', 'jezioro-niedzwiedz-cekcyn', 'LAKE', 53.44857, 17.923722, 'Kujawsko-Pomorskie', 'Cekcyn / Ostrowo', 'Jezioro Niedźwiedź (lokalnie notowane jako Nirdiwuec) to dziki akwen o charakterze dystroficzno-eutroficznym, położony w głębi kompleksu leśnego. Charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i bardzo miękkim dnem wyścielonym osadami organicznymi. Maksymalna głębokość nie przekracza 4-5 metrów. Brzegi są niskie i podmokłe, porośnięte mchem torfowcem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81316, 'Jezioro Muł', 'jezioro-mul', 'LAKE', 53.751353, 18.439157, 'Pomorskie', 'Osiek', 'Zgodnie z nazwą, akwen ten charakteryzuje się wybitnie miękkim, mulistym dnem. Jest to płytkie, silnie zarastające jezioro, stanowiące idealne siedlisko dla lina. Ryby te osiągają tu solidne rozmiary dzięki bogatej bazie pokarmowej.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81317, 'Jezioro Strzyżyny Wielkie', 'jezioro-strzyzyny-wielkie', 'LAKE', 53.457446, 17.926254, 'Kujawsko-Pomorskie', 'Cekcyn / Ostrowo', 'Strzyżyny Wielkie to rozległy akwen rynnowy (pow. ok. 50 ha) stanowiący istotny element rynny cekcyńskiej. Charakteryzuje się twardym dnem piaszczysto-żwirowym i głębokością sięgającą 12-14 metrów. Woda posiada wysoką klasę czystości. Brzegi są wysokie i w całości zalesione, co nadaje akwenowi dziki i surowy charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81318, 'Jezioro Okonińskie', 'jezioro-okoninskie', 'LAKE', 53.464547, 17.944837, 'Kujawsko-Pomorskie', 'Cekcyn / Okoniny Nadjeziorne', 'Jezioro Okonińskie to legenda Borów Tucholskich i jedno z najczystszych jezior w Polsce (I klasa czystości). Posiada krystalicznie czystą wodę (widoczność do 7-9 metrów) i wybitnie twarde, piaszczysto-kredowe dno. Batymetria jest monumentalna – stoki opadają gwałtownie do rynny sięgającej blisko 25 metrów. Brzegi są porośnięte majestatycznym borem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81319, 'Jezioro Boryny Wielkie', 'jezioro-boryny-wielkie', 'LAKE', 53.466667, 17.936769, 'Kujawsko-Pomorskie', 'Cekcyn / Ostrowo', 'Boryny Wielkie to malowniczy, śródleśny akwen o charakterze rynnowym. Posiada czystą wodę i pofałdowane dno piaszczysto-muliste. Maksymalna głębokość oscyluje wokół 10 metrów. Jezioro jest wyciszone i osłonięte od wiatrów, co sprzyja rozwojowi bujnej roślinności zanurzonej przy brzegach. Brzegi są wysokie, w całości zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81320, 'Jezioro Brajec', 'jezioro-brajec', 'LAKE', 52.181509, 16.106215, 'Wielkopolskie', 'Rakoniewice / Wioska', 'Brajec to kameralne, śródleśne "oczko" o charakterze wytopiskowym. Posiada muliste dno i przyzwoitą przejrzystość wody wiosną. Maksymalna głębokość nie przekracza 5-6 metrów. Jezioro jest w całości otoczone lasem, co zapewnia absolutną ciszę i ochronę przed wiatrem. Roślinność brzegowa jest gęsta i urozmaicona.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81321, 'Jezioro Boryny Małe', 'jezioro-boryny-male', 'LAKE', 53.471825, 17.945008, 'Kujawsko-Pomorskie', 'Cekcyn / Ostrowo', 'Boryny Małe to kameralny sąsiad Boryn Wielkich, o bardziej eutroficznym charakterze. Zbiornik jest stosunkowo płytki (max 5 m), z dnem wyścielonym grubą warstwą mułu i detrytusu. Jezioro jest silnie zarastające, co tworzy idealne warunki dla narybku i ryb ciepłolubnych. Brzegi są niskie i silnie zarośnięte trzciną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81322, 'Jezioro Minikowskie', 'jezioro-minikowskie', 'LAKE', 53.48557, 17.948141, 'Kujawsko-Pomorskie', 'Lubiewo / Minikowo', 'Jezioro Minikowskie to malowniczy zbiornik rynnowy położony w pofałdowanym terenie rolniczo-leśnym. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 6-8 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest otoczone pasem lasu od strony zachodniej, co zapewnia osłonę przed dominującymi wiatrami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81323, 'Jezioro Tymiec', 'jezioro-tymiec', 'LAKE', 53.490268, 17.953677, 'Kujawsko-Pomorskie', 'Lubiewo / Minikowo', 'Tymiec to niewielki, kameralny zbiornik rynnowy ukryty wśród wzgórz i kęp lasów. Akwen charakteryzuje się czystą wodą i twardym dnem w strefie przybrzeżnej. Maksymalna głębokość oscyluje wokół 7-8 metrów. Jezioro jest wyciszone, osłonięte od wiatru, co sprzyja rozwojowi bujnej roślinności zanurzonej. Brzegi są wysokie i suche.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81324, 'Jezioro Zamrzeńskie', 'jezioro-zamrzenskie', 'LAKE', 53.479648, 17.92089, 'Kujawsko-Pomorskie', 'Gostycyn / Zamrzenica', 'Jezioro Zamrzeńskie to malownicza rynna polodowcowa położona w bezpośrednim sąsiedztwie rzeki Brdy. Akwen charakteryzuje się twardym dnem i głębokością sięgającą 12-14 metrów. Woda jest przejrzysta, o wysokiej klasie czystości. Jezioro jest połączone systemem cieków z systemem Brdy, co sprzyja migracji ryb. Brzegi są wysokie, w dużej mierze zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81325, 'Jezioro Lucim', 'jezioro-lucim', 'LAKE', 53.507578, 17.960501, 'Kujawsko-Pomorskie', 'Koronowo / Lucim', 'Jezioro Lucim to głęboki akwen rynnowy położony na południowym skraju Borów Tucholskich. Charakteryzuje się bardzo czystą wodą i twardym, piaszczystym dnem. Batymetria jest urozmaicona, z wyraźnie zarysowaną rynną środkową sięgającą 18-20 metrów. Brzegi są wysokie i w dużej mierze zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81326, 'Jezioro Bysławskie', 'jezioro-byslawskie', 'LAKE', 53.51434, 17.993631, 'Kujawsko-Pomorskie', 'Lubiewo / Bysław', 'Jezioro Bysławskie to serce rekreacyjne gminy Lubiewo. Jest to zbiornik rynnowy o urozmaiconym dnie i maksymalnej głębokości ok. 12-15 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są częściowo zagospodarowane – od strony Bysławia znajdują się liczne pomosty, plaża i slipy dla łodzi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81327, 'Jezioro Gwiazda', 'jezioro-gwiazda-lubiewo', 'LAKE', 53.530618, 17.962046, 'Kujawsko-Pomorskie', 'Lubiewo', 'Gwiazda to kameralny, śródleśny zbiornik o charakterze rynnowym, ukryty w głębi kompleksu leśnego. Akwen cechuje się czystą wodą i twardym dnem piaszczysto-żwirowym. Batymetria jest regularna – rynna o głębokości do 9 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte starym lasem sosnowym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81328, 'Jezioro Drzycimskie', 'jezioro-drzycimskie', 'LAKE', 53.531153, 17.978482, 'Kujawsko-Pomorskie', 'Lubiewo / Drzycim', 'Jezioro Drzycimskie to malowniczy akwen rynnowy położony w pagórkowatym terenie leśno-polnym. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 10-12 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę dzięki otwartej ekspozycji na wiatr z kierunków zachodnich.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81329, 'Jezioro Skąpe (k. Gruty)', 'jezioro-skape-gruta', 'LAKE', 53.461207, 18.910775, 'Kujawsko-Pomorskie', 'Gruta / Słup', 'Jezioro Skąpe to płytki, zarastający akwen o charakterze eutroficznym. Dno jest wybitnie miękkie, wyścielone osadami organicznymi. To wymarzone miejsce dla miłośników lekkiego spławika i poszukiwaczy "złotych" karasi.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81330, 'Jezioro Dziuki', 'jezioro-dziuki', 'LAKE', 53.523704, 17.960329, 'Kujawsko-Pomorskie', 'Lubiewo', 'Jezioro Dziuki to niewielki, kameralny akwen o charakterze eutroficznym, położony w ustronnej dolinie leśnej. Dno jest w dużej mierze muliste, bogate w bentos, z licznymi skupiskami grążeli żółtych. Akwen jest wybitnie wyciszony, co sprzyja rozwojowi narybku i czyni go idealnym miejscem dla ryb ciepłolubnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81331, 'Jezioro Miały', 'jezioro-mialy', 'LAKE', 53.545054, 17.969084, 'Kujawsko-Pomorskie', 'Cekcyn / Miały', 'Jezioro Miały to rynnowy sąsiad Wielkiego Cekcyńskiego, połączony z nim okresowo wąskim ciekiem. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 4-6 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin, co ułatwia dostęp do lustra wody z brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81332, 'Jezioro Wielkie Cekcyńskie', 'jezioro-wielkie-cekcynskie', 'LAKE', 53.555784, 17.986121, 'Kujawsko-Pomorskie', 'Cekcyn', 'Jezioro Wielkie Cekcyńskie to jeden z najczystszych i najgłębszych akwenów w Borach Tucholskich (I klasa czystości). Posiada monumentalną batymetrię – dno opada stromo do rynny sięgającej blisko 28 metrów. Woda charakteryzuje się niesamowitą przejrzystością (widoczność do 6 metrów). Dno jest wybitnie twarde, piaszczysto-żwirowe. Brzegi są wysokie i zagospodarowane – od strony Cekcyna znajdują się mola, plaże i promenada.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81333, 'Jezioro Skąpe', 'jezioro-skape-cekcyn', 'LAKE', 53.57694, 18.002043, 'Kujawsko-Pomorskie', 'Cekcyn / Główka', 'Skąpe to malowniczy, śródleśny akwen rynnowy o bardzo wydłużonym kształcie. Posiada czystą wodę i twarde dno piaszczysto-żwirowe. Batymetria jest typowo rynnowa: ostre spady zaczynają się blisko brzegu i schodzą do centralnej rynny o głębokości ok. 15 metrów. Jezioro jest w całości otoczone lasem, co zapewnia osłonę przed wiatrem i intymną atmosferę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81334, 'Jezioro Główka', 'jezioro-glowka', 'LAKE', 53.577373, 18.007665, 'Kujawsko-Pomorskie', 'Cekcyn / Główka', 'Jezioro Główka to kameralny zbiornik rynnowy położony w bezpośrednim sąsiedztwie miejscowości o tej samej nazwie. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym w strefie litoralu. Maksymalna głębokość oscyluje wokół 8-10 metrów. Jezioro posiada bardzo urozmaiconą linię brzegową z licznymi półwyspami i powalonymi do wody drzewami, co stwarza wędkarzom wiele opcji wyboru stanowiska.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81335, 'Jezioro Chłodne', 'jezioro-chlodne', 'LAKE', 53.583308, 18.004661, 'Kujawsko-Pomorskie', 'Cekcyn / Okonino', 'Jezioro Chłodne to głęboki, ustronny zbiornik rynnowy ukryty w głębi kompleksu borów cekcyńskich. Zgodnie z nazwą, woda jest tu chłodniejsza niż w sąsiednich akwenach, co wynika z głębokości (do 15-18 m) i osłonięcia brzegów wysokimi skarpami zalesionymi starodrzewem. Dno jest wybitnie twarde, piaszczyste.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81336, 'Jezioro Zadworne', 'jezioro-zadworne', 'LAKE', 53.588177, 18.012428, 'Kujawsko-Pomorskie', 'Cekcyn / Okonino', 'Zadworne to malowniczy, rynnowy akwen położony w otulinie leśnej. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem w strefie przybrzeżnej. Maksymalna głębokość sięga 10-12 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są wysokie, w dużej mierze zalesione, co zapewnia osłonę przed wiatrem i nadaje jezioru kameralny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81337, 'Jezioro Okonino', 'jezioro-okonino', 'LAKE', 53.588737, 18.020024, 'Kujawsko-Pomorskie', 'Cekcyn / Okonino', 'Jezioro Okonino to klasyczna rynna polodowcowa, długa i wąska, wciśnięta w pofalowany krajobraz borów. Akwen charakteryzuje się twardym dnem piaszczysto-żwirowym i wyraźnie zarysowaną rynną środkową o głębokości do 12-14 metrów. Woda jest krystalicznie czysta i dobrze natleniona. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81338, 'Jezioro Mętne', 'jezioro-metne-cekcyn', 'LAKE', 53.595969, 18.011398, 'Kujawsko-Pomorskie', 'Cekcyn / Okonino', 'Jezioro Mętne to akwen o charakterze wybitnie dystroficzno-eutroficznym, położony w głębi kompleksu leśnego. Nazwa nawiązuje do specyficznego, mrocznego odcienia wody o zabarwieniu humusowym. Dno jest wybitnie miękkie, wyścielone osadami organicznymi i osadami leśnymi. Zbiornik jest stosunkowo płytki (max 4-5 m), z bogatą roślinnością zanurzoną. Brzegi są niskie i podmokłe.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81339, 'Jezioro Okoninek', 'jezioro-okoninek', 'LAKE', 53.594238, 18.031268, 'Kujawsko-Pomorskie', 'Cekcyn / Okonino', 'Okoninek to mniejszy, ustronny zbiornik o charakterze rynnowym, położony w bezpośrednim sąsiedztwie jeziora Okonino. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8-10 metrów biegnie przez środek jeziora. Brzegi są porośnięte lasem mieszanym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81340, 'Jezioro Wołyczek', 'jezioro-wolyczek', 'LAKE', 53.600489, 18.033071, 'Kujawsko-Pomorskie', 'Cekcyn / Krzywogoniec', 'Jezioro Wołyczek to kameralny, śródleśny zbiornik o charakterze rynnowym, położony w bezpośrednim sąsiedztwie Krzywogońca. Akwen posiada twarde dno w strefie litoralu i rynnę środkową sięgającą 6-8 metrów. Woda jest czysta i dobrze natleniona. Brzegi są wysokie i porośnięte starym lasem sosnowym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81341, 'Jezioro Krzywogoniec', 'jezioro-krzywogoniec', 'LAKE', 53.603353, 18.039722, 'Kujawsko-Pomorskie', 'Cekcyn / Krzywogoniec', 'Jezioro Krzywogoniec to malowniczy akwen rynnowy, znany jako centrum rekreacyjne wiosny tematycznej "Wioska Kwiatowa". Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 10-12 metrów. Brzegi są w większości dostępne, z licznymi pomostami i piaszczystymi plażami, co sprzyja rekreacji wędkarskiej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81342, 'Jezioro Szczuczanek', 'jezioro-szczuczanek', 'LAKE', 53.615136, 18.042581, 'Kujawsko-Pomorskie', 'Cekcyn / Główka', 'Szczuczanek to niewielki, ustronny zbiornik o charakterze eutroficznym, ukryty w głębi kompleksu borów tucholskich. Akwen posiada mroczną wodę o lekkim zabarwieniu humusowym i miękkie dno wyścielonym osadami organicznymi. Maksymalna głębokość nie przekracza 5 metrów. Brzegi są niskie i bagniste, co zapewnia rybom doskonałe warunki do tarła.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81343, 'Jezioro Gacanek', 'jezioro-gacanek', 'LAKE', 53.610179, 18.090127, 'Kujawsko-Pomorskie', 'Cekcyn / Wielkie Budziska', 'Jezioro Gacanek to urokliwy, śródleśny zbiornik o charakterze rynnowym. Akwen cechuje się twardym dnem piaszczysto-żwirowym i bardzo czystą wodą. Batymetria jest regularna – rynna o głębokości do 8-10 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem sosnowym, co nadaje akwenowi dziki i ustronny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81344, 'Jezioro Suchom (Sucham)', 'jezioro-suchom-lniano', 'LAKE', 53.554563, 18.147354, 'Kujawsko-Pomorskie', 'Lniano / Suchomie', 'Suchom (często notowane jako Sucham) to głęboka rynna polodowcowa położona w sercu kompleksu leśnego. Akwen charakteryzuje się wybitnie twardym dnem i wodą o wysokiej przejrzystości (I klasa czystości). Maksymalna głębokość sięga blisko 18-20 metrów. Brzegi są wysokie, porośnięte starodrzewem, co zapewnia osłonę przed wiatrem i unikatowy mikroklimat sielawowy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81345, 'Jezioro Mukrz', 'jezioro-mukrz-lniano', 'LAKE', 53.520374, 18.122828, 'Kujawsko-Pomorskie', 'Lniano / Mukrz', 'Jezioro Mukrz to hydrologiczna perła Borów Tucholskich, znana z krystalicznie czystej wody i bogatej populacji sielawy. Akwen posiada monumentalną batymetrię – strome spady zaczynają się blisko brzegu i schodzą do rynny o głębokości blisko 20 metrów. Dno jest wybitnie twarde, piaszczysto-żwirowe. Brzegi są porośnięte majestatycznym borem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81346, 'Jezioro Wielewskie', 'jezioro-wielewskie', 'LAKE', 53.922537, 17.83905, 'Pomorskie', 'Wiele / Karsin', 'Jezioro Wielewskie to perła południowych Kaszub, położona u stóp słynnej Kalwarii Wielewskiej. Jest to potężna rynna polodowcowa (pow. ok. 160 ha) o monumentalnej głębokości sięgającej 40 metrów. Woda posiada I klasę czystości i niesamowitą przejrzystość. Dno jest wybitnie twarde, piaszczysto-żwirowe ze stromymi spadkami zaczynającymi się tuż przy pomoście.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81347, 'Jezioro Blewicz', 'jezioro-blewicz', 'LAKE', 53.93345, 17.80695, 'Pomorskie', 'Wiele / Karsin', 'Jezioro Blewicz to kameralny, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8-10 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem sosnowym, co nadaje akwenowi dziki charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81348, 'Jezioro Głuchówko', 'jezioro-gluchowko', 'LAKE', 53.934338, 17.819159, 'Pomorskie', 'Wiele', 'Głuchówko to urokliwe, ustronne jezioro położone w zagłębieniu terenu wśród borów. Akwen charakteryzuje się czystą wodą i twardym dnem w strefie litoralu. Maksymalna głębokość oscyluje wokół 7-8 metrów. Jezioro jest wyciszone i osłonięte od wiatrów, co sprzyja rozwojowi bujnej roślinności podwodnej w płytkich zatokach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81349, 'Jezioro Swatki', 'jezioro-swatki', 'LAKE', 53.936674, 17.814996, 'Pomorskie', 'Wiele', 'Swatki to niewielkie "oczko" leśne o charakterze dystroficzno-eutroficznym, położone w ciągu jezior w pobliżu Wiela. Akwen charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i miękkim dnem. Maksymalna głębokość nie przekracza 5 metrów. Brzegi są niskie, silnie zarośnięte trzciną pospolitą, co zapewnia rybom absolutny spokój.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81350, 'Jezioro Małe Zmarłe', 'jezioro-male-zmarle', 'LAKE', 53.938972, 17.816777, 'Pomorskie', 'Wiele', 'Małe Zmarłe to hydrologiczny unikat – jezioro lobeliowe o niesamowitej krystaliczności wody. Posiada twarde, piaszczyste dno i bardzo ubogi litoral. Maksymalna głębokość sięga 8-10 metrów. Jezioro położone jest w głębokiej niecce leśnej, co chroni je przed wiatrem i stwarza niepowtarzalny mikroklimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81351, 'Jezioro Zmarłe Duże', 'jezioro-zmarle-duze-2', 'LAKE', 53.942922, 17.80755, 'Pomorskie', 'Wiele / Karsin', 'Jezioro Zmarłe Duże to jeden z najbardziej tajemniczych akwenów regionu. Legenda głosi, że jezioro "nie ma dna", w rzeczywistości jest to głęboka rynna sięgająca blisko 18-20 metrów. Woda jest krystalicznie czysta, a dno wybitnie twarde, piaszczysto-żwirowe. Brzegi są wysokie i porośnięte majestatycznym borem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81352, 'Jezioro Kły', 'jezioro-kly', 'LAKE', 53.94623, 17.786565, 'Pomorskie', 'Karsin / Młosino', 'Jezioro Kły to mały, śródleśny zbiornik o charakterze dystroficznym, ukryty głęboko w borach. Woda posiada mroczny, herbaciany odcień, a dno jest bardzo miękkie, wyścielone osadami leśnymi. Maksymalna głębokość nie przekracza 4-5 metrów. Brzegi są niskie, bagniste, porośnięte mchem torfowcem i żurawiną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81353, 'Jezioro Słowikowo', 'jezioro-slowikowo', 'LAKE', 52.513935, 17.937799, 'Wielkopolskie', 'Słowikowo', 'Ostatni zbiornik w ciągu słowikowskim. Charakteryzuje się mulistym dnem i bogatą roślinnością wynurzoną. Brzegi są niskie i częściowo podmokłe. Woda jest żyzna, co sprzyja biomasie ryb spokojnego żeru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81354, 'Jezioro Młosino Duże', 'jezioro-mlosino-duze', 'LAKE', 53.950421, 17.79459, 'Pomorskie', 'Karsin / Młosino', 'Młosino Duże to malownicza rynna polodowcowa, stanowiąca część systemu rzeki Wdy. Akwen charakteryzuje się czystą wodą i twardym dnem piaszczystym w strefie przybrzeżnej. Maksymalna głębokość sięga 12-14 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę dzięki przepływowi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81355, 'Jezioro Kały', 'jezioro-kaly', 'LAKE', 53.949743, 17.803001, 'Pomorskie', 'Karsin / Wiele', 'Jezioro Kały to kameralny, płytki akwen (max 3-4 m) o charakterze eutroficznym. Dno jest w dużej mierze muliste, bogate w bentos. Linia brzegowa jest silnie porośnięta trzciną i tatarakiem, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych. Woda szybko się nagrzewa, co sprzyja intensywnym żerowaniom lina i karasia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81356, 'Jezioro Brzeźno (k. Wiela)', 'jezioro-brzeźno-wiele', 'LAKE', 53.957274, 17.808473, 'Pomorskie', 'Wiele / Karsin', 'Jezioro Brzeźno to malowniczy akwen rynnowy położony w otulinie leśnej. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem w strefie litoralu. Maksymalna głębokość sięga 10-12 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są wysokie, w dużej mierze zalesione, co zapewnia osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81357, 'Jezioro Młosino Wielkie', 'jezioro-mlosino-wielkie', 'LAKE', 53.956517, 17.777381, 'Pomorskie', 'Karsin / Młosino', 'Jezioro Młosino Wielkie to potężna rynna polodowcowa (pow. ok. 100 ha). Charakteryzuje się monumentalną batymetrią – dno opada stromo do rynny centralnej sięgającej ponad 20 metrów. Woda posiada wysoką klasę czystości. Jezioro jest połączone systemem cieków z rzeką Wdą, co sprzyja migracji ryb. Brzegi są wysokie i w całości zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81358, 'Jezioro Raduń', 'jezioro-radun-karsin', 'LAKE', 53.966745, 17.771759, 'Pomorskie', 'Karsin / Raduń', 'Jezioro Raduń to rozległa (pow. ok. 100 ha) rynna polodowcowa, będąca ważnym punktem na szlaku rzeki Wdy. Charakteryzuje się twardym dnem i głębokością sięgającą blisko 25 metrów. Woda posiada dobrą klasę czystości i jest doskonale natleniona przez nurt rzeki. Brzegi są wysokie i porośnięte lasem mieszanym, z licznymi dzikimi stanowiskami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81359, 'Jezioro Wdydze', 'jezioro-wdydze', 'LAKE', 53.977697, 17.902565, 'Pomorskie', 'Wdzydze Kiszewskie / Kościerzyna', 'Jezioro Wdydze, zwane Kaszubskim Morzem, to potężny kompleks rynnowy (pow. ok. 1450 ha) o unikatowej strukturze krzyża. To jeden z najgłębszych akwenów w Polsce (max 68 m). Woda posiada I klasę czystości. Dno jest wybitnie urozmaicone – od ogromnych głębin po piaszczyste mielizny i liczne wyspy (największa to Wielki Ostrów).
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81360, 'Jezioro Palgorz', 'jezioro-palgorz', 'LAKE', 53.963221, 17.877803, 'Pomorskie', 'Wdzydze Tucholskie', 'Palgorz to malowniczy, śródleśny zbiornik o charakterze rynnowym, położony w otulinie jeziora Wdydze. Akwen cechuje się krystaliczną wodą i twardym dnem piaszczysto-żwirowym. Maksymalna głębokość oscyluje wokół 10-12 metrów. Brzegi są wysokie, porośnięte starym borem sosnowym, co nadaje jezioru intymny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81361, 'Jezioro Kociołek (k. Wdzydz)', 'jezioro-kociolek-wdydze', 'LAKE', 53.966249, 17.873039, 'Pomorskie', 'Wdzydze Tucholskie', 'Kociołek to niewielki, niemal okrągły akwen o charakterze wytopiskowym. Mimo małej powierzchni, jest to zbiornik głęboki (ok. 8 m) o bardzo czystej wodzie. Jezioro jest wyciszone, osłonięte od wiatru przez pagórkowaty teren zalesiony borem. Roślinność wodna jest skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81362, 'Jezioro Piaseczno (wdydzkie)', 'jezioro-piaseczno-wdydzkie', 'LAKE', 53.965909, 17.868426, 'Pomorskie', 'Wdzydze Tucholskie', 'Piaseczno to hydrologiczna perła wdzydzkiego kompleksu leśnego. Posiada wybitnie twarde, piaszczyste dno (stąd nazwa) i wodę o niesamowitej przejrzystości (I klasa). Maksymalna głębokość sięga ok. 10 metrów. Jezioro charakteryzuje się bogatą roślinnością podwodną, w tym rozległymi łąkami ramienicowymi na stokach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81363, 'Jezioro Syconki Małe', 'jezioro-syconki-male', 'LAKE', 53.970515, 17.855637, 'Pomorskie', 'Wdzydze / Karsin', 'Syconki Małe to kameralny, śródleśny akwen o charakterze eutroficznym. Zbiornik jest stosunkowo płytki (max 4-5 m), z dnem wyścielonym osadami leśnymi i bogatą roślinnością zanurzoną. Jezioro jest wybitnie wyciszone, osłonięte od wiatru przez wysokie skarpy porośnięte borami, co nadaje mu intymny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81364, 'Jezioro Syconki Wielkie', 'jezioro-syconki-wielkie', 'LAKE', 53.974125, 17.848481, 'Pomorskie', 'Wdzydze / Karsin', 'Syconki Wielkie to rynnowy sąsiad Małych Syconek, o większej powierzchni i bardziej urozmaiconym dnie. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 8-10 metrów. Jezioro posiada kilka wyraźnych przegłębień i dobrze natlenioną wodę. Brzegi są wysokie, w całości zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81365, 'Jezioro Motowęże', 'jezioro-motoweze', 'LAKE', 53.976396, 17.831122, 'Pomorskie', 'Karsin / Wiele', 'Jezioro Motowęże to dziki, śródleśny akwen rynnowy o bardzo urozmaiconej linii brzegowej. Charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i miękkim dnem. Maksymalna głębokość sięga 12-14 metrów. Jezioro jest wybitnie wyciszone, stanowiąc jedną z ostatnich enklaw dzikości w tej części regionu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81366, 'Jezioro Zmarłe Małe', 'jezioro-zmarle-male', 'LAKE', 53.973662, 17.871638, 'Pomorskie', 'Wdzydze Tucholskie', 'Zmarłe Małe to niewielka, ale monumentalnie głęboka rynna polodowcowa (max ok. 15-18 m). Akwen słynie z krystalicznie czystej wody i wybitnie twardego, piaszczysto-żwirowego dna. Jezioro położone jest w głębokiej niecce leśnej, co chroni je przed wiatrem. To typowe jezioro sielawowe o bardzo niskiej trofii.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81367, 'Jezioro Lipno (wdydzkie)', 'jezioro-lipno-wdydzkie', 'LAKE', 54.00709, 17.828751, 'Pomorskie', 'Lipusz / Wdzydze', 'Jezioro Lipno to malowniczy zbiornik rynnowy położony w północnej części kompleksu wdzydzkiego. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 8-10 metrów. Jezioro jest otoczone wianuszkiem lasów i pól, co sprzyja dobremu natlenieniu wody przez wiatr. Brzegi są w większości dostępne, z licznymi kładkami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81368, 'Jezioro Radalne', 'jezioro-radalne', 'LAKE', 54.014832, 17.900934, 'Pomorskie', 'Wdzydze Kiszewskie', 'Radalne to akwen rynnowy bezpośrednio połączony z głównym plosem jeziora Wdydze. Charakteryzuje się twardym dnem i głębokością sięgającą 12 metrów. Woda posiada wysoką klasę czystości. Jezioro stanowi istotną drogę migracji dla troci jeziorowej. Brzegi są wysokie, w dużej mierze zalesione, z wieloma dzikimi stanowiskami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81369, 'Jezioro Gołuń', 'jezioro-golun', 'LAKE', 54.006109, 17.942905, 'Pomorskie', 'Wdzydze Kiszewskie / Gołuń', 'Jezioro Gołuń to wschodnie ramię "Wdzydzkiego Krzyża" (pow. ok. 170 ha). Charakteryzuje się monumentalną batymetrią – dno opada do rynny sięgającej 19-20 metrów. Woda posiada dobrą klasę czystości. Brzegi są zagospodarowane turystycznie – od strony miejscowości Gołuń znajdują się liczne pomosty, plaże i bazy żeglarskie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81370, 'Jezioro Chądzie', 'jezioro-chadzie', 'LAKE', 53.997886, 18.002257, 'Pomorskie', 'Borsuk / Wdzydze', 'Chądzie to urokliwy, ustronny zbiornik rynnowy ukryty w głębi kompleksu borów wdzydzkich. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są porośnięte majestatycznym lasem sosnowym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81371, 'Jezioro Okonińskie', 'jezioro-okoninskie-2', 'LAKE', 53.443681, 18.893867, 'Kujawsko-Pomorskie', 'Gruta / Okonin', 'Malownicza rynna rynnowa charakteryzująca się czystą wodą i twardym podłożem. Maksymalna głębokość sięga 12 metrów. Brzegi są wysokie i w dużej mierze dostępne dla wędkarzy. Spinningiści cenią jezioro za populację sandacza i szczupaka.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81372, 'Jezioro Kotel', 'jezioro-kotel', 'LAKE', 54.012689, 18.012986, 'Pomorskie', 'Borsuk', 'Jezioro Kotel to niewielki, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde dno w strefie przybrzeżnej i rynnę sięgającą 6-7 metrów. Woda jest czysta i dobrze natleniona. Brzegi są wysokie i porośnięte lasem mieszanym, co nadaje jezioru kameralny charakter. Roślinność wodna jest umiarkowana, z przewagą rzadkich pasów trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81373, 'Jezioro Stryjek', 'jezioro-stryjek', 'LAKE', 54.012915, 18.000627, 'Pomorskie', 'Borsuk', 'Stryjek to kameralny, śródleśny zbiornik położony w bezpośrednim sąsiedztwie jeziora Kotel. Ma charakter eutroficzny, z dnem mulistym i bogatszą roślinnością brzegową. Maksymalna głębokość nie przekracza 5 metrów. Brzegi są niskie, silnie zarośnięte trzciną i tatarakiem, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81374, 'Jezioro Strupino', 'jezioro-strupino', 'LAKE', 54.03772, 17.982559, 'Pomorskie', 'Kościerzyna / Juszkowo', 'Jezioro Strupino to malowniczy akwen rynnowy położony w głębi kompleksu leśnego. Charakteryzuje się czystą wodą i twardym dnem piaszczysto-żwirowym. Maksymalna głębokość sięga 10-12 metrów. Jezioro posiada bardzo regularną linię brzegową i jest osłonięte od wiatru przez wysokie skarpy porośnięte starodrzewem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81375, 'Jezioro Strupinko', 'jezioro-strupinko', 'LAKE', 54.041178, 17.966874, 'Pomorskie', 'Kościerzyna / Juszkowo', 'Strupinko to kameralny, rynnowy sąsiad jeziora Strupino. Akwen cechuje się czystą wodą i twardym podłożem. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte lasem sosnowym, co zapewnia osłonę przed wiatrem i nadaje jezioru intymny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81376, 'Jezioro Białe (k. Juszkowa)', 'jezioro-biale-juszkowo', 'LAKE', 54.045274, 17.950845, 'Pomorskie', 'Kościerzyna / Juszkowo', 'Jezioro Białe pod Juszkowem to hydrologiczna perła regionu – akwen o charakterze lobeliowym z krystalicznie czystą wodą i jasnym, piaszczystym dnem. Maksymalna głębokość sięga ok. 10 metrów. Jezioro charakteryzuje się bardzo ubogim litoralem i brakiem dopływów, co przekłada się na niesamowitą przejrzystość.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81377, 'Jezioro Kramsko Małe', 'jezioro-kramsko-male', 'LAKE', 54.048153, 17.934494, 'Pomorskie', 'Kościerzyna / Kramsko', 'Kramsko Małe to urokliwy, śródleśny zbiornik o charakterze rynnowym. Posiada czystą wodę i twarde dno piaszczysto-żwirowe w strefie przybrzeżnej. Maksymalna głębokość oscyluje wokół 8-10 metrów. Jezioro jest wyciszone, osłonięte od wiatrów, co sprzyja rozwojowi bujnej roślinności zanurzonej w płytkich zatokach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81378, 'Jezioro Miałe', 'jezioro-miale-borsuk', 'LAKE', 54.049248, 17.927606, 'Pomorskie', 'Kościerzyna / Borsuk', 'Jezioro Miałe to niewielki, kameralny akwen o charakterze eutroficznym, położony w ustronnej dolinie leśnej. Dno jest w dużej mierze muliste, bogate w bentos, z licznymi skupiskami grążeli żółtych. Akwen jest wybitnie wyciszony, co sprzyja rozwojowi narybku i czyni go idealnym miejscem dla ryb ciepłolubnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81379, 'Jezioro Kocie', 'jezioro-kocie-2', 'LAKE', 54.051635, 17.911234, 'Pomorskie', 'Kościerzyna / Kramsko', 'Jezioro Kocie to malowniczy, dziki akwen położony w zagłębieniu terenu wśród borów. Charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i miękkim dnem wyścielonym osadami leśnymi. Maksymalna głębokość nie przekracza 5 metrów. Brzegi są niskie, silnie zarośnięte trzciną pospolitą i tatarakiem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81380, 'Długi Staw (Łagów)', 'dlugi-staw-lagow', 'LAKE', 51.176261, 15.063372, 'Dolnośląskie', 'Zgorzelec / Łagów', 'Wąski, wydłużony zbiornik o charakterze rynnowym, stanowiący część systemu wodnego pod Zgorzelcem. Dno jest urozmaicone, piaszczyste z warstwą mułu w najgłębszych miejscach. Maksymalna głębokość to ok. 3-4 metry.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81381, 'Jezioro Kramsko Duże', 'jezioro-kramsko-duze', 'LAKE', 54.05382, 17.938743, 'Pomorskie', 'Kościerzyna / Kramsko', 'Jezioro Kramsko Duże to rozległa rynna polodowcowa (pow. ok. 60 ha) stanowiąca główny akwen w rejonie miejscowości Kramsko. Charakteryzuje się twardym dnem i głębokością sięgającą 15 metrów. Woda posiada dobrą klasę czystości i jest dobrze natleniona. Brzegi są zróżnicowane – od wysokich zalesionych skarp po dogodne dojścia piaszczyste.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81382, 'Jezioro Mielsite', 'jezioro-mielsite', 'LAKE', 54.050107, 17.97698, 'Pomorskie', 'Kościerzyna / Juszkowo', 'Mielsite to niewielki zbiornik rynnowy położony w otulinie leśnej. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 6-8 metrów. Jezioro jest wyciszone, osłonięte od wiatru, co sprzyja rozwojowi bujnej roślinności zanurzonej. Brzegi są wysokie i porośnięte lasem mieszanym, co nadaje akwenowi dziki charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81383, 'Jezioro Głęboczka', 'jezioro-gleboczka', 'LAKE', 54.049956, 17.990155, 'Pomorskie', 'Kościerzyna / Juszkowo', 'Jezioro Głęboczka w pełni zasługuje na swoją nazwę – batymetria jest tu gwałtowna, a dno opada stromo do rynny sięgającej blisko 12-14 metrów. Woda jest krystalicznie czysta, o sielawowym charakterze. Dno jest wybitnie twarde, piaszczysto-żwirowe. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym, co nadaje akwenowi surowy, północny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81384, 'Jezioro Glinice', 'jezioro-glinice', 'LAKE', 54.05488, 17.987634, 'Pomorskie', 'Kościerzyna / Juszkowo', 'Glinice to kameralny, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i przejrzystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte borem sosnowym, co zapewnia ciszę i osłonę przed wiatrem. Roślinność wodna jest umiarkowana.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81385, 'Jezioro Długie (k. Juszkowa)', 'jezioro-dlugie-juszkowo', 'LAKE', 54.058474, 17.982237, 'Pomorskie', 'Kościerzyna / Juszkowo', 'Jezioro Długie pod Juszkowem to klasyczna rynna polodowcowa, długa i wąska. Akwen charakteryzuje się twardym dnem piaszczysto-żwirowym i wyraźnie zarysowaną rynną środkową o głębokości do 10 metrów. Woda jest czysta i dobrze natleniona. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym, co nadaje akwenowi dziki charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81386, 'Jezioro Oczko Duże', 'jezioro-oczko-duze', 'LAKE', 54.057047, 17.998266, 'Pomorskie', 'Kościerzyna / Juszkowo', 'Oczko Duże to niewielki, śródleśny zbiornik o charakterze eutroficznym. Zbiornik jest stosunkowo płytki (max 4-5 m), z dnem wyścielonym osadami leśnymi i bogatą roślinnością zanurzoną. Jezioro jest wybitnie wyciszone, osłonięte od wiatru przez wysokie skarpy porośnięte borami, co nadaje mu intymny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81387, 'Jezioro Oczko Małe', 'jezioro-oczko-male', 'LAKE', 54.055574, 18.003244, 'Pomorskie', 'Kościerzyna / Juszkowo', 'Oczko Małe to kameralny sąsiad Oczka Dużego, o bardziej eutroficznym charakterze. Zbiornik jest płytki (max 3 m), z dnem wyścielonym grubą warstwą mułu i detrytusu. Jezioro jest silnie zarastające, co tworzy idealne warunki dla narybku i ryb ciepłolubnych. Brzegi są niskie i silnie zarośnięte trzciną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81388, 'Jezioro Zakrzewie', 'jezioro-zakrzewie', 'LAKE', 54.052879, 18.010948, 'Pomorskie', 'Kościerzyna / Juszkowo', 'Jezioro Zakrzewie to malowniczy zbiornik rynnowy o wydłużonym kształcie, położony w otulinie leśnej. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem w strefie litoralu. Maksymalna głębokość sięga 8-10 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są wysokie, w dużej mierze zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81389, 'Staw Jeleni III', 'staw-jeleni-3', 'LAKE', 51.507515, 16.997802, 'Dolnośląskie', 'Żmigród / Ruda Sułowska', 'Trzeci ze stawów kompleksu Jeleni, położony najbardziej na wschód. Wykorzystywany w cyklu produkcyjnym Stawów Milickich. Bardzo płytki, z dnem wyścielonym grubą warstwą żyznych osadów organicznych. Ostoja ptactwa wodno-błotnego.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81390, 'Jezioro Drzędno', 'jezioro-drzedno', 'LAKE', 54.063068, 18.010068, 'Pomorskie', 'Kościerzyna / Juszkowo', 'Jezioro Drzędno to urokliwy, rynnowy akwen ukryty w głębi borów kaszubskich. Charakteryzuje się twardym, piaszczystym dnem w strefie litoralu i rynną środkową sięgającą 10-12 metrów. Woda posiada wysoką klasę czystości i jest dobrze natleniona. Brzegi są wysokie i w całości zalesione, co zapewnia świetną osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81391, 'Jezioro Płocice', 'jezioro-plocice-koscierzyna', 'LAKE', 54.083015, 17.962443, 'Pomorskie', 'Kościerzyna / Loryniec', 'Jezioro Płocice to malownicza rynna polodowcowa o powierzchni ok. 35 ha. Akwen charakteryzuje się czystą wodą i dnem piaszczysto-żwirowym. Maksymalna głębokość sięga 12-14 metrów. Jezioro jest otoczone majestatycznym lasem sosnowym, co nadaje mu surowy, północny charakter. Linia brzegowa jest dość regularna z wyraźnie zarysowanymi spadkami dna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81392, 'Jezioro Okrężyte', 'jezioro-okrezyte', 'LAKE', 54.090617, 17.953463, 'Pomorskie', 'Kościerzyna / Syba', 'Jezioro Okrężyte to niewielki, niemal okrągły zbiornik wytopiskowy położony w otulinie leśnej. Posiada twarde dno i przejrzystą wodę. Maksymalna głębokość nie przekracza 8-10 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez wysokie skarpy porośnięte starodrzewem, co sprzyja rozwojowi bujnej roślinności podwodnej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81393, 'Jezioro Osuczno', 'jezioro-osuczno', 'LAKE', 54.096199, 17.94445, 'Pomorskie', 'Kościerzyna / Syba', 'Osuczno to kameralny akwen o charakterze dystroficzno-eutroficznym, położony w głębi kompleksu leśnego. Charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i miękkim dnem wyścielonym osadami leśnymi. Maksymalna głębokość nie przekracza 5 metrów. Brzegi są niskie i podmokłe, silnie zarośnięte trzciną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81394, 'Jezioro Księże (k. Kościerzyny)', 'jezioro-ksieze-koscierzyna', 'LAKE', 54.094853, 17.96829, 'Pomorskie', 'Kościerzyna', 'Jezioro Księże to malowniczy zbiornik rynnowy położony na obrzeżach Kościerzyny. Charakteryzuje się dnem piaszczysto-mulistym i średnią głębokością ok. 6 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest otoczone pagórkowatym terenem, co sprzyja dobremu natlenieniu wody przez wiatr. Brzegi są w większości dostępne, z wieloma kładkami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81395, 'Jezioro Wierzysko', 'jezioro-wierzysko', 'LAKE', 54.104554, 17.988439, 'Pomorskie', 'Kościerzyna', 'Jezioro Wierzysko to akwen rynnowo-przepływowy, przez który przepływa rzeka Wierzyca. Posiada wydłużony kształt i urozmaicone dno z wyraźnie zaznaczonym korytem rzeki. Maksymalna głębokość sięga 8-10 metrów. Dzięki stałemu dopływowi świeżej wody, jezioro jest doskonale natlenione. Brzegi są częściowo zagospodarowane miejską infrastrukturą.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81396, 'Jezioro Kapliczne', 'jezioro-kapliczne', 'LAKE', 54.115956, 17.987409, 'Pomorskie', 'Kościerzyna', 'Jezioro Kapliczne to niewielki akwen miejski położony w samym centrum Kościerzyny. Zbiornik przeszedł w ostatnich latach proces rekultywacji, co znacznie poprawiło warunki tlenowe. Jest to jezioro płytkie (max 3 m) o dnie mulistym. Brzegi są w całości zagospodarowane – promenady, pomosty i oświetlone alejki sprzyjają wędkowaniu miejskiemu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81397, 'Jezioro Mielnica', 'jezioro-mielnica', 'LAKE', 54.093646, 17.915225, 'Pomorskie', 'Kościerzyna / Grzybowo', 'Mielnica to malownicza, wąska rynna polodowcowa ukryta w głębi borów. Akwen charakteryzuje się twardym dnem piaszczysto-żwirowym i głębokością sięgającą 12-14 metrów. Woda jest przejrzysta i chłodna. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym, co nadaje akwenowi dziki i ustronny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81398, 'Stary Staw (Żmigród)', 'stary-staw-zmigrod', 'LAKE', 51.522259, 16.99718, 'Dolnośląskie', 'Żmigród', 'Historyczny zbiornik hodowlany o urozmaiconym dnie. Słynie z populacji dużych ryb spokojnego żeru. Ze względu na wiek zbiornika, roślinność wynurzona jest tu bardzo dobrze rozwinięta, tworząc labirynt trzcinowisk idealny dla lina i szczupaka.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81399, 'Jezioro Załnowo', 'jezioro-zalnowo', 'LAKE', 54.085023, 17.894601, 'Pomorskie', 'Kościerzyna / Syba', 'Jezioro Załnowo to kameralny zbiornik rynnowy położony w pofałdowanym terenie leśnym. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym w strefie litoralu. Maksymalna głębokość oscyluje wokół 8-10 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są wysokie, porośnięte borem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81400, 'Jezioro Sominko', 'jezioro-sominko', 'LAKE', 54.078994, 17.880635, 'Pomorskie', 'Sominy', 'Sominko to rynnowe poszerzenie systemu rzeki Zbrzycy, położone w pobliżu miejscowości Sominy. Akwen posiada wydłużony kształt i twarde podłoże. Batymetria jest urozmaicona z rynną sięgającą 10-12 metrów. Woda posiada wysoką klasę czystości. Jezioro jest połączone z większym jeziorem Somińskim, co sprzyja migracji ryb drapieżnych i sandacza.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81401, 'Jezioro Babiniec', 'jezioro-babiniec', 'LAKE', 54.073644, 17.878296, 'Pomorskie', 'Sominy', 'Babiniec to niewielki, ustronny akwen o charakterze eutroficznym, położony w bezpośrednim sąsiedztwie Somin. Dno jest w dużej mierze muliste, bogate w bentos. Linia brzegowa jest silnie porośnięta trzciną i tatarakiem, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych. Woda szybko się nagrzewa, co sprzyja intensywnym żerowaniom lina.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81402, 'Jezioro Oczko (k. Somin)', 'jezioro-oczko-sominy', 'LAKE', 54.072385, 17.872224, 'Pomorskie', 'Sominy', 'Jezioro Oczko to kameralny, śródleśny zbiornik o charakterze wytopiskowym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem sosnowym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81403, 'Grzybowski Młyn (Rozlewisko)', 'grzybowski-mlyn-rozlewisko', 'LAKE', 54.07197, 17.889326, 'Pomorskie', 'Kościerzyna / Grzybowski Młyn', 'Rozlewisko Grzybowski Młyn to specyficzny akwen powstały w wyniku spiętrzenia wód rzeki Trzebiochy (dopływ Wdy). Posiada charakter wybitnie przepływowy z twardym, piaszczysto-kamienistym dnem w osi nurtu i mulistymi zatokami. Maksymalna głębokość oscyluje wokół 4-5 metrów. Woda jest doskonale natleniona i chłodna przez cały rok.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81404, 'Jezioro Czarne (k. Somin)', 'jezioro-czarne-sominy', 'LAKE', 54.069842, 17.862761, 'Pomorskie', 'Sominy', 'Jezioro Czarne pod Sominami to dziki, śródleśny akwen o charakterze dystroficzno-eutroficznym. Akwen charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i miękkim dnem wyścielonym osadami leśnymi. Maksymalna głębokość nie przekracza 5 metrów. Jezioro jest w całości otoczone lasem, co zapewnia absolutną ciszę i ochronę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81405, 'Jezioro Czyste (k. Somin)', 'jezioro-czyste-sominy', 'LAKE', 54.068193, 17.858598, 'Pomorskie', 'Sominy', 'Jezioro Czyste to jeden z najczystszych akwenów w rejonie Somin (I klasa czystości). Posiada wybitnie twarde, piaszczyste dno i wodę o niesamowitej przejrzystości (widoczność do 5-6 metrów). Maksymalna głębokość sięga ok. 10 metrów. Jezioro charakteryzuje się bardzo rozwiniętą roślinnością podwodną, w tym rozległymi łąkami ramienicowymi na stokach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81406, 'Jezioro Płocice (k. Grzybowa)', 'jezioro-plocice-grzybowo', 'LAKE', 54.077665, 17.85111, 'Pomorskie', 'Kościerzyna / Grzybowo', 'Jezioro Płocice to urokliwy akwen rynnowy położony w głębi borów, na północ od Somin. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 8-10 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez wysokie skarpy porośnięte starodrzewem, co sprzyja rozwojowi bujnej roślinności zanurzonej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81407, 'Jezioro Kulkówko', 'jezioro-kulkowko', 'LAKE', 54.08218, 17.854321, 'Pomorskie', 'Kościerzyna / Grzybowo', 'Kulkówko to kameralny, śródleśny zbiornik o charakterze wytopiskowym. Akwen cechuje się czystą wodą i twardym podłożem w strefie litoralu. Batymetria jest regularna – niecka o głębokości do 6-7 metrów. Brzegi są porośnięte majestatycznym lasem sosnowym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81408, 'Jezioro Czarne (k. Grzybowa)', 'jezioro-czarne-grzybowo', 'LAKE', 54.090108, 17.865486, 'Pomorskie', 'Kościerzyna / Grzybowo', 'Jezioro Czarne to dziki akwen o charakterze dystroficzno-eutroficznym, położony w głębi kompleksu leśnego. Charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i miękkim dnem wyścielonym osadami leśnymi. Maksymalna głębokość nie przekracza 5 metrów. Brzegi są niskie i podmokłe, porośnięte mchem torfowcem, co zapewnia rybom absolutny spokój.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81409, 'Jezioro Płocice Małe', 'jezioro-plocice-male', 'LAKE', 54.089756, 17.856538, 'Pomorskie', 'Kościerzyna / Syba', 'Płocice Małe to niewielki, płytki akwen (max 3-4 m) o charakterze eutroficznym, połączony systemem rowów z większymi zbiornikami. Dno jest w dużej mierze muliste, bogate w bentos. Linia brzegowa jest silnie porośnięta trzciną i tatarakiem, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81410, 'Jezioro Płocice Wielkie', 'jezioro-plocice-wielkie', 'LAKE', 54.092889, 17.861388, 'Pomorskie', 'Kościerzyna / Syba', 'Jezioro Płocice Wielkie to malownicza rynna o powierzchni ok. 30 ha, położona w otulinie leśnej. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem w strefie litoralu. Maksymalna głębokość sięga 12 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są wysokie i suche, porośnięte lasem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81411, 'Jezioro Mielno (k. Kościerzyny)', 'jezioro-mielno-koscierzyna', 'LAKE', 54.101987, 17.870979, 'Pomorskie', 'Kościerzyna / Syba', 'Mielno to malowniczy akwen rynnowy o wydłużonym kształcie. Charakteryzuje się czystą wodą i twardym podłożem. Batymetria jest urozmaicona z rynną sięgającą 15 metrów. Jezioro jest otoczone majestatycznym lasem, co zapewnia ciszę i osłonę przed wiatrem. Przez jezioro przepływa rzeka Trzebiocha, co zapewnia stały dopływ świeżej wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81412, 'Jezioro Sudomie', 'jezioro-sudomie', 'LAKE', 54.093432, 17.897844, 'Pomorskie', 'Kościerzyna / Łubiana', 'Jezioro Sudomie to jeden z najważniejszych akwenów rynnowych w dorzeczu Wdy (pow. ok. 110 ha). Charakteryzuje się monumentalną batymetrią – dno opada do rynny sięgającej 12-14 metrów. Woda posiada dobrą klasę czystości. Jezioro jest połączone systemem rzecznym z systemem Wdydz, co sprzyja migracji ryb. Brzegi są wysokie, w dużej mierze zalesione, z licznymi pomostami turystycznymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81413, 'Jezioro Graniczne', 'jezioro-graniczne-koscierzyna', 'LAKE', 54.114094, 17.878382, 'Pomorskie', 'Kościerzyna / Syba', 'Jezioro Graniczne to klasyczna rynna rynnowa charakteryzująca się twardym dnem piaszczysto-żwirowym i głębokością sięgającą 15 metrów. Woda jest przejrzysta i chłodna. Brzegi są wysokie, porośnięte lasem mieszanym, co zapewnia doskonałą osłonę przed wiatrem. Akwen stanowi naturalną barierę w krajobrazie leśnym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81414, 'Jezioro Garczyn (k. Kościerzyny)', 'jezioro-garczyn-koscierzyna', 'LAKE', 54.128954, 17.910547, 'Pomorskie', 'Kościerzyna / Garczyn', 'Jezioro Garczyn to rozległa (ok. 100 ha) rynna polodowcowa, znana z krystalicznie czystej wody (I klasa czystości). Charakteryzuje się twardym dnem i głębokością sięgającą blisko 15-18 metrów. Jezioro posiada sielawowy charakter. Brzegi są wysokie i porośnięte lasem mieszanym, z licznymi pomostami i bazami rekreacyjnymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81415, 'Staw Niezgoda I', 'staw-niezgoda-1', 'LAKE', 51.522262, 17.054129, 'Dolnośląskie', 'Niezgoda', 'Jeden z dwóch głównych stawów przy miejscowości Niezgoda. Akwen wybitnie płytki, o wyrównanym dnie. Jest to kluczowe miejsce lęgowe dla wielu gatunków kaczek i gęsi. Woda w stawie jest spuszczana cyklicznie w ramach gospodarki rybackiej (odłowy jesienne).', 'Stawy Milickie SA / Rezerwat');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81416, 'Jezioro Wieprznickie', 'jezioro-wieprznickie', 'LAKE', 54.151704, 17.922306, 'Pomorskie', 'Kościerzyna / Wieprznica', 'Wieprznickie to malowniczy zbiornik rynnowy położony na zachód od Kościerzyny. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i maksymalną głębokością ok. 10-12 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są urozmaicone – od wysokich zalesionych skarp po piaszczyste plaże i kładki wędkarskie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81417, 'Jezioro Długie Wielkie', 'jezioro-dlugie-wielkie', 'LAKE', 54.151026, 17.869906, 'Pomorskie', 'Kościerzyna / Gostomie', 'Jezioro Długie Wielkie to klasyczna rynna polodowcowa, długa i wąska, ukryta w gęstym kompleksie leśnym. Akwen charakteryzuje się twardym dnem piaszczysto-żwirowym i wyraźnie zarysowaną rynną środkową o głębokości do 14 metrów. Woda jest krystalicznie czysta i dobrze natleniona. Brzegi są wysokie i porośnięte majestatycznym borem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81418, 'Jezioro Borowe', 'jezioro-borowe-koscierzyna', 'LAKE', 54.155825, 17.855959, 'Pomorskie', 'Kościerzyna / Gostomie', 'Jezioro Borowe to kameralny, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Brzegi są porośnięte borem sosnowym (stąd nazwa), co zapewnia ciszę i osłonę przed wiatrem. Roślinność wodna jest umiarkowana.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81419, 'Jezioro Gostomskie', 'jezioro-gostomskie', 'LAKE', 54.157547, 17.825146, 'Pomorskie', 'Kościerzyna / Gostomie', 'Jezioro Gostomskie to rozległa (pow. ok. 60 ha) rynna polodowcowa, będąca sercem miejscowości Gostomie. Akwen charakteryzuje się czystą wodą i urozmaiconym dnem z wyraźnymi piaszczystymi skarpami. Maksymalna głębokość sięga 8-10 metrów. Brzegi są wysokie, w dużej mierze porośnięte lasem sosnowym, co nadaje jezioru kameralny klimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81420, 'Jezioro Sumino', 'jezioro-sumino-koscierzyna', 'LAKE', 54.173986, 17.783861, 'Pomorskie', 'Parchowo / Sumino', 'Jezioro Sumino to malownicza rynna o powierzchni ok. 45 ha, ukryta wśród borów kaszubskich. Akwen cechuje się krystaliczną wodą i twardym, piaszczysto-żwirowym dnem. Batymetria jest typowo rynnowa: ostre spady zaczynają się blisko brzegu i schodzą do centralnej rynny o głębokości ok. 15 metrów. Brzegi są porośnięte starym borem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81421, 'Jezioro Suminko', 'jezioro-suminko', 'LAKE', 54.183025, 17.79665, 'Pomorskie', 'Parchowo / Sumino', 'Suminko to mniejszy, rynnowy sąsiad jeziora Sumino, połączony z nim okresowo wąskim ciekiem. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8 metrów biegnie przez środek jeziora. Jezioro jest wybitnie wyciszone, osłonięte od wiatru przez wysokie skarpy porośnięte lasem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81422, 'Jezioro Kotynia', 'jezioro-kotynia', 'LAKE', 54.190972, 17.805576, 'Pomorskie', 'Parchowo', 'Jezioro Kotynia to kameralny, śródleśny zbiornik o charakterze rynnowym. Posiada twarde dno i wodę o wysokiej przejrzystości. Batymetria jest gwałtowna – rynna o głębokości do 10 metrów wcina się w pofałdowany teren leśny. Brzegi są wysokie i suche, porośnięte borem sosnowym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81423, 'Jezioro Ostrowickie', 'jezioro-ostrowickie-parchowo', 'LAKE', 54.206281, 17.823772, 'Pomorskie', 'Parchowo / Nakla', 'Ostrowickie to malowniczy zbiornik rynnowy o powierzchni ok. 30 ha. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość sięga 12 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są w większości porośnięte lasem mieszanym, z wieloma dzikimi stanowiskami wędkarskimi i kładkami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81424, 'Staw Niezgoda II', 'staw-niezgoda-2', 'LAKE', 51.528881, 17.062368, 'Dolnośląskie', 'Niezgoda', 'Sąsiad Stawu Niezgoda I, o podobnej charakterystyce. Szerokie pasy trzcin i tataraku otaczają niemal całe lustro wody. Dno wybitnie muliste, bogate w bentos. Zbiornik objęty ścisłą ochroną w ramach Rezerwatu Stawy Milickie.', 'Stawy Milickie SA / Rezerwat');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81425, 'Jezioro Czarne (k. Nakli)', 'jezioro-czarne-nakla', 'LAKE', 54.20884, 17.839222, 'Pomorskie', 'Parchowo / Nakla', 'Jezioro Czarne koło Nakli to dziki akwen o charakterze dystroficzno-eutroficznym, położony w głębi kompleksu leśnego. Charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i miękkim dnem wyścielonym osadami leśnymi. Maksymalna głębokość nie przekracza 5 metrów. Brzegi są niskie, porośnięte mchem torfowcem, co zapewnia rybom absolutny spokój.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81426, 'Jezioro Długie (k. Nakli)', 'jezioro-dlugie-nakla', 'LAKE', 54.211299, 17.848835, 'Pomorskie', 'Parchowo / Nakla', 'Jezioro Długie to klasyczna rynna polodowcowa, długa i wąska, wciśnięta w pofalowany krajobraz borów. Akwen charakteryzuje się twardym dnem piaszczysto-żwirowym i wyraźnie zarysowaną rynną środkową o głębokości do 14 metrów. Woda jest czysta i dobrze natleniona. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81427, 'Jezioro Gostkowo', 'jezioro-gostkowo', 'LAKE', 54.213924, 17.807207, 'Pomorskie', 'Parchowo', 'Jezioro Gostkowo to malowniczy akwen rynnowy położony w pofałdowanym terenie rolniczo-leśnym. Charakteryzuje się dnem piaszczysto-mulistym i średnią głębokością ok. 6-8 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest otoczone pasem lasu od strony zachodniej, co zapewnia osłonę przed dominującymi wiatrami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81428, 'Jezioro Guścierz Duży', 'jezioro-guscierz-duzy', 'LAKE', 54.221991, 17.798667, 'Pomorskie', 'Parchowo', 'Guścierz Duży to kameralny, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 10-12 metrów biegnie przez środek jeziora. Brzegi są porośnięte majestatycznym borem sosnowym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81429, 'Jezioro Guścierz Mały', 'jezioro-guscierz-maly', 'LAKE', 54.229064, 17.800469, 'Pomorskie', 'Parchowo', 'Guścierz Mały to mniejszy, ustronny sąsiad Guścierza Dużego. Ma charakter bardziej eutroficzny, z dnem mulistym i bogatszą roślinnością brzegową. Maksymalna głębokość nie przekracza 5 metrów. Brzegi są niskie, silnie zarośnięte trzciną i tatarakiem, co stwarza wyśmienite warunki dla lęgów ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81430, 'Jezioro Głębokie (k. Parchowa)', 'jezioro-glebokie-parchowo', 'LAKE', 54.217927, 17.775729, 'Pomorskie', 'Parchowo', 'Jezioro Głębokie koło Parchowa w pełni zasługuje na swoją nazwę – batymetria jest tu gwałtowna, a dno opada stromo do rynny sięgającej blisko 18-20 metrów. Woda jest krystalicznie czysta, o sielawowym charakterze. Dno jest wybitnie twarde, piaszczysto-żwirowe. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81431, 'Jezioro Egorzyna (Igorzyna)', 'jezioro-egorzyna', 'LAKE', 54.24211, 17.790728, 'Pomorskie', 'Parchowo / Jamnowy Młyn', 'Egorzyna (często notowana jako Igorzyna) to dziki, śródleśny akwen rynnowy o bardzo wydłużonym kształcie. Posiada czystą wodę i twarde dno piaszczysto-żwirowe. Batymetria jest typowo rynnowa: ostre spady zaczynają się blisko brzegu i schodzą do centralnej rynny o głębokości ok. 12-14 metrów. Jezioro jest w całości otoczone lasem, co zapewnia osłonę przed wiatrem i intymną atmosferę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81432, 'Jezioro Sarszyna', 'jezioro-sarszyna', 'LAKE', 54.241031, 17.771373, 'Pomorskie', 'Parchowo / Jamno', 'Jezioro Sarszyna to malowniczy, śródleśny akwen o charakterze rynnowym, położony w ustronnej dolinie. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym w strefie litoralu. Maksymalna głębokość oscyluje wokół 10 metrów. Jezioro posiada bardzo urozmaiconą linię brzegową z licznymi powalonymi do wody drzewami, co stwarza idealne kryjówki dla drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81433, 'Jezioro Moczadło', 'jezioro-moczadlo-parchowo', 'LAKE', 54.227563, 17.763112, 'Pomorskie', 'Parchowo', 'Moczadło to niewielki, kameralny akwen o charakterze eutroficznym, położony w otulinie leśnej. Zbiornik jest płytki (max 3-4 m), z dnem wyścielonym grubą warstwą mułu i detrytusu. Jezioro jest silnie zarastające, co tworzy idealne warunki dla narybku i ryb ciepłolubnych. Brzegi są niskie i silnie zarośnięte trzciną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81434, 'Jezioro Śmiertne', 'jezioro-smiertne', 'LAKE', 54.25723, 17.772338, 'Pomorskie', 'Sulęczyno', 'Jezioro Śmiertne to dziki, śródleśny akwen położony w głębi borów sulęczyńskich. Mimo mrocznej nazwy, jest to urokliwe jezioro o charakterze dystroficzno-eutroficznym z mroczną, herbacianą wodą. Dno jest wysoce muliste i bogate w bentos. Maksymalna głębokość nie przekracza 5-6 metrów. Brzegi są niskie, bagniste i porośnięte mchem torfowcem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81435, 'Jezioro Gowidlińskie', 'jezioro-gowidlinskie', 'LAKE', 54.295115, 17.792187, 'Pomorskie', 'Gowidlino / Sierakowice', 'Jezioro Gowidlińskie to jeden z największych i najważniejszych akwenów Pojezierza Kaszubskiego (pow. ok. 400 ha). Posiada wybitnie rynnowy charakter o długości blisko 7 km i maksymalnej głębokości ok. 27 metrów. Woda jest dobrze natleniona i posiada urozmaiconą strukturę dna z licznymi górkami podwodnymi i twardymi, gliniastymi skarpami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81436, 'Jezioro Długie (Gowidlino)', 'jezioro-dlugie-gowidlino', 'LAKE', 54.283757, 17.816541, 'Pomorskie', 'Gowidlino', 'Jezioro Długie to wąska rynna polodowcowa stanowiąca południowo-wschodnią odnogę systemu gowidlińskiego. Charakteryzuje się bardzo stromymi brzegami porośniętymi lasem i krystalicznie czystą wodą. Dno jest twarde, piaszczysto-żwirowe, a głębokość narasta gwałtownie do ok. 15-18 metrów. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81437, 'Jezioro Długisee (Długie Małe)', 'jezioro-dlugisee', 'LAKE', 54.286699, 17.816005, 'Pomorskie', 'Gowidlino', 'Długisee to niewielki, kameralny zbiornik rynnowy bezpośrednio sąsiadujący z jeziorem Długim. Akwen posiada twarde podłoże i bardzo czystą wodę. Batymetria jest regularna z głębokością do 10 metrów. Jezioro jest wybitnie wyciszone, osłonięte od wiatrów przez wysokie skarpy zalesione borem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81438, 'Jezioro Trzebocińskie', 'jezioro-trzebocinskie', 'LAKE', 54.287826, 17.811885, 'Pomorskie', 'Gowidlino / Podjazy', 'Jezioro Trzebocińskie to malownicza rynna położona w pagórkowatym terenie polno-leśnym. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 10-12 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i jest osłonięte od silnych wiatrów, co sprzyja rozwojowi bujnego litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81439, 'Jezioro Skrzynka (Gowidlino)', 'jezioro-skrzynka-gowidlino', 'LAKE', 54.293111, 17.824094, 'Pomorskie', 'Gowidlino', 'Skrzynka to kameralny zbiornik wytopiskowy położony w otulinie leśnej. Posiada twarde dno i przejrzystą wodę. Maksymalna głębokość nie przekracza 8 metrów. Jezioro jest wyciszone, stanowiąc doskonałe miejsce dla ryb spokojnego żeru szukających schronienia. Brzegi są porośnięte pasem olszy i brzozy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81440, 'Jezioro Pręgozyno', 'jezioro-pregozyno', 'LAKE', 54.299523, 17.83169, 'Pomorskie', 'Tuchlino', 'Jezioro Pręgozyno to urokliwy, śródleśny zbiornik o charakterze rynnowym. Akwen cechuje się krystaliczną wodą i twardym dnem piaszczysto-żwirowym. Batymetria jest regularna – rynna o głębokości do 12 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem sosnowym, co nadaje akwenowi dziki charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81441, 'Jezioro Tuchińskie', 'jezioro-tuchinskie', 'LAKE', 54.310377, 17.843471, 'Pomorskie', 'Tuchlino', 'Jezioro Tuchińskie to malowniczy akwen rynnowy (pow. ok. 30 ha) położony w otulinie leśnej. Charakteryzuje się czystą wodą i twardym, piaszczystym dnem w strefie litoralu. Maksymalna głębokość sięga 12-14 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są wysokie, w dużej mierze zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81442, 'Jezioro Chojnowe', 'jezioro-chojnowe', 'LAKE', 54.287865, 17.729402, 'Pomorskie', 'Podjazy / Gowidlino', 'Chojnowe to ustronna rynna polodowcowa położona na zachód od Gowidlina. Akwen posiada twarde dno i przejrzystą wodę. Batymetria jest typowo rynnowa: ostre spady zaczynają się blisko brzegu i schodzą do centralnej rynny o głębokości ok. 15 metrów. Jezioro jest w całości otoczone lasem, co zapewnia osłonę przed wiatrem i intymną atmosferę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81443, 'Jezioro Warlońskie', 'jezioro-warlonskie', 'LAKE', 54.290607, 17.735624, 'Pomorskie', 'Podjazy', 'Jezioro Warlońskie to kameralny zbiornik rynnowy położony w bezpośrednim sąsiedztwie miejscowości Podjazy. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym w strefie litoralu. Maksymalna głębokość oscyluje wokół 10 metrów. Jezioro posiada bardzo urozmaiconą linię brzegową z licznymi powalonymi do wody drzewami, co stwarza idealne kryjówki dla drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81444, 'Jezioro Ostrowickie (k. Podjazów)', 'jezioro-ostrowickie-podjazy', 'LAKE', 54.294365, 17.724402, 'Pomorskie', 'Podjazy', 'Jezioro Ostrowickie to malowniczy, rynnowy akwen ukryty w głębi borów kaszubskich. Charakteryzuje się twardym, piaszczystym dnem w strefie litoralu i rynną środkową sięgającą 12-14 metrów. Woda posiada wysoką klasę czystości i jest dobrze natleniona. Brzegi są wysokie i w całości zalesione, co zapewnia świetną osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81445, 'Jezioro Malinko', 'jezioro-malinko', 'LAKE', 54.296631, 17.735517, 'Pomorskie', 'Podjazy', 'Malinko to niewielki, kameralny zbiornik rynnowy ukryty wśród wzgórz i kęp lasów. Akwen charakteryzuje się czystą wodą i twardym dnem w strefie przybrzeżnej. Maksymalna głębokość oscyluje wokół 7-8 metrów. Jezioro jest wyciszone, osłonięte od wiatru, co sprzyja rozwojowi bujnej roślinności zanurzonej. Brzegi są wysokie i suche.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81446, 'Jezioro Trzemeszno (k. Gowidlina)', 'jezioro-trzemeszno-kaszuby', 'LAKE', 54.318177, 17.73453, 'Pomorskie', 'Sierakowice / Trzebun', 'Jezioro Trzemeszno to klasyczna rynna polodowcowa o powierzchni ok. 40 ha. Charakteryzuje się bardzo czystą wodą i twardym dnem piaszczystym. Batymetria jest monumentalna – stoki opadają gwałtownie do rynny sięgającej blisko 20 metrów. Brzegi są porośnięte majestatycznym borem sosnowym, co nadaje akwenowi dziki charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81447, 'Jezioro Rokitno', 'jezioro-rokitno-kaszuby', 'LAKE', 54.323533, 17.718115, 'Pomorskie', 'Sierakowice / Rokitki', 'Jezioro Rokitno to malowniczy, śródleśny akwen rynnowy położony w ustronnej dolinie. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym w strefie litoralu. Maksymalna głębokość oscyluje wokół 10 metrów. Jezioro posiada bardzo urozmaiconą linię brzegową z licznymi powalonymi do wody drzewami, co stwarza idealne kryjówki dla drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81448, 'Jezioro Miemino', 'jezioro-miemino', 'LAKE', 54.358334, 17.824373, 'Pomorskie', 'Sierakowice / Kamienica Król.', 'Jezioro Miemino to malowniczy, śródleśny akwen rynnowy położony w otulinie Lasów Mirachowskich. Posiada twarde dno i czystą wodę. Maksymalna głębokość sięga 8-10 metrów. Brzegi są wysokie i w całości zalesione, co zapewnia świetną osłonę przed wiatrem i kameralny charakter łowiska.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81449, 'Jezioro Trzcinowe', 'jezioro-trzcinowe-kaszuby', 'LAKE', 54.359009, 17.845788, 'Pomorskie', 'Sierakowice / Kamienica Król.', 'Trzcinowe to niewielki zbiornik o charakterze eutroficznym, charakteryzujący się – zgodnie z nazwą – szerokim pasem trzcinowisk otaczających całe lustro wody. Dno jest piaszczysto-muliste, o średniej głębokości ok. 4-5 metrów. Woda jest żyzna i szybko nagrzewa się wiosną, co stymuluje ryby do intensywnego żerowania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81450, 'Staw Duża Grabówka', 'staw-duza-grabowka', 'LAKE', 51.519989, 17.097731, 'Dolnośląskie', 'Niezgoda / Grabówka', 'Rozległy staw hodowlany położony w centralnej części kompleksu Grabówka. Słynie z tradycyjnej hodowli karpia milickiego. Lustro wody przerywane jest kępami trzcin, co stwarza doskonałe warunki dla szczupaka polującego z zasadzki.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81451, 'Jezioro Długie (k. Kamienicy)', 'jezioro-dlugie-kamienica', 'LAKE', 54.353584, 17.854671, 'Pomorskie', 'Kamienica Królewska', 'Jezioro Długie to klasyczna, wąska rynna polodowcowa, ukryta w głębokim parowie leśnym. Akwen cechuje się bardzo czystą wodą i twardym podłożem. Batymetria jest regularna – rynna o głębokości do 12 metrów biegnie przez środek jeziora. Brzegi są wysokie, porośnięte buczyną, co nadaje akwenowi surowy, północny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81452, 'Jezioro Kamienieckie', 'jezioro-kamienieckie', 'LAKE', 54.398273, 17.868662, 'Pomorskie', 'Kamienica Królewska', 'Jezioro Kamienieckie to jeden z najpiękniejszych akwenów w dolinie Kamienicy (pow. ok. 60 ha). Charakteryzuje się czystą wodą i twardym piaszczystym dnem w strefie litoralu. Maksymalna głębokość sięga 12-14 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są wysokie, w dużej mierze zalesione, z licznymi kładkami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81453, 'Jezioro Mielenko', 'jezioro-mielenko-kaszuby', 'LAKE', 54.394726, 17.859006, 'Pomorskie', 'Kamienica Królewska', 'Mielenko to mniejszy, rynnowy sąsiad jeziora Kamienieckiego, połączony z nim okresowo wąskim ciekiem. Akwen posiada twarde podłoże i czystą wodę. Batymetria jest regularna z głębokością do 8 metrów. Jezioro jest wyciszone, osłonięte od wiatrów przez wysokie skarpy zalesione borem sosnowym, co sprzyja rozwojowi bujnego litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81454, 'Jezioro Okonek', 'jezioro-okonek-kamienica', 'LAKE', 54.397448, 17.847033, 'Pomorskie', 'Kamienica Królewska', 'Okonek to kameralny, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8-10 metrów biegnie przez środek jeziora. Brzegi są porośnięte majestatycznym lasem, co zapewnia ciszę i osłonę przed wiatrem. Roślinność wodna jest umiarkowana.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81455, 'Jezioro Święte (k. Kamienicy)', 'jezioro-swiete-kamienica', 'LAKE', 54.408961, 17.850723, 'Pomorskie', 'Kamienica Królewska / Załakowo', 'Jezioro Święte koło Kamienicy to jeden z najczystszych akwenów regionu (I klasa czystości). Posiada twarde, piaszczyste dno i wodę o niesamowitej przejrzystości (widoczność do 5-6 metrów). Maksymalna głębokość sięga ok. 10 metrów. Jezioro charakteryzuje się sielawowym charakterem i bogatą roślinnością podwodną, w tym rozległymi łąkami ramienicowymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81456, 'Jezioro Junno', 'jezioro-junno', 'LAKE', 54.401201, 17.905784, 'Pomorskie', 'Mirachowo / Kamienica Król.', 'Jezioro Junno to potężna rynna polodowcowa (pow. ok. 100 ha) położona w samym sercu Lasów Mirachowskich. Posiada monumentalną batymetrię – dno opada stromo do rynny sięgającej blisko 30 metrów. Woda charakteryzuje się niesamowitą przejrzystością (I klasa) i sielawowym charakterem. Dno jest wybitnie twarde, piaszczysto-żwirowe.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81457, 'Jezioro Białe (Potęgowskie)', 'jezioro-biale-potegowskie', 'LAKE', 54.409466, 17.915826, 'Pomorskie', 'Linia / Potęgowo', 'Jezioro Białe to najbardziej na północ wysunięty akwen kompleksu Potęgowskiego. Słynie z wybitnie jasnego, piaszczystego dna i krystalicznie czystej wody (I klasa). Maksymalna głębokość sięga 15-18 metrów. Jezioro posiada sielawowy charakter i bardzo ubogi litoral, co przekłada się na niesamowitą przejrzystość toni.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81458, 'Jezioro Czarne (Potęgowskie)', 'jezioro-czarne-potegowskie', 'LAKE', 54.417708, 17.924538, 'Pomorskie', 'Linia / Potęgowo', 'Czarne to malownicza, głęboka rynna (max ok. 18 m) w kompleksie Potęgowskim. W przeciwieństwie do jeziora Białego, posiada mroczniejszy odcień wody wynikający z otoczenia lasami iglastymi i dopływu substancji humusowych. Dno jest wybitnie twarde, piaszczysto-żwirowe ze stromymi spadkami zaczynającymi się blisko brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81459, 'Staw Mała Mewa', 'staw-mala-mewa', 'LAKE', 51.528211, 17.099018, 'Dolnośląskie', 'Niezgoda / Grabówka', 'Kameralny staw o nazwie nawiązującej do licznie występujących tu ptaków. Akwen silnie zarastający, z mroczną, żyzną wodą. Stanowi naturalny filtr i tarlisko dla okolicznych systemów wodnych Baryczy.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81460, 'Jezioro Odnoga', 'jezioro-odnoga', 'LAKE', 54.413364, 17.933335, 'Pomorskie', 'Linia / Potęgowo', 'Jezioro Odnoga to specyficzna, boczna odnoga systemu jeziora Potęgowskiego, oddzielona od głównego plosa przewężeniem. Ma charakter nieco bardziej osłonięty i zaciszny. Dno jest piaszczysto-muliste, o średniej głębokości ok. 6-8 metrów. Roślinność wodna jest tu bardziej rozwinięta niż w sąsiednim jeziorze Białym, z rozległymi polami grążeli.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81461, 'Jezioro Frydek', 'jezioro-frydek', 'LAKE', 53.275586, 18.940516, 'Kujawsko-Pomorskie', 'Wąbrzeźno', 'Frydek to niewielki, ale bardzo rybny zbiornik położony na obrzeżach Wąbrzeźna. Służy głównie jako łowisko rekreacyjne dla mieszkańców. Dominują tu ryby spokojnego żeru: płoć, leszcz i regularnie zarybiany karp. Idealne na szybkie popołudniowe wędkowanie.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81462, 'Jezioro Potęgowskie', 'jezioro-potegowskie', 'LAKE', 54.419356, 17.939773, 'Pomorskie', 'Linia / Potęgowo', 'Jezioro Potęgowskie to serce kompleksu Lasów Mirachowskich (pow. ok. 130 ha). To monumentalna rynna polodowcowa o długości ponad 3 km i głębokości sięgającej 22 metrów. Woda posiada wysoką klasę czystości. Akwen charakteryzuje się bardzo urozmaiconym dnem z licznymi górkami podwodnymi i twardymi, gliniastymi skarpami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81463, 'Jezioro Folwarczne', 'jezioro-folwarczne', 'LAKE', 54.417234, 17.897115, 'Pomorskie', 'Mirachowo', 'Jezioro Folwarczne to akwen rynnowy położony w bezpośrednim sąsiedztwie Mirachowa. Charakteryzuje się dnem piaszczysto-mulistym i średnią głębokością ok. 5 metrów (max do 8 m). Woda posiada przyzwoitą klasę czystości. Brzegi są porośnięte rzadkim pasem trzcin, co ułatwia dostęp do lustra wody z brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81464, 'Jezioro Bukowskie', 'jezioro-bukowskie', 'LAKE', 54.366865, 17.951488, 'Pomorskie', 'Sierakowice / Mirachowo', 'Jezioro Bukowskie to głęboka, śródleśna rynna (pow. ok. 35 ha) położona w południowej części kompleksu Lasów Mirachowskich. Akwen cechuje się bardzo twardym, piaszczysto-żwirowym dnem i wodą o wysokiej klasie czystości. Maksymalna głębokość sięga 15-18 metrów. Brzegi są wysokie i w całości porośnięte buczyną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81465, 'Jezioro Bąckie', 'jezioro-backie', 'LAKE', 54.386456, 18.005047, 'Pomorskie', 'Bącz / Kartuzy', 'Jezioro Bąckie to malowniczy akwen rynnowy stanowiący element systemu hydrologicznego górnej Słupi. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 10-12 metrów. Brzegi są urozmaicone, z licznymi kładkami i stanowiskami wędkarskimi od strony miejscowości Bącz.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81466, 'Jezioro Wielkie (k. Mirachowa)', 'jezioro-wielkie-mirachowo', 'LAKE', 54.389654, 17.959085, 'Pomorskie', 'Mirachowo', 'Jezioro Wielkie to centralny punkt systemu rynnowego Lasów Mirachowskich (pow. ok. 60 ha). Charakteryzuje się monumentalną batymetrią – strome, piaszczyste spady schodzą do rynny o głębokości ok. 20 metrów. Woda posiada wysoką klasę czystości i sielawowy charakter. Brzegi są wysokie, porośnięte majestatycznym lasem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81467, 'Jezioro Lubygość', 'jezioro-lubygosc', 'LAKE', 54.411216, 17.985349, 'Pomorskie', 'Mirachowo / Staniszewo', 'Lubygość to jedno z najbardziej spektakularnych jezior Kaszub. Położone w głębokim wąwozie leśnym, przypomina jeziora alpejskie. Woda jest krystalicznie czysta (I klasa), a dno wybitnie twarde, usiane głazami narzutowymi (tzw. "kamienne dno"). Maksymalna głębokość sięga 15 metrów. Brzegi to niemal pionowe, zalesione skarpy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81468, 'Jezioro Okuniewko', 'jezioro-okuniewko', 'LAKE', 54.419879, 17.98183, 'Pomorskie', 'Mirachowo', 'Okuniewko to niewielki, kameralny zbiornik rynnowy ukryty w sercu rezerwatu "Kurze Grzędy". Posiada krystalicznie czystą wodę i bardzo twarde, piaszczyste dno. Maksymalna głębokość oscyluje wokół 8-10 metrów. Jezioro jest wybitnie wyciszone, stanowiąc doskonałe siedlisko dla ryb lubiących spokój i czyste podłoże.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81469, 'Staw Duża Mewa', 'staw-duza-mewa', 'LAKE', 53.537929, 17.108974, 'Dolnośląskie', 'Niezgoda', 'Większy ze stawów grupy "Mewa". Charakteryzuje się otwartym lustrem wody i piaszczysto-mulistym dnem w okolicach mnichów spustowych. Kluczowy punkt na mapie ornitologicznej regionu.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81470, 'Jezioro Kamienne (k. Mirachowa)', 'jezioro-kamienne-mirachowo', 'LAKE', 54.422051, 18.002944, 'Pomorskie', 'Mirachowo / Staniszewo', 'Jezioro Kamienne to unikatowy akwen wytopiskowy, którego nazwa pochodzi od gigantycznego głazu narzutowego leżącego na brzegu. Akwen charakteryzuje się bardzo czystą wodą i dnem wyścielonym żwirem oraz kamieniami polodowcowymi. Maksymalna głębokość sięga 10-12 metrów. Jezioro jest osłonięte wysokimi skarpami porośniętymi borem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81471, 'Jezioro Miłoszewskie', 'jezioro-miloszewskie', 'LAKE', 54.445601, 18.042529, 'Pomorskie', 'Strzepcz / Miłoszewo', 'Jezioro Miłoszewskie to legenda polskiego wędkarstwa karpiowego, ale także potężna rynna polodowcowa (pow. ok. 50 ha) o głębokości sięgającej 30 metrów. Woda posiada wysoką klasę czystości i sielawowy charakter. Dno jest wybitnie urozmaicone z licznymi półkami, uskokami i twardymi partiami piaszczysto-gliniastymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81472, 'Jezioro Lewinko', 'jezioro-lewinko', 'LAKE', 54.454285, 18.060493, 'Pomorskie', 'Lewino / Strzepcz', 'Lewinko to rynnowy sąsiad jeziora Miłoszewskiego, charakteryzujący się czystą wodą i twardym podłożem. Maksymalna głębokość sięga 12-14 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są wysokie i w dużej mierze zalesione, co zapewnia świetną osłonę przed wiatrem i intymny charakter łowienia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81473, 'Jezioro Strzepcz', 'jezioro-strzepcz', 'LAKE', 54.4601, 18.019359, 'Pomorskie', 'Strzepcz', 'Jezioro Strzepcz to rynnowy akwen położony przy miejscowości o tej samej nazwie. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 5-7 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są częściowo zagospodarowane, z licznymi pomostami i plażą wiejską, co sprzyja rekreacji wędkarskiej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81474, 'Jezioro Lubowidzkie', 'jezioro-lubowidzkie', 'LAKE', 54.554396, 17.825875, 'Pomorskie', 'Lębork / Lubowidz', 'Jezioro Lubowidzkie to największy akwen w rejonie Lęborka (pow. ok. 160 ha). Jest to potężna rynna polodowcowa o głębokości sięgającej 15-16 metrów. Woda posiada przyzwoitą klasę czystości i jest dobrze natleniona. Brzegi są urozmaicone – od zalesionych skarp po piaszczyste plaże i pomosty turystyczne. Jezioro jest połączone z systemem rzeki Lęborczycy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81475, 'Jezioro Dąbrze', 'jezioro-dabrze', 'LAKE', 54.655619, 17.961788, 'Pomorskie', 'Choczewo / Słajszewo', 'Jezioro Dąbrze to ustronny, płytki akwen położony w pasie nadmorskim, niedaleko Choczewa. Ma charakter eutroficzny, z dnem mulistym i bogatą roślinnością brzegową. Maksymalna głębokość nie przekracza 3-4 metrów. Woda szybko nagrzewa się wiosną. Brzegi są niskie, silnie zarośnięte trzciną i tatarakiem, co zapewnia rybom doskonałe warunki do tarła.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81476, 'Jezioro Myczkowskie', 'jezioro-myczkowskie', 'LAKE', 49.414179, 22.438331, 'Podkarpackie', 'Solina / Myczkowce', 'Jezioro Myczkowskie to mniejszy brat Soliny, pełniący funkcję zbiornika wyrównawczego. Charakteryzuje się bardzo niską temperaturą wody (zrzuty z dolnych partii zapory solińskiej) i wybitnie rzecznym charakterem. Dno jest kamienisto-żwirowe, w wielu miejscach pokryte osadami. Batymetria jest urozmaicona ze starym korytem Sanu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81477, 'Jezioro Mucharskie (Świnna Poręba)', 'jezioro-mucharskie', 'LAKE', 49.808307, 19.581242, 'Małopolskie', 'Wadowice / Mucharz', 'Jezioro Mucharskie to najmłodszy duży zbiornik zaporowy w Polsce, powstały na rzece Skawie. Akwen ma charakter górski z bardzo stromymi brzegami i głębokością sięgającą 40-45 metrów przy zaporze. Dno jest wybitnie twarde, usiane głazami i pozostałościami infrastruktury. Woda jest czysta i dobrze natleniona.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81478, 'Staw Prostokątny', 'staw-prostokatny', 'LAKE', 51.522256, 17.115111, 'Dolnośląskie', 'Niezgoda / Grabówka', 'Staw o regularnym, geometrycznym kształcie, co ułatwia prowadzenie prac hodowlanych i odłowy. Dno jest wyrównane, a brzegi umocnione faszyną. Typowa woda karpiowa o bardzo wysokiej wydajności biologicznej.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81479, 'Jezioro Żywieckie', 'jezioro-zywieckie', 'LAKE', 49.719718, 19.194489, 'Śląskie', 'Żywiec', 'Jezioro Żywieckie to największy akwen w kaskadzie rzeki Soły (pow. ok. 1000 ha). Posiada charakterystyczną dla zbiorników górskich batymetrię z wyraźnym korytem rzecznym i rozległymi płyciznami w rejonie ujścia Soły (tzw. "Cofka"). Maksymalna głębokość sięga 25-27 metrów. Dno jest zróżnicowane: od mulistego w zatoce moszczanickiej po kamieniste przy zaporze.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81480, 'Jezioro Zamkowe (Wąbrzeźno)', 'jezioro-zamkowe-wabrzezno', 'LAKE', 53.289437, 18.932791, 'Kujawsko-Pomorskie', 'Wąbrzeźno', 'Jezioro miejskie w Wąbrzeźnie, po rewitalizacji. Posiada charakter rekreacyjno-parkowy. Mimo miejskiego położenia, woda utrzymuje przyzwoitą jakość. To świetne łowisko okonia, który chętnie trzyma się okolic nowych pomostów i umocnień brzegowych.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81481, 'Jezioro Międzybrodzkie', 'jezioro-miedzybrodzkie', 'LAKE', 49.78614, 19.20496, 'Śląskie', 'Międzybrodzie Żywieckie', 'Jezioro Międzybrodzkie to środkowy stopień kaskady Soły, położony u stóp Góry Żar. Zbiornik jest węższy i bardziej "rzeczny" niż Żywieckie. Charakteryzuje się bardzo czystą wodą i twardym, kamienistym dnem. Batymetria jest stabilna, z głębokością do 15-18 metrów. Ze względu na elektrownię szczytowo-pompową, występują tu dobowe wahania poziomu wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81482, 'Jezioro Czanieckie', 'jezioro-czanieckie', 'LAKE', 49.827671, 19.219508, 'Śląskie', 'Czaniec / Kęty', 'Jezioro Czanieckie to ostatni, najniższy stopień kaskady Soły. Jest to zbiornik technologiczny o charakterze wody pitnej. Akwen jest stosunkowo płytki, z betonowymi umocnieniami brzegowymi. Ze względu na strategiczną funkcję ujęcia wody dla aglomeracji śląskiej, dostęp do zbiornika jest bardzo ograniczony.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81483, 'Jezioro Goczałkowickie', 'jezioro-goczalkowickie', 'LAKE', 49.927116, 18.862324, 'Śląskie', 'Pszczyna / Goczałkowice-Zdrój', 'Jezioro Goczałkowice, zwane "Śląskim Morzem", to potężny zbiornik zaporowy na Wiśle (pow. ok. 3200 ha). Jest to akwen stosunkowo płytki (średnio 5 m, max 14 m przy zaporze), ale o ogromnej powierzchni lustra wody. Dno jest mulisto-piaszczyste z licznymi karczowiskami w rejonie ujścia Wisły. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81484, 'Jezioro Młyńszczok (Zebrzydowice)', 'jezioro-mlynszczok', 'LAKE', 49.882691, 18.62041, 'Śląskie', 'Zebrzydowice', 'Młyńszczok to malowniczy akwen położony w centrum Zebrzydowic, będący poszerzeniem rzeki Piotrówki. Posiada charakter stawowy-parkowy z piaszczysto-mulistym dnem. Maksymalna głębokość nie przekracza 3-4 metrów. Woda posiada przyzwoitą przejrzystość wiosną. Brzegi są zagospodarowane – molo, ścieżki spacerowe i oświetlone alejki.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81485, 'Jezioro Rybnickie', 'jezioro-rybnickie', 'LAKE', 50.136701, 18.499861, 'Śląskie', 'Rybnik', 'Jezioro Rybnickie (Zalew Rybnicki) to unikat w skali kraju – zbiornik z wodą zrzutową z elektrowni, która nigdy nie zamarza (temperatura wody nawet zimą rzadko spada poniżej 10-12 stopni). Akwen rynnowy o powierzchni ok. 450 ha, z dnem piaszczysto-mulistym. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81486, 'Jezioro Pławniowice', 'jezioro-plawniowice', 'LAKE', 50.390845, 18.474712, 'Śląskie', 'Gliwice / Pławniowice', 'Jezioro Pławniowice to zbiornik poeksploatacyjny (powstały w wyrobisku piasku), włączony w system Kanału Gliwickiego. Charakteryzuje się bardzo twardym, piaszczystym dnem i głębokością sięgającą blisko 15-18 metrów. Woda posiada wysoką klasę czystości i krystaliczną przejrzystość wiosną. Brzegi są suche, z licznymi piaszczystymi plażami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81487, 'Jezioro Turawskie', 'jezioro-turawskie', 'LAKE', 50.722774, 18.119545, 'Opolskie', 'Opole / Turawa', 'Turawa to jeden z najważniejszych zbiorników zaporowych w Polsce (pow. ok. 2400 ha), powstały na rzece Mała Panew. Charakteryzuje się ogromnymi piaszczystymi blatami i wyraźnym starym korytem rzeki. Maksymalna głębokość przy zaporze to ok. 13 metrów. Poziom wody ulega znacznym wahaniom sezonowym, co odsłania rozległe karczowiska.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81488, 'Staw Środkowy', 'staw-srodkowy-grabowka', 'LAKE', 51.518933, 17.114146, 'Dolnośląskie', 'Niezgoda / Grabówka', 'Zbiornik łącznikowy w systemie Grabówki. Posiada twardsze dno w osi przepływu wody. Słynie z dorodnych linów i karasi srebrzystych, które znajdują tu idealne warunki do żerowania w miękkim osadzie organicznym.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81489, 'Jezioro Rybaty', 'jezioro-rybaty', 'LAKE', 51.337379, 17.718287, 'Wielkopolskie', 'Odolanów / Milicz', 'Jezioro Rybaty to kameralny akwen położony na pograniczu Wielkopolski i Dolnego Śląska, w dorzeczu Baryczy. Posiada charakter stawowy z dnem piaszczysto-mulistym. Maksymalna głębokość nie przekracza 3-4 metrów. Woda jest żyzna i dobrze natleniona. Brzegi są niskie, porośnięte gęstą trzciną, co stwarza idealne warunki dla ryb spokojnego żeru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81490, 'Jezioro Dolskie Wielkie', 'jezioro-dolskie-wielkie', 'LAKE', 51.98158, 17.038808, 'Wielkopolskie', 'Dolsk', 'Dolskie Wielkie to malownicza rynna polodowcowa (pow. ok. 140 ha) położona bezpośrednio przy miejscowości Dolsk. Akwen charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 3-4 metrów (max do 6 m). Woda jest wybitnie żyzna. Brzegi są zagospodarowane miejską infrastrukturą, z licznymi pomostami i plażą.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81491, 'Jezioro Brzednia', 'jezioro-brzednia', 'LAKE', 51.987578, 17.013187, 'Wielkopolskie', 'Dolsk / Brzednia', 'Jezioro Brzednia to rynnowy sąsiad jeziora Dolskiego, charakteryzujący się bardziej ustronnym i dzikim charakterem. Akwen cechuje się dnem mulistym z piaszczystymi łachami w strefie przybrzeżnej. Maksymalna głębokość oscyluje wokół 5 metrów. Brzegi są w większości porośnięte lasem sosnowym, co zapewnia świetną osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81492, 'Jezioro Grzymisławskie', 'jezioro-grzymislawskie', 'LAKE', 52.046051, 17.033615, 'Wielkopolskie', 'Śrem', 'Grzymisławskie to potężna rynna polodowcowa (pow. ok. 180 ha) będąca centrum rekreacyjnym Śremu. Charakteryzuje się urozmaiconą batymetrią z głębokością sięgającą 11-12 metrów. Dno jest piaszczysto-muliste. Woda posiada przyzwoitą przejrzystość wiosną. Brzegi są w dużej mierze zagospodarowane, z licznymi pomostami i marinami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81493, 'Jezioro Nórka', 'jezioro-norka', 'LAKE', 52.009036, 16.949844, 'Wielkopolskie', 'Krzywiń / Mościszki', 'Nórka to kameralny zbiornik rynnowy położony w ustronnym terenie rolniczo-leśnym. Posiada piaszczysto-muliste dno i średnią głębokość ok. 3-4 metrów. Jezioro jest wyciszone, osłonięte od silnych wiatrów przez pagórkowaty teren, co sprzyja rozwojowi bujnej roślinności zanurzonej. Woda szybko nagrzewa się wiosną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81494, 'Jezioro Zbęchy', 'jezioro-zbechy', 'LAKE', 52.007451, 16.913109, 'Wielkopolskie', 'Krzywiń / Zbęchy', 'Jezioro Zbęchy to malowniczy, płytki akwen rynnowy (pow. ok. 100 ha). Posiada charakter wybitnie eutroficzny z dnem wyścielonym osadami organicznymi. Maksymalna głębokość nie przekracza 4-5 metrów. Woda jest wysoce żyzna i bogata w bentos. Brzegi są niskie, silnie zarośnięte szerokim pasem trzcinowisk, stanowiącym ostoję dla ptactwa wodnego.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81495, 'Jezioro Drzeczkowskie', 'jezioro-drzeczkowskie', 'LAKE', 51.930538, 16.685958, 'Wielkopolskie', 'Osieczna / Drzeczkowo', 'Drzeczkowskie to akwen rynnowy wchodzący w skład systemu hydrologicznego rzeki Samicy i zbiornika Wonieść. Charakteryzuje się mulistym dnem i średnią głębokością ok. 2-3 metrów. Jezioro jest połączone systemem kanałów z sąsiednimi akwenami, co sprzyja stałej migracji ryb. Brzegi są silnie zarośnięte trzciną pospolitą.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81496, 'Jezioro Witosławskie', 'jezioro-witoslawskie', 'LAKE', 51.941595, 16.7066, 'Wielkopolskie', 'Osieczna / Witosław', 'Jezioro Witosławskie to malownicza rynna polodowcowa o powierzchni ok. 50 ha. Akwen charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i maksymalną głębokością ok. 5 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są urozmaicone – od zalesionych skarp po piaszczyste dojścia przy miejscowości Witosław.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81497, 'Jezioro Bochenek', 'jezioro-bochenek', 'LAKE', 52.520296, 16.170802, 'Wielkopolskie', 'Kwilcz / Lubosz', 'Bochenek to kameralne "oczko" o charakterze wytopiskowym, ukryte wśród pól i zagajników. Akwen jest stosunkowo płytki, z miękkim dnem i bogatą roślinnością brzegową. Jezioro jest wybitnie wyciszone, stanowiąc doskonałe siedlisko dla ryb lubiących spokój.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81498, 'Jezioro Wojnowickie', 'jezioro-wojnowickie', 'LAKE', 51.946329, 16.719861, 'Wielkopolskie', 'Osieczna / Wojnowice', 'Wojnowickie to rynnowe przedłużenie systemu jezior osieckich. Charakteryzuje się dnem piaszczysto-mulistym i średnią głębokością ok. 3-4 metrów. Woda jest żyzna i dobrze natleniona. Brzegi są częściowo porośnięte lasem mieszanym, z wieloma dzikimi stanowiskami wędkarskimi i kładkami od strony miejscowości Wojnowice.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81499, 'Jezioro Jezierzyckie', 'jezioro-jezierzyckie', 'LAKE', 51.981856, 16.710291, 'Wielkopolskie', 'Lipno / Jezierzyce', 'Jezioro Jezierzyckie to akwen stanowiący część cofki zbiornika zaporowego Wonieść. Charakteryzuje się wybitnie przepływowym charakterem z twardym dnem w osi nurtu Samicy i mulistymi zatokami. Maksymalna głębokość nie przekracza 3 metrów. Dzięki stałemu ruchowi wody, jezioro jest świetnie natlenione, co sprzyja biomasie ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81500, 'Jezioro Wonieskie (Zbiornik Wonieść)', 'jezioro-wonieskie', 'LAKE', 52.007586, 16.689348, 'Wielkopolskie', 'Kościan / Wonieść', 'Wonieść to jeden z największych systemów retencyjnych w Wielkopolsce (pow. ok. 770 ha), powstały przez spiętrzenie kilku jezior rynnowych na rzece Samicy. Charakteryzuje się ogromną powierzchnią płytkich blatów i głębokością sięgającą 4-5 metrów przy zaporze. Dno jest wysoce zróżnicowane – od twardych piasków po grube pokłady mułu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81501, 'Jezioro Dominickie', 'jezioro-dominickie', 'LAKE', 51.949885, 16.313839, 'Wielkopolskie', 'Boszkowo / Wschowa', 'Jezioro Dominickie to najpopularniejszy i najczystszy akwen Pojezierza Leszczyńskiego (pow. ok. 350 ha). Słynie z krystalicznej wody (I klasa) i piaszczystego dna. Maksymalna głębokość sięga 17 metrów. Jezioro charakteryzuje się bardzo łagodnym spadkiem dna w strefie brzegowej, co czyni je idealnym dla rodzin, ale wędkarze muszą szukać ryb dalej od brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81502, 'Jezioro Sitno (k. Wąbrzeźna)', 'jezioro-sitno-wabrzezno', 'LAKE', 53.285615, 18.963518, 'Kujawsko-Pomorskie', 'Wąbrzeźno / Sitno', 'Sitno to malowniczy, czysty akwen o piaszczystym dnie, popularny wśród wędkarzy i nurków. Posiada urozmaiconą linię brzegową i pasy twardych trzcinowisk. Słynie z walecznego szczupaka i pięknej płoci sielawowej, poławianej na większych głębokościach.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81503, 'Jezioro Zapowiednik', 'jezioro-zapowiednik', 'LAKE', 51.919666, 16.304913, 'Wielkopolskie', 'Brenno / Wijewo', 'Zapowiednik to mały, śródleśny zbiornik o charakterze wytopiskowym. Posiada muliste dno i przyzwoitą przejrzystość wody. Maksymalna głębokość nie przekracza 5 metrów. Jezioro jest w całości otoczone lasem, co zapewnia absolutną ciszę i ochronę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81504, 'Jezioro Miałkie', 'jezioro-mialkie-przemet', 'LAKE', 51.933159, 16.235647, 'Wielkopolskie', 'Olejnica / Przemęt', 'Jezioro Miałkie to wybitnie płytki zbiornik (max 2 m) o charakterze eutroficznym, stanowiący część systemu Szlaku Konwaliowego. Dno jest wysoce muliste i bogate w bentos. Jezioro jest silnie zarastające, z ogromnymi polami lilii wodnych i grążeli, co czyni je idealnym biotopem dla ryb ciepłolubnych i ptactwa wodnego.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81505, 'Jezioro Trzytoniowe', 'jezioro-trzytoniowe', 'LAKE', 51.938026, 16.197796, 'Wielkopolskie / Lubuskie', 'Brenno / Wieleń', 'Jezioro Trzytoniowe to malownicza rynna położona na granicy województw. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 6-8 metrów. Jezioro jest wyciszone i osłonięte od silnych wiatrów. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin, co ułatwia dostęp do wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81506, 'Jezioro Wielińskie', 'jezioro-wielinskie', 'LAKE', 51.947493, 16.195564, 'Wielkopolskie / Lubuskie', 'Wieleń', 'Jezioro Wielińskie to akwen rynnowy położony przy miejscowości Wieleń. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 5 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są częściowo zagospodarowane turystycznie – od strony Wielenia znajdują się liczne pomosty, plaża i bazy rekreacyjne.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81507, 'Staw Grabówka Mały', 'staw-grabowka-maly', 'LAKE', 51.519213, 17.108481, 'Dolnośląskie', 'Niezgoda / Grabówka', 'Mniejszy staw wchodzący w skład kompleksu Grabówka. Wybitnie linowa woda. Brzegi są niskie, silnie zarośnięte wierzbami, co zapewnia rybom cień i osłonę w upalne letnie dni.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81508, 'Jezioro Sławskie', 'jezioro-slawskie', 'LAKE', 51.891227, 16.006565, 'Lubuskie', 'Sława', 'Jezioro Sławskie, zwane "Śląskim Morzem", to potężny akwen rynnowy (pow. ok. 820 ha). Mimo dużej powierzchni, jest stosunkowo płytkie (średnio 5 m, max 12 m). Charakteryzuje się bardzo rozwiniętą linią brzegową z licznymi wyspami, zatokami i półwyspami. Dno jest piaszczysto-muliste, bogate w bentos.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81509, 'Jezioro Tarnowskie Duże', 'jezioro-tarnowskie-duze', 'LAKE', 51.863038, 15.977297, 'Lubuskie', 'Sława / Tarnów Jezierny', 'Tarnowskie Duże to malownicza rynna (pow. ok. 90 ha) położona w bezpośrednim sąsiedztwie Sławy. Akwen charakteryzuje się czystą wodą i twardym dnem piaszczysto-żwirowym. Maksymalna głębokość sięga 15 metrów. Brzegi są wysokie i porośnięte majestatycznym lasem sosnowym, co zapewnia osłonę przed wiatrem i unikatowy mikroklimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81510, 'Jezioro Błotne (k. Sławy)', 'jezioro-blotne-slawa', 'LAKE', 51.86272, 15.997639, 'Lubuskie', 'Sława', 'Jezioro Błotne to akwen o charakterze wybitnie eutroficznym, położony w zagłębieniu terenu. Nazwa jest nieco myląca, gdyż woda posiada przyzwoitą czystość, jednak dno jest wybitnie miękkie, wyścielone grubą warstwą osadów organicznych. Zbiornik jest płytki (max 3 m), z bogatą roślinnością zanurzoną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81511, 'Jezioro Tarnowskie Małe', 'jezioro-tarnowskie-male', 'LAKE', 51.853552, 16.007338, 'Lubuskie', 'Sława / Tarnów Jezierny', 'Tarnowskie Małe to kameralny sąsiad Tarnowskiego Dużego. Charakteryzuje się mulistym dnem i średnią głębokością ok. 4 metrów. Jezioro jest wyciszone, osłonięte od wiatru, co sprzyja rozwojowi bujnej roślinności brzegowej. Woda szybko nagrzewa się wiosną, co stymuluje ryby do intensywnego żerowania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81512, 'Jezioro Młyńskie Duże', 'jezioro-mlynskie-duze-slawa', 'LAKE', 51.852964, 16.021628, 'Lubuskie', 'Sława / Tarnów Jezierny', 'Młyńskie Duże to akwen o charakterze rynnowym z dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 6-7 metrów. Woda posiada przyzwoitą przejrzystość wiosną. Brzegi są w większości dostępne, z licznymi stanowiskami wędkarskimi i kładkami od strony miejscowości.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81513, 'Jezioro Młyńskie Małe', 'jezioro-mlynskie-male-slawa', 'LAKE', 51.847769, 16.024804, 'Lubuskie', 'Sława', 'Młyńskie Małe to kameralny, śródleśny zbiornik o charakterze eutroficznym. Akwen jest stosunkowo płytki (max 3-4 m) z dnem wyścielonym osadami leśnymi. Jezioro jest wybitnie wyciszone, stanowiąc doskonałe miejsce dla ryb spokojnego żeru szukających schronienia w pasach grążeli i trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81514, 'Jezioro Chełme', 'jezioro-chelme', 'LAKE', 51.883306, 15.874386, 'Lubuskie', 'Nowa Sól / Lubięcin', 'Jezioro Chełme to malowniczy, płytki akwen (max 3-4 m) o charakterze eutroficznym, stanowiący część systemu jezior lubięcińskich. Dno jest wysoce muliste, bogate w bentos. Brzegi są niskie i silnie zarośnięte trzciną, co stwarza idealne warunki dla ryb ciepłolubnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81515, 'Jezioro Lubięcińskie', 'jezioro-lubiecinskie', 'LAKE', 51.888814, 15.880008, 'Lubuskie', 'Nowa Sól / Lubięcin', 'Jezioro Lubięcińskie to największy zbiornik w rynnie lubięcińskiej (pow. ok. 60 ha). Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 4-5 metrów. Woda jest dobrze natleniona i żyzna. Brzegi są częściowo zagospodarowane, z licznymi kładkami wędkarskimi i pomostami od strony miejscowości.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81516, 'Jezioro Święte (k. Lubięcina)', 'jezioro-swiete-lubiecin', 'LAKE', 51.92503, 15.935798, 'Lubuskie', 'Konotop / Lubięcin', 'Jezioro Święte koło Lubięcina to hydrologiczna perła regionu – akwen o charakterze zbliżonym do lobeliowego z bardzo czystą wodą i piaszczystym dnem. Maksymalna głębokość sięga 12-14 metrów. Jezioro charakteryzuje się sielawowym charakterem i bogatą roślinnością podwodną (łąki ramienicowe).
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81517, 'Jezioro Rudno', 'jezioro-rudno-lubuskie', 'LAKE', 52.002348, 15.974164, 'Lubuskie', 'Wolsztyn / Rudno', 'Jezioro Rudno to potężna rynna polodowcowa (pow. ok. 160 ha) stanowiąca część systemu "Wilczego". Charakteryzuje się urozmaiconym dnem z wyraźnie zarysowaną rynną środkową sięgającą 15 metrów. Woda posiada dobrą klasę czystości. Brzegi są wysokie, porośnięte majestatycznym lasem sosnowym, z licznymi bazami rekreacyjnymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81518, 'Jezioro Wilcze', 'jezioro-wilcze', 'LAKE', 52.019412, 15.973949, 'Lubuskie', 'Wolsztyn / Wilcze', 'Jezioro Wilcze to legenda czystości w regionie (I klasa). Posiada wybitnie twarde, piaszczyste dno i niesamowitą przejrzystość wody. Batymetria jest monumentalna – stoki opadają gwałtownie do rynny sięgającej blisko 20 metrów. Akwen jest otoczony gęstym lasem, co nadaje mu surowy, północny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81519, 'Jezioro Ośno', 'jezioro-osno', 'LAKE', 52.025695, 15.983863, 'Lubuskie', 'Wolsztyn / Wilcze', 'Ośno to mniejszy, ustronny zbiornik rynnowy położony w bezpośrednim sąsiedztwie jeziora Wilczego. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 10-12 metrów biegnie przez środek jeziora. Brzegi są porośnięte majestatycznym borem, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81520, 'Jezioro Obrzańskie', 'jezioro-obrzanskie', 'LAKE', 52.051374, 16.051111, 'Wielkopolskie', 'Wolsztyn / Obra', 'Jezioro Obrzańskie to akwen rynnowo-przepływowy, przez który przepływa rzeka Północny Kanał Obry. Charakteryzuje się twardym dnem w osi nurtu i piaszczysto-mulistymi zatokami. Maksymalna głębokość sięga 8-10 metrów. Dzięki stałemu dopływowi świeżej wody, jezioro jest świetnie natlenione, co sprzyja aktywności drapieżników przez cały rok.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81521, 'Jezioro Berzyńskie', 'jezioro-berzynskie', 'LAKE', 52.094261, 16.09128, 'Wielkopolskie', 'Wolsztyn', 'Berzyńskie to największy akwen w ciągu jezior wolsztyńskich (pow. ok. 140 ha). Jest to jezioro wybitnie płytkie (średnio 2 m, max 4 m) o charakterze eutroficznym. Dno jest wysoce muliste i bogate w bentos. Woda jest wysoce żyzna, co przekłada się na ogromną biomasę ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81522, 'Jezioro Święte (Wolsztyn)', 'jezioro-swiete-wolsztyn', 'LAKE', 52.08524, 16.046369, 'Wielkopolskie', 'Wolsztyn', 'Jezioro Święte pod Wolsztynem to niewielki, kameralny zbiornik rynnowy, znany z znacznie lepszej przejrzystości wody niż sąsiednie jeziora miejskie. Posiada twarde dno piaszczyste w strefie litoralu i rynnę środkową sięgającą 10-12 metrów. Brzegi są w większości porośnięte lasem sosnowym, co nadaje akwenowi zaciszny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81523, 'Jezioro Wolsztyńskie', 'jezioro-wolsztynskie', 'LAKE', 52.126086, 16.113532, 'Wielkopolskie', 'Wolsztyn', 'Jezioro Wolsztyńskie to rynnowy akwen położony w samym sercu Wolsztyna. Zbiornik przeszedł w ostatnich latach gruntowną rekultywację. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 2-3 metrów. Brzegi są w całości zagospodarowane – mola, promenada i oświetlone alejki sprzyjają wędkowaniu miejskiemu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81524, 'Jezioro Wioska (Północne)', 'jezioro-wioska-polnoc', 'LAKE', 52.1768, 16.110206, 'Wielkopolskie', 'Rakoniewice / Wioska', 'Jezioro Wioska (część północna) to niewielki, śródpolny akwen o charakterze eutroficznym. Zbiornik jest stosunkowo płytki, z dnem wyścielonym osadami organicznymi i bogatą roślinnością zanurzoną. Jezioro jest wyciszone, stanowiąc doskonałe miejsce dla ryb spokojnego żeru szukających schronienia w pasach trzcin i lilii wodnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81525, 'Jezioro Obieżne', 'jezioro-obiezne', 'LAKE', 52.519905, 16.161103, 'Wielkopolskie', 'Kwilcz / Lubosz', 'Obieżne to niewielki, wybitnie płytki zbiornik (max 3 m) o charakterze eutroficznym. Dno jest wysoce muliste i bogate w bentos. Jezioro jest silnie zarastające grążelem żółtym, co czyni je idealnym biotopem dla ryb ciepłolubnych i lęgów płazów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81526, 'Jezioro Wioska (Główne)', 'jezioro-wioska-glowne', 'LAKE', 52.168749, 16.111279, 'Wielkopolskie', 'Rakoniewice / Wioska', 'Główny plos jeziora Wioska to akwen rynnowy o powierzchni ok. 30 ha. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 4-5 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin, co ułatwia dostęp do lustra wody z brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81527, 'Jezioro Kuźnickie', 'jezioro-kuznickie', 'LAKE', 52.219151, 16.08583, 'Wielkopolskie', 'Rakoniewice / Kuźnica Zbąska', 'Jezioro Kuźnickie to legenda czystości w zachodniej Wielkopolsce (I klasa czystości). Posiada wybitnie twarde, piaszczyste dno i niesamowitą przejrzystość wody (widoczność do 5-7 metrów). Batymetria jest urozmaicona z rynną sięgającą blisko 14 metrów. Jezioro charakteryzuje się sielawowym charakterem i bogatą roślinnością podwodną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81528, 'Jezioro Strykowskie', 'jezioro-strykowskie', 'LAKE', 52.265117, 16.60635, 'Wielkopolskie', 'Stęszew / Strykowo', 'Jezioro Strykowskie to jedna z najdłuższych i najgłębszych rynien w okolicach Poznania (pow. ok. 300 ha). Charakteryzuje się monumentalną batymetrią – dno opada do rynny sięgającej blisko 19 metrów. Woda posiada dobrą klasę czystości. Jezioro ma bardzo wydłużony kształt i twarde dno piaszczysto-żwirowe z licznymi podwodnymi górkami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81529, 'Jezioro Witobelskie', 'jezioro-witobelskie', 'LAKE', 52.264484, 16.729431, 'Wielkopolskie', 'Stęszew', 'Jezioro Witobelskie to płytki akwen rynnowy (pow. ok. 100 ha) położony w bezpośrednim sąsiedztwie Stęszewa. Charakteryzuje się wybitnie eutroficznym charakterem i mulistym dnem. Średnia głębokość nie przekracza 2-3 metrów. Woda jest żyzna, co przekłada się na ogromną biomasę ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81530, 'Jezioro Łódzko-Dymaczewskie', 'jezioro-lodzko-dymaczewskie', 'LAKE', 52.242103, 16.760159, 'Wielkopolskie', 'Stęszew / Dymaczewo Stare', 'Łódzko-Dymaczewskie to największe jezioro w rynnie stęszewskiej (pow. ok. 160 ha). Akwen posiada urozmaiconą linię brzegową i dno piaszczysto-muliste. Maksymalna głębokość sięga 12 metrów. Północna część jeziora leży w granicach WPN, co narzuca pewne ograniczenia. Woda jest dobrze natleniona i posiada przyzwoitą przejrzystość wiosną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81531, 'Jezioro Budzyńskie (Rezerwat)', 'jezioro-budzynskie', 'LAKE', 52.244887, 16.82745, 'Wielkopolskie', 'Mosina / WPN', 'Jezioro Budzyńskie to unikatowy akwen położony w sercu Wielkopolskiego Parku Narodowego. Jest to płytkie jezioro eutroficzne o bardzo silnie zarośniętych brzegach. Stanowi ono ścisły rezerwat przyrody, będąc ostoją dla rzadkich gatunków ptactwa wodnego i płazów. Dno jest wysoce muliste, a lustro wody systematycznie się zmniejsza wskutek sukcesji roślinnej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81532, 'Jezioro Góreckie (Rezerwat)', 'jezioro-goreckie', 'LAKE', 52.262273, 16.79904, 'Wielkopolskie', 'Komorniki / WPN', 'Jezioro Góreckie uważane jest za najpiękniejsze jezioro Wielkopolskiego Parku Narodowego. Jest to głęboka rynna (max 17 m) o krystalicznie czystej wodzie i urokliwej wyspie (Zamkowa) z ruinami neogotyckiego zameczku. Akwen charakteryzuje się bardzo stromymi brzegami porośniętymi starym lasem bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81533, 'Jezioro Jarosławieckie', 'jezioro-jaroslawieckie', 'LAKE', 52.286753, 16.796143, 'Wielkopolskie', 'Jarosławiec / WPN', 'Jezioro Jarosławieckie to malowniczy zbiornik rynnowy położony w otulinie leśnej WPN. W przeciwieństwie do sąsiednich rezerwatów, Jarosławieckie jest udostępnione do rekreacji. Charakteryzuje się twardym, piaszczystym dnem w strefie litoralu i czystą wodą. Maksymalna głębokość oscyluje wokół 10-12 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81534, 'Jezioro Małe (k. Rosnowa)', 'jezioro-male-rosnowo', 'LAKE', 52.295188, 16.779256, 'Wielkopolskie', 'Komorniki / Rosnówko', 'Jezioro Małe to kameralny zbiornik rynnowy stanowiący południowe przedłużenie jeziora Rosnowskiego. Charakteryzuje się dnem piaszczysto-mulistym i średnią głębokością ok. 4 metrów. Woda jest żyzna i dobrze natleniona. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin, co ułatwia dostęp do wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81535, 'Jezioro Rosnowskie', 'jezioro-rosnowskie-2', 'LAKE', 52.302759, 16.761253, 'Wielkopolskie', 'Komorniki / Rosnowo', 'Jezioro Rosnowskie to klasyczna wielkopolska rynna, długa i wąska, wciśnięta w pofalowany krajobraz (pow. ok. 35 ha). Akwen charakteryzuje się twardym dnem w strefie przybrzeżnej i rynną środkową sięgającą 10-12 metrów. Woda posiada przyzwoitą przejrzystość wiosną. Brzegi są w większości wysokie i porośnięte lasem mieszanym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81536, 'Jezioro Chomęcickie (Comęckie)', 'jezioro-chomecickie', 'LAKE', 52.314409, 16.74458, 'Wielkopolskie', 'Komorniki / Chomęcice', 'Jezioro Chomęcickie (występujące w starszych źródłach jako Comęckie) to rynnowy akwen położony przy miejscowości Chomęcice. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 5 metrów. Woda jest żyzna, co przekłada się na bogatą biomasę ryb karpiowatych. Brzegi są częściowo zagospodarowane, z licznymi pomostami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81537, 'Jezioro Konarzewskie', 'jezioro-konarzewskie', 'LAKE', 52.319837, 16.730311, 'Wielkopolskie', 'Dopiewo / Konarzewo', 'Konarzewskie to kameralny, śródpolny zbiornik o charakterze rynnowym. Posiada muliste dno i przyzwoitą przejrzystość wody wiosną. Maksymalna głębokość nie przekracza 5 metrów. Jezioro jest wyciszone, stanowiąc doskonałe miejsce dla ryb spokojnego żeru szukających schronienia w pasach trzcin i lilii wodnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81538, 'Jezioro Tomickie', 'jezioro-tomickie', 'LAKE', 52.317925, 16.633558, 'Wielkopolskie', 'Stęszew / Tomice', 'Jezioro Tomickie to rozległy, wybitnie płytki akwen (max 2 m) o charakterze eutroficznym. Dno jest wysoce muliste i bogate w bentos. Jezioro jest silnie zarastające, z ogromnymi polami lilii wodnych i grążeli, co czyni je idealnym biotopem dla ryb ciepłolubnych i ptactwa wodnego (rezerwat ptasi w pobliżu).
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81539, 'Jezioro Niepruszewskie', 'jezioro-niepruszewskie', 'LAKE', 52.376694, 16.617508, 'Wielkopolskie', 'Buk / Niepruszewo', 'Jezioro Niepruszewskie to potężna rynna polodowcowa (pow. ok. 240 ha) o długości blisko 5 km. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 3-4 metrów (max 5 m). Woda jest wybitnie żyzna. Brzegi są urozmaicone – od zalesionych skarp po zagospodarowane plaże miejskie z pomostami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81540, 'Jezioro Lubosz Wielki', 'jezioro-lubosz-wielki', 'LAKE', 52.512601, 16.193676, 'Wielkopolskie', 'Pniewy / Lubosz', 'Lubosz Wielki to malowniczy akwen rynnowy o powierzchni ok. 60 ha. Charakteryzuje się dość urozmaiconą batymetrią z głębokością sięgającą 14-15 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są zróżnicowane – od zalesionych skarp po piaszczyste dojścia w miejscowości Lubosz.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81541, 'Jezioro Pniewskie', 'jezioro-pniewskie-2', 'LAKE', 52.510982, 16.239853, 'Wielkopolskie', 'Pniewy', 'Jezioro miejskie w Pniewach o charakterze wybitnie eutroficznym. Zbiornik jest płytki (max 4 m) o silnie zamulonym dnie, co sprzyja ogromnej biomasie ryb karpiowatych. Brzegi są w całości zagospodarowane – promenady, pomosty i oświetlone alejki sprzyjają rekreacji.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81542, 'Jezioro Zamorze', 'jezioro-zamorze', 'LAKE', 52.510589, 16.209512, 'Wielkopolskie', 'Pniewy / Zamorze', 'Zamorze to kameralny, śródpolny akwen rynnowy położony między Pniewami a Luboszem. Posiada muliste dno i średnią głębokość ok. 5-6 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez pagórkowaty teren, co sprzyja rozwojowi bujnej roślinności zanurzonej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81543, 'Jezioro Luboszek', 'jezioro-luboszek', 'LAKE', 52.526888, 16.208782, 'Wielkopolskie', 'Pniewy / Lubosz', 'Luboszek to niewielki, rynnowy sąsiad Lubosza Wielkiego. Akwen charakteryzuje się piaszczysto-mulistym dnem i głębokością do 5 metrów. Woda posiada przyzwoitą przejrzystość wiosną. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin, co ułatwia dostęp do wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81544, 'Staw Żabieniec Mały', 'staw-zabieniec-maly', 'LAKE', 51.514379, 17.117214, 'Dolnośląskie', 'Niezgoda', 'Niewielki staw leśno-łąkowy. Charakteryzuje się dużą ilością roślinności pływającej (lilie wodne, grążele). Jak sama nazwa wskazuje, to potężne tarlisko płazów, co przyciąga liczne drapieżniki, w tym szczupaka.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81545, 'Jezioro Mulino', 'jezioro-mulino', 'LAKE', 52.554621, 16.141362, 'Wielkopolskie', 'Sieraków / Kwilcz', 'Mulino to kameralny, rynnowy sąsiad Spulina, o nieco bardziej mulistym dnie (stąd nazwa). Akwen posiada czystą wodę i regularną linię brzegową. Maksymalna głębokość nie przekracza 5 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez wysokie skarpy zalesione starodrzewem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81546, 'Jezioro Lubocześnickie', 'jezioro-luboczesnickie', 'LAKE', 52.537476, 16.240604, 'Wielkopolskie', 'Pniewy / Lubocześnica', 'Lubocześnickie to malownicza rynna o powierzchni ok. 45 ha. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i głębokością sięgającą 10 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są urozmaicone, z licznymi stanowiskami wędkarskimi i kładkami od strony miejscowości.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81547, 'Jezioro Białokoskie', 'jezioro-bialokoskie', 'LAKE', 52.571397, 16.231871, 'Wielkopolskie', 'Chrzypsko Wielkie / Białokosz', 'Białokoskie to hydrologiczna perła Wielkopolski i jedno z najgłębszych jezior regionu (pow. ok. 150 ha, max 31 m). Charakteryzuje się monumentalną batymetrią – stoki opadają gwałtownie do rynny o sielawowym charakterze. Woda posiada I klasę czystości i niesamowitą przejrzystość. Dno jest wybitnie twarde.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81548, 'Jezioro Godnik', 'jezioro-godnik', 'LAKE', 53.748626, 18.434308, 'Pomorskie', 'Osiek', 'Godnik to ustronny, leśny zbiornik o charakterze rynnowym. Posiada twarde dno w strefie przybrzeżnej i czystą wodę. To bardzo stabilna woda leszczowo-szczupakowa, rzadko odwiedzana przez spinningistów, co daje szansę na ładne okazy.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81549, 'Jezioro Chrzypskie', 'jezioro-chrzypskie', 'LAKE', 52.61488, 16.226692, 'Wielkopolskie', 'Chrzypsko Wielkie', 'Chrzypskie to największy akwen w regionie (pow. ok. 300 ha). To potężna rynna polodowcowa o urozmaiconym dnie, z licznymi górkami podwodnymi i twardymi skarpami. Maksymalna głębokość sięga 15 metrów. Woda posiada dobrą klasę czystości. Brzegi są zagospodarowane turystycznie – mola, plaże i slipy sprzyjają wędkarzom zmotoryzowanym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81550, 'Jezioro Koszczynek', 'jezioro-koszczynek', 'LAKE', 52.626341, 16.198597, 'Wielkopolskie', 'Chrzypsko Wielkie', 'Koszczynek to mniejszy, ustronny zbiornik rynnowy położony w pagórkowatym terenie leśnym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna z rynną sięgającą 9 metrów. Jezioro jest wyciszone i osłonięte od wiatrów, co sprzyja rozwojowi bujnej roślinności zanurzonej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81551, 'Jezioro Kuchenne', 'jezioro-kuchenne', 'LAKE', 52.623476, 16.257391, 'Wielkopolskie', 'Chrzypsko Wielkie / Śródka', 'Kuchenne to malownicza rynna (pow. ok. 60 ha) charakteryzująca się twardym dnem piaszczysto-żwirowym i głębokością sięgającą 15 metrów. Woda posiada wysoką klasę czystości. Jezioro ma bardzo wydłużony kształt i jest otoczone wzniesieniami morenowymi, co zapewnia unikatowe walory krajobrazowe.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81552, 'Jezioro Liśnia', 'jezioro-lisnia', 'LAKE', 52.622955, 16.274986, 'Wielkopolskie', 'Chrzypsko Wielkie / Śródka', 'Liśnia to ustronny zbiornik rynnowy o dnie piaszczysto-mulistym i średniej głębokości ok. 8 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest otoczone pasem lasu od strony zachodniej, co zapewnia osłonę przed dominującymi wiatrami. Brzegi są porośnięte rzadkim pasem trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81553, 'Jezioro Wielkie (k. Chrzypska)', 'jezioro-wielkie-chrzypsko', 'LAKE', 52.643685, 16.260467, 'Wielkopolskie', 'Chrzypsko Wielkie', 'Jezioro Wielkie stanowi element rynny chrzypskiej. Jest to akwen o powierzchni ok. 35 ha i maksymalnej głębokości ok. 12 metrów. Charakteryzuje się dość twardym dnem w strefie przybrzeżnej i dobrze rozwiniętym pasem trzcin. Woda posiada przyzwoitą przejrzystość wiosną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81554, 'Jezioro Orliczko', 'jezioro-orliczko', 'LAKE', 52.615087, 16.335397, 'Wielkopolskie', 'Chrzypsko Wielkie / Nojewo', 'Orliczko to kameralny, śródpolny zbiornik o charakterze eutroficznym. Akwen charakteryzuje się mulistym dnem i średnią głębokością ok. 4-5 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez pagórkowaty teren, co sprzyja rozwojowi bujnej roślinności zanurzonej. Woda szybko nagrzewa się wiosną, stymulując ryby do żerowania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81555, 'Jezioro Głuchowo', 'jezioro-gluchowo', 'LAKE', 52.649158, 16.329374, 'Wielkopolskie', 'Chrzypsko Wielkie', 'Jezioro Głuchowo to niewielki zbiornik rynnowy położony w pofałdowanym terenie rolniczo-leśnym. Posiada dno piaszczysto-muliste i głębokość sięgającą 6-7 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin, co ułatwia dostęp do wody z brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81556, 'Jezioro Radziszewskie', 'jezioro-radziszewskie', 'LAKE', 52.643952, 16.230755, 'Wielkopolskie', 'Chrzypsko Wielkie / Radziszewo', 'Radziszewskie to jeden z najpiękniejszych akwenów Sierakowskiego Parku Krajobrazowego. Słynie z krystalicznie czystej wody (I klasa) i monumentalnej rynny sięgającej 15 metrów głębokości. Dno jest wybitnie twarde, piaszczysto-żwirowe. Brzegi są wysokie i w całości porośnięte majestatycznym lasem bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81557, 'Jezioro Charcickie', 'jezioro-charcickie', 'LAKE', 52.652958, 16.210327, 'Wielkopolskie', 'Chrzypsko Wielkie / Charcice', 'Jezioro Charcickie to wąska, długa rynna polodowcowa charakteryzująca się czystą wodą i twardym podłożem. Maksymalna głębokość oscyluje wokół 8-10 metrów. Jezioro jest wyciszone, osłonięte od silnych wiatrów przez pasy lasu i pagórki, co sprzyja rozwojowi bujnego litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81558, 'Jezioro Izdebienko', 'jezioro-izdebienko', 'LAKE', 52.661027, 16.200768, 'Wielkopolskie', 'Sieraków / Izdebno', 'Izdebienko to kameralny zbiornik rynnowy o dnie piaszczysto-mulistym. Maksymalna głębokość sięga 6 metrów. Woda posiada przyzwoitą przejrzystość wiosną. Jezioro jest otoczone pasem lasu, co zapewnia osłonę przed wiatrem i nadaje akwenowi intymny charakter. Roślinność zanurzona jest tu bardzo bogata.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81559, 'Jezioro Żołnierek', 'jezioro-zolnierek', 'LAKE', 52.665336, 16.202796, 'Wielkopolskie', 'Sieraków / Izdebno', 'Żołnierek to niewielkie, śródleśne "oczko" o charakterze wytopiskowym. Posiada muliste dno i przyzwoitą przejrzystość wody. Maksymalna głębokość nie przekracza 5 metrów. Jezioro jest w całości otoczone lasem, co zapewnia absolutną ciszę i ochronę przed wiatrem. Stanowi doskonałe miejsce dla ryb spokojnego żeru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81560, 'Jezioro Kaczlińskie', 'jezioro-kaczlinskie', 'LAKE', 52.664164, 16.16518, 'Wielkopolskie', 'Sieraków / Kaczlin', 'Jezioro Kaczlińskie to malownicza rynna (pow. ok. 30 ha) o czystej wodzie i twardym dnie piaszczysto-żwirowym. Maksymalna głębokość sięga 12-14 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę dzięki otwartej ekspozycji na wiatr. Brzegi są wysokie i w dużej mierze zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81561, 'Jezioro Lipie (k. Długiego)', 'jezioro-lipie-lubuskie', 'LAKE', 52.919573, 15.659037, 'Lubuskie', 'Dobiegniew / Długie', 'Jezioro Lipie to hydrologiczna legenda województwa lubuskiego i jedno z najczystszych jezior w Polsce (I klasa). Słynie z niesamowitej przejrzystości wody (widoczność do 7-8 metrów), co czyni je mekką nurków. Jest to głęboka rynna (max 27 m) o wybitnie twardym, piaszczystym dnie. Brzegi są porośnięte starym lasem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81562, 'Jezioro Słowa', 'jezioro-slowa', 'LAKE', 52.924177, 15.632601, 'Lubuskie', 'Dobiegniew / Długie', 'Jezioro Słowa to rynnowy sąsiad jeziora Lipie, połączony z nim wąskim przesmykiem. Charakteryzuje się identyczną, najwyższą klasą czystości wody i twardym dnem. Maksymalna głębokość sięga 15-17 metrów. Jezioro jest bardziej ustronne niż Lipie, otoczone gęstym borem, co zapewnia osłonę przed wiatrem i kameralny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81563, 'Jezioro Kokno', 'jezioro-kokno', 'LAKE', 52.919883, 15.684528, 'Lubuskie', 'Dobiegniew', 'Kokno to niewielki zbiornik o charakterze eutroficznym, położony w dolinie rzeki Mierzęckiej Strugi. Dno jest piaszczysto-muliste, a średnia głębokość nie przekracza 4 metrów. Woda jest żyzna, co sprzyja rozwojowi bujnego litoralu. Brzegi są niskie, porośnięte gęstą trzciną, stanowiącą doskonałe tarlisko dla ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81564, 'Staw Żabieniec Duży I', 'staw-zabieniec-duzy-1', 'LAKE', 51.51072, 17.117665, 'Dolnośląskie', 'Niezgoda', 'Pierwszy z serii dużych stawów kompleksu Żabieniec. Wykorzystywany do tuczu karpia. Posiada muliste dno i rozległe płycizny, które błyskawicznie nagrzewają się wiosną, stymulując ryby do żerowania.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81565, 'Jezioro Osiek (Chomętowskie)', 'jezioro-osiek-lubuskie', 'LAKE', 52.955668, 15.682297, 'Lubuskie', 'Dobiegniew / Osiek', 'Jezioro Osiek (znane również jako Chomętowskie) to potężny akwen rynnowy (pow. ok. 540 ha). To jedno z najgłębszych jezior regionu (max 35 m). Charakteryzuje się bardzo urozmaiconą linią brzegową z licznymi wyspami, półwyspami i głębokimi zatokami. Dno jest wybitnie zróżnicowane z licznymi górkami podwodnymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81566, 'Jezioro Ostrowica', 'jezioro-ostrowica-lubuskie', 'LAKE', 52.935969, 15.715599, 'Lubuskie', 'Dobiegniew / Osiek', 'Ostrowica to malowniczy zbiornik rynnowy bezpośrednio połączony z systemem jeziora Osiek. Akwen charakteryzuje się czystą wodą i twardym dnem piaszczysto-żwirowym. Maksymalna głębokość sięga 12-14 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i jest osłonięte od silnych wiatrów przez wysokie, zalesione brzegi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81567, 'Jezioro Prab', 'jezioro-prab', 'LAKE', 53.987829, 20.704079, 'Warmińsko-Mazurskie', 'Jeziorany / Ustnik', 'Jezioro Prab to urokliwy, warmiński akwen o typowo nizinnej charakterystyce. Posiada muliste dno i jest otoczone rozległymi łąkami oraz pasem trzcinowisk. Maksymalna głębokość nie przekracza 4-5 metrów. Woda jest żyzna, co sprzyja szybkiej wegetacji lina i karasia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81568, 'Jezioro Korzonek', 'jezioro-korzonek', 'LAKE', 53.748435, 18.428686, 'Pomorskie', 'Osiek', 'Korzonek to dziki, śródleśny zbiornik o mrocznej wodzie i bagnistych brzegach. Nazwa nawizuje do dużej ilości powalonych drzew i korzeni w wodzie, które stanowią naturalne kryjówki dla szczupaków i dorodnych okoni.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81569, 'Jezioro Ustnik (Rezerwat)', 'jezioro-ustnik', 'LAKE', 53.995131, 20.698693, 'Warmińsko-Mazurskie', 'Jeziorany', 'Ustnik to unikatowy zbiornik retencyjny, który stał się jednym z najważniejszych rezerwatów ornitologicznych w regionie. Akwen jest bardzo płytki, silnie zarastający, z ogromnymi połaciami trzcin i wyspami zielnymi. Jest to kluczowe miejsce lęgowe dla rzadkich gatunków ptactwa wodnego.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81570, 'Jezioro Spągi', 'jezioro-spagi', 'LAKE', 53.988964, 20.683587, 'Warmińsko-Mazurskie', 'Jeziorany', 'Spągi to niewielkie, śródpolne jezioro o charakterze eutroficznym, położone w sąsiedztwie Ustnika. Posiada muliste dno i średnią głębokość ok. 3 metrów. Woda jest żyzna, o mniejszej przejrzystości latem. Brzegi są niskie, porośnięte gęstym pasem trzciny pospolitej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81571, 'Jezioro Kukowino', 'jezioro-kukowino', 'LAKE', 53.95841, 22.404041, 'Warmińsko-Mazurskie', 'Olecko / Kukowo', 'Jezioro Kukowino to malowniczy akwen rynnowy położony na Pojezierzu Ełckim. Charakteryzuje się czystą wodą i twardym dnem piaszczysto-żwirowym. Maksymalna głębokość sięga 15-16 metrów. Brzegi są zróżnicowane – od wysokich zalesionych skarp po dogodne piaszczyste dojścia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81572, 'Jezioro Zajdy', 'jezioro-zajdy', 'LAKE', 53.975419, 22.415285, 'Warmińsko-Mazurskie', 'Olecko / Zajdy', 'Jezioro Zajdy to rynnowe przedłużenie systemu jezior wokół Olecka. Posiada mulisto-piaszczyste dno i średnią głębokość ok. 6-8 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest połączone systemem cieków z rzeką Legą, co sprzyja stałej migracji ryb. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81573, 'Jezioro Dudeckie', 'jezioro-dudeckie', 'LAKE', 53.972744, 22.396574, 'Warmińsko-Mazurskie', 'Świętajno / Dudki', 'Jezioro Dudeckie to malowniczy akwen rynnowy (pow. ok. 40 ha). Charakteryzuje się czystą wodą i urozmaiconą batymetrią z rynną sięgającą 12-14 metrów. Dno jest twarde, piaszczysto-żwirowe. Brzegi są wysokie i częściowo zalesione, co nadaje jezioru kameralny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81574, 'Jezioro Dworackie', 'jezioro-dworackie', 'LAKE', 53.985725, 22.338123, 'Warmińsko-Mazurskie', 'Świętajno / Dworackie', 'Dworackie to akwen rynnowy o wydłużonym kształcie, stanowiący istotny punkt na szlaku rzeki Legi. Charakteryzuje się twardym dnem w osi nurtu i głębokością sięgającą 12 metrów. Woda posiada dobrą klasę czystości i jest dobrze natleniona. Brzegi są urozmaicone, z licznymi kładkami wędkarskimi od strony miejscowości.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81575, 'Jezioro Świętajno (Olecko)', 'jezioro-swietajno-oleckie', 'LAKE', 54.001973, 22.311516, 'Warmińsko-Mazurskie', 'Świętajno', 'Jezioro Świętajno koło Olecka to absolutna legenda czystości (I klasa) i jedno z najgłębszych jezior w Polsce (max ok. 60 m!). To potężna rynna sielawowa z krystalicznie czystą wodą i monumentalną batymetrią. Dno jest wybitnie twarde, piaszczysto-kredowe. Jezioro słynie z unikatowej roślinności (lobelia) i przejrzystości sięgającej 6-8 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81576, 'Jezioro Muliste', 'jezioro-muliste', 'LAKE', 54.017254, 22.306409, 'Warmińsko-Mazurskie', 'Świętajno / Chełchy', 'Muliste to niewielki, kameralny zbiornik położony w bezpośrednim sąsiedztwie jeziora Świętajno. Ma charakter bardziej eutroficzny (stąd nazwa), z dnem pokrytym grubszą warstwą osadów i bogatszą roślinnością brzegową. Maksymalna głębokość nie przekracza 5-6 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez pas lasu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81577, 'Jezioro Chełchy', 'jezioro-chelchy', 'LAKE', 54.034721, 22.288513, 'Warmińsko-Mazurskie', 'Świętajno / Chełchy', 'Jezioro Chełchy to malowniczy akwen rynnowy położony w pofałdowanym terenie rolniczo-leśnym. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym w strefie litoralu. Maksymalna głębokość oscyluje wokół 8-10 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są w większości dostępne.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81578, 'Jezioro Długie (k. Dunajka)', 'jezioro-dlugie-dunajek', 'LAKE', 54.056389, 22.317481, 'Warmińsko-Mazurskie', 'Świętajno / Dunajek', 'Jezioro Długie to urokliwa, wąska rynna polodowcowa ukryta w głębi borów. Akwen charakteryzuje się twardym dnem piaszczysto-żwirowym i głębokością sięgającą 10-12 metrów. Woda jest przejrzysta i chłodna. Brzegi są wysokie i porośnięte majestatycznym lasem sosnowym, co nadaje akwenowi dziki i ustronny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81579, 'Jezioro Kociołek (k. Chełch)', 'jezioro-kociolek-chelchy', 'LAKE', 54.050773, 22.332587, 'Warmińsko-Mazurskie', 'Świętajno / Chełchy', 'Kociołek to niewielki, niemal okrągły zbiornik o charakterze wytopiskowym. Mimo małej powierzchni, jest to zbiornik głęboki (ok. 8 m) o bardzo czystej wodzie. Jezioro jest wyciszone, osłonięte od wiatru przez pagórkowaty teren zalesiony borem. Roślinność wodna jest skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81580, 'Jezioro Birek', 'jezioro-birek', 'LAKE', 54.086582, 22.261219, 'Warmińsko-Mazurskie', 'Świętajno / Gryzy', 'Birek to kameralny, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna z rynną sięgającą 6-8 metrów. Jezioro jest wybitnie wyciszone, osłonięte od wiatrów przez wysokie skarpy zalesione borem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81581, 'Jezioro Tyrkło', 'jezioro-tyrklo', 'LAKE', 53.822195, 21.867085, 'Warmińsko-Mazurskie', 'Orzysz / Okartowo', 'Jezioro Tyrkło to północno-wschodnia odnoga Śniardw, połączona z nimi kanałem. Jest to typowa, głęboka rynna (max ok. 29 m) o bardzo urozmaiconym dnie. Woda jest czysta, a brzegi wysokie i zalesione, co zapewnia osłonę przed wiatrami nękającymi główne plosy Mazur.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81582, 'Jezioro Tuchlin', 'jezioro-tuchlin', 'LAKE', 53.797066, 21.774302, 'Warmińsko-Mazurskie', 'Orzysz / Tuchlin', 'Tuchlin to w istocie rozległa, płytka zatoka jeziora Śniardwy, traktowana często jako oddzielny akwen. Charakteryzuje się wybitnie eutroficznym charakterem – dno jest muliste, a pasy trzcinowisk i lilii wodnych są niezwykle szerokie. Średnia głębokość oscyluje wokół 2-3 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81583, 'Jezioro Przykop', 'jezioro-przykop', 'LAKE', 53.864657, 21.963215, 'Warmińsko-Mazurskie', 'Miłki / Przykop', 'Jezioro Przykop to niewielki, kameralny akwen położony w pofałdowanym terenie rolniczo-leśnym. Posiada dno piaszczysto-muliste i średnią głębokość ok. 5 metrów. Woda posiada przyzwoitą przejrzystość wiosną. Brzegi są częściowo porośnięte rzadkim pasem trzcin, co ułatwia dostęp do wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81584, 'Jezioro Długie (k. Skomacka)', 'jezioro-dlugie-skomack', 'LAKE', 53.871209, 21.973, 'Warmińsko-Mazurskie', 'Ełk / Skomack Wielki', 'Jezioro Długie pod Skomackiem to klasyczna, wąska rynna polodowcowa. Akwen charakteryzuje się twardym dnem w strefie przybrzeżnej i wyraźnie zarysowaną rynną środkową o głębokości do 12 metrów. Woda jest czysta i dobrze natleniona. Brzegi są wysokie i w dużej mierze porośnięte lasem mieszanym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81585, 'Jezioro Zgniłek', 'jezioro-zgnilek-2', 'LAKE', 53.877279, 21.963086, 'Warmińsko-Mazurskie', 'Miłki / Skomack Wielki', 'Zgniłek to małe, śródleśne "oczko" o charakterze dystroficzno-eutroficznym. Mimo mało zachęcającej nazwy, jest to czysty akwen o mrocznej, herbacianej wodzie i miękkim dnie wyścielonym osadami leśnymi. Maksymalna głębokość nie przekracza 4-5 metrów. Brzegi są niskie, często bagniste.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81586, 'Jezioro Skomack Mały', 'jezioro-skomack-maly', 'LAKE', 53.885107, 21.98729, 'Warmińsko-Mazurskie', 'Stare Juchy / Skomack', 'Skomack Mały to urokliwy, rynnowy akwen położony w pofałdowanym terenie Pojezierza Ełckiego. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 8-10 metrów. Jezioro posiada dobrze rozwinięty pas roślinności wynurzonej, stanowiący świetne schronienie dla narybku.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81587, 'Jezioro Bielskie', 'jezioro-bielskie-2', 'LAKE', 53.890659, 21.969223, 'Warmińsko-Mazurskie', 'Stare Juchy / Skomack', 'Jezioro Bielskie to monumentalna rynna o powierzchni ok. 150 ha i głębokości sięgającej blisko 26 metrów. Woda posiada wysoką klasę czystości i sielawowy charakter. Dno jest wybitnie twarde, piaszczysto-żwirowe z gwałtownymi uskokami. Brzegi są wysokie, w dużej mierze zalesione, co zapewnia osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81588, 'Jezioro Pamerek', 'jezioro-pamerek', 'LAKE', 53.912681, 21.999232, 'Warmińsko-Mazurskie', 'Stare Juchy', 'Pamerek to kameralny, śródleśny zbiornik o charakterze rynnowym, stanowiący południowe przedłużenie jeziora Pamer. Posiada twarde dno i czystą wodę. Maksymalna głębokość sięga 6-8 metrów. Brzegi są wysokie i w całości zalesione, co zapewnia świetną osłonę przed wiatrem i intymny charakter łowiska.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81589, 'Jezioro Pamer', 'jezioro-pamer', 'LAKE', 53.920846, 22.005401, 'Warmińsko-Mazurskie', 'Stare Juchy', 'Jezioro Pamer to malowniczy, rynnowy akwen ukryty w głębi borów ełckich. Charakteryzuje się czystą wodą i twardym podłożem. Batymetria jest regularna z rynną sięgającą 10-12 metrów. Jezioro jest wybitnie wyciszone, osłonięte od wiatrów przez wysokie skarpy porośnięte majestatycznym lasem, co nadaje mu unikatowy klimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81590, 'Jezioro Wylewy', 'jezioro-wylewy', 'LAKE', 53.852326, 22.037201, 'Warmińsko-Mazurskie', 'Ełk / Woszczele', 'Jezioro Wylewy to płytki, rozległy zbiornik o charakterze eutroficznym, położony w pofalowanym terenie rolniczym. Charakteryzuje się mulistym dnem i średnią głębokością nie przekraczającą 3-4 metrów. Woda jest żyzna, co sprzyja rozwojowi bujnego litoralu. Brzegi są niskie i silnie zarośnięte szerokim pasem trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81591, 'Jezioro Mleczówka', 'jezioro-mleczowka', 'LAKE', 53.856149, 22.120199, 'Warmińsko-Mazurskie', 'Ełk / Siedliska', 'Mleczówka to urokliwy zbiornik rynnowy położony w bliskim sąsiedztwie Ełku. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 5 metrów (max do 10 m). Woda posiada przyzwoitą klasę czystości. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin, co ułatwia dostęp do wody z brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81592, 'Jezioro Rogale', 'jezioro-rogale', 'LAKE', 53.848077, 22.169724, 'Warmińsko-Mazurskie', 'Ełk / Rogale', 'Jezioro Rogale to malowniczy, płytki akwen (pow. ok. 100 ha) o charakterze wybitnie eutroficznym. Dno jest wysoce muliste i bogate w bentos. Maksymalna głębokość nie przekracza 5 metrów. Jezioro jest silnie zarastające, z ogromnymi polami lilii wodnych i grążeli, co czyni je idealnym biotopem dla ryb ciepłolubnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81593, 'Jezioro Dobrzyń', 'jezioro-dobrzyn', 'LAKE', 53.880745, 22.133632, 'Warmińsko-Mazurskie', 'Ełk / Dobrzyń', 'Jezioro Dobrzyń to akwen rynnowy o powierzchni ok. 40 ha, położony w ustronnej dolinie. Charakteryzuje się czystą wodą i twardym dnem piaszczystym w strefie litoralu. Maksymalna głębokość sięga 12-14 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są wysokie i w dużej mierze zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81594, 'Jezioro Krzywe (Stare Juchy)', 'jezioro-krzywe-stare-juchy-2', 'LAKE', 53.90871, 22.124341, 'Warmińsko-Mazurskie', 'Stare Juchy', 'Jezioro Krzywe to klasyczna rynna polodowcowa o urozmaiconym kształcie i bardzo czystej wodzie. Akwen charakteryzuje się twardym dnem piaszczysto-żwirowym i głębokością sięgającą blisko 28 metrów. Brzegi są wysokie, częściowo zalesione, z licznymi półwyspami, które tworzą naturalne osłony od wiatru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81595, 'Jezioro Juskie', 'jezioro-juskie', 'LAKE', 53.928629, 22.167159, 'Warmińsko-Mazurskie', 'Stare Juchy / Jucha', 'Jezioro Juskie to malowniczy akwen rynnowy położony w bliskim sąsiedztwie Starych Juch. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 10 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest połączone systemem cieków z jeziorem Szóstak, co sprzyja migracji ryb. Brzegi są w większości dostępne, z wieloma kładkami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81596, 'Jezioro Sowa', 'jezioro-sowa', 'LAKE', 54.028544, 22.147837, 'Warmińsko-Mazurskie', 'Wydminy / Gawliki Wielkie', 'Sowa to kameralny, śródleśny zbiornik o charakterze rynnowo-eutroficznym. Akwen posiada muliste dno z piaszczystymi łachami w strefie litoralu. Maksymalna głębokość nie przekracza 6-8 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez gęsty pas lasu, co sprzyja rozwojowi bujnej roślinności zanurzonej i narybku.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81597, 'Jezioro Bycek', 'jezioro-bycek', 'LAKE', 53.926821, 21.884873, 'Warmińsko-Mazurskie', 'Miłki / Przykop', 'Jezioro Bycek to niewielkie, urokliwe "oczko" położone w ustronnym terenie rolniczo-leśnym niedaleko Miłek. Akwen charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i miękkim dnem. Maksymalna głębokość nie przekracza 4-5 metrów. Brzegi są niskie, silnie zarośnięte trzciną pospolitą, co zapewnia rybom absolutny spokój.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81598, 'Jezioro Czarne (k. Wydmin)', 'jezioro-czarne-wydminy', 'LAKE', 54.052983, 21.939526, 'Warmińsko-Mazurskie', 'Wydminy / Gawliki', 'Jezioro Czarne pod Wydminami to głęboki, śródleśny zbiornik o charakterze rynnowym. Nazwa nawiązuje do ciemnego odcienia wody wynikającego z leśnego otoczenia, choć woda posiada dobrą klasę czystości. Dno jest wybitnie twarde, piaszczyste ze stromymi spadkami. Maksymalna głębokość sięga ok. 15 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81599, 'Jezioro Kożuchy', 'jezioro-kozuchy', 'LAKE', 54.032584, 21.894422, 'Warmińsko-Mazurskie', 'Giżycko / Kożuchy Wielkie', 'Jezioro Kożuchy to rozległy, wybitnie płytki akwen (max 2-3 m) o charakterze eutroficznym, położony w bezpośrednim sąsiedztwie słynnego rezerwatu ornitologicznego "Jezioro Kożuchy". Dno jest wysoce muliste, a lustro wody w dużej części porośnięte roślinnością pływającą. Stanowi ono kluczowe tarlisko dla ryb całego systemu jezior miłeckich.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81600, 'Jezioro Karpnik', 'jezioro-karpnik-lubuskie', 'LAKE', 52.531314, 15.18568, 'Lubuskie', 'Lubniewice / Jarnatów', 'Karpnik to kameralny, śródleśny zbiornik o charakterze stawowym-eutroficznym. Akwen jest stosunkowo płytki, z miękkim dnem i bogatą roślinnością brzegową. Jezioro jest wybitnie wyciszone, stanowiąc doskonałe siedlisko dla ryb szukających spokoju.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81601, 'Jezioro Dziekanowskie', 'jezioro-dziekanowskie', 'LAKE', 52.367454, 20.843897, 'Mazowieckie', 'Łomianki', 'Jezioro Dziekanowskie to największe starorzecze Wisły w okolicach Warszawy (pow. ok. 50 ha). Charakteryzuje się wydłużonym kształtem i niewielką głębokością (średnio 2-3 m). Dno jest w większości muliste, ale występują twardsze, piaszczyste partie. Lustro wody i rybostan są ściśle powiązane z poziomem wód gruntowych i okresowymi przyborami Wisły.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81602, 'Jezioro Kiełpińskie', 'jezioro-kielpinskie', 'LAKE', 52.36174, 20.876191, 'Mazowieckie', 'Łomianki', 'Kiełpińskie to malownicze starorzecze Wisły, stanowiące część rezerwatu przyrody. Jest węższe i bardziej "dzikie" niż sąsiednie Dziekanowskie. Woda posiada przyzwoitą przejrzystość, a brzegi są porośnięte starymi wierzbami i gęstymi szuwarami. Dno jest urozmaicone z dużą ilością powalonych drzew, co tworzy naturalne kryjówki dla ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81603, 'Jezioro Oborskie', 'jezioro-oborskie', 'LAKE', 52.991082, 19.218006, 'Kujawsko-Pomorskie', 'Lipno / Obory', 'Jezioro Oborskie to typowy akwen rynnowy Pojezierza Dobrzyńskiego. Charakteryzuje się pofałdowanym dnem i maksymalną głębokością ok. 8-10 metrów. Woda posiada dobrą klasę czystości. Brzegi są zróżnicowane – od wysokich zalesionych skarp po łagodne zejścia wśród pól. Akwen jest wyciszony i osłonięty od wiatru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81604, 'Jezioro Żalskie Duże', 'jezioro-zalskie-duze', 'LAKE', 53.016541, 19.318085, 'Kujawsko-Pomorskie', 'Rypin / Żałe', 'Żalskie Duże (znane też jako Wielkie) to największy zbiornik w rynnie żalskiej (pow. ok. 90 ha). Akwen charakteryzuje się monumentalną batymetrią z głębokością sięgającą 15-18 metrów. Woda jest dobrze natleniona. Dno jest wysoce urozmaicone z licznymi podwodnymi górkami i twardymi, gliniastymi skarpami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81605, 'Jezioro Głęboczek (k. Żałe)', 'jezioro-gleboczek-zale', 'LAKE', 53.026117, 19.334092, 'Kujawsko-Pomorskie', 'Rypin / Żałe', 'Głęboczek to mniejszy, rynnowy sąsiad jeziora Żalskiego. Zgodnie z nazwą, zbiornik jest stosunkowo głęboki w stosunku do swojej powierzchni (max ok. 10 m). Posiada twarde piaszczyste dno i czystą wodę. Brzegi są wysokie i w dużej mierze zalesione, co zapewnia osłonę przed wiatrem i nadaje akwenowi kameralny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81606, 'Jezioro Kapiec', 'jezioro-kapiec', 'LAKE', 53.032309, 19.306583, 'Kujawsko-Pomorskie', 'Rypin / Brzuze', 'Kapiec to niewielki, kameralny zbiornik o charakterze eutroficznym, położony w ustronnej dolinie. Dno jest w dużej mierze muliste, bogate w bentos, z licznymi skupiskami grążeli żółtych. Akwen jest wybitnie wyciszony, co sprzyja rozwojowi narybku i czyni go idealnym miejscem dla ryb ciepłolubnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81607, 'Jezioro Bobrowiec', 'jezioro-bobrowiec', 'LAKE', 53.037598, 19.308901, 'Kujawsko-Pomorskie', 'Rypin / Brzuze', 'Jezioro Bobrowiec to malowniczy akwen położony wśród wzgórz morenowych. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym w strefie litoralu. Maksymalna głębokość oscyluje wokół 8 metrów. Jezioro posiada dobrze rozwinięty pas roślinności wynurzonej, stanowiący świetną ostoję dla szczupaka i okonia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81608, 'Jezioro Kleszczyńskie', 'jezioro-kleszczynskie', 'LAKE', 53.050228, 19.287379, 'Kujawsko-Pomorskie', 'Rypin / Kleszczyn', 'Jezioro Kleszczyńskie to akwen rynnowy o powierzchni ok. 40 ha. Charakteryzuje się czystą wodą i twardym dnem w strefie przybrzeżnej. Maksymalna głębokość sięga 12-14 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są wysokie i częściowo zagospodarowane rolniczo.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81609, 'Jezioro Ostrowieckie (k. Rypina)', 'jezioro-ostrowieckie-rypin', 'LAKE', 53.061687, 19.292078, 'Kujawsko-Pomorskie', 'Rypin / Ostrowite', 'Ostrowieckie to malownicza rynna rynnowa charakteryzująca się czystą wodą i twardym dnem piaszczysto-żwirowym. Maksymalna głębokość sięga 12 metrów. Brzegi są wysokie, porośnięte lasem mieszanym, co zapewnia doskonałą osłonę przed wiatrem. Akwen posiada urozmaiconą linię brzegową z licznymi powalonymi do wody drzewami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81610, 'Jezioro Czarownica', 'jezioro-czarownica', 'LAKE', 53.061558, 19.314909, 'Kujawsko-Pomorskie', 'Rypin / Brzuze', 'Jezioro Czarownica to dziki, śródleśny akwen o charakterze dystroficzno-eutroficznym. Nazwa nawiązuje do mrocznej, herbacianej wody i otoczenia gęstym lasem. Dno jest wybitnie miękkie, wyścielone osadami organicznymi. Maksymalna głębokość nie przekracza 5 metrów. Brzegi są niskie i bagniste, co sprawia, że dostęp do wody z brzegu jest ograniczony.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81611, 'Jezioro Mażańskie', 'jezioro-mazanskie', 'LAKE', 54.121758, 21.518483, 'Warmińsko-Mazurskie', 'Kętrzyn / Srokowo', 'Jezioro Mażańskie to kameralny, śródleśny zbiornik o charakterze eutroficzno-dystroficznym. Akwen charakteryzuje się mroczną wodą i bardzo miękkim, torfowym dnem. Maksymalna głębokość nie przekracza 4-5 metrów. Jezioro jest wyciszone, stanowiąc doskonałe miejsce dla ryb spokojnego żeru szukających schronienia w gęstych pasach trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81612, 'Jezioro Boczniel', 'jezioro-boczniel-2', 'LAKE', 54.138515, 23.177676, 'Podlaskie', 'Suwałki / Sejny', 'Boczniel to urokliwa rynna polodowcowa położona w pofalowanym krajobrazie Suwalszczyzny. Charakteryzuje się czystą wodą i twardym dnem piaszczysto-żwirowym. Maksymalna głębokość oscyluje wokół 10-12 metrów. Brzegi są wysokie, w dużej mierze zalesione, co zapewnia osłonę przed wiatrem i nadaje jezioru kameralny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81613, 'Jezioro Płaskie (k. Sejn)', 'jezioro-plaskie-sejny', 'LAKE', 54.144624, 23.276124, 'Podlaskie', 'Sejny / Żegary', 'Jezioro Płaskie to malowniczy akwen rynnowy o powierzchni ok. 40 ha. Mimo nazwy, batymetria jeziora jest urozmaicona, z rynną sięgającą 12-14 metrów. Woda posiada wysoką klasę czystości. Brzegi są w większości wysokie i suche, co sprzyja rekreacji wędkarskiej. Akwen jest połączony systemem rowów z innymi jeziorami rynny sejneńskiej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81614, 'Jezioro Dumblis', 'jezioro-dumblis', 'LAKE', 54.220276, 23.456089, 'Podlaskie', 'Sejny / Bubele', 'Jezioro Dumblis leży w bezpośrednim sąsiedztwie granicy z Litwą. Jest to akwen o charakterze rynnowym z dnem piaszczysto-mulistym. Maksymalna głębokość sięga 10 metrów. Woda posiada dobrą klasę czystości. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin, co ułatwia dostęp do lustra wody z brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81615, 'Jezioro Bałędź', 'jezioro-baledz', 'LAKE', 54.094212, 23.508897, 'Podlaskie', 'Giby / Puszcza Augustowska', 'Jezioro Bałędź to dziki, śródleśny akwen rynnowy położony w samym sercu Puszczy Augustowskiej. Charakteryzuje się krystalicznie czystą wodą i twardym dnem piaszczysto-żwirowym. Maksymalna głębokość sięga ok. 15 metrów. Brzegi są wysokie i w całości porośnięte majestatycznym borem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81616, 'Jezioro Pilwie', 'jezioro-pilwie', 'LAKE', 54.091092, 23.479114, 'Podlaskie', 'Giby', 'Pilwie to kameralny, rynnowy sąsiad jeziora Bałędź. Akwen posiada twarde podłoże i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8-10 metrów biegnie przez środek jeziora. Brzegi są porośnięte lasem sosnowym, co zapewnia ciszę i osłonę przed wiatrem. Roślinność wodna jest umiarkowana.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81617, 'Jezioro Kielig', 'jezioro-kielig', 'LAKE', 54.07793, 23.461819, 'Podlaskie', 'Giby / Puszcza Augustowska', 'Jezioro Kielig to urokliwa rynna polodowcowa, ukryta w gęstym kompleksie leśnym. Akwen charakteryzuje się bardzo czystą wodą i twardym, piaszczysto-żwirowym dnem. Batymetria jest typowa dla regionu: strome spady zaczynają się blisko brzegu i schodzą do centralnej rynny sięgającej 12-14 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81618, 'Jezioro Gajlik', 'jezioro-gajlik', 'LAKE', 54.081756, 23.449159, 'Podlaskie', 'Giby', 'Gajlik to niewielki, kameralny zbiornik rynnowy ukryty wśród wzgórz i kęp lasów. Akwen charakteryzuje się czystą wodą i twardym dnem w strefie przybrzeżnej. Maksymalna głębokość oscyluje wokół 7-8 metrów. Jezioro jest wyciszone, osłonięte od wiatru, co sprzyja rozwojowi bujnej roślinności zanurzonej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81619, 'Jezioro Kaczan', 'jezioro-kaczan', 'LAKE', 54.042562, 23.361139, 'Podlaskie', 'Giby / Puszcza Augustowska', 'Jezioro Kaczan to hydrologiczna perełka Puszczy Augustowskiej – akwen o charakterze zbliżonym do lobeliowego z krystalicznie czystą wodą. Posiada wybitnie twarde, piaszczyste dno i bardzo ubogi litoral. Maksymalna głębokość sięga ok. 10 metrów. Jezioro położone jest w głębokiej niecce leśnej, co chroni je przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81620, 'Jezioro Miławskie', 'jezioro-milawskie', 'LAKE', 52.532265, 17.941403, 'Wielkopolskie', 'Trzemeszno', 'Miławskie to urokliwy zbiornik rynnowy położony w pofałdowanym krajobrazie rolniczym. Posiada piaszczysto-muliste dno i średnią głębokość ok. 5-7 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są częściowo zalesione, co zapewnia osłonę przed wiatrem.', 'PZW Poznań');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81621, 'Jezioro Degużynie', 'jezioro-deguzynie', 'LAKE', 54.020044, 23.491967, 'Podlaskie', 'Sejny / Giby', 'Degużynie to malowniczy akwen rynnowy (pow. ok. 30 ha) o bardzo wydłużonym kształcie. Posiada czystą wodę i twarde dno piaszczysto-żwirowe. Batymetria jest typowo rynnowa: ostre spady zaczynają się blisko brzegu i schodzą do centralnej rynny o głębokości ok. 12-14 metrów. Jezioro jest w całości otoczone lasem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81622, 'Jezioro Sienkiewielek', 'jezioro-sienkiewielek', 'LAKE', 53.898486, 23.450682, 'Podlaskie', 'Płaska / Puszcza Augustowska', 'Sienkiewielek to mały, śródleśny zbiornik o charakterze dystroficznym, ukryty głęboko w Puszczy Augustowskiej. Woda posiada mroczny, herbaciany odcień, a dno jest bardzo miękkie, wyścielone osadami leśnymi. Maksymalna głębokość nie przekracza 4-5 metrów. Brzegi są niskie, bagniste, porośnięte mchem torfowcem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81623, 'Jezioro Ślepe', 'jezioro-slepe', 'LAKE', 53.889344, 23.405449, 'Podlaskie', 'Płaska / Puszcza Augustowska', 'Jezioro Ślepe to urokliwe "oczko" leśne o charakterze dystroficzno-eutroficznym, położone w ciągu jezior w pobliżu Płaskiej. Akwen charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i miękkim dnem. Maksymalna głębokość nie przekracza 5 metrów. Brzegi są niskie, silnie zarośnięte trzciną pospolitą, co zapewnia rybom absolutny spokój.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81624, 'Jezioro Gulbik', 'jezioro-gulbik', 'LAKE', 53.65968, 20.73633, 'Warmińsko-Mazurskie', 'Pasym', 'Gulbik to kameralny zbiornik położony w bezpośrednim sąsiedztwie jeziora Kalwa. Ma charakter eutroficzny, z dnem mulistym i bogatą roślinnością brzegową. Maksymalna głębokość nie przekracza 5 metrów. Jezioro jest zaciszne, stanowiąc doskonałe miejsce dla ryb spokojnego żeru szukających schronienia przed drapieżnikami z większych akwenów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81625, 'Jezioro Pawlik', 'jezioro-pawlik', 'LAKE', 53.662406, 20.745385, 'Warmińsko-Mazurskie', 'Pasym', 'Pawlik to niewielkie, rynnowe "oczko" stanowiące część systemu hydrologicznego Pasymia. Charakteryzuje się czystą wodą i twardym dnem w strefie litoralu. Maksymalna głębokość oscyluje wokół 6-7 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez pagórkowaty teren, co sprzyja rozwojowi bujnej roślinności zanurzonej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81626, 'Jezioro Wadąg', 'jezioro-wadag', 'LAKE', 53.834903, 20.585289, 'Warmińsko-Mazurskie', 'Olsztyn / Myki', 'Jezioro Wadąg to potężny akwen rynnowy (pow. ok. 490 ha) położony na północny wschód od Olsztyna. To jedno z najbardziej rybnych jezior w regionie, charakteryzujące się wybitnie urozmaiconym dnem z licznymi górkami, głębokimi rynnami (max 35 m) i twardymi skarpami. Przez jezioro przepływa rzeka Wadąg, co zapewnia świetne natlenienie wody.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81627, 'Jezioro Łęgajny (Linowskie)', 'jezioro-legajny', 'LAKE', 53.830649, 20.631981, 'Warmińsko-Mazurskie', 'Barczewo / Łęgajny', 'Jezioro Łęgajny (często nazywane Linowskim) to malowniczy zbiornik o charakterze eutroficznym. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 5 metrów. Woda jest żyzna, co sprzyja rozwojowi dorodnego lina i karasia. Brzegi są porośnięte gęstym pasem trzcin, z licznymi stanowiskami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81628, 'Jezioro Dywickie', 'jezioro-dywickie', 'LAKE', 53.83197, 20.48491, 'Warmińsko-Mazurskie', 'Dywity / Olsztyn', 'Jezioro Dywickie to niewielki akwen położony w centrum miejscowości Dywity. Posiada charakter rynnowy z dnem piaszczysto-mulistym i maksymalną głębokością ok. 7-8 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są zagospodarowane rekreacyjnie – mola, ścieżki spacerowe i oświetlone alejki sprzyjają wędkowaniu rodzinnemu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81629, 'Jezioro Mosąg', 'jezioro-mosag', 'LAKE', 53.855166, 20.395947, 'Warmińsko-Mazurskie', 'Dywity / Różnowo', 'Jezioro Mosąg to specyficzny akwen rynnowo-przepływowy, przez który przepływa rzeka Łyna. Posiada wybitnie rzeczny charakter z wyraźnie zaznaczonym korytem rzeki na dnie. Maksymalna głębokość sięga 6-7 metrów. Dzięki stałemu przepływowi woda jest doskonale natleniona, co sprzyja dużej biomasie ryb drapieżnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81630, 'Jezioro Bukwałdzkie', 'jezioro-bukwaldzkie', 'LAKE', 53.873558, 20.349512, 'Warmińsko-Mazurskie', 'Dywity / Bukwałd', 'Jezioro Bukwałdzkie to malowniczy zbiornik rynnowy położony w pofałdowanym terenie rolniczo-leśnym. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość oscyluje wokół 12-14 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę. Brzegi są w większości dostępne, z licznymi kładkami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81631, 'Jezioro Pupel Duży', 'jezioro-pupel-duzy', 'LAKE', 53.896301, 20.392857, 'Warmińsko-Mazurskie', 'Dobre Miasto / Swobodna', 'Pupel Duży (często nazywany Jeziorem Swobodna) to malowniczy, śródleśny zbiornik o charakterze rynnowym. Akwen cechuje się twardym dnem piaszczysto-żwirowym i bardzo czystą wodą. Batymetria jest urozmaicona z rynną sięgającą 10-12 metrów. Brzegi są wysokie i porośnięte majestatycznym lasem sosnowym, co nadaje akwenowi dziki i ustronny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81632, 'Jezioro Pupel Mały', 'jezioro-pupel-maly', 'LAKE', 53.897818, 20.388007, 'Warmińsko-Mazurskie', 'Dobre Miasto / Swobodna', 'Pupel Mały to kameralny, śródleśny zbiornik położony w bezpośrednim sąsiedztwie Pupla Dużego. Ma charakter eutroficzny, z dnem mulistym i bogatszą roślinnością brzegową. Maksymalna głębokość nie przekracza 5 metrów. Jezioro jest wyciszone, stanowiąc doskonałe miejsce dla ryb spokojnego żeru szukających schronienia w pasach grążeli i lilii wodnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81633, 'Jezioro Limajno', 'jezioro-limajno', 'LAKE', 53.925411, 20.368996, 'Warmińsko-Mazurskie', 'Dobre Miasto / Swobodna', 'Jezioro Limajno, zwane "Perłą Warmii", to jeden z najczystszych i najgłębszych akwenów w regionie (I klasa czystości, max ok. 40 m). To potężna rynna sielawowa z krystalicznie czystą wodą i monumentalną batymetrią. Dno jest wybitnie twarde, piaszczysto-żwirowe. Brzegi są wysokie i w całości zalesione, co zapewnia unikatowy mikroklimat.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81634, 'Jezioro Stobajno', 'jezioro-stobajno', 'LAKE', 53.923291, 20.398393, 'Warmińsko-Mazurskie', 'Dobre Miasto / Czerwonka', 'Stobajno to mniejszy, ustronny zbiornik połączony wąskim przesmykiem z jeziorem Limajno. Charakteryzuje się mulistym dnem i średnią głębokością ok. 4-6 metrów. Jezioro jest wyciszone, osłonięte od wiatru, co sprzyja rozwojowi bujnej roślinności brzegowej. Woda szybko nagrzewa się wiosną, co stymuluje ryby do intensywnego żerowania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81635, 'Jezioro Kwiecewo', 'jezioro-kwiecewo', 'LAKE', 53.93467, 20.304923, 'Warmińsko-Mazurskie', 'Dobre Miasto / Kwiecewo', 'Jezioro Kwiecewo to rozległy, wybitnie płytki akwen (max 2 m) o charakterze polderowym-eutroficznym. Dno jest wysoce muliste, a lustro wody w dużej części porośnięte roślinnością wynurzoną. Stanowi ono kluczowe tarlisko dla ryb całego systemu dorzecza Łyny oraz jest ważnym punktem na ornitologicznej mapie Polski.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81636, 'Jezioro Przybiernowskie', 'jezioro-przybiernowskie', 'LAKE', 53.751813, 14.761505, 'Zachodniopomorskie', 'Przybiernów', 'Jezioro Przybiernowskie to malowniczy, stosunkowo płytki akwen (pow. ok. 80 ha) położony na Równinie Goleniowskiej. Charakteryzuje się mulistym dnem z licznymi piaszczystymi łachami. Maksymalna głębokość oscyluje wokół 5-6 metrów. Brzegi są niskie, porośnięte gęstym pasem trzcin, co stwarza idealne warunki dla ryb spokojnego żeru.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81637, 'Jezioro Rozgwiazda', 'jezioro-rozgwiazda', 'LAKE', 53.565525, 14.637051, 'Zachodniopomorskie', 'Szczecin / Pucice', 'Rozgwiazda to niewielkie, kameralne jezioro położone w otulinie leśnej niedaleko Pucic. Akwen posiada bardzo urozmaiconą linię brzegową z charakterystycznymi zatokami (stąd nazwa). Dno jest piaszczysto-muliste, a woda posiada przyzwoitą przejrzystość wiosną. Jezioro jest wyciszone, stanowiąc doskonałe schronienie dla ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81638, 'Jezioro Goleniowskie', 'jezioro-goleniowskie', 'LAKE', 53.545397, 14.874544, 'Zachodniopomorskie', 'Goleniów', 'Jezioro Goleniowskie (często utożsamiane z lokalnymi rozlewiskami rzeki Iny) to akwen o charakterze nizinnym i wybitnie żyznej wodzie. Dno jest miękkie, wyścielone osadami organicznymi. Maksymalna głębokość nie przekracza 4 metrów. Jezioro jest silnie zarastające, co sprzyja biomasie ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81639, 'Jezioro Warchlińskie (Warchlino)', 'jezioro-warchlinskie', 'LAKE', 53.439338, 14.982798, 'Zachodniopomorskie', 'Stargard / Warchlino', 'Warchlińskie to urokliwy, rynnowy akwen położony wśród pól i zagajników. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 5-7 metrów. Woda posiada dobrą klasę czystości. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin, co ułatwia dostęp do lustra wody z brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81640, 'Jezioro Grabowskie', 'jezioro-grabowskie-2', 'LAKE', 53.406616, 15.089507, 'Zachodniopomorskie', 'Stara Dąbrowa / Grabowo', 'Jezioro Grabowskie to akwen rynnowy o powierzchni ok. 30 ha. Charakteryzuje się mulistym dnem i średnią głębokością ok. 4-5 metrów. Woda jest żyzna, co sprzyja rozwojowi bujnej roślinności zanurzonej. Brzegi są częściowo porośnięte lasem mieszanym, z wieloma dzikimi stanowiskami wędkarskimi i kładkami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81641, 'Jezioro Starzyca (Chociwel)', 'jezioro-starzyca', 'LAKE', 53.463018, 15.339189, 'Zachodniopomorskie', 'Chociwel', 'Starzyca to malownicze jezioro rynnowe położone bezpośrednio przy miejscowości Chociwel. Charakteryzuje się urozmaiconą linią brzegową i dnem piaszczysto-mulistym. Maksymalna głębokość sięga 8-9 metrów. Brzegi są w całości zagospodarowane rekreacyjnie – promenada, mola i oświetlone alejki sprzyjają wędkowaniu miejskiemu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81642, 'Jezioro Kamienny Most', 'jezioro-kamienny-most', 'LAKE', 53.466823, 15.388069, 'Zachodniopomorskie', 'Chociwel / Kamienny Most', 'Kamienny Most to jeden z najpiękniejszych akwenów regionu (pow. ok. 40 ha). Słynie z krystalicznie czystej wody i twardego, piaszczystego dna. Maksymalna głębokość sięga 12 metrów. Jezioro jest otoczone gęstymi lasami i pagórkami, co nadaje mu kameralny charakter i zapewnia świetną osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81643, 'Jezioro Sadlińskie (Sadlno)', 'jezioro-sadlinskie', 'LAKE', 53.477702, 15.444009, 'Zachodniopomorskie', 'Węgorzyno', 'Jezioro Sadlińskie (Sadlno) to malowniczy akwen rynnowy położony na południowy zachód od Węgorzyna. Charakteryzuje się piaszczysto-mulistym dnem i głębokością sięgającą 12-14 metrów. Woda posiada przyzwoitą przejrzystość wiosną. Brzegi są urozmaicone, częściowo zalesione, z wieloma dzikimi stanowiskami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81644, 'Jezioro Węgorzyno (Derkacz)', 'jezioro-wegorzyno-derkacz', 'LAKE', 53.48322, 15.471067, 'Zachodniopomorskie', 'Węgorzyno', 'Jezioro Węgorzyno (często utożsamiane z połączonym akwenem Derkacz) to serce rekreacyjne Węgorzyna. Jest to głęboka rynna polodowcowa (pow. ok. 70 ha) o głębokości sięgającej blisko 15-18 metrów. Woda jest dobrze natleniona. Brzegi są w całości zagospodarowane miejską infrastrukturą – promenady, mola i oświetlone kładki sprzyjają wędkowaniu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81645, 'Jezioro Dłusko', 'jezioro-dlusko', 'LAKE', 53.480056, 15.497589, 'Zachodniopomorskie', 'Węgorzyno / Dłusko', 'Dłusko to monumentalna rynna polodowcowa charakteryzująca się krystalicznie czystą wodą i wybitnie twardym dnem. Maksymalna głębokość sięga blisko 20 metrów. Akwen posiada sielawowy charakter i bardzo ubogi litoral, co przekłada się na niesamowitą przejrzystość toni. Brzegi są wysokie, porośnięte majestatycznym lasem bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81646, 'Jezioro Storkowskie Górne', 'jezioro-storkowskie-gorne', 'LAKE', 53.530857, 15.586982, 'Zachodniopomorskie', 'Ińsko / Storkowo', 'Storkowskie Górne to kameralny, śródleśny zbiornik o charakterze rynnowym. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna – rynna o głębokości do 8-10 metrów biegnie przez środek jeziora. Brzegi są porośnięte starym borem sosnowym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81647, 'Jezioro Storkowskie Dolne', 'jezioro-storkowskie-dolne', 'LAKE', 53.528485, 15.582905, 'Zachodniopomorskie', 'Ińsko / Storkowo', 'Storkowskie Dolne to ustronny sąsiad jeziora Górnego, połączony z nim okresowo wąskim ciekiem. Charakteryzuje się bardziej mulistym dnem i średnią głębokością ok. 4-6 metrów. Jezioro jest wyciszone, osłonięte od wiatru, co sprzyja rozwojowi bujnej roślinności brzegowej. Woda szybko nagrzewa się wiosną, co stymuluje ryby do żerowania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81648, 'Jezioro Czarne Górne', 'jezioro-czarne-gorne', 'LAKE', 53.521638, 15.580201, 'Zachodniopomorskie', 'Ińsko / Storkowo', 'Czarne Górne to dziki, śródleśny akwen o charakterze dystroficzno-eutroficznym. Charakteryzuje się mroczną wodą o lekkim zabarwieniu humusowym i miękkim dnem wyścielonym osadami leśnymi. Maksymalna głębokość nie przekracza 5 metrów. Brzegi są niskie, porośnięte mchem torfowcem, co zapewnia rybom absolutny spokój.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81649, 'Jezioro Wolnowo', 'jezioro-wolnowo', 'LAKE', 53.505931, 15.578849, 'Zachodniopomorskie', 'Węgorzyno / Ińsko', 'Wolnowo to malownicze jezioro rynnowe położone w północnej otulinie Ińskiego Parku Krajobrazowego. Posiada twarde, piaszczyste dno i wodę o dobrej przejrzystości. Brzegi są wysokie i porośnięte gęstym lasem liściastym. Maksymalna głębokość oscyluje wokół 10-12 metrów.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81650, 'Jezioro Ińsko', 'jezioro-insko', 'LAKE', 53.443502, 15.538187, 'Zachodniopomorskie', 'Ińsko', 'Jezioro Ińsko to hydrologiczna perła Pomorza Zachodniego (pow. ok. 600 ha). Słynie z krystalicznej wody (I klasa) i monumentalnej głębokości sięgającej 42 metrów. Dno jest wybitnie urozmaicone z licznymi wyspami, podwodnymi górkami i stromymi uskokami. Jest to jedno z ulubionych miejsc nurków w Polsce.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81651, 'Jezioro Ścienne', 'jezioro-scienne', 'LAKE', 53.445393, 15.503683, 'Zachodniopomorskie', 'Ińsko / Ścienne', 'Jezioro Ścienne to rynnowy sąsiad Ińska, połączony z nim okresowo wąskim ciekiem. Akwen posiada twarde podłoże i bardzo czystą wodę. Batymetria jest regularna z rynną sięgającą 10-12 metrów. Jezioro jest wybitnie wyciszone, osłonięte od wiatrów przez wysokie skarpy zalesione borem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81652, 'Jezioro Linówka', 'jezioro-linowka-2', 'LAKE', 53.420601, 15.468664, 'Zachodniopomorskie', 'Ińsko', 'Linówka to niewielki, kameralny zbiornik o charakterze eutroficznym, położony wśród borów i mokradeł. Akwen jest stosunkowo płytki (max 3-4 m) z dnem wyścielonym grubą warstwą mułu i osadów organicznych. Woda nagrzewa się szybko, co sprzyja aktywności ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81653, 'Jezioro Okunie', 'jezioro-okunie', 'LAKE', 53.393117, 15.49922, 'Zachodniopomorskie', 'Ińsko / Chociwel', 'Jezioro Okunie to malowniczy, śródleśny akwen rynnowy położony w południowej części Parku Ińskiego. Posiada twarde dno i krystalicznie czystą wodę. Maksymalna głębokość sięga 8 metrów. Brzegi są wysokie i w całości porośnięte majestatycznym lasem bukowym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81654, 'Jezioro Stubnica', 'jezioro-stubnica', 'LAKE', 53.413802, 15.550033, 'Zachodniopomorskie', 'Ińsko', 'Stubnica to urokliwy zbiornik rynnowy położony w bliskim sąsiedztwie Ińska. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 8-10 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są urozmaicone, z wieloma dzikimi stanowiskami wędkarskimi i kładkami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81655, 'Jezioro Długie (Ińsko)', 'jezioro-dlugie-insko', 'LAKE', 53.442045, 15.585008, 'Zachodniopomorskie', 'Ińsko', 'Jezioro Długie to klasyczna rynna polodowcowa, długa i wąska, wciśnięta w pofalowany krajobraz (pow. ok. 40 ha). Akwen charakteryzuje się twardym dnem w strefie przybrzeżnej i rynną środkową sięgającą 12 metrów. Woda posiada wysoką klasę czystości. Brzegi są w większości wysokie i zalesione.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81656, 'Jezioro Kiełpino Małe', 'jezioro-kielpino-male', 'LAKE', 53.434359, 15.607303, 'Zachodniopomorskie', 'Ińsko / Kiełpino', 'Kiełpino Małe to niewielki, kameralny zbiornik rynnowy położony wśród wzgórz morenowych. Posiada muliste dno i przyzwoitą przejrzystość wody wiosną. Maksymalna głębokość nie przekracza 6 metrów. Jezioro jest wyciszone, stanowiąc doskonałe miejsce dla ryb spokojnego żeru szukających schronienia w pasach trzcin i lilii wodnych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81657, 'Mała Noteć (Rozlewisko)', 'mala-notec-rozlewisko', 'LAKE', 52.541156, 17.967067, 'Wielkopolskie', 'Trzemeszno / Kamieniec', 'Ten punkt odnosi się do spowolnionego nurtu i rozlewisk Małej Noteci. Ma charakter rzeki nizinnej o bardzo słabym uciągu, przypominającej wydłużone jezioro. Dno jest miękkie, bogate w roślinność zanurzoną. To idealne miejsce na lina i szczupaka, który znajduje tu świetne warunki do rozrodu.', 'PZW Poznań');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81658, 'Jezioro Kolpino (Kiełpino)', 'jezioro-kolpino', 'LAKE', 53.441534, 15.61595, 'Zachodniopomorskie', 'Ińsko / Kiełpino', 'Jezioro Kolpino (często nazywane po prostu Kiełpinem) to akwen rynnowy o powierzchni ok. 50 ha. Charakteryzuje się pofałdowanym dnem piaszczysto-mulistym i średnią głębokością ok. 8 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin, co ułatwia dostęp do lustra wody z brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81659, 'Jezioro Studnica (Poligon)', 'jezioro-studnica-drawsko', 'LAKE', 53.452285, 15.654101, 'Zachodniopomorskie', 'Drawsko Pomorskie / Poligon', 'Jezioro Studnica to potężny akwen rynnowy położony na terenie Poligonu Drawskiego. Słynie z bardzo czystej wody i twardego dna. Maksymalna głębokość sięga 25 metrów. Ze względu na położenie w strefie wojskowej, dostęp do jeziora jest ograniczony i możliwy tylko po uzyskaniu stosownych zezwoleń (zazwyczaj w okresach wolnych od strzelań).
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81660, 'Jezioro Mielno (Poligon)', 'jezioro-mielno-drawsko', 'LAKE', 53.45254, 15.68234, 'Zachodniopomorskie', 'Drawsko Pomorskie / Poligon', 'Mielno to rynnowy sąsiad Studnicy, również położony w sercu Poligonu Drawskiego. Charakteryzuje się mulistym dnem i średnią głębokością ok. 10 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez gęsty pas lasu, co sprzyja rozwojowi bujnej roślinności zanurzonej i doskonałych warunków dla drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81661, 'Jezioro Ostrowiec (Poligon)', 'jezioro-ostrowiec-drawsko', 'LAKE', 53.450368, 15.718775, 'Zachodniopomorskie', 'Drawsko Pomorskie / Poligon', 'Jezioro Ostrowiec to urokliwy, śródleśny zbiornik o charakterze rynnowym na terenie poligonu. Akwen cechuje się krystaliczną wodą i twardym dnem piaszczysto-żwirowym. Batymetria jest regularna – rynna o głębokości do 12 metrów biegnie przez środek jeziora. Brzegi są wysokie i porośnięte majestatycznym lasem bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81662, 'Jezioro Trzepielewo', 'jezioro-trzepielewo', 'LAKE', 53.442422, 15.729074, 'Zachodniopomorskie', 'Drawsko Pomorskie / Karwice', 'Trzepielewo to kameralne, śródpolne jezioro o charakterze eutroficznym. Posiada muliste dno i średnią głębokość ok. 4-5 metrów. Woda jest żyzna, co sprzyja biomasie ryb karpiowatych. Brzegi są porośnięte gęstym pasem trzciny pospolitej, z nielicznymi wydeptanymi stanowiskami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81663, 'Jezioro Rekowo Wielkie', 'jezioro-rekowo-wielkie', 'LAKE', 53.443147, 15.7586, 'Zachodniopomorskie', 'Drawsko Pomorskie / Rekowo', 'Rekowo Wielkie to malowniczy akwen rynnowy położony w pofałdowanym terenie Pojezierza Drawskiego. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym w strefie litoralu. Maksymalna głębokość sięga ok. 15 metrów. Brzegi są urozmaicone, z licznymi kładkami i stanowiskami wędkarskimi od strony miejscowości Rekowo.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81664, 'Jezioro Bucierz Mały (Poligon)', 'jezioro-bucierz-maly', 'LAKE', 53.459592, 15.769994, 'Zachodniopomorskie', 'Drawsko Pomorskie / Poligon', 'Bucierz Mały to kameralny, rynnowy sąsiad wielkiego jeziora Bucierz, położony na terenie zamkniętym poligonu. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Batymetria jest regularna z rynną sięgającą 10 metrów. Jezioro jest wybitnie wyciszone, stanowiąc doskonałe siedlisko dla ryb lubiących spokój.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81665, 'Jezioro Bucierz (Poligon)', 'jezioro-bucierz-drawsko', 'LAKE', 53.466911, 15.768278, 'Zachodniopomorskie', 'Drawsko Pomorskie / Poligon', 'Jezioro Bucierz to legenda polskiego wędkarstwa (pow. ok. 200 ha), położone w samym centrum Poligonu Drawskiego. Jest to głęboka rynna polodowcowa (max 28 m) o krystalicznie czystej wodzie. Akwen przez dekady był niemal całkowicie wyłączony z amatorskiego połowu ryb, co pozwoliło na zachowanie populacji gigantycznych drapieżników.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81666, 'Jezioro Wiry', 'jezioro-wiry', 'LAKE', 53.404085, 15.840011, 'Zachodniopomorskie', 'Kalisz Pomorski / Cybowo', 'Jezioro Wiry to kameralny, śródleśny akwen rynnowy położony w pofalowanym terenie morenowym. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość sięga 8-10 metrów. Brzegi są wysokie i w całości porośnięte lasem mieszanym, co zapewnia doskonałą osłonę przed wiatrem i nadaje łowisku intymny charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81667, 'Jezioro Małe Dębno', 'jezioro-male-debno', 'LAKE', 53.401731, 15.852928, 'Zachodniopomorskie', 'Kalisz Pomorski / Cybowo', 'Małe Dębno to rynnowy sąsiad Wielkiego Dębna, charakteryzujący się twardym, piaszczystym dnem i bardzo czystą wodą. Maksymalna głębokość oscyluje wokół 10-12 metrów. Jezioro posiada regularną linię brzegową i jest otoczone gęstym lasem sosnowym. Dzięki przepływowemu charakterowi woda jest dobrze natleniona przez cały rok.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81668, 'Jezioro Wielkie Dębno', 'jezioro-wielkie-debno', 'LAKE', 53.398278, 15.860353, 'Zachodniopomorskie', 'Kalisz Pomorski / Cybowo', 'Jezioro Wielkie Dębno to potężna rynna polodowcowa o powierzchni ok. 50 ha i głębokości sięgającej blisko 25 metrów. Woda posiada wysoką klasę czystości i sielawowy charakter. Dno jest wybitnie twarde, piaszczysto-żwirowe z gwałtownymi uskokami. Brzegi są wysokie, porośnięte majestatycznym lasem bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81669, 'Jezioro Binowo (k. Kalisza)', 'jezioro-binowo-kalisz', 'LAKE', 53.400811, 15.886059, 'Zachodniopomorskie', 'Kalisz Pomorski', 'Binowo pod Kaliszem Pomorskim to niewielki, ustronny zbiornik o charakterze rynnowym. Akwen posiada piaszczysto-muliste dno i średnią głębokość ok. 5-6 metrów. Jezioro jest wyciszone, osłonięte od wiatru, co sprzyja rozwojowi bujnej roślinności zanurzonej. Woda posiada przyzwoitą przejrzystość wiosną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81670, 'Jezioro Strunowo', 'jezioro-strunowo', 'LAKE', 53.381309, 15.777955, 'Zachodniopomorskie', 'Kalisz Pomorski / Strunowo', 'Jezioro Strunowo to malowniczy, śródpolny akwen o charakterze eutroficznym. Zbiornik jest stosunkowo płytki (max 4-5 m), z dnem wyścielonym osadami organicznymi. Brzegi są niskie, silnie zarośnięte trzciną i tatarakiem, co stwarza idealne warunki dla ryb ciepłolubnych i ptactwa wodnego.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81671, 'Jezioro Zły Łęg', 'jezioro-zly-leg', 'LAKE', 53.390368, 15.790229, 'Zachodniopomorskie', 'Kalisz Pomorski / Cybowo', 'Zły Łęg to dziki, śródleśny zbiornik o charakterze dystroficznym. Woda posiada charakterystyczny, herbaciany odcień, a dno jest bardzo miękkie, wyścielone osadami torfowymi. Maksymalna głębokość nie przekracza 3-4 metrów. Jezioro jest wybitnie wyciszone i niemal całkowicie otoczone gęstym borem iglastym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81672, 'Jezioro Pańskie', 'jezioro-panskie', 'LAKE', 53.296008, 15.702124, 'Zachodniopomorskie', 'Drawno / Kalisz Pomorski', 'Jezioro Pańskie to urokliwy, śródleśny akwen o charakterze rynnowym, położony w otulinie Drawieńskiego Parku Narodowego. Posiada twarde dno i wodę o wysokiej przejrzystości. Maksymalna głębokość oscyluje wokół 8-10 metrów. Jezioro jest wybitnie wyciszone, otoczone starodrzewem, co zapewnia niemal mistyczną atmosferę podczas wędkowania.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81673, 'Jezioro Trzebuń', 'jezioro-trzebun', 'LAKE', 53.306186, 15.721393, 'Zachodniopomorskie', 'Drawno / Drawnik', 'Trzebuń to malownicze, mocno wydłużone jezioro rynnowe o powierzchni ok. 60 ha. Akwen charakteryzuje się bardzo urozmaiconym dnem z wyraźną rynną środkową sięgającą 15 metrów. Woda posiada I klasę czystości. Brzegi są wysokie, porośnięte lasem sosnowym, z licznymi dogodnymi miejscami do biwakowania i wędkowania z brzegu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81674, 'Jezioro Za Dywizją', 'jezioro-za-dywizja', 'LAKE', 53.318852, 15.721393, 'Zachodniopomorskie', 'Kalisz Pomorski / Poligon', 'Jezioro Za Dywizją to unikatowy akwen położony na skraju czynnego poligonu drawskiego. Nazwa nawiązuje do historycznych rejonów rozmieszczenia wojsk. Posiada dno piaszczysto-muliste i średnią głębokość ok. 6 metrów. Jezioro jest wybitnie wyciszone, stanowiąc doskonałe siedlisko dla ryb szukających spokoju. Roślinność brzegowa jest tu bardzo bogata.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81675, 'Jezioro Jodnik', 'jezioro-jodnik', 'LAKE', 53.316692, 15.723978, 'Zachodniopomorskie', 'Kalisz Pomorski / Poligon', 'Jodnik to kameralne, śródleśne "oczko" o charakterze wytopiskowym, sąsiadujące z jeziorem Za Dywizją. Posiada muliste dno i przyzwoitą przejrzystość wody wiosną. Maksymalna głębokość nie przekracza 5 metrów. Jezioro jest w całości otoczone gęstym borem, co zapewnia absolutną ciszę i ochronę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81676, 'Jezioro Lubniewsko', 'jezioro-lubniewsko', 'LAKE', 52.491619, 15.204649, 'Lubuskie', 'Lubniewice', 'Lubniewsko to największy akwen w grupie lubniewickiej (pow. ok. 240 ha). Jest to jezioro rynnowe o bardzo urozmaiconej linii brzegowej z licznymi zatokami i półwyspami. Maksymalna głębokość sięga 13-15 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są niemal w całości zalesione, co nadaje jezioru dziki charakter mimo bliskości kurortu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81677, 'Jezioro Lubiąż', 'jezioro-lubiaz', 'LAKE', 52.516381, 15.230656, 'Lubuskie', 'Lubniewice', 'Jezioro Lubiąż to wizytówka Lubniewic, położone bezpośrednio przy centrum miejscowości i zabytkowym zamku. Posiada dwie wyraźne części połączone przewężeniem. Dno jest urozmaicone, piaszczysto-muliste, z rynną sięgającą 12-13 metrów. Woda jest dobrze natleniona i żyzna.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81678, 'Jezioro Krajnik', 'jezioro-krajnik', 'LAKE', 52.511655, 15.252886, 'Lubuskie', 'Lubniewice', 'Krajnik to najmniejsze z trzech jezior lubniewickich, połączone z jeziorem Lubiąż krótkim kanałem. Ma charakter bardziej eutroficzny, jest płytsze (max 4-5 m) i silniej zarośnięte. Dno jest muliste, bogate w bentos. Brzegi są niskie i w dużej części niedostępne, co sprzyja lęgom ptactwa i ryb.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81679, 'Jezioro Krzywe (Lubniewice)', 'jezioro-krzywe-lubniewice', 'LAKE', 52.530453, 15.195465, 'Lubuskie', 'Lubniewice / Jarnatów', 'Krzywe to urokliwa, długa rynna polodowcowa położona na północ od Lubniewic. Akwen charakteryzuje się czystą wodą i twardym dnem w strefie przybrzeżnej. Maksymalna głębokość sięga 12 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez wysokie skarpy porośnięte starym lasem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81680, 'Jezioro Ostrowicko (Ostrowie)', 'jezioro-ostrowicko-torzym', 'LAKE', 52.383945, 15.167613, 'Lubuskie', 'Torzym / Ostrowów', 'Jezioro Ostrowicko (znane też jako Ostrowie) to rynnowy akwen położony w ustronnej dolinie rzeki Ilanki. Charakteryzuje się czystą wodą i twardym dnem piaszczysto-żwirowym. Maksymalna głębokość sięga ok. 10 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę dzięki przepływowemu charakterowi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81681, 'Jezioro Recze', 'jezioro-recze-2', 'LAKE', 52.387401, 15.155361, 'Lubuskie', 'Torzym / Gądków Wielki', 'Recze to urokliwa, głęboka rynna polodowcowa (max ok. 15 m) ukryta w gęstym kompleksie leśnym. Akwen cechuje się krystalicznie czystą wodą i twardym podłożem. Brzegi są wysokie i w całości porośnięte majestatycznym lasem bukowym, co zapewnia osłonę przed wiatrem i nadaje akwenowi surowy charakter.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81682, 'Jezioro Sandacznik', 'jezioro-sandacznik', 'LAKE', 52.390766, 15.158987, 'Lubuskie', 'Torzym', 'Sandacznik to niewielki, kameralny zbiornik rynnowy, który swoją nazwę zawdzięcza historycznej obfitości sandacza. Posiada piaszczysto-muliste dno i średnią głębokość ok. 5 metrów. Woda posiada przyzwoitą przejrzystość wiosną. Jezioro jest wyciszone, otoczone pasem lasu, co sprzyja rozwojowi bujnej roślinności zanurzonej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81683, 'Jezioro Długie (Torzym)', 'jezioro-dlugie-torzym', 'LAKE', 52.375417, 15.18023, 'Lubuskie', 'Torzym', 'Jezioro Długie to klasyczna rynna polodowcowa, długa i wąska, wciśnięta w pofalowany krajobraz torzymskich borów. Akwen charakteryzuje się twardym dnem w strefie przybrzeżnej i rynną środkową sięgającą 10-12 metrów. Woda posiada wysoką klasę czystości. Brzegi są w większości wysokie i porośnięte lasem mieszanym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81684, 'Jezioro Trzcinno', 'jezioro-trzcinno-torzym', 'LAKE', 52.375902, 15.190079, 'Lubuskie', 'Torzym', 'Trzcinno to niewielki zbiornik o charakterze eutroficznym, charakteryzujący się – zgodnie z nazwą – bardzo szerokim pasem trzcinowisk otaczających całe lustro wody. Dno jest piaszczysto-muliste, o średniej głębokości ok. 4 metrów. Woda jest żyzna, co sprzyja szybkiej wegetacji lina i karasia.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81685, 'Jezioro Kamienieckie', 'jezioro-kamienieckie-2', 'LAKE', 52.552196, 17.974663, 'Wielkopolskie', 'Kamieniec / Trzemeszno', 'Jezioro Kamienieckie to malownicza rynna (pow. ok. 70 ha) charakteryzująca się urozmaiconą linią brzegową. Maksymalna głębokość sięga 12-14 metrów. Woda jest żyzna, co sprzyja dużej biomasie ryb karpiowatych. Brzegi są dostępne dla wędkarzy, z licznymi pomostami i kładkami.', 'PZW Poznań');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81686, 'Jezioro Męcko', 'jezioro-mecko', 'LAKE', 52.365605, 15.18317, 'Lubuskie', 'Torzym / Wędrzyn', 'Jezioro Męcko to kameralny, śródleśny zbiornik o charakterze rynnowym, położony w pobliżu poligonu w Wędrzynie. Charakteryzuje się piaszczysto-mulistym dnem i średnią głębokością ok. 6-8 metrów. Woda posiada przyzwoitą przejrzystość wiosną. Brzegi są wysokie, porośnięte starym lasem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81687, 'Jezioro Kopaniec', 'jezioro-kopaniec', 'LAKE', 52.360727, 15.198345, 'Lubuskie', 'Torzym / Wędrzyn', 'Kopaniec to niewielkie jezioro wytopiskowe ukryte w głębi borów lubuskich. Posiada charakter eutroficzny z mulistym dnem i bogatą roślinnością zanurzoną. Maksymalna głębokość nie przekracza 5 metrów. Jezioro jest wyciszone, stanowiąc doskonałe schronienie dla ryb spokojnego żeru i ptactwa wodnego.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81688, 'Jezioro Męcko Małe', 'jezioro-mecko-male', 'LAKE', 52.357847, 15.187247, 'Lubuskie', 'Torzym / Wędrzyn', 'Męcko Małe to ustronny sąsiad jeziora Męcko, charakteryzujący się mniejszą powierzchnią, ale podobnym, leśnym klimatem. Dno jest wysoce muliste, a pasy trzcinowisk są tu gęstsze niż w większym bracie. Woda nagrzewa się szybko, co sprzyja aktywności ryb karpiowatych już od wczesnej wiosny.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81689, 'Jezioro Malcz Północny', 'jezioro-malcz-polnocny', 'LAKE', 52.345568, 15.214176, 'Lubuskie', 'Torzym / Łagów', 'Malcz Północny to urokliwa rynna polodowcowa charakteryzująca się czystą wodą i twardym podłożem w strefie przybrzeżnej. Maksymalna głębokość oscyluje wokół 10-12 metrów. Jezioro jest otoczone gęstym lasem mieszanym, co zapewnia świetną osłonę przed wiatrem i intymny charakter łowiska.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81690, 'Jezioro Malcz Południowy', 'jezioro-malcz-poludniowy', 'LAKE', 52.332472, 15.21791, 'Lubuskie', 'Torzym / Łagów', 'Malcz Południowy stanowi rynnowe przedłużenie systemu Malcz. Posiada dno piaszczysto-muliste i średnią głębokość ok. 8 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są wysokie i w całości zalesione. Akwen jest wyciszony, co sprzyja biomasie ryb szukających schronienia w pasach rdestnicy pływającej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81691, 'Jezioro Linie', 'jezioro-linie', 'LAKE', 52.331882, 15.234175, 'Lubuskie', 'Łagów / Torzym', 'Jezioro Linie to malowniczy akwen rynnowy, którego nazwa (podobnie jak w przypadku Linciuszów) wprost sugeruje główny gatunek ryb. Posiada dno muliste z piaszczystymi wypłyceniami i głębokość sięgającą 6-7 metrów. Woda jest żyzna i dobrze natleniona. Jezioro otoczone jest pięknym starodrzewem bukowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81692, 'Jezioro Ciecz (Trześniowskie)', 'jezioro-ciecz-trzesniowskie', 'LAKE', 52.353856, 15.298805, 'Lubuskie', 'Łagów', 'Jezioro Ciecz to legenda Ziemi Lubuskiej i jedno z najgłębszych jezior w zachodniej Polsce (max 58,8 m). Słynie z krystalicznie czystej wody (I klasa) i monumentalnej batymetrii – dno opada niemal pionowo do rynny głównej. Akwen charakteryzuje się sielawowym charakterem i wybitnie twardym, piaszczysto-kredowym dnem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81693, 'Jezioro Łagowskie', 'jezioro-lagowskie', 'LAKE', 52.323593, 15.288076, 'Lubuskie', 'Łagów', 'Jezioro Łagowskie to turystyczne serce regionu, rynna polodowcowa położona u stóp Zamku Joannitów. W przeciwieństwie do jeziora Ciecz, posiada charakter nieco bardziej żyzny (eutroficzny) i mniejszą głębokość (max 13 m). Dno jest piaszczysto-muliste. Jezioro jest połączone z Cieczą wąskim kanałem w centrum miejscowości.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81694, 'Jezioro Ciche', 'jezioro-ciche-lagow', 'LAKE', 52.323436, 15.298805, 'Lubuskie', 'Łagów / Sieniawa', 'Jezioro Ciche to niewielki, kameralny zbiornik rynnowy ukryty w głębokim parowie leśnym. Zgodnie z nazwą, panuje tu absolutna cisza. Akwen charakteryzuje się bardzo czystą wodą i twardym dnem. Maksymalna głębokość sięga ok. 10 metrów. Roślinność wodna jest skąpa, ograniczona do wąskiego pasa litoralu.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81695, 'Jezioro Szydłowskie (Szydłowie)', 'jezioro-szydlowskie', 'LAKE', 52.585349, 17.932477, 'Wielkopolskie', 'Trzemeszno / Szydłowo', 'Szydłowskie to typowy akwen rynnowy Pojezierza Gnieźnieńskiego. Posiada twarde dno w strefie litoralu i rynnę środkową sięgającą 10 metrów. Jezioro jest wyciszone, osłonięte od wiatru przez pagórkowaty teren, co sprzyja rozwojowi bujnej roślinności zanurzonej.', 'PZW Poznań');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81696, 'Jezioro Konotop (k. Łagowa)', 'jezioro-konotop-lagow', 'LAKE', 52.247631, 15.222244, 'Lubuskie', 'Lubrza / Łagów', 'Jezioro Konotop to urokliwy, śródleśny akwen rynnowy położony w południowej części Parku Łagowskiego. Posiada twarde dno i krystalicznie czystą wodę. Maksymalna głębokość sięga ok. 8-10 metrów. Brzegi są wysokie i w całości porośnięte majestatycznym lasem bukowym, co zapewnia ciszę i osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81697, 'Jezioro Dziarg', 'jezioro-dziarg', 'LAKE', 52.239904, 15.23874, 'Lubuskie', 'Lubrza / Łagów', 'Dziarg to malowniczy akwen o urozmaiconej linii brzegowej i pofałdowanym dnie piaszczysto-mulistym. Maksymalna głębokość sięga ok. 10 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest otoczone borem sosnowym i jest znacznie mniej oblegane turystycznie niż sąsiednie akweny w Lubrzy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81698, 'Jezioro Kosobudzkie', 'jezioro-kosobudzkie', 'LAKE', 52.230797, 15.253186, 'Lubuskie', 'Świebodzin / Kosobudz', 'Jezioro Kosobudzkie to malownicza rynna (pow. ok. 50 ha) położona w otulinie Gryżyńskiego Parku Krajobrazowego. Charakteryzuje się czystą wodą i urozmaiconym dnem z wyraźnymi piaszczystymi skarpami. Maksymalna głębokość sięga 12-14 metrów. Brzegi są wysokie i w całości porośnięte lasem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81699, 'Jezioro Kołek', 'jezioro-kolek', 'LAKE', 52.165273, 15.280781, 'Lubuskie', 'Gryżyna', 'Kołek to kameralny, śródleśny zbiornik o charakterze wytopiskowym, ukryty w sercu borów gryżyńskich. Akwen posiada twarde piaszczyste dno i krystalicznie czystą wodę. Batymetria jest regularna – misa o głębokości do 8 metrów. Jezioro jest wybitnie wyciszone, osłonięte od wiatru przez wysokie skarpy zalesione starodrzewem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81700, 'Jezioro Ciborze', 'jezioro-ciborze', 'LAKE', 52.1445, 15.411072, 'Lubuskie', 'Skąpe / Ciborze', 'Jezioro Ciborze to malowniczy zbiornik rynnowy położony w pofałdowanym terenie rolniczo-leśnym. Charakteryzuje się dnem piaszczysto-mulistym i średnią głębokością ok. 6-8 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest otoczone pasem lasu od strony południowej, co zapewnia osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81701, 'Jezioro Skąpe', 'jezioro-skape', 'LAKE', 52.13378, 15.420814, 'Lubuskie', 'Skąpe', 'Jezioro Skąpe to płytki akwen (max 3-4 m) o charakterze eutroficznym. Dno jest wysoce muliste i bogate w bentos. Jezioro jest silnie zarastające, z ogromnymi polami lilii wodnych i grążeli, co czyni je idealnym biotopem dla ryb ciepłolubnych i lęgów szczupaka. Brzegi są niskie i silnie zarośnięte trzciną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81702, 'Jezioro Trzeboch', 'jezioro-trzeboch', 'LAKE', 52.175959, 15.451863, 'Lubuskie', 'Lubrza / Skąpe', 'Trzeboch to klasyczna, długa rynna polodowcowa stanowiąca południowy kraniec systemu jezior lubrzańskich. Akwen charakteryzuje się bardzo czystą wodą i twardym dnem piaszczystym. Maksymalna głębokość sięga 12-14 metrów. Brzegi są wysokie i w większości porośnięte lasem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81703, 'Jezioro Niedźwiedno', 'jezioro-niedzwiedno', 'LAKE', 52.200848, 15.467677, 'Lubuskie', 'Lubrza', 'Niedźwiedno to urokliwy, śródleśny zbiornik o charakterze rynnowym. Posiada piaszczysto-muliste dno i przyzwoitą klasę czystości. Maksymalna głębokość nie przekracza 6-7 metrów. Jezioro jest wyciszone, stanowiąc doskonałe miejsce dla ryb spokojnego żeru szukających schronienia w pasach grążeli żółtych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81704, 'Jezioro Czerniak', 'jezioro-czerniak', 'LAKE', 52.209264, 15.446134, 'Lubuskie', 'Lubrza', 'Czerniak to niewielki, niemal okrągły zbiornik o charakterze wytopiskowym. Mimo małej powierzchni, jest to zbiornik o urozmaiconym dnie i przyzwoitej głębokości (ok. 5-6 m). Jezioro jest wyciszone, osłonięte od wiatru przez pasy drzew i pagórki. Roślinność wodna jest umiarkowana, z przewagą rdestnicy pływającej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81705, 'Jezioro Mogileńskie', 'jezioro-mogilenskie', 'LAKE', 52.636424, 17.954407, 'Kujawsko-Pomorskie', 'Mogilno', 'Jezioro miejskie położone w sercu Mogilna. Charakteryzuje się wybitnie eutroficznym charakterem i niewielką głębokością (średnio 2-3 m). Brzegi są w całości zagospodarowane rekreacyjnie – promenady i pomosty ułatwiają wędkowanie miejskie. Słynie z dużej ilości karasia i lina.', 'PZW Bydgoszcz');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81706, 'Jezioro Lubich', 'jezioro-lubich', 'LAKE', 52.226383, 15.4848, 'Lubuskie', 'Lubrza', 'Lubich to malownicza, wąska rynna polodowcowa o powierzchni ok. 25 ha. Charakteryzuje się czystą wodą i twardym dnem piaszczysto-żwirowym. Maksymalna głębokość sięga ok. 10 metrów. Jezioro posiada wyraźnie zarysowaną rynnę centralną i dobrze natlenioną wodę dzięki przepływowemu charakterowi (Szlak Nenufarów).
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81707, 'Jezioro Trzcinno (Lubrza)', 'jezioro-trzcinno-lubrza', 'LAKE', 52.240054, 15.500185, 'Lubuskie', 'Lubrza', 'Trzcinno to niewielki zbiornik o charakterze eutroficznym, charakteryzujący się – zgodnie z nazwą – bardzo szerokim pasem trzcinowisk otaczających całe lustro wody. Dno jest piaszczysto-muliste, o średniej głębokości ok. 4 metrów. Woda jest żyzna, co sprzyja szybkiej wegetacji lina i szczupaka.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81708, 'Jezioro Zamecko', 'jezioro-zamecko', 'LAKE', 52.252595, 15.548133, 'Lubuskie', 'Lubrza', 'Jezioro Zamecko to rynnowy akwen położony bezpośrednio przy miejscowości Lubrza. Zbiornik jest elementem historycznych umocnień Międzyrzeckiego Rejonu Umocnionego. Charakteryzuje się pofałdowanym dnem i średnią głębokością ok. 6-8 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są częściowo zagospodarowane, z licznymi pomostami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81709, 'Jezioro Turowskie', 'jezioro-turowskie', 'LAKE', 51.821139, 15.236063, 'Lubuskie', 'Zielona Góra / Turów', 'Jezioro Turowskie to kameralny akwen o charakterze eutroficznym, położony wśród lasów na południe od Zielonej Góry. Charakteryzuje się mulistym dnem i średnią głębokością ok. 3-4 metrów. Woda jest żyzna, co sprzyja szybkiej wegetacji roślinności wodnej. Brzegi są niskie i w dużej części zarośnięte trzciną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81710, 'Jezioro Wielkie (w Dąbiu)', 'jezioro-wielkie-dabie-2', 'LAKE', 51.995491, 15.156798, 'Lubuskie', 'Krosno Odrzańskie / Dąbie', 'Jezioro Wielkie w Dąbiu to jeden z najpopularniejszych akwenów rekreacyjnych w powiecie krośnieńskim (pow. ok. 22 ha). Jest to jezioro rynnowe o dnie piaszczysto-mulistym i głębokości sięgającej 10 metrów. Woda posiada przyzwoitą klasę czystości. Brzegi są dobrze zagospodarowane, z licznymi pomostami i plażami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81711, 'Jezioro Dąbie Małe', 'jezioro-dabie-male', 'LAKE', 51.990631, 15.169523, 'Lubuskie', 'Krosno Odrzańskie / Dąbie', 'Dąbie Małe to mniejszy, bardziej ustronny sąsiad Jeziora Wielkiego. Ma charakter wybitnie eutroficzny, jest płytsze (max 3-4 m) i silniej zarośnięte. Dno jest muliste, bogate w bentos. Akwen jest wyciszony, co sprzyja lęgom ptactwa wodnego i stanowi świetne naturalne tarlisko dla ryb karpiowatych.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81712, 'Jezioro Borek (Kosarzyn)', 'jezioro-borek-kosarzyn', 'LAKE', 52.050437, 14.772921, 'Lubuskie', 'Gubin / Kosarzyn', 'Jezioro Borek to malowniczy akwen położony w Krzesińskim Parku Krajobrazowym, tuż przy granicy z Niemcami. Posiada piaszczysto-muliste dno i średnią głębokość ok. 5-6 metrów. Jezioro słynie z urozmaiconej linii brzegowej i bardzo czystej wody. Otoczone jest majestatycznymi borami sosnowymi, co zapewnia osłonę przed wiatrem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81713, 'Jezioro Głębokie (k. Cybinki)', 'jezioro-glebokie-cybinka', 'LAKE', 52.249166, 14.792061, 'Lubuskie', 'Cybinka / Urad', 'Głębokie koło Cybinki to absolutna perła czystości w regionie (I klasa). Jest to monumentalna rynna polodowcowa, ukryta głęboko w lesie, o głębokości sięgającej blisko 20 metrów. Woda jest krystaliczna, o sielawowym charakterze. Dno jest wybitnie twarde, piaszczysto-kredowe, z gwałtownymi spadkami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81714, 'Jezioro Supno', 'jezioro-supno', 'LAKE', 52.260908, 14.791567, 'Lubuskie', 'Cybinka / Urad', 'Supno to rynnowy sąsiad jeziora Głębokiego, charakteryzujący się równie wysoką czystością wody i twardym podłożem. Maksymalna głębokość oscyluje wokół 10-12 metrów. Jezioro ma bardzo wydłużony kształt i jest otoczone gęstym borem sosnowym. Dzięki przepływowemu charakterowi woda jest doskonale natleniona.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81715, 'Jezioro Kunowskie', 'jezioro-kunowskie', 'LAKE', 52.633873, 18.069674, 'Kujawsko-Pomorskie', 'Mogilno / Kunowo', 'Kunowskie to ustronny zbiornik rynnowy o dnie piaszczysto-mulistym. Woda posiada przyzwoitą klasę czystości. Jezioro jest otoczone pasem lasu od strony zachodniej. Wędkarsko to bardzo stabilna woda leszczowo-szczupakowa, rzadziej odwiedzana przez turystów.', 'PZW Bydgoszcz');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81716, 'Jezioro Raczno', 'jezioro-raczno', 'LAKE', 52.226906, 14.87699, 'Lubuskie', 'Cybinka / Radzików', 'Jezioro Raczno to malowniczy, śródleśny zbiornik o dnie piaszczysto-mulistym. Maksymalna głębokość sięga 8-10 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest wyciszone, osłonięte od wiatru przez pasy starodrzewu, co sprzyja rozwojowi bujnej roślinności zanurzonej. Brzegi są częściowo porośnięte trzciną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81717, 'Jezioro Raczewko', 'jezioro-raczewko', 'LAKE', 52.223133, 14.876652, 'Lubuskie', 'Cybinka', 'Raczewko to niewielkie, rynnowe jezioro stanowiące satelitę jeziora Raczno. Akwen charakteryzuje się bardzo czystą wodą i twardym dnem piaszczysto-żwirowym. Brzegi są wysokie i w całości zalesione. To typowa woda okoniowa, gdzie drapieżniki o jasnym ubarwieniu grupują się na twardych stokach rynny.', 'PZW Zielona Góra');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81718, 'Jezioro Moczydło', 'jezioro-moczydlo-maszewo', 'LAKE', 52.091018, 15.031571, 'Lubuskie', 'Maszewo / Rybojedzko', 'Moczydło to śródleśny zbiornik o charakterze eutroficznym. Posiada muliste dno i jest otoczone gęstym borem sosnowym. Maksymalna głębokość nie przekracza 4 metrów. To wyśmienite łowisko lina i karasia, które znajdują tu schronienie w pasach grążeli i lilii wodnych.', 'PZW Zielona Góra');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81719, 'Staw Podgórny', 'staw-podgorny', 'LAKE', 52.09061, 15.056355, 'Lubuskie', 'Maszewo / Grzmiąca', 'Staw Podgórny to malownicze spiętrzenie leśne o charakterze stawowym. Charakteryzuje się dnem pokrytym grubą warstwą osadów organicznych i bogatą roślinnością zanurzoną. Idealne miejsce dla wędkarzy szukających absolutnej ciszy i kontaktu z dziką naturą borów lubuskich.', 'Nadleśnictwo / PZW');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81720, 'Zbiornik Mietkowski (Zalew Mietków)', 'zbiornik-mietkowski', 'LAKE', 50.955838, 16.620169, 'Dolnośląskie', 'Mietków / Sobótka', 'Mietków to największy zbiornik zaporowy na Dolnym Śląsku (pow. ok. 930 ha). Powstał na rzece Bystrzycy. Charakteryzuje się ogromnymi, otwartymi przestrzeniami i piaszczysto-żwirowym dnem. Maksymalna głębokość przy tamie to ok. 13 metrów, ale średnio jest to płytka woda (2-4 m).
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81721, 'Staw Ponurej Kapliczki', 'staw-ponurej-kapliczki', 'LAKE', 50.825425, 15.80599, 'Dolnośląskie', 'Jelenia Góra / Bukowiec', 'Urokliwy, historyczny staw położony w Parku Krajobrazowym Doliny Pałaców i Ogrodów w Bukowcu. Posiada charakter górskiego stawu parkowego. Otoczony starodrzewem i zabytkową architekturą. Woda jest chłodna, zasilana górskimi strumieniami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81722, 'Staw Kąpielnik', 'staw-kapielnik-bukowiec', 'LAKE', 50.826942, 15.809616, 'Dolnośląskie', 'Jelenia Góra / Bukowiec', 'Kolejny z ciągu stawów w Bukowcu, dawniej pełniący funkcje rekreacyjne. Jest to zbiornik płytki, z dnem pokrytym osadami liściastymi. Woda ma odcień lekko torfowy. Brzegi są dobrze dostępne, z pięknym widokiem na Śnieżkę.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81723, 'Staw Graniczny', 'staw-graniczny-cieplice', 'LAKE', 50.842208, 15.668285, 'Dolnośląskie', 'Jelenia Góra / Cieplice', 'Niewielki staw śródpolny położony na obrzeżach Jeleniej Góry. Posiada muliste dno i regularną linię brzegową porośniętą trzciną. Zbiornik jest płytki, co sprawia, że woda szybko nagrzewa się wiosną.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81724, 'Stawy Młyńska', 'stawy-mlynska-mirsk', 'LAKE', 50.969318, 15.437336, 'Dolnośląskie', 'Mirsk / Gryfów Śląski', 'Kompleks stawów położony w dolinie rzeki Kwisy. Są to zbiorniki o charakterze pożwirowym i potorfowym. Posiadają urozmaiconą linię brzegową z licznymi kępami drzew i wiklin. Woda jest żyzna i dobrze natleniona.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81725, 'Jezioro Leśniańskie', 'jezioro-lesnianskie', 'LAKE', 51.033921, 15.291746, 'Dolnośląskie', 'Leśna / Sucha', 'Jezioro Leśniańskie to malowniczy zbiornik zaporowy na Kwisie (pow. ok. 140 ha), nad którym góruje słynny Zamek Czocha. Akwen ma charakter górski: strome, skaliste brzegi, duża głębokość (do 12 m) i twarde dno. Woda jest chłodna i czysta.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81726, 'Łogowski Staw', 'logowski-staw', 'LAKE', 51.164922, 15.047901, 'Dolnośląskie', 'Zgorzelec / Łagów', 'Duży staw o charakterze hodowlano-rekreacyjnym położony w pobliżu Zgorzelca. Posiada piaszczysto-muliste dno i średnią głębokość ok. 2 metrów. Brzegi są częściowo zalesione, z licznymi stanowiskami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81727, 'Staw Dębnik', 'staw-debnik-lagow', 'LAKE', 51.175507, 15.048974, 'Dolnośląskie', 'Zgorzelec / Łagów', 'Kameralny staw sąsiadujący z kompleksem Łogowskim. Posiada wybitnie leśny charakter, brzegi są gęsto porośnięte dębami (stąd nazwa). Woda ma ciemniejszy odcień ze względu na osady organiczne.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81728, 'Jezioro Kunickie', 'jezioro-kunickie', 'LAKE', 51.2241, 16.260366, 'Dolnośląskie', 'Legnica / Kunice', 'Jezioro Kunickie to największy i najpopularniejszy akwen Pojezierza Legnickiego (pow. ok. 95 ha). Jest to jezioro polodowcowe o piaszczysto-mulistym dnie i głębokości sięgającej 12-14 metrów. Woda posiada przyzwoitą klasę czystości, choć latem bywa mętna ze względu na duży ruch rekreacyjny.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81729, 'Jezioro Jaśkowickie', 'jezioro-jaskowickie', 'LAKE', 51.219493, 16.310406, 'Dolnośląskie', 'Legnica / Jaśkowice Legnickie', 'Jaśkowickie to rynnowy sąsiad jeziora Kunickiego. Charakteryzuje się bardziej kameralnym charakterem i mulistym dnem. Średnia głębokość to ok. 5-6 metrów. Akwen jest otoczony pasem drzew i wiklin, co zapewnia dobrą osłonę od wiatru. 
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81730, 'Jezioro Koskowickie (Rezerwat)', 'jezioro-koskowickie', 'LAKE', 51.190064, 16.257963, 'Dolnośląskie', 'Legnica / Koskowice', 'Jezioro Koskowickie to unikatowy akwen chroniony w ramach rezerwatu przyrody (pow. ok. 60 ha). Jest to jezioro płytkie (max 3 m), wybitnie eutroficzne, z ogromnymi połaciami trzcinowisk, które stanowią jedną z najważniejszych ostoi ptactwa wodnego w regionie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81731, 'Staw Górny (k. Brzegu Dolnego)', 'staw-gorny-wolow', 'LAKE', 51.356295, 16.576824, 'Dolnośląskie', 'Wołów / Brzeg Dolny', 'Staw Górny to element kompleksu stawów w rejonie Wołowa. Jest to płytki zbiornik śródpolny o mulistym dnie i bogatej roślinności zanurzonej. Maksymalna głębokość nie przekracza 2-3 metrów. Woda nagrzewa się szybko, co sprzyja aktywności ryb karpiowatych już od wczesnej wiosny.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81732, 'Staw Dolny (k. Brzegu Dolnego)', 'staw-dolny-wolow', 'LAKE', 51.362657, 16.572576, 'Dolnośląskie', 'Wołów / Brzeg Dolny', 'Staw Dolny sąsiaduje z Górnym, pełniąc funkcję naturalnego odstojnika i tarliska. Charakteryzuje się gęstym pasem trzcin i mniejszą powierzchnią otwartego lustra wody. Dno jest wysoce zamulone, bogate w ochotkę i inne organizmy bentosowe.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81733, 'Jezioro Rakówek', 'jezioro-rakowek-2', 'LAKE', 51.424112, 16.857169, 'Dolnośląskie', 'Wąsosz / Wińsko', 'Rakówek to niewielki, urokliwy akwen położony w dolinie rzeki Barycz (strefa peryferyjna). Posiada charakter starorzecza/jeziora zalewowego z dnem piaszczysto-mulistym. Maksymalna głębokość to ok. 3-4 metry. Brzegi są niskie, często podmokłe, porośnięte wierzbami i olchami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81734, 'Jezioro Błociec', 'jezioro-blociec', 'LAKE', 51.422587, 16.863842, 'Dolnośląskie', 'Wąsosz / Wińsko', 'Błociec to sąsiad Rakówka, o wybitnie eutroficznym charakterze. Zbiornik jest bardzo płytki i silnie zarastający grążelem żółtym. Dno jest wybitnie miękkie, wyścielone osadami organicznymi. Nazwa oddaje charakter terenu – brzegi bywają bagniste i trudnodostępne.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81735, 'Duży Staw (Wińsko)', 'duzy-staw-winsko', 'LAKE', 51.453112, 16.743164, 'Dolnośląskie', 'Wińsko / Wąsosz', 'Duży Staw pod Wińskiem to rozległy akwen o charakterze stawowym, wykorzystywany rekreacyjnie i wędkarsko. Posiada wyrównane dno i głębokość ok. 1,5 - 2,5 metra. Woda jest żyzna, co sprzyja szybkiej wegetacji narybku. Brzegi są dostępne, z licznymi stanowiskami gruntowymi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81736, 'Zbiornik Jutrosin', 'zbiornik-jutrosin', 'LAKE', 51.664436, 17.174828, 'Wielkopolskie', 'Jutrosin', 'Zbiornik Jutrosin to nowoczesny obiekt retencyjny na rzece Orla (pow. ok. 90 ha). Jest to akwen płytki (średnio 1,5 - 2,5 m), ale o bardzo dużej wydajności biologicznej. Posiada piaszczysto-żwirowe dno, które w głębszych partiach pokrywa się mułem. Brzegi są w większości otwarte i łatwo dostępne.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81737, 'Staw Jeleni II', 'staw-jeleni-2', 'LAKE', 51.502026, 16.986043, 'Dolnośląskie', 'Żmigród / Ruda Sułowska', 'Staw Jeleni II to element kompleksu stawów milickich w rejonie Rudy Sułowskiej. Jest to płytki zbiornik o charakterze hodowlanym, otoczony gęstym pasem trzcin. Stanowi istotne żerowisko dla ptactwa wodnego. Woda jest żyzna, typowa dla karpiowych zbiorników produkcyjnych.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81738, 'Staw Jeleni I', 'staw-jeleni-1', 'LAKE', 51.509184, 16.986108, 'Dolnośląskie', 'Żmigród / Ruda Sułowska', 'Północny zbiornik z grupy Jeleni. Charakteryzuje się regularnym kształtem i mulistym dnem. Wokół stawu przebiegają trasy przyrodnicze pozwalające na obserwację fauny Doliny Baryczy. Podobnie jak inne stawy kompleksu, służy głównie intensywnej hodowli karpia.', 'Stawy Milickie SA');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81739, 'Jezioro Gosławskie', 'jezioro-goslawskie', 'LAKE', 52.295056, 18.239365, 'Wielkopolskie', 'Konin', 'Gosławskie to największe z "jezior podgrzewanych" (pow. ok. 380 ha). Jest wybitnie płytkie (średnio 1.5 - 3 m), co w połączeniu ze zrzutem ciepłej wody z elektrowni sprawia, że temperatura wody jest tu znacznie wyższa niż w naturalnych akwenach.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81740, 'Jezioro Pątnowskie', 'jezioro-patnowskie', 'LAKE', 52.306646, 18.300219, 'Wielkopolskie', 'Konin', 'Pątnowskie to kolejny element systemu chłodzenia konińskich elektrowni. Jest głębsze od Gosławskiego (do 5-6 m) i ma bardziej urozmaiconą linię brzegową. Woda jest ciepła, co sprzyja szybkiej wegetacji roślinności i fauny.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81741, 'Jezioro Wilczyńskie', 'jezioro-wilczynskie', 'LAKE', 52.479669, 18.109889, 'Wielkopolskie', 'Wilczyn', 'Wilczyńskie to krystalicznie czysta rynna polodowcowa (I klasa czystości). Niestety, akwen boryka się z problemem obniżającego się lustra wody (wpływ lejów depresyjnych kopalni). Mimo to, wciąż oferuje doskonałe warunki do nurkowania i wędkowania technicznego.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81742, 'Jezioro Suszewskie', 'jezioro-suszewskie', 'LAKE', 52.481132, 18.091135, 'Wielkopolskie', 'Wilczyn / Suszewo', 'Suszewskie to mniejszy, ustronny akwen położony w ciągu jezior wilczyńskich. Charakteryzuje się bardzo czystą wodą i piaszczysto-mulistym dnem. Brzegi są częściowo zalesione i mniej oblegane przez turystów niż sąsiednie jeziora.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81743, 'Jezioro Budzisławskie', 'jezioro-budzislawskie', 'LAKE', 52.462135, 18.054228, 'Wielkopolskie', 'Kleczew / Budzisław Kościelny', 'Budzisławskie to jedno z najczystszych jezior w Polsce. Widoczność pod wodą sięga tu 8 metrów, co czyni je mekką nurków (znajduje się tu podwodna figura Matki Boskiej). Jest to głęboka rynna (max 35 m) o twardym dnie.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81744, 'Jezioro Rusin (Kownackie)', 'jezioro-rusin', 'LAKE', 52.452455, 17.999854, 'Wielkopolskie', 'Mrówki / Wilczyn', 'Jezioro Rusin (często mylone z Kownackim) to akwen o charakterze rynnowym. Podobnie jak sąsiednie wody, charakteryzuje się wysoką przejrzystością. Dno jest piaszczyste z warstwą mułu w głębi. Brzegi są urozmaicone, z licznymi stanowiskami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81745, 'Jezioro Niedzięgiel (Skorzęcińskie)', 'jezioro-niedziegiel', 'LAKE', 52.446548, 17.89896, 'Wielkopolskie', 'Skorzęcin / Witkowo', 'Niedzięgiel to serce jednego z największych ośrodków wypoczynkowych w Polsce – Skorzęcina. Jest to potężny, czysty akwen o urozmaiconym dnie. Mimo ogromnej presji turystycznej w sezonie letnim, jezioro pozostaje bardzo rybne.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81746, 'Jezioro Białe (k. Skorzęcina)', 'jezioro-biale-skorzecin', 'LAKE', 52.465581, 17.895956, 'Wielkopolskie', 'Witkowo / Skorzęcin', 'Jezioro Białe sąsiaduje z Niedzięglem, ale jest od niego znacznie spokojniejsze. Woda posiada I klasę czystości i piaszczyste dno. Maksymalna głębokość to ok. 10 metrów. Akwen otoczony jest gęstym lasem sosnowym.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81747, 'Jezioro Czarne (k. Skorzęcina)', 'jezioro-czarne-skorzecin', 'LAKE', 52.474001, 17.88909, 'Wielkopolskie', 'Witkowo / Skorzęcin', 'Czarne to niewielki, śródleśny zbiornik o charakterze eutroficznym. Ma ciemniejszą wodę i muliste dno w porównaniu do sąsiedniego jeziora Białego. Jest to zbiornik wyciszony, otoczony bagnami i lasem.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81748, 'Jezioro Orchowskie', 'jezioro-orchowskie', 'LAKE', 52.493655, 18.008308, 'Wielkopolskie', 'Orchowo', 'Jezioro Orchowskie to malownicza rynna położona wśród pól i zagajników. Posiada twarde dno i średnią głębokość ok. 5-7 metrów. Woda posiada dobrą klasę czystości, choć lustro wody wykazuje tendencję spadkową.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81749, 'Jezioro Denera', 'jezioro-denera', 'LAKE', 52.50136, 17.965286, 'Wielkopolskie', 'Orchowo / Słowikowo', 'Denera to niewielki, kameralny zbiornik rynnowy. Posiada piaszczysto-muliste dno i regularną linię brzegową. Maksymalna głębokość nie przekracza 6 metrów. Jezioro jest wyciszone i osłonięte od wiatrów, co sprzyja rozwojowi bujnej roślinności zanurzonej.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81750, 'Jezioro Słowikowo Sireckie', 'jezioro-slowikowo-sireckie', 'LAKE', 52.509758, 17.957304, 'Wielkopolskie', 'Słowikowo', 'Niewielki akwen stanowiący część ciągu jezior rynnowych rzeki Noteci. Posiada charakter przepływowy, co zapewnia dobre natlenienie wody. Dno jest muliste z piaszczystymi łachami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81751, 'Jezioro Pakoskie (Zbiornik Pakość)', 'jezioro-pakoskie', 'LAKE', 52.723618, 18.101692, 'Kujawsko-Pomorskie', 'Pakość / Janikowo', 'Jezioro Pakoskie to potężny akwen (pow. ok. 750 ha) o charakterze zbiornika retencyjnego, powstały przez spiętrzenie wód Noteci Zachodniej. Składa się z kilku plosów połączonych zwężeniami. Dno jest wybitnie urozmaicone, z licznymi górkami i zatopionymi łąkami.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81752, 'Jezioro Wolickie', 'jezioro-wolickie', 'LAKE', 52.866256, 17.892737, 'Kujawsko-Pomorskie', 'Barcin / Żnin', 'Wolickie to rozległy, stosunkowo płytki akwen (pow. ok. 180 ha) stanowiący ważny punkt na szlaku Noteci. Posiada charakter przepływowy, co zapewnia dobre natlenienie wody. Dno jest muliste z piaszczystymi blatami. Słynie z populacji dużego leszcza i sandacza.', 'PZW Bydgoszcz');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81753, 'Jezioro Kierzkowskie', 'jezioro-kierzkowskie-2', 'LAKE', 52.848509, 17.881579, 'Kujawsko-Pomorskie', 'Żnin / Kierzkowo', 'Kierzkowskie to typowa rynna pałucka o powierzchni ok. 50 ha. Charakteryzuje się czystą wodą i twardym dnem w strefie przybrzeżnej. Maksymalna głębokość sięga 12 metrów. Brzegi są wysokie, częściowo zalesione, z licznymi stanowiskami wędkarskimi.', 'PZW Bydgoszcz');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81754, 'Jezioro Kierzkowskie Małe', 'jezioro-kierzkowskie-male', 'LAKE', 52.854303, 17.872868, 'Kujawsko-Pomorskie', 'Żnin / Kierzkowo', 'Mniejszy, ustronny sąsiad jeziora Kierzkowskiego. Posiada charakter eutroficzny, jest płytszy i silniej zarośnięty. To typowy matecznik szczupaka i lina. Jezioro zapewnia spokój i kontakt z naturą, będąc rzadziej odwiedzanym niż większe akweny żnińskie.', 'PZW Bydgoszcz');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81755, 'Jezioro Płażno', 'jezioro-plazno', 'LAKE', 52.868122, 18.091478, 'Kujawsko-Pomorskie', 'Złotniki Kujawskie / Tuczno', 'Jezioro Płażno to malowniczy akwen rynnowy stanowiący zachodni kraniec ciągu jezior tuczneńskich. Charakteryzuje się piaszczysto-mulistym dnem i średnią głębokością ok. 5-6 metrów. Woda posiada przyzwoitą przejrzystość wiosną. Brzegi są częściowo zalesione i wyciszone.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81756, 'Jezioro Leszcze', 'jezioro-leszcze', 'LAKE', 52.874104, 18.100362, 'Kujawsko-Pomorskie', 'Złotniki Kujawskie / Leszcze', 'Jezioro Leszcze, zgodnie ze swoją nazwą, słynie z populacji ryb karpiowatych. Jest to niewielki zbiornik rynnowy o dnie piaszczysto-mulistym i maksymalnej głębokości ok. 7-8 metrów. Woda jest żyzna, co sprzyja szybkiej wegetacji litoralu. Brzegi są porośnięte rzadkim, ale twardym pasem trzcin.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81757, 'Jezioro Tuczno', 'jezioro-tuczno-kujawskie', 'LAKE', 52.864869, 18.121476, 'Kujawsko-Pomorskie', 'Złotniki Kujawskie / Tuczno', 'Jezioro Tuczno to centralny akwen rynny tuczneńskiej (pow. ok. 40 ha). Posiada urozmaiconą linię brzegową i dno o charakterze piaszczysto-żwirowym w strefie przybrzeżnej. Maksymalna głębokość sięga 12-13 metrów. Woda posiada dobrą klasę czystości i jest dobrze natleniona.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81758, 'Jezioro Chełmżyńskie', 'jezioro-chelmzynskie', 'LAKE', 53.176723, 18.645816, 'Kujawsko-Pomorskie', 'Chełmża', 'Jezioro Chełmżyńskie to potężny akwen rynnowy (pow. ok. 270 ha) o wybitnie urozmaiconym dnie. Słynie z dużej głębokości (max ok. 27 m) i licznych górek podwodnych oraz głębokich rynien. Woda posiada dobrą klasę czystości. Brzegi są wysokie, częściowo zurbanizowane w okolicach Chełmży, ale w dużej mierze dostępne dla wędkarzy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81759, 'Jezioro Grzywna', 'jezioro-grzywna', 'LAKE', 53.1705, 18.624272, 'Kujawsko-Pomorskie', 'Chełmża / Grzywna', 'Jezioro Grzywna to niewielki, stosunkowo płytki zbiornik sąsiadujący z Jeziorem Chełmżyńskim. Ma charakter eutroficzny, z dnem mulistym i bogatą roślinnością brzegową. Maksymalna głębokość nie przekracza 4-5 metrów. Jezioro jest wyciszone, stanowiąc doskonałe siedlisko dla ryb szukających spokoju.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81760, 'Jezioro Grodzicieńskie', 'jezioro-grodzicienskie', 'LAKE', 53.159023, 18.706284, 'Kujawsko-Pomorskie', 'Chełmża / Grodziec', 'Grodzicieńskie (Grodziec) to malowniczy zbiornik rynnowy o dnie piaszczysto-mulistym. Maksymalna głębokość sięga ok. 10 metrów. Woda posiada przyzwoitą klasę czystości. Jezioro jest otoczone pasem lasu i pól, co zapewnia osłonę przed silnymi wiatrami. Brzegi są w większości dostępne, z licznymi stanowiskami wędkarskimi.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81761, 'Jezioro Kamionkowskie', 'jezioro-kamionkowskie', 'LAKE', 53.140598, 18.766236, 'Kujawsko-Pomorskie', 'Toruń / Kamionki Małe', 'Kamionkowskie to jedno z najczystszych jezior w okolicach Torunia. Słynie z krystalicznej wody i piaszczystego dna. Mimo dużej presji turystycznej w sezonie letnim, akwen oferuje świetne warunki do spinningu (okoń) oraz połowu dorodnej płoci na piaszczystych stokach.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81762, 'Jezioro Mlewieckie', 'jezioro-mlewieckie', 'LAKE', 53.163499, 18.773232, 'Kujawsko-Pomorskie', 'Chełmża / Mlewo', 'Mlewieckie to kameralny, śródpolny zbiornik o charakterze eutroficznym. Posiada muliste dno i bogatą roślinność brzegową. Jest to typowa "woda linowa", gdzie wczesnym rankiem można liczyć na spotkanie z dorodnym karasiem złotym i walecznym linem.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81763, 'Jezioro Duże (Radzyń)', 'jezioro-duze-radzyn', 'LAKE', 53.469838, 18.964291, 'Kujawsko-Pomorskie', 'Radzyń Chełmiński', 'Główny akwen rynnowy w okolicach Radzynia Chełmińskiego. Posiada urozmaiconą linię brzegową i rynnę środkową sięgającą 12-14 metrów. Wędkarsko to bardzo uniwersalna woda, oferująca zarówno dobre wyniki spinningowe (szczupak), jak i gruntowe (leszcz).', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81764, 'Jezioro Księże', 'jezioro-ksieze-2', 'LAKE', 53.462457, 18.968925, 'Kujawsko-Pomorskie', 'Radzyń Chełmiński', 'Księże to rynnowy sąsiad Jeziora Dużego. Posiada twarde dno w strefie litoralu i czystą wodę. Jezioro zapewnia komfortowe warunki łowienia w ciszy, z dala od szlaków komunikacyjnych. Słynie z dorodnej płoci i lina.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81765, 'Jezioro Małe (Radzyń)', 'jezioro-male-radzyn', 'LAKE', 53.478138, 18.945623, 'Kujawsko-Pomorskie', 'Radzyń Chełmiński', 'Mniejszy zbiornik w systemie radzyńskim, o charakterze bardziej eutroficznym. Płytki, silnie nagrzewający się wiosną, co stymuluje ryby do żerowania. Idealne miejsce na krótkie, popołudniowe wypady ze spławikiem.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81766, 'Jezioro Salno', 'jezioro-salno', 'LAKE', 53.487635, 18.958197, 'Kujawsko-Pomorskie', 'Gruta / Salno', 'Salno to malownicza rynna (pow. ok. 40 ha) o czystej wodzie i twardym dnie piaszczysto-żwirowym. Maksymalna głębokość sięga 15 metrów. Wędkarsko to wybitna woda sandaczowa i okoniowa. Dzięki twardemu dnu, jigowanie jest tu niezwykle skuteczne.', 'PZW Toruń');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81767, 'Jezioro Kałębie (Morze Kociewskie)', 'jezioro-kalebie', 'LAKE', 53.709615, 18.471622, 'Pomorskie', 'Osiek', 'Kałębie to największe jezioro Kociewia (pow. ok. 460 ha). Jest to akwen rynnowy, ale o nietypowo małej głębokości (średnio 2-3 m). Słynie z dużej fali i silnych wiatrów. Dno jest urozmaicone, piaszczysto-muliste z licznymi kępami rdestnicy.
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81768, 'Jezioro Słone', 'jezioro-slone-osiek', 'LAKE', 53.724952, 18.427634, 'Pomorskie', 'Osiek', 'Jezioro Słone to urokliwy, śródleśny akwen rynnowy. W przeciwieństwie do Kałębia, woda jest tu głębsza i znacznie czystsza. Dno jest twarde, piaszczysto-żwirowe. Brzegi są wysokie i w całości zalesione, co zapewnia świetną osłonę przed wiatrem.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81769, 'Jezioro Trzebiechowo', 'jezioro-trzebiechowo', 'LAKE', 53.702187, 18.426874, 'Pomorskie', 'Osiek', 'Trzebiechowo to kameralne jezioro położone na południowy zachód od Osieka. Charakteryzuje się mulistym dnem i bogatą roślinnością zanurzoną. To wyśmienite łowisko lina i karasia złocistego. Woda szybko nagrzewa się wiosną, co stymuluje ryby do intensywnego żerowania.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81770, 'Jezioro Smolnickie', 'jezioro-smolnickie', 'LAKE', 53.767221, 18.425574, 'Pomorskie', 'Osiek / Smolniki', 'Smolnickie to urokliwy, śródleśny akwen rynnowy położony w gęstym kompleksie Borów Tucholskich. Posiada twarde dno i wodę o dobrej przejrzystości. Brzegi są wysokie i w całości zalesione. To wyśmienita woda okoniowa, gdzie drapieżniki grupują się na piaszczystych skarpach wzdłuż powalonych drzew.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81771, 'Jezioro Głuche', 'jezioro-gluche-osiek', 'LAKE', 53.772813, 18.476772, 'Pomorskie', 'Osiek / Głuche', 'Jezioro Głuche to ustronny zbiornik o charakterze rynnowym. Zgodnie z nazwą, panuje tu absolutna cisza. Akwen charakteryzuje się mulistym dnem i bogatą roślinnością zanurzoną. To typowy matecznik szczupaka i lina. Woda posiada przyzwoitą przejrzystość wiosną, co sprzyja spinningowaniu.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81772, 'Jezioro Długie (Ocypel)', 'jezioro-dlugie-ocypel', 'LAKE', 53.779361, 18.348455, 'Pomorskie', 'Ocypel', 'Klasyczna, długa rynna polodowcowa wciśnięta w leśny krajobraz. Posiada twarde dno i krystalicznie czystą wodę. Brzegi są strome i porośnięte borem sosnowym. Wędkarsko to bardzo stabilna woda na okonia i dorodną płocię. Dzięki głębokościom sięgającym 10-12 m, ryba ma tu świetne warunki tlenowe.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81773, 'Jezioro Piaseczno (k. Ocypla)', 'jezioro-piaseczno-ocypel', 'LAKE', 53.801943, 18.324251, 'Pomorskie', 'Ocypel', 'Piaseczno to perła czystości regionu. Posiada wybitnie piaszczyste dno (stąd nazwa) i wodę o I klasie czystości. To ulubione miejsce nurków i spinningistów szukających walecznych okoni. Przejrzystość wody wymusza stosowanie bardzo cienkich przyponów z fluorocarbonu.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81774, 'Jezioro Czarnel (Czarne Ocyplowskie)', 'jezioro-czarnel', 'LAKE', 53.793708, 18.313608, 'Pomorskie', 'Ocypel', 'Czarnel to mroczne, śródleśne jezioro o charakterze dystroficznym. Woda ma odcień herbaty, a dno jest bardzo miękkie. To królestwo lina i karasia złocistego. Spinningiści poławiają tu szczupaka leśnego, który ma w tej wodzie wyjątkowo ciemne, niemal czarne ubarwienie.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81775, 'Jezioro Wielki Ocypel', 'jezioro-wielki-ocypel', 'LAKE', 53.798725, 18.303695, 'Pomorskie', 'Ocypel', 'Wielki Ocypel to serce turystyczne borów (pow. ok. 100 ha). Posiada bardzo urozmaiconą linię brzegową z licznymi półwyspami. Woda jest bardzo czysta, o sielawowym charakterze. Słynie z populacji wielkiego okonia i szczupaka pelagicznego. Mimo dużej presji turystycznej, akwen jest bardzo rybny dzięki dużej powierzchni i licznym kryjówkom.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81776, 'Jezioro Ocypelek', 'jezioro-ocypelek', 'LAKE', 53.80666, 18.288674, 'Pomorskie', 'Ocypel', 'Mniejszy brat Wielkiego Ocypla, o znacznie bardziej kameralnym charakterze. Płytki, silnie zarośnięty grążelem i trzciną. To idealna oaza lina i karasia. Woda szybko się nagrzewa, co sprawia, że brania ryb spokojnego żeru zaczynają się tu znacznie wcześniej niż na głębokim sąsiedzie.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81777, 'Jezioro Święte (Ocypel)', 'jezioro-swiete-ocypel', 'LAKE', 53.809598, 18.266959, 'Pomorskie', 'Ocypel', 'Święte to lobeliowe jezioro o niesamowitej przejrzystości. Dno jest wybitnie piaszczyste. Ze względu na rzadką roślinność, wędkowanie z brzegu jest tu trudne (ryby widzą wędkarza). Najskuteczniejszy jest spinning z łodzi na dalekim dystansie w poszukiwaniu okonia.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81778, 'Jezioro Stare', 'jezioro-stare-pomorskie', 'LAKE', 53.824774, 18.410425, 'Pomorskie', 'Lubichowo / Zelgoszcz', 'Jezioro Stare to malowniczy akwen rynnowy otoczony lasami i polami. Posiada piaszczysto-muliste dno i średnią głębokość ok. 5-6 metrów. To bardzo stabilna woda leszczowo-szczupakowa. Często poławiane są tu dorodne wzdręgi, które w czystej wodzie mają intensywnie czerwone płetwy.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81779, 'Jezioro Lubichowskie', 'jezioro-lubichowskie', 'LAKE', 53.847312, 18.392487, 'Pomorskie', 'Lubichowo', 'Lubichowskie to główny akwen miejscowości Lubichowo. Zbiornik rynnowy o urozmaiconym dnie i dobrej zasobności w ryby karpiowate. Dzięki dobremu zagospodarowaniu (plaża miejska, pomosty), jest to wygodne łowisko dla osób szukających komfortu. Słynie z populacji dużego leszcza.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81780, 'Jezioro Zelgoszczek', 'jezioro-zelgoszczek', 'LAKE', 53.843705, 18.436904, 'Pomorskie', 'Lubichowo / Zelgoszcz', 'Kameralne jezioro śródleśne o charakterze wytopiskowym. Posiada miękkie dno i pasy gęstych trzcinowisk. To matecznik lina i szczupaka. Jezioro zapewnia absolutną ciszę i kontakt z dziką naturą, rzadko odwiedzane przez turystów z zewnątrz.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81781, 'Jezioro Czarnoleskie', 'jezioro-czarnoleskie', 'LAKE', 53.832988, 18.482008, 'Pomorskie', 'Czarnylas / Lubichowo', 'Czarnoleskie to akwen o charakterze rynnowym z dnem piaszczysto-mulistym. Woda posiada przyzwoitą klasę czystości. To woda bardzo rybna, słynąca z dużego okonia i płoci. Brzegi są urozmaicone, z wieloma dzikimi stanowiskami wędkarskimi ukrytymi wśród olsów.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81782, 'Jezioro Mościska', 'jezioro-mosciska', 'LAKE', 53.863728, 18.454349, 'Pomorskie', 'Lubichowo / Mościska', 'Urokliwy, wydłużony zbiornik o dnie twardym w strefie litoralu. Woda jest czysta i dobrze natleniona. Spinningiści poławiają tu szczupaki i okonie, a wędkarze gruntowi cenią Mościska za populację walecznego lina i dużego leszcza.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81783, 'Jezioro Szteklinek', 'jezioro-szteklinek', 'LAKE', 53.89296, 18.46334, 'Pomorskie', 'Szteklin / Borzechowo', 'Niewielki, rynnowy sąsiad dużego jeziora Szteklińskiego. Charakteryzuje się czystą wodą i piaszczystym dnem. To typowa okoniowa perełka, idealna na lekki spinning. Brzegi są wysokie i porośnięte gęstym lasem liściastym.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81784, 'Jezioro Raduńskie (Starogardzkie)', 'jezioro-radunskie-starogard', 'LAKE', 53.924193, 18.384826, 'Pomorskie', 'Starogard Gdański / Raduń', 'Jezioro Raduńskie to malowniczy akwen położony w pofałdowanym terenie Pojezierza Starogardzkiego. Posiada pofałdowane dno i średnią głębokość ok. 4-5 metrów. Wędkarsko to bardzo uniwersalna woda, oferująca zarówno dobre wyniki spinningowe (szczupak), jak i gruntowe (leszcz).', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81785, 'Jezioro Grygorek', 'jezioro-grygorek', 'LAKE', 53.929864, 18.39843, 'Pomorskie', 'Starogard Gdański / Raduń', 'Grygorek to niewielki, kameralny zbiornik śródleśny. Posiada muliste dno i bogatą roślinność brzegową. To typowa linowa oaza, rzadko odwiedzana, co sprawia, że ryby są tu mniej płochliwe niż na pobliskim jeziorze Raduńskim.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81786, 'Jezioro Czyżon', 'jezioro-czyzon', 'LAKE', 53.982085, 18.264942, 'Pomorskie', 'Kaliska', 'Czyżon to malowniczy, śródleśny zbiornik rynnowy o bardzo urozmaiconym dnie. Akwen charakteryzuje się czystą wodą i twardym dnem w strefie litoralu. Brzegi są wysokie i w całości zalesione. To wyśmienite łowisko okoniowe, gdzie "pasiaki" chętnie trzymają się zwalonych do wody pni dębów.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81787, 'Jezioro Wielkie (k. Kalisk)', 'jezioro-wielkie-kaliska', 'LAKE', 53.973557, 18.264856, 'Pomorskie', 'Kaliska', 'Największy akwen w zespole jezior borzechowskich. Posiada charakter rynnowy, piaszczysto-muliste dno i przyzwoitą klasę czystości. To bardzo stabilna woda leszczowa i szczupakowa. Dzięki dobremu natlenieniu ryby są tu waleczne, a spinningiści mogą liczyć na ładne szczupaki z toni.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81788, 'Jezioro Pińczyskie', 'jezioro-pinczyskie', 'LAKE', 53.972459, 18.296034, 'Pomorskie', 'Pinczyn / Zblewo', 'Pińczyskie to kameralny zbiornik rynnowy o urozmaiconej linii brzegowej. Posiada muliste dno i bogatą roślinność podwodną. To typowa oaza lina i karasia. Woda szybko się nagrzewa, co sprzyja wczesnowiosennym braniom ryb spokojnego żeru.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81789, 'Jezioro Pani', 'jezioro-pani', 'LAKE', 53.964508, 18.27949, 'Pomorskie', 'Borzechowo', 'Urokliwe, mniejsze jezioro o charakterze wytopiskowym. Woda posiada dobrą przejrzystość. Brzegi są częściowo zalesione, z licznymi kładkami wędkarskimi. Słynie z populacji dużej wzdręgi i szczupaka, który znajduje świetne schronienie w pasach trzcin.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81790, 'Jezioro Struga', 'jezioro-struga-borzechowo', 'LAKE', 53.96447, 18.264513, 'Pomorskie', 'Borzechowo', 'Akwen o charakterze rynnowym, połączony systemem strug z Jeziorem Wielkim. Dno jest piaszczysto-muliste. To bardzo wdzięczna woda na "lekki" spinning – obfituje w okonia. Wędkarze spławikowi cenią Strugę za dorodną płoć.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81791, 'Jezioro Piaseczno (k. Zblewa)', 'jezioro-piaseczno-zblewo', 'LAKE', 53.944242, 18.246789, 'Pomorskie', 'Zblewo / Płociczno', 'Piaseczno to perła czystości w regionie (I klasa). Krystaliczna woda i piaszczyste dno czynią je atrakcyjnym zarówno dla wędkarzy, jak i nurków. Spinningiści muszą tu stosować bardzo cienkie przypony z fluorocarbonu ze względu na ogromną widoczność. Słynie z pięknych okoni.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81792, 'Jezioro Lipskie', 'jezioro-lipskie', 'LAKE', 53.94625, 18.23945, 'Pomorskie', 'Zblewo / Lipie', 'Lipskie to niewielki, stosunkowo płytki akwen o charakterze eutroficznym. Dominują tu ryby spokojnego żeru. Brzegi są niskie, często podmokłe, co zapewnia rybom naturalny spokój. Wyśmienite łowisko lina o świcie.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81793, 'Jezioro Kazubskie', 'jezioro-kazubskie', 'LAKE', 53.940592, 18.217649, 'Pomorskie', 'Kaliska / Kazub', 'Śródleśny akwen rynnowy otoczony gęstym borem. Woda ma ciemniejszy odcień, a dno jest muliste. To matecznik szczupaka leśnego. Jezioro zapewnia absolutną ciszę i izolację od cywilizacji. Ryby są tu mniej płochliwe, ale wymagają technicznego podejścia.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81794, 'Jezioro Wygonin (Karpisko)', 'jezioro-wygonin', 'LAKE', 53.952704, 18.144951, 'Pomorskie', 'Wygonin / Stara Kiszewa', 'Wygonin to legenda polskiego i europejskiego karpiarstwa (pow. ok. 65 ha). To głęboka rynna (do 25 m) o krystalicznej wodzie i twardym dnie. Akwen zarządzany jako łowisko "No Kill". Pływają tu karpie przekraczające 30 kg oraz ogromne amury. Woda bardzo trudna technicznie, wymagająca wywózki i precyzyjnego nęcenia.', 'Łowisko Specjalne Wygonin');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81795, 'Jezioro Krąg', 'jezioro-krag', 'LAKE', 53.976693, 18.102379, 'Pomorskie', 'Kaliska / Iwiczno', 'Krąg to malowniczy zbiornik o niemal okrągłym kształcie. Posiada czystą wodę i urozmaiconą linię brzegową. Wędkarsko słynie z populacji sandacza i szczupaka. Dno piaszczysto-żwirowe sprzyja spinningowaniu "z opadu".', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81796, 'Jezioro Długie (k. Iwiczna)', 'jezioro-dlugie-iwiczno', 'LAKE', 53.973533, 18.127699, 'Pomorskie', 'Kaliska / Iwiczno', 'Klasyczna, długa i wąska rynna polodowcowa. Woda czysta, o sielawowym charakterze. To wyśmienite łowisko okonia sielawowego i szczupaka pelagicznego. Brzegi strome, zalesione, co utrudnia łowienie z brzegu – zalecana łódź.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81797, 'Jezioro Popówko', 'jezioro-popowko-2', 'LAKE', 53.9794, 18.124223, 'Pomorskie', 'Kaliska', 'Niewielkie jezioro wytopiskowe położone w bliskim sąsiedztwie jeziora Długiego. Ma charakter bardziej eutroficzny, jest płytsze i silniej zarośnięte. To królestwo lina i karasia srebrzystego.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81798, 'Jezioro Czerlonko', 'jezioro-czerlonko', 'LAKE', 53.977122, 18.123171, 'Pomorskie', 'Kaliska', 'Małe, śródleśne "oczko" o mrocznej wodzie. Dno miękkie, wyścielone liśćmi. Rybostan zdominowany przez drobny szczupak i okonia, ale trafiają się tu przepięknie ubarwione liny. Oaza spokoju dla wędkarzy ceniących samotność.', 'PZW Gdańsk');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81799, 'Jezioro Kalwa', 'jezioro-kalwa-2', 'LAKE', 53.660253, 20.76725, 'Warmińsko-Mazurskie', 'Pasym', 'Jezioro Kalwa to wizytówka Pasymia (pow. ok. 560 ha). Posiada unikatowy kształt podkowy i bardzo rozwiniętą linię brzegową z licznymi wyspami. To wędkarska legenda regionu, słynąca z potężnej populacji sandacza i medalowego leszcza.', 'Gospodarstwo Rybackie Szwaderowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81800, 'Jezioro Toczyłowo', 'jezioro-toczylowo', 'LAKE', 53.685327, 22.473564, 'Podlaskie', 'Grajewo', 'Jezioro Toczyłowo to rozległy, stosunkowo płytki akwen (pow. ok. 100 ha) położony niedaleko Grajewa. Charakteryzuje się mulistym dnem z piaszczystymi wypłyceniami w strefie brzegowej. Maksymalna głębokość oscyluje wokół 8-10 metrów. Woda jest żyzna i dobrze natleniona. Pod kątem wędkarskim to doskonała woda szczupakowa i leszczowa. Szczupaki poławia się tu głównie wzdłuż gęstych pasów trzcinowisk. Wędkarze gruntowi cenią akwen za populację dorodnego leszcza i lina.', 'PZW Białystok');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81801, 'Jezioro Mierucie', 'jezioro-mierucie', 'LAKE', 53.672774, 22.432194, 'Podlaskie', 'Grajewo / Mierucie', 'Mierucie to kameralny, śródpolny zbiornik o charakterze eutroficznym. Posiada muliste dno i średnią głębokość ok. 3-4 metrów. Jezioro jest wyciszone, osłonięte od wiatru, co sprzyja rozwojowi bujnej roślinności zanurzonej. Wędkarsko to typowa "oaza linowa". Ryby rosną tu szybko dzięki żyznej wodzie. Metoda spławikowa na skraju grążeli o świcie daje tu świetne rezultaty.', 'PZW Białystok');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81802, 'Jezioro Chorzelskie', 'jezioro-chorzelskie', 'LAKE', 53.677044, 22.353487, 'Warmińsko-Mazurskie', 'Prostki / Chorzele', 'Jezioro Chorzelskie to malowniczy akwen położony na granicy województw. Charakteryzuje się czystą wodą i dnem piaszczysto-mulistym. Maksymalna głębokość sięga 10-12 metrów. Dla wędkarza to bardzo stabilna woda na okonia i szczupaka. Okonie grupują się na piaszczystych skarpach, reagując najlepiej na jaskółki. Jezioro nie zna dużej presji turystycznej.', 'PZW Suwałki');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81803, 'Jezioro Skrodzkie', 'jezioro-skrodzkie', 'LAKE', 53.652229, 22.231779, 'Podlaskie', 'Rajgród / Skrodzkie', 'Skrodzkie to urokliwy akwen rynnowy położony w pofalowanym terenie rolniczo-leśnym. Posiada twarde dno w strefie litoralu i rynnę środkową sięgającą 8-10 metrów. Wędkarsko to wyśmienita woda na okonia i dorodną płocię. Wędkarze stacjonarni cenią akwen za populację lina i karasia w zacisznych zatokach.', 'PZW Białystok');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81804, 'Jezioro Kumielskie', 'jezioro-kumielskie', 'LAKE', 53.557751, 21.98714, 'Warmińsko-Mazurskie', 'Pisz / Kumielsk', 'Jezioro Kumielskie to rozległy akwen rynnowy (pow. ok. 120 ha). Charakteryzuje się urozmaiconą linią brzegową i dnem piaszczysto-mulistym z licznymi górkami podwodnymi. Słynie z dużego leszcza i szczupaka. Leszcze poławia się tu na piaszczystych blatach metodą feederową.', 'Gospodarstwo Jeziorowe w Piszu');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81805, 'Jezioro Głęboczek (Pasym)', 'jezioro-gleboczek-pasym', 'LAKE', 53.4751, 20.82819, 'Warmińsko-Mazurskie', 'Pasym', 'Głęboczek w Pasymiu to niewielka, ale monumentalnie głęboka rynna polodowcowa (max ok. 15 m). Akwen słynie z krystalicznie czystej wody i wybitnie twardego dna. Pod kątem wędkarskim to łowisko wybitnie techniczne. Okonie o jasnych barwach grupują się na twardych stokach rynny.', 'Gospodarstwo Rybackie Szwaderowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81806, 'Jezioro Konik', 'jezioro-konik', 'LAKE', 53.479721, 20.822396, 'Warmińsko-Mazurskie', 'Pasym', 'Jezioro Konik to kameralny, rynnowy zbiornik połączony wąskim ciekiem z jeziorem Kalwa. Akwen posiada twarde piaszczyste dno i bardzo czystą wodę. Wędkarsko to typowa "okoniowa perełka". Przejrzystość wody sprzyja finezyjnemu spinningowi.', 'Gospodarstwo Rybackie Szwaderowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81807, 'Jezioro Kociołek (Pasym)', 'jezioro-kociolek-pasym', 'LAKE', 53.480667, 20.834541, 'Warmińsko-Mazurskie', 'Pasym', 'Kociołek to niewielki, niemal okrągły zbiornik o charakterze wytopiskowym. Mimo małej powierzchni, jest to zbiornik głęboki (ok. 8-10 m) o bardzo czystej wodzie. Wędkarsko to łowisko okoniowe i szczupakowe. Przejrzystość wody wymusza stosowanie fluorocarbonu.', 'Gospodarstwo Rybackie Szwaderowo');
INSERT INTO public.map_spots (id, name, slug, spot_type, latitude, longitude, province, nearest_city, description, manager) VALUES (81808, 'Jezioro Rekowe', 'jezioro-rekowe', 'LAKE', 53.488839, 20.799136, 'Warmińsko-Mazurskie', 'Pasym / Rekowe', 'Jezioro Rekowe to długa rynna polodowcowa charakteryzująca się czystą wodą i twardym dnem piaszczysto-żwirowym. Maksymalna głębokość sięga ok. 15 metrów. To wyśmienita woda okoniowa i sandaczowa. Dzięki twardemu dnu, jigowanie jest tu niezwykle precyzyjne.', 'Gospodarstwo Rybackie Szwaderowo');
